window.HADITH_CACHE["bukhari_0"] = {"1":{"ar":"حَدَّثَنَا الْحُمَيْدِيُّ عَبْدُ اللَّهِ بْنُ الزُّبَيْرِ قَالَ حَدَّثَنَا سُفْيَانُ قَالَ حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ الْأَنْصَارِيُّ قَالَ أَخْبَرَنِي مُحَمَّدُ بْنُ إِبْرَاهِيمَ التَّيْمِيُّ أَنَّهُ سَمِعَ عَلْقَمَةَ بْنَ وَقَّاصٍ اللَّيْثِيَّ يَقُولُ سَمِعْتُ عُمَرَ بْنَ الْخَطَّابِ رَضِيَ اللَّهُ عَنْهُ عَلَى الْمِنْبَرِقَالَ سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ إِنَّمَا الْأَعْمَالُ بِالنِّيَّاتِ وَإِنَّمَا لِكُلِّ امْرِئٍ مَا نَوَى فَمَنْ كَانَتْ هِجْرَتُهُ إِلَى دُنْيَا يُصِيبُهَا أَوْ إِلَى امْرَأَةٍ يَنْكِحُهَا فَهِجْرَتُهُ إِلَى مَا هَاجَرَ إِلَيْهِ","id":"Telah menceritakan kepada kami [Al Humaidi Abdullah bin Az Zubair] dia berkata, Telah menceritakan kepada kami [Sufyan] yang berkata, bahwa Telah menceritakan kepada kami [Yahya bin Sa'id Al Anshari] berkata, telah mengabarkan kepada kami [Muhammad bin Ibrahim At Taimi], bahwa dia pernah mendengar [Alqamah bin Waqash Al Laitsi] berkata; saya pernah mendengar [Umar bin Al Khaththab] diatas mimbar berkata; saya mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Semua perbuatan tergantung niatnya, dan (balasan) bagi tiap-tiap orang (tergantung) apa yang diniatkan; Barangsiapa niat hijrahnya karena dunia yang ingin digapainya atau karena seorang perempuan yang ingin dinikahinya, maka hijrahnya adalah kepada apa dia diniatkan\""},"2":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ يُوسُفَ قَالَ أَخْبَرَنَا مَالِكٌ عَنْ هِشَامِ بْنِ عُرْوَةَ عَنْ أَبِيهِ عَنْ عَائِشَ��َ أُمِّ الْمُؤْمِنِينَ رَضِيَ اللَّهُ عَنْهَاأَنَّ الْحَارِثَ بْنَ هِشَامٍ رَضِيَ اللَّهُ عَنْهُ سَأَلَ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ يَا رَسُولَ اللَّهِ كَيْفَ يَأْتِيكَ الْوَحْيُ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَحْيَانًا يَأْتِينِي مِثْلَ صَلْصَلَةِ الْجَرَسِ وَهُوَ أَشَدُّهُ عَلَيَّ فَيُفْصَمُ عَنِّي وَقَدْ وَعَيْتُ عَنْهُ مَا قَالَ وَأَحْيَانًا يَتَمَثَّلُ لِي الْمَلَكُ رَجُلًا فَيُكَلِّمُنِي فَأَعِي مَا يَقُولُ قَالَتْ عَائِشَةُ رَضِيَ اللَّهُ عَنْهَا وَلَقَدْ رَأَيْتُهُ يَنْزِلُ عَلَيْهِ الْوَحْيُ فِي الْيَوْمِ الشَّدِيدِ الْبَرْدِ فَيَفْصِمُ عَنْهُ وَإِنَّ جَبِينَهُ لَيَتَفَصَّدُ عَرَقًا","id":"Telah menceritakan kepada kami [Abdullah bin Yusuf] berkata, telah mengabarkan kepada kami [Malik] dari [Hisyam bin 'Urwah] dari [bapaknya] dari [Aisyah] Ibu Kaum Mu'minin, bahwa Al Harits bin Hisyam bertanya kepada Rasulullah shallallahu 'alaihi wasallam: \"Wahai Rasulullah, bagaimana caranya wahyu turun kepada engkau?\" Maka Rasulullah shallallahu 'alaihi wasallam menjawab: \"Terkadang datang kepadaku seperti suara gemerincing lonceng dan cara ini yang paling berat buatku, lalu terhenti sehingga aku dapat mengerti apa yang disampaikan. Dan terkadang datang Malaikat menyerupai seorang laki-laki lalu berbicara kepadaku maka aku ikuti apa yang diucapkannya\". Aisyah berkata: \"Sungguh aku pernah melihat turunnya wahyu kepada Beliau shallallahu 'alaihi wasallam pada suatu hari yang sangat dingin lalu terhenti, dan aku lihat dahi Beliau mengucurkan keringat.\" "},"3":{"ar":"حَدَّثَنَا يَحْيَى بْنُ بُكَيْرٍ قَالَ حَدَّثَنَا اللَّيْثُ عَنْ عُقَيْلٍ عَنْ ابْنِ شِهَابٍ عَنْ عُرْوَةَ بْنِ الزُّبَيْرِ عَنْ عَائِشَةَ أُمِّ الْمُؤْمِنِينَ أَنَّهَا قَالَتْأَوَّلُ مَا بُدِئَ بِهِ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِنْ الْوَحْيِ الرُّؤْيَا الصَّالِحَةُ فِي النَّوْمِ فَكَانَ لَا يَرَى رُؤْيَا إِلَّا جَاءَتْ مِثْلَ فَلَقِ الصُّبْحِ ثُمَّ حُبِّبَ إِلَيْهِ الْخَلَاءُ وَكَانَ يَخْلُو بِغَارِ حِرَاءٍ فَيَتَحَنَّثُ فِيهِ وَهُوَ التَّعَبُّدُ اللَّيَالِيَ ذَوَاتِ الْعَدَدِ قَبْلَ أَنْ يَنْزِعَ إِلَى أَهْلِهِ وَيَتَزَوَّدُ لِذَلِكَ ثُمَّ يَرْجِعُ إِلَى خَدِيجَةَ فَيَتَزَوَّدُ لِمِثْلِهَا حَتَّى جَاءَهُ الْحَقُّ وَهُوَ فِي غَارِ حِرَاءٍ فَجَاءَهُ الْمَلَكُ فَقَالَ اقْرَأْ قَالَ مَا أَنَا بِقَارِئٍ قَالَ فَأَخَذَنِي فَغَط��َنِي حَتَّى بَلَغَ مِنِّي الْجَهْدَ ثُمَّ أَرْسَلَنِي فَقَالَ اقْرَأْ قُلْتُ مَا أَنَا بِقَارِئٍ فَأَخَذَنِي فَغَطَّنِي الثَّانِيَةَ حَتَّى بَلَغَ مِنِّي الْجَهْدَ ثُمَّ أَرْسَلَنِي فَقَالَ اقْرَأْ فَقُلْتُ مَا أَنَا بِقَارِئٍ فَأَخَذَنِي فَغَطَّنِي الثَّالِثَةَ ثُمَّ أَرْسَلَنِي فَقَالَ{ اقْرَأْ بِاسْمِ رَبِّكَ الَّذِي خَلَقَ خَلَقَ الْإِنْسَانَ مِنْ عَلَقٍ اقْرَأْ وَرَبُّكَ الْأَكْرَمُ }فَرَجَعَ بِهَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَرْجُفُ فُؤَادُهُ فَدَخَلَ عَلَى خَدِيجَةَ بِنْتِ خُوَيْلِدٍ رَضِيَ اللَّهُ عَنْهَا فَقَالَ زَمِّلُونِي زَمِّلُونِي فَزَمَّلُوهُ حَتَّى ذَهَبَ عَنْهُ الرَّوْعُ فَقَالَ لِخَدِيجَةَ وَأَخْبَرَهَا الْخَبَرَ لَقَدْ خَشِيتُ عَلَى نَفْسِي فَقَالَتْ خَدِيجَةُ كَلَّا وَاللَّهِ مَا يُخْزِيكَ اللَّهُ أَبَدًا إِنَّكَ لَتَصِلُ الرَّحِمَ وَتَحْمِلُ الْكَلَّ وَتَكْسِبُ الْمَعْدُومَ وَتَقْرِي الضَّيْفَ وَتُعِينُ عَلَى نَوَائِبِ الْحَقِّ فَانْطَلَقَتْ بِهِ خَدِيجَةُ حَتَّى أَتَتْ بِهِ وَرَقَةَ بْنَ نَوْفَلِ بْنِ أَسَدِ بْنِ عَبْدِ الْعُزَّى ابْنَ عَمِّ خَدِيجَةَ وَكَانَ امْرَأً قَدْ تَنَصَّرَ فِي الْجَاهِلِيَّةِ وَكَانَ يَكْتُبُ الْكِتَابَ الْعِبْرَانِيَّ فَيَكْتُبُ مِنْ الْإِنْجِيلِ بِالْعِبْرَانِيَّةِ مَا شَاءَ اللَّهُ أَنْ يَكْتُبَ وَكَانَ شَيْخًا كَبِيرًا قَدْ عَمِيَ فَقَالَتْ لَهُ خَدِيجَةُ يَا ابْنَ عَمِّ اسْمَعْ مِنْ ابْنِ أَخِيكَ فَقَالَ لَهُ وَرَقَةُ يَا ابْنَ أَخِي مَاذَا تَرَى فَأَخْبَرَهُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ خَبَرَ مَا رَأَى فَقَالَ لَهُ وَرَقَةُ هَذَا النَّامُوسُ الَّذِي نَزَّلَ اللَّهُ عَلَى مُوسَى يَا لَيْتَنِي فِيهَا جَذَعًا لَيْتَنِي أَكُونُ حَيًّا إِذْ يُخْرِجُكَ قَوْمُكَ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَوَمُخْرِجِيَّ هُمْ قَالَ نَعَمْ لَمْ يَأْتِ رَجُلٌ قَطُّ بِمِثْلِ مَا جِئْتَ بِهِ إِلَّا عُودِيَ وَإِنْ يُدْرِكْنِي يَوْمُكَ أَنْصُرْكَ نَصْرًا مُؤَزَّرًا ثُمَّ لَمْ يَنْشَبْ وَرَقَةُ أَنْ تُوُفِّيَ وَفَتَرَ الْوَحْيُقَالَ ابْنُ شِهَابٍ وَأَخْبَرَنِي أَبُو سَلَمَةَ بْنُ عَبْدِ الرَّحْمَنِ أَنَّ جَابِرَ بْنَ عَبْدِ اللَّهِ الْأَنْصَارِيَّ قَالَ وَهُوَ يُحَدِّثُ عَنْ فَتْرَةِ الْوَحْيِ فَقَالَ فِي حَدِيثِهِ بَيْنَا أَنَا أَمْشِي إِذْ سَمِعْتُ صَوْتًا مِنْ السَّمَاءِ فَرَفَعْتُ بَصَرِي فَإِذَا الْمَلَكُ الَّذِي جَاءَنِي بِحِرَاءٍ جَالِسٌ عَلَى كُرْسِيٍّ بَيْنَ السَّمَاءِ وَالْأَرْضِ فَرُعِبْتُ مِنْهُ فَرَجَعْتُ فَقُلْتُ زَمِّلُونِي زَمِّلُونِي فَأَنْزَلَ اللَّهُ تَعَالَى{ يَا أَيُّهَا الْمُدَّثِّرُ قُمْ فَأَنْذِرْ إِلَى قَوْلِهِ وَالرُّجْزَ فَاهْجُرْ }فَحَمِيَ الْوَحْيُ وَتَتَابَعَ تَابَعَهُ عَبْدُ اللَّهِ بْنُ يُوسُفَ وَأَبُو صَالِحٍ وَتَابَعَهُ هِلَالُ بْنُ رَدَّادٍ عَنْ ال��ُّهْرِيِّ وَقَالَ يُونُسُ وَمَعْمَرٌ بَوَادِرُهُ","id":"Telah menceritakan kepada kami [Yahya bin Bukair] berkata, Telah menceritakan kepada kami dari [Al Laits] dari ['Uqail] dari [Ibnu Syihab] dari ['Urwah bin Az Zubair] dari [Aisyah] -Ibu Kaum Mu'minin-, bahwasanya dia berkata: \"Permulaaan wahyu yang datang kepada Rasulullah shallallahu 'alaihi wasallam adalah dengan mimpi yang benar dalam tidur. Dan tidaklah Beliau bermimpi kecuali datang seperti cahaya subuh. Kemudian Beliau dianugerahi kecintaan untuk menyendiri, lalu Beliau memilih gua Hiro dan bertahannuts yaitu 'ibadah di malam hari dalam beberapa waktu lamanya sebelum kemudian kembali kepada keluarganya guna mempersiapkan bekal untuk bertahannuts kembali. Kemudian Beliau menemui Khadijah mempersiapkan bekal. Sampai akhirnya datang Al Haq saat Beliau di gua Hiro, Malaikat datang seraya berkata: \"Bacalah?\" Beliau menjawab: \"Aku tidak bisa baca\". Nabi shallallahu 'alaihi wasallam menjelaskan: Maka Malaikat itu memegangku dan memelukku sangat kuat kemudian melepaskanku dan berkata lagi: \"Bacalah!\" Beliau menjawab: \"Aku tidak bisa baca\". Maka Malaikat itu memegangku dan memelukku sangat kuat kemudian melepaskanku dan berkata lagi: \"Bacalah!\". Beliau menjawab: \"Aku tidak bisa baca\". Malaikat itu memegangku kembali dan memelukku untuk ketiga kalinya dengan sangat kuat lalu melepaskanku, dan berkata lagi: (Bacalah dengan (menyebut) nama Tuhanmu yang Menciptakan, Dia Telah menciptakan manusia dari segumpal darah. Bacalah, dan Tuhanmulah yang Maha Pemurah).\" Nabi shallallahu 'alaihi wasallam kembali kepada keluarganya dengan membawa kalimat wahyu tadi dalam keadaan gelisah. Beliau menemui Khadijah binti Khawailidh seraya berkata: \"Selimuti aku, selimuti aku!\". Beliau pun diselimuti hingga hilang ketakutannya. Lalu Beliau menceritakan peristiwa yang terjadi kepada Khadijah: \"Aku mengkhawatirkan diriku\". Maka Khadijah berkata: \"Demi Allah, Allah tidak akan mencelakakanmu selamanya, karena engkau adalah orang yang menyambung silaturrahim.\" Khadijah kemudian mengajak Beliau untuk bertemu dengan Waroqoh bin Naufal bin Asad bin Abdul 'Uzza, putra paman Khadijah, yang beragama Nasrani di masa Jahiliyyah, dia juga menulis buku dalam bahasa Ibrani, juga menulis Kitab Injil dalam Bahasa Ibrani dengan izin Allah. Saat itu Waroqoh sudah tua dan matanya buta. Khadijah berkata: \"Wahai putra pamanku, dengarkanlah apa yang akan disampaikan oleh putra saudaramu ini\". Waroqoh berkata: \"Wahai putra saudaraku, apa yang sudah kamu alami\". Maka Rasulullah shallallahu 'alaihi wasallam menuturkan peristiwa yang dialaminya. Waroqoh berkata: \"Ini adalah Namus, seperti yang pernah Allah turunkan kepada Musa. Duhai seandainya aku masih muda dan aku masih hidup saat kamu nanti diusir oleh kaummu\". Rasulullah shallallahu 'alaihi wasallam bertanya: \"Apakah aku akan diusir mereka?\" Waroqoh menjawab: \"Iya. Karena tidak ada satu orang pun yang datang dengan membawa seperti apa yang kamu bawa ini kecuali akan disakiti (dimusuhi). Seandainya aku ada saat kejadian itu, pasti aku akan menolongmu dengan sekemampuanku\". Waroqoh tidak mengalami peristiwa yang diyakininya tersebut karena lebih dahulu meninggal dunia pada masa fatroh (kekosongan) wahyu. [Ibnu Syihab] berkata; telah mengabarkan kepadaku [Abu Salamah bin Abdurrahman] bahwa [Jabir bin Abdullah Al Anshari] bertutur tentang kekosongan wahyu, sebagaimana yang Rasulullah shallallahu 'alaihi wasallam ceritakan: \"Ketika sedang berjalan aku mendengar suara dari langit, aku memandang ke arahnya dan ternyata Malaikat yang pernah datang kepadaku di gua Hiro, duduk di atas kursi antara langit dan bumi. Aku pun ketakutan dan pulang, dan berkata: \"Selimuti aku. Selimuti aku\". Maka Allah Ta'ala menurunkan wahyu: (Wahai orang yang berselimut) sampai firman Allah (dan berhala-berhala tinggalkanlah). Sejak saat itu wahyu terus turun berkesinambungan.\" Hadits ini juga diriwayatkan oleh [Abdullah bin Yusuf] dan [Abu Shalih] juga oleh [Hilal bin Raddad] dari [Az Zuhri]. Dan [Yunus] berkata; dan [Ma'mar] menyepakati bahwa dia mendapatkannya dari Az Zuhri. "},"4":{"ar":"حَدَّثَنَا مُوسَى بْنُ إِسْمَاعِيلَ قَالَ حَدَّثَنَا أَبُو عَوَانَةَ قَالَ حَدَّثَنَا مُوسَى بْنُ أَبِي عَائِشَةَ قَالَ حَدَّثَنَا سَعِيدُ بْنُ جُبَيْرٍ عَنْ ابْنِ عَبَّاسٍفِي قَوْلِهِ تَعَالَى{ لَا تُحَرِّكْ بِهِ لِسَانَكَ لِتَعْجَلَ بِهِ }قَالَ كَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُعَالِجُ مِنْ التَّنْزِيلِ شِدَّةً وَكَانَ مِمَّا يُحَرِّكُ شَفَتَيْهِ فَقَالَ ابْنُ عَبَّاسٍ فَأَنَا أُحَرِّكُهُمَا لَكُمْ كَمَا كَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُحَرِّكُهُمَا وَقَالَ سَعِيدٌ أَنَا أُحَرِّكُهُمَا كَمَا رَأَيْتُ ابْنَ عَبَّاسٍ يُحَرِّكُهُمَا فَحَرَّكَ شَفَتَيْهِ فَأَنْزَلَ اللَّهُ تَعَالَى{ لَا تُحَرِّكْ بِهِ لِسَانَكَ لِتَعْجَلَ بِهِ إِنَّ عَلَيْنَا جَمْعَهُ وَقُرْآنَهُ }قَالَ جَمْعُهُ لَكَ فِي صَدْرِكَ وَتَقْرَأَهُ{ فَإِذَا قَرَأْنَاهُ فَاتَّبِعْ قُرْآنَهُ }قَالَ فَاسْتَمِعْ لَهُ وَأَنْصِتْ{ ثُمَّ إِنَّ عَلَيْنَا بَيَانَهُ }ثُمَّ إِنَّ عَلَيْنَا أَنْ تَقْرَأَهُ فَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بَعْدَ ذَلِكَ إِذَا أَتَاهُ جِبْرِيلُ اسْتَمَعَ فَإِذَا انْطَلَقَ جِبْرِيلُ قَرَأَهُ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَمَا قَرَأَهُ","id":"Telah menceritakan kepada kami [Musa bin Isma'il] dia berkata, Telah menceritakan kepada kami [Abu 'Awanah] berkata, bahwa Telah menceritakan kepada kami [Musa bin Abu Aisyah] berkata, Telah menceritakan kepada kami [Sa'id bin Jubair] dari [Ibnu 'Abbas] tentang firman Allah Ta'ala: (Janganlah kamu gerakkan lidahmu untuk (membaca) Al Quran karena hendak cepat-cepat ingin (menguasainya).\" Berkata Ibnu 'Abbas: \"Rasulullah shallallahu 'alaihi wasallam sangat kuat keinginannya untuk menghafalkan apa yang diturunkan (Al Qur'an) dan menggerak-gerakkan kedua bibir Beliau.\" Berkata Ibnu 'Abbas: \"aku akan menggerakkan kedua bibirku (untuk membacakannya) kepada kalian sebagaimana Rasulullah shallallahu 'alaihi wasallam melakukannya kepadaku\". Berkata Sa'id: \"Dan aku akan menggerakkan kedua bibirku (untuk membacakannya) kepada kalian sebagaimana aku melihat Ibnu 'Abbas melakukannya. Maka Nabi shallallahu 'alaihi wasallam menggerakkan kedua bibirnya, Kemudian turunlah firman Allah Ta'ala: Janganlah kamu gerakkan lidahmu untuk (membaca) Al Quran karena hendak cepat-cepat (menguasai) nya. Sesungguhnya atas tanggungan Kamilah mengumpulkannya (di dadamu) dan (membuatmu pandai) membacanya\". Maksudnya Allah mengumpulkannya di dalam dadamu (untuk dihafalkan) dan kemudian kamu membacanya: \"Apabila Kami telah selesai membacakannya, maka ikutilah bacaannya itu\". Maksudnya: \"Dengarkanlah dan diamlah\". Kemudian Allah Ta'ala berfirman: \"Kemudian, sesungguhnya atas tanggungan Kamilah penjelasannya. Maksudnya: \"Dan Kewajiban Kamilah untuk membacakannya\" Dan Rasulullah shallallahu 'alaihi wasallam sejak saat itu bila Jibril 'Alaihis Salam datang kepadanya, Beliau mendengarkannya. Dan bila Jibril 'Alaihis Salam sudah pergi, maka Nabi shallallahu 'alaihi wasallam membacakannya (kepada para sahabat) sebagaimana Jibril 'Alaihis Salam membacakannya kepada Beliau shallallahu 'alaihi wasallam"},"5":{"ar":"حَدَّثَنَا عَبْدَانُ قَالَ أَخْبَرَنَا عَبْدُ اللَّهِ قَالَ أَخْبَرَنَا يُونُسُ عَنْ الزُّهْرِيِّ ح و حَدَّثَنَا بِشْرُ بْنُ مُحَمَّدٍ قَالَ أَخْبَرَنَا عَبْدُ اللَّهِ قَالَ أَخْبَرَنَا يُونُسُ وَمَعْمَرٌ عَنْ الزُّهْرِيِّ نَحْوَهُ قَالَ أَخْبَرَنِي عُبَيْدُ اللَّهِ بْنُ عَبْدِ اللَّهِ عَنْ ابْنِ عَبَّاسٍ قَالَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَجْوَدَ النَّاسِ وَكَانَ أَجْوَدُ مَا يَكُونُ فِي رَمَضَانَ حِينَ يَلْقَاهُ جِبْرِيلُ وَكَانَ يَلْقَاهُ فِي كُلِّ لَيْلَةٍ مِنْ رَمَضَانَ فَيُدَارِسُهُ الْقُرْآنَ فَلَرَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَجْوَدُ بِالْخَيْرِ مِنْ الرِّيحِ الْمُرْسَلَةِ","id":"Telah menceritakan kepada kami [Abdan] dia berkata, telah mengabarkan kepada kami [Abdullah] telah mengabarkan kepada kami [Yunus] dari [Az Zuhri] dan dengan riwayat yang sama, telah menceritakan pula kepada kami [Bisyir bin Muhammad] berkata, telah mengabarkan kepada kami [Abdullah] berkata, telah mengabarkan kepada kami [Yunus] dan [Ma'mar] dari [Az Zuhri] seperti lainnya berkata, telah mengabarkan kepada kami [Ubaidullah bin Abdullah] dari [Ibnu 'Abbas] berkata, bahwa Rasulullah shallallahu 'alaihi wasallam adalah manusia yang paling lembut terutama pada bulan Ramadlan ketika malaikat Jibril 'Alaihis Salam menemuinya, dan adalah Jibril 'Alaihis Salam mendatanginya setiap malam di bulan Ramadlan, dimana Jibril 'Alaihis Salam mengajarkan Al Qur'an. Sungguh Rasulullah shallallahu 'alaihi wasallam jauh lebih lembut daripada angin yang berhembus. "},"6":{"ar":"حَدَّثَنَا أَبُو الْيَمَانِ الْحَكَمُ بْنُ نَافِعٍ قَالَ أَخْبَرَنَا شُعَيْبٌ عَنْ الزُّهْرِيِّ قَالَ أَخْبَرَنِي عُبَيْدُ اللَّهِ بْنُ عَبْدِ اللَّهِ بْنِ عُتْبَةَ بْنِ مَسْعُودٍ أَنَّ عَبْدَ اللَّهِ بْنَ عَبَّاسٍ أَخْبَرَهُ أَنَّ أَبَا سُفْيَانَ بْنَ حَرْبٍ أَخْبَرَهُأَنَّ هِرَقْلَ أَرْسَلَ إِلَيْهِ فِي رَكْبٍ مِنْ قُرَيْشٍ وَكَانُوا تِجَارًا بِالشَّأْمِ فِي الْمُدَّةِ الَّتِي كَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَادَّ فِيهَا أَبَا سُفْيَانَ وَكُفَّارَ قُرَيْشٍ فَأَتَوْهُ وَهُمْ بِإِيلِيَاءَ فَدَعَاهُمْ فِي مَجْلِسِهِ وَحَوْلَهُ عُظَمَاءُ الرُّومِ ثُمَّ دَعَاهُمْ وَدَعَا بِتَرْجُمَانِهِ فَقَالَ أَيُّكُمْ أَقْرَبُ نَسَبًا بِهَذَا الرَّجُلِ الَّذِي يَزْعُمُ أَنَّهُ نَبِيٌّ فَقَالَ أَبُو سُفْيَانَ فَقُلْتُ أَنَا أَقْرَبُهُمْ نَسَبًا فَقَالَ أَدْنُوهُ مِنِّي وَقَرِّبُوا أَصْحَابَهُ فَاجْعَلُوهُمْ عِنْدَ ظَهْرِهِ ثُمَّ قَالَ لِتَرْجُمَانِهِ قُلْ لَهُمْ إِنِّي سَائِلٌ هَذَا عَنْ هَذَا الرَّجُلِ فَإِنْ كَذَبَنِي فَكَذِّبُوهُ فَوَاللَّهِ لَوْلَا الْحَيَاءُ مِنْ أَنْ يَأْثِرُوا عَلَيَّ كَذِبًا لَكَذَبْتُ عَنْهُ ثُمَّ كَانَ أَوَّلَ مَا سَأَلَنِي عَنْهُ أَنْ قَالَ كَيْفَ نَسَبُهُ فِيكُمْ قُلْتُ هُوَ فِينَا ذُو نَسَبٍ قَالَ فَهَلْ قَالَ هَذَا الْقَوْلَ مِنْكُمْ أَحَدٌ قَطُّ قَبْلَهُ قُلْتُ لَا قَالَ فَهَلْ كَانَ مِنْ آبَائِهِ مِنْ مَلِكٍ قُلْتُ لَا قَالَ فَأَشْرَافُ النَّاسِ يَتَّبِعُونَهُ أَمْ ضُعَفَاؤُهُمْ فَقُلْتُ بَلْ ضُعَفَاؤُهُمْ قَالَ أَيَزِيدُونَ أَمْ يَنْقُصُونَ قُلْتُ بَلْ يَزِيدُونَ قَالَ فَهَلْ يَرْتَدُّ أَحَدٌ مِنْهُمْ سَخْطَةً لِدِينِهِ بَعْدَ أَنْ يَدْخُلَ فِيهِ قُلْتُ لَا قَالَ فَهَلْ كُنْتُمْ تَتَّهِمُونَهُ بِالْكَذِبِ قَبْلَ أَنْ يَقُولَ مَا قَالَ قُلْتُ لَا قَالَ فَهَلْ يَغْدِرُ قُلْتُ لَا وَنَحْنُ مِنْهُ فِي مُدَّةٍ لَا نَدْرِي مَا هُوَ فَاعِلٌ فِيهَا قَالَ وَلَمْ تُمْكِنِّي كَلِمَةٌ أُدْخِلُ فِيهَا شَيْئًا غَيْرُ هَذِهِ الْكَلِمَةِ قَالَ فَهَلْ قَاتَلْتُمُوهُ قُلْتُ نَعَمْ قَالَ فَكَيْفَ كَانَ قِتَالُكُمْ إِيَّاهُ قُلْتُ الْحَرْبُ بَيْنَنَا وَبَيْنَهُ سِجَالٌ يَنَالُ مِنَّا وَنَنَالُ مِنْهُ قَالَ مَاذَا يَأْمُرُكُمْ قُلْتُ يَقُولُ اعْبُدُوا اللَّهَ وَحْدَهُ وَلَا تُشْرِكُوا بِهِ شَيْئًا وَاتْرُكُوا مَا يَقُولُ آبَاؤُكُمْ وَيَأْمُرُنَا بِالصَّلَاةِ وَالزَّكَاةِ وَالصِّدْقِ وَالْعَفَافِ وَالصِّلَةِ فَقَالَ لِلتَّرْجُمَانِ قُلْ لَهُ سَأَلْتُكَ عَنْ نَسَبِهِ فَذَكَرْتَ أَنَّهُ فِيكُمْ ذُو نَسَبٍ فَكَذَلِكَ الرُّسُلُ تُبْعَثُ فِي نَسَبِ قَوْمِهَا وَسَأَلْتُكَ هَلْ قَالَ أَحَدٌ مِنْكُمْ هَذَا الْقَوْلَ فَذَكَرْتَ أَنْ لَا فَقُلْتُ لَوْ كَانَ أَحَدٌ قَالَ هَذَا الْقَوْلَ قَبْلَهُ لَقُلْتُ رَجُلٌ يَأْتَسِي بِقَوْلٍ قِيلَ قَبْلَهُ وَسَأَلْتُكَ هَلْ كَانَ مِنْ آبَائِهِ مِنْ مَلِكٍ فَذَكَرْتَ أَنْ لَا قُلْتُ فَلَوْ كَانَ مِنْ آبَائِهِ مِنْ مَلِكٍ قُلْتُ رَجُلٌ يَطْلُبُ مُلْكَ أَبِيهِ وَسَأَلْتُكَ هَلْ كُنْتُمْ تَتَّهِمُونَهُ بِالْكَذِبِ قَبْلَ أَنْ يَقُولَ مَا قَالَ فَذَكَرْتَ أَنْ لَا فَقَدْ أَعْرِفُ أَنَّهُ لَمْ يَكُنْ لِيَذَرَ الْكَذِبَ عَلَى النَّاسِ وَيَكْذِبَ عَلَى اللَّهِ وَسَأَلْتُكَ أَشْرَافُ النَّاسِ اتَّبَعُوهُ أَمْ ضُعَفَاؤُهُمْ فَذَكَرْتَ أَنَّ ضُعَفَاءَهُمْ اتَّبَعُوهُ وَهُمْ أَتْبَاعُ الرُّسُلِ وَسَأَلْتُكَ أَيَزِيدُونَ أَمْ يَنْقُصُونَ فَذَكَرْتَ أَنَّهُمْ يَزِيدُونَ وَكَذَلِكَ أَمْرُ الْإِيمَانِ حَتَّى يَتِمَّ وَسَأَلْتُكَ أَيَرْتَدُّ أَحَدٌ سَخْطَةً لِدِينِهِ بَعْدَ أَنْ يَدْخُلَ فِيهِ فَذَكَرْتَ أَنْ لَا وَكَذَلِكَ الْإِيمَانُ حِينَ تُخَالِطُ بَشَاشَتُهُ الْقُلُوبَ وَسَأَلْتُكَ هَلْ يَغْدِرُ فَذَكَرْتَ أَنْ لَا وَكَذَلِكَ الرُّسُلُ لَا تَغْدِرُ وَسَأَلْتُكَ بِمَا يَأْمُرُكُمْ فَذَكَرْتَ أَنَّهُ يَأْمُرُكُمْ أَنْ تَعْبُدُوا اللَّهَ وَلَا تُشْرِكُوا بِهِ شَيْئًا وَيَنْهَاكُمْ عَنْ عِبَادَةِ الْأَوْثَانِ وَيَأْمُرُكُمْ بِالصَّلَاةِ وَالصِّدْقِ وَالْعَفَافِ فَإِنْ كَانَ مَا تَقُولُ حَقًّا فَسَيَمْلِكُ مَوْضِعَ قَدَمَيَّ هَاتَيْنِ وَقَدْ كُنْتُ أَعْلَمُ أَنَّهُ خَارِجٌ لَمْ أَكُنْ أَظُنُّ أَنَّهُ مِنْكُمْ فَلَوْ أَنِّي أَعْلَمُ أَنِّي أَخْلُصُ إِلَيْهِ لَتَجَشَّمْتُ لِقَاءَهُ وَلَوْ كُنْتُ عِنْدَهُ لَغَسَلْتُ عَنْ قَدَمِهِ ثُمَّ دَعَا بِكِتَابِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الَّذِي بَعَثَ بِهِ دِحْيَةُ إِلَى عَظِيمِ بُصْرَى فَدَفَعَهُ إِلَى هِرَقْلَ فَقَرَأَهُ فَإِذَا فِيهِ بِسْمِ اللَّهِ الرَّحْمَنِ الرَّحِيمِ مِنْ مُحَمَّدٍ عَبْدِ اللَّهِ وَرَسُولِهِ إِلَى هِرَقْلَ عَظِيمِ الرُّومِ سَلَامٌ عَلَى مَنْ اتَّبَعَ الْهُدَى أَمَّا بَعْدُ فَإِنِّي أَدْعُوكَ بِدِعَايَةِ الْإِسْلَامِ أَسْلِمْ تَسْلَمْ يُؤْتِكَ اللَّهُ أَجْرَكَ مَرَّتَيْنِ فَإِنْ تَوَلَّيْتَ فَإِنَّ عَلَيْكَ إِثْمَ الْأَرِيسِيِّينَ وَ{ يَا أَهْلَ الْكِتَابِ تَعَالَوْا إِلَى كَلِمَةٍ سَوَاءٍ بَيْنَنَا وَبَيْنَكُمْ أَنْ لَا نَعْبُدَ إِلَّا اللَّهَ وَلَا نُشْرِكَ بِهِ شَيْئًا وَلَا يَتَّخِذَ بَعْضُنَا بَعْضًا أَرْبَابًا مِنْ دُونِ اللَّهِ فَإِنْ تَوَلَّوْا فَقُولُوا اشْهَدُوا بِأَنَّا مُسْلِمُونَ }قَالَ أَبُو سُفْيَانَ فَلَمَّا قَالَ مَا قَالَ وَفَرَغَ مِنْ قِرَاءَةِ الْكِتَابِ كَثُرَ عِنْدَهُ الصَّخَبُ وَارْتَفَعَتْ الْأَصْوَاتُ وَأُخْرِجْنَا فَقُلْتُ لِأَصْحَابِي حِينَ أُخْرِجْنَا لَقَدْ أَمِرَ أَمْرُ ابْنِ أَبِي كَبْشَةَ إِنَّهُ يَخَافُهُ مَلِكُ بَنِي الْأَصْفَرِ فَمَا زِلْتُ مُوقِنًا أَنَّهُ سَيَظْهَرُ حَتَّى أَدْخَلَ اللَّهُ عَلَيَّ الْإِسْلَامَ وَكَانَ ابْنُ النَّاظُورِ صَاحِبُ إِيلِيَاءَ وَهِرَقْلَ سُقُفًّا عَلَى نَصَارَى الشَّأْمِ يُحَدِّثُ أَنَّ هِرَقْلَ حِينَ قَدِمَ إِيلِيَاءَ أَصْبَحَ يَوْمًا خَبِيثَ النَّفْسِ فَقَالَ بَعْضُ بَطَارِقَتِهِ قَدْ اسْتَنْكَرْنَا هَيْئَتَكَ قَالَ ابْنُ النَّاظُورِ وَكَانَ هِرَقْلُ حَزَّاءً يَنْظُرُ فِي النُّجُومِ فَقَالَ لَهُمْ حِينَ سَأَلُوهُ إِنِّي رَأَيْتُ اللَّيْلَةَ حِينَ نَظَرْتُ فِي النُّجُومِ مَلِكَ الْخِتَانِ قَدْ ظَهَرَ فَمَنْ يَخْتَتِنُ مِنْ هَذِهِ الْأُمَّةِ قَالُوا لَيْسَ يَخْتَتِنُ إِلَّا الْيَهُودُ فَلَا يُهِمَّنَّكَ شَأْنُهُمْ وَاكْتُبْ إِلَى مَدَايِنِ مُلْكِكَ فَيَقْتُلُوا مَنْ فِيهِمْ مِنْ الْيَهُودِ فَبَيْنَمَا هُمْ عَلَى أَمْرِهِمْ أُتِيَ هِرَقْلُ بِرَجُلٍ أَرْسَلَ بِهِ مَلِكُ غَسَّانَ يُخْبِرُ عَنْ خَبَرِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَلَمَّا اسْتَخْبَرَهُ هِرَقْلُ قَالَ اذْهَبُوا فَانْظُرُوا أَمُخْتَتِنٌ هُوَ أَمْ لَا فَنَظَرُوا إِلَيْهِ فَحَدَّثُوهُ أَنَّهُ مُخْتَتِنٌ وَسَأَلَهُ عَنْ الْعَرَبِ فَقَالَ هُمْ يَخْتَتِنُونَ فَقَالَ هِرَقْلُ هَذَا مُلْكُ هَذِهِ الْأُمَّةِ قَدْ ظَهَرَ ثُمَّ كَتَبَ هِرَقْلُ إِلَى صَاحِبٍ لَهُ بِرُومِيَةَ وَكَانَ نَظِيرَهُ فِي الْعِلْمِ وَسَارَ هِرَقْلُ إِلَى حِمْصَ فَلَمْ يَرِمْ حِمْصَ حَتَّى أَتَاهُ كِتَابٌ مِنْ صَاحِبِهِ يُوَافِقُ رَأْيَ هِرَقْلَ عَلَى خُرُوجِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَأَنَّهُ نَبِيٌّ فَأَذِنَ هِرَقْلُ لِعُظَمَاءِ الرُّومِ فِي دَسْكَرَةٍ لَهُ بِحِمْصَ ثُمَّ أَمَرَ بِأَبْوَابِهَا فَغُلِّقَتْ ثُمَّ اطَّلَعَ فَقَالَ يَا مَعْشَرَ الرُّومِ هَلْ لَكُمْ فِي الْفَلَاحِ وَالرُّشْدِ وَأَنْ يَثْبُتَ مُلْكُكُمْ فَتُبَايِعُوا هَذَا النَّبِيَّ فَحَاصُوا حَيْصَةَ حُمُرِ الْوَحْشِ إِلَى الْأَبْوَابِ فَوَجَدُوهَا قَدْ غُلِّقَتْ فَلَمَّا رَأَى هِرَقْلُ نَفْرَتَهُمْ وَأَيِسَ مِنْ الْإِيمَانِ قَالَ رُدُّوهُمْ عَلَيَّ وَقَالَ إِنِّي قُلْتُ مَقَالَتِي آنِفًا أَخْتَبِرُ بِهَا شِدَّتَكُمْ عَلَى دِينِكُمْ فَقَدْ رَأَيْتُ فَسَجَدُوا لَهُ وَرَضُوا عَنْهُ فَكَانَ ذَلِكَ آخِرَ شَأْنِ هِرَقْلَرَوَاهُ صَالِحُ بْنُ كَيْسَانَ وَيُونُسُ وَمَعْمَرٌ عَنْ الزُّهْرِيِّ","id":"Telah menceritakan kepada kami [Abu Al Yaman Al Hakam bin Nafi'] dia berkata, telah mengabarkan kepada kami [Syu'aib] dari [Az Zuhri] telah mengabarkan kepadaku [Ubaidullah bin Abdullah bin 'Utbah bin Mas'ud] bahwa [Abdullah bin 'Abbas] telah mengabarkan kepadanya bahwa [Abu Sufyan bin Harb] telah mengabarkan kepadanya; bahwa Heraclius menerima rombongan dagang Quraisy, yang sedang mengadakan ekspedisi dagang ke Negeri Syam pada saat berlakunya perjanjian antara Nabi shallallahu 'alaihi wasallam dengan Abu Sufyan dan orang-orang kafir Quraisy. Saat singgah di Iliya' mereka menemui Heraclius atas undangan Heraclius untuk di diajak dialog di majelisnya, yang saat itu Heraclius bersama dengan para pembesar-pembesar Negeri Romawi. Heraclius berbicara dengan mereka melalui penerjemah. Heraclius berkata; \"Siapa diantara kalian yang paling dekat hubungan keluarganya dengan orang yang mengaku sebagai Nabi itu?.\" Abu Sufyan berkata; maka aku menjawab; \"Akulah yang paling dekat hubungan kekeluargaannya dengan dia\". Heraclius berkata; \"Dekatkanlah dia denganku dan juga sahabat-sahabatnya.\" Maka mereka meletakkan orang-orang Quraisy berada di belakang Abu Sufyan. Lalu Heraclius berkata melalui penerjemahnya: \"Katakan kepadanya, bahwa aku bertanya kepadanya tentang lelaki yang mengaku sebagai Nabi. Jika ia berdusta kepadaku maka kalian harus mendustakannya.\"Demi Allah, kalau bukan rasa malu akibat tudingan pendusta yang akan mereka lontarkan kepadaku niscaya aku berdusta kepadanya.\" Abu Sufyan berkata; Maka yang pertama ditanyakannya kepadaku tentangnya (Nabi shallallahu 'alaihi wasallam) adalah: \"bagaimana kedudukan nasabnya ditengah-tengah kalian?\" Aku jawab: \"Dia adalah dari keturunan baik-baik (bangsawan) \". Tanyanya lagi: \"Apakah ada orang lain yang pernah mengatakannya sebelum dia?\" Aku jawab: \"Tidak ada\". Tanyanya lagi: \"Apakah bapaknya seorang raja?\" Jawabku: \"Bukan\". Apakah yang mengikuti dia orang-orang yang terpandang atau orang-orang yang rendah?\" Jawabku: \"Bahkan yang mengikutinya adalah orang-orang yang rendah\". Dia bertanya lagi: \"Apakah bertambah pengikutnya atau berkurang?\" Aku jawab: \"Bertambah\". Dia bertanya lagi: \"Apakah ada yang murtad disebabkan dongkol terhadap agamanya?\" Aku jawab: \"Tidak ada\". Dia bertanya lagi: \"Apakah kalian pernah mendapatkannya dia berdusta sebelum dia menyampaikan apa yang dikatakannya itu?\" Aku jawab: \"Tidak pernah\". Dia bertanya lagi: \"Apakah dia pernah berlaku curang?\" Aku jawab: \"Tidak pernah. Ketika kami bergaul dengannya, dia tidak pernah melakukan itu\". Berkata Abu Sufyan: \"Aku tidak mungkin menyampaikan selain ucapan seperti ini\". Dia bertanya lagi: \"Apakah kalian memeranginya?\" Aku jawab: \"Iya\". Dia bertanya lagi: \"Bagaimana kesudahan perang tersebut?\" Aku jawab: \"Perang antara kami dan dia sangat banyak. Terkadang dia mengalahkan kami terkadang kami yang mengalahkan dia\". Dia bertanya lagi: \"Apa yang diperintahkannya kepada kalian?\" Aku jawab: \"Dia menyuruh kami; 'Sembahlah Allah dengan tidak menyekutukannya dengan sesuatu apapun, dan tinggalkan apa yang dikatakan oleh nenek moyang kalian. ' Dia juga memerintahkan kami untuk menegakkan shalat, menunaikan zakat, berkata jujur, saling memaafkan dan menyambung silaturrahim\". Maka Heraclius berkata kepada penerjemahnya: \"Katakan kepadanya, bahwa aku telah bertanya kepadamu tentang keturunan orang itu, kamu ceritakan bahwa orang itu dari keturunan bangsawan. Begitu juga laki-laki itu dibangkitkan di tengah keturunan kaumnya. Dan aku tanya kepadamu apakah pernah ada orang sebelumnya yang mengatakan seperti yang dikatakannya, kamu jawab tidak. Seandainya dikatakan ada orang sebelumnya yang mengatakannya tentu kuanggap orang ini meniru orang sebelumnya yang pernah mengatakan hal serupa. Aku tanyakan juga kepadamu apakah bapaknya ada yang dari keturunan raja, maka kamu jawab tidak. Aku katakan seandainya bapaknya dari keturunan raja, tentu orang ini sedang menuntut kerajaan bapaknya. Dan aku tanyakan juga kepadamu apakah kalian pernah mendapatkan dia berdusta sebelum dia menyampaikan apa yang dikatakannya, kamu menjawabnya tidak. Sungguh aku memahami, kalau kepada manusia saja dia tidak berani berdusta apalagi berdusta kepada Allah. Dan aku juga telah bertanya kepadamu, apakah yang mengikuti dia orang-orang yang terpandang atau orang-orang yang rendah?\" Kamu menjawab orang-orang yang rendah yang mengikutinya. Memang mereka itulah yang menjadi para pengikut Rasul. Aku juga sudah bertanya kepadamu apakah bertambah pengikutnya atau berkurang, kamu menjawabnya bertambah. Dan memang begitulah perkara iman hingga menjadi sempurna. Aku juga sudah bertanya kepadamu apakah ada yang murtad disebabkan marah terhadap agamanya. Kamu menjawab tidak ada. Dan memang begitulah iman bila telah masuk tumbuh bersemi di dalam hati. Aku juga sudah bertanya kepadamu apakah dia pernah berlaku curang, kamu jawab tidak pernah. Dan memang begitulah para Rasul tidak mungkin curang. Dan aku juga sudah bertanya kepadamu apa yang diperintahkannya kepada kalian, kamu jawab dia memerintahkan kalian untuk menyembah Allah dengan tidak menyekutukannya dengan sesuatu apapun, dan melarang kalian menyembah berhala, dia juga memerintahkan kalian untuk menegakkan shalat, menunaikan zakat, berkata jujur, saling memaafkan dan menyambung silaturrahim. Seandainya semua apa yang kamu katakan ini benar, pasti dia akan menguasai kerajaan yang ada di bawah kakiku ini. Sungguh aku telah menduga bahwa dia tidak ada diantara kalian sekarang ini, seandainya aku tahu jalan untuk bisa menemuinya, tentu aku akan berusaha keras menemuinya hingga bila aku sudah berada di sisinya pasti aku akan basuh kedua kakinya. Kemudian Heraclius meminta surat Rasulullah shallallahu 'alaihi wasallam yang dibawa oleh Dihyah untuk para Penguasa Negeri Bashrah, Maka diberikannya surat itu kepada Heraclius, maka dibacanya dan isinya berbunyi: \"Bismillahir rahmanir rahim. Dari Muhammad, hamba Allah dan Rasul-Nya untuk Heraclius. Penguasa Romawi, Keselamatan bagi siapa yang mengikuti petunjuk. Kemudian daripada itu, aku mengajakmu dengan seruan Islam; masuk Islamlah kamu, maka kamu akan selamat, Allah akan memberi pahala kepadamu dua kali. Namun jika kamu berpaling, maka kamu menanggung dosa rakyat kamu, dan: Hai ahli kitab, marilah (berpegang) kepada suatu kalimat (ketetapan) yang tidak ada perselisihan antara kami dan kamu, bahwa tidak kita sembah kecuali Allah dan tidak kita persekutukan dia dengan sesuatupun dan tidak (pula) sebagian kita menjadikan sebagian yang lain sebagai Rabb selain Allah\". Jika mereka berpaling, maka katakanlah kepada mereka: \"Saksikanlah, bahwa kami adalah orang-orang yang berserah diri (kepada Allah).\" Abu Sufyan menuturkan: \"Setelah Heraclius menyampaikan apa yang dikatakannya dan selesai membaca surat tersebut, terjadilah hiruk pikuk dan suara-suara ribut, sehingga mengusir kami. Aku berkata kepada teman-temanku setelah kami diusir keluar; \"sungguh dia telah diajak kepada urusan Anak Abu Kabsyah. Heraclius mengkhawatirkan kerajaan Romawi.\"Pada masa itupun aku juga khawatir bahwa Muhammad akan berjaya, sampai akhirnya (perasaan itu hilang setelah) Allah memasukkan aku ke dalam Islam. Dan adalah Ibnu An Nazhur, seorang Pembesar Iliya' dan Heraclius adalah seorang uskup agama Nashrani, dia menceritakan bahwa pada suatu hari ketika Heraclius mengunjungi Iliya' dia sangat gelisah, berkata sebagian komandan perangnya: \"Sungguh kami mengingkari keadaanmu. Selanjutnya kata Ibnu Nazhhur, \"Heraclius adalah seorang ahli nujum yang selalu memperhatikan perjalanan bintang-bintang. Dia pernah menjawab pertanyaan para pendeta yang bertanya kepadanya; \"Pada suatu malam ketika saya mengamati perjalanan bintang-bintang, saya melihat raja Khitan telah lahir, siapakah di antara ummat ini yang di khitan?\" Jawab para pendeta; \"Yang berkhitan hanyalah orang-orang Yahudi, janganlah anda risau karena orang-orang Yahudi itu. Perintahkan saja keseluruh negeri dalam kerajaan anda, supaya orang-orang Yahudi di negeri tersebut di bunuh.\" Ketika itu di hadapakan kepada Heraclius seorang utusan raja Bani Ghasssan untuk menceritakan perihal Rasulullah shallallahu 'alaihi wasallam, setelah orang itu selesai bercerita, lalu Heraclius memerintahkan agar dia diperiksa, apakah dia berkhitan ataukah tidak. Seusai di periksa, ternyata memang dia berkhitam. Lalu di beritahukan orang kepada Heraclius. Heraclius bertanya kepada orang tersebut tentang orang-orang Arab yang lainnya, di khitankah mereka ataukah tidak?\" Dia menjawab; \"Orang Arab itu di khitan semuanya.\" Heraclius berkata; 'inilah raja ummat, sesungguhnya dia telah terlahir.\" Kemudian heraclisu berkirim surat kepada seorang sahabatnya di Roma yang ilmunya setarf dengan Heraclisu (untuk menceritakan perihal kelahiran Nabi Muhammad shallallahu 'alaihi wasallam). Sementara itu, ia meneruskan perjalanannya ke negeri Himsha, tetapi sebelum tiba di Himsha, balasan surat dari sahabatnya itu telah tiba terlebih dahulu. Sahabatnya itu menyetujui pendapat Heraclius bahwa Muhammad telah lahir dan bahwa beliau memang seorang Nabi. Heraclius lalu mengundang para pembesar Roma supaya datang ke tempatnya di Himsha, setelah semuanya hadir dalam majlisnya, Heraclius memerintahkan supaya mengunci semua pintu. Kemudian dia berkata; 'Wahai bangsa rum, maukah anda semua beroleh kemenangan dan kemajuan yang gilang gemilang, sedangkan kerajaan tetap utuh di tangan kita? Kalau mau, akuilah Muhammad sebagai Nabi!.\" Mendengar ucapan itu, mereka lari bagaikan keledai liar, padahal semua pintu telah terkunci. Melihat keadaan yang demikian, Heraclius jadi putus harapan yang mereka akan beriman (percaya kepada kenabian Muhammad). Lalu di perintahkannya semuanya untuk kembali ke tempatnya masing-masing seraya berkata; \"Sesungguhnya saya mengucapkan perkataan saya tadi hanyalah sekedar menguji keteguhan hati anda semua. Kini saya telah melihat keteguhan itu.\" Lalu mereka sujud di hadapan Heraclius dan mereka senang kepadanya. Demikianlah akhir kisah Heraclius. Telah di riwayatkan oleh [Shalih bin Kaisan] dan [Yunus] dan [Ma'mar] dari [Az Zuhri]."},"7":{"ar":"حَدَّثَنَا عُبَيْدُ اللَّهِ بْنُ مُوسَى قَالَ أَخْبَرَنَا حَنْظَلَةُ بْنُ أَبِي سُفْيَانَ عَنْ عِكْرِمَةَ بْنِ خَالِدٍ عَنْ ابْنِ عُمَرَ رَضِيَ اللَّهُ عَنْهُمَاقَالَ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بُنِيَ الْإِسْلَامُ عَلَى خَمْسٍ شَهَادَةِ أَنْ لَا إِلَهَ إِلَّا اللَّهُ وَأَنَّ مُحَمَّدًا رَسُولُ اللَّهِ وَإِقَامِ الصَّلَاةِ وَإِيتَاءِ الزَّكَاةِ وَالْحَجِّ وَصَوْمِ رَمَضَانَ","id":"Telah menceritakan kepada kami [Abdullah bin Musa] dia berkata, telah mengabarkan kepada kami [Hanzhalah bin Abu Sufyan] dari ['Ikrimah bin Khalid] dari [Ibnu Umar] berkata: Rasulullah shallallahu 'alaihi wasallam bersabda: \"Islam dibangun diatas lima (landasan); persaksian tidak ada ilah selain Allah dan sesungguhnya Muhammad utusan Allah, mendirikan shalat, menunaikan zakat, haji dan puasa Ramadlan\". "},"8":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مُحَمَّدٍ الْجُعْفِيُّ قَالَ حَدَّثَنَا أَبُو عَامِرٍ الْعَقَدِيُّ قَالَ حَدَّثَنَا سُلَيْمَانُ بْنُ بِلَالٍ عَنْ عَبْدِ اللَّهِ بْنِ دِينَارٍ عَنْ أَبِي صَالِحٍ عَنْ أَبِي هُرَيْرَةَ رَضِيَ اللَّهُ عَنْهُعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ الْإِيمَانُ بِضْعٌ وَسِتُّونَ شُعْبَةً وَالْحَيَاءُ شُعْبَةٌ مِنْ الْإِيمَانِ","id":"Telah menceritakan kepada kami [Abdullah bin Muhammad Al Ju'fi] dia berkata, Telah menceritakan kepada kami [Abu 'Amir Al 'Aqadi] yang berkata, bahwa Telah menceritakan kepada kami [Sulaiman bin Bilal] dari [Abdullah bin Dinar] dari [Abu Shalih] dari [Abu Hurairah] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Iman memiliki lebih dari enam puluh cabang, dan malu adalah bagian dari iman\". "},"9":{"ar":"حَدَّثَنَا آدَمُ بْنُ أَبِي إِيَاسٍ قَالَ حَدَّثَنَا شُعْبَةُ عَنْ عَبْدِ اللَّهِ بْنِ أَبِي السَّفَرِ وَإِسْمَاعِيلَ بْنِ أَبِي خَالِدٍ عَنْ الشَّعْبِيِّ عَنْ عَبْدِ اللَّهِ بْنِ عَمْرٍو رَضِيَ اللَّهُ عَنْهُمَاعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ الْمُسْلِمُ مَنْ سَلِمَ الْمُسْلِمُونَ مِنْ لِسَانِهِ وَيَدِهِ وَالْمُهَاجِرُ مَنْ هَجَرَ مَا نَهَى اللَّهُ عَنْهُقَالَ أَبُو عَبْد اللَّهِ وَقَالَ أَبُو مُعَاوِيَةَ حَدَّثَنَا دَاوُدُ هُوَ ابْنُ أَبِي هِنْدٍ عَنْ عَامِرٍ قَالَ سَمِعْتُ عَبْدَ اللَّهِ يَعْنِي ابْنَ عَمْرٍو عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَقَالَ عَبْدُ الْأَعْلَى عَنْ دَاوُدَ عَنْ عَامِرٍ عَنْ عَبْدِ اللَّهِ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah menceritakan kepada kami [Adam bin Abu Iyas] berkata, Telah menceritakan kepada kami [Syu'bah] dari [Abdullah bin Abu As Safar] dan [Isma'il bin Abu Khalid] dari [Asy Sya'bi] dari [Abdullah bin 'Amru] dari Nabi shallallahu 'alaihi wasallam, bersabda: \"Seorang muslim adalah orang yang Kaum Muslimin selamat dari lisan dan tangannya, dan seorang Muhajir adalah orang yang meninggalkan apa yang dilarang oleh Allah \" Abu Abdullah berkata; dan [Abu Mu'awiyyah] berkata; Telah menceritakan kepada kami [Daud], dia adalah anak Ibnu Hind, dari ['Amir] berkata; aku mendengar [Abdullah], maksudnya ibnu 'Amru, dari Nabi shallallahu 'alaihi wasallam Dan berkata [Abdul A'laa] dari [Daud] dari ['Amir] dari [Abdullah] dari Nabi shallallahu 'alaihi wasallam "},"10":{"ar":"حَدَّثَنَا سَعِيدُ بْنُ يَحْيَى بْنِ سَعِيدٍ الْقُرَشِيُّ قَالَ حَدَّثَنَا أَبِي قَالَ حَدَّثَنَا أَبُو بُرْدَةَ بْنُ عَبْدِ اللَّهِ بْنِ أَبِي بُرْدَةَ عَنْ أَبِي بُرْدَةَ عَنْ أَبِي مُوسَى رَضِيَ اللَّهُ عَنْهُ قَالَقَالُوا يَا رَسُولَ اللَّهِ أَيُّ الْإِسْلَامِ أَفْضَلُ قَالَ مَنْ سَلِمَ الْمُسْلِمُونَ مِنْ لِسَانِهِ وَيَدِهِ","id":"Telah menceritakan kepada kami [Sa'id bin Yahya bin Sa'id Al Qurasyi] dia berkata, Telah menceritakan kepada kami [bapakku] berkata, bahwa Telah menceritakan kepada kami [Abu Burdah bin Abdullah bin Abu Burdah] dari [Abu Burdah] dari [Abu Musa] berkata: 'Wahai Rasulullah, Islam manakah yang paling utama?\" Rasulullah shallallahu 'alaihi wasallam menjawab: \"Siapa yang Kaum Muslimin selamat dari lisan dan tangannya\". "},"11":{"ar":"حَدَّثَنَا عَمْرُو بْنُ خَالِدٍ قَالَ حَدَّثَنَا اللَّيْثُ عَنْ يَزِيدَ عَنْ أَبِي الْخَيْرِ عَنْ عَبْدِ اللَّهِ بْنِ عَمْرٍو رَضِيَ اللَّهُ عَنْهُمَاأَنَّ رَجُلًا سَأَلَ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَيُّ الْإِسْلَامِ خَيْرٌ قَالَ تُطْعِمُ الطَّعَامَ وَتَقْرَأُ السَّلَامَ عَلَى مَنْ عَرَفْتَ وَمَنْ لَمْ تَعْرِفْ","id":"Telah menceritakan kepada kami ['Amru bin Khalid] berkata, Telah menceritakan kepada kami [Al Laits] dari [Yazid] dari [Abu Al Khair] dari [Abdullah bin 'Amru]; Ada seseorang yang bertanya kepada Nabi shallallahu 'alaihi wasallam; \"Islam manakah yang paling baik?\" Nabi shallallahu 'alaihi wasallam menjawab: \"Kamu memberi makan, mengucapkan salam kepada orang yang kamu kenal dan yang tidak kamu kenal\". "},"12":{"ar":"حَدَّثَنَا مُسَدَّدٌ قَالَ حَدَّثَنَا يَحْيَى عَنْ شُعْبَةَ عَنْ قَتَادَةَ عَنْ أَنَسٍ رَضِيَ اللَّهُ عَنْهُ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَعَنْ حُسَيْنٍ الْمُعَلِّمِ قَالَ حَدَّثَنَا قَتَادَةُ عَنْ أَنَسٍعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا يُؤْمِنُ أَحَدُكُمْ حَتَّى يُحِبَّ لِأَخِيهِ مَا يُحِبُّ لِنَفْسِهِ","id":"Telah menceritakan kepada kami [Musaddad] berkata, telah menceritakan kepada kami [Yahya] dari [Syu'bah] dari [Qotadah] dari [Anas] dari Nabi shallallahu 'alaihi wasallam Dan dari [Husain Al Mu'alim] berkata, telah menceritakan kepada kami [Qotadah] dari [Anas] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Tidaklah beriman seseorang dari kalian sehingga dia mencintai untuk saudaranya sebagaimana dia mencintai untuk dirinya sendiri\". "},"13":{"ar":"حَدَّثَنَا أَبُو الْيَمَانِ قَالَ أَخْبَرَنَا شُعَيْبٌ قَالَ حَدَّثَنَا أَبُو الزِّنَادِ عَنْ الْأَعْرَجِ عَنْ أَبِي هُرَيْرَةَ رَضِيَ اللَّهُ عَنْهُأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ فَوَالَّذِي نَفْسِي بِيَدِهِ لَا يُؤْمِنُ أَحَدُكُمْ حَتَّى أَكُونَ أَحَبَّ إِلَيْهِ مِنْ وَالِدِهِ وَوَلَدِهِ","id":"Telah menceritakan kepada kami [Abu Al Yaman] berkata, telah mengabarkan kepada kami [Syu'aib] berkata, telah menceritakan kepada kami [Abu Az Zanad] dari [Al A'raj] dari [Abu Hurairah], bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Maka demi Zat yang jiwaku di tangan-Nya, tidaklah beriman seorang dari kalian hingga aku lebih dicintainya daripada orang tuanya dan anaknya\". "},"14":{"ar":"حَدَّثَنَا يَعْقُوبُ بْنُ إِبْرَاهِيمَ قَالَ حَدَّثَنَا ابْنُ عُلَيَّةَ عَنْ عَبْدِ الْعَزِيزِ بْنِ صُهَيْبٍ عَنْ أَنَسٍ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ح و حَدَّثَنَا آدَمُ قَالَ حَدَّثَنَا شُعْبَةُ عَنْ قَتَادَةَ عَنْ أَنَسٍ قَالَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا يُؤْمِنُ أَحَدُكُمْ حَتَّى أَكُونَ أَحَبَّ إِلَيْهِ مِنْ وَالِدِهِ وَوَلَدِهِ وَالنَّاسِ أَجْمَعِينَ","id":"Telah menceritakan kepada kami [Ya'qub bin Ibrahim] berkata, telah menceritakan kepada kami [Ibnu 'Ulayyah] dari [Abdul 'Aziz bin Shuhaib] dari [Anas] dari Nabi shallallahu 'alaihi wasallam Dan telah menceritakan pula kepada kami [Adam] berkata, telah menceritakan kepada kami [Syu'bah] dari [Qotadah] dari [Anas] berkata, Nabi shallallahu 'alaihi wasallam bersabda: \"Tidaklah beriman seorang dari kalian hingga aku lebih dicintainya daripada orang tuanya, anaknya dan dari manusia seluruhnya\". "},"15":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ الْمُثَنَّى قَالَ حَدَّثَنَا عَبْدُ الْوَهَّابِ الثَّقَفِيُّ قَالَ حَدَّثَنَا أَيُّوبُ عَنْ أَبِي قِلَابَةَ عَنْ أَنَسِ بْنِ مَالِكٍ رَضِيَ اللَّهُ عَنْهُعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ ثَلَاثٌ مَنْ كُنَّ فِيهِ وَجَدَ حَلَاوَةَ الْإِيمَانِ أَنْ يَكُونَ اللَّهُ وَرَسُولُهُ أَحَبَّ إِلَيْهِ مِمَّا سِوَاهُمَا وَأَنْ يُحِبَّ الْمَرْءَ لَا يُحِبُّهُ إِلَّا لِلَّهِ وَأَنْ يَكْرَهَ أَنْ يَعُودَ فِي الْكُفْرِ كَمَا يَكْرَهُ أَنْ يُقْذَفَ فِي النَّارِ","id":"Telah menceritakan kepada kami [Muhammad bin Al Mutsanna] berkata, telah menceritakan kepada kami [Abdul Wahhab Ats Tsaqafi] berkata, telah menceritakan kepada kami [Ayyub] dari [Abu Qilabah] dari [Anas bin Malik] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Tiga perkara yang apabila ada pada diri seseorang, ia akan mendapatkan manisnya iman: Dijadikannya Allah dan Rasul-Nya lebih dicintainya dari selain keduanya. Jika ia mencintai seseorang, dia tidak mencintainya kecuali karena Allah. Dan dia benci kembali kepada kekufuran seperti dia benci bila dilempar ke neraka\""},"16":{"ar":"حَدَّثَنَا أَبُو الْوَلِيدِ قَالَ حَدَّثَنَا شُعْبَةُ قَالَ أَخْبَرَنِي عَبْدُ اللَّهِ بْنُ عَبْدِ اللَّهِ بْنِ جَبْرٍ قَالَ سَمِعْتُ أَنَسًاعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ آيَةُ الْإِيمَانِ حُبُّ الْأَنْصَارِ وَآيَةُ النِّفَاقِ بُغْضُ الْأَنْصَارِ","id":"Telah menceritakan kepada kami [Abu Al Walid] berkata, telah menceritakan kepada kami [Syu'bah] telah mengabarkan kepadaku [Abdullah bin Abdullah bin Jabar], berkata; aku mendengar [Anas] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Tanda iman adalah mencintai (kaum) Anshar dan tanda nifaq adalah membenci (kaum) Anshar\". "},"17":{"ar":"حَدَّثَنَا أَبُو الْيَمَانِ قَالَ أَخْبَرَنَا شُعَيْبٌ عَنْ الزُّهْرِيِّ قَالَ أَخْبَرَنِي أَبُو إِدْرِيسَ عَائِذُ اللَّهِ بْنُ عَبْدِ اللَّهِ أَنَّ ��ُبَادَةَ بْنَ الصَّامِتِ رَضِيَ اللَّهُ عَنْهُوَكَانَ شَهِدَ بَدْرًا وَهُوَ أَحَدُ النُّقَبَاءِ لَيْلَةَ الْعَقَبَةِ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ وَحَوْلَهُ عِصَابَةٌ مِنْ أَصْحَابِهِ بَايِعُونِي عَلَى أَنْ لَا تُشْرِكُوا بِاللَّهِ شَيْئًا وَلَا تَسْرِقُوا وَلَا تَزْنُوا وَلَا تَقْتُلُوا أَوْلَادَكُمْ وَلَا تَأْتُوا بِبُهْتَانٍ تَفْتَرُونَهُ بَيْنَ أَيْدِيكُمْ وَأَرْجُلِكُمْ وَلَا تَعْصُوا فِي مَعْرُوفٍ فَمَنْ وَفَى مِنْكُمْ فَأَجْرُهُ عَلَى اللَّهِ وَمَنْ أَصَابَ مِنْ ذَلِكَ شَيْئًا فَعُوقِبَ فِي الدُّنْيَا فَهُوَ كَفَّارَةٌ لَهُ وَمَنْ أَصَابَ مِنْ ذَلِكَ شَيْئًا ثُمَّ سَتَرَهُ اللَّهُ فَهُوَ إِلَى اللَّهِ إِنْ شَاءَ عَفَا عَنْهُ وَإِنْ شَاءَ عَاقَبَهُ فَبَايَعْنَاهُ عَلَى ذَلِك","id":"Telah menceritakan kepada kami [Abu Al Yaman] berkata, telah mengabarkan kepada kami [Syu'aib] dari [Az Zuhri] berkata, telah mengabarkan kepada kami [Abu Idris 'Aidzullah bin Abdullah], bahwa ['Ubadah bin Ash Shamit] adalah sahabat yang ikut perang Badar dan juga salah seorang yang ikut bersumpah pada malam Aqobah, dia berkata; bahwa Rasulullah shallallahu 'alaihi wasallam bersabda ketika berada ditengah-tengah sebagian sahabat: \"Berbai'atlah kalian kepadaku untuk tidak menyekutukan Allah dengan sesuatu apapun, tidak mencuri, tidak berzina, tidak membunuh anak-anak kalian, tidak membuat kebohongan yang kalian ada-adakan antara tangan dan kaki kalian, tidak bermaksiat dalam perkara yang ma'ruf. Barangsiapa diantara kalian yang memenuhinya maka pahalanya ada pada Allah dan barangsiapa yang melanggar dari hal tersebut lalu Allah menghukumnya di dunia maka itu adalah kafarat baginya, dan barangsiapa yang melanggar dari hal-hal tersebut kemudian Allah menutupinya (tidak menghukumnya di dunia) maka urusannya kembali kepada Allah, jika Dia mau, dimaafkannya atau disiksanya\". Maka kami membai'at Beliau untuk perkara-perkara tersebut. "},"18":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مَسْلَمَةَ عَنْ مَالِكٍ عَنْ عَبْدِ الرَّحْمَنِ بْنِ عَبْدِ اللَّهِ بْنِ عَبْدِ الرَّحْمَنِ بْنِ أَبِي صَعْصَعَةَ عَنْ أَبِيهِ عَنْ أَبِي سَعِيدٍ الْخُدْرِيِّ رَضِيَ اللَّهُ عَنْهُ أَنَّهُ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُوشِكُ أَنْ يَكُونَ خَيْرَ مَالِ الْمُسْلِمِ غَنَمٌ يَتْبَعُ بِهَا شَعَفَ الْجِبَالِ وَمَوَاقِعَ الْقَطْرِ يَفِرُّ بِدِينِهِ مِنْ الْفِتَنِ","id":"Telah menceritakan kepada kami [Abdullah bin Maslamah] dari [Malik] dari [Abdurrahman bin Abdullah bin Abdurrahman bin Abu Sha'Sha'ah] dari [bapaknya] dari [Abu Sa'id Al Khudri] bahwa dia berkata, Rasulullah shallallahu 'alaihi wasallam bersabda: \"Hampir saja terjadi (suatu zaman) harta seorang muslim yang paling baik adalah kambing yang digembalakannya di puncak gunung dan tempat-tempat terpencil, dia pergi menghindar dengan membawa agamanya disebabkan takut terkena fitnah\". "},"19":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ سَلَامٍ قَالَ أَخْبَرَنَا عَبْدَةُ عَنْ هِشَامٍ عَنْ أَبِيهِ عَنْ عَائِشَةَ قَالَتْكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا أَمَرَهُمْ أَمَرَهُمْ مِنْ الْأَعْمَالِ بِمَا يُطِيقُونَ قَالُوا إِنَّا لَسْنَا كَهَيْئَتِكَ يَا رَسُولَ اللَّهِ إِنَّ اللَّهَ قَدْ غَفَرَ لَكَ مَا تَقَدَّمَ مِنْ ذَنْبِكَ وَمَا تَأَخَّرَ فَيَغْضَبُ حَتَّى يُعْرَفَ الْغَضَبُ فِي وَجْهِهِ ثُمَّ يَقُولُ إِنَّ أَتْقَاكُمْ وَأَعْلَمَكُمْ بِاللَّهِ أَنَا","id":"Telah menceritakan kepada kami [Muhammad bin Salam] berkata, telah mengabarkan kepada kami ['Abdah] dari [Hisyam] dari [bapaknya] dari [Aisyah] berkata: \"Rasulullah shallallahu 'alaihi wasallam bila memerintahkan kepada para sahabat, Beliau memerintahkan untuk melakukan amalan yang mampu mereka kerjakan, kemudian para sahabat berkata; \"Kami tidaklah seperti engkau, ya Rasulullah, karena engkau sudah diampuni dosa-dosa yang lalu dan yang akan datang\". Maka Beliau shallallahu 'alaihi wasallam menjadi marah yang dapat terlihat dari wajahnya, kemudian bersabda: \"Sesungguhnya yang paling taqwa dan paling mengerti tentang Allah diantara kalian adalah aku\". "},"20":{"ar":"حَدَّثَنَا سُلَيْمَانُ بْنُ حَرْبٍ قَالَ حَدَّثَنَا شُعْبَةُ عَنْ قَتَادَةَ عَنْ أَنَسِ بْنِ مَالِكٍ رَضِيَ اللَّهُ عَنْهُعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ ثَلَاثٌ مَنْ كُنَّ فِيهِ وَجَدَ حَلَاوَةَ الْإِيمَانِ مَنْ كَانَ اللَّهُ وَرَسُولُهُ أَحَبَّ إِلَيْهِ مِمَّا سِوَاهُمَا وَمَنْ أَحَبَّ عَبْدًا لَا يُحِبُّهُ إِلَّا لِلَّهِ عَزَّ وَجَلَّ وَمَنْ يَكْرَهُ أَنْ يَعُودَ فِي الْكُفْرِ بَعْدَ إِذْ أَنْقَذَهُ اللَّهُ مِنْهُ كَمَا يَكْرَهُ أَنْ يُلْقَى فِي النَّارِ","id":"Telah menceritakan kepada kami [Sulaiman bin Harb] berkata, telah menceritakan kepada kami [Syu'bah] dari [Qotadah] dari [Anas bin Malik] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Tiga (perkara) yang apabila ada pada diri seseorang, ia akan mendapatkan manisnya iman: Allah dan Rasul-Nya lebih dicintainya dari selain keduanya. Dan siapa yang bila mencintai seseorang, dia tidak mencintai orang itu kecuali karena Allah 'azza wajalla. Dan siapa yang benci kembali kepada kekufuran seperti dia benci bila dilempar ke neraka\". "},"21":{"ar":"حَدَّثَنَا إِسْمَاعِيلُ قَالَ حَدَّثَنِي مَالِكٌ عَنْ عَمْرِو بْنِ يَحْيَى الْمَازِنِيِّ عَنْ أَبِيهِ عَنْ أَبِي سَعِيدٍ الْخُدْرِيِّ رَضِيَ اللَّهُ عَنْهُعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ يَدْخُلُ أَهْلُ الْجَنَّةِ الْجَنَّةَ وَأَهْلُ النَّارِ النَّارَ ثُمَّ يَقُولُ اللَّهُ تَعَالَى أَخْرِجُوا مِنْ النَّارِ مَنْ كَانَ فِي قَلْبِهِ مِثْقَالُ حَبَّةٍ مِنْ خَرْدَلٍ مِنْ إِيمَانٍ فَيُخْرَجُونَ مِنْهَا قَدْ اسْوَدُّوا فَيُلْقَوْنَ فِي نَهَرِ الْحَيَا أَوْ الْحَيَاةِ شَكَّ مَالِكٌ فَيَنْبُتُونَ كَمَا تَنْبُتُ الْحِبَّةُ فِي جَانِبِ السَّيْلِ أَلَمْ تَرَ أَنَّهَا تَخْرُجُ صَفْرَاءَ مُلْتَوِيَةًقَالَ وُهَيْبٌ حَدَّثَنَا عَمْرٌو الْحَيَاةِ وَقَالَ خَرْدَلٍ مِنْ خَيْرٍ","id":"Telah menceritakan kepada kami [Isma'il] berkata, telah menceritakan kepada kami [Malik] dari ['Amru bin Yahya Al Mazani] dari [bapaknya] dari [Abu Sa'id Al Khudri] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Ahlu surga telah masuk ke surga dan Ahlu neraka telah masuk neraka. Lalu Allah Ta'ala berfirman: \"Keluarkan dari neraka siapa yang didalam hatinya ada iman sebesar biji sawi\". Maka mereka keluar dari neraka dalam kondisi yang telah menghitam gosong kemudian dimasukkan kedalam sungai hidup atau kehidupan. -Malik ragu. - Lalu mereka tumbuh bersemi seperti tumbuhnya benih di tepi aliran sungai. Tidakkah kamu perhatikan bagaimana dia keluar dengan warna kekuningan.\"Berkata [Wuhaib] Telah menceritakan kepada kami ['Amru]: \"Kehidupan\". Dan berkata: \"Sedikit dari kebaikan\". "},"22":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ عُبَيْدِ اللَّهِ قَالَ حَدَّثَنَا إِبْرَاهِيمُ بْنُ سَعْدٍ عَنْ صَالِحٍ عَنْ ابْنِ شِهَابٍ عَنْ أَبِي أُمَامَةَ بْنِ سَهْلِ بْنِ حُنَيْفٍ أَنَّهُ سَمِعَ أَبَا سَعِيدٍ الْخُدْرِيَّ يَقُولُقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بَيْنَا أَنَا نَائِمٌ رَأَيْتُ النَّاسَ يُعْرَضُونَ عَلَيَّ وَعَلَيْهِمْ قُمُصٌ مِنْهَا مَا يَبْلُغُ الثُّدِيَّ وَمِنْهَا مَا دُونَ ذَلِكَ وَعُرِضَ عَلَيَّ عُمَرُ بْنُ الْخَطَّابِ وَعَلَيْهِ قَمِيصٌ يَجُرُّهُ قَالُوا فَمَا أَوَّلْتَ ذَلِكَ يَا رَسُولَ اللَّهِ قَالَ الدِّينَ","id":"Telah menceritakan kepada kami [Muhammad bin Ubaidillah] berkata, telah menceritakan kepada kami [Ibrahim bin Sa'd] dari [Shalih] dari [Ibnu Syihab] dari [Abu Umamah bin Sahal bin Hunaif] bahwasanya dia mendengar [Abu Said Al Khudri] berkata, Rasulullah shallallahu 'alaihi wasallam bersabda: \"Ketika aku tidur, aku bermimpi melihat orang-orang dihadapkan kepadaku. Mereka mengenakan baju, diantaranya ada yang sampai kepada buah dada dan ada yang kurang dari itu. Dan dihadapkan pula kepadaku Umar bin Al Khaththab dan dia mengenakan baju dan menyeretnya. Para sahabat bertanya: \"Apa maksudnya hal demikian menurut engkau, ya Rasulullah?\" Beliau shallallahu 'alaihi wasallam menjawab: \"Ad-Din (agama) \". "},"23":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ يُوسُفَ قَالَ أَخْبَرَنَا مَالِكُ بْنُ أَنَسٍ عَنْ ابْنِ شِهَابٍ عَنْ سَالِمِ بْنِ عَبْدِ اللَّهِ عَنْ أَبِيهِأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَرَّ عَلَى رَجُلٍ مِنْ الْأَنْصَارِ وَهُوَ يَعِظُ أَخَاهُ فِي الْحَيَاءِ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ دَعْهُ فَإِنَّ الْحَيَاءَ مِنْ الْإِيمَانِ","id":"Telah menceritakan kepada kami [Abdullah bin Yusuf] berkata, telah mengabarkan kepada kami [Malik bin Anas] dari [Ibnu Syihab] dari [Salim bin Abdullah] dari [bapaknya], bahwa Rasulullah shallallahu 'alaihi wasallam berjalan melewati seorang sahabat Anshar yang saat itu sedang memberi pengarahan saudaranya tentang malu. Maka Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tinggalkanlah dia, karena sesungguhnya malu adalah bagian dari iman\". "},"24":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مُحَمَّدٍ الْمُسْنَدِيُّ قَالَ حَدَّثَنَا أَبُو رَوْحٍ الْحَرَمِيُّ بْنُ عُمَارَةَ قَالَ حَدَّثَنَا شُعْبَةُ عَنْ وَاقِدِ بْنِ مُحَمَّدٍ قَالَ سَمِعْتُ أَبِي يُحَدِّثُ عَنْ ابْنِ عُمَرَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ أُمِرْتُ أَنْ أُقَاتِلَ النَّاسَ حَتَّى يَشْهَدُوا أَنْ لَا إِلَهَ إِلَّا اللَّهُ وَأَنَّ مُحَمَّدًا رَسُولُ اللَّهِ وَيُقِيمُوا الصَّلَاةَ وَيُؤْتُوا الزَّكَاةَ فَإِذَا فَعَلُوا ذَلِكَ عَصَمُوا مِنِّي دِمَاءَهُمْ وَأَمْوَالَهُمْ إِلَّا بِحَقِّ الْإِسْلَامِ وَحِسَابُهُمْ عَلَى اللَّهِ","id":"Telah menceritakan kepada kami [Abdullah bin Muhammad Al Musnadi] dia berkata, Telah menceritakan kepada kami [Abu Rauh Al Harami bin Umarah] berkata, telah menceritakan kepada kami [Syu'bah] dari [Waqid bin Muhammad] berkata; aku mendengar [bapakku] menceritakan dari [Ibnu Umar], bahwa Rasulullah shallallahu 'alaihi wasallam telah bersabda: \"Aku diperintahkan untuk memerangi manusia hingga mereka bersaksi; tidak ada ilah kecuali Allah dan bahwa sesungguhnya Muhammad adalah utusan Allah, menegakkan shalat, menunaikan zakat. Jika mereka lakukan yang demikian maka mereka telah memelihara darah dan harta mereka dariku kecuali dengan haq Islam dan perhitungan mereka ada pada Allah\""},"25":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ يُونُسَ وَمُوسَى بْنُ إِسْمَاعِيلَ قَالَا حَدَّثَنَا إِبْرَاهِيمُ بْنُ سَعْدٍ قَالَ حَدَّثَنَا ابْنُ شِهَابٍ عَنْ سَعِيدِ بْنِ الْمُسَيَّبِ عَنْ أَبِي هُرَيْرَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ سُئِلَ أ��يُّ الْعَمَلِ أَفْضَلُ فَقَالَ إِيمَانٌ بِاللَّهِ وَرَسُولِهِ قِيلَ ثُمَّ مَاذَا قَالَ الْجِهَادُ فِي سَبِيلِ اللَّهِ قِيلَ ثُمَّ مَاذَا قَالَ حَجٌّ مَبْرُورٌ","id":"Telah menceritakan kepada kami [Ahmad bin Yunus] dan [Musa bin Isma'il] keduanya berkata, telah menceritakan kepada kami [Ibrahim bin Sa'd] berkata, telah menceritakan kepada kami [Ibnu Syihab] dari [Sa'id bin Al Musayyab] dari [Abu Hurairah], bahwa Rasulullah shallallahu 'alaihi wasallam ditanya tentang Islam, manakah yang paling utama? Maka Rasulullah shallallahu 'alaihi wasallam menjawab: \"Iman kepada Allah dan Rasul-Nya\". Lalu ditanya lagi: \"Lalu apa?\" Beliau menjawab: \"Al Jihad fi sabilillah (berperang di jalan Allah). Lalu ditanya lagi: \"Kemudian apa lagi?\" Jawab Beliau shallallahu 'alaihi wasallam: \"haji mabrur\". "},"26":{"ar":"حَدَّثَنَا أَبُو الْيَمَانِ قَالَ أَخْبَرَنَا شُعَيْبٌ عَنْ الزُّهْرِيِّ قَالَ أَخْبَرَنِي عَامِرُ بْنُ سَعْدِ بْنِ أَبِي وَقَّاصٍ عَنْ سَعْدٍ رَضِيَ اللَّهُ عَنْهُأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَعْطَى رَهْطًا وَسَعْدٌ جَالِسٌ فَتَرَكَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ رَجُلًا هُوَ أَعْجَبُهُمْ إِلَيَّ فَقُلْتُ يَا رَسُولَ اللَّهِ مَا لَكَ عَنْ فُلَانٍ فَوَاللَّهِ إِنِّي لَأَرَاهُ مُؤْمِنًا فَقَالَ أَوْ مُسْلِمًا فَسَكَتُّ قَلِيلًا ثُمَّ غَلَبَنِي مَا أَعْلَمُ مِنْهُ فَعُدْتُ لِمَقَالَتِي فَقُلْتُ مَا لَكَ عَنْ فُلَانٍ فَوَاللَّهِ إِنِّي لَأَرَاهُ مُؤْمِنًا فَقَالَ أَوْ مُسْلِمًا ثُمَّ غَلَبَنِي مَا أَعْلَمُ مِنْهُ فَعُدْتُ لِمَقَالَتِي وَعَادَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ثُمَّ قَالَ يَا سَعْدُ إِنِّي لَأُعْطِي الرَّجُلَ وَغَيْرُهُ أَحَبُّ إِلَيَّ مِنْهُ خَشْيَةَ أَنْ يَكُبَّهُ اللَّهُ فِي النَّارِوَرَوَاهُ يُونُسُ وَصَالِحٌ وَمَعْمَرٌ وَابْنُ أَخِي الزُّهْرِيِّ عَنْ الزُّهْرِيِّ","id":"Telah menceritakan kepada kami [Abu Al Yaman] berkata, telah mengabarkan kepada kami [Syu'aib] dari [Az Zuhri] berkata, telah mengabarkan kepadaku ['Amir bin Sa'd bin Abu Waqash] dari [Sa'd], bahwa Rasulullah shallallahu 'alaihi wasallam memberikan makanan kepada beberapa orang dan saat itu Sa'd sedang duduk. Tetapi Beliau tidak memberi makanan tersebut kepada seorang laki-laki, padahal orang tersebut yang paling berkesan bagiku diantara mereka yang ada, maka aku bertanya kepada Rasulullah shallallahu 'alaihi wasallam: \"Wahai Rasulullah, bagaimana dengan si fulan? Sungguh aku melihat dia sebagai seorang mu'min.\" Nabi shallallahu 'alaihi wasallam membalas: \"atau dia muslim?\" Kemudian aku terdiam sejenak, dan aku terdorong untuk lebih memastikan apa yang dimaksud Beliau shallallahu 'alaihi wasallam, maka aku ulangi ucapanku: \"Wahai Rasulullah, bagaimana dengan si fulan? Sungguh aku memandangnya sebagai seorang mu'min.\" Nabi shallallahu 'alaihi wasallam membalas: \"atau dia muslim?\" Lalu aku terdorong lagi untuk lebih memastikan apa yang dimaksudnya hingga aku ulangi lagi pertanyaanku. Lalu Nabi shallallahu 'alaihi wasallam bersabda: \"Wahai Sa'd, sesungguhnya aku juga akan memberi kepada orang tersebut. Namun aku lebih suka memberi kepada yang lainnya dari pada memberi kepada dia, karena aku takut kalau Allah akan mencampakkannya ke neraka\". [Yunus], [Shalih], [Ma'mar] dan [keponakan Az Zuhri], telah meriwayatkan dari [Az Zuhri] "},"27":{"ar":"حَدَّثَنَا قُتَيْبَةُ قَالَ حَدَّثَنَا اللَّيْثُ عَنْ يَزِيدَ بْنِ أَبِي حَبِيبٍ عَنْ أَبِي الْخَيْرِ عَنْ عَبْدِ اللَّهِ بْنِ عَمْرٍوأَنَّ رَجُلًا سَأَلَ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَيُّ الْإِسْلَامِ خَيْرٌ قَالَ تُطْعِمُ الطَّعَامَ وَتَقْرَأُ السَّلَامَ عَلَى مَنْ عَرَفْتَ وَمَنْ لَمْ تَعْرِفْ","id":"Telah menceritakan kepada kami [Qutaibah] berkata, telah menceritakan kepada kami [Al Laits] dari [Yazid bin Abu Habib] dari [Abu Al Khair] dari [Abdullah bin 'Amru] bahwa ada seseorang bertanya kepada Rasulullah shallallahu 'alaihi wasallam; \"Islam manakah yang paling baik?\" Nabi shallallahu 'alaihi wasallam menjawab: \"Kamu memberi makan dan memberi salam kepada orang yang kamu kenal dan yang tidak kamu kenal\". "},"28":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مَسْلَمَةَ عَنْ مَالِكٍ عَنْ زَيْدِ بْنِ أَسْلَمَ عَنْ عَطَاءِ بْنِ يَسَارٍ عَنْ ابْنِ عَبَّاسٍ قَالَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أُرِيتُ النَّارَ فَإِذَا أَكْثَرُ أَهْلِهَا النِّسَاءُ يَكْفُرْنَ قِيلَ أَيَكْفُرْنَ بِاللَّهِ قَالَ يَكْفُرْنَ الْعَشِيرَ وَيَكْفُرْنَ الْإِحْسَانَ لَوْ أَحْسَنْتَ إِلَى إِحْدَاهُنَّ الدَّهْرَ ثُمَّ رَأَتْ مِنْكَ شَيْئًا قَالَتْ مَا رَأَيْتُ مِنْكَ خَيْرًا قَطُّ","id":"Telah menceritakan kepada kami [Abdullah bin Maslamah] dari [Malik] dari [Zaid bin Aslam] dari ['Atho' bin Yasar] dari [Ibnu 'Abbas] berkata, Nabi shallallahu 'alaihi wasallam bersabda: \"Aku diperlihatkan neraka, ternyata kebanyakan penghuninya adalah wanita. Karena mereka sering mengingkari\". Ditanyakan: \"Apakah mereka mengingkari Allah?\" Beliau bersabda: \"Mereka mengingkari pemberian suami, mengingkari kebaikan. Seandainya kamu berbuat baik terhadap seseorang dari mereka sepanjang masa, lalu dia melihat satu saja kejelekan darimu maka dia akan berkata: 'aku belum pernah melihat kebaikan sedikitpun darimu\". "},"29":{"ar":"حَدَّثَنَا سُلَيْمَانُ بْنُ حَرْبٍ قَالَ حَدَّثَنَا شُعْبَةُ عَنْ وَاصِلٍ الْأَحْدَبِ عَنْ الْمَعْرُورِ بْنِ سُوَيْدٍ قَالَ لَقِيتُ أَبَا ذَرٍّبِالرَّبَذَةِ وَعَلَيْهِ حُلَّةٌ وَعَلَى غُلَامِهِ حُلَّةٌ فَسَأَلْتُهُ عَنْ ذَلِكَ فَقَالَ إِنِّي سَابَبْتُ رَجُلًا فَعَيَّرْتُهُ بِأُمِّهِ فَقَالَ لِي النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَا أَبَا ذَرٍّ أَعَيَّرْتَهُ بِأُمِّهِ إِنَّكَ امْرُؤٌ فِيكَ جَاهِلِيَّةٌ إِخْوَانُكُمْ خَوَلُكُمْ جَعَلَهُمْ اللَّهُ تَحْتَ أَيْدِيكُمْ فَمَنْ كَانَ أَخُوهُ تَحْتَ يَدِهِ فَلْيُطْعِمْهُ مِمَّا يَأْكُلُ وَلْيُلْبِسْهُ مِمَّا يَلْبَسُ وَلَا تُكَلِّفُوهُمْ مَا يَغْلِبُهُمْ فَإِنْ كَلَّفْتُمُوهُمْ فَأَعِينُوهُمْ","id":"Telah menceritakan kepada kami [Sulaiman bin Harb] berkata, telah menceritakan kepada kami [Syu'bah] dari [Washil Al Ahdab] dari [Al Ma'rur bin Suwaid] berkata: Aku bertemu [Abu Dzar] di Rabdzah yang saat itu mengenakan pakaian dua lapis, begitu juga anaknya, maka aku tanyakan kepadanya tentang itu, maka dia menjawab: Aku telah menghina seseorang dengan cara menghina ibunya, maka Nabi shallallahu 'alaihi wasallam menegurku: \"Wahai Abu Dzar apakah kamu menghina ibunya? Sesungguhnya kamu masih memiliki (sifat) jahiliyyah. Saudara-saudara kalian adalah tanggungan kalian, Allah telah menjadikan mereka di bawah tangan kalian. Maka siapa yang saudaranya berada di bawah tangannya (tanggungannya) maka jika dia makan berilah makanan seperti yang dia makan, bila dia berpakaian berilah seperti yang dia pakai, janganlah kalian membebani mereka sesuatu yang di luar batas kemampuan mereka. Jika kalian membebani mereka, maka bantulah mereka\". "},"30":{"ar":"حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ الْمُبَارَكِ حَدَّثَنَا حَمَّادُ بْنُ زَيْدٍ حَدَّثَنَا أَيُّوبُ وَيُونُسُ عَنْ الْحَسَنِ عَنْ الْأَحْنَفِ بْنِ قَيْسٍ قَالَذَهَبْتُ لِأَنْصُرَ هَذَا الرَّجُلَ فَلَقِيَنِي أَبُو بَكْرَةَ فَقَالَ أَيْنَ تُرِيدُ قُلْتُ أَنْصُرُ هَذَا الرَّجُلَ قَالَ ارْجِعْ فَإِنِّي سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ إِذَا الْتَقَى الْمُسْلِمَانِ بِسَيْفَيْهِمَا فَالْقَاتِلُ وَالْمَقْتُولُ فِي النَّارِ فَقُلْتُ يَا رَسُولَ اللَّهِ هَذَا الْقَاتِلُ فَمَا بَالُ الْمَقْتُولِ قَالَ إِنَّهُ كَانَ حَرِيصًا عَلَى قَتْلِ صَاحِبِهِ","id":"Telah menceritakan kepada kami [Abdurrahman bin Al Mubarak] Telah menceritakan kepada kami [Hammad bin Zaid] Telah menceritakan kepada kami [Ayyub] dan [Yunus] dari [Al Hasan] dari [Al Ahnaf bin Qais] berkata; aku datang untuk menolong seseorang kemudian bertemu [Abu Bakrah], maka dia bertanya: \"Kamu mau kemana?\" Aku jawab: \"hendak menolong seseorang\" dia berkata: \"Kembalilah, karena aku pernah mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Jika dua orang muslim saling bertemu (untuk berkelahi) dengan menghunus pedang masing-masing, maka yang terbunuh dan membunuh masuk neraka\". aku pun bertanya: \"Wahai Rasulullah, ini bagi yang membunuh, tapi bagaimana dengan yang terbunuh?\" Maka Nabi shallallahu 'alaihi wasallam menjawab: \"Dia juga sebelumnya sangat ingin untuk membunuh temannya\". "},"31":{"ar":"حَدَّثَنَا أَبُو الْوَلِيدِ قَالَ حَدَّثَنَا شُعْبَةُ ح قَالَ و حَدَّثَنِي بِشْرُ بْنُ خَالِدٍ أَبُو مُحَمَّدٍ الْعَسْكَرِيُّ قَالَ حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ عَنْ شُعْبَةَ عَنْ سُلَيْمَانَ عَنْ إِبْرَاهِيمَ عَنْ عَلْقَمَةَ عَنْ عَبْدِ اللَّهِ قَالَلَمَّا نَزَلَتْ{ الَّذِينَ آمَنُوا وَلَمْ يَلْبِسُوا إِيمَانَهُمْ بِظُلْمٍ }قَالَ أَصْحَابُ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَيُّنَا لَمْ يَظْلِمْ فَأَنْزَلَ اللَّهُ عَزَّ وَجَلَّ{ إِنَّ الشِّرْكَ لَظُلْمٌ عَظِيمٌ }","id":"Telah menceritakan kepada kami [Abu Al Walid] berkata, telah menceritakan kepada kami [Syu'bah] dan juga telah meriwayatkan hadits yang serupa ini, Telah menceritakan kepadaku [Bisyir bin Khalid Abu Muhammad Al 'Asykari] berkata, telah menceritakan kepada kami [Muhammad bin Ja'far] dari [Syu'bah] dari [Sulaiman] dari [Ibrahim] dari [Alqamah] dari [Abdullah] berkata: ketika turun ayat: \"Orang-orang beriman dan tidak mencampur adukkan iman mereka dengan kezhaliman\" para sahabat Rasulullah shallallahu 'alaihi wasallam bertanya: \"Siapakah diantara kami yang tidak berbuat zhalim? Maka Allah 'azza wajalla menurunkan (firman-Nya): \"Sesungguhnya kesyirikan adalah kezhaliman yang besar\". (QS. Luqman: 13) "},"32":{"ar":"حَدَّث��نَا سُلَيْمَانُ أَبُو الرَّبِيعِ قَالَ حَدَّثَنَا إِسْمَاعِيلُ بْنُ جَعْفَرٍ قَالَ حَدَّثَنَا نَافِعُ بْنُ مَالِكِ بْنِ أَبِي عَامِرٍ أَبُو سُهَيْلٍ عَنْ أَبِيهِ عَنْ أَبِي هُرَيْرَةَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ آيَةُ الْمُنَافِقِ ثَلَاثٌ إِذَا حَدَّثَ كَذَبَ وَإِذَا وَعَدَ أَخْلَفَ وَإِذَا اؤْتُمِنَ خَانَ","id":"Telah menceritakan kepada kami [Sulaiman Abu ar Rabi'] berkata, telah menceritakan kepada kami [Isma'il bin Ja'far] berkata, telah menceritakan kepada kami [Nafi' bin Malik bin Abu 'Amir Abu Suhail] dari [bapaknya] dari [Abu Hurairah] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Tanda-tanda munafiq ada tiga; jika berbicara dusta, jika berjanji mengingkari dan jika diberi amanat dia khianat\". "},"33":{"ar":"حَدَّثَنَا قَبِيصَةُ بْنُ عُقْبَةَ قَالَ حَدَّثَنَا سُفْيَانُ عَنْ الْأَعْمَشِ عَنْ عَبْدِ اللَّهِ بْنِ مُرَّةَ عَنْ مَسْرُوقٍ عَنْ عَبْدِ اللَّهِ بْنِ عَمْرٍوأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ أَرْبَعٌ مَنْ كُنَّ فِيهِ كَانَ مُنَافِقًا خَالِصًا وَمَنْ كَانَتْ فِيهِ خَصْلَةٌ مِنْهُنَّ كَانَتْ فِيهِ خَصْلَةٌ مِنْ النِّفَاقِ حَتَّى يَدَعَهَا إِذَا اؤْتُمِنَ خَانَ وَإِذَا حَدَّثَ كَذَبَ وَإِذَا عَاهَدَ غَدَرَ وَإِذَا خَاصَمَ فَجَرَتَابَعَهُ شُعْبَةُ عَنْ الْأَعْمَشِ","id":"Telah menceritakan kepada kami [Qabishah bin 'Uqbah] berkata, telah menceritakan kepada kami [Sufyan] dari [Al A'masy] dari [Abdullah bin Murrah] dari [Masruq] dari [Abdullah bin 'Amru] bahwa Nabi shallallahu 'alaihi wasallam bersabda: \"Empat hal bila ada pada seseorang maka dia adalah seorang munafiq tulen, dan barangsiapa yang terdapat pada dirinya satu sifat dari empat hal tersebut maka pada dirinya terdapat sifat nifaq hingga dia meninggalkannya. Yaitu, jika diberi amanat dia khianat, jika berbicara dusta, jika berjanji mengingkari dan jika berseteru curang\". Hadits ini diriwayatkan pula oleh [Syu'bah] dari [Al A'masy]. "},"34":{"ar":"حَدَّثَنَا أَبُو الْيَمَانِ قَالَ أَخْبَرَنَا شُعَيْبٌ قَالَ حَدَّثَنَا أَبُو الزِّنَادِ عَنْ الْأَعْرَجِ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ يَقُمْ لَيْلَةَ الْقَدْرِ إِيمَانًا وَاحْتِسَابًا غُفِرَ لَهُ مَا تَقَدَّمَ مِنْ ذَنْبِهِ","id":"Telah menceritakan kepada kami [Abu Al Yaman] berkata, telah mengabarkan kepada kami [Syu'aib] berkata, telah menceritakan kepada kami [Abu Al Zanad] dari [Al A'raj] dari [Abu Hurairah] berkata, Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa menegakkan lailatul qodar karena iman dan mengharap pahala, maka diampuni dosa-dosanya yang telah lalu\". "},"35":{"ar":"حَدَّثَنَا حَرَمِيُّ بْنُ حَفْصٍ قَالَ حَدَّثَنَا عَبْدُ الْوَاحِدِ قَالَ حَدَّثَنَا عُمَارَةُ قَالَ حَدَّثَنَا أَبُو زُرْعَةَ بْنُ عَمْرِو بْنِ جَرِيرٍ قَالَ سَمِعْتُ أَبَا هُرَيْرَةَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ انْتَدَبَ اللَّهُ لِمَنْ خَرَجَ فِي سَبِيلِهِ لَا يُخْرِجُهُ إِلَّا إِيمَانٌ بِي وَتَصْدِيقٌ بِرُسُلِي أَنْ أُرْجِعَهُ بِمَا نَالَ مِنْ أَجْرٍ أَوْ غَنِيمَةٍ أَوْ أُدْخِلَهُ الْجَنَّةَ وَلَوْلَا أَنْ أَشُقَّ عَلَى أُمَّتِي مَا قَعَدْتُ خَلْفَ سَرِيَّةٍ وَلَوَدِدْتُ أَنِّي أُقْتَلُ فِي سَبِيلِ اللَّهِ ثُمَّ أُحْيَا ثُمَّ أُقْتَلُ ثُمَّ أُحْيَا ثُمَّ أُقْتَلُ","id":"Telah menceritakan kepada kami [Harami bin Hafsh] berkata, telah menceritakan kepada kami [Abdul Wahid] berkata, telah menceritakan kepada kami [Umarah] berkata, telah menceritakan kepada kami [Abu Zur'ah bin 'Amru bin Jarir] berkata: Aku mendengar [Abu Hurairah] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Allah menjamin orang yang keluar (berperang) di jalan-Nya, tidak ada yang mendorongnya keluar kecuali karena iman kepada-Ku dan membenarkan para rasul-Ku untuk mengembalikannya dengan memperoleh pahala atau ghonimah atau memasukkannya ke surga. Kalau seandainya tidak memberatkan umatku tentu aku tidak akan duduk tinggal diam di belakang sariyyah (pasukan khusus) dan tentu aku ingin sekali bila aku terbunuh di jalan Allah lalu aku dihidupkan lagi kemudian terbunuh lagi lalu aku dihidupkan kembali kemudian terbunuh lagi\". "},"36":{"ar":"حَدَّثَنَا إِسْمَاعِيلُ قَالَ حَدَّثَنِي مَالِكٌ عَنْ ابْنِ شِهَابٍ عَنْ حُمَيْدِ بْنِ عَبْدِ الرَّحْمَنِ عَنْ أَبِي هُرَيْرَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ قَامَ رَمَضَانَ إِيمَانًا وَاحْتِسَابًا غُفِرَ لَهُ مَا تَقَدَّمَ مِنْ ذَنْبِهِ","id":"Telah menceritakan kepada kami [Isma'il] berkata, telah menceritakan kepadaku [Malik] dari [Ibnu Syihab] dari [Humaid bin Abdurrahman] dari [Abu Hurairah] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa menegakkan Ramadlan karena iman dan mengharap pahala, maka diampuni dosa-dosanya yang telah lalu\". "},"37":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ سَلَامٍ قَالَ أَخْبَرَنَا مُحَمَّدُ بْنُ فُضَيْلٍ قَالَ حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ عَنْ أَبِي سَلَمَةَ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ صَامَ رَمَضَانَ إِيمَانًا وَاحْتِسَابًا غُفِرَ لَهُ مَا تَقَدَّمَ مِنْ ذَنْبِهِ","id":"Telah menceritakan kepada kami [Muhammad bin Salam] berkata, telah mengabarkan kepada kami [Muhammad bin Fudlail] berkata, telah menceritakan kepada kami [Yahya bin Sa'id] dari [Abu Salamah] dari [Abu Hurairah] berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa yang berpuasa karena iman dan mengharap pahala, maka diampuni dosa-dosanya yang telah lalu\". "},"38":{"ar":"حَدَّثَنَا عَبْدُ السَّلَامِ بْنُ مُطَهَّرٍ قَالَ حَدَّثَنَا عُمَرُ بْنُ عَلِيٍّ عَنْ مَعْنِ بْنِ مُحَمَّدٍ الْغِفَارِيِّ عَنْ سَعِيدِ بْنِ أَبِي سَعِيدٍ الْمَقْبُرِيِّ عَنْ أَبِي هُرَيْرَةَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِنَّ الدِّينَ يُسْرٌ وَلَنْ يُشَادَّ الدِّينَ أَحَدٌ إِلَّا غَلَبَهُ فَسَدِّدُوا وَقَارِبُوا وَأَبْشِرُوا وَاسْتَعِينُوا بِالْغَدْوَةِ وَالرَّوْحَةِ وَشَيْءٍ مِنْ الدُّلْجَةِ","id":"Telah menceritakan kepada kami [Abdus Salam bin Muthahhar] berkata, telah menceritakan kepada kami [Umar bin Ali] dari [Ma'an bin Muhammad Al Ghifari] dari [Sa'id bin Abu Sa'id Al Maqburi] dari [Abu Hurairah] bahwa Nabi shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya agama itu mudah, dan tidaklah seseorang mempersulit agama kecuali dia akan dikalahkan (semakin berat dan sulit). Maka berlakulah lurus kalian, mendekatlah (kepada yang benar) dan berilah kabar gembira dan minta tolonglah dengan Al Ghadwah (berangkat di awal pagi) dan ar-ruhah (berangkat setelah zhuhur) dan sesuatu dari ad-duljah ((berangkat di waktu malam) \". "},"39":{"ar":"حَدَّثَنَا عَمْرُو بْنُ خَالِدٍ قَالَ حَدَّثَنَا زُهَيْرٌ قَالَ حَدَّثَنَا أَبُو إِسْحَاقَ عَنْ الْبَرَاءِ بْنِ عَازِبٍأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ أَوَّلَ مَا قَدِمَ الْمَدِينَةَ نَزَلَ عَلَى أَجْدَادِهِ أَوْ قَالَ أَخْوَالِهِ مِنْ الْأَنْصَارِ وَأَنَّهُ صَلَّى قِبَلَ بَيْتِ الْمَقْدِسِ سِتَّةَ عَشَرَ شَهْرًا أَوْ سَبْعَةَ عَشَرَ شَهْرًا وَكَانَ يُعْجِبُهُ أَنْ تَكُونَ قِبْلَتُهُ قِبَلَ الْبَيْتِ وَأَنَّهُ صَلَّى أَوَّلَ صَلَاةٍ صَلَّاهَا صَلَاةَ الْعَصْرِ وَصَلَّى مَعَهُ قَوْمٌ فَخَرَجَ رَجُلٌ مِمَّنْ صَلَّى مَعَهُ فَمَرَّ عَلَى أَهْلِ مَسْجِدٍ وَهُمْ رَاكِعُونَ فَقَالَ أَشْهَدُ بِاللَّهِ لَقَدْ صَلَّيْتُ مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قِبَلَ مَكَّةَ فَدَارُوا كَمَا هُمْ قِبَلَ الْبَيْتِ وَكَانَتْ الْيَهُودُ قَدْ أَعْجَبَهُمْ إِذْ كَانَ يُصَلِّي قِبَلَ بَيْتِ الْمَقْدِسِ وَأَهْلُ الْكِتَابِ فَلَمَّا وَلَّى وَجْهَهُ قِبَلَ الْبَيْتِ أَنْكَرُوا ذَلِكَقَالَ زُهَيْرٌ حَدَّثَنَا أَبُو إِسْحَاقَ عَنْ الْبَرَاءِ فِي حَدِيثِهِ هَذَا أَنَّهُ مَاتَ عَلَى الْقِبْلَةِ قَبْلَ أَنْ تُحَوَّلَ رِجَالٌ وَقُتِلُوا فَلَمْ نَدْرِ مَا نَقُولُ فِيهِمْ فَأَنْزَلَ اللَّهُ تَعَالَى{ وَمَا كَانَ اللَّهُ لِيُضِيعَ إِيمَانَكُمْ }","id":"Telah menceritakan kepada kami ['Amru bin Khalid] berkata, telah menceritakan kepada kami [Zuhair] berkata, telah menceritakan kepada kami [Abu Ishaq] dari [Al Barro` bin 'Azib] bahwa Nabi shallallahu 'alaihi wasallam saat pertama kali datang di Madinah, singgah pada kakek-kakeknya ('Azib) atau paman-pamannya dari Kaum Anshar, dan saat itu Beliau shallallahu 'alaihi wasallam shalat menghadap Baitul Maqdis selama enam belas bulan atau tujuh belas bulan, dan Beliau sangat senang sekali kalau shalat menghadap Baitullah (Ka'bah). Shalat yang dilakukan Beliau shallallahu 'alaihi wasallam pertama kali (menghadap Ka'bah) itu adalah shalat 'ashar dan orang-orang juga ikut shalat bersama Beliau. Pada suatu hari sahabat yang ikut shalat bersama Nabi shallallahu 'alaihi wasallam pergi melewati orang-orang di Masjid lain saat mereka sedang ruku', maka dia berkata: \"Aku bersaksi kepada Allah bahwa aku ikut shalat bersama Rasulullah shallallahu 'alaihi wasallam menghadap Makkah, maka orang-orang yang sedang (ruku') tersebut berputar menghadap Baitullah dan orang-orang Yahudi dan Ahlul Kitab menjadi heran, sebab sebelumnya Nabi shallallahu 'alaihi wasallam shalat menghadap Baitul Maqdis. Ketika melihat Nabi shallallahu 'alaihi wasallam menghadapkan wajahnya ke Baitullah mereka mengingkari hal ini. Berkata Zuhair Telah menceritakan kepada kami Abu Ishaq dari Al Barro`, dalam haditsnya ini menerangkan tentang (hukum) seseorang yang meninggal dunia pada saat arah qiblat belum dialihkan dan juga banyak orang-orang yang terbunuh pada masa itu?, kami tidak tahu apa yang harus kami sikapi tentang mereka hingga akhirnya Allah Ta'ala menurunkan firman-Nya: \"Dan Allah tidaklah akan menyia-nyiakan iman kalian\". (QS. Al Baqoroh: 143) "},"40":{"ar":"حَدَّثَنَا إِسْحَاقُ بْنُ مَنْصُورٍ قَالَ حَدَّثَنَا عَبْدُ الرَّزَّاقِ قَالَ أَخْبَرَنَا مَعْمَرٌ عَنْ هَمَّامِ بْنِ مُنَبِّهٍ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا أَحْسَنَ أَحَدُكُمْ إِسْلَامَهُ فَكُلُّ حَسَنَةٍ يَعْمَلُهَا تُكْتَبُ لَهُ بِعَشْرِ أَمْثَالِهَا إِلَى سَبْعِ مِائَةِ ضِعْفٍ وَكُلُّ سَيِّئَةٍ يَعْمَلُهَا تُكْتَبُ لَهُ بِمِثْلِهَا","id":"Telah menceritakan kepada kami [Ishaq bin Manshur] berkata, telah menceritakan kepada kami [Abdurrazzaq] berkata, telah mengabarkan kepada kami [Ma'mar] dari [Hamam bin Munabbih] dari [Abu Hurairah] berkata, Rasulullah shallallahu 'alaihi wasallam bersabda: \"Apabila seorang dari kalian memperbaiki keIslamannya maka dari setiap kebaikan akan ditulis baginya sepuluh (kebaikan) yang serupa hingga tujuh ratus tingkatan, dan setiap satu kejelekan yang dikerjakan akan ditulis satu kejelekan saja yang serupa dengannya\". "},"41":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ الْمُثَنَّى حَدَّثَنَا يَحْيَى عَنْ هِشَامٍ قَالَ أَخْبَرَنِي أَبِي عَنْ عَائِشَةَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ دَخَلَ عَلَيْهَا وَعِنْدَهَا امْرَأَةٌ قَالَ مَنْ هَذِهِ قَالَتْ فُلَانَةُ تَذْكُرُ مِنْ صَلَاتِهَا قَالَ مَهْ عَلَيْكُمْ بِمَا تُطِيقُونَ فَوَاللَّهِ لَا يَمَلُّ اللَّهُ حَتَّى تَمَلُّوا وَكَانَ أَحَبَّ الدِّينِ إِلَيْهِ مَادَامَ عَلَيْهِ صَاحِبُهُ","id":"Telah menceritakan kepada kami [Muhammad bin Al Mutsanna] berkata, telah menceritakan kepada kami [Yahya] dari [Hisyam] berkata, telah mengabarkan [bapakku] kepadaku dari [Aisyah] bahwa Nabi shallallahu 'alaihi wasallam mendatanginya dan bersamanya ada seorang wanita lain, lalu Nabi shallallahu 'alaihi wasallam bertanya: \"siapa ini?\" Aisyah menjawab: \"si fulanah\", Lalu diceritakan tentang shalatnya. Maka Nabi shallallahu 'alaihi wasallam bersabda: \"tinggalkanlah apa yang tidak kalian sanggupi, demi Allah, Allah tidak akan bosan hingga kalian sendiri yang menjadi bosan, dan agama yang paling dicintai-Nya adalah apa yang senantiasa dikerjakan secara rutin dan kontinyu\". "},"42":{"ar":"حَدَّثَنَا مُسْلِمُ بْنُ إِبْرَاهِيمَ قَالَ حَدَّثَنَا هِشَامٌ قَالَ حَدَّثَنَا قَتَادَةُ عَنْ أَنَسٍعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ يَخْرُجُ مِنْ النَّارِ مَنْ قَالَ لَا إِلَهَ إِلَّا اللَّهُ وَفِي قَلْبِهِ وَزْنُ شَعِيرَةٍ مِنْ خَيْرٍ وَيَخْرُجُ مِنْ النَّارِ مَنْ قَالَ لَا إِلَهَ إِلَّا اللَّهُ وَفِي قَلْبِهِ وَزْنُ بُرَّةٍ مِنْ خَيْرٍ وَيَخْرُجُ مِنْ النَّارِ مَنْ قَالَ لَا إِلَهَ إِلَّا اللَّهُ وَفِي قَلْبِهِ وَزْنُ ذَرَّةٍ مِنْ خَيْرٍقَالَ أَبُو عَبْد اللَّهِ قَالَ أَبَانُ حَدَّثَنَا قَتَادَةُ حَدَّثَنَا أَنَسٌ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِنْ إِيمَانٍ مَكَانَ مِنْ خَيْرٍ","id":"Telah menceritakan kepada kami [Muslim bin Ibrahim] berkata, telah menceritakan kepada kami [Hisyam] berkata, telah menceritakan kepada kami [Qotadah] dari [Anas] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Akan dikeluarkan dari neraka siapa yang mengatakan tidak ada Ilah kecuali Allah dan dalam hatinya ada kebaikan sebesar jemawut. Dan akan dikeluarkan dari neraka siapa yang mengatakan tidak ada ilah kecuali Allah dan dalam hatinya ada kebaikan sebesar biji gandum. Dan akan dikeluarkan dari neraka siapa yang mengatakan tidak ada ilah kecuali Allah dan dalam hatinya ada kebaikan sebesar biji sawi. Abu Abdullah berkata; [Aban] berkata; Telah menceritakan kepada kami [Qotadah] Telah menceritakan kepada kami [Anas] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda. Dan kata iman di dalam hadits ini diganti dengan kata kebaikan. "},"43":{"ar":"حَدَّثَنَا الْحَسَنُ بْنُ الصَّبَّاحِ سَمِعَ جَعْفَرَ بْنَ عَوْنٍ حَدَّثَنَا أَبُو الْعُمَيْسِ أَخْبَرَنَا قَيْسُ بْنُ مُسْلِمٍ عَنْ طَارِقِ بْنِ شِهَابٍ عَنْ عُمَرَ بْنِ الْخَطَّابِأَنَّ رَجُلًا مِنْ الْيَهُودِ قَالَ لَهُ يَا أَمِيرَ الْمُؤْمِنِينَ آيَةٌ فِي كِتَابِكُمْ تَقْرَءُونَهَا لَوْ عَلَيْنَا مَعْشَرَ الْيَهُودِ نَزَلَتْ لَاتَّخَذْنَا ذَلِكَ الْيَوْمَ عِيدًا قَالَ أَيُّ آيَةٍ قَالَ{ الْيَوْمَ أَكْمَلْتُ لَكُمْ دِينَكُمْ وَأَتْمَمْتُ عَلَيْكُمْ نِعْمَتِي وَرَضِيتُ لَكُمْ الْإِسْلَامَ دِينًا }قَالَ عُمَرُ قَدْ عَرَفْنَا ذَلِكَ الْيَوْمَ وَالْمَكَانَ الَّذِي نَزَلَتْ فِيهِ عَلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَهُوَ قَائِمٌ بِعَرَفَةَ يَوْمَ جُمُعَةٍ","id":"Telah menceritakan kepada kami [Al Hasan bin Ash Shabbah] bahwa dia mendengar [Ja'far bin 'Aun] berkata; Telah menceritakan kepada kami [Abu Al 'Umais], telah mengabarkan kepada kami [Qais bin Muslim] dari [Thariq bin Syihab] dari [Umar bin Al Khaththab]; Ada seorang laki-laki Yahudi berkata: \"Wahai Amirul Mu'minin, ada satu ayat dalam kitab kalian yang kalian baca, seandainya ayat itu diturunkan kepada kami Kaum Yahudi, tentulah kami jadikan (hari diturunkannya ayat itu) sebagai hari raya ('ied). Maka Umar bin Al Khaththab berkata: \"Ayat apakah itu?\" (Orang Yahudi itu) berkata: \"Pada hari ini telah Kusempurnakan untuk kalian agama kalian, dan telah Ku-cukupkan kepada kalian nikmat-Ku, dan telah Ku-ridhai Islam itu jadi agama bagi kalian\". (QS. Al Maidah ayat 3). Maka Umar bin Al Khaththab menjawab: \"Kami tahu hari tersebut dan dimana tempat diturunkannya ayat tersebut kepada Nabi shallallahu 'alaihi wasallam, yaitu pada hari Jum'at ketika Beliau shallallahu 'alaihi wasallam berada di 'Arafah. "},"44":{"ar":"حَدَّثَنَا إِسْمَاعِيلُ قَالَ حَدَّثَنِي مَالِكُ بْنُ أَنَسٍ عَنْ عَمِّهِ أَبِي سُهَيْلِ بْنِ مَالِكٍ عَنْ أَبِيهِ أَنَّهُ سَمِعَ طَلْحَةَ بْنَ عُبَيْدِ اللَّهِ يَقُولُجَاءَ رَجُلٌ إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِنْ أَهْلِ نَجْدٍ ثَائِرَ الرَّأْسِ يُسْمَعُ دَوِيُّ صَوْتِهِ وَلَا يُفْقَهُ مَا يَقُولُ حَتَّى دَنَا فَإِذَا هُوَ يَسْأَلُ عَنْ الْإِسْلَامِ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ خَمْسُ صَلَوَاتٍ فِي الْيَوْمِ وَاللَّيْلَةِ فَقَالَ هَلْ عَلَيَّ غَيْرُهَا قَالَ لَا إِلَّا أَنْ تَطَوَّعَ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَصِيَامُ رَمَضَانَ قَالَ هَلْ عَلَيَّ غَيْرُهُ قَالَ لَا إِلَّا أَنْ تَطَوَّعَ قَالَ وَذَكَرَ لَهُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الزَّكَاةَ قَالَ هَلْ عَلَيَّ غَيْرُهَا قَالَ لَا إِلَّا أَنْ تَطَوَّعَ قَالَ فَأَدْبَرَ الرَّجُلُ وَهُوَ يَقُولُ وَاللَّهِ لَا أَزِيدُ عَلَى هَذَا وَلَا أَنْقُصُ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَفْلَحَ إِنْ صَدَقَ","id":"Telah menceritakan kepada kami [Isma'il] Telah menceritakan kepadaku [Malik bin Anas] dari pamannya - [Abu Suhail bin Malik] - dari [bapaknya], bahwa dia mendengar [Thalhah bin 'Ubaidullah] berkata: Telah datang kepada Rasulullah shallallahu 'alaihi wasallam seorang dari penduduk Najed dalam keadaan kepalanya penuh debu dengan suaranya yang keras terdengar, namun tidak dapat dimengerti apa maksud yang diucapkannya, hingga mendekat (kepada Nabi shallallahu 'alaihi wasallam) kemudian dia bertanya tentang Islam, maka Rasulullah shallallahu 'alaihi wasallam menjawab: \"Shalat lima kali dalam sehari semalam\". Kata orang itu: \"apakah ada lagi selainnya buatku\". Nabi shallallahu 'alaihi wasallam menjawab: \"Tidak ada kecuali yang thathawu' (sunnat) \". Rasulullah shallallahu 'alaihi wasallam berkata: \"Dan puasa Ramadlan\". Orang itu bertanya lagi: \"Apakah ada lagi selainnya buatku\". Rasulullah shallallahu 'alaihi wasallam menjawab: \"Tidak ada kecuali yang thathawu' (sunnat) \". Lalu Rasulullah shallallahu 'alaihi wasallam menyebut: \"Zakat\": Kata orang itu: \"apakah ada lagi selainnya buatku\". Rasulullah shallallahu 'alaihi wasallam menjawab: \"Tidak ada kecuali yang thathawu' (sunnat) \". Thalhah bin 'Ubaidullah berkata: Lalu orang itu pergi sambil berkata: \"Demi Allah, aku tidak akan menambah atau menguranginya\". Maka Rasulullah shallallahu 'alaihi wasallam bersabda: \"Dia akan beruntung jika jujur menepatinya\". "},"45":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ عَبْدِ اللَّهِ بْنِ عَلِيٍّ الْمَنْجُوفِيُّ قَالَ حَدَّثَنَا رَوْحٌ قَالَ حَدَّثَنَا عَوْفٌ عَنْ الْحَسَنِ وَمُحَمَّدٍ عَنْ أَبِي هُرَيْرَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ اتَّبَعَ جَنَازَةَ مُسْلِمٍ إِيمَانًا وَاحْتِسَابًا وَكَانَ مَعَهُ حَتَّى يُصَلَّى عَلَيْهَا وَيَفْرُغَ مِنْ دَفْنِهَا فَإِنَّه يَرْجِعُ مِنْ الْأَجْرِ بِقِيرَاطَيْنِ كُلُّ قِيرَاطٍ مِثْلُ أُحُدٍ وَمَنْ صَلَّى عَلَيْهَا ثُمَّ رَجَعَ قَبْلَ أَنْ تُدْفَنَ فَإِنَّهُ يَرْجِعُ بِقِيرَاطٍتَابَعَهُ عُثْمَانُ الْمُؤَذِّنُ قَالَ حَدَّثَنَا عَوْفٌ عَنْ مُحَمَّدٍ عَنْ أَبِي هُرَيْرَةَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَحْوَهُ","id":"Telah menceritakan kepada kami [Ahmad bin Abdullah bin Ali Al Manjufi] berkata, telah menceritakan kepada kami [Rauh] berkata, telah menceritakan kepada kami ['Auf] dari [Al Hasan] dan [Muhammad] dari [Abu Hurairah], bahwa Rasulullah shallallahu 'alaihi wasallam telah bersabda: \"Barangsiapa mengiringi jenazah muslim, karena iman dan mengharapkan balasan dan dia selalu bersama jenazah tersebut sampai dishalatkan dan selesai dari penguburannya, maka dia pulang dengan membawa dua qiroth, setiap qiroth setara dengan gunung Uhud. Dan barangsiapa menyolatkannya dan pulang sebelum dikuburkan maka dia pulang membawa satu qiroth\". Hadits seperti ini juga diriwayatkan dari [Utsman Al Mu`adzin], dia berkata; telah menceritakan kepada kami ['Auf] dari [Muhammad] dari [Abu Hurairah] dari Nabi shallallahu 'alaihi wasallam. "},"46":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ عَرْعَرَةَ قَالَ حَدَّثَنَا شُعْبَةُ عَنْ زُبَيْدٍ قَالَ سَأَلْتُ أَبَا وَائِلٍعَنْ الْمُرْجِئَةِ فَقَالَ حَدَّثَنِي عَبْدُ اللَّهِ أَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ سِبَابُ الْمُسْلِمِ فُسُوقٌ وَقِتَالُهُ كُفْرٌ","id":"Telah menceritakan kepada kami [Muhammad bin 'Ar'arah] berkata, Telah menceritakan kepada kami [Syu'bah] dari [Zubaid] berkata: Aku bertanya kepada [Abu Wa'il] tentang Murji`ah, maka dia menjawab: Telah menceritakan kepadaku [Abdullah] bahwa Nabi shallallahu 'alaihi wasallam bersabda: \"mencerca orang muslim adalah fasiq dan memeranginya adalah kufur\". "},"47":{"ar":"أَخْبَرَنَا قُتَيْبَةُ بْنُ سَعِيدٍ حَدَّثَنَا إِسْمَاعِيلُ بْنُ جَعْفَرٍ عَنْ حُمَيْدٍ حَدَّثَنِي أَنَسُ بْنُ مَالِكٍ قَالَ أَخْبَرَنِي عُبَادَةُ بْنُ الصَّامِتِأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ خَرَجَ يُخْبِرُ بِلَيْلَةِ الْقَدْرِ فَتَلَاحَى رَجُلَانِ مِنْ الْمُسْلِمِينَ فَقَالَ إِنِّي خَرَجْتُ لِأُخْبِرَكُمْ بِلَيْلَةِ الْقَدْرِ وَإِنَّهُ تَلَاحَى فُلَانٌ وَفُلَانٌ فَرُفِعَتْ وَعَسَى أَنْ يَكُونَ خَيْرًا لَكُمْ الْتَمِسُوهَا فِي السَّبْعِ وَالتِّسْعِ وَالْخَمْسِ","id":"Telah mengabarkan kepada kami [Qutaibah bin Sa'id] Telah menceritakan kepada kami [Isma'il bin Ja'far] dari [Humaid], Telah menceritakan kepadaku [Anas bin Malik] berkata, telah mengabarkan kepadaku ['Ubadah bin Ash Shamit], bahwa Rasulullah shallallahu 'alaihi wasallam keluar untuk menjelaskan tentang Lailatul Qodar, lalu ada dua orang muslimin saling berdebat. Maka Nabi shallallahu 'alaihi wasallam bersabda: \"Aku datang untuk menjelaskan Lailatul Qodar kepada kalian, namun fulan dan fulan saling berdebat sehingga akhirnya diangkat (lailatul qodar), dan semoga menjadi lebih baik buat kalian, maka itu intailah (lailatul qodar) itu pada hari yang ketujuh, enam dan lima \". "},"48":{"ar":"حَدَّثَنَا مُسَدَّدٌ قَالَ حَدَّثَنَا إِسْمَاعِيلُ بْنُ إِبْرَاهِيمَ أَخْبَرَنَا أَبُو حَيَّانَ التَّيْمِيُّ عَنْ أَبِي زُرْعَةَ عَنْ أَبِي هُرَيْرَةَ قَالَكَانَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بَارِزًا يَوْمًا لِلنَّاسِ فَأَتَاهُ جِبْرِيلُ فَقَالَ مَا الْإِيمَانُ قَالَ الْإِيمَانُ أَنْ تُؤْمِنَ بِاللَّهِ وَمَلَائِكَتِهِ وَكُتُبِهِ وَبِلِقَائِهِ وَرُسُلِهِ وَتُؤْمِنَ بِالْبَعْثِ قَالَ مَا الْإِسْلَامُ قَالَ الْإِسْلَامُ أَنْ تَعْبُدَ اللَّهَ وَلَا تُشْرِكَ بِهِ شَيْئًا وَتُقِيمَ الصَّلَاةَ وَتُؤَدِّيَ الزَّكَاةَ الْمَفْرُوضَةَ وَتَصُومَ رَمَضَانَ قَالَ مَا الْإِحْسَانُ قَالَ أَنْ تَعْبُدَ اللَّهَ كَأَنَّكَ تَرَاهُ فَإِنْ لَمْ تَكُنْ تَرَاهُ فَإِنَّهُ يَرَاكَ قَالَ مَتَى السَّاعَةُ قَالَ مَا الْمَسْئُولُ عَنْهَا بِأَعْلَمَ مِنْ السَّائِلِ وَسَأُخْبِرُكَ عَنْ أَشْرَاطِهَا إِذَا وَلَدَتْ الْأَمَةُ رَبَّهَا وَإِذَا تَطَاوَلَ رُعَاةُ الْإِبِلِ الْبُهْمُ فِي الْبُنْيَانِ فِي خَمْسٍ لَا يَعْلَمُهُنَّ إِلَّا اللَّهُ ثُمَّ تَلَا النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ{ إِنَّ اللَّهَ عِنْدَهُ عِلْمُ السَّاعَةِ }الْآيَةَ ثُمَّ أَدْبَرَ فَقَالَ رُدُّوهُ فَلَمْ يَرَوْا شَيْئًا فَقَالَ هَذَا جِبْرِيلُ جَاءَ يُعَلِّمُ النَّاسَ دِينَهُمْقَالَ أَبُو عَبْد اللَّهِ جَعَلَ ذَلِك كُلَّهُ مِنْ الْإِيمَانِ","id":"Telah menceritakan kepada kami [Musaddad] berkata, Telah menceritakan kepada kami [Isma'il bin Ibrahim] telah mengabarkan kepada kami [Abu Hayyan At Taimi] dari [Abu Zur'ah] dari [Abu Hurairah] berkata; bahwa Nabi shallallahu 'alaihi wasallam pada suatu hari muncul kepada para sahabat, lalu datang Malaikat Jibril 'Alaihis Salam yang kemudian bertanya: \"Apakah iman itu?\" Nabi shallallahu 'alaihi wasallam menjawab: \"Iman adalah kamu beriman kepada Allah, malaikat-malaikat-Nya, kitab-kitab-Nya, pertemuan dengan-Nya, Rasul-Rasul-Nya, dan kamu beriman kepada hari berbangkit\". (Jibril 'Alaihis salam) berkata: \"Apakah Islam itu?\" Jawab Nabi shallallahu 'alaihi wasallam: \"Islam adalah kamu menyembah Allah dan tidak menyekutukannya dengan suatu apapun, kamu dirikan shalat, kamu tunaikan zakat yang diwajibkan, dan berpuasa di bulan Ramadlan\". (Jibril 'Alaihis salam) berkata: \"Apakah ihsan itu?\" Nabi shallallahu 'alaihi wasallam menjawab: \"Kamu menyembah Allah seolah-olah melihat-Nya dan bila kamu tidak melihat-Nya sesungguhnya Dia melihatmu\". (Jibril 'Alaihis salam) berkata lagi: \"Kapan terjadinya hari kiamat?\" Nabi shallallahu 'alaihi wasallam menjawab: \"Yang ditanya tentang itu tidak lebih tahu dari yang bertanya. Tapi aku akan terangkan tanda-tandanya; (yaitu); jika seorang budak telah melahirkan tuannya, jika para penggembala unta yang berkulit hitam berlomba-lomba membangun gedung-gedung selama lima masa, yang tidak diketahui lamanya kecuali oleh Allah\". Kemudian Nabi shallallahu 'alaihi wasallam membaca: \"Sesungguhnya hanya pada Allah pengetahuan tentang hari kiamat\" (QS. Luqman: 34). Setelah itu Jibril 'Alaihis salam pergi, kemudian Nabi shallallahu 'alaihi wasallam berkata; \"hadapkan dia ke sini.\" Tetapi para sahabat tidak melihat sesuatupun, maka Nabi bersabda; \"Dia adalah Malaikat Jibril datang kepada manusia untuk mengajarkan agama mereka.\" Abu Abdullah berkata: \"Semua hal yang diterangkan Beliau shallallahu 'alaihi wasallam dijadikan sebagai iman. "},"49":{"ar":"حَدَّثَنَا إِبْرَاهِيمُ بْنُ حَمْزَةَ قَالَ حَدَّثَنَا إِبْرَاهِيمُ بْنُ سَعْدٍ عَنْ صَالِحٍ عَنْ ابْنِ شِهَابٍ عَنْ عُبَيْدِ اللَّهِ بْنِ عَبْدِ اللَّهِ أَنَّ عَبْدَ اللَّهِ بْنَ عَبَّاسٍ أَخْبَرَهُ قَالَ أَخْبَرَنِي أَبُو سُفْيَانَ بْنُ حَرْبٍأَنَّ هِرَقْلَ قَالَ لَهُ سَأَلْتُكَ هَلْ يَزِيدُونَ أَمْ يَنْقُصُونَ فَزَعَمْتَ أَنَّهُمْ يَزِيدُونَ وَكَذَلِكَ الْإِيمَانُ حَتَّى يَتِمَّ وَسَأَلْتُكَ هَلْ يَرْتَدُّ أَحَدٌ سَخْطَةً لِدِينِهِ بَعْدَ أَنْ يَدْخُلَ فِيهِ فَزَعَمْتَ أَنْ لَا وَكَذَلِكَ الْإِيمَانُ حِينَ تُخَالِطُ بَشَاشَتُهُ الْقُلُوبَ لَا يَسْخَطُهُ أَحَدٌ","id":"Telah menceritakan kepada kami [Ibrahim bin Hamzah] berkata, telah menceritakan kepada kami [Ibrahim bin Sa'd] dari [Shalih] dari [Ibnu Syihab] dari [Ubaidillah bin Abdullah] bahwa [Abdullah bin 'Abbas] mengabarkan kepadanya, bahwa dia berkata; telah mengabarkan kepadaku [Abu Sufyan bin Harb] bahwa Heraqlius berkata kepadanya: \"Aku sudah bertanya kepadamu, apakah jumlah mereka bertambah atau berkurang? Maka kamu bertutur bahwa mereka bertambah, dan memang begitulah iman akan terus berkembang hingga sempurna. Dan aku bertanya kepadamu, apakah ada orang yang murtad karena dongkol pada agamanya? Kemudian kamu bertutur; tidak ada, maka begitu juga iman bila sudah tumbuh bersemi dalam hati tidak akan ada yang dongkol kepadanya\". "},"50":{"ar":"حَدَّثَنَا أَبُو نُعَيْمٍ حَدَّثَنَا زَكَرِيَّاءُ عَنْ عَامِرٍ قَالَ سَمِعْتُ النُّعْمَانَ بْنَ بَشِيرٍ يَقُولُسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ الْحَلَالُ بَيِّنٌ وَالْحَرَامُ بَيِّنٌ وَبَيْنَهُمَا مُشَبَّهَاتٌ لَا يَعْلَمُهَا كَثِيرٌ مِنْ النَّاسِ فَمَنْ اتَّقَى الْمُشَبَّهَاتِ اسْتَبْرَأَ لِدِينِهِ وَعِرْضِهِ وَمَنْ وَقَعَ فِي الشُّبُهَاتِ كَرَاعٍ يَرْعَى حَوْلَ الْحِمَى يُوشِكُ أَنْ يُوَاقِعَهُ أَلَا وَإِنَّ لِكُلِّ مَلِكٍ حِمًى أَلَا إِنَّ حِمَى اللَّهِ فِي أَرْضِهِ مَحَارِمُهُ أَلَا وَإِنَّ فِي الْجَسَدِ مُضْغَةً إِذَا صَلَحَتْ صَلَحَ الْجَسَدُ كُلُّهُ وَإِذَا فَسَدَتْ فَسَدَ الْجَسَدُ كُلُّهُ أَلَا وَهِيَ الْقَلْبُ","id":"Telah menceritakan kepada kami [Abu Nu'aim] Telah menceritakan kepada kami [Zakaria] dari ['Amir] berkata; aku mendengar [An Nu'man bin Basyir] berkata; aku mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Yang halal sudah jelas dan yang haram juga sudah jelas. Namun diantara keduanya ada perkara syubhat (samar) yang tidak diketahui oleh banyak orang. Maka barangsiapa yang menjauhi diri dari yang syubhat berarti telah memelihara agamanya dan kehormatannya. Dan barangsiapa yang sampai jatuh (mengerjakan) pada perkara-perkara syubhat, sungguh dia seperti seorang penggembala yang menggembalakan ternaknya di pinggir jurang yang dikhawatirkan akan jatuh ke dalamnya. Ketahuilah bahwa setiap raja memiliki batasan, dan ketahuilah bahwa batasan larangan Allah di bumi-Nya adalah apa-apa yang diharamkan-Nya. Dan ketahuilah pada setiap tubuh ada segumpal darah yang apabila baik maka baiklah tubuh tersebut dan apabila rusak maka rusaklah tubuh tersebut. Ketahuilah, ia adalah hati\". "},"51":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ الْجَعْدِ قَالَ أَخْبَرَنَا شُعْبَةُ عَنْ أَبِي جَمْرَةَ قَالَكُنْتُ أَقْعُدُ مَعَ ابْنِ عَبَّاسٍ يُجْلِسُنِي عَلَى سَرِيرِهِ فَقَالَ أَقِمْ عِنْدِي حَتَّى أَجْعَلَ لَكَ سَهْمًا مِنْ مَالِي فَأَقَمْتُ مَعَهُ شَهْرَيْنِ ثُمَّ قَالَ إِنَّ وَفْدَ عَبْدِ الْقَيْسِ لَمَّا أَتَوْا النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ الْقَوْمُ أَوْ مَنْ الْوَفْدُ قَالُوا رَبِيعَةُ قَالَ مَرْحَبًا بِالْقَوْمِ أَوْ بِالْوَفْدِ غَيْرَ خَزَايَا وَلَا نَدَامَى فَقَالُوا يَا رَسُولَ اللَّهِ إِنَّا لَا نَسْتَطِيعُ أَنْ نَأْتِيكَ إِلَّا فِي الشَّهْرِ الْحَرَامِ وَبَيْنَنَا وَبَيْنَكَ هَذَا الْحَيُّ مِنْ كُفَّارِ مُضَرَ فَمُرْنَا بِأَمْرٍ فَصْلٍ نُخْبِرْ بِهِ مَنْ وَرَاءَنَا وَنَدْخُلْ بِهِ الْجَنَّةَ وَسَأَلُوهُ عَنْ الْأَشْرِبَةِ فَأَمَرَهُمْ بِأَرْبَعٍ وَنَهَاهُمْ عَنْ أَرْبَعٍ أَمَرَهُمْ بِالْإِيمَانِ بِاللَّهِ وَحْدَهُ قَالَ أَتَدْرُونَ مَا الْإِيمَانُ بِاللَّهِ وَحْدَهُ قَالُوا اللَّهُ وَرَسُولُهُ أَعْلَمُ قَالَ شَهَادَةُ أَنْ لَا إِلَهَ إِلَّا اللَّهُ وَأَنَّ مُحَمَّدًا رَسُولُ اللَّهِ وَإِقَامُ الصَّلَاةِ وَإِيتَاءُ الزَّكَاةِ وَصِيَامُ رَمَضَانَ وَأَنْ تُعْطُوا مِنْ الْمَغْنَمِ الْخُمُسَ وَنَهَاهُمْ عَنْ أَرْبَعٍ عَنْ الْحَنْتَمِ وَالدُّبَّاءِ وَالنَّقِيرِ وَالْمُزَفَّتِ وَرُبَّمَا قَالَ الْمُقَيَّرِ وَقَالَ احْفَظُوهُنَّ وَأَخْبِرُوا بِهِنَّ مَنْ وَرَاءَكُمْ","id":"Telah menceritakan kepada kami [Ali bin Al Ja'di] berkata, telah mengabarkan kepada kami [Syu'bah] dari [Abu Jamrah] berkata: aku pernah duduk bersama [Ibnu 'Abbas] saat dia mempersilahkan aku duduk di permadaninya lalu berkata: \"Tinggallah bersamaku hingga aku memberimu bagian dari hartaku\". Maka aku tinggal mendampingi dia selama dua bulan, lalu berkata: Ketika utusan Abu Qais datang menemui Nabi shallallahu 'alaihi wasallam, Beliau bertanya kepada mereka: \"Kaum manakah ini atau utusan siapakah ini? Mereka menjawab: \"Rabi'ah!\" Beliau shallallahu 'alaihi wasallam bersabda: \"selamat datang wahai para utusan dengan sukarela dan tanpa menyesal\". para utusan itu berkata: \"ya Rasulullah, kami tidak dapat mendatangimu kecuali di bulan suci, karena antara kami dan engkau ada suku Mudlor yang kafir. Oleh karena itu ajarkanlah kami dengan satu pelajaran yang jelas yang dapat kami amalkan dan dapat kami ajarkan kepada orang-orang di kampung kami, yang dengan begitu kami dapat masuk surga.\" kemudian mereka bertanya kepada Nabi shallallahu 'alaihi wasallam tentang minuman, maka Nabi shallallahu 'alaihi wasallam memerintahkan mereka dengan empat hal dan melarang dari empat hal, memerintahkan mereka untuk beriman kepada Allah satu-satunya, kemudian bertanya: \"Tahukah kalian apa arti beriman kepada Allah satu-satunya?\" Mereka menjawab: \"Allah dan Rasul-Nya yang lebih mengetahui.\" Nabi shallallahu 'alaihi wasallam menjelaskan: Persaksian tidak ada ilah kecuali Allah dan bahwa Muhammad adalah utusan Allah, menegakkan shalat, menunaikan zakat, berpuasa pada bulan Ramadlan dan mengeluarkan seperlima dari harta rampasan perang\". Dan Nabi shallallahu 'alaihi wasallam melarang mereka dari empat perkara, yaitu janganlah kalian meminum sesuatu dari al hantam, ad Dubbaa`, an naqir dan al Muzaffaat. Atau Beliau shallallahu 'alaihi wasallam menyebut muqoyyir (bukan naqir). Nabi shallallahu 'alaihi wasallam bersabda: \"jagalah semuanya dan beritahukanlah kepada orang-orang di kampung kalian\". "},"52":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مَسْلَمَةَ قَالَ أَخْبَرَنَا مَالِكٌ عَنْ يَحْيَى بْنِ سَعِيدٍ عَنْ مُحَمَّدِ بْنِ إِبْرَاهِيمَ عَنْ عَلْقَمَةَ بْنِ وَقَّاصٍ عَنْ عُمَرَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ الْأَعْمَالُ بِالنِّيَّةِ وَلِكُلِّ امْرِئٍ مَا نَوَى فَمَنْ كَانَتْ هِجْرَتُهُ إِلَى اللَّهِ وَرَسُولِهِ فَهِجْرَتُهُ إِلَى اللَّهِ وَرَسُولِهِ وَمَنْ كَانَتْ هِجْرَتُهُ لدُنْيَا يُصِيبُهَا أَوْ امْرَأَةٍ يَتَزَوَّجُهَا فَهِجْرَتُهُ إِلَى مَا هَاجَرَ إِلَيْهِ","id":"Telah menceritakan kepada kami [Abdullah bin Maslamah] berkata, telah mengabarkan kepada kami [Malik] dari [Yahya bin Sa'id] dari [Muhammad bin Ibrahim] dari [Alqamah bin Waqash] dari [Umar], bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Semua perbuatan tergantung niatnya, dan (balasan) bagi tiap-tiap orang (tergantung) apa yang diniatkan; barangsiapa niat hijrahnya karena Allah dan Rasul-Nya, maka hijrahnya adalah kepada Allah dan Rasul-Nya. Barangsiapa niat hijrahnya karena dunia yang ingin digapainya atau karena seorang perempuan yang ingin dinikahinya, maka hijrahnya adalah kepada apa dia diniatkan.\". "},"53":{"ar":"حَدَّثَنَا حَجَّاجُ بْنُ مِنْهَالٍ قَالَ حَدَّثَنَا شُعْبَةُ قَالَ أَخْبَرَنِي عَدِيُّ بْنُ ثَابِتٍ قَالَ سَمِعْتُ عَبْدَ اللَّهِ بْنَ يَزِيدَ عَنْ أَبِي مَسْعُودٍعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِذَا أَنْفَقَ الرَّجُلُ عَلَى أَهْلِهِ يَحْتَسِبُهَا فَهُوَ لَهُ صَدَقَةٌ","id":"Telah menceritakan kepada kami [Hajjaj bin Minhal] berkata, telah menceritakan kepada kami [Syu'bah] berkata, telah mengabarkan kepadaku ['Adi bin Tsabit] berkata: Aku pernah mendengar [Abdullah bin Yazid] dari [Abu Mas'ud] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Apabila seseorang memberi nafkah untuk keluarganya dengan niat mengharap pahala maka baginya Sedekah\". "},"54":{"ar":"حَدَّثَنَا الْحَكَمُ بْنُ نَافِعٍ قَالَ أَخْبَرَنَا شُعَيْبٌ عَنْ الزُّهْرِيِّ قَالَ حَدَّثَنِي عَامِرُ بْنُ سَعْدٍ عَنْ سَعْدِ بْنِ أَبِي وَقَّاصٍ أَنَّهُ أَخْبَرَهُأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِنَّكَ لَنْ تُنْفِقَ نَفَقَةً تَبْتَغِي بِهَا وَجْهَ اللَّهِ إِلَّا أُجِرْتَ عَلَيْهَا حَتَّى مَا تَجْعَلُ فِي فَمِ امْرَأَتِكَ","id":"Telah menceritakan kepada kami [Al Hakam bin Nafi'] berkata, telah mengabarkan kepada kami [Syu'aib] dari [Az Zuhri] berkata, telah menceritakan kepadaku ['Amir bin Sa'd] dari [Sa'd bin Abu Waqash] bahwasanya dia mengabarkan, bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya, tidaklah kamu menafkahkan suatu nafkah yang dimaksudkan mengharap wajah Allah kecuali kamu akan diberi pahala termasuk sesuatu yang kamu suapkan ke mulut istrimu\". "},"55":{"ar":"حَدَّثَنَا مُسَدَّدٌ قَالَ حَدَّثَنَا يَحْيَى عَنْ إِسْمَاعِيلَ قَالَ حَدَّثَنِي قَيْسُ بْنُ أَبِي حَازِمٍ عَنْ جَرِيرِ بْنِ عَبْدِ اللَّهِ قَالَبَايَعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَلَى إِقَامِ الصَّلَاةِ وَإِيتَاءِ الزَّكَاةِ وَالنُّصْحِ لِكُلِّ مُسْلِمٍ","id":"Telah menceritakan kepada kami [Musaddad] berkata, telah menceritakan kepada kami [Yahya] dari [Isma'il] berkata, telah menceritakan kepadaku [Qais bin Abu Hazim] dari [Jarir bin Abdullah] berkata: \"Aku telah membai'at Rasulullah untuk menegakkan shalat, menunaikan zakat dan menasehati kepada setiap muslim\". "},"56":{"ar":"حَدَّثَنَا أَبُو النُّعْمَانِ قَالَ حَدَّثَنَا أَبُو عَوَانَةَ عَنْ زِيَادِ بْنِ عِلَاقَةَ قَالَ سَمِعْتُ جَرِيرَ بْنَ عَبْدِ اللَّهِ يَقُولُيَوْمَ مَاتَ الْمُغِيرَةُ بْنُ شُعْبَةَ قَامَ فَحَمِدَ اللَّهَ وَأَثْنَى عَلَيْهِ وَقَالَ عَلَيْكُمْ بِاتِّقَاءِ اللَّهِ وَحْدَهُ لَا شَرِيكَ لَهُ وَالْوَقَارِ وَالسَّكِينَةِ حَتَّى يَأْتِيَكُمْ أَمِيرٌ فَإِنَّمَا يَأْتِيكُمْ الْآنَ ثُمَّ قَالَ اسْتَعْفُوا لِأَمِيرِكُمْ فَإِنَّهُ كَانَ يُحِبُّ الْعَفْوَ ثُمَّ قَالَ أَمَّا بَعْدُ فَإِنِّي أَتَيْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قُلْتُ أُبَايِعُكَ عَلَى الْإِسْلَامِ فَشَرَطَ عَلَيَّ وَالنُّصْحِ لِكُلِّ مُسْلِمٍ فَبَايَعْتُهُ عَلَى هَذَا وَرَبِّ هَذَا الْمَسْجِدِ إِنِّي لَنَاصِحٌ لَكُمْ ثُمَّ اسْتَغْ��َرَ وَنَزَلَ","id":"Telah menceritakan kepada kami [Abu An Nu'man] berkata, telah menceritakan kepada kami [Abu 'Awanah] dari [Ziyad bin 'Alaqah] berkata; saya mendengar [Jarir bin Abdullah] berkata ketika Al Mughirah bin Syu'bah meninggal, sambil berdiri dia memuji Allah dan mensucikan-Nya, berkata: \"Wajib atas kalian bertakwa kepada Allah satu-satunya dan tidak menyekutukannya, dan dengan penuh ketundukan dan ketenangan sampai datang pemimpin pengganti, dan sekarang datang penggantinya, \" kemudian dia berkata: \"Mintakanlah maaf kepada Allah Subhanahu wa Ta'ala buat pemimpin kalian ini (Al Mughirah), karena dia suka memberi maaf.\" Lalu berkata: \"Amma ba'du, sesungguhnya aku mendatangi Nabi shallallahu 'alaihi wasallam kemudian aku berkata: \"Aku membai'at engkau untuk Islam\". Lalu Nabi shallallahu 'alaihi wasallam memberi syarat dan menasehati kepada setiap muslim, maka aku membai'at Beliau untuk perkara itu, dan demi Pemilik Masjid ini, sungguh aku akan selalu memberi nasihat kepada kalian\" Kemudian dia beristighfar lalu turun dari mimbar. "},"57":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ سِنَانٍ قَالَ حَدَّثَنَا فُلَيْحٌ ح و حَدَّثَنِي إِبْرَاهِيمُ بْنُ الْمُنْذِرِ قَالَ حَدَّثَنَا مُحَمَّدُ بْنُ فُلَيْحٍ قَالَ حَدَّثَنِي أَبِي قَالَ حَدَّثَنِي هِلَالُ بْنُ عَلِيٍّ عَنْ عَطَاءِ بْنِ يَسَارٍ عَنْ أَبِي هُرَيْرَةَ قَالَبَيْنَمَا النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي مَجْلِسٍ يُحَدِّثُ الْقَوْمَ جَاءَهُ أَعْرَابِيٌّ فَقَالَ مَتَى السَّاعَةُ فَمَضَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُحَدِّثُ فَقَالَ بَعْضُ الْقَوْمِ سَمِعَ مَا قَالَ فَكَرِهَ مَا قَالَ وَقَالَ بَعْضُهُمْ بَلْ لَمْ يَسْمَعْ حَتَّى إِذَا قَضَى حَدِيثَهُ قَالَ أَيْنَ أُرَاهُ السَّائِلُ عَنْ السَّاعَةِ قَالَ هَا أَنَا يَا رَسُولَ اللَّهِ قَالَ فَإِذَا ضُيِّعَتْ الْأَمَانَةُ فَانْتَظِرْ السَّاعَةَ قَالَ كَيْفَ إِضَاعَتُهَا قَالَ إِذَا وُسِّدَ الْأَمْرُ إِلَى غَيْرِ أَهْلِهِ فَانْتَظِرْ السَّاعَةَ","id":"Telah menceritakan kepada kami [Muhammad bin Sinan] berkata, telah menceritakan kepada kami [Fulaih]. Dan telah diriwayatkan pula hadits serupa dari jalan lain, yaitu Telah menceritakan kepadaku [Ibrahim bin Al Mundzir] berkata, telah menceritakan kepada kami [Muhammad bin Fulaih] berkata, telah menceritakan kepadaku [bapakku] berkata, telah menceritakan kepadaku [Hilal bin Ali] dari [Atho' bin Yasar] dari [Abu Hurairah] berkata: Ketika Nabi shallallahu 'alaihi wasallam berada dalam suatu majelis membicarakan suatu kaum, tiba-tiba datanglah seorang Arab Badui lalu bertanya: \"Kapan datangnya hari kiamat?\" Namun Nabi shallallahu 'alaihi wasallam tetap melanjutkan pembicaraannya. Sementara itu sebagian kaum ada yang berkata; \"beliau mendengar perkataannya akan tetapi beliau tidak menyukai apa yang dikatakannya itu, \" dan ada pula sebagian yang mengatakan; \"bahwa beliau tidak mendengar perkataannya.\" Hingga akhirnya Nabi shallallahu 'alaihi wasallam menyelesaikan pembicaraannya, seraya berkata: \"Mana orang yang bertanya tentang hari kiamat tadi?\" Orang itu berkata: \"saya wahai Rasulullah!\". Maka Nabi shallallahu 'alaihi wasallam bersabda: \"Apabila sudah hilang amanah maka tunggulah terjadinya kiamat\". Orang itu bertanya: \"Bagaimana hilangnya amanat itu?\" Nabi shallallahu 'alaihi wasallam menjawab: \"Jika urusan diserahkan bukan kepada ahlinya, maka akan tunggulah terjadinya kiamat\". "},"58":{"ar":"حَدَّثَنَا أَبُو النُّعْمَانِ عَارِمُ بْنُ الْفَضْلِ قَالَ حَدَّثَنَا أَبُو عَوَانَةَ عَنْ أَبِي بِشْرٍ عَنْ يُوسُفَ بْنِ مَاهَكَ عَنْ عَبْدِ اللَّهِ بْنِ عَمْرٍو قَالَتَخَلَّفَ عَنَّا النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي سَفْرَةٍ سَافَرْنَاهَا فَأَدْرَكَنَا وَقَدْ أَرْهَقَتْنَا الصَّلَاةُ وَنَحْنُ نَتَوَضَّأُ فَجَعَلْنَا نَمْسَحُ عَلَى أَرْجُلِنَا فَنَادَى بِأَعْلَى صَوْتِهِ وَيْلٌ لِلْأَعْقَابِ مِنْ النَّارِ مَرَّتَيْنِ أَوْ ثَلَاثًا","id":"Telah menceritakan kepada kami [Abu An Nu'man 'Arim bin Al Fadlal] berkata, telah menceritakan kepada kami [Abu 'Awanah] dari [Abu Bisyir] dari [Yusuf bin Mahak] dari [Abdullah bin 'Amru] berkata: Nabi shallallahu 'alaihi wasallam pernah tertinggal dari kami dalam suatu perjalanan yang kami lakukan hingga Beliau mendapatkan kami sementara waktu shalat sudah hampir habis, kami berwudlu' dengan hanya mengusap kaki kami. Maka Nabi shallallahu 'alaihi wasallam berseru dengan suara yang keras: \"celakalah bagi tumit-tumit yang tidak basah akan masuk neraka.\" Beliau serukan hingga dua atau tiga kali. "},"59":{"ar":"حَدَّثَنَا قُتَيْبَةُ بْنُ سَعِيدٍ حَدَّثَنَا إِسْمَاعِيلُ بْنُ جَعْفَرٍ عَنْ عَبْدِ اللَّهِ بْنِ دِينَارٍ عَنْ ابْنِ عُمَرَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ مِنْ الشَّجَرِ شَجَرَةً لَا يَسْقُطُ وَرَقُهَا وَإِنَّهَا مَثَلُ الْمُسْلِمِ فَحَدِّثُونِي مَا هِيَ فَوَقَعَ النَّاسُ فِي شَجَرِ الْبَوَادِي قَالَ عَبْدُ اللَّهِ وَوَقَعَ فِي نَفْسِي أَنَّهَا النَّخْلَةُ فَاسْتَحْيَيْتُ ثُمَّ قَالُوا حَدِّثْنَا مَا هِيَ يَا رَسُولَ اللَّهِ قَالَ هِيَ النَّخْلَةُ","id":"Telah menceritakan kepada kami [Qutaibah bin Sa'id] Telah menceritakan kepada kami [Isma'il bin Ja'far] dari [Abdullah bin Dinar] dari [Ibnu Umar] berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya diantara pohon ada suatu pohon yang tidak jatuh daunnya. Dan itu adalah perumpamaan bagi seorang muslim\". Nabi shallallahu 'alaihi wasallam bertanya: \"Katakanlah kepadaku, pohon apakah itu?\" Maka para sahabat beranggapan bahwa yang dimaksud adalah pohon yang berada di lembah. Abdullah berkata: \"Aku berpikir dalam hati pohon itu adalah pohon kurma, tapi aku malu mengungkapkannya. Kemudian para sahabat bertanya: \"Wahai Rasulullah, pohon apakah itu?\" Beliau shallallahu 'alaihi wasallam menjawab: \"Pohon kurma\". "},"60":{"ar":"حَدَّثَنَا خَالِدُ بْنُ مَخْلَدٍ حَدَّثَنَا سُلَيْمَانُ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ دِينَارٍ عَنْ ابْنِ عُمَرَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِنَّ مِنْ الشَّجَرِ شَجَرَةً لَا يَسْقُطُ وَرَقُهَا وَإِنَّهَا مَثَلُ الْمُسْلِمِ حَدِّثُونِي مَا هِيَ قَالَ فَوَقَعَ النَّاسُ فِي شَجَرِ الْبَوَادِي قَالَ عَبْدُ اللَّهِ فَوَقَعَ فِي نَفْسِي أَنَّهَا النَّخْلَةُ فَاسْتَحْيَيْتُ ثُمَّ قَالُوا حَدِّثْنَا مَا هِيَ يَا رَسُولَ اللَّهِ قَالَ هِيَ النَّخْلَةُ","id":"Telah menceritakan kepada kami [Khalid bin Makhlad] Telah menceritakan kepada kami [Sulaiman] Telah menceritakan kepada kami [Abdullah bin Dinar] dari [Ibnu Umar] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Sesungguhnya diantara pohon ada satu pohon yang tidak jatuh daunnya. Dan itu adalah perumpamaan bagi seorang muslim\". Nabi shallallahu 'alaihi wasallam bertanya: \"Katakanlah padaku, pohon apakah itu?\" Maka para sahabat beranggapan bahwa yang dimaksud adalah pohon yang berada di lembah. Abdullah berkata: Aku berpikir dalam hati pohon itu adalah pohon kurma, tapi aku malu mengungkapkannya. Kemudian orang-orang berkata: \"Wahai Rasulullah, pohon apakah itu?\" Beliau shallallahu 'alaihi wasallam menjawab: \"Pohon kurma\". "},"61":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ يُوسُفَ قَالَ حَدَّثَنَا اللَّيْثُ عَنْ سَعِيدٍ هُوَ الْمَقْبُرِيُّ عَنْ شَرِيكِ بْنِ عَبْدِ اللَّهِ بْنِ أَبِي نَمِرٍ أَنَّهُ سَمِعَ أَنَسَ بْنَ مَالِكٍ يَقُولُبَيْنَمَا نَحْنُ جُلُوسٌ مَعَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي الْمَسْجِدِ دَخَلَ رَجُلٌ عَلَى جَمَلٍ فَأَنَاخَهُ فِي الْمَسْجِدِ ثُمَّ عَقَلَهُ ثُمَّ قَالَ لَهُمْ أَيُّكُمْ مُحَمَّدٌ وَالنَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مُتَّكِئٌ بَيْنَ ظَهْرَانَيْهِمْ فَقُلْنَا هَذَا الرَّجُلُ الْأَبْيَضُ الْمُتَّكِئُ فَقَالَ لَهُ الرَّجُلُ يَا ابْنَ عَبْدِ الْمُطَّلِبِ فَقَالَ لَهُ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَدْ أَجَبْتُكَ فَقَالَ الرَّجُلُ لِلنَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنِّي سَائِلُكَ فَمُشَدِّدٌ عَلَيْكَ فِي الْمَسْأَلَةِ فَلَا تَجِدْ عَلَيَّ فِي نَفْسِكَ فَقَالَ سَلْ عَمَّا بَدَا لَكَ فَقَالَ أَسْأَلُكَ بِرَبِّكَ وَرَبِّ مَنْ قَبْلَكَ أَاللَّهُ أَرْسَلَكَ إِلَى النَّاسِ كُلِّهِمْ فَقَالَ اللَّهُمَّ نَعَمْ قَالَ أَنْشُدُكَ بِاللَّهِ أَاللَّهُ أَمَرَكَ أَنْ نُصَلِّيَ الصَّلَوَاتِ الْخَمْسَ فِي الْيَوْمِ وَاللَّيْلَةِ قَالَ اللَّهُمَّ نَعَمْ قَالَ أَنْشُدُكَ بِاللَّهِ أَاللَّهُ أَمَرَكَ أَنْ نَصُومَ هَذَا الشَّهْرَ مِنْ السَّنَةِ قَالَ اللَّهُمَّ نَعَمْ قَالَ أَنْشُدُكَ بِاللَّهِ أَاللَّهُ أَمَرَكَ أَنْ تَأْخُذَ هَذِهِ الصَّدَقَةَ مِنْ أَغْنِيَائِنَا فَتَقْسِمَهَا عَلَى فُقَرَائِنَا فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ اللَّهُمَّ نَعَمْ فَقَالَ الرَّجُلُ آمَنْتُ بِمَا جِئْتَ بِهِ وَأَنَا رَسُولُ مَنْ وَرَائِي مِنْ قَوْمِي وَأَنَا ضِمَامُ بْنُ ثَعْلَبَةَ أَخُو بَنِي سَعْدِ بْنِ بَكْرٍوَرَوَاهُ مُوسَى بْنُ إِسْمَاعِيلَ وَعَلِيُّ بْنُ عَبْدِ الْحَمِيدِ عَنْ سُلَيْمَانَ بْنِ المُغِيرَةِ عَنْ ثَابِتٍ عَنْ أَنَسٍ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِهَذَا","id":"Telah menceritakan kepada kami [Abdullah bin Yusuf] berkata, telah menceritakan kepada kami [Al Laits] dari [Sa'id Al Maqburi] dari [Syarik bin Abdullah bin Abu Namir] bahwa dia mendengar [Anas bin Malik] berkata: Ketika kami sedang duduk-duduk bersama Nabi shallallahu 'alaihi wasallam didalam Masjid, ada seorang yang menunggang unta datang lalu menambatkannya di dekat Masjid lalu berkata kepada mereka (para sahabat): \"Siapa diantara kalian yang bernama Muhammad?\" Pada saat itu Nabi shallallahu 'alaihi wasallam bersandaran di tengah para sahabat, lalu kami menjawab: \"orang Ini, yang berkulit putih yang sedang bersandar\". Orang itu berkata kepada Beliau; \"Wahai putra Abdul Muththalib\" Nabi shallallahu 'alaihi wasallam menjawab: \"Ya, aku sudah menjawabmu\". Maka orang itu berkata kepada Nabi shallallahu 'alaihi wasallam: \"Aku bertanya kepadamu persoalan yang mungkin berat buatmu namun janganlah kamu merasakan sesuatu terhadapku.\" Maka Nabi shallallahu 'alaihi wasallam menjawab: \"Tanyalah apa yang menjadi persoalanmu\". Orang itu berkata: \"Aku bertanya kepadamu demi Rabbmu dan Rabb orang-orang sebelummu. Apakah Allah yang mengutusmu kepada manusia seluruhnya?\" Nabi shallallahu 'alaihi wasallam menjawab: \"Demi Allah, ya benar!\" Kata orang itu: \"Aku bersumpah kepadamu atas nama Allah, apakah Allah yang memerintahkanmu supaya kami shalat lima (waktu) dalam sehari semalam?\" Nabi shallallahu 'alaihi wasallam menjawab: \"Demi Allah, ya benar!\" Kata orang itu: \"Aku bersumpah kepadamu atas nama Allah, apakah Allah yang memerintahkanmu supaya kami puasa di bulan ini dalam satu tahun?\" Nabi shallallahu 'alaihi wasallam menjawab: \"Demi Allah, ya benar!\" Kata orang itu: \"Aku bersumpah kepadamu atas nama Allah, apakah Allah yang memerintahkanmu supaya mengambil sedekah dari orang-orang kaya di antara kami lalu membagikannya kepada orang-orang fakir diantara kami?\" Nabi shallallahu 'alaihi wasallam menjawab: \"Demi Allah, ya benar!\" Kata orang itu: \"Aku beriman dengan apa yang engkau bawa dan aku adalah utusan kaumku, aku Dlamam bin Tsa'labah saudara dari Bani Sa'd bin Bakr.\" Begitulah (kisah tadi) sebagaimana yang diriwayatkan oleh [Musa bin Isma'il] dan [Ali bin Abdul Hamid] dari [Sulaiman bin Al Mughirah] dari [Tsabit] dari [Anas] dari Nabi shallallahu 'alaihi wasallam"},"62":{"ar":"حَدَّثَنَا إِسْمَاعِيلُ بْنُ عَبْدِ اللَّهِ قَالَ حَدَّثَنِي إِبْرَاهِيمُ بْنُ سَعْدٍ عَنْ صَالِحٍ عَنْ ابْنِ شِهَابٍ عَنْ عُبَيْدِ اللَّهِ بْنِ عَبْدِ اللَّهِ بْنِ عُتْبَةَ بْنِ مَسْعُودٍ أَنَّ عَبْدَ اللَّهِ بْنَ عَبَّاسٍ أَخْبَرَهُأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بَعَثَ بِكِتَابِهِ رَجُلًا وَأَمَرَهُ أَنْ يَدْفَعَهُ إِلَى عَظِيمِ الْبَحْرَيْنِ فَدَفَعَهُ عَظِيمُ الْبَحْرَيْنِ إِلَى كِسْرَى فَلَمَّا قَرَأَهُ مَزَّقَهُفَحَسِبْتُ أَنَّ ابْنَ الْمُسَيَّبِ قَالَ فَدَعَا عَلَيْهِمْ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنْ يُمَزَّقُوا كُلَّ مُمَزَّقٍ","id":"Telah menceritakan kepada kami [Isma'il bin Abdullah] berkata, telah menceritakan kepadaku [Ibrahim bin Sa'd] dari [Shalih] dari [Ibnu Syihab] dari [Ubaidullah bin Abdullah bin Utbah bin Mas'ud] bahwa [Abdullah bin 'Abbas] telah mengabarkannya, bahwa Nabi shallallahu 'alaihi wasallam telah mengutus seseorang dengan membawa surat dan memerintahkan kepadanya untuk memberikan surat tersebut kepada Pemimpin Bahrain. Lalu Pemimpin Bahrain itu memberikannya kepada Kisra. Tatkala dibaca, surat itu dirobeknya. Aku mengira kemudian [Ibnu Musayyab] berkata; lalu Rasulullah shallallahu 'alaihi wasallam berdoa agar mereka (kekuasaannya) dirobek-robek sehancur-hancurnya. "},"63":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ مُقَاتِلٍ أَبُو الْحَسَنِ الْمَرْوَزِيُّ أَخْبَرَنَا عَبْدُ اللَّهِ قَالَ أَخْبَرَنَا شُعْبَةُ عَنْ قَتَادَةَ عَنْ أَنَسِ بْنِ مَالِكٍ قَالَكَتَبَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كِتَابًا أَوْ أَرَادَ أَنْ يَكْتُبَ فَقِيلَ لَهُ إِنَّهُمْ لَا يَقْرَءُونَ كِتَابًا إِلَّا مَخْتُومًا فَاتَّخَذَ خَاتَمًا مِنْ فِضَّةٍ نَقْشُهُ مُحَمَّدٌ رَسُولُ اللَّهِ كَأَنِّي أَنْظُرُ إِلَى بَيَاضِهِ فِي يَدِهِ فَقُلْتُ لِقَتَادَةَ مَنْ قَالَ نَقْشُهُ مُحَمَّدٌ رَسُولُ اللَّهِ قَالَ أَنَسٌ","id":"Telah menceritakan kepada kami [Muhammad bin Muqotil Abu Al Hasan Al Marwazi] telah mengabarkan kepada kami [Abdullah] berkata, telah mengabarkan kepada kami [Syu'bah] dari [Qotadah] dari [Anas bin Malik] berkata: Nabi shallallahu 'alaihi wasallam menulis surat atau bermaksud menulis surat, lalu dikatakan kepada Beliau, bahwa mereka tidak akan membaca tulisan kecuali tertera stempel. Maka Nabi shallallahu 'alaihi wasallam membuat stempel yang terbuat dari perak yang bertanda; Muhammad Rasulullah. Seakan-akan aku melihat warna putih pada tangan Beliau shallallahu 'alaihi wasallam\". Lalu aku bertanya kepada Qotadah: \"Siapa yang membuat tanda Muhammad Rasulullah?\" Jawabnya: \"Anas\". "},"64":{"ar":"حَدَّثَنَا إِسْمَاعِيلُ قَالَ حَدَّثَنِي مَالِكٌ عَنْ إِسْحَاقَ بْنِ عَبْدِ اللَّهِ بْنِ أَبِي طَلْحَةَ أَنَّ أَبَا مُرَّةَ مَوْلَى عَقِيلِ بْنِ أَبِي طَالِبٍ أَخْبَرَهُ عَنْ أَبِي وَاقِدٍ اللَّيْثِيِّأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بَيْنَمَا هُوَ جَالِسٌ فِي الْمَسْجِدِ وَالنَّاسُ مَعَهُ إِذْ أَقْبَلَ ثَلَاثَةُ نَفَرٍ فَأَقْبَلَ اثْنَانِ إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَذَهَبَ وَاحِدٌ قَالَ فَوَقَفَا عَلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَمَّا أَحَدُهُمَا فَرَأَى فُرْجَةً فِي الْحَلْقَةِ فَجَلَسَ فِيهَا وَأَمَّا الْآخَرُ فَجَلَسَ خَلْفَهُمْ وَأَمَّا الثَّالِثُ فَأَدْبَرَ ذَاهِبًا فَلَمَّا فَرَغَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ أَلَا أُخْبِرُكُمْ عَنْ النَّفَرِ الثَّلَاثَةِ أَمَّا أَحَدُهُمْ فَأَوَى إِلَى اللَّهِ فَآوَاهُ اللَّهُ وَأَمَّا الْآخَرُ فَاسْتَحْيَا فَاسْتَحْيَا اللَّهُ مِنْهُ وَأَمَّا الْآخَرُ فَأَعْرَضَ فَأَعْرَضَ اللَّهُ عَنْهُ","id":"Telah menceritakan kepada kami [Isma'il] berkata, telah menceritakan kepadaku [Malik] dari [Ishaq bin Abdullah bin Abu Thalhah] bahwa [Abu Murrah] -mantan budak Uqail bin Abu Thalib-, mengabarkan kepadanya dari [Abu Waqid Al Laitsi], bahwa Rasulullah shallallahu 'alaihi wasallam ketika sedang duduk bermajelis di Masjid bersama para sahabat datanglah tiga orang. Yang dua orang menghadap Nabi shallallahu 'alaihi wasallam dan yang seorang lagi pergi, yang dua orang terus duduk bersama Nabi shallallahu 'alaihi wasallam dimana satu diantaranya nampak berbahagia bermajelis bersama Nabi shallallahu 'alaihi wasallam sedang yang kedua duduk di belakang mereka, sedang yang ketiga berbalik pergi, Setelah Rasulullah shallallahu 'alaihi wasallam selesai bermajelis, Beliau bersabda: \"Maukah kalian aku beritahu tentang ketiga orang tadi?\" Adapun seorang diantara mereka, dia meminta perlindungan kepada Allah, maka Allah lindungi dia. Yang kedua, dia malu kepada Allah, maka Allah pun malu kepadanya. Sedangkan yang ketiga berpaling dari Allah maka Allah pun berpaling darinya\". "},"65":{"ar":"حَدَّثَنَا مُسَدَّدٌ قَالَ حَدَّثَنَا بِشْرٌ قَالَ حَدَّثَنَا ابْنُ عَوْنٍ عَنْ ابْنِ سِيرِينَ عَنْ عَبْدِ الرَّحْمَنِ بْنِ أَبِي بَكْرَةَ عَنْ أَبِيهِذَكَرَ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَعَدَ عَلَى بَعِيرِهِ وَأَمْسَكَ إِنْسَانٌ بِخِطَامِهِ أَوْ بِزِمَامِهِ قَالَ أَيُّ يَوْمٍ هَذَا فَسَكَتْنَا حَتَّى ظَنَنَّا أَنَّهُ سَيُسَمِّيهِ سِوَى اسْمِهِ قَالَ أَلَيْسَ يَوْمَ النَّحْرِ قُلْنَا بَلَى قَالَ فَأَيُّ شَهْرٍ هَذَا فَسَكَتْنَا حَتَّى ظَنَنَّا أَنَّهُ سَيُسَمِّيهِ بِغَيْرِ اسْمِهِ فَقَالَ أَلَيْسَ بِذِي الْحِجَّةِ قُلْنَا بَلَى قَالَ فَإِنَّ دِمَاءَكُمْ وَأَمْوَالَكُمْ وَأَعْرَاضَكُمْ بَيْنَكُمْ حَرَامٌ كَحُرْمَةِ يَوْمِكُمْ هَذَا فِي شَهْرِكُمْ هَذَا فِي بَلَدِكُمْ هَذَا لِيُبَلِّغ الشَّاهِدُ الْغَائِبَ فَإِنَّ الشَّاهِدَ عَسَى أَنْ يُبَلِّغَ مَنْ هُوَ أَوْعَى لَهُ مِنْهُ","id":"Telah menceritakan kepada kami [Musaddad] berkata, telah menceritakan kepada kami [Bisyir] berkata, telah menceritakan kepada kami [Ibnu 'Aun] dari [Ibnu Sirin] dari [Abdurrahman bin Abu Bakrah] dari [bapaknya], dia menuturkan, bahwa Nabi shallallahu 'alaihi wasallam duduk diatas untanya sementara orang-orang memegangi tali kekang unta tersebut. Beliau shallallahu 'alaihi wasallam berkata: \"Hari apakah ini? '. Kami semua terdiam dan menyangka bahwa Beliau akan menamakan nama lain selain nama hari yang sudah dikenal. Beliau shallallahu 'alaihi wasallam berkata: \"Bukankah hari ini hari Nahar?\" Kami menjawab: \"Benar\". Nabi shallallahu 'alaihi wasallam kembali bertanya: \"Bulan apakah ini? '. Kami semua terdiam dan menyangka bahwa Beliau akan menamakan nama lain selain nama bulan yang sudah dikenal. Beliau shallallahu 'alaihi wasallam berkata: \"Bukankah ini bulan Dzul Hijjah?\" Kami menjawab: \"Benar\". Nabi shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya darah kalian, harta kalian dan kehormatan kalian sesama kalian haram (suci) sebagaimana sucinya hari kalian ini, bulan kalian ini dan tanah kalian ini. (Maka) hendaklah yang hadir menyampaikan kepada yang tidak hadir, karena orang yang hadir semoga dapat menyampaikan kepada orang yang lebih paham darinya\". "},"66":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ يُوسُفَ قَالَ أَخْبَرَنَا سُفْيَانُ عَنْ الْأَعْمَشِ عَنْ أَبِي وَائِلٍ عَنْ ابْنِ مَسْعُودٍ قَالَكَانَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَتَخَوَّلُنَا بِالْمَوْعِظَةِ فِي الْأَيَّامِ كَرَاهَةَ السَّآمَةِ عَلَيْنَا","id":"Telah menceritakan kepada kami [Muhammad bin Yusuf] berkata, telah mengabarkan kepada kami [Sufyan] dari [Al A'masy] dari [Abu Wa'il] dari [Ibnu Mas'ud] berkata; bahwa Nabi shallallahu 'alaihi wasallam memperingatkan kami dengan suatu pelajaran tentang hari-hari yang sulit yang akan kami hadapi. "},"67":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ قَالَ حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ قَالَ حَدَّثَنَا شُعْبَةُ قَالَ حَدَّثَنِي أَبُو التَّيَّاحِ عَنْ أَنَسِ بْنِ مَالِكٍعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ يَسِّرُوا وَلَا تُعَسِّرُوا وَبَشِّرُوا وَلَا تُنَفِّرُوا","id":"Telah menceritakan kepada kami [Muhammad bin Basysyar] berkata, telah menceritakan kepada kami [Yahya bin Sa'id] berkata, telah menceritakan kepada kami [Syu'bah] Telah menceritakan kepadaku [Abu At Tayyah] dari [Anas bin Malik] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"permudahlah dan jangan persulit, berilah kabar gembira dan jangan membuat orang lari.\""},"68":{"ar":"حَدَّثَنَا عُثْمَانُ بْنُ أَبِي شَيْبَةَ قَالَ حَدَّثَنَا جَرِيرٌ عَنْ مَنْصُورٍ عَنْ أَبِي وَائِلٍ قَالَ كَانَ عَبْدُ اللَّهِيُذَكِّرُ النَّاسَ فِي كُلِّ خَمِيسٍ فَقَالَ لَهُ رَجُلٌ يَا أَبَا عَبْدِ الرَّحْمَنِ لَوَدِدْتُ أَنَّكَ ذَكَّرْتَنَا كُلَّ يَوْمٍ قَالَ أَمَا إِنَّهُ يَمْنَعُنِي مِنْ ذَلِكَ أَنِّي أَكْرَهُ أَنْ أُمِلَّكُمْ وَإِنِّي أَتَخَوَّلُكُمْ بِالْمَوْعِظَةِ كَمَا كَانَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَتَخَوَّلُنَا بِهَا مَخَافَةَ السَّآمَةِ عَلَيْنَا","id":"Telah menceritakan kepada kami [Utsman bin Abu Syaibah] berkata, telah menceritakan kepada kami [Jarir] dari [Manshur] dari [Abu Wa'il] berkata; bahwa [Abdullah] memberi pelajaran kepada orang-orang setiap hari Kamis, kemudian seseorang berkata: \"Wahai Abu Abdurrahman, sungguh aku ingin kalau anda memberi pelajaran kepada kami setiap hari\" dia berkata: \"Sungguh aku enggan melakukannya, karena aku takut membuat kalian bosan, dan aku ingin memberi pelajaran kepada kalian sebagaimana Nabi shallallahu 'alaihi wasallam memberi pelajaran kepada kami karena khawatir kebosanan akan menimpa kami\". "},"69":{"ar":"حَدَّثَنَا سَعِيدُ بْنُ عُفَيْرٍ قَالَ حَدَّثَنَا ابْنُ وَهْبٍ عَنْ يُونُسَ عَنْ ابْنِ شِهَابٍ قَالَ قَالَ حُمَيْدُ بْنُ عَبْدِ الرَّحْمَنِ سَمِعْتُ مُعَاوِيَةَ خَطِيبًا يَقُولُسَمِعْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ مَنْ يُرِدْ اللَّهُ بِهِ خَيْرًا يُفَقِّهْهُ فِي الدِّينِ وَإِنَّمَا أَنَا قَاسِمٌ وَاللَّهُ يُعْطِي وَلَنْ تَزَالَ هَذِهِ الْأُمَّةُ قَائِمَةً عَلَى أَمْرِ اللَّهِ لَا يَضُرُّهُمْ مَنْ خَالَفَهُمْ حَتَّى يَأْتِيَ أَمْرُ اللَّهِ","id":"Telah menceritakan kepada kami [Sa'id bin 'Ufair] Telah menceritakan kepada kami [Ibnu Wahab] dari [Yunus] dari [Ibnu Syihab] berkata, [Humaid bin Abdurrahman] berkata; aku mendengar [Mu'awiyyah] memberi khutbah untuk kami, dia berkata; Aku mendengar Nabi shallallahu 'alaihi wasallam bersabda: \"Barangsiapa yang Allah kehendaki menjadi baik maka Allah faqihkan dia terhadap agama. Aku hanyalah yang membagi-bagikan sedang Allah yang memberi. Dan senantiasa ummat ini akan tegak diatas perintah Allah, mereka tidak akan celaka karena adanya orang-orang yang menyelisihi mereka hingga datang keputusan Allah\". "},"70":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ عَبْدِ اللَّهِ حَدَّثَنَا سُفْيَانُ قَالَ قَالَ لِي ابْنُ أَبِي نَجِيحٍ عَنْ مُجَاهِدٍ قَالَ صَحِبْتُ ابْنَ عُمَرَإِلَى الْمَدِينَةِ فَلَمْ أَسْمَعْهُ يُحَدِّثُ عَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِلَّا حَدِيثًا وَاحِدًا قَالَ كُنَّا عِنْدَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأُتِيَ بِجُمَّارٍ فَقَالَ إِنَّ مِنْ الشَّجَرِ شَجَرَةً مَثَلُهَا كَمَثَلِ الْمُسْلِمِ فَأَرَدْتُ أَنْ أَقُولَ هِيَ النَّخْلَةُ فَإِذَا أَنَا أَصْغَرُ الْقَوْمِ فَسَكَتُّ قَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ هِيَ النَّخْلَةُ","id":"Telah menceritakan kepada kami [Ali bin Abdullah] Telah menceritakan kepada kami [Sufyan] berkata, telah berkata kepadaku [Ibnu Abu Najih] dari [Mujahid] berkata; aku pernah menemani [Ibnu Umar] pergi ke Madinah, namun aku tidak mendengar dia membicarakan tentang Rasulullah shallallahu 'alaihi wasallam kecuali satu kejadian dimana dia berkata: Kami pernah bersama Nabi shallallahu 'alaihi wasallam lalu Beliau dipertemukan dengan jama'ah. Kemudian Beliau bersabda: \"Sesungguhnya diantara pohon ada suatu pohon yang merupakan perumpamaan bagi seorang muslim\". Aku ingin mengatakan bahwa itu adalah pohon kurma namun karena aku yang termuda maka aku diam. Maka kemudian Nabi shallallahu 'alaihi wasallam bersabda: \"Itu adalah pohon kurma\". "},"71":{"ar":"حَدَّثَنَا الْحُمَيْدِيُّ قَالَ حَدَّثَنَا سُفْيَانُ قَالَ حَدَّثَنِي إِسْمَاعِيلُ بْنُ أَبِي خَالِدٍ عَلَى غَيْرِ مَا حَدَّثَنَاهُ الزُّهْرِيُّ قَالَ سَمِعْتُ قَيْسَ بْنَ أَبِي حَازِمٍ قَالَ سَمِعْتُ عَبْدَ اللَّهِ بْنَ مَسْعُودٍ قَالَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا حَسَدَ إِلَّا فِي اثْنَتَيْنِ رَجُلٌ آتَاهُ اللَّهُ مَالًا فَسُلِّطَ عَلَى هَلَكَتِهِ فِي الْحَقِّ وَرَجُلٌ آتَاهُ اللَّهُ الْحِكْمَةَ فَهُوَ يَقْضِي بِهَا وَيُعَلِّمُهَا","id":"Telah menceritakan kepada kami [Al Humaidi] berkata, telah menceritakan kepada kami [Sufyan] berkata, telah menceritakan kepadaku [Isma'il bin Abu Khalid] -dengan lafazh hadits yang lain dari yang dia ceritakan kepada kami dari Az Zuhri- berkata; aku mendengar [Qais bin Abu Hazim] berkata; aku mendengar [Abdullah bin Mas'ud] berkata; Nabi shallallahu 'alaihi wasallam bersabda: \"Tidak boleh mendengki kecuali terhadap dua hal; (terhadap) seorang yang Allah berikan harta lalu dia pergunakan harta tersebut di jalan kebenaran dan seseorang yang Allah berikan hikmah lalu dia mengamalkan dan mengajarkannya kepada orang lain\". "},"72":{"ar":"حَدَّثَنِي مُحَمَّدُ بْنُ غُرَيْرٍ الزُّهْرِيُّ قَالَ حَدَّثَنَا يَعْقُوبُ بْنُ إِبْرَاهِيمَ قَالَ حَدَّثَنِي أَبِي عَنْ صَالِحٍ عَنْ ابْنِ شِهَابٍ حَدَّثَهُ أَنَّ عُبَيْدَ اللَّهِ بْنَ عَبْدِ اللَّهِ أَخْبَرَهُ عَنْ ابْنِ عَبَّاسٍأَنَّهُ تَمَارَى هُوَ وَالْحُرُّ بْنُ قَيْسِ بْنِ حِصْنٍ الْفَزَارِيُّ فِي صَاحِبِ مُوسَى قَالَ ابْنُ عَبَّاسٍ هُوَ خَضِرٌ فَمَرَّ بِهِمَا أُبَيُّ بْنُ كَعْبٍ فَدَعَاهُ ابْنُ عَبَّاسٍ فَقَالَ إِ��ِّي تَمَارَيْتُ أَنَا وَصَاحِبِي هَذَا فِي صَاحِبِ مُوسَى الَّذِي سَأَلَ مُوسَى السَّبِيلَ إِلَى لُقِيِّهِ هَلْ سَمِعْتَ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَذْكُرُ شَأْنَهُ قَالَ نَعَمْ سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ بَيْنَمَا مُوسَى فِي مَلَإٍ مِنْ بَنِي إِسْرَائِيلَ جَاءَهُ رَجُلٌ فَقَالَ هَلْ تَعْلَمُ أَحَدًا أَعْلَمَ مِنْكَ قَالَ مُوسَى لَا فَأَوْحَى اللَّهُ عَزَّ وَجَلَّ إِلَى مُوسَى بَلَى عَبْدُنَا خَضِرٌ فَسَأَلَ مُوسَى السَّبِيلَ إِلَيْهِ فَجَعَلَ اللَّهُ لَهُ الْحُوتَ آيَةً وَقِيلَ لَهُ إِذَا فَقَدْتَ الْحُوتَ فَارْجِعْ فَإِنَّكَ سَتَلْقَاهُ وَكَانَ يَتَّبِعُ أَثَرَ الْحُوتِ فِي الْبَحْرِ فَقَالَ لِمُوسَى فَتَاهُ{ أَرَأَيْتَ إِذْ أَوَيْنَا إِلَى الصَّخْرَةِ فَإِنِّي نَسِيتُ الْحُوتَ وَمَا أَنْسَانِيهِ إِلَّا الشَّيْطَانُ أَنْ أَذْكُرَهُ }{ قَالَ ذَلِكَ مَا كُنَّا نَبْغِي فَارْتَدَّا عَلَى آثَارِهِمَا قَصَصًا }فَوَجَدَا خَضِرًا فَكَانَ مِنْ شَأْنِهِمَا الَّذِي قَصَّ اللَّهُ عَزَّ وَجَلَّ فِي كِتَابِهِ","id":"Telah menceritakan kepadaku [Muhammad bin Gharair Az Zuhri] berkata, Telah menceritakan kepada kami [Ya'qub bin Ibrahim] berkata, telah menceritakan [bapakku] kepadaku dari [Shalih] dari [Ibnu Syihab], dia menceritakan bahwa ['Ubaidullah bin Abdullah] mengabarkan kepadanya dari [Ibnu 'Abbas], bahwasanya dia dan Al Hurru bin Qais bin Hishin Al Fazari berdebat tentang sahabat Musa 'Alaihis salam, Ibnu 'Abbas berkata; dia adalah Khidlir 'Alaihis salam. Tiba-tiba lewat Ubay bin Ka'b di depan keduanya, maka Ibnu 'Abbas memanggilnya dan berkata: \"Aku dan temanku ini berdebat tentang sahabat Musa 'Alaihis salam, yang ditanya tentang jalan yang akhirnya mempertemukannya, apakah kamu pernah mendengar Nabi shallallahu 'alaihi wasallam menceritakan masalah ini?\" [Ubay bin Ka'ab] menjawab: Ya, benar, aku pernah mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Ketika Musa di tengah pembesar Bani Israil, datang seseorang yang bertanya: apakah kamu mengetahui ada orang yang lebih pandai darimu?\" Berkata Musa 'Alaihis salam: \"Tidak\". Maka Allah Ta'ala mewahyukan kepada Musa 'Alaihis salam: \"Ada, yaitu hamba Kami bernama Hidlir.\" Maka Musa 'Alaihis Salam meminta jalan untuk bertemu dengannya. Allah menjadikan ikan bagi Musa sebagai tanda dan dikatakan kepadanya; \"jika kamu kehilangan ikan tersebut kembalilah, nanti kamu akan berjumpa dengannya\". Maka Musa 'Alaihis Salam mengikuti jejak ikan di lautan. Berkatalah murid Musa 'Alaihis salam: \"Tahukah kamu tatkala kita mencari tempat berlindung di batu tadi? Sesungguhnya aku lupa (menceritakan tentang) ikan itu dan tidaklah yang melupakan aku untuk menceritakannya kecuali setan\". Maka Musa 'Alaihis Salam berkata:.\"Itulah (tempat) yang kita cari\". Lalu keduanya kembali, mengikuti jejak mereka semula. Maka akhirnya keduanya bertemu dengan Hidlir 'Alaihis salam.\" Begitulah kisah keduanya sebagaimana Allah ceritakan dalam Kitab-Nya. "},"73":{"ar":"حَدَّثَنَا أَبُو مَعْمَرٍ قَالَ حَدَّثَنَا عَبْدُ الْوَارِثِ قَالَ حَدَّثَنَا خَالِدٌ عَنْ عِكْرِمَةَ عَنْ ابْنِ عَبَّاسٍ قَالَضَمَّنِي رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَقَالَ اللَّهُمَّ عَلِّمْهُ الْكِتَابَ","id":"Telah menceritakan kepada kami [Abu Ma'mar] berkata, telah menceritakan kepada kami [Abdul Warits] berkata, telah menceritakan kepada kami [Khalid] dari ['Ikrimah] dari [Ibnu 'Abbas] berkata: Pada suatu hari Rasulullah shallallahu 'alaihi wasallam berada di sampingku lalu bersabda: \"Ya Allah, ajarkanlah dia Kitab\". "},"74":{"ar":"حَدَّثَنَا إِسْمَاعِيلُ بْنُ أَبِي أُوَيْسٍ قَالَ حَدَّثَنِي مَالِكٌ عَنْ ابْنِ شِهَابٍ عَنْ عُبَيْدِ اللَّهِ بْنِ عَبْدِ اللَّهِ بْنِ عُتْبَةَ عَنْ عَبْدِ اللَّهِ بْنِ عَبَّاسٍ قَالَأَقْبَلْتُ رَاكِبًا عَلَى حِمَارٍ أَتَانٍ وَأَنَا يَوْمَئِذٍ قَدْ نَاهَزْتُ الِاحْتِلَامَ وَرَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُصَلِّي بِمِنًى إِلَى غَيْرِ جِدَارٍ فَمَرَرْتُ بَيْنَ يَدَيْ بَعْضِ الصَّفِّ وَأَرْسَلْتُ الْأَتَانَ تَرْتَعُ فَدَخَلْتُ فِي الصَّفِّ فَلَمْ يُنْكَرْ ذَلِكَ عَلَيَّ","id":"Telah menceritakan kepada kami [Isma'il bin Abu Uwais] berkata, Telah menceritakan kepadaku [Malik] dari [Ibnu Syihab] dari ['Ubaidullah bin Abdullah bin 'Utbah] dari [Abdullah bin 'Abbas] berkata; aku datang dengan menunggang keledai betina, yang saat itu aku hampir menginjak masa baligh, dan Rasulullah sedang shalat di Mina dengan tidak menghadap dinding. Maka aku lewat di depan sebagian shaf kemudian aku melepas keledai betina itu supaya mencari makan sesukanya. Lalu aku masuk kembali di tengah shaf dan tidak ada orang yang menyalahkanku\". "},"75":{"ar":"حَدَّثَنِي مُحَمَّدُ بْنُ يُوسُفَ قَالَ حَدَّثَنَا أَبُو مُسْهِرٍ قَالَ حَدَّثَنِي مُحَمَّدُ بْنُ حَرْبٍ حَدَّثَنِي الزُّبَيْدِيُّ عَنْ الزُّهْرِيِّ عَنْ مَحْمُودِ بْنِ الرَّبِيعِ قَالَعَقَلْتُ مِنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَجَّةً مَجَّهَا فِي وَجْهِي وَأَنَا ابْنُ خَمْسِ سِنِينَ مِنْ دَلْوٍ","id":"Telah menceritakan kepadaku [Muhammad bin Yusuf] berkata, Telah menceritakan kepada kami [Abu Mushir] berkata, Telah menceritakan kepadaku [Muhammad bin Harb] Telah menceritakan kepadaku [Az Zubaidi] dari [Az Zuhri] dari [Mahmud bin Ar Rabbi'] berkata: \"Aku mengingat dari Nabi, saat Beliau melumuri air ludah Beliau di wajahku, saat itu aku baru berumur lima tahun\". "},"76":{"ar":"حَدَّثَنَا أَبُو الْقَاسِمِ خَالِدُ بْنُ خَلِيٍّ قَاضِي حِمْصَ قَالَ حَدَّثَنَا مُحَمَّدُ بْنُ حَرْبٍ قَالَ حَدَّثَنَا الْأَوْزَاعِيُّ أَخْبَرَنَا الزُّهْرِيُّ عَنْ عُبَيْدِ اللَّهِ بْنِ عَبْدِ اللَّهِ بْنِ عُتْبَةَ بْنِ مَسْعُودٍ عَنْ ابْنِ عَبَّاسٍأَنَّهُ تَمَارَى هُوَ وَالْحُرُّ بْنُ قَيْسِ بْنِ حِصْنٍ الْفَزَارِيُّ فِي صَاحِبِ مُوسَى فَمَرَّ بِهِمَا أُبَيُّ بْنُ كَعْبٍ فَدَعَاهُ ابْنُ عَبَّاسٍ فَقَالَ إِنِّي تَمَارَيْتُ أَنَا وَصَاحِبِي هَذَا فِي صَاحِبِ مُوسَى الَّذِي سَأَلَ السَّبِيلَ إِلَى لُقِيِّهِ هَلْ سَمِعْتَ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَذْكُرُ شَأْنَهُ فَقَالَ أُبَيٌّ نَعَمْ سَمِعْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَذْكُرُ شَأْنَهُ يَقُولُ بَيْنَمَا مُوسَى فِي مَلَإٍ مِنْ بَنِي إِسْرَائِيلَ إِذْ جَاءَهُ رَجُلٌ فَقَالَ أَتَعْلَمُ أَحَدًا أَعْلَمَ مِنْكَ قَالَ مُوسَى لَا فَأَوْحَى اللَّهُ عَزَّ وَجَلَّ إِلَى مُوسَى بَلَى عَبْدُنَا خَضِرٌ فَسَأَلَ السَّبِيلَ إِلَى لُقِيِّهِ فَجَعَلَ اللَّهُ لَهُ الْحُوتَ آيَةً وَقِيلَ لَهُ إِذَا فَقَدْتَ الْحُوتَ فَارْجِعْ فَإِنَّكَ سَتَلْقَاهُ فَكَانَ مُوسَى صَلَّى اللَّهُ عَلَيْهِ يَتَّبِعُ أَثَرَ الْحُوتِ فِي الْبَحْرِ فَقَالَ فَتَى مُوسَى لِمُوسَى{ أَرَأَيْتَ إِذْ أَوَيْنَا إِلَى الصَّخْرَةِ فَإِنِّي نَسِيتُ الْحُوتَ وَمَا أَنْسَانِيهِ إِلَّا الشَّيْطَانُ أَنْ أَذْكُرَهُ }قَالَ مُوسَى{ ذَلِكَ مَا كُنَّا نَبْغِي فَارْتَدَّا عَلَى آثَارِهِمَا قَصَصًا }فَوَجَدَا خَضِرًا فَكَانَ مِنْ شَأْنِهِمَا مَا قَصَّ اللَّهُ فِي كِتَابِهِ","id":"Telah menceritakan kepada kami [Abu Al Qasim Khalid bin Khali] -seorang hakim di Himshi-, dia berkata; telah menceritakan kepada kami [Muhammad bin Harb] berkata, Telah menceritakan kepada kami [Al Auza'i] telah mengabarkan kepada kami [Az Zuhri] dari ['Ubaidullah bin Abdullah bin 'Utbah bin Mas'ud] dari [Ibnu 'Abbas] bahwasanya dia dan Al Hurru bin Qais bin Hishin Al Fazari berdebat tentang sahabat Musa 'Alaihis salam, Ibnu 'Abbas berkata; dia adalah Khidlir 'Alaihis salam. Tiba-tiba lewat Ubay bin Ka'b di depan keduanya, maka Ibnu 'Abbas memanggilnya dan berkata: \"Aku dan temanku ini berdebat tentang sahabat Musa 'Alaihis salam, yang ditanya tentang jalan yang akhirnya mempertemukannya, apakah kamu pernah mendengar Nabi shallallahu 'alaihi wasallam menceritakan masalah ini?\" [Ubay bin Ka'ab] menjawab: Ya, benar, aku pernah mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Ketika Musa di tengah pembesar Bani Israil, datang seseorang yang bertanya: apakah kamu mengetahui ada orang yang lebih pandai darimu?\" Berkata Musa 'Alaihis salam: \"Tidak\". Maka Allah Ta'ala mewahyukan kepada Musa 'Alaihis salam: \"Ada, yaitu hamba Kami bernama Hidlir.\" Maka Musa 'Alaihis Salam meminta jalan untuk bertemu dengannya. Allah menjadikan ikan bagi Musa sebagai tanda dan dikatakan kepadanya; \"jika kamu kehilangan ikan tersebut kembalilah, nanti kamu akan berjumpa dengannya\". Maka Musa 'Alaihis Salam mengikuti jejak ikan di lautan. Berkatalah murid Musa 'Alaihis salam: \"Tahukah kamu tatkala kita mencari tempat berlindung di batu tadi? Sesungguhnya aku lupa (menceritakan tentang) ikan itu dan tidaklah yang melupakan aku untuk menceritakannya kecuali setan\". Maka Musa 'Alaihis Salam berkata:.\"Itulah (tempat) yang kita cari\". Lalu keduanya kembali, mengikuti jejak mereka semula. Maka akhirnya keduanya bertemu dengan Hidlir 'Alaihis salam.\" Begitulah kisah keduanya sebagaimana Allah ceritakan dalam Kitab-Nya. "},"77":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ الْعَلَاءِ قَالَ حَدَّثَنَا حَمَّادُ بْنُ أُسَامَةَ عَنْ بُرَيْدِ بْنِ عَبْدِ اللَّهِ عَنْ أَبِي بُرْدَةَ عَنْ أَبِي مُوسَىعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَثَلُ مَا بَعَثَنِي اللَّهُ بِهِ مِنْ الْهُدَى وَالْعِلْمِ كَمَثَلِ الْغَيْثِ الْكَثِيرِ أَصَابَ أَرْضًا فَكَانَ مِنْهَا نَقِيَّةٌ قَبِلَتْ الْمَاءَ فَأَنْبَتَتْ الْكَلَأَ وَالْعُشْبَ الْكَثِيرَ وَكَانَتْ مِنْهَا أَجَادِبُ أَمْسَكَتْ الْمَاءَ فَنَفَعَ اللَّهُ بِهَا النَّاسَ فَشَرِبُوا وَسَقَوْا وَزَرَعُوا وَأَصَابَتْ مِنْهَا طَائِفَةً أُخْرَى إِنَّمَا هِيَ قِيعَانٌ لَا تُمْسِكُ مَاءً وَلَا تُنْبِتُ كَلَأً فَذَلِكَ مَثَلُ مَنْ فَقُهَ فِي دِينِ اللَّهِ وَنَفَعَهُ مَا بَعَثَنِي اللَّهُ بِهِ فَعَلِمَ وَعَلَّمَ وَمَثَلُ مَنْ لَمْ يَرْفَعْ بِذَلِكَ رَأْسًا وَلَمْ يَقْبَلْ هُدَى اللَّهِ الَّذِي أُرْسِلْتُ بِهِقَالَ أَبُو عَبْد اللَّهِ قَالَ إِسْحَاقُ وَكَانَ مِنْهَا طَائِفَةٌ قَيَّلَتْ الْمَاءَ قَاعٌ يَعْلُوهُ الْمَاءُ وَالصَّفْصَفُ الْمُسْتَوِي مِنْ الْأَرْضِ","id":"Telah menceritakan kepada kami [Muhammad bin Al 'Ala`] berkata, telah menceritakan kepada kami [Hammad bin Usamah] dari [Buraid bin Abdullah] dari [Abu Burdah] dari [Abu Musa] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Perumpamaan petunjuk dan ilmu yang Allah mengutusku dengan membawanya adalah seperti hujan yang lebat yang turun mengenai tanah. Diantara tanah itu ada jenis yang dapat menyerap air sehingga dapat menumbuhkan tumbuh-tumbuhan dan rerumputan yang banyak. Dan di antaranya ada tanah yang keras lalu menahan air (tergenang) sehingga dapat diminum oleh manusia, memberi minum hewan ternak dan untuk menyiram tanaman. Dan yang lain ada permukaan tanah yang berbentuk lembah yang tidak dapat menahan air dan juga tidak dapat menumbuhkan tanaman. perumpamaan itu adalah seperti orang yang faham agama Allah dan dapat memanfa'atkan apa yang aku diutus dengannya, dia mempelajarinya dan mengajarkannya, dan juga perumpamaan orang yang tidak dapat mengangkat derajat dan tidak menerima hidayah Allah dengan apa yang aku diutus dengannya\". Berkata Abu Abdullah; [Ishaq] berkata: \"Dan diantara jenis tanah itu ada yang berbentuk lembah yang dapat menampung air hingga penuh dan diantaranya ada padang sahara yang datar\". "},"78":{"ar":"حَدَّثَنَا عِمْرَانُ بْنُ مَيْسَرَةَ قَالَ حَدَّثَنَا عَبْدُ الْوَارِثِ عَنْ أَبِي التَّيَّاحِ عَنْ أَنَسِ بْنِ مَالِكٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ مِنْ أَشْرَاطِ السَّاعَةِ أَنْ يُرْفَعَ الْعِلْمُ وَيَثْبُتَ الْجَهْلُ وَيُشْرَبَ الْخَمْرُ وَيَظْهَرَ الزِّنَا","id":"Telah menceritakan kepada kami ['Imran bin Maisarah] berkata, telah menceritakan kepada kami [Abdul Warits] dari [Abu At Tayyah] dari [Anas bin Malik] berkata, telah bersabda Rasul shallallahu 'alaihi wasallam: \"Sesungguhnya diantara tanda-tanda kiamat adalah diangkatnya ilmu dan merebaknya kebodohan dan diminumnya khamer serta praktek perzinahan secara terang-terangan\". "},"79":{"ar":"حَدَّثَنَا مُسَدَّدٌ قَالَ حَدَّثَنَا يَحْيَى عَنْ شُعْبَةَ عَنْ قَتَادَةَ عَنْ أَنَسِ بْنِ مَالِكٍقَالَ لَأُحَدِّثَنَّكُمْ حَدِيثًا لَا يُحَدِّثُكُمْ أَحَدٌ بَعْدِي سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ مِنْ أَشْرَاطِ السَّاعَةِ أَنْ يَقِلَّ الْعِلْمُ وَيَظْهَرَ الْجَهْلُ وَيَظْهَرَ الزِّنَا وَتَكْثُرَ النِّسَاءُ وَيَقِلَّ الرِّجَالُ حَتَّى يَكُونَ لِخَمْسِينَ امْرَأَةً الْقَيِّمُ الْوَاحِدُ","id":"Telah menceritakan kepada kami [Musaddad] berkata, telah menceritakan kepada kami [Yahya] dari [Syu'bah] dari [Qotadah] dari [Anas bin Malik] berkata: Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya diantara tanda-tanda kiamat adalah sedikitnya ilmu dan merebaknya kebodohan, perzinahan secara terang-terangan, jumlah perempuan yang lebih banyak dan sedikitnya laki-laki, sampai-sampai (perbandingannya) lima puluh perempuan sama dengan hanya satu orang laki-laki. "},"80":{"ar":"حَدَّثَنَا سَعِيدُ بْنُ عُفَيْرٍ قَالَ حَدَّثَنِي اللَّيْثُ قَالَ حَدَّثَنِي عُقَيْلٌ عَنْ ابْنِ شِهَابٍ عَنْ حَمْزَةَ بْنِ عَبْدِ اللَّهِ بْنِ عُمَرَ أَنَّ ابْنَ عُمَرَ قَالَسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ بَيْنَا أَنَا نَائِمٌ أُتِيتُ بِقَدَحِ لَبَنٍ فَشَرِبْتُ حَتَّى إِنِّي لَأَرَى الرِّيَّ يَخْرُجُ فِي أَظْفَارِي ثُمَّ أَعْطَيْتُ فَضْلِي عُمَرَ بْنَ الْخَطَّابِ قَالُوا فَمَا أَوَّلْتَهُ يَا رَسُولَ اللَّهِ قَالَ الْعِلْمَ","id":"Telah menceritakan kepada kami [Sa'id bin 'Ufair] berkata, Telah menceritakan kepadaku [Al Laits] berkata, Telah menceritakan kepadaku ['Uqail] dari [Ibnu Syihab] dari [Hamzah bin Abdullah bin Umar] bahwa [Ibnu Umar] berkata: aku mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Ketika aku tidur, aku bermimpi diberi segelas susu lalu aku meminumnya hingga aku melihat pemandangan yang bagus keluar dari kuku-kukuku, kemudian aku berikan sisanya kepada sahabat muliaku Umar bin Al Khaththab\". Orang-orang bertanya: \"Apa ta'wilnya wahai Rasulullah?\" Beliau menjawab: \"Ilmu\". "},"81":{"ar":"حَدَّثَنَا إِسْمَاعِيلُ قَالَ حَدَّثَنِي مَالِكٌ عَنْ ابْنِ شِهَابٍ عَنْ عِيسَى بْنِ طَلْحَةَ بْنِ عُبَيْدِ اللَّهِ عَنْ عَبْدِ اللَّهِ بْنِ عَمْرِو بْنِ الْعَاصِأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَقَفَ فِي حَجَّةِ الْوَدَاعِ بِمِنًى لِلنَّاسِ يَسْأَلُونَهُ فَجَاءَهُ رَجُلٌ فَقَالَ لَمْ أَشْعُرْ فَحَلَقْتُ قَبْلَ أَنْ أَذْبَحَ فَقَالَ اذْبَحْ وَلَا حَرَجَ فَجَاءَ آخَرُ فَقَالَ لَمْ أَشْعُرْ فَنَحَرْتُ قَبْلَ أَنْ أَرْمِيَ قَالَ ارْمِ وَلَا حَرَجَ فَمَا سُئِلَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ شَيْءٍ قُدِّمَ وَلَا أُخِّرَ إِلَّا قَالَ افْعَلْ وَلَا حَرَجَ","id":"Telah menceritakan kepada kami [Isma'il] berkata, Telah menceritakan kepadaku [Malik] dari [Ibnu Syihab] dari ['Isa bin Thalhah bin Ubaidillah] dari [Abdullah bin 'Amru bin Al 'Ash]; bahwa Rasulullah shallallahu 'alaihi wasallam berdiri di Mina pada haji wada' memberi kesempatan kepada manusia untuk bertanya kepada beliau. Lalu datanglah seseorang dan berkata: \"Aku tidak menyadari, ternyata saat aku mencukur rambut aku belum menyembelih.\" Maka Nabi shallallahu 'alaihi wasallam bersabda: \"Sembelihlah, tidak apa-apa\" Kemudian datang orang lain dan berkata: \"Aku tidak menyadari, ternyata ketika berkurban aku belum melempar (jumrah) \". Nabi shallallahu 'alaihi wasallam bersabda: \"lemparlah dan tidak apa-apa\". Dan tidaklah Nabi shallallahu 'alaihi wasallam ditanya tentang sesuatu perkara sebelum dan sesudahnya kecuali beliau menjawab: \"Lakukanlah dan tidak apa-apa\". "},"82":{"ar":"حَدَّثَنَا مُوسَى بْنُ إِسْمَاعِيلَ قَالَ حَدَّثَنَا وُهَيْبٌ قَالَ حَدَّثَنَا أَيُّوبُ عَنْ عِكْرِمَةَ عَنْ ابْنِ عَبَّاسٍأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ سُئِلَ فِي حَجَّتِهِ فَقَالَ ذَبَحْتُ قَبْلَ أَنْ أَرْمِيَ فَأَوْمَأَ بِيَدِهِ قَالَ وَلَا حَرَجَ قَالَ حَلَقْتُ قَبْلَ أَنْ أَذْبَحَ فَأَوْمَأَ بِيَدِهِ وَلَا حَرَجَ","id":"Telah menceritakan kepada kami [Musa bin Isma'il] berkata, Telah menceritakan kepada kami [Wuhaib] berkata, telah menceritakan kepada kami [Ayyub] dari ['Ikrimah] dari [Ibnu 'Abbas]; bahwa Nabi shallallahu 'alaihi wasallam ditanya seseorang tentang haji yang dilakukannya, orang itu bertanya: \"Aku menyembelih hewan sebelum aku melempar jumrah\". Beliau memberi isyarat dengan tangannya, yang maksudnya \"tidak apa-apa\".\"Dan aku mencukur sebelum menyembelih\". Beliau memberi isyarat dengan tangannya yang maksudnya \"tidak apa-apa\". "},"83":{"ar":"حَدَّثَنَا الْمَكِّيُّ بْنُ إِبْرَاهِيمَ قَالَ أَخْبَرَنَا حَنْظَلَةُ بْنُ أَبِي سُفْيَانَ عَنْ سَالِمٍ قَالَ سَمِعْتُ أَبَا هُرَيْرَةَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ يُقْبَضُ الْعِلْمُ وَيَظْهَرُ الْجَهْلُ وَالْفِتَنُ وَيَكْثُرُ الْهَرْجُ قِيلَ يَا رَسُولَ اللَّهِ وَمَا الْهَرْجُ فَقَالَ هَكَذَا بِيَدِهِ فَحَرَّفَهَا كَأَنَّه يُرِيدُ الْقَتْلَ","id":"Telah menceritakan kepada kami [Al Makki bin Ibrahim] berkata, telah mengabarkan kepada kami [Hanzhalah bin Abu Sufyan] dari [Salim] berkata; aku mendengar [Abu Hurairah] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Ilmu akan diangkat dan akan tersebar kebodohan dan fitnah merajalela serta banyak timbul kekacauan\". Ditanyakan kepada Beliau shallallahu 'alaihi wasallam: \"Wahai Rasulullah, apa yang dimaksud dengan kekacauan?\" Maka Rasul shallallahu 'alaihi wasallam menjawab: \"Begini\". Nabi shallallahu 'alaihi wasallam memberi isyarat dengan tangannya lalu memiringkannya. Seakan yang dimaksudnya adalah pembunuhan. "},"84":{"ar":"حَدَّثَنَا مُوسَى بْنُ إِسْمَاعِيلَ قَالَ حَدَّثَنَا وُهَيْبٌ قَالَ حَدَّثَنَا هِشَامٌ عَنْ فَاطِمَةَ عَنْ أَسْمَاءَ قَالَتْأَتَيْتُ عَائِشَةَ وَهِيَ تُصَلِّي فَقُلْتُ مَا شَأْنُ النَّاسِ فَأَشَارَتْ إِلَى السَّمَاءِ فَإِذَا النَّاسُ قِيَامٌ فَقَالَتْ سُبْحَانَ اللَّهِ قُلْتُ آيَةٌ فَأَشَارَتْ بِرَأْسِهَا أَيْ نَعَمْ فَقُمْتُ حَتَّى تَجَلَّانِي الْغَشْيُ فَجَعَلْتُ أَصُبُّ عَلَى رَأْسِي الْمَاءَ فَحَمِدَ اللَّهَ عَزَّ وَجَلَّ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَأَثْنَى عَلَيْهِ ثُمَّ قَالَ مَا مِنْ شَيْءٍ لَمْ أَكُنْ أُرِيتُهُ إِلَّا رَأَيْتُهُ فِي مَقَامِي حَتَّى الْجَنَّةُ وَالنَّارُ فَأُوحِيَ إِلَيَّ أَنَّكُمْ تُفْتَنُونَ فِي قُبُورِكُمْ مِثْلَ أَوْ قَرِيبَ لَا أَدْرِي أَيَّ ذَلِكَ قَالَتْ أَسْمَاءُ مِنْ فِتْنَةِ الْمَسِيحِ الدَّجَّالِ يُقَالُ مَا عِلْمُكَ بِهَذَا الرَّجُلِ فَأَمَّا الْمُؤْمِنُ أَوْ الْمُوقِنُ لَا أَدْرِي بِأَيِّهِمَا قَالَتْ أَسْمَاءُ فَيَقُولُ هُوَ مُحَمَّدٌ رَسُولُ اللَّهِ جَاءَنَا بِالْبَيِّنَاتِ وَالْهُدَى فَأَجَبْنَا وَاتَّبَعْنَا هُوَ مُحَمَّدٌ ثَلَاثًا فَيُقَالُ نَمْ صَالِحًا قَدْ عَلِمْنَا إِنْ كُنْتَ لَمُوقِنًا بِهِ وَأَمَّا الْمُنَافِقُ أَوْ الْمُرْتَابُ لَا أَدْرِي أَيَّ ذَلِكَ قَالَتْ أَسْمَاءُ فَيَقُولُ لَا أَدْرِي سَمِعْتُ النَّاسَ يَقُولُونَ شَيْئًا فَقُلْتُهُ","id":"Telah menceritakan kepada kami [Musa bin Isma'il] berkata, Telah menceritakan kepada kami [Wuhaib] berkata, Telah menceritakan kepada kami [Hisyam] dari [Fatimah] dari [Asma'] berkata: Aku menemui Aisyah saat dia sedang shalat. Setelah itu aku tanyakan kepadanya: \"Apa yang sedang dilakukan orang-orang?\" Aisyah memberi isyarat ke langit. Ternyata orang-orang sedang melaksanakan shalat (gerhana matahari). Maka Aisyah berkata: \"Maha suci Allah\". Aku tanyakan lagi: \"Satu tanda saja?\" Lalu dia memberi isyarat dengan kepalanya, maksudnya mengangguk tanda mengiyakan. Maka akupun ikut shalat namun timbul perasaan yang membingungkanku, hingga aku siram kepalaku dengan air. Dalam khutbahnya, Nabi shallallahu 'alaihi wasallam memuji Allah dan mensucikan-Nya, lalu bersabda: \"Tidak ada sesuatu yang belum diperlihatkan kepadaku, kecuali aku sudah melihatnya dari tempatku ini hingga surga dan neraka, lalu diwahyukan kepadaku: bahwa kalian akan terkena fitnah dalam kubur kalian seperti -atau hampir berupa- fitnah -yang aku sendiri tidak tahu apa yang diucapkan Asma' diantaranya adalah fitnah Al Masihud dajjal-; \"akan ditanyakan kepada seseorang (didalam kuburnya); \"Apa yang kamu ketahui tentang laki-laki ini?\" Adapun orang beriman atau orang yang yakin, -Asma' kurang pasti mana yang dimaksud diantara keduanya- akan menjawab: 'Dia adalah Muhammad Rasulullah telah datang kepada kami membawa penjelasan dan petunjuk. Maka kami sambut dan kami ikuti. Dia adalah Muhammad, ' diucapkannya tiga kali. Maka kepada orang itu dikatakan: 'Tidurlah dengan tenang, sungguh kami telah mengetahui bahwa kamu adalah orang yang yakin'. Adapun orang Munafiq atau orang yang ragu, -Asma' kurang pasti mana yang dimaksud diantara keduanya-, akan menjawab; \"aku tidak tahu siapa dia, aku mendengar manusia membicarakan sesuatu maka akupun mengatakannya\". "},"85":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ قَالَ حَدَّثَنَا غُنْدَرٌ قَالَ حَدَّثَنَا شُعْبَةُ عَنْ أَبِي جَمْرَةَ قَالَكُنْتُ أُتَرْجِمُ بَيْنَ ابْنِ عَبَّاسٍ وَبَيْنَ النَّاسِ فَقَالَ إِنَّ وَفْدَ عَبْدِ الْقَيْسِ أَتَوْا النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ مَنْ الْوَفْدُ أَوْ مَنْ الْقَوْمُ قَالُوا رَبِيعَةُ فَقَالَ مَرْحَبًا بِالْقَوْمِ أَوْ بِالْوَفْدِ غَيْرَ خَزَايَا وَلَا نَدَامَى قَالُوا إِنَّا نَأْتِيكَ مِنْ شُقَّةٍ بَعِيدَةٍ وَبَيْنَنَا وَبَيْنَكَ هَذَا الْحَيُّ مِنْ كُفَّارِ مُضَرَ وَلَا نَسْتَطِيعُ أَنْ نَأْتِيَكَ إِلَّا فِي شَهْرٍ حَرَامٍ فَمُرْنَا بِأَمْرٍ نُخْبِرُ بِهِ مَنْ وَرَاءَنَا نَدْخُلُ بِهِ الْجَنَّةَ فَأَمَرَهُمْ بِأَرْبَعٍ وَنَهَاهُمْ عَنْ أَرْبَعٍ أَمَرَهُمْ بِالْإِيمَانِ بِاللَّهِ عَزَّ وَجَلَّ وَحْدَهُ قَالَ هَلْ تَدْرُونَ مَا الْإِيمَانُ بِاللَّهِ وَحْدَهُ قَالُوا اللَّهُ وَرَسُولُهُ أَعْلَمُ قَالَ شَهَادَةُ أَنْ لَا إِلَهَ إِلَّا اللَّهُ وَأَنَّ مُحَمَّدًا رَسُولُ اللَّهِ وَإِقَامُ الصَّلَاةِ وَإِيتَاءُ الزَّكَاةِ وَصَوْمُ رَمَضَانَ وَتُعْطُوا الْخُمُسَ مِنْ الْمَغْنَمِ وَنَهَاهُمْ عَنْ الدُّبَّاءِ وَالْحَنْتَمِ وَالْمُزَفَّتِ قَالَ شُعْبَةُ رُبَّمَا قَالَ النَّقِيرِ وَرُبَّمَا قَالَ الْمُقَيَّرِ قَالَ احْفَظُوهُ وَأَخْبِرُوهُ مَنْ وَرَاءَكُمْ","id":"Telah menceritakan kepada kami [Muhammad bin Basysyar] berkata, telah menceritakan kepada kami [Ghundar] berkata, telah menceritakan kepada kami [Syu'bah] dari [Abu Jamrah] berkata aku pernah menjadi penerjemah antara [Ibnu 'Abbas] dan orang-orang, katanya; bahwasanya telah datang rombongan utusan Abdul Qais menemui Nabi shallallahu 'alaihi wasallam lalu Nabi shallallahu 'alaihi wasallam berkata: \"Utusan siapakah ini atau kaum manakah ini?\" Utusan itu menjawab: \"Rabi'ah\". Lalu Nabi shallallahu 'alaihi wasallam berkata: \"Selamat datang kaum atau para utusan dengan sukarela dan tanpa menyesal\". Para utusan berkata: \"Wahai Rasulullah kami datang dari perjalanan yang jauh sementara diantara kampung kami dan engkau ada kampung kaum kafir (suku) Mudlor, dan kami tidak sanggup untuk mendatangi engkau kecuali di bulan suci. Ajarkanlah kami dengan satu perintah yang jelas, yang dapat kami amalkan dan kami ajarkan kepada orang-orang di kampung kami dan dengan begitu kami dapat masuk surga.\" Lalu mereka bertanya kepada Nabi shallallahu 'alaihi wasallam tentang minuman. Maka Nabi shallallahu 'alaihi wasallam memerintahkan mereka dengan empat hal dan melarang dari empat hal, memerintahkan mereka untuk beriman kepada Allah satu-satunya, beliau berkata: \"Tahukah kalian apa arti beriman kepada Allah satu-satunya?\" Mereka menjawab: \"Allah dan Rasul-Nya yang lebih mengetahui.\" Nabi shallallahu 'alaihi wasallam menjelaskan: \"Persaksian tidak ada ilah yang berhak disembah kecuali Allah dan bahwa Muhammad adalah utusan Allah, menegakkan shalat, menunaikan zakat, berpuasa di bulan Ramadlan dan kalian mengeluarkan seperlima dari harta rampasan perang\". Dan Nabi shallallahu 'alaihi wasallam melarang mereka dari empat perkara, yaitu dari meminum dari dari al hantam, ad Dubbaa` dan al Muzaffaat. Syu'bah menerangkan; terkadang beliau menyebutkan an naqir dan terkadang muqoyyir (bukan naqir). Kemudian Nabi shallallahu 'alaihi wasallam bersabda: \"jagalah semuanya dan beritahukanlah kepada orang-orang di kampung kalian\". "},"86":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ مُقَاتِلٍ أَبُو الْحَسَنِ قَالَ أَخْبَرَنَا عَبْدُ اللَّهِ قَالَ أَخْبَرَنَا عُمَرُ بْنُ سَعِيدِ بْنِ أَبِي حُسَيْنٍ قَالَ حَدَّثَنِي عَبْدُ اللَّهِ بْنُ أَبِي مُلَيْكَةَ عَنْ عُقْبَةَ بْنِ الْحَارِثِأَنَّهُ تَزَوَّجَ ابْنَةً لِأَبِي إِهَابِ بْنِ عَزِيزٍ فَأَتَتْهُ امْرَأَةٌ فَقَالَتْ إِنِّي قَدْ أَرْضَعْتُ عُقْبَةَ وَالَّتِي تَزَوَّجَ فَقَالَ لَهَا عُقْبَةُ مَا أَعْلَمُ أَنَّكِ أَرْضَعْتِنِي وَلَا أَخْبَرْتِنِي فَرَكِبَ إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِالْمَدِينَةِ فَسَأَلَهُ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَيْفَ وَقَدْ قِيلَ فَفَارَقَهَا عُقْبَةُ وَنَكَحَتْ زَوْجًا غَيْرَهُ","id":"Telah menceritakan kepada kami [Muhammad bin Muqotil Abu Al Hasan] berkata, telah mengabarkan kepada kami [Abdullah] berkata, telah mengabarkan kepada kami [Umar bin Sa'id bin Abu Husain] berkata, telah menceritakan kepadaku [Abdullah bin Abu Mulaikah] dari ['Uqbah bin Al Harits]; bahwasanya dia menikahi seorang perempuan putri Ibnu Ihab bin 'Aziz. Lalu datanglah seorang perempuan dan berkata: \"Aku pernah menyusui 'Uqbah dan wanita yang dinikahinya itu\". Maka 'Uqbah berkata kepada perempuan itu: \"Aku tidak tahu kalau kamu pernah menyusuiku dan kamu tidak memberitahu aku.\" Maka 'Uqbah mengendarai kendaraannya menemui Rasul shallallahu 'alaihi wasallam di Madinah dan menyampaikan masalahnya. Maka Rasul shallallahu 'alaihi wasallam bersabda: \"harus bagaimana lagi, sedangkan dia sudah mengatakannya\". Maka 'Uqbah menceraikannya dan menikah dengan wanita yang lain. "},"87":{"ar":"حَدَّثَنَا أَبُو الْيَمَانِ أَخْبَرَنَا شُعَيْبٌ عَنْ الزُّهْرِيِّ ح قَالَ أَبُو عَبْد اللَّهِ وَقَالَ ابْنُ وَهْبٍ أَخْبَرَنَا يُونُسُ عَنْ ابْنِ شِهَابٍ عَنْ عُبَيْدِ اللَّهِ بْنِ عَبْدِ اللَّهِ بْنِ أَبِي ثَوْرٍ عَنْ عَبْدِ اللَّهِ بْنِ عَبَّاسٍ عَنْ عُمَرَ قَالَكُنْتُ أَنَا وَجَا��ٌ لِي مِنْ الْأَنْصَارِ فِي بَنِي أُمَيَّةَ بْنِ زَيْدٍ وَهِيَ مِنْ عَوَالِي الْمَدِينَةِ وَكُنَّا نَتَنَاوَبُ النُّزُولَ عَلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَنْزِلُ يَوْمًا وَأَنْزِلُ يَوْمًا فَإِذَا نَزَلْتُ جِئْتُهُ بِخَبَرِ ذَلِكَ الْيَوْمِ مِنْ الْوَحْيِ وَغَيْرِهِ وَإِذَا نَزَلَ فَعَلَ مِثْلَ ذَلِكَ فَنَزَلَ صَاحِبِي الْأَنْصَارِيُّ يَوْمَ نَوْبَتِهِ فَضَرَبَ بَابِي ضَرْبًا شَدِيدًا فَقَالَ أَثَمَّ هُوَ فَفَزِعْتُ فَخَرَجْتُ إِلَيْهِ فَقَالَ قَدْ حَدَثَ أَمْرٌ عَظِيمٌ قَالَ فَدَخَلْتُ عَلَى حَفْصَةَ فَإِذَا هِيَ تَبْكِي فَقُلْتُ طَلَّقَكُنَّ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَتْ لَا أَدْرِي ثُمَّ دَخَلْتُ عَلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقُلْتُ وَأَنَا قَائِمٌ أَطَلَّقْتَ نِسَاءَكَ قَالَ لَا فَقُلْتُ اللَّهُ أَكْبَرُ","id":"Telah menceritakan kepada kami [Abu Al Yaman] telah mengabarkan kepada kami [Syu'aib] dari [Az Zuhri]. Menurut jalur yang lainnya; Abu Abdullah berkata; dan berkata [Ibnu Wahb]; telah mengabarkan kepada kami [Yunus] dari [Ibnu Syihab] dari ['Ubaidullah bin Abdullah bin Abu Tsaur] dari [Abdullah bin 'Abbas] dari [Umar] berkata: Aku dan tetanggaku dari Anshar berada di desa Banu Umayyah bin Zaid dia termasuk orang kepercayaan di Madinah, kami saling bergantian menimba ilmu dari Rasul shallallahu 'alaihi wasallam, sehari aku yang menemui Beliau shallallahu 'alaihi wasallam dan hari lain dia yang menemui Beliau shallallahu 'alaihi wasallam, Jika giliranku tiba, aku menanyakan seputar wahyu yang turun hari itu dan perkara lainnya. Dan jika giliran tetanggaku tiba, ia pun melakukan hal yang sama. Ketika hari giliran tetanggaku tiba, dia datang kepadaku dengan mengetuk pintuku dengan sangat keras, seraya berkata: \"Apakah dia ada disana?\" Maka aku kaget dan keluar menemuinya. Dia berkata: \"Telah terjadi persoalan yang gawat!\". Umar berkata: \"Aku pergi menemui Hafshah, dan ternyata dia sedang menangis, aku bertanya kepadanya: \"Apakah Rasul shallallahu 'alaihi wasallam menceraikanmu?\" Hafshah menjawab: \"Aku tidak tahu\". Maka aku menemui Nabi shallallahu 'alaihi wasallam, sambil berdiri aku tanyakan: \"Apakah engkau menceraikan istri-istri engkau?\" Nabi shallallahu 'alaihi wasallam menjawab: \"Tidak\". Maka aku ucapkan: \"Allah Maha Besar\". "},"88":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ كَثِيرٍ قَالَ أَخْبَرَنَا سُفْيَانُ عَنْ ابْنِ أَبِي خَالِدٍ عَنْ قَيْسِ بْنِ أَبِي حَازِمٍ عَنْ أَبِي مَسْعُودٍ الْأَنْصَارِيِّ قَالَقَالَ رَجُلٌ يَا رَسُولَ اللَّهِ لَا أَكَادُ أُدْرِكُ الصَّلَاةَ مِمَّا يُطَوِّلُ بِنَا فُلَانٌ فَمَا رَأَيْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي مَوْعِظَةٍ أَشَدَّ غَضَبًا مِنْ يَوْمِئِذٍ فَقَالَ أَيُّهَا النَّاسُ إِنَّكُمْ مُنَفِّرُونَ فَمَنْ صَلَّى بِالنَّاسِ فَلْيُخَفِّفْ فَإِنَّ فِيهِمْ الْمَرِيضَ وَالضَّعِيفَ وَذَا الْحَاجَةِ","id":"Telah menceritakan kepada kami [Muhammad bin Katsir] berkata, telah mengabarkan kepada kami [Sufyan] dari [Ibnu Abu Khalid] dari [Qais bin Abu Hazim] dari [Abu Al Mas'ud Al Anshari] berkata, seorang sahabat bertanya: \"Wahai Rasulullah, aku hampir tidak sanggup shalat yang dipimpin seseorang dengan bacaannya yang panjang.\" Maka aku belum pernah melihat Nabi shallallahu 'alaihi wasallam memberi peringatan dengan lebih marah dari yang disampaikannya hari itu seraya bersabda: \"Wahai manusia, kalian membuat orang lari menjauh. Maka barangsiapa shalat mengimami orang-orang ringankanlah. Karena diantara mereka ada orang sakit, orang lemah dan orang yang punya keperluan\". "},"89":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مُحَمَّدٍ قَالَ حَدَّثَنَا عَبْدُ الْمَلِكِ بْنُ عَمْرٍو الْعَقَدِيُّ قَالَ حَدَّثَنَا سُلَيْمَانُ بْنُ بِلَالٍ الْمَدِينِيُّ عَنْ رَبِيعَةَ بْنِ أَبِي عَبْدِ الرَّحْمَنِ عَنْ يَزِيدَ مَوْلَى الْمُنْبَعِثِ عَنْ زَيْدِ بْنِ خَالِدٍ الْجُهَنِيِّأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ سَأَلَهُ رَجُلٌ عَنْ اللُّقَطَةِ فَقَالَ اعْرِفْ وِكَاءَهَا أَوْ قَالَ وِعَاءَهَا وَعِفَاصَهَا ثُمَّ عَرِّفْهَا سَنَةً ثُمَّ اسْتَمْتِعْ بِهَا فَإِنْ جَاءَ رَبُّهَا فَأَدِّهَا إِلَيْهِ قَالَ فَضَالَّةُ الْإِبِلِ فَغَضِبَ حَتَّى احْمَرَّتْ وَجْنَتَاهُ أَوْ قَالَ احْمَرَّ وَجْهُهُ فَقَالَ وَمَا لَكَ وَلَهَا مَعَهَا سِقَاؤُهَا وَحِذَاؤُهَا تَرِدُ الْمَاءَ وَتَرْعَى الشَّجَرَ فَذَرْهَا حَتَّى يَلْقَاهَا رَبُّهَا قَالَ فَضَالَّةُ الْغَنَمِ قَالَ لَكَ أَوْ لِأَخِيكَ أَوْ لِلذِّئْبِ","id":"Telah menceritakan kepada kami [Abdullah bin Muhammad] berkata, Telah menceritakan kepada kami [Abdul Malik bin 'Amru Al 'Aqadi] berkata, Telah menceritakan kepada kami [Sulaiman bin Bilal Al Madini] dari [Rabi'ah bin Abu Abdurrahman] dari [Yazid] mantan budak Al Munba'its, dari [Zaid bin Khalid Al Juhani] bahwa Nabi shallallahu 'alaihi wasallam ditanya oleh seseorang tentang barang temuan, maka Nabi shallallahu 'alaihi wasallam bersabda: \"Kenalilah tali pengikatnya, atau Beliau berkata; kantong dan tutupnya, kemudian umumkan selama satu tahun, setelah itu pergunakanlah. Jika datang pemiliknya maka berikanlah kepadanya\". Orang itu bertanya: \"Bagaimana dengan orang yang menemukan unta?\" Maka Nabi shallallahu 'alaihi wasallam marah hingga nampak merah mukanya, lalu berkata: \"apa urusanmu dengan unta itu, sedang dia selalu membawa air di perutnya, bersepatu sehingga dapat hilir mudik mencari minum dan makan rerumputan, maka biarkanlah dia hingga pemiliknya datang mengambilnya\". Orang itu bertanya lagi tentang menemukan kambing, maka Beliau menjawab: \"Itu untuk kamu atau saudaramu atau serigala\". "},"90":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ الْعَلَاءِ قَالَ حَدَّثَنَا أَبُو أُسَامَةَ عَنْ بُرَيْدٍ عَنْ أَبِي بُرْدَةَ عَنْ أَبِي مُوسَى قَالَسُئِلَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ أَشْيَاءَ كَرِهَهَا فَلَمَّا أُكْثِرَ عَلَيْهِ غَضِبَ ثُمَّ قَالَ لِلنَّاسِ سَلُونِي عَمَّا شِئْتُمْ قَالَ رَجُلٌ مَنْ أَبِي قَالَ أَبُوكَ حُذَافَةُ فَقَامَ آخَرُ فَقَالَ مَنْ أَبِي يَا رَسُولَ اللَّهِ فَقَالَ أَبُوكَ سَالِمٌ مَوْلَى شَيْبَةَ فَلَمَّا رَأَى عُمَرُ مَا فِي وَجْهِهِ قَالَ يَا رَسُولَ اللَّهِ إِنَّا نَتُوبُ إِلَى اللَّهِ عَزَّ وَجَلَّ","id":"Telah menceritakan kepada kami [Muhammad bin Al 'Ala`] berkata, Telah menceritakan kepada kami [Abu Usamah] dari [Buraid] dari [Abu Burdah] dari [Abu Musa] berkata; Nabi shallallahu 'alaihi wasallam pernah ditanya tentang sesuatu yang Beliau tidak suka, ketika terus ditanya, Beliau marah lalu berkata kepada orang-orang: \"Bertanyalah kepadaku sesuka kalian\". Maka seseorang bertanya: \"Siapakah bapakku?\" Beliau shallallahu 'alaihi wasallam menjawab: \"Bapakmu adalah Hudzafah\". Yang lain bertanya: \"Siapakah bapakku wahai Rasulullah shallallahu 'alaihi wasallam?: \"Bapakmu Salim, sahaya Syaibah\" Ketika Umar melihat apa yang ada pada wajah Beliau, dia berkata: \"Wahai Rasulullah, kami bertaubat kepada Allah 'azza wajalla\". "},"91":{"ar":"حَدَّثَنَا أَبُو الْيَمَانِ قَالَ أَخْبَرَنَا شُعَيْبٌ عَنْ الزُّهْرِيِّ قَالَ أَخْبَرَنِي أَنَسُ بْنُ مَالِكٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ خَرَجَ فَقَامَ عَبْدُ اللَّهِ بْنُ حُذَافَةَ فَقَالَ مَنْ أَبِي فَقَالَ أَبُوكَ حُذَافَةُ ثُمَّ أَكْثَرَ أَنْ يَقُولَ سَلُونِي فَبَرَكَ عُمَرُ عَلَى رُكْبَتَيْهِ فَقَالَ رَضِينَا بِاللَّهِ رَبًّا وَبِالْإِسْلَامِ دِينًا وَبِمُحَمَّدٍ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَبِيًّا فَسَكَتَ","id":"Telah menceritakan kepada kami [Abu Al Yaman] berkata, telah mengabarkan kepada kami [Syu'aib] dari [Az Zuhri] berkata, telah mengabarkan kepadaku [Anas bin Malik] bahwa Rasulullah shallallahu 'alaihi wasallam keluar, lalu Abdullah bin Hudzafah menghadap kepadanya dan berkata: \"Siapakah bapakku?\" Nabi shallallahu 'alaihi wasallam menjawab: \"Bapakmu Hudzaafah\". Ketika semakin banyak pertanyaan, Nabi bersabda: \"Bertanyalah kalian kepadaku?\" Maka Umar turun berlutut seraya berkata: \"Kami ridla Allah sebagai Rabb kami, Islam sebagai agama kami dan Muhammad shallallahu 'alaihi wasallam sebagai Nabi Kami.\" Maka Abdullah bin Hudzafah terdiam. "},"92":{"ar":"حَدَّثَنَا عَبْدَةُ قَالَ حَدَّثَنَا عَبْدُ الصَّمَدِ قَالَ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ الْمُثَنَّى قَالَ حَدَّثَنَا ثُمَامَةُ بْنُ عَبْدِ اللَّهِ عَنْ أَنَسٍعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُ كَانَ إِذَا سَلَّمَ سَلَّمَ ثَلَاثًا وَإِذَا تَكَلَّمَ بِكَلِمَةٍ أَعَادَهَا ثَلَاثًا","id":"Telah menceritakan kepada kami [Abdah] berkata, Telah menceritakan kepada kami [Abdushshamad] berkata, Telah menceritakan kepada kami [Abdullah bin Al Mutsanna] berkata; [Tsumamah bin Abdullah] telah menceritakan kepada kami dari [Anas] dari Nabi shallallahu 'alaihi wasallam, bahwa Nabi shallallahu 'alaihi wasallam apabila memberi salam, diucapkannya tiga kali dan bila berbicara dengan satu kalimat diulangnya tiga kali. "},"93":{"ar":"حَدَّثَنَا عَبْدَةُ بْنُ عَبْدِ اللَّهِ الصَّفَارُ حَدَّثَنَا عَبْدُ الصَّمَدِ قَالَ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ الْمُثَنَّى قَالَ حَدَّثَنَا ثُمَامَةُ بْنُ عَبْدِ اللَّهِ عَنْ أَنَسٍعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُ كَانَ إِذَا تَكَلَّمَ بِكَلِمَةٍ أَعَادَهَا ثَلَاثًا حَتَّى تُفْهَمَ عَنْهُ وَإِذَا أَتَى عَلَى قَوْمٍ فَسَلَّمَ عَلَيْهِمْ سَلَّمَ عَلَيْهِمْ ثَلَاثًا","id":"Telah menceritakan kepada kami ['Abdah bin Abdullah Ash Shafar] Telah menceritakan kepada kami [Abdushshamad] berkata, Telah menceritakan kepada kami [Abdullah bin Al Mutsanna] berkata; [Tsumamah bin Abdullah] telah menceritakan kepada kami dari [Anas] dari Nabi shallallahu 'alaihi wasallam, bahwa Nabi shallallahu 'alaihi wasallam bila berbicara diulangnya tiga kali hingga dapat dipahami dan bila mendatangi kaum, Beliau memberi salam tiga kali. "},"94":{"ar":"حَدَّثَنَا مُسَدَّدٌ قَالَ حَدَّثَنَا أَبُو عَوَانَةَ عَنْ أَبِي بِشْرٍ عَنْ يُوسُفَ بْنِ مَاهَكَ عَنْ عَبْدِ اللَّهِ بْنِ عَمْرٍو قَالَتَخَلَّفَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي سَفَرٍ سَافَرْنَاهُ فَأَدْرَكَنَا وَقَدْ أَرْهَقْنَا الصَّلَاةَ صَلَاةَ الْعَصْرِ وَنَحْنُ نَتَوَضَّأُ فَجَعَلْنَا نَمْسَحُ عَلَى أَرْجُلِنَا فَنَادَى بِأَعْلَى صَوْتِهِ وَيْلٌ لِلْأَعْقَابِ مِنْ النَّارِ مَرَّتَيْنِ أَوْ ثَلَاثًا","id":"Telah menceritakan kepada kami [Musaddad] berkata, Telah menceritakan kepada kami [Abu 'Awanah] dari [Abu Bisyir] dari [Yusuf bin Mahak] dari [Abdullah bin 'Amru] berkata, Nabi shallallahu 'alaihi wasallam pernah tertinggal dari kami dalam suatu perjalanan yang kami lakukan, hingga Beliau mendapatkan kami sementara waktu shalat sudah hampir habis, maka kami berwudlu' dengan hanya mengusap kaki kami. Maka Nabi shallallahu 'alaihi wasallam berseru dengan suara yang keras: \"celakalah bagi tumit-tumit yang tidak basah akan masuk neraka.\" Diserukannya hingga dua atau tiga kali. "},"95":{"ar":"أَخْبَرَنَا مُحَمَّدٌ هُوَ ابْنُ سَلَامٍ حَدَّثَنَا الْمُحَارِبِيُّ قَالَ حَدَّثَنَا صَالِحُ بْنُ حَيَّانَ قَالَ قَالَ عَامِرٌ الشَّعْبِيُّ حَدَّثَنِي أَبُو بُرْدَةَ عَنْ أَبِيهِ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ثَلَاثَةٌ لَهُمْ أَجْرَانِ رَجُلٌ مِنْ أَهْلِ الْكِتَابِ آمَنَ بِنَبِيِّهِ وَآمَنَ بِمُحَمَّدٍ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَالْعَبْدُ الْمَمْلُوكُ إِذَا أَدَّى حَقَّ اللَّهِ وَحَقَّ مَوَالِيهِ وَرَجُلٌ كَانَتْ عِنْدَهُ أَمَةٌ فَأَدَّبَهَا فَأَحْسَنَ تَأْدِيبَهَا وَعَلَّمَهَا فَأَحْسَنَ تَعْلِيمَهَا ثُمَّ أَعْتَقَهَا فَتَزَوَّجَهَا فَلَهُ أَجْرَانِثُمَّ قَالَ عَامِرٌ أَعْطَيْنَاكَهَا بِغَيْرِ شَيْءٍ قَدْ كَانَ يُرْكَبُ فِيمَا دُونَهَا إِلَى الْمَدِينَةِ","id":"Telah mengabarkan kepada kami [Muhammad Ibnu Salam], Telah menceritakan kepada kami [Al Muharibi] berkata, Telah menceritakan kepada kami [Shalih bin Al Hayyan] berkata, telah berkata ['Amir Asy Sya'bi]; telah menceritakan kepadaku [Abu Burdah] dari [bapaknya] berkata, telah bersabda Rasulullah shallallahu 'alaihi wasallam: \"Ada tiga orang yang akan mendapat pahala dua kali; seseorang dari Ahlul Kitab yang beriman kepada Nabinya dan beriman kepada Muhammad shallallahu 'alaihi wasallam, dan seorang hamba sahaya yang menunaikan hak Allah dan hak tuannya. Dan seseorang yang memiliki hamba sahaya wanita lalu dia memperlakukannya dengan baik, mendidiknya dengan baik, dan mengajarkan kepadanya dengan sebaik-baik pengajaran, kemudian membebaskannya dan menikahinya, maka baginya dua pahala\". Berkata 'Amir: \"Aku berikan permasalahan ini kepadamu tanpa imbalan, dan sungguh telah ditempuh untuk memperolehnya dengan menuju Madinah\". "},"96":{"ar":"حَدَّثَنَا سُلَيْمَانُ بْنُ حَرْبٍ قَالَ حَدَّثَنَا شُعْبَةُ عَنْ أَيُّوبَ قَالَ سَمِعْتُ عَطَاءً قَالَ سَمِعْتُ ابْنَ عَبَّاسٍ قَالَأَشْهَدُ عَلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَوْ قَالَ عَطَاءٌ أَشْهَدُ عَلَى ابْنِ عَبَّاسٍ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ خَرَجَ وَمَعَهُ بِلَالٌ فَظَنَّ أَنَّهُ لَمْ يُسْمِعْ فَوَعَظَهُنَّ وَأَمَرَهُنَّ بِالصَّدَقَةِ فَجَعَلَتْ الْمَرْأَةُ تُلْقِي الْقُرْطَ وَالْخَاتَمَ وَبِلَالٌ يَأْخُذُ فِي طَرَفِ ثَوْبِهِقَالَ أَبُو عَبْد اللَّهِ وَقَالَ إِسْمَاعِيلُ عَنْ أَيُّوبَ عَنْ عَطَاءٍ وَقَالَ عَنْ ابْنِ عَبَّاسٍ أَشْهَدُ عَلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah menceritakan kepada kami [Sulaiman bin Harb] berkata, Telah menceritakan kepada kami [Syu'bah] dari [Ayyub] berkata; aku mendengar ['Atho'] berkata; aku mendengar [Ibnu 'Abbas] berkata: aku menyaksikan bahwa Nabi shallallahu 'alaihi wasallam -sedang menurut 'Atho', dia berkata; aku menyaksikan Ibnu 'Abbas berkata; - bahwa Nabi shallallahu 'alaihi wasallam keluar bersama Bilal, -dan dia mengira bahwa dia tidak mendengar, - maka Nabi memberi pelajaran kepada para wanita dan memerintahkan untuk bersedekah, maka seorang wanita memberikan anting dan cincin emasnya, dan Bilal memasukkannya ke saku bajunya. Berkata Abu Abdullah; dan [Isma'il] berkata; dari [Ayyub] dari ['Atho'], dan dia berkata; dari [Ibnu 'Abbas] bahwa ia bersaksi terhadap Rasulullah shallallahu 'alaihi wasallam"},"97":{"ar":"حَدَّثَنَا عَبْدُ الْعَزِيزِ بْنُ عَبْدِ اللَّهِ قَالَ حَدَّثَنِي سُلَيْمَانُ عَنْ عَمْرِو بْنِ أَبِي عَمْرٍو عَنْ سَعِيدِ بْنِ أَبِي سَعِيدٍ الْمَقْبُرِيِّ عَنْ أَبِي هُرَيْرَةَ أَنَّهُ قَالَقِيلَ يَا رَسُولَ اللَّهِ مَنْ أَسْعَدُ النَّاسِ بِشَفَاعَتِكَ يَوْمَ الْقِيَامَةِ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَقَدْ ظَنَنْتُ يَا أَبَا هُرَيْرَةَ أَنْ لَا يَسْأَلُنِي عَنْ هَذَا الْحَدِيثِ أَحَدٌ أَوَّلُ مِنْكَ لِمَا رَأَيْتُ مِنْ حِرْصِكَ عَلَى الْحَدِيثِ أَسْعَدُ النَّاسِ بِشَفَاعَتِي يَوْمَ الْقِيَامَةِ مَنْ قَالَ لَا إِلَهَ إِلَّا اللَّهُ خَالِصًا مِنْ قَلْبِهِ أَوْ نَفْسِهِ","id":"Telah menceritakan kepada kami [Abdul 'Aziz bin Abdullah] berkata, telah menceritakan kepadaku [Sulaiman] dari ['Amru bin Abu 'Amru] dari [Sa'id Al Maqburi] dari [Abu Hurairah], bahwa dia berkata: ditanyakan (kepada Rasulullah shallallahu 'alaihi wasallam: \"Wahai Rasulullah siapakah orang yang paling berbahagia dengan syafa'atmu pada hari kiamat?\" Rasulullah shallallahu 'alaihi wasallam menjawab: \"Aku telah menduga wahai Abu Hurairah, bahwa tidak ada orang yang mendahuluimu dalam menanyakan masalah ini, karena aku lihat betapa perhatian dirimu terhadap hadits. Orang yang paling berbahagia dengan syafa'atku pada hari kiamat adalah orang yang mengucapkan Laa ilaaha illallah dengan ikhlas dari hatinya atau jiwanya\"."},"98":{"ar":"حَدَّثَنَا إِسْمَاعِيلُ بْنُ أَبِي أُوَيْسٍ قَالَ حَدَّثَنِي مَالِكٌ عَنْ هِشَامِ بْنِ عُرْوَةَ عَنْ أَبِيهِ عَنْ عَبْدِ اللَّهِ بْنِ عَمْرِو بْنِ الْعَاصِ قَالَسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ إِنَّ اللَّهَ لَا يَقْبِضُ الْعِلْمَ انْتِزَاعًا يَنْتَزِعُهُ مِنْ الْعِبَادِ وَلَكِنْ يَقْبِضُ الْعِلْمَ بِقَبْضِ الْعُلَمَاءِ حَتَّى إِذَا لَمْ يُبْقِ عَالِمًا اتَّخَذَ النَّاسُ رُءُوسًا جُهَّالًا فَسُئِلُوا فَأَفْتَوْا بِغَيْرِ عِلْمٍ فَضَلُّوا وَأَضَلُّواقَالَ الْفِرَبْرِيُّ حَدَّثَنَا عَبَّاسٌ قَالَ حَدَّثَنَا قُتَيْبَةُ حَدَّثَنَا جَرِيرٌ عَنْ هِشَامٍ نَحْوَهُ","id":"Telah menceritakan kepada kami [Isma'il bin Abu Uwais] berkata, telah menceritakan kepadaku [Malik] dari [Hisyam bin 'Urwah] dari [bapaknya] dari [Abdullah bin 'Amru bin Al 'Ash] berkata; aku mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya Allah tidaklah mencabut ilmu sekaligus mencabutnya dari hamba, akan tetapi Allah mencabut ilmu dengan cara mewafatkan para ulama hingga bila sudah tidak tersisa ulama maka manusia akan mengangkat pemimpin dari kalangan orang-orang bodoh, ketika mereka ditanya mereka berfatwa tanpa ilmu, mereka sesat dan menyesatkan\". Berkata Al Firabri Telah menceritakan kepada kami 'Abbas berkata, Telah menceritakan kepada kami Qutaibah Telah menceritakan kepada kami Jarir dari Hisyam seperti ini juga. "},"99":{"ar":"حَدَّثَنَا آدَمُ قَالَ حَدَّثَنَا شُعْبَةُ قَالَ حَدَّثَنِي ابْنُ الْأَصْبَهَانِيِّ قَالَ سَمِعْتُ أَبَا صَالِحٍ ذَكْوَانَ يُحَدِّثُ عَنْ أَبِي سَعِيدٍ الْخُدْرِيِّقَالَتْ النِّسَاءُ لِلنَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ غَلَبَنَا عَلَيْكَ الرِّجَالُ فَاجْعَلْ لَنَا يَوْمًا مِنْ نَفْسِكَ فَوَعَدَهُنَّ يَوْمًا لَقِيَهُنَّ فِيهِ فَوَعَظَهُنَّ وَأَمَرَهُنَّ فَكَانَ فِيمَا قَالَ لَهُنَّ مَا مِنْكُنَّ امْرَأَةٌ تُقَدِّمُ ثَلَاثَةً مِنْ وَلَدِهَا إِلَّا كَانَ لَهَا حِجَابًا مِنْ النَّارِ فَقَالَتْ امْرَأَةٌ وَاثْنَتَيْنِ فَقَالَ وَاثْنَتَيْنِحَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ قَالَ حَدَّثَنَا غُنْدَرٌ قَالَ حَدَّثَنَا شُعْبَةُ عَنْ عَبْدِ الرَّحْمَنِ بْنِ الْأَصْبَهَانِيِّ عَنْ ذَكْوَانَ عَنْ أَبِي سَعِيدٍ الْخُدْرِيِّ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِهَذَا وَعَنْ عَبْدِ الرَّحْمَنِ بْنِ الْأَصْبَهَانِيِّ قَالَ سَمِعْتُ أَبَا حَازِمٍ عَنْ أَبِي هُرَيْرَةَ قَالَ ثَلَاثَةً لَمْ يَبْلُغُوا الْحِنْثَ","id":"Telah menceritakan kepada kami [Adam] berkata, Telah menceritakan kepada kami [Syu'bah] berkata, telah menceritakan kepadaKu [Ibnu Al Ashbahani] berkata; aku mendengar [Abu Shalih Dzakwan] menceritakan dari [Abu Sa'id Al Khudri]; kaum wanita berkata kepada Nabi shallallahu 'alaihi wasallam: \"kaum lelaki telah mengalahkan kami untuk bertemu dengan engkau, maka berilah kami satu hari untuk bermajelis dengan diri tuan\" Maka Nabi shallallahu 'alaihi wasallam berjanji kepada mereka satu untuk bertemu mereka, lalu Nabi shallallahu 'alaihi wasallam memberi pelajaran dan memerintahkan kepada mereka, diantara yang disampaikannya adalah: \"Tidak seorangpun dari kalian yang didahului oleh tiga orang dari anaknya kecuali akan menjadi tabir bagi dirinya dari neraka\". Berkata seseorang: \"bagaimana kalau dua orang?\" Nabi shallallahu 'alaihi wasallam menjawab: \"Juga dua\". Telah menceritakan kepada kami [Muhammad bin Basysyar] berkata, Telah menceritakan kepada kami [Ghundar] berkata, Telah menceritakan kepada kami [Syu'bah] dari [Abdurrahman Al Ashbahani] dari [Dzakwan] dari [Abu Sa'id Al Khudri] dari Nabi shallallahu 'alaihi wasallam. Dan dengan sanad seperti ini dari [Abdurrahman Al Ashbahani] berkata; aku mendengar [Abu Hazm] dari [Abu Hurairah] berkata: \"Tiga orang yang belum baligh\". "},"100":{"ar":"حَدَّثَنَا سَعِيدُ بْنُ أَبِي مَرْيَمَ قَالَ أَخْبَرَنَا نَافِعُ بْنُ عُمَرَ قَالَ حَدَّثَنِي ابْنُ أَبِي مُلَيْكَةَ أَنَّ عَائِشَةَ زَوْجَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَكَانَتْ لَا تَسْمَعُ شَيْئًا لَا تَعْرِفُهُ إِلَّا رَاجَعَتْ فِيهِ حَتَّى تَعْرِفَهُ وَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ حُوسِبَ عُذِّبَ قَالَتْ عَائِشَةُ فَقُلْتُ أَوَلَيْسَ يَقُولُ اللَّهُ تَعَالَى{ فَسَوْفَ يُحَاسَبُ حِسَابًا يَسِيرًا }قَالَتْ فَقَالَ إِنَّمَا ذَلِكِ الْعَرْضُ وَلَكِنْ مَنْ نُوقِشَ الْحِسَابَ يَهْلِكْ","id":"Telah menceritakan kepada kami [Sa'id bin Abu Maryam] berkata, telah mengabarkan kepada kami [Nafi' bin Umar] berkata, telah menceritakan kepadaku [Ibnu Abu Mulaikah] bahwa [Aisyah] istri Nabi shallallahu 'alaihi wasallam tidaklah mendengar sesuatu yang tidak dia mengerti kecuali menanyakannya kepada Nabi shallallahu 'alaihi wasallam sampai dia mengerti, dan Nabi shallallahu 'alaihi wasallam pernah bersabda: \"Siapa yang dihisab berarti dia disiksa\" Aisyah berkata: maka aku bertanya kepada Nabi: \"Bukankah Allah Ta'ala berfirman: \"Kelak dia akan dihisab dengan hisab yang ringan\" Aisyah berkata: Maka Nabi shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya yang dimaksud itu adalah pemaparan (amalan). Akan tetapi barangsiapa yang didebat hisabnya pasti celaka\"."},"101":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ يُوسُفَ قَالَ حَدَّثَنِي اللَّيْثُ قَالَ حَدَّثَنِي سَعِيدٌ هُوَ ابْنُ أَبِي سَعِيدٍ عَنْ أَبِي شُرَيْحٍأَنَّهُ قَالَ لِعَمْرِو بْنِ سَعِيدٍ وَهُوَ يَبْعَثُ الْبُعُوثَ إِلَى مَكَّةَ ائْذَنْ لِي أَيُّهَا الْأَمِيرُ أُحَدِّثْكَ قَوْلًا قَامَ بِهِ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْغَدَ مِنْ يَوْمِ الْفَتْحِ سَمِعَتْهُ أُذُنَايَ وَوَعَاهُ قَلْبِي وَأَبْصَرَتْهُ عَيْنَايَ حِينَ تَكَلَّمَ بِهِ حَمِدَ اللَّهَ وَأَثْنَى عَلَيْهِ ثُمَّ قَالَ إِنَّ مَكَّةَ حَرَّمَهَا اللَّهُ وَلَمْ يُحَرِّمْهَا النَّاسُ فَلَا يَحِلُّ لِامْرِئٍ يُؤْمِنُ بِاللَّهِ وَالْيَوْمِ الْآخِرِ أَنْ يَسْفِكَ بِهَا دَمًا وَلَا يَعْضِدَ بِهَا شَجَرَةً فَإِنْ أَحَدٌ تَرَخَّصَ لِقِتَالِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِيهَا فَقُولُوا إِنَّ اللَّهَ قَدْ أَذِنَ لِرَسُولِهِ وَلَمْ يَأْذَنْ لَكُمْ وَإِنَّمَا أَذِنَ لِي فِيهَا سَاعَةً مِنْ نَهَارٍ ثُمَّ عَادَتْ حُرْمَتُهَا الْيَوْمَ كَحُرْمَتِهَا بِالْأَمْسِ وَلْيُبَلِّغْ الشَّاهِدُ الْغَائِبَ فَقِيلَ لِأَبِي شُرَيْحٍ مَا قَالَ عَمْرٌو قَالَ أَنَا أَعْلَمُ مِنْكَ يَا أَبَا شُرَيْحٍ لَا يُعِيذُ عَاصِيًا وَلَا فَارًّا بِدَمٍ وَلَا فَارًّا بِخَرْبَةٍ","id":"Telah menceritakan kepada kami ['Abdullah bin Yusuf] berkata,, telah menceritakan kepada saya [Al Laits] berkata, telah menceritakan kepada saya [Sa'id] dia adalah anaknya Abu Sa'id dari [Abu Syuraih] bahwa dia berkata kepada 'Amru bin Sa'id saat dia mengutus rombongan ke Makkah, \"Wahai amir, izinkan aku menyampaikan satu persoalan yang pernah Nabi shallallahu 'alaihi wasallam sampaikan dalam khutbahnya saat pembebasan Makkah. Kedua telingaku mendengar, hatiku merasakannya dan kedua mataku melihat, beliau memuji Allah dan mensucikan Allah seraya bersabda: 'Sesungguhnya Makkah, Allah telah mensucikannya dan orang-orang (Musyrikin Makkah) tidak mensucikannya. Maka tidak halal bagi setiap orang yang beriman kepada Allah dan Hari Akhir menumpahkan darah di dalamnya, dan tidak boleh mencabut pepohonan di dalamnya. Jika seseorang minta keringanan karena peperangan yang pernah dilakukan oleh Rasulullah shallallahu 'alaihi wasallam di dalamnya maka katakanlah 'sesungguhnya Allah Ta'ala telah mengizinkan Rasul-Nya dan tidak mengizinkan kepada kalian.' Sesungguhnya Allah Ta'ala telah mengizinkanku pada satu saat pada siang hari kemudian dikembalikan kesuciannya hari ini sebagaimana disucikannya sebelumnya. Maka hendaklah yang hadir menyampaikan kepada yang tidak hadir.\" Maka dikatakan kepada Abu Syuraij, \"Apa yang dikatakan 'Amru?\" Dia berkata, \"Aku lebih mengetahui daripadamu wahai Abu Syuraij: \"Beliau tidak akan melindungi orang yang bermaksiat, orang yang menumpahkan darah dan orang yang mencuri.\""},"102":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ عَبْدِ الْوَهَّابِ قَالَ حَدَّثَنَا حَمَّادٌ عَنْ أَيُّوبَ عَنْ مُحَمَّدٍ عَنْ ابْنِ أَبِي بَكْرَةَ عَنْ أَبِي بَكْرَةَذُكِرَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ فَإِنَّ دِمَاءَكُمْ وَأَمْوَالَكُمْ قَالَ مُحَمَّدٌ وَأَحْسِبُهُ قَالَ وَأَعْرَاضَكُمْ عَلَيْكُمْ حَرَامٌ كَحُرْمَةِ يَوْمِكُمْ هَذَا فِي شَهْرِكُمْ هَذَا أَلَا لِيُبَلِّغ الشَّاهِدُ مِنْكُمْ الْغَائِبَ وَكَانَ مُحَمَّدٌ يَقُولُ صَدَقَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ ذَلِكَ أَلَا هَلْ بَلَّغْتُ مَرَّتَيْنِ","id":"Telah menceritakan kepada kami ['Abdullah bin 'Abdul Wahhab] berkata, telah menceritakan kepada kami [Hammad] dari [Ayyub] dari [Muhammad] dari [Ibnu Abu Bakrah] dari [Abu Bakrah] Nabi shallallahu 'alaihi wasallam menyebutkan: \"Sesungguhnya darah kalian, harta kalian, Muhammad berkata; menurutku beliau mengatakan, \"dan kehormatan kalian adalah haram atas kalian sebagaimana haramnya hari kalian ini di bulan kalian ini. Hendaklah yang hadir menyampaikan kepada yang tidak hadir.\" Dan Muhammad berkata, \"Benarlah Rasulullah shallallahu 'alaihi wasallam seperti apa yang disabdakannya, 'Bukankah aku telah menyampaikannya? ' beliau ulangi hingga dua kali."},"103":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ الْجَعْدِ قَالَ أَخْبَرَنَا شُعْبَةُ قَالَ أَخْبَرَنِي مَنْصُورٌ قَالَ سَمِعْتُ رِبْعِيَّ بْنَ حِرَاشٍ يَقُولُ سَمِعْتُ عَلِيًّا يَقُولُقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا تَكْذِبُوا عَلَيَّ فَإِنَّهُ مَنْ كَذَبَ عَلَيَّ فَلْيَلِجْ النَّارَ","id":"Telah menceritakan kepada kami ['Ali bin Al Ja'd] berkata, telah mengabarkan kepada kami [Syu'bah] berkata, telah mengabarkan kepadaku [Manshur] berkata, aku mendengar [Rib'i bin Jirasy] berkata, aku mendengar ['Ali] berkata, \"Nabi shallallahu 'alaihi wasallam bersabda: \"Janganlah kalian berdusta terhadapku (atas namaku), karena barangsiapa berduasta terhadapku dia akan masuk neraka.\""},"104":{"ar":"حَدَّثَنَا أَبُو الْوَلِيدِ قَالَ حَدَّثَنَا شُعْبَةُ عَنْ جَامِعِ بْنِ شَدَّادٍ عَنْ عَامِرِ بْنِ عَبْدِ اللَّهِ بْنِ الزُّبَيْرِ عَنْ أَبِيهِ قَالَ قُلْتُ لِلزُّبَيْرِإِنِّي لَا أَسْمَعُكَ تُحَدِّثُ عَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَمَا يُحَدِّثُ فُلَانٌ وَفُلَانٌ قَالَ أَمَا إِنِّي لَمْ أُفَارِقْهُ وَلَكِنْ سَمِعْتُهُ يَقُولُ مَنْ كَذَبَ عَلَيَّ فَلْيَتَبَوَّأْ مَقْعَدَهُ مِنْ النَّارِ","id":"Telah menceritakan kepada kami [Abu Al Walid] berkata, telah menceritakan kepada kami [Syu'bah] dari [Jami' bin Syaddad] dari ['Amir bin 'Abdullah bin Az Zubair] dari [Bapaknya] berkata, \"Aku berkata kepada [Az Zubair], \"Aku belum pernah mendengar kamu membicarakan sesuatu dari Rasulullah shallallahu 'alaihi wasallam sebagaimana orang-orang lain membicarakannya?\" Az Zubair menjawab, \"Aku tidak pernah berpisah dengan beliau, aku mendengar beliau mengatakan: \"Barangsiapa berdusta terhadapku maka hendaklah ia persiapkan tempat duduknya di neraka.\""},"105":{"ar":"حَدَّثَنَا أَبُو مَعْمَرٍ قَالَ حَدَّثَنَا عَبْدُ الْوَارِثِ عَنْ عَبْدِ الْعَزِيزِ قَالَ أَنَسٌإِنَّهُ لَيَمْنَعُنِي أَنْ أُحَدِّثَكُمْ حَدِيثًا كَثِيرًا أَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ تَعَمَّدَ عَلَيَّ كَذِبًا فَلْيَتَبَوَّأْ مَقْعَدَهُ مِنْ النَّارِ","id":"Telah menceritakan kepada kami [Abu Ma'mar] berkata, telah menceritakan kepada kami ['Abdul Warits] dari ['Abdul 'Aziz] berkata, [Anas] berkata, \"Beliau melarangku untuk banyak menceritakan hadits kepada kalian karena Nabi shallallahu 'alaihi wasallam bersabda: \"Barangsiapa sengaja berdusta terhadapku (atas namaku), maka hendaklah ia persiapkan tempat duduknya di neraka.\""},"106":{"ar":"حَدَّثَنَا مَكِّيُّ بْنُ إِبْرَاهِيمَ قَالَ حَدَّثَنَا يَزِيدُ بْنُ أَبِي عُبَيْدٍ عَنْ سَلَمَةَ قَالَسَمِعْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ مَنْ يَقُلْ عَلَيَّ مَا لَمْ أَقُلْ فَلْيَتَبَوَّأْ مَقْعَدَهُ مِنْ النَّارِ","id":"Telah menceritakan kepada kami [Makki bin Ibrahim] berkata, telah menceritakan kepada kami [Yazid bin Abu 'Ubaid] dari [Salamah] berkata, \"Aku mendengar Nabi shallallahu 'alaihi wasallam bersabda: \"Barangsiapa berkata tentangku yang tidak pernah aku katakan, maka hendaklah ia persiapkan tempat duduknya di neraka.\""},"107":{"ar":"حَدَّثَنَا مُوسَى قَالَ حَدَّثَنَا أَبُو عَوَانَةَ عَنْ أَبِي حَصِينٍ عَنْ أَبِي صَالِحٍ عَنْ أَبِي هُرَيْرَةَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ تَسَمَّوْا بِاسْمِي وَلَا تَكْتَنُوا بِكُنْيَتِي وَمَنْ رَآنِي فِي الْمَنَامِ فَقَدْ رَآنِي فَإِنَّ الشَّيْطَانَ لَا يَتَمَثَّلُ فِي صُورَتِي وَمَنْ كَذَبَ عَلَيَّ مُتَعَمِّدًا فَلْيَتَبَوَّأْ مَقْعَدَهُ مِنْ النَّارِ","id":"Telah menceritakan kepada kami [Musa] telah menceritakan kepada kami [Abu 'Awanah] dari [Abu Hushain] dari [Abu Shalih] dari [Abu Hurairah] ia berkata, \"Aku mendengar Nabi shallallahu 'alaihi wasallam bersabda: \"Berikanlah nama dengan namaku dan jangan dengan julukanku. Karena barangsiapa melihatku dalam mimpinya sungguh dia benar-benar telah melihatku, karena setan tidak sanggup menyerupai bentukku. Dan barangsiapa berdusta terhadapku, maka hendaklah ia persiapkan tempat duduknya dalam neraka.\""},"108":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ سَلَامٍ قَالَ أَخْبَرَنَا وَكِيعٌ عَنْ سُفْيَانَ عَنْ مُطَرِّفٍ عَنْ الشَّعْبِيِّ عَنْ أَبِي جُحَيْفَةَ قَالَ قُلْتُ لِعَلِيِّ بْنِ أَبِي طَالِبٍهَلْ عِنْدَكُمْ كِتَابٌ قَالَ لَا إِلَّا كِتَابُ اللَّهِ أَوْ فَهْمٌ أُعْطِيَهُ رَجُلٌ مُسْلِمٌ أَوْ مَا فِي هَذِهِ الصَّحِيفَةِ قَالَ قُلْتُ فَمَا فِي هَذِهِ الصَّحِيفَةِ قَالَ الْعَقْلُ وَفَكَاكُ الْأَسِيرِ وَلَا يُقْتَلُ مُسْلِمٌ بِكَافِرٍ","id":"Telah menceritakan kepada kami [Muhammad bin Salam] berkata, telah mengabarkan kepada kami [Waki'] dari [Sufyan] dari [Mutharrif] dari [Asy Sya'bi] dari [Abu Juhaifah] berkata, \"Aku bertanya kepada ['Ali bin Abu Thalib], \"Apakah kalian memiliki kitab?\" ia menjawab, \"Tidak, kecuali Kitabullah atau pemahaman yang diberikan kepada seorang Muslim, atau apa yang ada pada lembaran ini.\" Aku katakan, \"Apa yang ada dalam lembaran ini?\" Dia menjawab, \"Tebusan, membebaskan tawanan, dan jangan sampai seorang Muslim dibunuh demi membela seorang kafir.\""},"109":{"ar":"حَدَّثَنَا أَبُو نُعَيْمٍ الْفَضْلُ بْنُ دُكَيْنٍ قَالَ حَدَّثَنَا شَيْبَانُ عَنْ يَحْيَى عَنْ أَبِي سَلَمَةَ عَنْ أَبِي هُرَيْرَةَأَنَّ خُزَاعَةَ قَتَلُوا رَجُلًا مِنْ بَنِي لَيْثٍ عَامَ فَتْحِ مَكَّةَ بِقَتِيلٍ مِنْهُمْ قَتَلُوهُ فَأُخْبِرَ بِذَلِكَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَرَكِبَ رَاحِلَتَهُ فَخَطَبَ فَقَالَ إِنَّ اللَّهَ حَبَسَ عَنْ مَكَّةَ الْقَتْلَ أَوْ الْفِيلَ قَالَ أَبُو عَبْد اللَّهِ كَذَا قَالَ أَبُو نُعَيْمٍ وَاجْعَلُوهُ عَلَى الشَّكِّ الْفِيلَ أَوْ الْقَتْلَ وَغَيْرُهُ يَقُولُ الْفِيلَ وَسَلَّطَ عَلَيْهِمْ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَالْمُؤْمِنِينَ أَلَا وَإِنَّهَا لَمْ تَحِلَّ لِأَحَدٍ قَبْلِي وَلَمْ تَحِلَّ لِأَحَدٍ بَعْدِي أَلَا وَإِنَّهَا حَلَّتْ لِي سَاعَةً مِنْ نَهَارٍ أَلَا وَإِنَّهَا سَاعَتِي هَذِهِ حَرَامٌ لَا يُخْتَلَى شَوْكُهَا وَلَا يُعْضَدُ شَجَرُهَا وَلَا تُلْتَقَطُ سَاقِطَتُهَا إِلَّا لِمُنْشِدٍ فَمَنْ قُتِلَ فَهُوَ بِخَيْرِ النَّظَرَيْنِ إِمَّا أَنْ يُعْقَلَ وَإِمَّا أَنْ يُقَادَ أَهْلُ الْقَتِيلِ فَجَاءَ رَجُلٌ مِنْ أَهْلِ الْيَمَنِ فَقَالَ اكْتُبْ لِي يَا رَسُولَ اللَّهِ فَقَالَ اكْتُبُوا لِأَبِي فُلَانٍ فَقَالَ رَجُلٌ مِنْ قُرَيْشٍ إِلَّا الْإِذْخِرَ يَا رَسُولَ اللَّهِ فَإِنَّا نَجْعَلُهُ فِي بُيُوتِنَا وَقُبُورِنَا فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِلَّا الْإِذْخِرَ إِلَّا الْإِذْخِرَقَالَ أَبُو عَبْد اللَّهِ يُقَالُ يُقَادُ بِالْقَافِ فَقِيلَ لِأَبِي عَبْدِ اللَّهِ أَيُّ شَيْءٍ كَتَبَ لَهُ قَالَ كَتَبَ لَهُ هَذِهِ الْخُطْبَةَ","id":"Telah menceritakan kepada kami [Abu Nu'aim Al Fadll bin Dukain] berkata, telah menceritakan kepada kami [Syaiban] dari [Yahya] dari [Abu Salamah] dari [Abu Hurairah], bahwa suku Khaza'ah telah membunuh seorang laki-laki dari Bani Laits saat hari pembesan Makkah, sebagai balasan terbunuhnya seorang laki-laki dari mereka (suku Laits). Peristiwa itu lalu disampaikan kepada Nabi shallallahu 'alaihi wasallam, beliau lalu naik kendaraannya dan berkhutbah: \"Sesungguhnya Allah telah membebaskan Makkah dari pembunuhan, atau pasukan gajah.\" Abu Ubaidullah berkata, \"Demikian Abu Nu'aim menyebutkannya, mereka ragu antara 'pembunuhan' dan 'gajah'. Sedangkan yang lian berkata, \"Gajah. Lalu Allah memenangkan Rasulullah shallallahu 'alaihi wasallam dan kaum Mukminin atas mereka. Beliau bersabda: \"Ketahuilah tanah Makkah tidaklah halal bagi seorangpun baik sebelumku atau sesudahku, ketahuilah bahwa sesungguhnya ia pernah menjadi halal buatku sesaat di suatu hari. Ketahuilah, dan pada saat ini ia telah menjadi haram; durinya tidak boleh dipotong, pohonnya tidak boleh ditebang, barang temuannya tidak boleh diambil kecuali untuk diumumkan dan dicari pemiliknya. Maka barangsiapa dibunuh, dia akan mendapatkan satu dari dua kebaikan; meminta tebusan atau meminta balasan dari keluarga korban.\" Lalu datang seorang penduduk Yaman dan berkata, \"Wahai Rasulullah, tuliskanlah buatku?\" beliau lalu bersabda: \"Tuliskanlah untuk Abu fulan.\" Seorang laki-laki Quraisy lalu berkata, \"Kecuali pohon Idzhir wahai Rasulullah, karena pohon itu kami gunakan di rumah kami dan di kuburan kami.\" Maka Nabi shallallahu 'alaihi wasallam bersabda: \"Kecuali pohon Idzhir, kecuali pohon Idzhir.\" Lalu dikatakan kepada Abu Abdullah, \"Apa yang dituliskan untuknya?\" Ia menjawab, \"Khutbah tadi.\""},"110":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ عَبْدِ اللَّهِ قَالَ حَدَّثَنَا سُفْيَانُ قَالَ حَدَّثَنَا عَمْرٌو قَالَ أَخْبَرَنِي وَهْبُ بْنُ مُنَبِّهٍ عَنْ أَخِيهِ قَالَ سَمِعْتُ أَبَا هُرَيْرَةَ يَقُولُمَا مِنْ أَصْحَابِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَحَدٌ أَكْثَرَ حَدِيثًا عَنْهُ مِنِّي إِلَّا مَا كَانَ مِنْ عَبْدِ اللَّهِ بْنِ عَمْرٍو فَإِنَّهُ كَانَ يَكْتُبُ وَلَا أَكْتُبُتَابَعَهُ مَعْمَرٌ عَنْ هَمَّامٍ عَنْ أَبِي هُرَيْرَةَ","id":"Telah menceritakan kepada kami ['Ali bin 'Abdullah] berkata, telah menceritakan kepada kami [Sufyan] berkata, telah menceritakan kepada kami ['Amru] berkata, telah mengabarkan kepadaku [Wahhab bin Munabbih] dari [saudaranya] berkata, aku mendengar [Abu Hurairah] berkata, \"Tidaklah ada seorangpun dari sahabat Nabi shallallahu 'alaihi wasallam yang lebih banyak haditsnya dibandingkan aku, kecuali 'Abdullah bin 'Amru. Sebab ia bisa menulis sedang saya tidak.\" [Ma'mar] juga meriwayatkan dari [Hammam] dari [Abu Hurairah].\""},"111":{"ar":"حَدَّثَنَا يَحْيَى بْنُ سُلَيْمَانَ قَالَ حَدَّثَنِي ابْنُ وَهْبٍ قَالَ أَخْبَرَنِي يُونُسُ عَنْ ابْنِ شِهَابٍ عَنْ عُبَيْدِ اللَّهِ بْنِ عَبْدِ اللَّهِ عَنْ ابْنِ عَبَّاسٍ قَالَلَمَّا اشْتَدَّ بِالنَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَجَعُهُ قَالَ ائْتُونِي بِكِتَابٍ أَكْتُبْ لَكُمْ كِتَابًا لَا تَضِلُّوا بَعْدَهُ قَالَ عُمَرُ إِنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ غَلَبَهُ الْوَجَعُ وَعِنْدَنَا كِتَابُ اللَّهِ حَسْبُنَا فَاخْتَلَفُوا وَكَثُرَ اللَّغَطُ قَالَ قُومُوا عَنِّي وَلَا يَنْبَغِي عِنْدِي التَّنَازُعُفَخَرَجَ ابْنُ عَبَّاسٍ يَقُولُ إِنَّ الرَّزِيَّةَ كُلَّ الرَّزِيَّةِ مَا حَالَ بَيْنَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَبَيْنَ كِتَابِهِ","id":"Telah menceritakan kepada kami [Yahya bin Sulaiman] berkata, telah menceritakan kepadaku [Ibnu Wahhab] berkata, telah mengabarkan kepadaku [Yunus] dari [Ibnu Syihab] dari ['Ubaidullah bin 'Abdullah] dari [Ibnu 'Abbas] berkata, \"Ketika Nabi shallallahu 'alaihi wasallam bertambah parah sakitnya, beliau bersabda: \"Berikan aku surat biar aku tuliskan sesuatu untuk kalian sehingga kalian tidak akan sesat setelahku.\" Umar berkata, \"Sesungguhnya Nabi shallallahu 'alaihi wasallam semakin berat sakitnya dan di sisi kami ada Kitabullah, yang cukup buat kami. Kemudian orang-orang berselisih dan timbul suara gaduh, maka Nabi shallallahu 'alaihi wasallam bersabda: \"Pergilah kalian menjauh dariku, tidak pantas terjadi perdebatan di hadapanku.\" Maka Ibnu 'Abbas keluar seraya berkata, \"Ini adalah musibah, dan sungguh segala musibah tidak boleh terjadi di hadapan Rasulullah shallallahu 'alaihi wasallam dan Al Qur'an.\""},"112":{"ar":"حَدَّثَنَا صَدَقَةُ أَخْبَرَنَا ابْنُ عُيَيْنَةَ عَنْ مَعْمَرٍ عَنْ الزُّهْرِيِّ عَنْ هِنْدٍ عَنْ أُمِّ سَلَمَةَ وَعَمْرٍو وَيَحْيَى بْنِ سَعِيدٍ عَنْ الزُّهْرِيِّ عَنْ هِنْدٍ عَنْ أُمِّ سَلَمَةَ قَالَتْاسْتَيْقَظَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ذَاتَ لَيْلَةٍ فَقَالَ سُبْحَانَ اللَّهِ مَاذَا أُنْزِلَ اللَّيْلَةَ مِنْ الْفِتَنِ وَمَاذَا فُتِحَ مِنْ الْخَزَائِنِ أَيْقِظُوا صَوَاحِبَاتِ الْحُجَرِ فَرُبَّ كَاسِيَةٍ فِي الدُّنْيَا عَارِيَةٍ فِي الْآخِرَةِ","id":"Telah menceritakan kepada kami [Shadaqah] telah mengabarkan kepada kami [Ibnu 'Uyainah] dari [Ma'mar] dari [Az Zuhri] dari [Hind] dari [Ummu Salamah] dan ['Amru]. Dan dari [Yahya bin Sa'id] dari [Az Zuhri] dari [Hind] dari [Ummu Salamah] berkata, \"Pada suatu malam Nabi shallallahu 'alaihi wasallam terbangun lalu bersabda: \"Subhaanallah (Maha suci Allah), fitnah apakah yang diturunkan pada malam ini? Dan apa yang dibuka dari dua perbendaharaan (Ramawi dan Parsi)? Bangunlah wahai orang-orang yang ada di balik dinding (kamar-kamar), karena betapa banyak orang hidup menikmati nikmat-nikmat dari Allah di dunia ini namun akan telanjang nanti di akhirat (tidak mendapatkan kebaikan).\""},"113":{"ar":"حَدَّثَنَا سَعِيدُ بْنُ عُفَيْرٍ قَالَ حَدَّثَنِي اللَّيْثُ قَالَ حَدَّثَنِي عَبْدُ الرَّحْمَنِ بْنُ خَالِدِ بْنِ مُسَافِرٍ عَنْ ابْنِ شِهَابٍ عَنْ سَالِمٍ وَأَبِي بَكْرِ بْنِ سُلَيْمَانَ بْنِ أَبِي حَثْمَةَ أَنَّ عَبْدَ اللَّهِ بْنَ عُمَرَ قَالَصَلَّى بِنَا النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْعِشَاءَ فِي آخِرِ حَيَاتِهِ فَلَمَّا سَلَّمَ قَامَ فَقَالَ أَرَأَيْتَكُمْ لَيْلَتَكُمْ هَذِهِ فَإِنَّ رَأْسَ مِائَةِ سَنَةٍ مِنْهَا لَا يَبْقَى مِمَّنْ هُوَ عَلَى ظَهْرِ الْأَرْضِ أَحَدٌ","id":"Telah menceritakan kepada kami [Sa'id bin 'Ufair] berkata, telah menceritakan kepada saya [Al Laits] berkata, telah menceritakan kepadaku ['Abdurrahman bin Khalid bin Musafir] dari [Ibnu Syihab] dari [Salim] dan [Abu Bakar bin Sulaiman bin Abu Hatsmah] bahwa ['Abdullah bin 'Umar] berkata, \"Nabi shallallahu 'alaihi wasallam shalat Isya' bersama kami di akhir hayatnya. Setelah selesai memberi salam beliau berdiri dan bersabda: \"Tidakkah kalian perhatikan malam kalian ini?. Sesungguhnya pada setiap penghujung seratus tahun darinya tidak akan tersisa seorangpun dari muka bumi ini.\""},"114":{"ar":"حَدَّثَنَا آدَمُ قَالَ حَدَّثَنَا شُعْبَةُ قَالَ حَدَّثَنَا الْحَكَمُ قَالَ سَمِعْتُ سَعِيدَ بْنَ جُبَيْرٍ عَنْ ابْنِ عَبَّاسٍ قَالَبِتُّ فِي بَيْتِ خَالَتِي مَيْمُونَةَ بِنْتِ الْحَارِثِ زَوْجِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَكَانَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عِنْدَهَا فِي لَيْلَتِهَا فَصَلَّى النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْعِشَاءَ ثُمَّ جَاءَ إِلَى مَنْزِلِهِ فَصَلَّى أَرْبَعَ رَكَعَاتٍ ثُمَّ نَامَ ثُمَّ قَامَ ثُمَّ قَالَ نَامَ الْغُلَيِّمُ أَوْ كَلِمَةً تُشْبِهُهَا ثُمَّ قَامَ فَقُمْتُ عَنْ يَسَارِهِ فَجَعَلَنِي عَنْ يَمِينِهِ فَصَلَّى خَمْسَ رَكَعَاتٍ ثُمَّ صَلَّى رَكْعَتَيْنِ ثُمَّ نَامَ حَتَّى سَمِعْتُ غَطِيطَهُ أَوْ خَطِيطَهُ ثُمَّ خَرَجَ إِلَى الصَّلَاةِ","id":"Telah menceritakan kepada kami [Adam] berkata, telah menceritakan kepada kami [Syu'bah] berkata, telah menceritakan kepada kami [Al Hakam] berkata, aku mendengar [Sa'id bin Jubair] dari [Ibnu 'Abbas] berkata, \"Aku bermalam di rumah bibiku (Maimunah binti Al Harits), isteri Nabi shallallahu 'alaihi wasallam. Dan saat itu Nabi shallallahu 'alaihi wasallam bersamanya karena memang menjadi gilirannya. Nabi shallallahu 'alaihi wasallam melaksanakan shalat isya`, lalu beliau pulang ke rumahnya dan shalat empat rakaat, kemudian tidur dan bangun lagi untuk shalat.\" Ibnu Abbas berkata, \"Beliau lalu tidur seperti anak kecil (sebentar-sebentar bangun) -atau kalimat yang semisal itu-, kemudian beliau bangun shalat. Kemudian aku bangun dan berdiri si sisi kirinya, beliau lalu menempatkan aku di kanannya. Setelah itu beliau shalat lima rakaat, kemudian shalat dua rakaat, kemudian tidur hingga aku mendengar dengkurannya, kemudian beliau keluar untuk melaksanakan shalat subuh.\""},"115":{"ar":"حَدَّثَنَا عَبْدُ الْعَزِيزِ بْنُ عَبْدِ اللَّهِ قَالَ حَدَّثَنِي مَالِكٌ عَنْ ابْنِ شِهَابٍ عَنْ الْأَعْرَجِ عَنْ أَبِي هُرَيْرَةَ قَالَإِنَّ النَّاسَ يَقُولُونَ أَكْثَرَ أَبُو هُرَيْرَةَ وَلَوْلَا آيَتَانِ فِي كِتَابِ اللَّهِ مَا حَدَّثْتُ حَدِيثًا ثُمَّ يَتْلُو{ إِنَّ الَّذِينَ يَكْتُمُونَ مَا أَنْزَلْنَا مِنْ الْبَيِّنَاتِ وَالْهُدَى إِلَى قَوْلِهِ الرَّحِيمُ }إِنَّ إِخْوَانَنَا مِنْ الْمُهَاجِرِينَ كَانَ يَشْغَلُهُمْ الصَّفْقُ بِالْأَسْوَاقِ وَإِنَّ إِخْوَانَنَا مِنْ الْأَنْصَارِ كَانَ يَشْغَلُهُمْ الْعَمَلُ فِي أَمْوَالِهِمْ وَإِنَّ أَبَا هُرَيْرَةَ كَانَ يَلْزَمُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِشِبَعِ بَطْنِهِ وَيَحْضُرُ مَا لَا يَحْضُرُونَ وَيَحْفَظُ مَا لَا يَحْفَظُونَ","id":"Telah menceritakan kepada kami ['Abdul 'Aziz bin 'Abdullah] berkata, telah menceritakan kepadaku [Malik] dari [Ibnu Syihab] dari [Al A'raj] dari [Abu Hurairah] berkata, \"Sesungguhnya orang-orang mengatakan, \"Abu Hurairah adalah yang paling banyak (menyampaikan hadits dari Rasulullah shallallahu 'alaihi wasallam), kalau bukan karena dua ayat dalam Kitabullah aku tidak akan menyampaikannya.\" Lalu dia membaca ayat: '(Sesungguhnya orang-orang yang menyembunyikan apa yang telah Kami turunkan berupa penjelasan dan petunjuk) ' ……hingga akhir ayat.. '(Allah Maha Penyayang) ' (Qs. Al Baqarah: 159-160). Sesungguhnya saudara-saudara kita dari kalangan Muhajirin, mereka disibukkan dengan perdagangan di pasar-pasar, dan saudara-saudara kita dari kalangan Anshar, mereka disibukkan dengan pekerjaan mereka dalam mengurus harta mereka. sementara Abu Hurairah selalu menyertai Rasulullah shallallahu 'alaihi wasallam dalam keadaan lapar, ia selalu hadir saat orang-orang tidak bosa hadir, dan ia dapat menghafal saat orang-orang tidak bisa menghafalnya.\""},"116":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ أَبِي بَكْرٍ أَبُو مُصْعَبٍ قَالَ حَدَّثَنَا مُحَمَّدُ بْنُ إِبْرَاهِيمَ بْنِ دِينَارٍ عَنْ ابْنِ أَبِي ذِئْبٍ عَنْ سَعِيدٍ الْمَقْبُرِيِّ عَنْ أَبِي هُرَيْرَةَ قَالَ قُلْتُيَا رَسُولَ اللَّهِ إِنِّي أَسْمَعُ مِنْكَ حَدِيثًا كَثِيرًا أَنْسَاهُ قَالَ ابْسُطْ رِدَاءَكَ فَبَسَطْتُهُ قَالَ فَغَرَفَ بِيَدَيْهِ ثُمَّ قَالَ ضُمَّهُ فَضَمَمْتُهُ فَمَا نَسِيتُ شَيْئًا بَعْدَهُحَدَّثَنَا إِبْرَاهِيمُ بْنُ الْمُنْذِرِ قَالَ حَدَّثَنَا ابْنُ أَبِي فُدَيْكٍ بِهَذَا أَوْ قَالَ غَرَفَ بِيَدِهِ فِيهِ","id":"Telah menceritakan kepada kami [Ahmad bin Abu Bakr Abu Mush'ab] berkata, telah menceritakan kepada kami [Muhammad bin Ibrahim bin Dinar] dari [Abu Dzi'b] dari [Sa'id Al Maqburi] dari [Abu Hurairah] berkata \"Aku berkata, \"Wahai Rasulullah, aku telah mendengar dari tuan banyak hadits namun aku lupa. Beliau lalu bersabda: \"Hamparkanlah selendangmu.\" Maka aku menghamparkannya, beliau lalu (seolah) menciduk sesuatu dengan tangannya, lalu bersabda: \"Ambillah.\" Aku pun mengambilnya, maka sejak itu aku tidak pernah lupa lagi.\" Telah menceritakan kepada kami [Ibrahim bin Al Mundzir] berkata, telah menceritakan kepada kami [Ibnu Abu Fudaik] dengan redaksi seperti ini, atau dia berkata, \"Menuangkan ke dalam tangannya.\""},"117":{"ar":"حَدَّثَنَا إِسْمَاعِيلُ قَالَ حَدَّثَنِي أَخِي عَنْ ابْنِ أَبِي ذِئْبٍ عَنْ سَعِيدٍ الْمَقْبُرِيِّ عَنْ أَبِي هُرَيْرَةَ قَالَحَفِظْتُ مِنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وِعَاءَيْنِ فَأَمَّا أَحَدُهُمَا فَبَثَثْتُهُ وَأَمَّا الْآخَرُ فَلَوْ بَثَثْتُهُ قُطِعَ هَذَا الْبُلْعُومُ","id":"Telah menceritakan kepada kami [Isma'il] berkata, telah menceritakan kepadaku [saudaraku] dari [Ibnu Abu Dzi'b] dari [Sa'id Al Maqburi] dari [Abu Hurairah] berkata, \"Aku menyimpan ilmu (hadits) dari Rasulullah shallallahu 'alaihi wasallam pada dua wadah. Yang satu aku sebarkan dan sampaikan, yang satu lagi sekiranya aku sampaikan maka akan terputuslah tenggorakan ini.\""},"118":{"ar":"حَدَّثَنَا حَجَّاجٌ قَالَ حَدَّثَنَا شُعْبَةُ قَالَ أَخْبَرَنِي عَلِيُّ بْنُ مُدْرِكٍ عَنْ أَبِي زُرْعَةَ بْنِ عَمْرٍو عَنْ جَرِيرٍأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَهُ فِي حَجَّةِ الْوَدَاعِ اسْتَنْصِتْ النَّاسَ فَقَالَ لَا تَرْجِعُوا بَعْدِي كُفَّارًا يَضْرِبُ بَعْضُكُمْ رِقَابَ بَعْضٍ","id":"Telah menceritakan kepada kami [Hajjaj] berkata, telah menceritakan kepada kami [Syu'bah] berkata, telah menceritakan kepadaku ['Ali bin Mudrik] dari [Abu Zur'ah bin 'Amru] dari [Jarir], bahwa Nabi shallallahu 'alaihi wasallam bersabda kepadanya saat beliau diminta untuk memberi nasihat kepada orang-orang waktu haji wada' \"Janganlah kalian kembali menjadi kafir, sehingga kalian saling membunuh satu sama lain.\""},"119":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مُحَمَّدٍ قَالَ حَدَّثَنَا سُفْيَانُ قَالَ حَدَّثَنَا عَمْرٌو قَالَ أَخْبَرَنِي سَعِيدُ بْنُ جُبَيْرٍ قَالَ قُلْتُ لِابْنِ عَبَّاسٍإِنَّ نَوْفًا الْبَكَالِيَّ يَزْعُمُ أَنَّ مُوسَى لَيْسَ بِمُوسَى بَنِي إِسْرَائِيلَ إِنَّمَا هُوَ مُوسَى آخَرُ فَقَالَ كَذَبَ عَدُوُّ اللَّهِ حَدَّثَنَا أُبَيُّ بْنُ كَعْبٍ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَامَ مُوسَى النَّبِيُّ خَطِيبًا فِي بَنِي إِسْرَائِيلَ فَسُئِلَ أَيُّ النَّاسِ أَعْلَمُ فَقَالَ أَنَا أَعْلَمُ فَعَتَبَ اللَّهُ عَلَيْهِ إِذْ لَمْ يَرُدَّ الْعِلْمَ إِلَيْهِ فَأَوْحَى اللَّهُ إِلَيْهِ أَنَّ عَبْدًا مِنْ عِبَادِي بِمَجْمَعِ الْبَحْرَيْنِ هُوَ أَعْلَمُ مِنْكَ قَالَ يَا رَبِّ وَكَيْفَ بِهِ فَقِيلَ لَهُ احْمِلْ حُوتًا فِي مِكْتَلٍ فَإِذَا فَقَدْتَهُ فَهُوَ ثَمَّ فَانْطَلَقَ وَانْطَلَقَ بِفَتَاهُ يُوشَعَ بْنِ نُونٍ وَحَمَلَا حُوتًا فِي مِكْتَلٍ حَتَّى كَانَا عِنْدَ الصَّخْرَةِ وَضَعَا رُءُوسَهُمَا وَنَامَا فَانْسَلَّ الْحُوتُ مِنْ الْمِكْتَلِ{ فَاتَّخَذَ سَبِيلَهُ فِي الْبَحْرِ سَرَبًا }وَكَانَ لِمُوسَى وَفَتَاهُ عَجَبًا فَانْطَلَقَا بَقِيَّةَ لَيْلَتِهِمَا وَيَوْمَهُمَا فَلَمَّا أَصْبَحَ قَالَ مُوسَى لِفَتَاهُ{ آتِنَا غَدَاءَنَا لَقَدْ لَقِينَا مِنْ سَفَرِنَا هَذَا نَصَبًا }وَلَمْ يَجِدْ مُوسَى مَسًّا مِنْ النَّصَبِ حَتَّى جَاوَزَ الْمَكَانَ الَّذِي أُمِرَ بِهِ فَقَالَ لَهُ فَتَاهُ{ أَرَأَيْتَ إِذْ أَوَيْنَا إِلَى الصَّخْرَةِ فَإِنِّي نَسِيتُ الْحُوتَ وَمَا أَنْسَانِيهِ إِلَّا الشَّيْطَانُ }قَالَ مُوسَى{ ذَلِكَ مَا كُنَّا نَبْغِي فَارْتَدَّا عَلَى آثَارِهِمَا قَصَصًا }فَلَمَّا انْتَهَيَا إِلَى الصَّخْرَةِ إِذَا رَجُلٌ مُسَجًّى بِثَوْبٍ أَوْ قَالَ تَسَجَّى بِثَوْبِهِ فَسَلَّمَ مُوسَى فَقَالَ الْخَضِرُ وَأَنَّى بِأَرْضِكَ السَّلَامُ فَقَالَ أَنَا مُوسَى فَقَالَ مُوسَى بَنِي إِسْرَائِيلَ قَالَ نَعَمْ قَالَ{ هَلْ أَتَّبِعُكَ عَلَى أَنْ تُعَلِّمَنِي مِمَّا عُلِّمْتَ رَشَدًا }قَالَ{ إِنَّكَ لَنْ تَسْتَطِيعَ مَعِيَ صَبْرًا }يَا مُوسَى إِنِّي عَلَى عِلْمٍ مِنْ عِلْمِ اللَّهِ عَلَّمَنِيهِ لَا تَعْلَمُهُ أَنْتَ وَأَنْتَ عَلَى عِلْمٍ عَلَّمَكَهُ لَا أَعْلَمُهُ{ قَالَ سَتَجِدُنِي إِنْ شَاءَ اللَّهُ صَابِرًا وَلَا أَعْصِي لَكَ أَمْرًا }فَانْطَلَقَا يَمْشِيَانِ عَلَى سَاحِلِ الْبَحْرِ لَيْسَ لَهُمَا سَفِينَةٌ فَمَرَّتْ بِهِمَا سَفِينَةٌ فَكَلَّمُوهُمْ أَنْ يَحْمِلُوهُمَا فَعُرِفَ الْخَضِرُ فَحَمَلُوهُمَا بِغَيْرِ نَوْلٍ فَجَاءَ عُصْفُورٌ فَوَقَعَ عَلَى حَرْفِ السَّفِينَةِ فَنَقَرَ نَقْرَةً أَوْ نَقْرَتَيْنِ فِي الْبَحْرِ فَقَالَ الْخَضِرُ ي��ا مُوسَى مَا نَقَصَ عِلْمِي وَعِلْمُكَ مِنْ عِلْمِ اللَّهِ إِلَّا كَنَقْرَةِ هَذَا الْعُصْفُورِ فِي الْبَحْرِ فَعَمَدَ الْخَضِرُ إِلَى لَوْحٍ مِنْ أَلْوَاحِ السَّفِينَةِ فَنَزَعَهُ فَقَالَ مُوسَى قَوْمٌ حَمَلُونَا بِغَيْرِ نَوْلٍ عَمَدْتَ إِلَى سَفِينَتِهِمْ فَخَرَقْتَهَا لِتُغْرِقَ أَهْلَهَا{ قَالَ أَلَمْ أَقُلْ إِنَّكَ لَنْ تَسْتَطِيعَ مَعِيَ صَبْرًا قَالَ لَا تُؤَاخِذْنِي بِمَا نَسِيتُ وَلَا تُرْهِقْنِي مِنْ أَمْرِي عُسْرًا }فَكَانَتْ الْأُولَى مِنْ مُوسَى نِسْيَانًا فَانْطَلَقَا فَإِذَا غُلَامٌ يَلْعَبُ مَعَ الْغِلْمَانِ فَأَخَذَ الْخَضِرُ بِرَأْسِهِ مِنْ أَعْلَاهُ فَاقْتَلَعَ رَأْسَهُ بِيَدِهِ فَقَالَ مُوسَى{ أَقَتَلْتَ نَفْسًا زَكِيَّةً بِغَيْرِ نَفْسٍ }{ قَالَ أَلَمْ أَقُلْ لَكَ إِنَّكَ لَنْ تَسْتَطِيعَ مَعِيَ صَبْرًا }قَالَ ابْنُ عُيَيْنَةَ وَهَذَا أَوْكَدُ{ فَانْطَلَقَا حَتَّى إِذَا أَتَيَا أَهْلَ قَرْيَةٍ اسْتَطْعَمَا أَهْلَهَا فَأَبَوْا أَنْ يُضَيِّفُوهُمَا فَوَجَدَا فِيهَا جِدَارًا يُرِيدُ أَنْ يَنْقَضَّ فَأَقَامَهُ }قَالَ الْخَضِرُ بِيَدِهِ فَأَقَامَهُ فَقَالَ لَهُ مُوسَى{ لَوْ شِئْتَ لَاتَّخَذْتَ عَلَيْهِ أَجْرًا قَالَ هَذَا فِرَاقُ بَيْنِي وَبَيْنِكَ }قَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَرْحَمُ اللَّهُ مُوسَى لَوَدِدْنَا لَوْ صَبَرَ حَتَّى يُقَصَّ عَلَيْنَا مِنْ أَمْرِهِمَا","id":"Telah menceritakan kepada kami ['Abdullah bin Muhammad] berkata, telah menceritakan kepada kami [Sufyan] telah menceritakan kepada kami ['Amru] berkata, telah mengabarkan kepadaku [Sa'id bin Jubair] berkata, aku berkata kepada [Ibnu 'Abbas], \"Sesungguhnya Nauf Al Bakali menganggap bahwa Musa bukanlah Musa Bani Isra'il, tapi Musa yang lain.\" Ibnu Abbas lalu berkata, \"Musuh Allah itu berdusta, sungguh [Ubay bin Ka'b] telah menceritakan kepada kami dari Nabi shallallahu 'alaihi wasallam: \"Musa Nabi Allah berdiri di hadapan Bani Isra'il memberikan khutbah, lalu dia ditanya: \"Siapakah orang yang paling pandai?\" Musa menjawab: \"Aku.\" Maka Allah Ta'ala mencelanya karena dia tidak diberi pengetahuan tentang itu. Lalu Allah Ta'ala memahyukan kepadanya: \"Ada seorang hamba di antara hamba-Ku yang tinggal di pertemuan antara dua lautan lebih pandai darimu.\" Lalu Musa berkata, \"Wahai Rabb, bagaimana aku bisa bertemu dengannya?\" Maka dikatakan padanya: \"Bawalah ikan dalam keranjang, bila nanti kamu kehilangan ikan itu, maka itulah petunjuknya.\" Lalu berangkatlah Musa bersama pelayannya yang bernama Yusya' bin Nun, dan keduanya membawa ikan dalam keranjang hingga keduanya sampai pada batu besar. Lalu keduanya meletakkan kepalanya di atas batu dan tidur. Kemudian keluarlah ikan itu dari keranjang (lalu ikan itu melompat mengambil jalannya ke laut itu) ' (Qs. Al Kahfi: 61). Kejadian ini mengherankan Musa dan muridnya, maka keduanya melanjutkan sisa malam dan hari perjalannannya. Hingga pada suatu pagi Musa berkata kepada pelayannya, '(Bawalah kemari makanan kita, sesungguhnya kita telah merasa lelah karena perjalanan kita ini) ' (Qs. Al Kahfi: 62). Musa tidak merasakan kelelahan kecuali setelah sampai pada tempat yang dituju sebagaimana diperintahkan. Maka muridnya berkata kepadanya: '(Tahukah kamu ketika kita mencari tempat berlindung di batu tadi? Sesungguhnya aku lupa menceritakan ikan itu. Dan tidaklah yang melupakan aku ini kecuali setan) ' (Qs. Al Kahfi: 63). Musa lalu berkata: '(Itulah tempat yang kita cari. Lalu keduanya kembali mengikuti jejak mereka semula) ' (Qs. Al Kahfi: 64). Ketika keduanya sampai di batu tersebut, didapatinya ada seorang laki-laki mengenakan pakaian yang lebar, Musa lantas memberi salam. Khidlir lalu berkata, \"Bagaimana cara salam di tempatmu?\" Musa menjawab, \"Aku adalah Musa.\" Khidlir balik bertanya, \"Musa Bani Isra'il?\" Musa menjawab, \"Benar.\" Musa kemudian berkata: '(Bolehkah aku mengikutimu supaya kamu mengajarkan kepadaku ilmu yang benar di antara ilmu-ilmu yang telah diajarkan kepadamu?) ' Khidlir menjawab: \"Sesungguhnya kamu sekali-kali tidak akan sanggup sabar bersama Aku) ' (Qs. Al Kahfi: 66-67). Khidlir melanjutkan ucapannya, \"Wahai Musa, aku memiliki ilmu dari ilmunya Allah yang Dia mangajarkan kepadaku yang kamu tidak tahu, dan kamu juga punya ilmu yang diajarkan-Nya yang aku juga tidak tahu.\" Musa berkata: '(Insya Allah kamu akan mendapati aku sebagai orang yang sabar, dan aku tidak akan menentangmu dalam sesuatu urusanpun) ' (Qs. Al Kahfi: 69). Maka keduanya berjalan kaki di tepi pantai sementara keduanya tidak memiliki perahu, lalu melintaslah sebuah perahu kapal. Mereka berbicara agar orang-orang yang ada di perahu itu mau membawa keduanya. Karena Khidlir telah dikenali maka mereka pun membawa keduanya dengan tanpa bayaran. Kemudian datang burung kecil hinggap di sisi perahu mematuk-matuk di air laut untuk minum dengan satu atau dua kali patukan. Khidlir lalu berkata, \"Wahai Musa, ilmuku dan ilmumu bila dibandingkan dengan ilmu Allah tidaklah seberapa kecuali seperti patukan burung ini di air lautan.\" Kemudian Khidlir sengaja mengambil papan perahu lalu merusaknya. Musa pun berkata, \"Mereka telah membawa kita dengan tanpa bayaran, tapi kenapa kamu merusaknya untuk menenggelamkan penumpangnya?\" Khidlir berkata: '(Bukankah aku telah berkata, \"Sesungguhnya kamu sekali-kali tidak akan sabar bersama dengan aku) ' Musa menjawab: '(Janganlah kamu menghukum aku karena kelupaanku dan janganlah kamu membebani aku dengan sesuatu kesulitan dalam urusanku) ' (Qs. Al Kahfi: 72-73). Kejadian pertama ini karena Musa terlupa. Kemudian keduanya pergi hingga bertemu dengan anak kecil yang sedang bermain dengan dua temannya. Khidlir lalu memegang kepala anak itu, mengangkat dan membantingnya hingga mati. Maka Musa pun bertanya: '(Mengapa kamu membunuh jiwa yang bersih, bukan karena dia membunuh orang lain?) ' (Qs. Al Kahfi: 74). Khidlir menjawab: '(Bukankah sudah kukatakan kepadamu, bahwa sesungguhnya kamu tidak akan dapat sabar bersamaku?) ' (Qs. Al Kahfi: 75). Ibnu 'Uyainah berkata, \"Ini adalah sebuah penegasan. '(Maka keduanya berjalan hingga tatkala keduanya sampai kepada penduduk suatu negeri, mereka minta dijamu kepada penduduk negeri itu, tetapi penduduk negeri itu tidak mau menjamu mereka. Kemudian keduanya mendapatkan dalam negeri itu dinding rumah yang hampir roboh. Maka Khidlir menegakkan dinding itu) ' (Qs. Al Kahfi: 77). Rasulullah meneruskan ceritanya: \"Khidlir melakukannya dengan tangannya sendiri. Lalu Musa berkata, '(Jikalau kamu mau, niscaya kamu mengambil upah untuk itu. Khidlir menjawab, \"Inilah saat perpisahan antara aku dan kamu) ' (Qs. Al Kahfi: 77-78). Nabi shallallahu 'alaihi wasallam bersabda: \"Semoga Allah merahmati Musa. Kita sangat berharap sekiranya Musa bisa sabar sehingga akan banyak cerita yang bisa kita dengar tentang keduanya.\""},"120":{"ar":"حَدَّثَنَا عُثْمَانُ قَالَ أَخْبَرَنَا جَرِيرٌ عَنْ مَنْصُورٍ عَنْ أَبِي وَائِلٍ عَنْ أَبِي مُوسَى قَالَجَاءَ رَجُلٌ إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ يَا رَسُولَ اللَّهِ مَا الْقِتَالُ فِي سَبِيلِ اللَّهِ فَإِنَّ أَحَدَنَا يُقَاتِلُ غَضَبًا وَيُقَاتِلُ حَمِيَّةً فَرَفَعَ إِلَيْهِ رَأْسَهُ قَالَ وَمَا رَفَعَ إِلَيْهِ رَأْسَهُ إِلَّا أَنَّهُ كَانَ قَائِمًا فَقَالَ مَنْ قَاتَلَ لِتَكُونَ كَلِمَةُ اللَّهِ هِيَ الْعُلْيَا فَهُوَ فِي سَبِيلِ اللَّهِ عَزَّ وَجَلَّ","id":"Telah menceritakan kepada kami ['Utsman] berkata, telah menceritakan kepada kami [Jarir] dari [Manshur] dari [Abu Wa'il] dari [Abu Musa] berkata, \"Seorang laki-laki datang menemui Nabi shallallahu 'alaihi wasallam dan bertanya, \"Wahai Rasulullah, apakah yang disebut dengan perang fi sabilillah (di jalan Allah)? Sebab di antara kami ada yang berperang karena marah dan ada yang karena semangat?\" Beliau lalu mengangkat kepalanya ke arah orang yang bertanya, dan tidaklah beliau angkat kepalanya kecuali karena orang yang bertanya itu berdiri. Beliau lalu menjawab: \"Barangsiapa berperang untuk meninggikan kalimat Allah, maka dia perperang di jalan Allah 'azza wajalla.\""},"121":{"ar":"حَدَّثَنَا أَبُو نُعَيْمٍ قَالَ حَدَّثَنَا عَبْدُ الْعَزِيزِ بْنُ أَبِي سَلَمَةَ عَنْ الزُّهْرِيِّ عَنْ عِيسَى بْنِ طَلْحَةَ عَنْ عَبْدِ اللَّهِ بْنِ عَمْرٍو قَالَرَأَيْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عِنْدَ الْجَمْرَةِ وَهُوَ يُسْأَلُ فَقَالَ رَجُلٌ يَا رَسُولَ اللَّهِ نَحَرْتُ قَبْلَ أَنْ أَرْمِيَ قَالَ ارْمِ وَلَا حَرَجَ قَالَ آخَرُ يَا رَسُولَ اللَّهِ حَلَقْتُ قَبْلَ أَنْ أَنْحَرَ قَالَ انْحَرْ وَلَا حَرَجَ فَمَا سُئِلَ عَنْ شَيْءٍ قُدِّمَ وَلَا أُخِّرَ إِلَّا قَالَ افْعَلْ وَلَا حَرَجَ","id":"Telah menceritakan kepada kami [Abu Nu'aim] berkata, telah menceritakan kepada kami [Abdul 'Aziz bin Abu Salamah] dari [Az Zuhri] dari ['Isa bin Thalhah] dari ['Abdullah bin 'Amru] berkata, \"Aku melihat Nabi shallallahu 'alaihi wasallam di sisi jumrah sedang ditanya. Seorang laki-laki bertanya, \"Wahai Rasulullah, aku menyembelih hewan sebelum aku melempar?\" Beliau lalu bersabda: \"Melemparlah sekarang, dan kau tidak dosa.\" Kemudian datang orang lain dan berkata, \"Wahai Rasulullah, aku telah mencukur rambut sebelum aku menyembelih?\" Beliau menjawab: \"Sembelihlah sekarang, tidak kau tidak berdosa.\" Dan tidaklah beliau ditanya tentang sesuatu yang dikerjakan lebih dahulu atau sesuatu yang diakhirkan dalam mengerjakannya kecuali menjawab: \"Lakukanlah dan tidak dosa.\""},"122":{"ar":"حَدَّثَنَا قَيْسُ بْنُ حَفْصٍ قَالَ حَدَّثَنَا عَبْدُ الْوَاحِدِ قَالَ حَدَّثَنَا الْأَعْمَشُ سُلَيْمَانُ بْنُ مِهْرَانَ عَنْ إِبْرَاهِيمَ عَنْ عَلْقَمَةَ عَنْ عَبْدِ اللَّهِ قَالَبَيْنَا أَنَا أَمْشِي مَعَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي خَرِبِ الْمَدِينَةِ وَهُوَ يَتَوَكَّأُ عَلَى عَسِيبٍ مَعَهُ فَمَرَّ بِنَفَرٍ مِنْ الْيَهُودِ فَقَالَ بَعْضُهُمْ لِبَعْضٍ سَلُوهُ عَنْ الرُّوحِ وَقَالَ بَعْضُهُمْ لَا تَسْأَلُوهُ لَا يَجِيءُ فِيهِ بِشَيْءٍ تَكْرَهُونَهُ فَقَالَ بَعْضُهُمْ لَنَسْأَلَنَّهُ فَقَامَ رَجُلٌ مِنْهُمْ فَقَالَ يَا أَبَا الْقَاسِمِ مَا الرُّوحُ فَسَكَتَ فَقُلْتُ إِنَّهُ يُوحَى إِلَيْهِ فَقُمْتُ فَلَمَّا انْجَلَى عَنْهُ قَالَ{ وَيَسْأَلُونَكَ عَنْ الرُّوحِ قُلْ الرُّوحُ مِنْ أَمْرِ رَبِّي }وَمَا أُوتُوا مِنْ الْعِلْمِ إِلَّا قَلِيلًاقَالَ الْأَعْمَشُ هَكَذَا فِي قِرَاءَتِنَا","id":"Telah menceritakan kepada kami [Qais bin Hafsh] berkata, telah menceritakan kepada kami ['Abdul Wahid] berkata, telah menceritakan kepada kami [Al A'masy Sulaiman bin Mihran] dari [Ibrahim] dari ['Alqamah] dari ['Abdullah] berkata, \"Ketika aku berjalan bersama Nabi shallallahu 'alaihi wasallam di sekitar pinggiran Kota Madinah, saat itu beliau membawa tongkat dari batang pohon kurma. Beliau lalu melewati sekumpulan orang Yahudi, maka sesama mereka saling berkata, \"Tanyakanlah kepadanya tentang ruh!\" Sebagian yang lain berkata, \"Janganlah kalian bicara dengannya hingga ia akan mengatakan sesuatu yang kalian tidak menyukainya.\" Lalu sebagian yang lain berkata, \"Sungguh, kami benar-benar akan bertanya kepadanya.\" Maka berdirilah seorang laki-laki dari mereka seraya bertanya, \"Wahai Abul Qasim, ruh itu apa?\" Beliau diam. Maka aku pun bergumam, \"Sesungguhnya beliau sedang menerima wahyu.\" Ketika orang itu berpaling, beliau pun membaca: '(Dan mereka bertanya kepadamu tentang ruh. Katakanlah: \"Ruh itu termasuk urusan Rabbku, dan tidaklah kamu diberi pengetahuan melainkan sedikit) ' (Qs. Al Israa`: 85). Al A'masy berkata, \"Seperti inilah dalam qira`ah kami.\""},"123":{"ar":"حَدَّثَنَا عُبَيْدُ اللَّهِ بْنُ مُوسَى عَنْ إِسْرَائِيلَ عَنْ أَبِي إِسْحَاقَ عَنْ الْأَسْوَدِ قَالَ قَالَ لِي ابْنُ الزُّبَيْرِ كَانَتْ عَائِشَةُ تُسِرُّ إِلَيْكَ كَثِيرًا فَمَا حَدَّثَتْكَ فِي الْكَعْبَةِ قُلْتُ قَالَتْ لِيقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَا عَائِشَةُ لَوْلَا قَوْمُكِ حَدِيثٌ عَهْدُهُمْ قَالَ ابْنُ الزُّبَيْرِ بِكُفْرٍ لَنَقَضْتُ الْكَعْبَةَ فَجَعَلْتُ لَهَا بَابَيْنِ بَابٌ يَدْخُلُ النَّاسُ وَبَابٌ يَخْرُجُونَفَفَعَلَهُ ابْنُ الزُّبَيْرِ","id":"Telah menceritakan kepada kami ['Abdullah bin Musa] dari [Isra'il] dari [Abu Ishaq] dari [Al Aswad] berkata, Ibnu Az Zubair berkata kepadaku, \" ['Aisyah] banyak merahasiakan (hadits) kepadamu. Apa yang pernah dibicarakannya kepadamu tentang Ka'bah?\" Aku berkata, \"Aisyah berkata kepadaku, \"Nabi shallallahu 'alaihi wasallam berkata kepadaku: \"Wahai 'Aisyah, kalau bukan karena kaummu masih dekat zaman mereka, Az Zubair menyebutkan, \"Dengan kekufuran, maka Ka'bah akan aku rubah, lalu aku buat dua pintu untuk orang-orang masuk dan satu untuk mereka keluar.\" Di kemudian hari hal ini dilaksanakan oleh Ibnu Zubair.\""},"124":{"ar":"وَقَالَ عَلِيٌّحَدِّثُوا النَّاسَ بِمَا يَعْرِفُونَ أَتُحِبُّونَ أَنْ يُكَذَّبَ اللَّهُ وَرَسُولُهُحَدَّثَنَا عُبَيْدُ اللَّهِ بْنُ مُوسَى عَنْ مَعْرُوفِ بْنِ خَرَّبُوذٍ عَنْ أَبِي الطُّفَيْلِ عَنْ عَلِيٍّ بِذَلِكَ","id":"Dan Ali berkata, \"Berbicaralah dengan manusia sesuai dengan kadar pemahaman mereka, apakah kalian ingin jika Allah dan rasul-Nya didustakan?\" Telah menceritakan kepada kami ['Ubaidullah bin Musa] dari [Ma 'ruf bin Kharrabudz] dari [Abu Ath Thufail] dari ['Ali] seperti itu.\""},"125":{"ar":"حَدَّثَنَا إِسْحَاقُ بْنُ إِبْرَاهِيمَ قَالَ حَدَّثَنَا مُعَاذُ بْنُ هِشَامٍ قَالَ حَدَّثَنِي أَبِي عَنْ قَتَادَةَ قَالَ حَدَّثَنَ�� أَنَسُ بْنُ مَالِكٍأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَمُعاذٌ رَدِيفُهُ عَلَى الرَّحْلِ قَالَ يَا مُعَاذَ بْنَ جَبَلٍ قَالَ لَبَّيْكَ يَا رَسُولَ اللَّهِ وَسَعْدَيْكَ قَالَ يَا مُعَاذُ قَالَ لَبَّيْكَ يَا رَسُولَ اللَّهِ وَسَعْدَيْكَ ثَلَاثًا قَالَ مَا مِنْ أَحَدٍ يَشْهَدُ أَنْ لَا إِلَهَ إِلَّا اللَّهُ وَأَنَّ مُحَمَّدًا رَسُولُ اللَّهِ صِدْقًا مِنْ قَلْبِهِ إِلَّا حَرَّمَهُ اللَّهُ عَلَى النَّارِ قَالَ يَا رَسُولَ اللَّهِ أَفَلَا أُخْبِرُ بِهِ النَّاسَ فَيَسْتَبْشِرُوا قَالَ إِذًا يَتَّكِلُوا وَأَخْبَرَ بِهَا مُعَاذٌ عِنْدَ مَوْتِهِ تَأَثُّمًا","id":"Telah menceritakan kepada kami [Ishaq bin Ibrahim] berkata, telah menceritakan kepada kami [Mu'adz bin Hisyam] berkata, telah menceritakan kepadaku [Bapakku] dari [Qatadah] berkata, telah menceritakan kepada kami [Anas bin Malik] bahwa Nabi shallallahu 'alaihi wasallam menunggang kendaraan sementara Mu'adz membonceng di belakangnya. Beliau lalu bersabda: \"Wahai Mu'adz bin Jabal!\" Mu'adz menjawab, \"Wahai Rasulullah, aku penuhi panggilanmu.\" Beliau memanggil kembali: \"Wahai Mu'adz!\" Mu'adz menjawab, \"Wahai Rasulullah, aku penuhi panggilanmu.\" Hal itu hingga terulang tiga kali, beliau lantas bersabda: \"Tidaklah seseorang bersaksi bahwa tidak ada Tuhan yang berhak disembah selain Allah, dan Muhammad adalah Rasulullah, tulus dari dalam hatinya, kecuali Allah akan mengharamkan baginya neraka.\" Mu'adz lalu bertanya, \"Apakah boleh aku memberitahukan hal itu kepada orang, sehingga mereka bergembira dengannya?\" Beliau menjawab: \"Nanti mereka jadi malas (untuk beramal).\" Mu'adz lalu menyampaikan hadits itu ketika dirinya akan meninggal karena takut dari dosa.\""},"126":{"ar":"حَدَّثَنَا مُسَدَّدٌ قَالَ حَدَّثَنَا مُعْتَمِرٌ قَالَ سَمِعْتُ أَبِي قَالَ سَمِعْتُ أَنَسَ بْنَ مَالِكٍ قَالَ ذُكِرَ لِيأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لِمُعَاذِ بْنِ جَبَلٍ مَنْ لَقِيَ اللَّهَ لَا يُشْرِكُ بِهِ شَيْئًا دَخَلَ الْجَنَّةَ قَالَ أَلَا أُبَشِّرُ النَّاسَ قَالَ لَا إِنِّي أَخَافُ أَنْ يَتَّكِلُوا","id":"Telah menceritakan kepada kami [Musaddad] berkata, telah menceritakan kepada kami [Mu'tamir] berkata, aku mendengar [Bapakku] berkata, aku mendengar [Anas bin Malik] berkata, \"Disebutkan kepadaku bahwa Nabi shallallahu 'alaihi wasallam pernah bersabda kepada Mu'adz bin Jabal: \"Barangsiapa berjumpa Allah dengan tidak menyekutukan-Nya dengan sesuatu apapun, maka dia akan masuk surga.\" Mu'adz bertanya, \"Bolehkan jika itu aku sampaikan kepada manusia?\" Beliau menjawab: \"Jangan, karena aku khawatir mereka akan jadi malas (untuk beramal).\""},"127":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ سَلَامٍ قَالَ أَخْبَرَنَا أَبُو مُعَاوِيَةَ قَالَ حَدَّثَنَا هِشَامُ بْنُ عُرْوَةَ عَنْ أَبِيهِ عَنْ زَيْنَبَ ابْنَةِ أُمِّ سَلَمَةَ عَنْ أُمِّ سَلَمَةَ قَالَتْجَاءَتْ أُمُّ سُلَيْمٍ إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَتْ يَا رَسُولَ اللَّهِ إِنَّ اللَّهَ لَا يَسْتَحْيِي مِنْ الْحَقِّ فَهَلْ عَلَى الْمَرْأَةِ مِنْ غُسْلٍ إِذَا احْتَلَمَتْ قَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا رَأَتْ الْمَاءَ فَغَطَّتْ أُمُّ سَلَمَةَ تَعْنِي وَجْهَهَا وَقَالَتْ يَا رَسُولَ اللَّهِ أَوَتَحْتَلِمُ الْمَرْأَةُ قَالَ نَعَمْ تَرِبَتْ يَمِينُكِ فَبِمَ يُشْبِهُهَا وَلَدُهَا","id":"Telah menceritakan kepada kami [Muhammad bin Salam] berkata, telah mengabarkan kepada kami [Abu Mu'awiyah] berkata, telah menceritakan kepada kami [Hisyam bin 'Urwah] dari [Bapaknya] dari [Zainab] puteri Ummu Salamah, dari [Ummu Salamah] ia berkata, \"Ummu Sulaim datang menemui Rasulullah shallallahu 'alaihi wasallam dan berkata, \"Wahai Rasulullah, sesungguhnya Allah tidak malu dalam perkara yang hak. Apakah bagi wanita wajib mandi jika ia bermimpi?\" Nabi shallallahu 'alaihi wasallam menjawab: \"Ya, jika dia melihat air.\" Ummu Salamah lalu menutupi wajahnya seraya bertanya, \"Wahai Rasulullah, apakah seorang wanita itu bermimpi?\" Beliau menjawab: \"Ya. Celaka kamu. (jika tidak) Lantas dari mana datangnya kemiripan seorang anak itu?\""},"128":{"ar":"حَدَّثَنَا إِسْمَاعِيلُ قَالَ حَدَّثَنِي مَالِكٌ عَنْ عَبْدِ اللَّهِ بْنِ دِينَارٍ عَنْ عَبْدِ اللَّهِ بْنِ عُمَرَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِنَّ مِنْ الشَّجَرِ شَجَرَةً لَا يَسْقُطُ وَرَقُهَا وَهِيَ مَثَلُ الْمُسْلِمِ حَدِّثُونِي مَا هِيَ فَوَقَعَ النَّاسُ فِي شَجَرِ الْبَادِيَةِ وَوَقَعَ فِي نَفْسِي أَنَّهَا النَّخْلَةُ قَالَ عَبْدُ اللَّهِ فَاسْتَحْيَيْتُ فَقَالُوا يَا رَسُولَ اللَّهِ أَخْبِرْنَا بِهَا فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ هِيَ النَّخْلَةُ قَالَ عَبْدُ اللَّهِ فَحَدَّثْتُ أَبِي بِمَا وَقَعَ فِي نَفْسِي فَقَالَ لَأَنْ تَكُونَ قُلْتَهَا أَحَبُّ إِلَيَّ مِنْ أَنْ يَكُونَ لِي كَذَا وَكَذَا","id":"Telah menceritakan kepada kami [Isma'il] berkata, telah menceritakan kepadaku [Malik] dari ['Abdullah bin Dinar] dari ['Abdullah bin 'Umar], bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya di antara pohon-pohon ada satu pohon yang tidak jatuh daunnya, dan itu adalah perumpamaan bagi seorang Muslim. Ceritakan kepadaku pohon apakah itu?\" Maka orang-orang menganggapnya sebagai pohon-pohon yang ada di lembah, sedangkan menurut perkiraanku bahwa itu adalah pohon kurma.\" 'Abdullah berkata, \"Tetapi aku malu (untuk mengungkapkannya). Lalu orang-orang berkata, \"Wahai Rasulullah, beritahukan kami pohon apakah itu?\" Maka Rasulullah shallallahu 'alaihi wasallam pun menjawab: \"Dia adalah pohon kurma.\" 'Abdullah berkata, \"Kemudian aku ceritakan hal itu kepada bapakku, Maka bapakku berkata, \"Aku lebih suka bila engkau ungkapkan saat itu dari pada aku memiliki begini dan begini.\""},"129":{"ar":"حَدَّثَنَا مُسَدَّدٌ قَالَ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ دَاوُدَ عَنْ الْأَعْمَشِ عَنْ مُنْذِرٍ الْثَّوْرِيِّ عَنْ مُحَمَّدِ بْنِ الْحَنَفِيَّةِ عَنْ عَلِيِّ بْنِ أَبِي طَالِبٍ قَالَكُنْتُ رَجُلًا مَذَّاءً فَأَمَرْتُ الْمِقْدَادَ بْنَ الْأَسْوَدِ أَنْ يَسْأَلَ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَسَأَلَهُ فَقَالَ فِيهِ الْوُضُوءُ","id":"Telah menceritakan kepada kami [Musaddad] berkata, telah menceritakan kepada kami ['Abdullah bin Daud] dari [Al A'masy] dari [Mundzir Ats Tsauri] dari [Muhammad Al Hanafiyah] dari ['Ali bin Abu Thalib] berkata, \"Aku adalah seorang laki-laki yang mudah mengeluarkan madzi, lalu suruh Miqdad bin Al Aswad untuk menanyakan hal itu kepada Nabi shallallahu 'alaihi wasallam. Lalu ia pun menanyakannya kepada beliau, dan beliau menjawab: \"Padanya ada kewajiban wudlu.\""},"130":{"ar":"حَدَّثَنِي قُتَيْبَةُ بْنُ سَعِيدٍ قَالَ حَدَّثَنَا اللَّيْثُ بْنُ سَعْدٍ قَالَ حَدَّثَنَا نَافِعٌ مَوْلَى عَبْدِ اللَّهِ بْنِ عُمَرَ بْنِ الْخَطَّابِ عَنْ عَبْدِ اللَّهِ بْنِ عُمَرَأَنَّ رَجُلًا قَامَ فِي الْمَسْجِدِ فَقَالَ يَا رَسُولَ اللَّهِ مِنْ أَيْنَ تَأْمُرُنَا أَنْ نُهِلَّ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُهِلُّ أَهْلُ الْمَدِينَةِ مِنْ ذِي الْحُلَيْفَةِ وَيُهِلُّ أَهْلُ الشَّأْمِ مِنْ الْجُحْفَةِ وَيُهِلُّ أَهْلُ نَجْدٍ مِنْ قَرْنٍ وَقَالَ ابْنُ عُمَرَ وَيَزْعُمُونَ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ وَيُهِلُّ أَهْلُ الْيَمَنِ مِنْ يَلَمْلَمَ وَكَانَ ابْنُ عُمَرَ يَقُولُ لَمْ أَفْقَهْ هَذِهِ مِنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah menceritakan kepadaku [Qutaibah bin Sa'id] berkata, telah menceritakan kepada kami [Al Laits bin Sa'd] telah menceritakan kepada kami [Nafi'] mantan budak 'Abdullah bin 'Umar bin Al Khaththab, dari ['Abdullah bin 'Umar], bahwa ada seorang laki-laki datang berdiri di masjid lalu bertanya, \"Wahai Rasulullah, dari mana Tuan memerintahkan kami untuk bertalbiyah?\" Rasulullah shallallahu 'alaihi wasallam lalu menjawab: \"Bagi penduduk Madinah bertalbiyah dari Dzul Hulaifah, penduduk Syam dari Al Juhfah, dan penduduk Najed dari Qarn.\" Ibnu Umar berkata, \"Orang-orang mengklaim bahwa Rasulullah shallallahu 'alaihi wasallam akan mengatakan bahwa penduduk Yaman bertalbiyah dari Yalamlam.\" Sementara Ibnu Umar berkata, \"Aku tidak yakin bahwa (yang terakhir) ini dari Rasulullah shallallahu 'alaihi wasallam.\""},"131":{"ar":"حَدَّثَنَا آدَمُ قَالَ حَدَّثَنَا ابْنُ أَبِي ذِئْبٍ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَعَنْ الزُّهْرِيِّ عَنْ سَالِمٍ عَنْ ابْنِ عُمَرَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّ رَجُلًا سَأَلَهُ مَا يَلْبَسُ الْمُحْرِمُ فَقَالَ لَا يَلْبَسُ الْقَمِيصَ وَلَا الْعِمَامَةَ وَلَا السَّرَاوِيلَ وَلَا الْبُرْنُسَ وَلَا ثَوْبًا مَسَّهُ الْوَرْسُ أَوْ الزَّعْفَرَانُ فَ��ِنْ لَمْ يَجِدْ النَّعْلَيْنِ فَلْيَلْبَسْ الْخُفَّيْنِ وَلْيَقْطَعْهُمَا حَتَّى يَكُونَا تَحْتَ الْكَعْبَيْنِ","id":"Telah menceritakan kepada kami [Adam] berkata, telah menceritakan kepada kami [Ibnu Abu Dzi'b] dari [Nafi'] dari [Ibnu 'Umar] dari Nabi shallallahu 'alaihi wasallam, dan dari [Az Zuhri] dari [Salim] dari [Ibnu 'Umar] dari Nabi shallallahu 'alaihi wasallam, bahwa ada seorang laki-laki bertanya, \"Apa yang harus dikenakan oleh orang yang melakukan ihram?\" Beliau menjawab: \"Ia tidak boleh memakai baju, Imamah (surban yang dililitkan pada kepala), celana panjang, mantel, atau pakaian yang diberi minyak wangi atau za'faran. Jika dia tidak mendapatkan sandal, maka ia boleh mengenakan sepatu dengan memotongnya hingga di bawah mata kaki.\""},"132":{"ar":"حَدَّثَنَا إِسْحَاقُ بْنُ إِبْرَاهِيمَ الْحَنْظَلِيُّ قَالَ أَخْبَرَنَا عَبْدُ الرَّزَّاقِ قَالَ أَخْبَرَنَا مَعْمَرٌ عَنْ هَمَّامِ بْنِ مُنَبِّهٍ أَنَّهُ سَمِعَ أَبَا هُرَيْرَةَ يَقُولُقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا تُقْبَلُ صَلَاةُ مَنْ أَحْدَثَ حَتَّى يَتَوَضَّأَ قَالَ رَجُلٌ مِنْ حَضْرَمَوْتَ مَا الْحَدَثُ يَا أَبَا هُرَيْرَةَ قَالَ فُسَاءٌ أَوْ ضُرَاطٌ","id":"Telah menceritakan kepada kami [Ishaq bin Ibrahim Al Hanzhali] berkata, telah mengabarkan kepada kami [Abdurrazaq] berkata, telah mengabarkan kepada kami [Ma'mar] dari [Hammam bin Munabbih] bahwa ia mendengar [Abu Hurairah] berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tidak akan diterima shalat seseorang yang berhadats hingga dia berwudlu.\" Seorang laki-laki dari Hadlramaut berkata, \"Apa yang dimaksud dengan hadats wahai Abu Hurairah?\" Abu Hurairah menjawab, \"Kentut baik dengan suara atau tidak.\""},"133":{"ar":"حَدَّثَنَا يَحْيَى بْنُ بُكَيْرٍ قَالَ حَدَّثَنَا اللَّيْثُ عَنْ خَالِدٍ عَنْ سَعِيدِ بْنِ أَبِي هِلَالٍ عَنْ نُعَيْمٍ الْمُجْمِرِ قَالَرَقِيتُ مَعَ أَبِي هُرَيْرَةَ عَلَى ظَهْرِ الْمَسْجِدِ فَتَوَضَّأَ فَقَالَ إِنِّي سَمِعْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ إِنَّ أُمَّتِي يُدْعَوْنَ يَوْمَ الْقِيَامَةِ غُرًّا مُحَجَّلِينَ مِنْ آثَارِ الْوُضُوءِ فَمَنْ اسْتَطَاعَ مِنْكُمْ أَنْ يُطِيلَ غُرَّتَهُ فَلْيَفْعَلْ","id":"Telah menceritakan kepada kami [Yahya bin Bukair] berkata, telah menceritakan kepada kami [Al Laits] dari [Khalid] dari [Sa'id bin Abu Hilal] dari [Nu'aim bin Al Mujmir] berkata, \"Aku mendaki masjid bersama [Abu Hurairah], lalu dia berwudlu' dan berkata, \"Aku mendengar Nabi shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya umatku akan dihadirkan pada hari kiamat dengan wajah berseri-seri karena sisa air wudlu, barangsiapa di antara kalian bisa memperpanjang cahayanya hendaklah ia lakukan.\""},"134":{"ar":"حَدَّثَنَا عَلِيٌّ قَالَ حَدَّثَنَا سُفْيَانُ قَالَ حَدَّثَنَا الزُّهْرِيُّ عَنْ سَعِيدِ بْنِ الْمُسَيَّبِ ح وَعَنْ عَبَّادِ بْنِ تَمِيمٍ عَنْ عَمِّهِأَنَّهُ شَكَا إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الرَّجُلُ الَّذِي يُخَيَّلُ إِلَيْهِ أَنَّهُ يَجِدُ الشَّيْءَ فِي الصَّلَاةِ فَقَالَ لَا يَنْفَتِلْ أَوْ لَا يَنْصَرِفْ حَتَّى يَسْمَعَ صَوْتًا أَوْ يَجِدَ رِيحًا","id":"Telah menceritakan kepada kami ['Ali] berkata, telah menceritakan kepada kami [Sufyan] berkata, telah menceritakan kepada kami [Az Zuhri] dari [Sa'id bin Al Musayyab]. (dalam jalur lain disebutkan) Telah menceritakan kepada kami ['Abbad bin Tamim] dari [Pamannya], bahwa ada seseorang yang mengadukan keraguannya kepada Rasulullah shallallahu 'alaihi wasallam, bahwa seakan-akan ia mendapatkan sesuatu dalam shalatnya. Beliau lalu bersabda: \"Janganlah kamu pindah atau pergi hingga kamu mendengar suara atau mencium baunya.\""},"135":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ عَبْدِ اللَّهِ قَالَ حَدَّثَنَا سُفْيَانُ عَنْ عَمْرٍو قَالَ أَخْبَرَنِي كُرَيْبٌ عَنْ ابْنِ عَبَّاسٍ أَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَامَ حَتَّى نَفَخَ ثُمَّ صَلَّى وَرُبَّمَا قَالَ اضْطَجَعَ حَتَّى نَفَخَ ثُمَّ قَامَ فَصَلَّى ثُمَّ حَدَّثَنَا بِهِ سُفْيَانُ مَرَّةً بَعْدَ مَرَّةٍ عَنْ عَمْرٍو عَنْ كُرَيْبٍ عَنْ ابْنِ عَبَّاسٍقَالَ بِتُّ عِنْدَ خَالَتِي مَيْمُونَةَ لَيْلَةً فَقَامَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِنْ اللَّيْلِ فَلَمَّا كَانَ فِي بَعْضِ اللَّيْلِ قَامَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَتَوَضَّأَ مِنْ شَنٍّ مُعَلَّقٍ وُضُوءًا خَفِيفًا يُخَفِّفُهُ عَمْرٌو وَيُقَلِّلُهُ وَقَامَ يُصَلِّي فَتَوَضَّأْتُ نَحْوًا مِمَّا تَوَضَّأَ ثُمَّ جِئْتُ فَقُمْتُ عَنْ يَسَارِهِ وَرُبَّمَا قَالَ سُفْيَانُ عَنْ شِمَالِهِ فَحَوَّلَنِي فَجَعَلَنِي عَنْ يَمِينِهِ ثُمَّ صَلَّى مَا شَاءَ اللَّهُ ثُمَّ اضْطَجَعَ فَنَامَ حَتَّى نَفَخَ ثُمَّ أَتَاهُ الْمُنَادِي فَآذَنَهُ بِالصَّلَاةِ فَقَامَ مَعَهُ إِلَى الصَّلَاةِ فَصَلَّى وَلَمْ يَتَوَضَّأْقُلْنَا لِعَمْرٍو إِنَّ نَاسًا يَقُولُونَ إِنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ تَنَامُ عَيْنُهُ وَلَا يَنَامُ قَلْبُهُ قَالَ عَمْرٌو سَمِعْتُ عُبَيْدَ بْنَ عُمَيْرٍ يَقُولُ رُؤْيَا الْأَنْبِيَاءِ وَحْيٌ ثُمَّ قَرَأَ{ إِنِّي أَرَى فِي الْمَنَامِ أَنِّي أَذْبَحُكَ }","id":"Telah menceritakan kepada kami ['Ali bin 'Abdullah] berkata, telah menceritakan kepada kami [Sufyan] dari ['Amru] berkata, telah mengabarkan kepadaku [Kuraib] dari [Ibnu 'Abbas], bahwa Nabi shallallahu 'alaihi wasallam tidur sampai mendengkur kemudian bangun dan mengerjakan shalat. Atau ia mengatakan, \"Nabi berbaring hingga mendengkur, kemudian beliau berdiri shalat. Kemudian [Sufyan] secara berturut-turut meriwayatkan hadits tersebut kepada kami, dari ['Amru] dari [Kuraib] dari [Ibnu 'Abbas] ia berkata, \"Pada suatu malam aku pernah menginap di rumah bibiku, Maimunah, Nabi shallallahu 'alaihi wasallam lalu melaksanakan shalat malam. Hingga pada suatu malam, Nabi shallallahu 'alaihi wasallam bangun dan berwudlu dari bejana kecil dengan wudlu yang ringan, setelah itu berdiri dan shalat. Aku lalu ikut berwudlu' dari bejana yang beliau gunakan untuk wudlu', kemudian aku menghampiri beliau dan ikut shalat di sisi kirinya -Sufyan juga menyebutkan sebelah kiri-, beliau lalu menggeser aku ke sisi kanannya. Setelah itu beliau shalat sesuai yang dikehendakinya, kemudian beliau berbaring dan tidur hingga mendengkur. Kemudian seorang tukang adzan datang memberitahukan beliau bahwa waktu shalat telah tiba, beliau lalu pergi bersamanya dan shalat tanpa berwudlu lagi.\" Kami lalu katakan kepada Amru, \"Orang-orang mengatakan bahwa mata Rasulullah shallallahu 'alaihi wasallam tidur, namun tidak dengan hatinya.\" Amru lalu berkata, \"Aku pernah mendengar Ubaid bin Umair berkata, \"Mimpinya para Nabi adalah wahyu.\" Kemudian ia membaca: '(Sesungguhnya aku bermimpi bahwa aku akan menyembelihmu..) ' (Qs. Ash Shaaffat: 102)."},"136":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مَسْلَمَةَ عَنْ مَالِكٍ عَنْ مُوسَى بْنِ عُقْبَةَ عَنْ كُرَيْبٍ مَوْلَى ابْنِ عَبَّاسٍ عَنْ أُسَامَةَ بْنِ زَيْدٍ أَنَّهُ سَمِعَهُ يَقُولُدَفَعَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِنْ عَرَفَةَ حَتَّى إِذَا كَانَ بِالشِّعْبِ نَزَلَ فَبَالَ ثُمَّ تَوَضَّأَ وَلَمْ يُسْبِغْ الْوُضُوءَ فَقُلْتُ الصَّلَاةَ يَا رَسُولَ اللَّهِ فَقَالَ الصَّلَاةُ أَمَامَكَ فَرَكِبَ فَلَمَّا جَاءَ الْمُزْدَلِفَةَ نَزَلَ فَتَوَضَّأَ فَأَسْبَغَ الْوُضُوءَ ثُمَّ أُقِيمَتْ الصَّلَاةُ فَصَلَّى الْمَغْرِبَ ثُمَّ أَنَاخَ كُلُّ إِنْسَانٍ بَعِيرَهُ فِي مَنْزِلِهِ ثُمَّ أُقِيمَتْ الْعِشَاءُ فَصَلَّى وَلَمْ يُصَلِّ بَيْنَهُمَا","id":"Telah menceritakan kepada kami ['Abdullah bin Maslamah] dari [Malik] dari [Musa bin 'Uqbah] dari [Kuraib] mantan budak Ibnu 'Abbas, dari [Usamah bin Zaid] bahwa ia mendengarnya berkata, \"Rasulullah shallallahu 'alaihi wasallam bertolak meninggalkan 'Arafah hingga setelah sampai di lembah (jalan di sisi gunung) beliau turun buang air kecil, kemudian beliau berwudlu namun dengan wudlu' yang ringan. Aku lalu bertanya, \"Apakah akan shalat wahai Rasulullah? ' beliau menjawab: \"Shalat masih ada di depanmu.\" Beliau lalu mengendarai tunggangannya hingga sampai di Muzdalifaah beliau turun dan wudlu' secara sempurna, kemudian iqamah dikumandangkan, dan beliau pun melaksanakan shalat Maghrib. Kemudian orang-orang menambatkan unta-unta mereka pada tempatnya, lalu iqamat isya` dikumandangkan, beliau lalu mengerjakan shalat isya` tanpa mengerjakan shalat yang lain di antara keduanya.\""},"137":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ عَبْدِ الرَّحِيمِ قَالَ أَخْبَرَنَا أَبُو سَلَمَةَ الْخُزَاعِيُّ مَنْصُورُ بْنُ سَلَمَةَ قَالَ أَخْبَرَنَا ابْنُ بِلَالٍ يَعْنِي سُلَيْمَانَ عَنْ زَيْدِ بْنِ أَسْلَمَ عَنْ عَطَاءِ بْنِ يَسَارٍ عَنْ ابْنِ عَبَّاسٍأَنَّهُ تَوَضَّأَ فَغَسَلَ وَجْهَهُ أَخَذَ غَرْفَةً مِنْ مَاءٍ فَمَضْمَضَ بِهَا وَاسْتَنْشَقَ ثُمَّ أَخَذَ غَرْفَةً مِنْ مَاءٍ فَجَعَلَ بِهَا هَكَذَا أَضَافَهَا إِلَى يَدِهِ الْأُخْرَى فَغَسَلَ بِهِمَا وَجْهَهُ ثُمَّ أَخَذَ غَرْفَةً مِنْ مَاءٍ فَغَسَلَ بِهَا يَدَهُ الْيُمْنَى ثُمَّ أَخَذَ غَرْفَةً مِنْ مَاءٍ فَغَسَلَ بِهَا يَدَهُ الْيُسْرَى ثُمَّ مَسَحَ بِرَأْسِهِ ثُمَّ أَخَذَ غَرْفَةً مِنْ مَاءٍ فَرَشَّ عَلَى رِجْلِهِ الْيُمْنَى حَتَّى غَسَلَهَا ثُمَّ أَخَذَ غَرْفَةً أُخْرَى فَغَسَلَ بِهَا رِجْلَهُ يَعْنِي الْيُسْرَى ثُمَّ قَالَ هَكَذَا رَأَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَتَوَضَّأُ","id":"Telah menceritakan kepada kami [Muhammad bin 'Abdurrahman] berkata, telah mengabarkan kepada kami [Abu Salamah Al Khaza'i Manshur bin Salamah] berkata, telah mengabarkan kepada kami [Ibnu Bilal] -yaitu Sulaiman- dari [Zaid bin Aslam] dari ['Atha' bin Yasar] dari [Ibnu 'Abbas], bahwa dia berwudlu', ia mencuci wajahnya, lalu mengambil air satu cidukan tangan dan menggunakannya untuk berkumur dan istintsaq, lalu ia kembali mengambil satu cidukan tangannya dan menjadikannya begini -menuangkan pada tangannya yang lain-, lalu dengan kedua tangannya ia membasuh wajahnya, lalu mengambil air satu cidukan dan membasuh tangan kanannya, lalu kembali mengambil air satu cidukan dan membasuh tangannya yang sebelah kiri. Kemudian mengusap kepala, lalu mengambil air satu cidukan dan menyela-nyela kaki kanannya hingga membasuhnya, lalu mengambil air satu cidukan lagi dan membasuh kaki kirinya. Setelah itu ia berkata, \"Seperti inilah aku lihat Rasulullah shallallahu 'alaihi wasallam berwudlu.\""},"138":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ عَبْدِ اللَّهِ قَالَ حَدَّثَنَا جَرِيرٌ عَنْ مَنْصُورٍ عَنْ سَالِمِ بْنِ أَبِي الْجَعْدِ عَنْ كُرَيْبٍ عَنْ ابْنِ عَبَّاسٍيَبْلُغُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَوْ أَنَّ أَحَدَكُمْ إِذَا أَتَى أَهْلَهُ قَالَ بِاسْمِ اللَّهِ اللَّهُمَّ جَنِّبْنَا الشَّيْطَانَ وَجَنِّبْ الشَّيْطَانَ مَا رَزَقْتَنَا فَقُضِيَ بَيْنَهُمَا وَلَدٌ لَمْ يَضُرُّهُ","id":"Telah menceritakan kepada kami ['Ali bin 'Abdullah] berkata, telah menceritakan kepada kami [Jarir] dari [Manshur] dari [Salim bin Abu Al Ja'd] dari [Kuraib] dari [Ibnu 'Abbas] dan sampai kepada Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Jika salah seorang dari kalian ingin mendatangi isterinya (untuk bersetubuh), maka hendaklah ia membaca; 'ALLAHUMMA JANNIBNASY SYAITHAANA WA JANNIBISY SYAITHAANA MAA RAZAQTANAA (Ya Allah, jauhkanlah kami dari setan dan jauhkanlah setan dari apa yang Engkau rizkikan (anak) kepada kami) '. Jika dikaruniai anak dari hubungan keduanya maka setan tidak akan dapat mencelakakan anak itu.\""},"139":{"ar":"حَدَّثَنَا آدَمُ قَالَ حَدَّثَنَا شُعْبَةُ عَنْ عَبْدِ الْعَزِيزِ بْنِ صُهَيْبٍ قَالَ سَمِعْتُ أَنَسًا يَقُولُكَانَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا دَخَلَ الْخَلَاءَ قَالَ اللَّهُمَّ إِنِّي أَعُوذُ بِكَ مِنْ الْخُبُثِ وَالْخَبَائِثِتَابَعَهُ ابْنُ عَرْعَرَةَ عَنْ شُعْبَةَ وَقَالَ غُنْدَرٌ عَنْ شُعْبَةَ إِذَا أَتَى الْخَلَاءَ وَقَالَ مُوسَى عَنْ حَمَّادٍ إِذَا دَخَلَ وَقَالَ سَعِيدُ بْنُ زَيْدٍ حَدَّثَنَا عَبْدُ الْعَزِيزِ إِذَا أَرَادَ أَنْ يَدْخُلَ","id":"Telah menceritakan kepada kami [Adam] berkata, telah menceritakan kepada kami [Syu'bah] dari [Abdul 'Aziz bin Shuhaib] berkata, aku mendengar [Anas] berkata, \"Jika Nabi shallallahu 'alaihi wasallam masuk ke dalam WC, maka beliau berdo'a: ALLAHUMMA INNI A'UUDZU BIKA MINAL KHUBUTSI WAL KHBA`ITS (Ya Allah aku berlindung kepada-Mu dari setan laki-laki dan setan perempuan) '. Dan hadits ini dikuatkan oleh [Ibnu 'Ar'arah] dari [Syu'bah], dan [Ghundar] berkata dari [Syu'bah] ia berkata, \"Jika mendatangi WC.\" Dan [Musa] dari [Hammad], \"Jika masuk.\" Dan [Sa'id bin Zaid] berkata, telah menceritakan kepada kami [Abdul 'Aziz], \"Jika mau masuk.\""},"140":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مُحَمَّدٍ قَالَ حَدَّثَنَا هَاشِمُ بْنُ الْقَاسِمِ قَالَ حَدَّثَنَا وَرْقَاءُ عَنْ عُبَيْدِ اللَّهِ بْنِ أَبِي يَزِيدَ عَنْ ابْنِ عَبَّاسٍأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ دَخَلَ الْخَلَاءَ فَوَضَعْتُ لَهُ وَضُوءًا قَالَ مَنْ وَضَعَ هَذَا فَأُخْبِرَ فَقَالَ اللَّهُمَّ فَقِّهْهُ فِي الدِّينِ","id":"Telah menceritakan kepada kami ['Abdullah bin Muhammad] berkata, telah menceritakan kepada kami [Hasyim bin Al Qasim] telah menceritakan kepada kami [Warqa'] dari ['Ubaidullah bin Abu Yazid] dari [Ibnu 'Abbas], bahwa pernah Nabi shallallahu 'alaihi wasallam masuk kedalam WC, lalu aku letakkan bejana berisi air. Beliau lantas bertanya: \"Siapa yang meletakkan ini?\" Aku lalu memberitahukannya, maka beliau pun bersabda: \"Ya Allah pandaikanlah dia dalam agama.\""},"141":{"ar":"حَدَّثَنَا آدَمُ قَالَ حَدَّثَنَا ابْنُ أَبِي ذِئْبٍ قَالَ حَدَّثَنَا الزُّهْرِيُّ عَنْ عَطَاءِ بْنِ يَزِيدَ اللَّيْثِيِّ عَنْ أَبِي أَيُّوبَ الْأَنْصَارِيِّ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا أَتَى أَحَدُكُمْ الْغَائِطَ فَلَا يَسْتَقْبِل الْقِبْلَةَ وَلَا يُوَلِّهَا ظَهْرَهُ شَرِّقُوا أَوْ غَرِّبُوا","id":"Telah menceritakan kepada kami [Adam] berkata, telah menceritakan kepada kami [Ibnu Abu Dzi'b] berkata, telah menceritakan kepada kami [Az Zuhri] dari ['Atha' bin Yazid Al Laitsi] dari [Abu Ayyub Al Anshari] berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Jika salah seorang dari kalian masuk ke dalam WC untuk buang hajat, maka janganlah menghadap ke arah kiblat membelakanginya. Hendaklah ia menghadap ke arah timurnya atau baratnya.\""},"142":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ يُوسُفَ قَالَ أَخْبَرَنَا مَالِكٌ عَنْ يَحْيَى بْنِ سَعِيدٍ عَنْ مُحَمَّدِ بْنِ يَحْيَى بْنِ حَبَّانَ عَنْ عَمِّهِ وَاسِعِ بْنِ حَبَّانَ عَنْ عَبْدِ اللَّهِ بْنِ عُمَرَأَنَّهُ كَانَ يَقُولُ إِنَّ نَاسًا يَقُولُونَ إِذَا قَعَدْتَ عَلَى حَاجَتِكَ فَلَا تَسْتَقْبِلْ الْقِبْلَةَ وَلَا بَيْتَ الْمَقْدِسِ فَقَالَ عَبْدُ اللَّهِ بْنُ عُمَرَ لَقَدْ ارْتَقَيْتُ يَوْمًا عَلَى ظَهْرِ بَيْتٍ لَنَا فَرَأَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَلَى لَبِنَتَيْنِ مُسْتَقْبِلًا بَيْتَ الْمَقْدِسِ لِحَاجَتِهِ وَقَالَ لَعَلَّكَ مِنْ الَّذِينَ يُصَلُّونَ عَلَى أَوْرَاكِهِمْ فَقُلْتُ لَا أَدْرِي وَاللَّهِقَالَ مَالِكٌ يَعْنِي الَّذِي يُصَلِّي وَلَا يَرْتَفِعُ عَنْ الْأَرْضِ يَسْجُدُ وَهُوَ لَاصِقٌ بِالْأَرْضِ","id":"Telah menceritakan kepada kami ['Abdullah bin Yusuf] berkata, telah menceritakan kepada kami [Malik] telah mengabarkan kepada kami [Yahya bin Sa'id] dari [Muhammad bin Yahya bin Hibban] dari pamannya [Wasi' bin Hibban] dari ['Abdullah bin 'Umar] bahwa ia berkata, \"Orang-orang berkata, \"Jika kamu menunaikan hajatmu maka janganlah menghadap kiblat atau menghadap ke arah Baitul Maqdis.\" 'Abdullah bin 'Umar lalu berkata, \"Pada suatu hari aku pernah naik atap rumah milik kami, lalu aku melihat Rasulullah shallallahu 'alaihi wasallam buang hajat menghadap Baitul Maqdis di antara dua dinding. Lalu ada seseorang yang berkata, \"Barangkali kamu termasuk dari orang-orang yang shalat dengan mendekatkan paha (ke tanah)?\" Maka aku jawab, \"Demi Allah, aku tidak tahu.\" Malik berkata, \"Yaitu orang yang shalat namun tidak mengangkat (paha) dari tanah ketika sujud, yakni menempel tanah.\""},"143":{"ar":"حَدَّثَنَا يَحْيَى بْنُ بُكَيْرٍ قَالَ حَدَّثَنَا اللَّيْثُ قَالَ حَدَّثَنِي عُقَيْلٌ عَنْ ابْنِ شِهَابٍ عَنْ عُرْوَةَ عَنْ عَائِشَةَأَنَّ أَزْوَاجَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كُنَّ يَخْرُجْنَ بِاللَّيْلِ إِذَا تَبَرَّزْنَ إِلَى الْمَنَاصِعِ وَهُوَ صَعِيدٌ أَفْيَحُ فَكَانَ عُمَرُ يَقُولُ لِلنَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ احْجُبْ نِسَاءَكَ فَلَمْ يَكُنْ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَفْعَلُ فَخَرَجَتْ سَوْدَةُ بِنْتُ زَمْعَةَ زَوْجُ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَيْلَةً مِنْ اللَّيَالِي عِشَاءً وَكَانَتْ امْرَأَةً طَوِيلَةً فَنَادَاهَا عُمَرُ أَلَا قَدْ عَرَفْنَاكِ يَا سَوْدَةُ حِرْصًا عَلَى أَنْ يَنْزِلَ الْحِجَابُ فَأَنْزَلَ اللَّهُ آيَةَ الْحِجَابِحَدَّثَنَا زَكَرِيَّاءُ قَالَ حَدَّثَنَا أَبُو أُسَامَةَ عَنْ هِشَامِ بْنِ عُرْوَةَ عَنْ أَبِيهِ عَنْ عَائِشَةَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ قَدْ أُذِنَ أَنْ تَخْرُجْنَ فِي حَاجَتِكُنَّ قَالَ هِشَامٌ يَعْنِي الْبَرَازَ","id":"Telah menceritakan kepada kami [Yahya bin Bukair] berkata, telah menceritakan kepada kami [Al Laits] berkata, telah menceritakan kepadaku ['Uqail] dari [Ibnu Syihab] dari [Urwah] dari ['Aisyah], bahwa jika isteri-isteri Nabi shallallahu 'alaihi wasallam ingin buang hajat, mereka keluar pada waktu malam menuju tempat buang hajat yang berupa tanah lapang dan terbuka. Umar pernah berkata kepada Nabi shallallahu 'alaihi wasallam, \"Hijabilah isteri-isteri Tuan.\" Namun Nabi shallallahu 'alaihi wasallam tidak melakukannya. Lalu pada suatu malam waktu Isya` Saudah binti Zam'ah, isteri Nabi shallallahu 'alaihi wasallam, keluar (untuk buang hajat). Dan Saudah adalah seorang wanita yang berpostur tinggi. 'Umar lalu berseru kepadanya, \"Sungguh kami telah mengenalmu wahai Saudah! ' Umar ucapkan demikian karena sangat antusias agar ayat hijab diturunkan. Maka Allah kemudian menurunkan ayat hijab.\" Telah menceritakan kepada kami [Zakaria] berkata, telah menceritakan kepada kami [Abu Usamah] dari [Hisyam bin 'Urwah] dari [Bapaknya] dari ['Aisyah] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Allah telah mengizinkan kalian (isteri-isteri Nabi) keluar untuk menunaikan hajat kalian.\" Hisyam berkata, \"Yakni buang air besar.\""},"144":{"ar":"حَدَّثَنَا إِبْرَاهِيمُ بْنُ الْمُنْذِرِ قَالَ حَدَّثَنَا أَنَسُ بْنُ عِيَاضٍ عَنْ عُبَيْدِ اللَّهِ عَنْ مُحَمَّدِ بْنِ يَحْيَى بْنِ حَبَّانَ عَنْ وَاسِعِ بْنِ حَبَّانَ عَنْ عَبْدِ اللَّهِ بْنِ عُمَرَ قَالَارْتَقَيْتُ فَوْقَ ظَهْرِ بَيْتِ حَفْصَةَ لِبَعْضِ حَاجَتِي فَرَأَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقْضِي حَاجَتَهُ مُسْتَدْبِرَ الْقِبْلَةِ مُسْتَقْبِلَ الشَّأْمِ","id":"Telah menceritakan kepada kami [Ibrahim bin Al Mundzir] berkata, telah menceritakan kepada kami [Anas bin 'Iyadl] dari ['Ubaidullah] dari [Muhammad bin Yahya bin Hibban] dari [Wasi' bin Hibban] dari ['Abdullah bin 'Umar] berkata, \"Aku pernah naik di rumah Hafshah karena suatu urusanku. Maka aku melihat Rasulullah shallallahu 'alaihi wasallam buang hajat membelakangi kiblat menghadap Syam.\""},"145":{"ar":"حَدَّثَنَا يَعْقُوبُ بْنُ إِبْرَاهِيمَ قَالَ حَدَّثَنَا يَزِيدُ بْنُ هَارُونَ قَالَ أَخْبَرَنَا يَحْيَى عَنْ مُحَمَّدِ بْنِ يَحْيَى بْنِ حَبَّانَ أَنَّ عَمَّهُ وَاسِعَ بْنَ حَبَّانَ أَخْبَرَهُ أَنَّ عَبْدَ اللَّهِ بْنَ عُمَرَ أَخْبَرَهُ قَالَلَقَدْ ظَهَرْتُ ذَاتَ يَوْمٍ عَلَى ظَهْرِ بَيْتِنَا فَرَأَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَاعِدًا عَلَى لَبِنَتَيْنِ مُسْتَقْبِلَ بَيْتِ الْمَقْدِسِ","id":"Telah menceritakan kepada kami [Ya'qub bin Ibrahim] berkata, telah menceritakan kepada kami [Yazid bin Harun] berkata, telah menceritakan kepada kami [Yahya] dari [Muhammad bin Yahya bin Hibban] bahwa pamannya [Wasi' bin Hibban] mengabarkan kepadanya bahwa ['Abdullah bin 'Umar] mengabarkan kepadanya, ia berkata, \"Pada suatu hari aku pernah berada di atas rumah milik kami, saat itu aku melihat Rasulullah shallallahu 'alaihi wasallam duduk (buang hajat) di atas dua batu bata menghadap Baitul Maqdis.\""},"146":{"ar":"حَدَّثَنَا أَبُو الْوَلِيدِ هِشَامُ بْنُ عَبْدِ الْمَلِكِ قَالَ حَدَّثَنَا شُعْبَةُ عَنْ أَبِي مُعَاذٍ وَاسْمُهُ عَطَاءُ بْنُ أَبِي مَيْمُونَةَ قَالَ سَمِعْتُ أَنَسَ بْنَ مَالِكٍ يَقُولُكَانَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا خَرَجَ لِحَاجَتِهِ أَجِيءُ أَنَا وَغُلَامٌ مَعَنَا إِدَاوَةٌ مِنْ مَاءٍ يَعْنِي يَسْتَنْجِي بِهِ","id":"Telah menceritakan kepada kami [Abu Al Walid Hisyam bin 'Abdul Malik] berkata, telah menceritakan kepada kami [Syu'bah] dari [Abu Mu'adz] dan namanya adalah 'Atha bin Abu Maimunah ia berkata, \"Aku mendengar [Anas bin Malik] berkata, \"Jika Nabi shallallahu 'alaihi wasallam keluar untuk buang hajat, maka aku dan seorang temanku membawakan bejana berisi air, yakni agar beliau bisa beristinja` dengannya.\""},"147":{"ar":"حَدَّثَنَا سُلَيْمَانُ بْنُ حَرْبٍ قَالَ حَدَّثَنَا شُعْبَةُ عَنْ أَبِي مُعَاذٍ هُوَ عَطَاءُ بْنُ أَبِي مَيْمُونَةَ قَالَ سَمِعْتُ أَنَسًا يَقُولُكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا خَرَجَ لِحَاجَتِهِ تَبِعْتُهُ أَنَا وَغُلَامٌ مِنَّا مَعَنَا إِدَاوَةٌ مِنْ مَاءٍ","id":"Telah menceritakan kepada kami [Sulaiman bin Harb] berkata, telah menceritakan kepada kami [Syu'bah] dari [Abu Mu'adz] -yaitu 'Atha' bin Abu Maimunah- ia berkata, \"Aku mendengar [Anas] berkata, \"Jika Rasulullah shallallahu 'alaihi wasallam keluar untuk buang hajat, maka aku dan seorang temanku mengikutinya dengan membawa bejana berisi air.\""},"148":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ قَالَ حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ قَالَ حَدَّثَنَا شُعْبَةُ عَنْ عَطَاءِ بْنِ أَبِي مَيْمُونَةَ سَمِعَ أَنَسَ بْنَ مَالِكٍ يَقُولُكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَدْخُلُ الْخَلَاءَ فَأَحْمِلُ أَنَا وَغُلَامٌ إِدَاوَةً مِنْ مَاءٍ وَعَنَزَةً يَسْتَنْجِي بِالْمَاءِتَابَعَهُ النَّضْرُ وَشَاذَانُ عَنْ شُعْبَةَ الْعَنَزَةُ عَصًا عَلَيْهِ زُجٌّ","id":"Telah menceritakan kepada kami [Muhammad bin Basysyar] berkata, telah menceritakan kepada kami [Muhammad bin Ja'far] berkata, telah menceritakan kepada kami [Syu'bah] dari ['Atha' bin Abu Maimunah] ia mendengar [Anas bin Malik] berkata, \"Rasulullah shallallahu 'alaihi wasallam masuk ke dalam WC untuk buang hajat, lalu aku dan seorang temanku membawa bejana berisi air dan sebatang kayu (tongkat) untuk beliau gunakan beristinja'. Hadits ini kuatkan oleh [An-Nadlr] dan [Syadzan] dari [Syu'bah], \"Al Anazah adalah tongkat yang ujungnya ada besi.\""},"149":{"ar":"حَدَّثَنَا مُعَاذُ بْنُ فَضَالَةَ قَالَ حَدَّثَنَا هِشَامٌ هُوَ الدَّسْتَوَائِيُّ عَنْ يَحْيَى بْنِ أَبِي كَثِيرٍ عَنْ عَبْدِ اللَّهِ بْنِ أَبِي قَتَادَةَ عَنْ أَبِيهِ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا شَرِبَ أَحَدُكُمْ فَلَا يَتَنَفَّسْ فِي الْإِنَاءِ وَإِذَا أَتَى الْخَلَاءَ فَلَا يَمَسَّ ذَكَرَهُ بِيَمِينِهِ وَلَا يَتَمَسَّحْ بِيَمِينِهِ","id":"Telah menceritakan kepada kami [Mu'adz bin Fadlalah] berkata, telah menceritakan kepada kami [Hisyam] -yaitu Al Dastawa'I- dari [Yahya bin Abu Katsir] dari ['Abdullah bin Abu Qatadah] dari [Bapaknya] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam telah bersabda: \"Jika salah seorang dari kalian minum, maka janganlah ia bernafas dalam gelas. Dan jika masuk ke dalam WC janganlah dia menyentuh kemaluannya dengan tangan kanannya dan jangan membersihkan dengan tangan kanannya.\""},"150":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ يُوسُفَ قَالَ حَدَّثَنَا الْأَوْزَاعِيُّ عَنْ يَحْيَى بْنِ أَبِي كَثِيرٍ عَنْ عَبْدِ اللَّهِ بْنِ أَبِي قَتَادَةَ عَنْ أَبِيهِعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِذَا بَالَ أَحَدُكُمْ فَلَا يَأْخُذَنَّ ذَكَرَهُ بِيَمِينِهِ وَلَا يَسْتَنْجِي بِيَمِينِهِ وَلَا يَتَنَفَّسْ فِي الْإِنَاءِ","id":"Telah menceritakan kepada kami [Muhammad bin Yusuf] berkata, telah menceritakan kepada kami [Al Auza'i] dari [Yahya bin Abu Katsir] dari ['Abdullah bin Abu Qatadah] dari [Bapaknya] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Jika salah seorang dari kalian kencing maka janganlah ia memegang kemaluannya dengan tangan kanan, jangan beristinja' dengan tangan kanan dan jangan bernafas dalam gelas saat minum.\""},"151":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ مُحَمَّدٍ الْمَكِّيُّ قَالَ حَدَّثَنَا عَمْرُو بْنُ يَحْيَى بْنِ سَعِيدِ بْنِ عَمْرٍو الْمَكِّيُّ عَنْ جَدِّهِ عَنْ أَبِي هُرَيْرَةَ قَالَاتَّبَعْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَخَرَجَ لِحَاجَتِهِ فَكَانَ لَا يَلْتَفِتُ فَدَنَوْتُ مِنْهُ فَقَالَ ابْغِنِي أَحْجَارًا أَسْتَنْفِضْ بِهَا أَوْ نَحْوَهُ وَلَا تَأْتِنِي بِعَظْمٍ وَلَا رَوْثٍ فَأَتَيْتُهُ بِأَحْجَارٍ بِطَرَفِ ثِيَابِي فَوَضَعْتُهَا إِلَى جَنْبِهِ وَأَعْرَضْتُ عَنْهُ فَلَمَّا قَضَى أَتْبَعَهُ بِهِنَّ","id":"Telah menceritakan kepada kami [Ahmad bin Muhammad Al Makki] berkata, telah menceritakan kepada kami ['Amru bin Yahya bin Sa'id bin 'Amru Al Makki] dari [Kakeknya] dari [Abu Hurairah] ia berkata, \"Aku mengikuti Nabi shallallahu 'alaihi wasallam saat beliau keluar untuk buang hajat, dan beliau tidak menoleh (ke kanan atau ke kiri) hingga aku pun mendekatinya. Lalu Beliau bersabda: \"Carikan untukku batu untuk aku gunakan beristinja' dan jangan bawakan tulang atau kotoran hewan.\" Lalu aku datang kepada beliau dengan membawa kerikil di ujung kainku, batu tersebut aku letakkan di sisinya, lalu aku berpaling darinya. Setelah selesai beliau gunakan batu-batu tersebut.\""},"152":{"ar":"حَدَّثَنَا أَبُو نُعَيْمٍ قَالَ حَدَّثَنَا زُهَيْرٌ عَنْ أَبِي إِسْحَاقَ قَالَ لَيْسَ أَبُو عُبَيْدَةَ ذَكَرَهُ وَلَكِنْ عَبْدُ الرَّحْمَنِ بْنُ الْأَسْوَدِ عَنْ أَبِيهِ أَنَّهُ سَمِعَ عَبْدَ اللَّهِ يَقُولُأَتَى النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْغَائِطَ فَأَمَرَنِي أَنْ آتِيَهُ بِثَلَاثَةِ أَحْجَارٍ فَوَجَدْتُ حَجَرَيْنِ وَالْتَمَسْتُ الثَّالِثَ فَلَمْ أَجِدْهُ فَأَخَذْتُ رَوْثَةً فَأَتَيْتُهُ بِهَا فَأَخَذَ الْحَجَرَيْنِ وَأَلْقَى الرَّوْثَةَ وَقَالَ هَذَا رِكْسٌوَقَالَ إِبْرَاهِيمُ بْنُ يُوسُفَ عَنْ أَبِيهِ عَنْ أَبِي إِسْحَاقَ حَدَّثَنِي عَبْدُ الرَّحْمَنِ","id":"Telah menceritakan kepada kami [Abu Nu'aim] berkata, telah menceritakan kepada kami [Zuhair] dari [Abu Ishaq] berkata -Abu 'Ubaidah tidak menyebutkannya tetapi- ['Abdurrahman bin Aswad] dari [Bapaknya] bahwa ia mendengar ['Abdullah] berkata, \"Nabi shallallahu 'alaihi wasallam pergi ke WC, lalu beliau memerintahkan aku membawakan tiga buah batu. Aku hanya mendapatkan dua batu, lalu aku mencari batu yang ketiga, namun aku tidak mendapatkannya hingga aku pun mengambil kotoran hewan yang sudah kering. Kemudian semua itu aku bahwa ke hadapan Nabi. Namun beliau hanya mengambil dua batu dan membuang kotoran hewan yang telah kering tersebut seraya bersabda: \"Ini najis.\" [Ibrahim bin Yusuf] berkata dari [Bapaknya] dari [Abu Ishaq] berkata, telah menceritakan kepadaku ['Abdurrahman].\""},"153":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ يُوسُفَ قَالَ حَدَّثَنَا سُفْيَانُ عَنْ زَيْدِ بْنِ أَسْلَمَ عَنْ عَطَاءِ بْنِ يَسَارٍ عَنْ ابْنِ عَبَّاسٍ قَالَتَوَضَّأَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَرَّةً مَرَّةً","id":"Telah menceritakan kepada kami [Muhammad bin Yusuf] berkata, telah menceritakan kepada kami [Sufyan] dari [Zaid bin Aslam] dari ['Atha' bin Yasar] dari [Ibnu 'Abbas] berkata, \"Nabi shallallahu 'alaihi wasallam berwudlu' sekali sekali.\""},"154":{"ar":"حَدَّثَنَا حُسَيْنُ بْنُ عِيسَى قَالَ حَدَّثَنَا يُونُسُ بْنُ مُحَمَّدٍ قَالَ حَدَّثَنَا فُلَيْحُ بْنُ سُلَيْمَانَ عَنْ عَبْدِ اللَّهِ بْنِ أَبِي بَكْرِ بْنِ عَمْرِو بْنِ حَزْمٍ عَنْ عَبَّادِ بْنِ تَمِيمٍ عَنْ عَبْدِ اللَّهِ بْنِ زَيْدٍأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ تَوَضَّأَ مَرَّتَيْنِ مَرَّتَيْنِ","id":"Telah menceritakan kepada kami [Husain bin 'Isa] berkata, telah menceritakan kepada kami [Yunus bin Muhammad] berkata, telah menceritakan kepada kami [Fulaih bin Sulaiman] dari ['Abdullah bin Abu Bakar bin 'Amru bin Hazm] dari ['Abbad bin Tamim] dari ['Abdullah bin Zaid], bahwa Nabi shallallahu 'alaihi wasallam berwudlu dua kali dua kali.\""},"155":{"ar":"حَدَّثَنَا عَبْدُ الْعَزِيزِ بْنُ عَبْدِ اللَّهِ الْأُوَيْسِيُّ قَالَ حَدَّثَنِي إِبْرَاهِيمُ بْنُ سَعْدٍ عَنْ ابْنِ شِهَابٍ أَنَّ عَطَاءَ بْنَ يَزِيدَ أَخْبَرَهُ أَنَّ حُمْرَانَ مَوْلَى عُثْمَانَ أَخْبَرَهُ أَنَّهُ رَأَى عُثْمَانَ بْنَ عَفَّانَدَعَا بِإِنَاءٍ فَأَفْرَغَ عَلَى كَفَّيْهِ ثَلَاثَ مِرَارٍ فَغَسَلَهُمَا ثُمَّ أَدْخَلَ يَمِينَهُ فِي الْإِنَاءِ فَمَضْمَضَ وَاسْتَنْشَقَ ثُمَّ غَسَلَ وَجْهَهُ ثَلَاثًا وَيَدَيْهِ إِلَى الْمِرْفَقَيْنِ ثَلَاثَ مِرَارٍ ثُمَّ مَسَحَ بِرَأْسِهِ ثُمَّ غَسَلَ رِجْلَيْهِ ثَلَاثَ مِرَارٍ إِلَى الْكَعْبَيْنِ ثُمَّ قَالَ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ تَوَضَّأَ نَحْوَ وُضُوئِي هَذَا ثُمَّ صَلَّى رَكْعَتَيْنِ لَا يُحَدِّثُ فِيهِمَا نَفْسَهُ غُفِرَ لَهُ مَا تَقَدَّمَ مِنْ ذَنْبِهِوَعَنْ إِبْرَاهِيمَ قَالَ قَالَ صَالِحُ بْنُ كَيْسَانَ قَالَ ابْنُ شِهَابٍ وَلَكِنْ عُرْوَةُ يُحَدِّثُ عَنْ حُمْرَانَ فَلَمَّا تَوَضَّأَ عُثْمَانُ قَالَ أَلَا أُحَدِّثُكُمْ حَدِيثًا لَوْلَا آيَةٌ مَا حَدَّثْتُكُمُوهُ سَمِعْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ لَا يَتَوَضَّأُ رَجُلٌ يُحْسِنُ وُضُوءَهُ وَيُصَلِّي الصَّلَاةَ إِلَّا غُفِرَ لَهُ مَا بَيْنَهُ وَبَيْنَ الصَّلَاةِ حَتَّى يُصَلِّيَهَا قَالَ عُرْوَةُ الْآيَةَ{ إِنَّ الَّذِينَ يَكْتُمُونَ مَا أَنْزَلْنَا مِنْ الْبَيِّنَاتِ }","id":"Telah menceritakan kepada kami [Abdul 'Aziz bin 'Abdullah Al Uwaisy] berkata, telah menceritakan kepadaku [Ibrahim bin Sa'd] dari [Syihab] bahwa ['Atha' bin Yazid] mengabarkan kepadanya bahwa [Humran] mantan budan 'Utsman mengabarkan kepadanya, bahwa ia telah melihat ['Utsman bin 'Affan] minta untuk diambilkan bejana (berisi air). Lalu dia menuangkan pada telapak tangannya tiga kali lalu membasuh keduanya, lalu ia memasukkan tangan kanannya ke dalam bejana lalu berkumur-kumur dan memasukkan air ke dalam hidung, kemudian membasuh wajahnya tiga kali, kemudian membasuh kedua tangan hingga siku tiga kali, kemudian mengusap kepala, kemudian membasuh kedua kakinya tiga kali hingga kedua mata kaki. Setelah itu ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa berwudlu seperti wudluku ini, kemudian dia shalat dua rakaat dan tidak berbicara antara keduanya, maka dosanya yang telah lalu akan diampuni.\" Dan dari [Ibrahim] berkata, [Shalih bin Kaisan] berkata, [Ibnu Syihab] berkata. Tetapi ['Urwah] menceritakan dari [Humran], \"Ketika ['Utsman] berwudlu, dia berkata, \"Maukah aku sampaikan kepada kalian sebuah hadits yang kalau bukan karena ada satu ayat tentu aku tidak akan menyampaikannya? Aku pernah mendengar Nabi shallallahu 'alaihi wasallam bersabda: \"Tidaklah seorang laki-laki berwudlu dengan membaguskan wudlunya kemudian mengerjakan shalat, kecuali akan diampuni (dosa) antara wudlunya dan shalatnya itu hingga selesai shalatnya.\" 'Urwah berkata, \"Ayat yang dimaksud adalah: '(Sesungguhnya orang-orang yang menyembunyikan apa yang telah kami turunkan…) ' (Qs. Al Baqarah: 159)."},"156":{"ar":"حَدَّثَنَا عَبْدَانُ قَالَ أَخْبَرَنَا عَبْدُ اللَّهِ قَالَ أَخْبَرَنَا يُونُسُ عَنْ الزُّهْرِيِّ قَالَ أَخْبَرَنِي أَبُو إِدْرِيسَ أَنَّهُ سَمِعَ أَبَا هُرَيْرَةَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُ قَالَ مَنْ تَوَضَّأَ فَلْيَسْتَنْثِرْ وَمَنْ اسْتَجْمَرَ فَلْيُوتِرْ","id":"Telah menceritakan kepada kami ['Abdan] berkata, telah mengabarkan kepada kami ['Abdullah] berkata, telah mengabarkan kepada kami [Yunus] dari [Az Zuhri] berkata, telah mengabarkan kepadaku [Abu Idris] bahwa dia mendengar [Abu Hurairah] dari Nabi shallallahu 'alaihi wasallam, bahwa beliau bersabda: \"Barangsiapa berwudlu hendaklah mengeluarkan (air dari hidung), dan barangsiapa beristinja' dengan batu hendaklah dengan bilangan ganjil.\""},"157":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ يُوسُفَ قَالَ أَخْبَرَنَا مَالِكٌ عَنْ أَبِي الزِّنَادِ عَنْ الْأَعْرَجِ عَنْ أَبِي هُرَيْرَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِذَا تَوَضَّأَ أَحَدُكُمْ فَلْيَجْعَلْ فِي أَنْفِهِ ثُمَّ لِيَنْثُرْ وَمَنْ اسْتَجْمَرَ فَلْيُوتِرْ وَإِذَا اسْتَيْقَظَ أَحَدُكُمْ مِنْ نَوْمِهِ فَلْيَغْسِلْ يَدَهُ قَبْلَ أَنْ يُدْخِلَهَا فِي وَضُوئِهِ فَإِنَّ أَحَدَكُمْ لَا يَدْرِي أَيْنَ بَاتَتْ يَدُهُ","id":"Telah menceritakan kepada kami ['Abdullah bin Yusuf] berkata, telah mengabarkan kepada kami [Malik] dari [Abu Az Zinad] dari [Al A'raj] dari [Abu Hurairah], bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Jika salah seorang dari kalian berwudlu hendaklah dengan memasukkan air ke dalam hidung, barangsiapa beristinja' dengan batu hendaklah dengan bilangan ganjil. Dan jika salah seorang dari kalian bangun dari tidurnya, hendaklah membasuh kedua telapak tangannya sebelum memasukkannya dalam bejana air wudlunya, sebab salah seorang dari kalian tidak tahu ke mana tangannya bermalam.\""},"158":{"ar":"حَدَّثَنَا مُوسَى قَالَ حَدَّثَنَا أَبُو عَوَانَةَ عَنْ أَبِي بِشْرٍ عَنْ يُوسُفَ بْنِ مَاهَكَ عَنْ عَبْدِ اللَّهِ بْنِ عَمْرٍو قَالَتَخَلَّفَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنَّا فِي سَفْرَةٍ سَافَرْنَاهَا فَأَدْرَكَنَا وَقَدْ أَرْهَقْنَا الْعَصْرَ فَجَعَلْنَا نَتَوَضَّأُ وَنَمْسَحُ عَلَى أَرْجُلِنَا فَنَادَى بِأَعْلَى صَوْتِهِ وَيْلٌ لِلْأَعْقَابِ مِنْ النَّارِ مَرَّتَيْنِ أَوْ ثَلَاثًا","id":"Telah menceritakan kepada kami [Musa] berkata, telah menceritakan kepada kami [Abu 'Awanah] dari [Abu Bisyir] dari [Yusuf bin Mahak] dari [Abdullah bin 'Amru] berkata, \"Nabi shallallahu 'alaihi wasallam pernah tertinggal dari kami dalam suatu perjalanan yang kami lakukan, beliau lalu dapat menyusul saat kami hampir kehabisan waktu shalat 'Ashar sehingga kami berwudlu dengan hanya mengusap kaki kami. Maka Nabi shallallahu 'alaihi wasallam berseru dengan suara yang keras: \"Tumit-tumit yang tidak terkena air wudlu akan masuk ke dalam neraka.\" Beliau ucapkan itu hingga tiga kali.\""},"159":{"ar":"حَدَّثَنَا أَبُو الْيَمَانِ قَالَ أَخْبَرَنَا شُعَيْبٌ عَنْ الزُّهْرِيِّ قَالَ أَخْبَرَنِي عَطَاءُ بْنُ يَزِيدَ عَنْ حُمْرَانَ مَوْلَى عُثْمَانَ بْنِ عَفَّانَ أَنَّهُ رَأَى عُثْمَانَ بْنَ عَفَّانَدَعَا بِوَضُوءٍ فَأَفْرَغَ عَلَى يَدَيْهِ مِنْ إِنَائِهِ فَغَسَلَهُمَا ثَلَاثَ مَرَّاتٍ ثُمَّ أَدْخَلَ يَمِينَهُ فِي الْوَضُوءِ ثُمَّ تَمَضْمَضَ وَاسْتَنْشَقَ وَاسْتَنْثَرَ ثُمَّ غَسَلَ وَجْهَهُ ثَلَاثًا وَيَدَيْهِ إِلَى الْمِرْفَقَيْنِ ثَلَاثًا ثُمَّ مَسَحَ بِرَأْسِهِ ثُمَّ غَسَلَ كُلَّ رِجْلٍ ثَلَاثًا ثُمَّ قَالَ رَأَيْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَتَوَضَّأُ نَحْوَ وُضُوئِي هَذَا وَقَالَ مَنْ تَوَضَّأَ نَحْوَ وُضُوئِي هَذَا ثُمَّ صَلَّى رَكْعَتَيْنِ لَا يُحَدِّثُ فِيهِمَا نَفْسَهُ غَفَرَ اللَّهُ لَهُ مَا تَقَدَّمَ مِنْ ذَنْبِهِ","id":"Telah menceritakan kepada kami [Abu Al Yaman] berkata, telah mengabarkan kepada kami [Syu'aib] dari [Az Zuhri] berkata, telah mengabarkan kepadaku ['Atha' bin Yazid] dari [Humran] mantan budak 'Utsman bin 'Affan, bahwa ia melihat ['Utsman bin 'Affan] minta untuk diambilkan air wudlu. Ia lalu menuang bejana itu pada kedua tangannya, lalu ia basuh kedua tangannya tersebut hingga tiga kali. Kemudian ia memasukkan tangan kanannya ke dalam air wudlunya, kemudian berkumur, memasukkan air ke dalam hidung dan mengeluarkannya. Kemudian membasuh mukanya tiga kali, membasuh kedua lengannya hingga siku tiga kali, mengusap kepalanya lalu membasuh setiap kakinya tiga kali. Setelah itu ia berkata, \"Aku telah melihat Nabi shallallahu 'alaihi wasallam berwudlu seperti wudluku ini, beliau lalu bersabda: \"Barangsiapa berwudlu seperti wudluku ini, kemudian dia shalat dua rakaat dan tidak berbicara antara keduanya, maka Allah mengampuni dosanya yang telah lalu.\""},"160":{"ar":"حَدَّثَنَا آدَمُ بْنُ أَبِي إِيَاسٍ قَالَ حَدَّثَنَا شُعْبَةُ قَالَ حَدَّثَنَا مُحَمَّدُ بْنُ زِيَادٍ قَالَ سَمِعْتُ أَبَا هُرَيْرَةَ وَكَانَ يَمُرُّ بِنَا وَالنَّاسُ يَتَوَضَّئُونَ مِنْ الْمِطْهَرَةِ قَالَ أَسْبِغُوا الْوُضُوءَفَإِنَّ أَبَا الْقَاسِمِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ وَيْلٌ لِلْأَعْقَابِ مِنْ النَّارِ","id":"Telah menceritakan kepada kami [Adam bin Abu Iyas] berkata, telah menceritakan kepada kami [Syu'bah] berkata, telah menceritakan kepada kami [Muhammad bin Ziyad] berkata, \"Aku mendengar [Abu Hurairah] berkata saat dia lewat di hadapan kami, sementara saat itu orang-orang sedang berwudlu, \"Sempurnakanlah wudlu kalian! Sesungguhnya Abul Qasim shallallahu 'alaihi wasallam bersabda: \"Tumit-tumit yang tidak terkena air wudlu akan masuk neraka.\""},"161":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ يُوسُفَ قَالَ أَخْبَرَنَا مَالِكٌ عَنْ س��عِيدٍ الْمَقْبُرِيِّ عَنْ عُبَيْدِ بْنِ جُرَيْجٍ أَنَّهُ قَالَ لِعَبْدِ اللَّهِ بْنِ عُمَرَيَا أَبَا عَبْدِ الرَّحْمَنِ رَأَيْتُكَ تَصْنَعُ أَرْبَعًا لَمْ أَرَ أَحَدًا مِنْ أَصْحَابِكَ يَصْنَعُهَا قَالَ وَمَا هِيَ يَا ابْنَ جُرَيْجٍ قَالَ رَأَيْتُكَ لَا تَمَسُّ مِنْ الْأَرْكَانِ إِلَّا الْيَمَانِيَّيْنِ وَرَأَيْتُكَ تَلْبَسُ النِّعَالَ السِّبْتِيَّةَ وَرَأَيْتُكَ تَصْبُغُ بِالصُّفْرَةِ وَرَأَيْتُكَ إِذَا كُنْتَ بِمَكَّةَ أَهَلَّ النَّاسُ إِذَا رَأَوْا الْهِلَالَ وَلَمْ تُهِلَّ أَنْتَ حَتَّى كَانَ يَوْمُ التَّرْوِيَةِ قَالَ عَبْدُ اللَّهِ أَمَّا الْأَرْكَانُ فَإِنِّي لَمْ أَرَ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَمَسُّ إِلَّا الْيَمَانِيَّيْنِ وَأَمَّا النِّعَالُ السِّبْتِيَّةُ فَإِنِّي رَأَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَلْبَسُ النَّعْلَ الَّتِي لَيْسَ فِيهَا شَعَرٌ وَيَتَوَضَّأُ فِيهَا فَأَنَا أُحِبُّ أَنْ أَلْبَسَهَا وَأَمَّا الصُّفْرَةُ فَإِنِّي رَأَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَصْبُغُ بِهَا فَأَنَا أُحِبُّ أَنْ أَصْبُغَ بِهَا وَأَمَّا الْإِهْلَالُ فَإِنِّي لَمْ أَرَ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُهِلُّ حَتَّى تَنْبَعِثَ بِهِ رَاحِلَتُهُ","id":"Telah menceritakan kepada kami ['Abdullah bin Yusuf] berkata, telah mengabarkan kepada kami [Malik] dari [Sa'id Al Maqbari] dari ['Ubaid bin Juraij] bahwa dia berkata kepada ['Abdullah bin 'Umar], \"Wahai Abu 'Abdurrahman, aku melihat anda mengerjakan empat hal yang tidak aku lihat seorangpun dari sahabatmu melakukannya!\" 'Abdullah bin 'Umar berkata, \"Apa sajakah itu wahai Ibnu Juraij?\" Ibnu Juraij berkata, \"Aku melihat anda tidak menyentuh rukun-rukun (Ka'bah) kecuali rukun Yamani, aku melihat anda mengenakan sandal terbuat dari kulit, aku melihat anda mengecat (rambut) dengan berwarna kuning, dan saat manusia di Makkah melakukan talbiyah setelah melihat hilal aku melihat anda tidak melakukannya kecuali pada hari tarwiyah?\" 'Abdullah bin 'Umar pun berkata, \"Adapun tentang rukun Ka'bah, sungguh aku tidak pernah melihat Rasulullah shallallahu 'alaihi wasallam mengusapnya kecuali rukun Yamani. Sedangkan mengenai sandal dari kulit, sungguh aku melihat Rasulullah shallallahu 'alaihi wasallam juga mengenakan sandal kulit yang tidak berbulu, dan berwudlu dengan tetap mengenakannya, dan aku suka bila tetap mengenakannya. Adapun tentang warna kuning, sungguh aku melihat Rasulullah shallallahu 'alaihi wasallam mencelup dengan warna tersebut dan aku juga suka melakukannya. Dan tentang talbiyah, sungguh belum pernah aku melihat Rasulullah shallallahu 'alaihi wasallam bertalbiyah kecuali setelah kendaraannya melaju (menuju Mina).\""},"162":{"ar":"حَدَّثَنَا مُسَدَّدٌ قَالَ حَدَّثَنَا إِسْمَاعِيلُ قَالَ حَدَّثَنَا خَالِدٌ عَنْ حَفْصَةَ بِنْتِ سِيرِينَ عَنْ أُمِّ عَطِيَّةَ قَالَتْقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَهُنَّ فِي غَسْلِ ابْنَتِهِ ابْدَأْنَ بِمَيَامِنِهَا وَمَوَاضِعِ الْوُضُوءِ مِنْهَا","id":"Telah menceritakan kepada kami [Musaddad] berkata, telah menceritakan kepada kami [Isma'il] berkata, telah menceritakan kepada kami [Khalid] dari [Hafshah] dari [Ummu 'Athiyah] berkata, \"Nabi shallallahu 'alaihi wasallam bersabda kepada mereka saat memandikan puterinya: \"Hendaklah kalian mulai dari yang sebelah kanan dan anggota wudlunya.\""},"163":{"ar":"حَدَّثَنَا حَفْصُ بْنُ عُمَرَ قَالَ حَدَّثَنَا شُعْبَةُ قَالَ أَخْبَرَنِي أَشْعَثُ بْنُ سُلَيْم�� قَالَ سَمِعْتُ أَبِي عَنْ مَسْرُوقٍ عَنْ عَائِشَةَ قَالَتْكَانَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُعْجِبُهُ التَّيَمُّنُ فِي تَنَعُّلِهِ وَتَرَجُّلِهِ وَطُهُورِهِ وَفِي شَأْنِهِ كُلِّهِ","id":"Telah menceritakan kepada kami [Hafsh bin 'Umar] berkata, telah menceritakan kepada kami [Syu'bah] berkata, telah mengabarkan kepadaku [Asy'ats bin Sulaim] berkata, Aku mendengar [Bapakku] dari [Masruq] dari ['Aisyah] berkata, \"Nabi shallallahu 'alaihi wasallam suka memulai dari sebelah kanan saat mengenakan sandal, menyisir rambut, bersuci dan selainnya.\""},"164":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ يُوسُفَ قَالَ أَخْبَرَنَا مَالِكٌ عَنْ إِسْحَاقَ بْنِ عَبْدِ اللَّهِ بْنِ أَبِي طَلْحَةَ عَنْ أَنَسِ بْنِ مَالِكٍ أَنَّهُ قَالَرَأَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَحَانَتْ صَلَاةُ الْعَصْرِ فَالْتَمَسَ النَّاسُ الْوَضُوءَ فَلَمْ يَجِدُوهُ فَأُتِيَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِوَضُوءٍ فَوَضَعَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي ذَلِكَ الْإِنَاءِ يَدَهُ وَأَمَرَ النَّاسَ أَنْ يَتَوَضَّئُوا مِنْهُ قَالَ فَرَأَيْتُ الْمَاءَ يَنْبُعُ مِنْ تَحْتِ أَصَابِعِهِ حَتَّى تَوَضَّئُوا مِنْ عِنْدِ آخِرِهِمْ","id":"Telah menceritakan kepada kami ['Abdullah bin Yusuf] berkata, telah mengabarkan kepada kami [Malik] dari [Ishaq bin 'Abdullah bin Abu Thalhah] dari [Anas bin Malik] berkata, \"Ketika waktu shalat Ashar tiba, orang-orang mencari air wudlu namun tidak mendapatkannya. Lalu aku melihat Rasulullah shallallahu 'alaihi wasallam diberi air wudlu, Rasulullah shallallahu 'alaihi wasallam kemudian meletakkan tangannya di atas bejana tersebut seraya memerintahkan orang-orang untuk berwudlu darinya.\" Anas berkata, \"Aku melihat air keluar dari jari-jari beliau hingga semua orang sampai yang terakhir dapat berwudlu.\""},"165":{"ar":"حَدَّثَنَا مَالِكُ بْنُ إِسْمَاعِيلَ قَالَ حَدَّثَنَا إِسْرَائِيلُ عَنْ عَاصِمٍ عَنْ ابْنِ سِيرِينَ قَالَ قُلْتُلِعَبِيدَةَ عِنْدَنَا مِنْ شَعَرِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَصَبْنَاهُ مِنْ قِبَلِ أَنَسٍ أَوْ مِنْ قِبَلِ أَهْلِ أَنَسٍفَقَالَ لَأَنْ تَكُونَ عِنْدِي شَعَرَةٌ مِنْهُ أَحَبُّ إِلَيَّ مِنْ الدُّنْيَا وَمَا فِيهَا","id":"Telah menceritakan kepada kami [Malik bin Isma'il] berkata, telah menceritakan kepada kami [Israil] dari ['Ashim] dari [Ibnu Sirin] berkata, \"Aku berkata kepada Abidah, \"Kami memiliki rambut Nabi shallallahu 'alaihi wasallam yang kami dapat dari [Anas], atau keluarga Anas.' Ia lalu berkata, \"Sekiranya aku memiliki satu helai rambut Rasulullah, maka itu lebih aku sukai daripada dunia dan seisinya.\""},"166":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ عَبْدِ الرَّحِيمِ قَالَ أَخْبَرَنَا سَعِيدُ بْنُ سُلَيْمَانَ قَالَ حَدَّثَنَا عَبَّادٌ عَنْ ابْنِ عَوْنٍ عَنْ ابْنِ سِيرِينَ عَنْ أَنَسٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَمَّا حَلَقَ رَأْسَهُ كَانَ أَبُو طَلْحَةَ أَوَّلَ مَنْ أَخَذَ مِنْ شَعَرِهِ","id":"Telah menceritakan kepada kami [Muhammad bin 'Abdurrahim] berkata, telah mengabarkan kepada kami [Sa'id bin Sulaiman] berkata, telah menceritakan kepada kami ['Abbad] dari [Ibnu 'Aun] dari [Ibnu Sirin] dari [Anas], bahwa ketika Rasulullah shallallahu 'alaihi wasallam mencukur rambutnya, maka Abu Thalhah adalah orang yang pertama mengambil rambut beliau.\""},"167":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ يُوسُفَ عَنْ مَالِكٍ عَنْ أَبِي الزِّنَادِ عَنْ الْأَعْرَجِ عَنْ أَبِي هُرَيْرَةَ قَالَإِنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِذَا شَرِبَ الْكَلْبُ فِي إِنَاءِ أَحَدِكُمْ فَلْيَغْسِلْهُ سَبْعًا","id":"Telah menceritakan kepada kami ['Abdullah bin Yusuf] dari [Malik] dari [Abu Az Zinad] dari [Al A'raj] dari [Abu Hurairah] berkata, \"Sesungguhnya Rasulullah shallallahu 'alaihi wasallam bersabda: \"Jika anjing menjilat bejana seorang dari kalian, maka hendaklah ia cuci hingga tujuh kali.\""},"168":{"ar":"حَدَّثَنَا إِسْحَاقُ أَخْبَرَنَا عَبْدُ الصَّمَدِ حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ عَبْدِ اللَّهِ بْنِ دِينَارٍ سَمِعْتُ أَبِي عَنْ أَبِي صَالِحٍ عَنْ أَبِي هُرَيْرَةَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّ رَجُلًا رَأَى كَلْبًا يَأْكُلُ الثَّرَى مِنْ الْعَطَشِ فَأَخَذَ الرَّجُلُ خُفَّهُ فَجَعَلَ يَغْرِفُ لَهُ بِهِ حَتَّى أَرْوَاهُ فَشَكَرَ اللَّهُ لَهُ فَأَدْخَلَهُ الْجَنَّةَوَقَالَ أَحْمَدُ بْنُ شَبِيبٍ حَدَّثَنَا أَبِي عَنْ يُونُسَ عَنْ ابْنِ شِهَابٍ قَالَ حَدَّثَنِي حَمْزَةُ بْنُ عَبْدِ اللَّهِ عَنْ أَبِيهِ قَالَ كَانَتْ الْكِلَابُ تَبُولُ وَتُقْبِلُ وَتُدْبِرُ فِي الْمَسْجِدِ فِي زَمَانِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَلَمْ يَكُونُوا يَرُشُّونَ شَيْئًا مِنْ ذَلِكَ","id":"Telah menceritakan kepada kami [Ishaq] telah mengabarkan kepada kami ['Abdush Shamad] telah menceritakan kepada kami ['Abdurrahman bin 'Abdullah bin Dinar] aku mendengar [Bapakku] dari [Abu Shalih] dari [Abu Hurairah] dari Nabi shallallahu 'alaihi wasallam, bahwa ada seorang laki-laki melihat seekor anjing menjilat-jilat tanah karena kehausan, lalu orang itu mengambil sepatunya dan mengisinya air untuk kemudian diminumkan kepada anjing tersebut hingga kenyang. Allah lalu berterima kasih kepadanya dan memasukkannya ke dalam surga.\" [Ahmad bin Syabib] berkata, telah menceritakan kepada kami [Bapakku] dari [Yunus] dari [Ibnu Syihab] berkata, telah menceritakan kepadaku [Hamzah bin 'Abdullah] dari [Bapaknya], bahwa pada masa Rasulullah shallallahu 'alaihi wasallam ada beberapa anjing yang kencing dan membuang kotoran di dalam masjid, namun para sahabat tidak menyiramnya dengan sesuatu.\""},"169":{"ar":"حَدَّثَنَا حَفْصُ بْنُ عُمَرَ قَالَ حَدَّثَنَا شُعْبَةُ عَنْ ابْنِ أَبِي السَّفَرِ عَنْ الشَّعْبِيِّ عَنْ عَدِيِّ بْنِ حَاتِمٍ قَالَسَأَلْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ إِذَا أَرْسَلْتَ كَلْبَكَ الْمُعَلَّمَ فَقَتَلَ فَكُلْ وَإِذَا أَكَلَ فَلَا تَأْكُلْ فَإِنَّمَا أَمْسَكَهُ عَلَى نَفْسِهِ قُلْتُ أُرْسِلُ كَلْبِي فَأَجِدُ مَعَهُ كَلْبًا آخَرَ قَالَ فَلَا تَأْكُلْ فَإِنَّمَا سَمَّيْتَ عَلَى كَلْبِكَ وَلَمْ تُسَمِّ عَلَى كَلْبٍ آخَرَ","id":"Telah menceritakan kepada kami [Hafsh bin 'Umar] berkata, telah menceritakan kepada kami [Syu'bah] dari [Ibnu Abu As Safar] dari [Asy Sya'bi] dari ['Adi bin Hatim] berkata, \"Aku bertanya kepada Nabi shallallahu 'alaihi wasallam, beliau lalu menjawab: \"Jika kamu melepas anjing buruanmu yang telah terlatih lalu ia mendapatkan hasil buruan, maka makanlah hasil buruannya. Jika anjing itu memakannya maka kamu jangan memakannya, sebab ia menangkap untuk dirinya sendiri.\" Aku lalu bertanya lagi, \"Aku melepas anjing buruanku, lalu aku mendapati anjinglain bersama dengan anjingku?\" Beliau menjawab: \"Jangan kamu makan, karena kamu membaca basmalah untuk anjingmu dan tidak untuk anjing yang lain.\""},"170":{"ar":"حَدَّثَنَا آدَمُ بْنُ أَبِي إِيَاسٍ قَالَ حَدَّثَنَا ابْنُ أَبِي ذِئْبٍ حَدَّثَنَا سَعِيدٌ الْمَقْبُرِيُّ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا يَزَالُ الْعَبْدُ فِي صَلَاةٍ مَا كَانَ فِي الْمَسْجِدِ يَنْتَظِرُ الصَّلَاةَ مَا لَمْ يُحْدِثْ فَقَالَ رَجُلٌ أَعْجَمِيٌّ مَا الْحَدَثُ يَا أَبَا هُرَيْرَةَ قَالَ الصَّوْتُ يَعْنِي الضَّرْطَةَ","id":"Telah menceritakan kepada kami [Adam bin Abu Iyas] berkata, telah menceritakan kepada kami [Ibnu Abu Dzi'b] telah menceritakan kepada kami [Sa'id Al Maqburi] dari [Abu Hurairah] berkata, \"Nabi shallallahu 'alaihi wasallam bersabda: \"Seorang hamba akan selalu dihitung shalat selama ia di masjid menunggu shalat dan tidak berhadats.\" Lalu ada seorang laki-laki non-Arab berkata, \"Apa yang dimaksud dengan hadats wahai Abu Hurairah?\" Abu Hurairah menjawab, \"Suara.\" Yaitu kentut."},"171":{"ar":"حَدَّثَنَا أَبُو الْوَلِيدِ قَالَ حَدَّثَنَا سُفْيَانُ بْنُ عُيَيْنَةَ عَنْ الزُّهْرِيِّ عَنْ عَبَّادِ بْنِ تَمِيمٍ عَنْ عَمِّهِعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا يَنْصَرِفْ حَتَّى يَسْمَعَ صَوْتًا أَوْ يَجِدَ رِيحًا","id":"Telah menceritakan kepada kami [Abu Al Walid] berkata, telah menceritakan kepada kami [Sufyan bin 'Uyainah] dari [Az Zuhri] dari ['Abbad bin Tamim] dari [Pamannya] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Janganlah kamu pergi hingga engkau mendengar suara atau mencium bau.\""},"172":{"ar":"حَدَّثَنَا قُتَيْبَةُ بْنُ سَعِيدٍ قَالَ حَدَّثَنَا جَرِيرٌ عَنْ الْأَعْمَشِ عَنْ مُنْذِرٍ أَبِي يَعْلَى الْثَّوْرِيِّ عَنْ مُحَمَّدِ بْنِ الْحَنَفِيَّةِ قَالَ قَالَ عَلِيٌّكُنْتُ رَجُلًا مَذَّاءً فَاسْتَحْيَيْتُ أَنْ أَسْأَلَ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَمَرْتُ الْمِقْدَادَ بْنَ الْأَسْوَدِ فَسَأَلَهُ فَقَالَ فِيهِ الْوُضُوءُوَرَوَاهُ شُعْبَةُ عَنْ الْأَعْمَشِ","id":"Telah menceritakan kepada kami [Qutaibah bin Sa'id] berkata, telah menceritakan kepada kami [Jarir] dari [Al A'masy] dari [Mundzir Abu Ya'la Ats Tsauri] dari [Muhammad bin Al Hanafiyah] ia berkata, [Ali] berkata, \"Aku adalah seorang laki-laki yang mudah mengeluarkan madzi, karena malu untuk bertanya kepada Rasulullah shallallahu 'alaihi wasallam, maka aku suruh Miqdad bin Al Aswad untuk bertanya. Lalu ia pun bertanya, beliau kemudian menjawab: \"Cukup baginya berwudlu.\" [Syu'bah] juga meriwayatkan dari [Al A'masy].\""},"173":{"ar":"حَدَّثَنَا سَعْدُ بْنُ حَفْصٍ حَدَّثَنَا شَيْبَانُ عَنْ يَحْيَى عَنْ أَبِي سَلَمَةَ أَنَّ عَطَاءَ بْنَ يَسَارٍ أَخْبَرَهُ أَنَّ زَيْدَ بْنَ خَالِدٍ أَخْبَرَهُ أَنَّهُ سَأَلَ عُثْمَانَ بْنَ عَفَّانَ رَضِيَ اللَّهُ عَنْهُقُلْتُ أَرَأَيْتَ إِذَا جَامَعَ فَلَمْ يُمْنِ قَالَ عُثْمَانُ يَتَوَضَّأُ كَمَا يَتَوَضَّأُ لِلصَّلَاةِ وَيَغْسِلُ ذَكَرَهُ قَالَ عُثْمَانُ سَمِعْتُهُ مِنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَسَأَلْتُ عَنْ ذَلِكَ عَلِيًّا وَالزُّبَيْرَ وَطَلْحَةَ وَأُبَيَّ بْنَ كَعْبٍ رَضِيَ اللَّهُ عَنْهُمْ فَأَمَرُوهُ بِذَلِكَ","id":"Telah menceritakan kepada kami [Sa'd bin Hafsh] telah menceritakan kepada kami [Syaiban] dari [Yahya] dari [Abu Salamah] bahwa ['Atha bin Yasar] mengabarkan kepadanya, bahwa [Zaid bin Khalid] mengabarkan kepadanya, bahwa ia pernah bertanya ['Utsman bin 'Affan] radliallahu 'anhu, Aku bertanya, \"Apa pendapatmu jika seorang laki-laki berhubungan badan dengan isterinya namun tidak keluar air mani?\" 'Utsman menjawab, \"Hendaknya ia berwudlu seperti wudlunya untuk shalat, lalu membasuh kemaluannya.\" Utsman melanjutkan, \"Aku mendengarnya dari Rasulullah shallallahu 'alaihi wasallam, aku menanyakan hal itu kepada 'Ali, Zubair, Thalhah, dan Ubay bin Ka'b? radliallahu 'anhum. Mereka semua menyuruh untuk melakukannya.\""},"174":{"ar":"حَدَّثَنَا إِسْحَاقُ قَالَ أَخْبَرَنَا النَّضْرُ قَالَ أَخْبَرَنَا شُعْبَةُ عَنْ الْحَكَمِ عَنْ ذَكْوَانَ أَبِي صَالِحٍ عَنْ أَبِي سَعِيدٍ الْخُدْرِيِّأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَرْسَلَ إِلَى رَجُلٍ مِنْ الْأَنْصَارِ فَجَاءَ وَرَأْسُهُ يَقْطُرُ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَعَلَّنَا أَعْجَلْنَاكَ فَقَالَ نَعَمْ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا أُعْجِلْتَ أَوْ قُحِطْتَ فَعَلَيْكَ الْوُضُوءُتَابَعَهُ وَهْبٌ قَالَ حَدَّثَنَا شُعْبَةُ قَالَ أَبُو عَبْد اللَّهِ وَلَمْ يَقُلْ غُنْدَرٌ وَيَحْيَى عَنْ شُعْبَةَ الْوُضُوءُ","id":"Telah menceritakan kepada kami [Ishaq] berkata, telah mengabarkan kepada kami [An Nadlr] berkata, telah mengabarkan kepada kami [Syu'bah] dari [Al Hakam] dari [Dzakwan Abu Shalih] dari [Abu Sa'id Al Khudri], bahwa Rasulullah shallallahu 'alaihi wasallam mengirim seorang utusan kepada seorang laki-laki Anshar. Maka laki-laki Anshar itu pun datang sementara kepalanya basah. Lalu Nabi shallallahu 'alaihi wasallam bertanya: \"Sepertinya kami telah membuat kamu tergesa-gesa?\" Laki-laki Anshar itu menjawab, \"Benar.\" Rasulullah shallallahu 'alaihi wasallam lalu bersabda: \"Jika kamu dibuat tergesa-gesa atau tertahan (tidak mengeluarkan mani), maka cukup bagimu berwudlu.\" Hadits ini dikuatkan juga oleh [Wahhab] ia berkata, telah menceritakan kepada kami [Syu'bah]. Abu 'Abdullah berkata, riwayat [Ghundar] dan [Yahya] dari [Syu'bah] tidak menyebutkan 'wudlu'.\""},"175":{"ar":"حَدَّثَنِي مُحَمَّدُ ��ْنُ سَلَامٍ قَالَ أَخْبَرَنَا يَزِيدُ بْنُ هَارُونَ عَنْ يَحْيَى عَنْ مُوسَى بْنِ عُقْبَةَ عَنْ كُرَيْبٍ مَوْلَى ابْنِ عَبَّاسٍ عَنْ أُسَامَةَ بْنِ زَيْدٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَمَّا أَفَاضَ مِنْ عَرَفةَ عَدَلَ إِلَى الشِّعْبِ فَقَضَى حَاجَتَهُ قَالَ أُسَامَةُ بْنُ زَيْدٍ فَجَعَلْتُ أَصُبُّ عَلَيْهِ وَيَتَوَضَّأُ فَقُلْتُ يَا رَسُولَ اللَّهِ أَتُصَلِّي فَقَالَ الْمُصَلَّى أَمَامَكَ","id":"Telah menceritakan kepadaku [Muhammad bin Salam] berkata, telah mengabarkan kepada kami [Yazid bin Harun] dari [Yahya] dari [Musa bin 'Uqbah] dari [Kuraib] mantan budak Ibnu 'Abbas, dari [Usamah bin Zaid], bahwa ketika Rasulullah shallallahu 'alaihi wasallam bertolak meninggalkan 'Arafah beliau menuju bukit dan menunaikan hajatnya.\" Usamah bin Zaid berkata, \"Aku lalu menuangkan air untuknya hingga beliau pun berwudlu. aku lalu berkata, \"Wahai Rasulullah, apakah kita akan shalat di sini?\" Beliau menjawab: \"Tempat shalat ada di depanmu.\""},"176":{"ar":"حَدَّثَنَا عَمْرُو بْنُ عَلِيٍّ قَالَ حَدَّثَنَا عَبْدُ الْوَهَّابِ قَالَ سَمِعْتُ يَحْيَى بْنَ سَعِيدٍ قَالَ أَخْبَرَنِي سَعْدُ بْنُ إِبْرَاهِيمَ أَنَّ نَافِعَ بْنَ جُبَيْرِ بْنِ مُطْعِمٍ أَخْبَرَهُ أَنَّهُ سَمِعَ عُرْوَةَ بْنَ الْمُغِيرَةِ بْنِ شُعْبَةَ يُحَدِّثُ عَنْ الْمُغِيرَةِ بْنِ شُعْبَةَأَنَّهُ كَانَ مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي سَفَرٍ وَأَنَّهُ ذَهَبَ لِحَاجَةٍ لَهُ وَأَنَّ مُغِيرَةَ جَعَلَ يَصُبُّ الْمَاءَ عَلَيْهِ وَهُوَ يَتَوَضَّأُ فَغَسَلَ وَجْهَهُ وَيَدَيْهِ وَمَسَحَ بِرَأْسِهِ وَمَسَحَ عَلَى الْخُفَّيْنِ","id":"Telah menceritakan kepada kami ['Amru bin 'Ali] berkata, telah menceritakan kepada kami ['Abdul Wahhab] berkata, aku mendengar [Yahya bin Sa'id] berkata, telah mengabarkan kepadaku [Sa'd bin Ibrahim] bahwa [Nafi' bin Jubair bin Muth'im] mengabarkan kepadanya, bahwa dia mendengar ['Urwah bin Al Mughirah bin Syu'bah] menceritakan dari [Al Mughirah bin Syu'bah], bahwa dia pernah bersama Rasulullah shallallahu 'alaihi wasallam dalam suatu perjalanan. Beliau lalu pergi untuk buang hajat, sementara Al Mughirah menuangkan air untuk beliau hingga beliau pun berwudlu, membasuh muka, mengusap kepala dan sepasang sepatunya.\""},"177":{"ar":"حَدَّثَنَا إِسْمَاعِيلُ قَالَ حَدَّثَنِي مَالِكٌ عَنْ مَخْرَمَةَ بْنِ سُلَيْمَانَ عَنْ كُرَيْبٍ مَوْلَى ابْنِ عَبَّاسٍ أَنَّ عَبْدَ اللَّهِ بْنَ عَبَّاسٍ أَخْبَرَهُأَنَّهُ بَاتَ لَيْلَةً عِنْدَ مَيْمُونَةَ زَوْجِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَهِيَ خَالَتُهُ فَاضْطَجَعْتُ فِي عَرْضِ الْوِسَادَةِ وَاضْطَجَعَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَأَهْلُهُ فِي طُولِهَا فَنَامَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حَتَّى إِذَا انْتَصَفَ اللَّيْلُ أَوْ قَبْلَهُ بِقَلِيلٍ أَوْ بَعْدَهُ بِقَلِيلٍ اسْتَيْقَظَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَجَلَسَ يَمْسَحُ النَّوْمَ عَنْ وَجْهِهِ بِيَدِهِ ثُمَّ قَرَأَ الْعَشْرَ الْآيَاتِ الْخَوَاتِمَ مِنْ سُورَةِ آلِ عِمْرَانَ ثُمَّ قَامَ إِلَى شَنٍّ مُعَلَّقَةٍ فَتَوَضَّأَ مِنْهَا فَأَحْسَنَ وُضُوءَهُ ثُمَّ قَامَ يُصَلِّي قَالَ ابْنُ عَبَّاسٍ فَقُمْتُ فَصَنَعْتُ مِثْلَ مَا صَنَعَ ثُمَّ ذَهَبْتُ فَقُمْتُ إِلَى جَنْبِهِ فَوَضَعَ يَدَهُ الْيُمْنَى عَلَى رَأْسِي وَأَخَذَ بِأُذُنِي الْيُمْنَى يَفْتِلُهَا فَصَلَّى رَكْعَتَيْنِ ثُمَّ رَكْعَتَيْنِ ثُمَّ رَكْعَتَيْنِ ثُمَّ رَكْعَتَيْنِ ثُمَّ رَكْعَتَيْنِ ثُمَّ رَكْعَتَيْنِ ثُمَّ أَوْتَرَ ثُمَّ اضْطَجَعَ حَتَّى أَتَاهُ الْمُؤَذِّنُ فَقَامَ فَصَلَّى رَكْعَتَيْنِ خَفِيفَتَيْنِ ثُمَّ خَرَجَ فَصَلَّى الصُّبْحَ","id":"Telah menceritakan kepada kami [Isma'il] berkata, telah menceritakan kepadaku [Malik] dari [Makhramah bin Sulaiman] dari [Kuraib] mantan budak Ibnu 'Abbas, bahwa ['Abdullah bin 'Abbas] mengabarkan kepadanya, bahwa ia pada suatu malam pernah bermalam di rumah Maimunah, isteri Nabi shallallahu 'alaihi wasallam, dan bibinya dari pihak ibu. Katanya, \"Aku berbaring di sisi bantal sementara Nabi shallallahu 'alaihi wasallam dan isterinya berbaring pada bagian panjang (tengahnya). Rasulullah shallallahu 'alaihi wasallam lalu tidur hingga pada tengah malam, atau kurang sedikit, atau lewat sedikit, beliau bangun dan duduk sambil mengusap sisa-sisa kantuk yang ada di wajahnya dengan tangan. Beliau kemudian membaca sepuluh ayat terakhir dari Surah Ali 'Imran. Kemudian berdiri menuju tempat wudlu, beliau lalu berwudlu dengan memperbagus wudlunya, lalu shalat.\" Ibnu 'Abbas berkata, \"Maka akupun ikut dan melakukan sebagaimana yang beliau lakukan, aku lalu berdiri di sampingnya. Beliau kemudian meletakkan tangan kanannya di kepalaku seraya memegang telingaku hingga menggeserku ke sebelah kanannya. Kemudian beliau shalat dua rakaat, kemudian dua rakaat, kemudian dua rakaat, kemudian dua rakaat, kemudian witir. Setelah itu beliau tidur berbaring hingga tukang adzan mendatanginya, beliau lalu berdiri dan shalat dua rakaat ringan, kemudian keluar untuk menunaikan shalat Subuh.\""},"178":{"ar":"حَدَّثَنَا إِسْمَاعِيلُ قَالَ حَدَّثَنِي مَالِكٌ عَنْ هِشَامِ بْنِ عُرْوَةَ عَنْ امْرَأَتِهِ فَاطِمَةَ عَنْ جَدَّتِهَا أَسْمَاءَ بِنْتِ أَبِي بَكْرٍ أَنَّهَا قَالَتْأَتَيْتُ عَائِشَةَ زَوْجَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حِينَ خَسَفَتْ الشَّمْسُ فَإِذَا النَّاسُ قِيَامٌ يُصَلُّونَ وَإِذَا هِيَ قَائِمَةٌ تُصَلِّي فَقُلْتُ مَا لِلنَّاسِ فَأَشَارَتْ بِيَدِهَا نَحْوَ السَّمَاءِ وَقَالَتْ سُبْحَانَ اللَّهِ فَقُلْتُ آيَةٌ فَأَشَارَتْ أَيْ نَعَمْ فَقُمْتُ حَتَّى تَجَلَّانِي الْغَشْيُ وَجَعَلْتُ أَصُبُّ فَوْقَ رَأْسِي مَاءً فَلَمَّا انْصَرَفَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حَمِدَ اللَّهَ وَأَثْنَى عَلَيْهِ ثُمَّ قَالَ مَا مِنْ شَيْءٍ كُنْتُ لَمْ أَرَهُ إِلَّا قَدْ رَأَيْتُهُ فِي مَقَامِي هَذَا حَتَّى الْجَنَّةَ وَالنَّارَ وَلَقَدْ أُوحِيَ إِلَيَّ أَنَّكُمْ تُفْتَنُونَ فِي الْقُبُورِ مِثْلَ أَوْ قَرِيبَ مِنْ فِتْنَةِ الدَّجَّالِ لَا أَدْرِي أَيَّ ذَلِكَ قَالَتْ أَسْمَاءُ يُؤْتَى أَحَدُكُمْ فَيُقَالُ لَهُ مَا عِلْمُكَ بِهَذَا الرَّجُلِ فَأَمَّا الْمُؤْمِنُ أَوْ الْمُوقِنُ لَا أَدْرِي أَيَّ ذَلِكَ قَالَتْ أَسْمَاءُ فَيَقُولُ هُوَ مُحَمَّدٌ رَسُولُ اللَّهِ جَاءَنَا بِالْبَيِّنَاتِ وَالْهُدَى فَأَجَبْنَا وَآمَنَّا وَاتَّبَعْنَا فَيُقَالُ لَهُ نَمْ صَالِحًا فَقَدْ عَلِمْنَا إِنْ كُنْتَ لَمُؤْمِنًا وَأَمَّا الْمُنَافِقُ أَوْ الْمُرْتَابُ لَا أَدْرِي أَيَّ ذَلِكَ قَالَتْ أَسْمَاءُ فَيَقُولُ لَا أَدْرِي سَمِعْتُ النَّاسَ يَقُولُونَ شَيْئًا فَقُلْتُهُ","id":"Telah menceritakan kepada kami [Isma'il] berkata, telah menceritakan kepadaku [Malik] dari [Hisyam bin 'Urwah] dari isterinya [Fatimah] dari neneknya [Asma` binti Abu Bakar] bahwa ia berkata, \"Aku pernah menemui 'Aisyah, isteri Nabi shallallahu 'alaihi wasallam, ketika terjadi gerhana matahari. Saat itu orang-orang sedang melaksanakan shalat dan saat itu iapun berdiri shalat. Setelah itu aku katakan kepadanya, \"Apa yang dilakukan orang-orang?\" Aisyah lalu memberi isyarat dengan tangannya ke arah langit seraya berkata, \"Maha suci Allah.\" Aku lalu berkata, \"Satu tanda kekuasaan Allah.\" Lalu dia mengiyakan dengan memberi isyarat. Maka akupun ikut shalat sementara timbul perkara yang membingungkanku, hingga aku siram kepalaku dengan air. Selesai shalat Rasulullah shallallahu 'alaihi wasallam mengucapkan puja dan puji kepada Allah, kemudian beliau bersabda: \"Tidak ada sesuatu yang belum diperlihatkan kepadaku, kecuali aku sudah melihatnya dari tempatku ini hingga surga dan neraka. Dan telah diwahyukan kepadaku bahwa kalian akan terkena fitnah dalam qubur kalian seperti, atau hampir serupa dengan fitnah Dajjal yang aku sendiri tidak tahu fitnah apakah itu.\" Asma` berkata, \"Setiap salah seorang dari kalian akan didatangkan (dalam sidang), lalu dikatakan kepadanya, 'Apa yang kamu ketahui tentang laki-laki ini (Rasulullah)? ' Adapun orang beriman atau orang yang yakin -aku tidak tahu mana yang Asma' ucapkan-, lalu orang tersebut akan menjawab, 'Dia adalah Muhammad utusan Allah. Ia datang kepada kami membawa penjelasan dan petunjuk. Kami lalu menyambutnya, beriman dan mengikuti seruannya.' Maka kepada orang itu dikatakan, 'Tidurlah kamu dengan baik, sungguh kami telah mengetahui bahwa kamu adalah orang beriman.' Adapun Munafik atau pelaku dosa besar -Aku tidak tahu mana yang diucapkan Asma'- akan menjawab, 'Aku tidak tahu siapa dia, aku mendengar orang-orang mengatakan sesuatu maka aku pun mengikuti ucapan tersebut'.\""},"179":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ يُوسُفَ قَالَ أَخْبَرَنَا مَالِكٌ عَنْ عَمْرِو بْنِ يَحْيَى الْمَازِنِيِّ عَنْ أَبِيهِ أَنَّ رَجُلًا قَالَ لِعَبْدِ اللَّهِ بْنِ زَيْدٍ وَهُوَ جَدُّ عَمْرِو بْنِ يَحْيَىأَتَسْتَطِيعُ أَنْ تُرِيَنِي كَيْفَ كَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَتَوَضَّأُ فَقَالَ عَبْدُ اللَّهِ بْنُ زَيْدٍ نَعَمْ فَدَعَا بِمَاءٍ فَأَفْرَغَ عَلَى يَدَيْهِ فَغَسَلَ مَرَّتَيْنِ ثُمَّ مَضْمَضَ وَاسْتَنْثَرَ ثَلَاثًا ثُمَّ غَسَلَ وَجْهَهُ ثَلَاثًا ثُمَّ غَسَلَ يَدَيْهِ مَرَّتَيْنِ مَرَّتَيْنِ إِلَى الْمِرْفَقَيْنِ ثُمَّ مَسَحَ رَأْسَهُ بِيَدَيْهِ فَأَقْبَلَ بِهِمَا وَأَدْبَرَ بَدَأَ بِمُقَدَّمِ رَأْسِهِ حَتَّى ذَهَبَ بِهِمَا إِلَى قَفَاهُ ثُمَّ رَدَّهُمَا إِلَى الْمَكَانِ الَّذِي بَدَأَ مِنْهُ ثُمَّ غَسَلَ رِجْلَيْهِ","id":"Telah menceritakan kepada kami ['Abdullah bin Yusuf] berkata, telah mengabarkan kepada kami [Malik] dari ['Amru bin Yahya Al Mazini] dari [Bapaknya] bahwa ada seorang laki-laki berkata kepada ['Abdullah bin Zaid] -dia adalah kakek 'Amru bin Yahya-, \"Bisakah engkau perlihatkan kepadaku bagaimana Rasulullah shallallahu 'alaihi wasallam berwudlu?\" 'Abdullah bin Zaid lalu menjawab, \"Tentu.\" Abdullah lalu minta diambilkan air wudlu, lalu ia menuangkan air pada kedua tangannya dan membasuhnya dua kali, lalu berkumur dan mengeluarkan air dari dalam hidung sebanyak kali, kemudian membasuh mukanya tiga kali, kemudian membasuh kedua tangan dua kali dua kali sampai ke siku, kemudian mengusap kepalanya dengan tangan, dimulai dari bagian depan dan menariknya hingga sampai pada bagian tengkuk, lalu menariknya kembali ke tempat semula. Setelah itu membasuh kedua kakinya.\""},"180":{"ar":"حَدَّثَنَا مُوسَى قَالَ حَدَّثَنَا وُهَيْبٌ عَنْ عَمْرٍو عَنْ أَبِيهِشَهِدْتُ عَمْرَو بْنَ أَبِي حَسَنٍ سَأَلَ عَبْدَ اللَّهِ بْنَ زَيْدٍ عَنْ وُضُوءِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَدَعَا بِتَوْرٍ مِنْ مَاءٍ فَتَوَضَّأَ لَهُمْ وُضُوءَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَكْفَأَ عَلَى يَدِهِ مِنْ التَّوْرِ فَغَسَلَ يَدَيْهِ ثَلَاثًا ثُمَّ أَدْخَلَ يَدَهُ فِي التَّوْرِ فَمَضْمَضَ وَاسْتَنْشَقَ وَاسْتَنْثَرَ ثَلَاثَ غَرَفَاتٍ ثُمَّ أَدْخَلَ يَدَهُ فَغَسَلَ وَجْهَهُ ثَلَاثًا ثُمَّ غَسَلَ يَدَيْهِ مَرَّتَيْنِ إِلَى الْمِرْفَقَيْنِ ثُمَّ أَدْخَلَ يَدَهُ فَمَسَحَ رَأْسَهُ فَأَقْبَلَ بِهِمَا وَأَدْبَرَ مَرَّةً وَاحِدَةً ثُمَّ غَسَلَ رِجْلَيْهِ إِلَى الْكَعْبَيْنِ","id":"Telah menceritakan kepada kami [Musa] berkata, telah menceritakan kepada kami [Wuhhaib] dari ['Amru] dari [Bapaknya] berkata, \"Aku pernah menyaksikan 'Amru bin Abu Hasan bertanya kepada ['Abdullah bin Zaid] tentang wudlunya Nabi shallallahu 'alaihi wasallam. Lalu ia minta diambilkan satu gayung air, kemudian ia memperlihatkan kepada mereka cara wudlu Nabi shallallahu 'alaihi wasallam. Ia menuangkan air dari gayung ke telapak tangannya lalu mencucinya tiga kali, kemudian memasukkan tangannya ke dalam gayung, lalu berkumur-kumur, lalu memasukkan air ke hidung lalu mengeluarkannya kembali dengan tiga kali cidukan, kemudian memasukkan tangannya ke dalam gayung, lalu membasuh mukanya tiga kali, kemudian membasuh kedua tangannya dua kali sampai ke siku. Kemudian memasukkan tangannya ke dalam gayung, lalu mengusap kepalanya dengan tangan; mulai dari bagian depan ke belakang dan menariknya kembali sebanyak satu kali, lalu membasuh kedua kakinya hingga mata kaki.\""},"181":{"ar":"حَدَّثَنَا آدَمُ قَالَ حَدَّثَنَا شُعْبَةُ قَالَ حَدَّثَنَا الْحَكَمُ قَالَ سَمِعْتُ أَبَا جُحَيْفَةَ يَقُولُخَرَجَ عَلَيْنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِالْهَاجِرَةِ فَأُتِيَ بِوَضُوءٍ فَتَوَضَّأَ فَجَعَلَ النَّاسُ يَأْخُذُونَ مِنْ فَضْلِ وَضُوئِهِ فَيَتَمَسَّحُونَ بِهِ فَصَلَّى النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الظُّهْرَ رَكْعَتَيْنِ وَالْعَصْرَ رَكْعَتَيْنِ وَبَيْنَ يَدَيْهِ عَنَزَةٌوَقَالَ أَبُو مُوسَى دَعَا النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِقَدَحٍ فِيهِ مَاءٌ فَغَسَلَ يَدَيْهِ وَوَجْهَهُ فِيهِ وَمَجَّ فِيهِ ثُمَّ قَالَ لَهُمَا اشْرَبَا مِنْهُ وَأَفْرِغَا عَلَى وُجُوهِكُمَا وَنُحُورِكُمَا","id":"Telah menceritakan kepada kami [Adam] berkata, telah menceritakan kepada kami [Syu'bah] berkata, telah menceritakan kepada kami [Al Hakam] berkata, aku pernah mendengar [Abu Juhaifah] berkata, \"Rasulullah shallallahu 'alaihi wasallam pernah keluar mendatangi kami di waktu tengah hari yang panas. Beliau lalu diberi air wudlu hingga beliau pun berwudlu, orang-orang lalu mengambil sisa air wudlu beliau seraya mengusap-ngusapkannya. Kemudian Nabi shallallahu 'alaihi wasallam shalat zhuhur dua rakaat dan 'ashar dua rakaat sedang di depannya diletakkan tombak kecil.\" Abu Musa berkata, \"Nabi shallallahu 'alaihi wasallam meminta bejana berisi air, beliau lalu membasuh kedua tangan dan mukanya di dalamnya, lalu menyentuh air untuk memberkahinya seraya berkata kepada keduanya (Abu Musa dan Bilal): \"Minumlah darinya dan usapkanlah pada wajah dan leher kalian berdua.\""},"182":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ عَبْدِ اللَّهِ قَالَ حَدَّثَنَا يَعْقُوبُ بْنُ إِبْرَاهِيمَ بْنِ سَعْدٍ قَالَ حَدَّثَنَا أَبِي عَنْ صَالِحٍ عَنْ ابْنِ شِهَابٍ قَالَ أَخْبَرَنِي مَحْمُودُ بْنُ الرَّبِيعِ قَالَوَهُوَ الَّذِي مَجَّ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي وَجْهِهِ وَهُوَ غُلَامٌ مِنْ بِئْرِهِمْوَقَالَ عُرْوَةُ عَنْ الْمِسْوَرِ وَغَيْرِهِ يُصَدِّقُ كُلُّ وَاحِدٍ مِنْهُمَا صَاحِبَهُ وَإِذَا تَوَضَّأَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَادُوا يَقْتَتِلُونَ عَلَى وَضُوئِهِ","id":"Telah menceritakan kepada kami ['Ali bin 'Abdullah] berkata, telah menceritakan kepada kami [Ya'qub bin Ibrahim bin Sa'd] berkata, telah menceritakan kepada kami [Bapakku] dari [Shalih] dari [Ibnu Syihab] berkata, [Mahmud bin Ar Rabi'] mengabarkan kepadaku, ia berkata, \"Dialah orang yang diberkahi oleh Rasulullah shallallahu 'alaihi wasallam di wajahnya saat dia masih kecil dari sumur mereka.\" Dan 'Urwah menyebutkan dari Al Miswar, dan Selainnya -setiap dari keduanya saling membenarkan satu sama lain-, bahwa ketika Nabi shallallahu 'alaihi wasallam berwudlu, hampir saja mereka berkelahi memperebutkan bejana bekas wudlu beliau.\""},"183":{"ar":"بَاب حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ يُونُسَ قَالَ حَدَّثَنَا حَاتِمُ بْنُ إِسْمَاعِيلَ عَنْ الْجَعْدِ قَالَ سَمِعْتُ السَّائِبَ بْنَ يَزِيدَ يَقُولُذَهَبَتْ بِي خَالَتِي إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَتْ يَا رَسُولَ اللَّهِ إِنَّ ابْنَ أُخْتِي وَجِعٌ فَمَسَحَ رَأْسِي وَدَعَا لِي بِالْبَرَكَةِ ثُمَّ تَوَضَّأَ فَشَرِبْتُ مِنْ وَضُوئِهِ ثُمَّ قُمْتُ خَلْفَ ظَهْرِهِ فَنَظَرْتُ إِلَى خَاتَمِ النُّبُوَّةِ بَيْنَ كَتِفَيْهِ مِثْلَ زِرِّ الْحَجَلَةِ","id":"Bab. Telah menceritakan kepada kami ['Abdurrahman bin Yunus] berkata, telah menceritakan kepada kami [Hatim bin Isma'il] dari [Al Ja'd] berkata, aku mendengar [As Sa'ib bin Yazid] berkata, \"Bibiku pergi bersamaku menemui Nabi shallallahu 'alaihi wasallam, lalu ia berkata, \"Wahai Rasulullah, sesungguhnya putra saudara perempuanku ini sedang sakit.\" Maka Nabi shallallahu 'alaihi wasallam mengusap kepalaku dan memohonkan keberkahan untukku. Kemudian beliau berwudlu, maka aku pun minum dari sisa air wudlunya, kemudian aku berdiri di belakangnya hingga aku melihat ada tanda kenabian sebesar telur burung di pundaknya.\""},"184":{"ar":"حَدَّثَنَا مُسَدَّدٌ قَالَ حَدَّثَنَا خَالِدُ بْنُ عَبْدِ اللَّهِ قَالَ حَدَّثَنَا عَمْرُو بْنُ يَحْيَى عَنْ أَبِيهِ عَنْ عَبْدِ اللَّهِ بْنِ زَيْدٍأَنَّهُ أَفْرَغَ مِنْ الْإِنَاءِ عَلَى يَدَيْهِ فَغَسَلَهُمَا ثُمَّ غَسَلَ أَوْ مَضْمَضَ وَاسْتَنْشَقَ مِنْ كَفَّةٍ وَاحِدَةٍ فَفَعَلَ ذَلِكَ ثَلَاثًا فَغَسَلَ يَدَيْهِ إِلَى الْمِرْفَقَيْنِ مَرَّتَيْنِ مَرَّتَيْنِ وَمَسَحَ بِرَأْسِهِ مَا أَقْبَلَ وَمَا أَدْبَرَ وَغَسَلَ رِجْلَيْهِ إِلَى الْكَعْبَيْنِ ثُمَّ قَالَ هَكَذَا وُضُوءُ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah menceritakan kepada kami [Musaddad] berkata, telah menceritakan kepada kami [Khalid bin 'Abdullah] telah menceritakan kepada kami ['Amru bin Yahya] dari [Bapaknya] dari ['Abdullah bin Zaid], bahwa ia menuangkan air dari gayung ke telapak tangannya lalu mencucinya, atau berkumur-kumur, lalu memasukkan air ke hidung dari satu cedukan telapak tangannya. Dia lakukan ini tiga kali. Kemudian membasuh kedua tangannya sampai ke siku dua kali dua kali. Kemudian mengusap kepalanya dengan tangan dan menariknya (ke belakang kepala) lalu mengembalikannya sekali, lalu membasuh kedua kakinya hingga ke mata kaki. Setelah itu ia berkata, \"Begitulah wudlunya Rasulullah shallallahu 'alaihi wasallam.\""},"185":{"ar":"حَدَّثَنَا سُلَيْمَانُ بْنُ حَرْبٍ قَالَ حَدَّثَنَا وُهَيْبٌ قَالَ حَدَّثَنَا عَمْرُو بْنُ يَحْيَى عَنْ أَبِيهِ قَالَشَهِدْتُ عَمْرَو بْنَ أَبِي حَسَنٍ سَأَلَ عَبْدَ اللَّهِ بْنَ زَيْدٍ عَنْ وُضُوءِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَدَعَا بِتَوْرٍ مِنْ مَاءٍ فَتَوَضَّأَ لَهُمْ فَكَفَأَ عَلَى يَدَيْهِ فَغَسَلَهُمَا ثَلَاثًا ثُمَّ أَدْخَلَ يَدَهُ فِي الْإِنَاءِ فَمَضْمَضَ وَاسْتَنْشَقَ وَاسْتَنْثَرَ ثَلَاثًا بِثَلَاثِ غَرَفَاتٍ مِنْ مَاءٍ ثُمَّ أَدْخَلَ يَدَهُ فِي الْإِنَاءِ فَغَسَلَ وَجْهَهُ ثَلَاثًا ثُمَّ أَدْخَلَ يَدَهُ فِي الْإِنَاءِ فَغَسَلَ يَدَيْهِ إِلَى الْمِرْفَقَيْنِ مَرَّتَيْنِ مَرَّتَيْنِ ثُمَّ أَدْخَلَ يَدَهُ فِي الْإِنَاءِ فَمَسَحَ بِرَأْسِهِ فَأَقْبَلَ بِيَدَيْهِ وَأَدْبَرَ بِهِمَا ثُمَّ أَدْخَلَ يَدَهُ فِي الْإِنَاءِ فَغَسَلَ رِجْلَيْهِو حَدَّثَنَا مُوسَى قَالَ حَدَّثَنَا وُهَيْبٌ قَالَ مَسَحَ رَأْسَهُ مَرَّةً","id":"Telah menceritakan kepada kami [Sulaiman bin Harb] berkata, telah menceritakan kepada kami [Wuhhaib] dari ['Amru bin Yahya] dari [Bapaknya] berkata; Aku pernah menyaksikan 'Amru bin Abu Hasan bertanya kepada ['Abdullah bin Zaid] tentang wudlunya Nabi shallallahu 'alaihi wasallam. Abdullah lalu minta diambilkan bejana berisi air, lalu ia memperlihatkan kepada mereka cara wudlu Nabi shallallahu 'alaihi wasallam. Lalu ia memulai dengan menuangkan air dari bejana ke telapak tangannya lalu mencucinya tiga kali. Kemudian memasukkan tangannya ke dalam bejana, lalu berkumur-kumur, lalu memasukkan air ke hidung dan mengeluarkannya kembali dengan tiga kali cidukan. Kemudian memasukkan tangannya ke dalam bejana dan membasuh mukanya tiga kali, kemudian memasukkan tangannya ke dalam bejana dan membasuh kedua tangannya sampai ke siku dua kali dua kali. Kemudian ia memasukkan tangannya ke dalam bejana dan mengusap kepalanya dengan tangan, ia mulai dari bagian depan ke belakang lalu mengembalikannya lagi (ke arah depan), kemudian memasukkan tangannya ke dalam bejana dan membasuh kedua kakinya.\" Dan telah menceritakan kepada kami [Musa] berkata, telah menceritakan kepada kami [Wuhaib] berkata, \"Ia mengusap kepalanya satu kali.\""},"186":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ يُوسُفَ قَالَ أَخْبَرَنَا مَالِكٌ عَنْ نَافِعٍ عَنْ عَبْدِ اللَّهِ بْنِ عُمَرَ أَنَّهُ قَالَكَانَ الرِّجَالُ وَالنِّسَاءُ يَتَوَضَّئُونَ فِي زَمَانِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ جَمِيعًا","id":"Telah menceritakan kepada kami ['Abdullah bin Yusuf] berkata, telah mengabarkan kepada kami [Malik] dari [Nafi'] dari ['Abdullah bin 'Umar], bahwa ia berkata, \"Pada masa Rasulullah shallallahu 'alaihi wasallam, laki-laki dan perempuan semuanya minta diajari berwudlu.\""},"187":{"ar":"حَدَّثَنَا أَبُو الْوَلِيدِ قَالَ حَدَّثَنَا شُعْبَةُ عَنْ مُحَمَّدِ بْنِ الْمُنْكَدِرِ قَالَ سَمِعْتُ جَابِرًا يَقُولُجَاءَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَعُودُنِي وَأَنَا مَرِيضٌ لَا أَعْقِلُ فَتَوَضَّأَ وَصَبَّ عَلَيَّ مِنْ وَضُوئِهِ فَعَقَلْتُ فَقُلْتُ يَا رَسُولَ اللَّهِ لِمَنْ الْمِيرَاثُ إِنَّمَا يَرِثُنِي كَلَالَةٌ فَنَزَلَتْ آيَةُ الْفَرَائِضِ","id":"Telah menceritakan kepada kami [Abu Al Walid] berkata, telah menceritakan kepada kami [Syu'bah] dari [Muhammad bin Al Munkadir] berkata, \"Aku mendengar [Jabir] berkata, \"Rasulullah shallallahu 'alaihi wasallam datang menjenguk saat aku sedang sakit yang mengakibatkan aku tidak sadar. Nabi shallallahu 'alaihi wasallam lalu berwudlu dan menyiramkan sisa air wudlunya hingga aku pun sadar. Aku lalu bertanya, 'Wahai Rasulullah, untuk siapakah warisan itu? Sebab aku tidak mewariskan kalalah (tidak punya anak)? ' maka turunlah ayat tentang waris.\""},"188":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مُنِيرٍ سَمِعَ عَبْدَ اللَّهِ بْنَ بَكْرٍ قَالَ حَدَّثَنَا حُمَيْدٌ عَنْ أَنَسٍ قَالَحَضَرَتْ الصَّلَاةُ فَقَامَ مَنْ كَانَ قَرِيبَ الدَّارِ إِلَى أَهْلِهِ وَبَقِيَ قَوْمٌ فَأُتِيَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِمِخْضَبٍ مِنْ حِجَارَةٍ فِيهِ مَاءٌ فَصَغُرَ الْمِخْضَبُ أَنْ يَبْسُطَ فِيهِ كَفَّهُ فَتَوَضَّأَ الْقَوْمُ كُلُّهُمْ قُلْنَا كَمْ كُنْتُمْ قَالَ ثَمَانِينَ وَزِيَادَةً","id":"Telah menceritakan kepada kami ['Abdullah bin Munir] mendengar ['Abdullah bin Bakar] berkata, telah menceritakan kepada kami [Humaid] dari [Anas] berkata, \"Waktu shalat telah masuk, bagi orang-orang yang rumahnya dekat mereka pulang untuk wudlu, sementara yang lain masih di dalam masjid. Lalu diberikan sebuah bejana kecil yang terbuat dari kayu kepada Rasulullah shallallahu 'alaihi wasallam. Namun bejana itu tidak cukup untuk dimasuki oleh telapak tangan beliau, hingga orang-orang pun berwudlu (dari jari tangan beliau) semua.\" Kami lalu bertanya, \"Berapa jumlah kalian saat itu?\" Anas menjawab, \"Lebih dari delapan puluh orang.\""},"189":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ الْعَلَاءِ قَالَ حَدَّثَنَا أَبُو أُسَامَةَ عَنْ بُرَيْدٍ عَنْ أَبِي بُرْدَةَ عَنْ أَبِي مُوسَىأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ دَعَا بِقَدَحٍ فِيهِ مَاءٌ فَغَسَلَ يَدَيْهِ وَوَجْهَهُ فِيهِ وَمَجَّ فِيهِ","id":"Telah menceritakan kepada kami [Muhammad bin Al 'Ala`] berkata, telah menceritakan kepada kami [Abu Usamah] dari [Buraid] dari [Abu Burdah] dari [Abu Musa], bahwa Nabi shallallahu 'alaihi wasallam minta diambilkan bejana berisi air, beliau lalu mencuci kedua tangan dan wajahnya dalam bejana tersebut dan mendoakan keberkahan.\""},"190":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ يُونُسَ قَالَ حَدَّثَنَا عَبْدُ الْعَزِيزِ بْنُ أَبِي سَلَمَةَ قَالَ حَدَّثَنَا عَمْرُو بْنُ يَحْيَى عَنْ أَبِيهِ عَنْ عَبْدِ اللَّهِ بْنِ زَيْدٍ قَالَأَتَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَخْرَجْنَا لَهُ مَاءً فِي تَوْرٍ مِنْ صُفْرٍ فَتَوَضَّأَ فَغَسَلَ وَجْهَهُ ثَلَاثًا وَيَدَيْهِ مَرَّتَيْنِ مَرَّتَيْنِ وَمَسَحَ بِرَأْسِهِ فَأَقْبَلَ بِهِ وَأَدْبَرَ وَغَسَلَ رِجْلَيْهِ","id":"Telah menceritakan kepada kami [Ahmad bin Yunus] berkata, telah menceritakan kepada kami ['Abdul 'Aziz bin Abu Salamah] berkata, telah menceritakan kepada kami ['Amru bin Yahya] dari [Bapaknya] dari ['Abdullah bin Zaid] berkata, \"Rasulullah shallallahu 'alaihi wasallam datang, lalu kami menyiapkan air dalam sebuah bejana yang terbuat dari tembaga. Beliau lalu berwudlu; membasuh muka tiga kali, lalu membasuh tangan dua kali dua kali, lalu mengusap kepalanya dimulai dari depan ke belakang dan menariknya kembali ke depan. Kemudian membasuh kedua kakinya.\""},"191":{"ar":"حَدَّثَنَا أَبُو الْيَمَانِ قَالَ أَخْبَرَنَا شُعَيْبٌ عَنْ الزُّهْرِيِّ قَالَ أَخْبَرَنِي عُبَيْدُ اللَّهِ بْنُ عَبْدِ اللَّهِ بْنِ عُتْبَةَ أَنَّ عَائِشَةَ قَالَتْلَمَّا ثَقُلَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَاشْتَدَّ بِهِ وَجَعُهُ اسْتَأْذَنَ أَزْوَاجَهُ فِي أَنْ يُمَرَّضَ فِي بَيْتِي فَأَذِنَّ لَهُ فَخَرَجَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بَيْنَ رَجُلَيْنِ تَخُطُّ رِجْلَاهُ فِي الْأَرْضِ بَيْنَ عَبَّاسٍ وَرَجُلٍ آخَرَقَالَ عُبَيْدُ اللَّهِ فَأَخْبَرْتُ عَبْدَ اللَّهِ بْنَ عَبَّاسٍ فَقَالَ أَتَدْرِي مَنْ الرَّجُلُ الْآخَرُ قُلْتُ لَا قَالَ هُوَ عَلِيُّ بْنُ أَبِي طَالِبٍ رَضِيَ اللَّهُ عَنْهُ وَكَانَتْ عَائِشَةُ رَضِيَ اللَّهُ عَنْهَا تُحَدِّثُ أَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ بَعْدَمَا دَخَلَ بَيْتَهُ وَاشْتَدَّ وَجَعُهُ هَرِيقُوا عَلَيَّ مِنْ سَبْعِ قِرَبٍ لَمْ تُحْلَلْ أَوْكِيَتُهُنَّ لَعَلِّي أَعْهَدُ إِلَى النَّاسِ وَأُجْلِسَ فِي مِخْضَبٍ لِحَفْصَةَ زَوْجِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ثُمَّ طَفِقْنَا نَصُبُّ عَلَيْهِ تِلْكَ حَتَّى طَفِقَ يُشِيرُ إِلَيْنَا أَنْ قَدْ فَعَلْتُنَّ ثُمَّ خَرَجَ إِلَى النَّاسِ","id":"Telah menceritakan kepada kami [Abu Al Yaman] berkata, telah mengabarkan kepada kami [Syu'aib] dari [Az Zuhri] berkata, telah mengabarkan kepadaku ['Ubaidullah bin 'Abdullah bin 'Utbah] bahwa ['Aisyah] berkata, \"Tatkala sakit Nabi shallallahu 'alaihi wasallam semakin berat, beliau minta izin kepada isteri-isterinya agar beliau dirawat di rumahku, lalu mereka pun mengizinkannya. Nabi shallallahu 'alaihi wasallam lalu keluar berjalan dengan dipapah oleh dua orang; 'Abbas dan seorang lagi.\" ['Ubaidullah] berkata, \"Aku lalu kabarkan hal itu kepada ['Abdullah bin 'Abbas], lalu dia berkata, \"Tahukah kamu, siapakah lelaki yang lain itu?\" Aku jawab, \"Tidak\". Dia lantas berkata, \"Orang itu adalah 'Ali bin Abu Thalib? radliallahu 'anhu.\" ['Aisyah] menceritakan bahwa ketika Nabi shallallahu 'alaihi wasallam sudah berada di rumahnya dan sakitnya makin berat, beliau mengatakan: \"Siramkan air kepadaku dari tujuh geriba yang belun dilepas ikatannya, sehingga aku dapat memberi pesan kepada orang-orang.\" Kemudian Nabi shallallahu 'alaihi wasallam didudukkan untuk mandi dengan ember milik Hafshah, isteri Nabi shallallahu 'alaihi wasallam. Maka kami segera menyiram beliau hingga beliau memberi isyarat sudah cukup. Setelah itu beliau keluar menemui orang-orang.\""},"192":{"ar":"حَدَّثَنَا خَالِدُ بْنُ مَخْلَدٍ قَالَ حَدَّثَنَا سُلَيْمَانُ بْنُ بِلَالٍ قَالَ حَدَّثَنِي عَمْرُو بْنُ يَحْيَى عَنْ أَبِيهِ قَالَكَانَ عَمِّي يُكْثِرُ مِنْ الْوُضُوءِ قَالَ لِعَبْدِ اللَّهِ بْنِ زَيْدٍ أَخْبِرْنِيا كَيْفَ رَأَيْتَ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَتَوَضَّأُ فَدَعَا بِتَوْرٍ مِنْ مَاءٍ فَكَفَأَ عَلَى يَدَيْهِ فَغَسَلَهُمَا ثَلَاثَ مِرَارٍ ثُمَّ أَدْخَلَ يَدَهُ فِي التَّوْرِ فَمَضْمَضَ وَاسْتَنْثَرَ ثَلَاثَ مَرَّاتٍ مِنْ غَرْفَةٍ وَاحِدَةٍ ثُمَّ أَدْخَلَ يَدَهُ فَاغْتَرَفَ بِهَا فَغَسَلَ وَجْهَهُ ثَلَاثَ مَرَّاتٍ ثُمَّ غَسَلَ يَدَيْهِ إِلَى الْمِرْفَقَيْنِ مَرَّتَيْنِ مَرَّتَيْنِ ثُمَّ أَخَذَ بِيَدِهِ مَاءً فَمَسَحَ رَأْسَهُ فَأَدْبَرَ بِهِ وَأَقْبَلَ ثُمَّ غَسَلَ رِجْلَيْهِ فَقَالَ هَكَذَا رَأَيْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَتَوَضَّأُ","id":"Telah menceritakan kepada kami [Khalid bin Mukhallad] berkata, telah menceritakan kepada kami [Sulaiman bin Bilal] berkata, telah menceritakan kepadaku ['Amru bin Yahya] dari [Bapaknya] berkata, \" Pamanku berlebihan dalam berwudlu, lalu ia berkata kepada ['Abdullah bin Zaid], \"Beritahu kami berdua bagaimana kamu melihat Nabi shallallahu 'alaihi wasallam wudlu. 'Abdullah bin Zaid minta bejana berisi air, lalu ia menuangkan ke telapak tangannya dan mencucinya tiga kali. Kemudian memasukkan tangannya ke dalam bejana tersebut, lalu berkumur dan mengeluarkan air dari dalam hidung sebanyak tiga kali dari satu cidukan tangan. Kemudian memasukkan tangannya ke dalam bejana menciduk air dan membasuh mukanya tiga kali. Kemudian membasuh tangannya sampai siku dua kali-dua kali. Kemudian mengambil air dengan tangannya dan mengusap kepalanya, ia tarik tangannya ke belakang kepala lalu dikembalikan ke depan. Kemudian membasuh kakinya. Setelah itu berkata, \"Begitulah aku melihat Nabi shallallahu 'alaihi wasallam berwudlu'.\" "},"193":{"ar":"حَدَّثَنَا مُسَدَّدٌ قَالَ حَدَّثَنَا حَمَّادٌ عَنْ ثَابِتٍ عَنْ أَنَسٍأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ دَعَا بِإِنَاءٍ مِنْ مَاءٍ فَأُتِيَ بِقَدَحٍ رَحْرَاحٍ فِيهِ شَيْءٌ مِنْ مَاءٍ فَوَضَعَ أَصَابِعَهُ فِيهِ قَالَ أَنَسٌ فَجَعَلْتُ أَنْظُرُ إِلَى الْمَاءِ يَنْبُعُ مِنْ بَيْنِ أَصَابِعِهِ قَالَ أَنَسٌ فَحَزَرْتُ مَنْ تَوَضَّأَ مَا بَيْنَ السَّبْعِينَ إِلَى الثَّمَانِينَ","id":"Telah menceritakan kepada kami [Musaddad] berkata, telah mengabarkan kepada kami [Hammad] dari [Tsabit] dari [Anas bin Malik], bahwa Nabi shallallahu 'alaihi wasallam minta untuk diambilkan bejana berisi air kepada orang-orang, maka diberikanlah satu bejana besar dan beliau meletakkan tangannya ke dalam bejana tersebut.\" Anas berkata, 'Aku sengaja memperhatikan air yang keluar dari selah-selah jari beliau.\" Anas melanjutkan, \"Aku menduga bahwa orang-orang yang berwudlu saat itu berjumlah antara tujuh puluh hingga delapan puluh orang.\""},"194":{"ar":"حَدَّثَنَا أَبُو نُعَيْمٍ قَالَ حَدَّثَنَا مِسْعَرٌ قَالَ حَدَّثَنِي ابْنُ جَبْرٍ قَالَ سَمِعْتُ أَنَسًا يَقُولُكَانَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَغْسِلُ أَوْ كَانَ يَغْتَسِلُ بِالصَّاعِ إِلَى خَمْسَةِ أَمْدَادٍ وَيَتَوَضَّأُ بِالْمُدِّ","id":"Telah menceritakan kepada kami [Abu Nu'aim] berkata, telah menceritakan kepada kami [Mis'ar] berkata, telah menceritakan kepadaku [Ibnu Jabar] berkata, \"Aku mendengar [Anas] berkata, \"Nabi shallallahu 'alaihi wasallam membasuh, atau mandi dengan satu sha' hingga lima mud, dan berwudlu dengan satu mud.\""},"195":{"ar":"حَدَّثَنَا أَصْبَغُ بْنُ الْفَرَجِ الْمِصْرِيُّ عَنْ ابْنِ وَهْبٍ قَالَ حَدَّثَنِي عَمْرُو بْنُ الْحَارِثِ حَدَّثَنِي أَبُو النَّضْرِ عَنْ أَبِي سَلَمَةَ بْنِ عَبْدِ الرَّحْمَنِ عَنْ عَبْدِ اللَّهِ بْنِ عُمَرَ عَنْ سَعْدِ بْنِ أَبِي وَقَّاصٍعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُ مَسَحَ عَلَى الْخُفَّيْنِوَأَنَّ عَبْدَ اللَّهِ بْنَ عُمَرَ سَأَلَ عُمَرَ عَنْ ذَلِكَ فَقَالَ نَعَمْ إِذَا حَدَّثَكَ شَيْئًا سَعْدٌ عَنْ النَّبِيّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَلَا تَسْأَلْ عَنْهُ غَيْرَهُ وَقَالَ مُوسَى بْنُ عُقْبَةَ أَخْبَرَنِي أَبُو النَّضْرِ أَنَّ أَبَا سَلَمَةَ أَخْبَرَهُ أَنَّ سَعْدًا حَدَّثَهُ فَقَالَ عُمَرُ لِعَبْدِ اللَّهِ نَحْوَهُ","id":"Telah menceritakan kepada kami [Ashbagh bin Al Faraj Al Mishri] dari [Ibnu Wahhab] berkata, telah menceritakan kepadaku ['Amru bin Al Harits] telah menceritakan kepadaku [Abu An Nadlr] dari [Abu Salamah bin 'Abdurrahman] dari ['Abdullah bin 'Umar] dari [Sa'd bin Abu Waqash] dari Nabi shallallahu 'alaihi wasallam, bahwa beliau mengusap sepasang sepatunya.\" ['Abdullah bin 'Umar] menanyakan hal ini kepada ['Umar] ia lalu menjawab, \"Ya. Jika Sa'd menceritakan kepadamu sebuah hadits dari Nabi shallallahu 'alaihi wasallam, maka janganlah kamu bertanya kepada selainnya.\" [Musa bin 'Uqbah] berkata, telah mengabarkan kepadaku [Abu An Nadlr] bahwa [Abu Salamah] menceritakan kepadanya, bahwa [Sa'd] menceritakan kepadanya, dan ['Umar] menyebutkan kepada ['Abdullah] seperti itu.\""},"196":{"ar":"حَدَّثَنَا عَمْرُو بْنُ خَالِدٍ الْحَرَّانِيُّ قَالَ حَدَّثَنَا اللَّيْثُ عَنْ يَحْيَى بْنِ سَعِيدٍ عَنْ سَعْدِ بْنِ إِبْرَاهِيمَ عَنْ نَافِعِ بْنِ جُبَيْرٍ عَنْ عُرْوَةَ بْنِ الْمُغِيرَةِ عَنْ أَبِيهِ الْمُغِيرَةِ بْنِ شُعْبَةَعَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُ خَرَجَ لِحَاجَتِهِ فَاتَّبَعَهُ الْمُغِيرَةُ بِإِدَاوَةٍ فِيهَا مَاءٌ فَصَبَّ عَلَيْهِ حِينَ فَرَغَ مِنْ حَاجَتِهِ فَتَوَضَّأَ وَمَسَحَ عَلَى الْخُفَّيْنِ","id":"Telah menceritakan kepada kami ['Amru bin Khalid Al Harrani] berkata, telah menceritakan kepada kami [Al Laits] dari [Yahya bin Sa'id] dari [Sa'd bin Ibrahim] dari [Nafi' bin Jubair] dari ['Urwah bin Al Mughirah bin Syu'bah] dari bapaknya, [Al Mughirah bin Syu'bah] dari Rasulullah shallallahu 'alaihi wasallam, bahwa beliau keluar untuk buang hajat, lalu Al Mughirah mengikutinya dengan membawa bejana berisi air. Selesai buang hajat, Al Mughirah menuangkan air kepada beliau hingga beliau pun berwudlu dan mengusap sepasang sepatunya.\""},"197":{"ar":"حَدَّثَنَا أَبُو نُعَيْمٍ قَالَ حَدَّثَنَا شَيْبَانُ عَنْ يَحْيَى عَنْ أَبِي سَلَمَةَ عَنْ جَعْفَرِ بْنِ عَمْرِو بْنِ أُمَيَّةَ الضَّمْرِيِّ أَنَّ أَبَاهُ أَخْبَرَهُأَنَّهُ رَأَى النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَمْسَحُ عَلَى الْخُفَّيْنِوَتَابَعَهُ حَرْبُ بْنُ شَدَّادٍ وَأَبَانُ عَنْ يَحْيَى","id":"Telah menceritakan kepada kami [Abu Nu'aim] berkata, telah menceritakan kepada kami [Syaiban] dari [Yahya] dari [Abu Salamah] dari [Ja'far bin 'Amru bin Umayyah Al Dlamri], bahwa [Bapaknya] mengabarkan kepadanya, bahwa ia pernah melihat Nabi shallallahu 'alaihi wasallam mengusap sepasang sepatunya.\" Hadits ini diperkuat oleh [Harb bin Syaddad] dan [Aban] dari [Yahya]."},"198":{"ar":"حَدَّثَنَا عَبْدَانُ قَالَ أَخْبَرَنَا عَبْدُ اللَّهِ قَالَ أَخْبَرَنَا الْأَوْزَاعِيُّ عَنْ يَحْيَى عَنْ أَبِي سَلَمَةَ عَنْ جَعْفَرِ بْنِ عَمْرِو بْنِ أُمَيَّةَ عَنْ أَبِيهِ قَالَرَأَيْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَمْسَحُ عَلَى عِمَامَتِهِ وَخُفَّيْهِوَتَابَعَهُ مَعْمَرٌ عَنْ يَحْيَى عَنْ أَبِي سَلَمَةَ عَنْ عَمْرٍو قَالَ رَأَيْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah menceritakan kepada kami ['Abdan] berkata, telah mengabarkan kepada kami ['Abdullah] berkata, telah mengabarkan kepada kami [Al Auza'i] dari [Yahya] dari [Abu Salamah] dari [Ja'far bin 'Amru bin Umayyah] dari [Bapaknya] ia berkata, \"Aku melihat Nabi shallallahu 'alaihi wasallam mengusap sorban dan sepasang sepatunya.\" Hadits ini diperkuat oleh [Ma'mar] dari [Yahya] dari [Abu Salamah] dari ['Amru] berkata, \"Aku melihat Nabi shallallahu 'alaihi wasallam.\""},"199":{"ar":"حَدَّثَنَا أَبُو نُعَيْمٍ قَالَ حَدَّثَنَا زَكَرِيَّاءُ عَنْ عَامِرٍ عَنْ عُرْوَةَ بْنِ الْمُغِيرَةِ عَنْ أَبِيهِ قَالَكُنْتُ مَعَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي سَفَرٍ فَأَهْوَيْتُ لِأَنْزِعَ خُفَّيْهِ فَقَالَ دَعْهُمَا فَإِنِّي أَدْخَلْتُهُمَا طَاهِرَتَيْنِ فَمَسَحَ عَلَيْهِمَا","id":"Telah menceritakan kepada kami [Abu Nu'aim] berkata, telah menceritakan kepada kami [Zakaria] dari ['Amir] dari ['Urwah bin Al Mughirah bin Syu'bah] dari [Bapaknya] ia berkata, \"Aku pernah bersama Nabi shallallahu 'alaihi wasallam dalam suatu perjalanan, aku lalu merunduk untuk melepas kedua sepatunya, namun beliau bersabda: \"Biarkan saja, karena aku mengenakannya dalam keadaan suci.\" Dan beliau hanya mengusap sepatunya."},"200":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ يُوسُفَ قَالَ أَخْبَرَنَا مَالِكٌ عَنْ زَيْدِ بْنِ أَسْلَمَ عَنْ عَطَاءِ بْنِ يَسَارٍ عَنْ عَبْدِ اللَّهِ بْنِ عَبَّاسٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَكَلَ كَتِفَ شَاةٍ ثُمَّ صَلَّى وَلَمْ يَتَوَضَّأْ","id":"Telah menceritakan kepada kami ['Abdullah bin Yusuf] berkata, telah mengabarkan kepada kami [Malik] dari [Zaid bin Aslam] dari ['Atha bin Yasar] dari ['Abdullah bin 'Abbas], bahwa Rasulullah shallallahu 'alaihi wasallam makan paha kambing kemudian shalat dan tidak berwudlu lagi.\""},"201":{"ar":"حَدَّثَنَا يَحْيَى بْنُ بُكَيْرٍ قَالَ حَدَّثَنَا اللَّيْثُ عَنْ عُقَيْلٍ عَنْ ابْنِ شِهَابٍ قَالَ أَخْبَرَنِي جَعْفَرُ بْنُ عَمْرِو بْنِ أُمَيَّةَ أَنَّ أَبَاهُ أَخْبَرَهُأَنَّهُ رَأَى رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَحْتَزُّ مِنْ كَتِفِ شَاةٍ فَدُعِيَ إِلَى الصَّلَاةِ فَأَلْقَى السِّكِّينَ فَصَلَّى وَلَمْ يَتَوَضَّأْ","id":"Telah menceritakan kepada kami [Yahya bin Bukair] berkata, telah menceritakan kepada kami [Al Laits] dari ['Uqail] dari [Ibnu Syihab] berkata, telah mengabarkan kepadaku [Ja'far bin 'Amru bin Umayyah] bahwa [Bapaknya] mengabarkan kepadanya, bahwa ia pernah melihat Rasulullah shallallahu 'alaihi wasallam memotong daging paha kambing, saat panggilan shalat tiba beliau langsung meletakkan pisaunya dan shalat tanpa berwudlu lagi.\""},"202":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ يُوسُفَ قَالَ أَخْبَرَنَا مَالِكٌ عَنْ يَحْيَى بْنِ سَعِيدٍ عَنْ بُشَيْرِ بْنِ يَسَارٍ مَوْلَى بَنِي حَارِثَةَ أَنَّ سُوَيْدَ بْنَ النُّعْمَانِ أَخْبَرَهُأَنَّهُ خَرَجَ مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَامَ خَيْبَرَ حَتَّى إِذَا كَانُوا بِالصَّهْبَاءِ وَهِيَ أَدْنَى خَيْبَرَ فَصَلَّى الْعَصْرَ ثُمَّ دَعَا بِالْأَزْوَادِ فَلَمْ يُؤْتَ إِلَّا بِالسَّوِيقِ فَأَمَرَ بِهِ فَثُرِّيَ فَأَكَلَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَأَكَلْنَا ثُمَّ قَامَ إِلَى الْمَغْرِبِ فَمَضْمَضَ وَمَضْمَضْنَا ثُمَّ صَلَّى وَلَمْ يَتَوَضَّأْ","id":"Telah menceritakan kepada kami ['Abdullah bin Yusuf] berkata, telah mengabarkan kepada kami [Malik] dari [Yahya bin Sa'id] dari [Busyair bin Yasar] mantan budak Bani Haritsah, bahwa [Suwaid bin An Nu'man] mengabarkan kepadanya, bahwa ia pernah keluar bersama Rasulullah shallallahu 'alaihi wasallam pada tahun pendudukan Khaibar, hingga ketika mereka sampai di Shahba', suatu wilayah di pinggiran Khaibar, beliau mengerjakan shalat Ashar. Lalu beliau minta diambilkan makanan dari perbekalan yang mereka bawa, namun tidak didapatkan kecuali makanan yang terbuat dari kurma dan gandum. Beliau kemudian memerintahkan untuk menghidangkannya, maka dicampurlah makanan tersebut dengan air hingga menjadi adonan, Rasulullah shallallahu 'alaihi wasallam makan dan kami pun ikut makan. Setelah itu beliau berdiri untuk shalat Maghrib, beliau lalu berkumur-kumur dan kami juga ikut berkumur-kumur, lalu beliau shalat tanpa berwudlu lagi.\""},"203":{"ar":"و حَدَّثَنَا أَصْبَغُ قَالَ أَخْبَرَنَا ابْنُ وَهْبٍ قَالَ أَخْبَرَنِي عَمْرُو بْنُ الْحَارِثِ عَنْ بُكَيْرٍ عَنْ كُرَيْبٍ عَنْ مَيْمُونَةَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَكَلَ عِنْدَهَا كَتِفًا ثُمَّ صَلَّى وَلَمْ يَتَوَضَّأْ","id":"Dan telah menceritakan kepada kami [Ashbagh] berkata, telah mengabarkan kepada kami [Ibnu Wahhab] berkata, telah mengabarkan kepadaku ['Amru bin Al Harits] dari [Bukair] dari [Kuraib] dari [Maimunah], bahwa Nabi shallallahu 'alaihi wasallam pernah makan daging paha (kambing) di sisinya kemudian shalat tanpa berwudlu lagi.\""},"204":{"ar":"حَدَّثَنَا يَحْيَى بْنُ بُكَيْرٍ وَقُتَيْبَةُ قَالَا حَدَّثَنَا اللَّيْثُ عَنْ عُقَيْلٍ عَنْ ابْنِ شِهَابٍ عَنْ عُبَيْدِ اللَّهِ بْنِ عَبْدِ اللَّهِ بْنِ عُتْبَةَ عَنْ ابْنِ عَبَّاسٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ شَرِبَ لَبَنًا فَمَضْمَضَ وَقَالَ إِنَّ لَهُ دَسَمًاتَابَعَهُ يُونُسُ وَصَالِحُ بْنُ كَيْسَانَ عَنْ الزُّهْرِيِّ","id":"Telah menceritakan kepada kami [Yahya bin Bukair] dan [Qutaibah] keduanya berkata, telah menceritakan kepada kami [Al Laits] dari ['Uqail] dari [Ibnu Syihab] dari ['Abdullah bin 'Abdullah bin 'Utbah] dari [Ibnu 'Abbas], bahwa Rasulullah shallallahu 'alaihi wasallam minum susu kemudian berkumur-kumur, beliau lalu bersabda: \"Sesungguhnya susu mengandung lemak.\" Hadits ini dikuatkan oleh [Yunus] dan [Shalih bin Kaisan] dari [Az Zuhri]."},"205":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ يُوسُفَ قَالَ أَخْبَرَنَا مَالِكٌ عَنْ هِشَامِ بْنِ عُرْوَةَ عَنْ أَبِيهِ عَنْ عَائِشَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِذَا نَعَسَ أَحَدُكُمْ وَهُوَ يُصَلِّي فَلْيَرْقُدْ حَتَّى يَذْهَبَ عَنْهُ النَّوْمُ فَإِنَّ أَحَدَكُمْ إِذَا صَلَّى وَهُوَ نَاعِسٌ لَا يَدْرِي لَعَلَّهُ يَسْتَغْفِرُ فَيَسُبُّ نَفْسَهُ","id":"Telah menceritakan kepada kami ['Abdullah bin Yusuf] berkata, telah mengabarkan kepada kami [Malik] dari [Hisyam bin 'Urwah] dari [Bapaknya] dari ['Aisyah], bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Jika salah seorang dari kalian mengantuk saat shalat hendaklah ia tidur hingga hilang kantuknya, karena bila shalat dalam keadaan mengantuk ia tidak menyadari, mungkin ia bermaksud beristighfar padahal bisa jadi ia mencaci dirinya.\""},"206":{"ar":"حَدَّثَنَا أَبُو مَعْمَرٍ قَالَ حَدَّثَنَا عَبْدُ الْوَارِثِ حَدَّثَنَا أَيُّوبُ عَنْ أَبِي قِلَابَةَ عَنْ أَنَسٍعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِذَا نَعَسَ أَحَدُكُمْ فِي الصَّلَاةِ فَلْيَنَمْ حَتَّى يَعْلَمَ مَا يَقْرَأُ","id":"Telah menceritakan kepada kami [Abu Ma 'mar] berkata, telah menceritakan kepada kami ['Abdul Warits] telah menceritakan kepada kami [Ayyub] dari [Abu Qilabah] dari [Anas] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Jika salah seorang dari kalian mengantuk saat shalat, hendaklah tidur (dahulu) hingga ia mengetahui apa yang ia baca.\""},"207":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ يُوسُفَ قَالَ حَدَّثَنَا سُفْيَانُ عَنْ عَمْرِو بْنِ عَامِرٍ قَالَ سَمِعْتُ أَنَسَ بْنَ مَالِكٍ قَالَ ح و حَدَّثَنَا مُسَدَّدٌ قَالَ حَدَّثَنَا يَحْيَى عَنْ سُفْيَانَ قَالَ حَدَّثَنِي عَمْرُو بْنُ عَامِرٍ عَنْ أَنَسِ بْنِ مَالِكٍ قَالَكَانَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَتَوَضَّأُ عِنْدَ كُلِّ صَلَاةٍ قُلْتُ كَيْفَ كُنْتُمْ تَصْنَعُونَ قَالَ يُجْزِئُ أَحَدَنَا الْوُضُوءُ مَا لَمْ يُحْدِثْ","id":"Telah menceritakan kepada kami [Muhammad bin Yusuf] berkata, telah menceritakan kepada kami [Sufyan] dari ['Amru bin 'Amir] berkata, aku mendengar [Anas bin Malik] berkata. (dalam jalur lain disebutkan) Telah menceritakan kepada kami [Musaddad] berkata, telah menceritakan kepada kami [Yahya] dari [Sufyan] berkata, telah menceritakan kepadaku ['Amru bin 'Amir] berkata, aku mendengar [Anas bin Malik] berkata, \"Nabi shallallahu 'alaihi wasallam berwudlu setiap kali akan shalat.\" Aku bertanya, \"Bagaimana cara kalian melaksanakannya?\" Anas bin Malik menjawab, \"Setiap orang dari kami mencukupkan dengan sekali wudlu' selama tidak berhadats (batal).\""},"208":{"ar":"حَدَّثَنَا خَالِدُ بْنُ مَخْلَدٍ قَالَ حَدَّثَنَا سُلَيْمَانُ بْنُ بِلَالٍ قَالَ حَدَّثَنِي يَحْيَى بْنُ سَعِيدٍ قَالَ أَخْبَرَنِي بُشَيْرُ بْنُ يَسَارٍ قَالَ أَخْبَرَنِي سُوَيْدُ بْنُ النُّعْمَانِ قَالَخَرَجْنَا مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَامَ خَيْبَرَ حَتَّى إِذَا كُنَّا بِالصَّهْبَاءِ صَلَّى لَنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْعَصْرَ فَلَمَّا صَلَّى دَعَا بِالْأَطْعِمَةِ فَلَمْ يُؤْتَ إِلَّا بِالسَّوِيقِ فَأَكَلْنَا وَشَرِبْنَا ثُمَّ قَامَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِلَى الْمَغْرِبِ فَمَضْمَضَ ثُمَّ صَلَّى لَنَا الْمَغْرِبَ وَلَمْ يَتَوَضَّأْ","id":"Telah menceritakan kepada kami [Khalid bin Makhlad] berkata, telah menceritakan kepada kami [Sulaiman bin Bilal] telah menceritakan kepadaku [Yahya bin Sa'id] berkata, telah mengabarkan kepadaku [Busyair bin Yasar] berkata, telah mengabarkan kepadaku [Suwaid bin An Nu'man] berkata, \"Kami pernah keluar bersama Rasulullah shallallahu 'alaihi wasallam pada tahun penaklukan Khaibar, hingga ketika kami sampai di suatu tempat bernama Shahba', beliau mengimami kami shalat Ashar. Selesai shalat beliau minta disajikan makanan, namun tidak ada kecuali makanan yang terbuat dari kurma dan gandum, lalu kami makan dan minum. Nabi shallallahu 'alaihi wasallam beranjak untuk melaksanakan shalat Maghrib, beliau berkumur lalu memimpin kami melaksanakan shalat maghrib tanpa berwudlu lagi.\""},"209":{"ar":"حَدَّثَنَا عُثْمَانُ قَالَ حَدَّثَنَا جَرِيرٌ عَنْ مَنْصُورٍ عَنْ مُجَاهِدٍ عَنْ ابْنِ عَبَّاسٍ قَالَمَرَّ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِحَائِطٍ مِنْ حِيطَانِ الْمَدِينَةِ أَوْ مَكَّةَ فَسَمِعَ صَوْتَ إِنْسَانَيْنِ يُعَذَّبَانِ فِي قُبُورِهِمَا فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُعَذَّبَانِ وَمَا يُعَذَّبَانِ فِي كَبِيرٍ ثُمَّ قَالَ بَلَى كَانَ أَحَدُهُمَا لَا يَسْتَتِرُ مِنْ بَوْلِهِ وَكَانَ الْآخَرُ يَمْشِي بِالنَّمِيمَةِ ثُمَّ دَعَا بِجَرِيدَةٍ فَكَسَرَهَا كِسْرَتَيْنِ فَوَضَعَ عَلَى كُلِّ قَبْرٍ مِنْهُمَا كِسْرَةً فَقِيلَ لَهُ يَا رَسُولَ اللَّهِ لِمَ فَعَلْتَ هَذَا قَالَ لَعَلَّهُ أَنْ يُخَفَّفَ عَنْهُمَا مَا لَمْ تَيْبَسَا أَوْ إِلَى أَنْ يَيْبَسَا","id":"Telah menceritakan kepada kami ['Utsman] berkata, telah menceritakan kepada kami [Jarir] dari [Manshur] dari [Mujahid] dari [Ibnu 'Abbas] berkata, \"Rasulullah shallallahu 'alaihi wasallam melewati perkebunan penduduk Madinah atau Makkah, lalu beliau mendengar suara dua orang yang sedang di siksa dalam kumur mereka. Maka Nabi shallallahu 'alaihi wasallam pun berkata: \"Keduanya sedang disiksa, dan tidaklah keduanya disiksa disebabkan dosa besar.\" Lalu beliau menerangkan: \"Yang satu disiksa karena tidak bersuci setelah kencing, sementara yang satunya lagi disiksa karena suka mengadu domba.\" Beliau kemudian minta diambilkan sebatang dahan kurma yang masih basah, beliau lalu membelah menjadi dua bagian, kemudian beliau menancapkan setiap bagian pada dua kuburan tersebut. Maka beliau pun ditanya, \"Kenapa Tuan melakukan ini?\" Beliau menjawab: \"Mudah-mudahan siksanya diringankan selama dahan itu masih basah.\""},"210":{"ar":"حَدَّثَنَا يَعْقُوبُ بْنُ إِبْرَاهِيمَ قَالَ حَدَّثَنَا إِسْمَاعِيلُ بْنُ إِبْرَاهِيمَ قَالَ حَدَّثَنِي رَوْحُ بْنُ الْقَاسِمِ قَالَ حَدَّثَنِي عَطَاءُ بْنُ أَبِي مَيْمُونَةَ عَنْ أَنَسِ بْنِ مَالِكٍ قَالَكَانَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا تَبَرَّزَ لِحَاجَتِهِ أَتَيْتُهُ بِمَاءٍ فَيَغْسِلُ بِهِ","id":"Telah menceritakan kepada kami [Ya'qub bin Ibrahim] berkata, telah menceritakan kepada kami [Isma'il bin Ibrahim] berkata, telah menceritakan kepadaku [Rauh bin Al Qasim] berkata, telah menceritakan kepadaku ['Atha bin Abu Maimunah] dari [Anas bin Malik] berkata, \"Jika Nabi shallallahu 'alaihi wasallam buang hajat aku selalu mendatanginya dengan membawa bejana berisi air, sehingga beliau bisa bersuci dengannya.\""},"211":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ الْمُثَنَّى قَالَ حَدَّثَنَا مُحَمَّدُ بْنُ خَازِمٍ قَالَ حَدَّثَنَا الْأَعْمَشُ عَنْ مُجَاهِدٍ عَنْ طَاوُسٍ عَنْ ابْنِ عَبَّاسٍ قَالَمَرَّ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِقَبْرَيْنِ فَقَالَ إِنَّهُمَا لَيُعَذَّبَانِ وَمَا يُعَذَّبَانِ فِي كَبِيرٍ أَمَّا أَحَدُهُمَا فَكَانَ لَا يَسْتَتِرُ مِنْ الْبَوْلِ وَأَمَّا الْآخَرُ فَكَانَ يَمْشِي بِالنَّمِيمَةِ ثُمَّ أَخَذَ جَرِيدَةً رَطْبَةً فَشَقَّهَا نِصْفَيْنِ فَغَرَزَ فِي كُلِّ قَبْرٍ وَاحِدَةً قَالُوا يَا رَسُولَ اللَّهِ لِمَ فَعَلْتَ هَذَا قَالَ لَعَلَّهُ يُخَفِّفُ عَنْهُمَا مَا لَمْ يَيْبَسَاوَقَالَ مُحَمَّدُ بْنُ الْمُثَنَّى وَحَدَّثَنَا وَكِيعٌ قَالَ حَدَّثَنَا الْأَعْمَشُ قَالَ سَمِعْتُ مُجَاهِدًا مِثْلَهُ يَسْتَتِرُ مِنْ بَوْلِهِ","id":"Telah menceritakan kepada kami [Muhammad bin Al Mutsanna] berkata, [Muhammad bin Hazm] berkata, telah menceritakan kepada kami [Al A'masy] dari [Mujahid] dari [Thawus] dari [Ibnu 'Abbas] berkata, \"Rasulullah shallallahu 'alaihi wasallam lewat di dekat dua kuburan, lalu beliau bersabda: \"Sesungguhnya keduanya sedang disiksa, dan keduanya disiksa bukan karena dosa besar. Yang satu disiksa karena tidak bersuci setelah kencing, sementara yang satunya suka mengadu domba.\" Kemudian beliau mengambil sebatang dahan kurma yang masih basah, beliau lalu membelahnya menjadi dua bagian kemudian menancapkannya pada masing-masing kuburan tersebut. Para sahabat pun bertanya, \"Wahai Rasulullah, kenapa engkau melakukan ini?\" beliau menjawab: \"Semoga siksa keduanya diringankan selama batang pohon ini basah.\" [Muhammad bin Al Mutsanna] berkata, telah menceritakan kepada kami [Waki'] berkata, telah menceritakan kepada kami [Al A'masy] ia berkata, \"Aku mendengar [Mujahid] menyebutkan seperti itu, \"Tidak bersuci setelah kencing.\""},"212":{"ar":"حَدَّثَنَا مُوسَى بْنُ إِسْمَاعِيلَ قَالَ حَدَّثَنَا هَمَّامٌ أَخْبَرَنَا إِسْحَاقُ عَنْ أَنَسِ بْنِ مَالِكٍأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ رَأَى أَعْرَابِيًّا يَبُولُ فِي الْمَسْجِدِ فَقَالَ دَعُوهُ حَتَّى إِذَا فَرَغَ دَعَا بِمَاءٍ فَصَبَّهُ عَلَيْهِ","id":"Telah menceritakan kepada kami [Musa bin Isma'il] berkata, telah menceritakan kepada kami [Hammam] telah mengabarkan kepada kami [Ishaq] dari [Anas bin Malik] bahwa Nabi shallallahu 'alaihi wasallam melihat seorang 'Arab badui kencing di dalam masjid, beliau lalu bersabda: \"Biarkanlah.\" Setelah orang itu selesai, beliau meminta air dan menyiram bekasnya.\""},"213":{"ar":"حَدَّثَنَا أَبُو الْيَمَانِ قَالَ أَخْبَرَنَا شُعَيْبٌ عَنْ الزُّهْرِيِّ قَالَ أَخْبَرَنِي عُبَيْدُ اللَّهِ بْنُ عَبْدِ اللَّهِ بْنِ عُتْبَةَ بْنِ مَسْعُودٍ أَنَّ أَبَا هُرَيْرَةَ قَالَقَامَ أَعْرَابِيٌّ فَبَالَ فِي الْمَسْجِدِ فَتَنَاوَلَهُ النَّاسُ فَقَالَ لَهُمْ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ دَعُوهُ وَهَرِيقُوا عَلَى بَوْلِهِ سَجْلًا مِنْ مَاءٍ أَوْ ذَنُوبًا مِنْ مَاءٍ فَإِنَّمَا بُعِثْتُمْ مُيَسِّرِينَ وَلَمْ تُبْعَثُوا مُعَسِّرِينَ","id":"Telah menceritakan kepada kami [Abu Al Yaman] berkata, telah mengabarkan kepada kami [Syu'aib] dari [Az Zuhri] berkata, telah mengabarkan kepadaku ['Ubaidullah bin 'Abdullah bin 'Utbah bin Mas'ud] bahwa [Abu Hurairah] berkata, \"Seorang 'Arab badui berdiri dan kencing di Masjid, lalu orang-orang ingin mengusirnya. Maka Nabi shallallahu 'alaihi wasallam pun bersabda kepada mereka: \"Biarkanlah dia dan siramlah bekas kencingnya dengan setimba air, atau dengan seember air, sesungguhnya kalian diutus untuk memberi kemudahan dan tidak diutus untuk membuat kesulitan.\""},"214":{"ar":"حَدَّثَنَا عَبْدَانُ قَالَ أَخْبَرَنَا عَبْدُ اللَّهِ قَالَ أَخْبَرَنَا يَحْيَى بْنُ سَعِيدٍ قَالَ سَمِعْتُ أَنَسَ بْنَ مَالِكٍ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بَابُ يُهَرِيقُ الْمَاءَ عَلَى الْبَوْلِ حَدَّثَنَا خَالِدُ بْنُ مَخْلَدٍ قَالَ وَحَدَّثَنَا سُلَيْمَانُ عَنْ يَحْيَى بْنِ سَعِيدٍ قَالَ سَمِعْتُ أَنَسَ بْنَ مَالِكٍ قَالَجَاءَ أَعْرَابِيٌّ فَبَالَ فِي طَائِفَةِ الْمَسْجِدِ فَزَجَرَهُ النَّاسُ فَنَهَاهُمْ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَلَمَّا قَضَى بَوْلَهُ أَمَرَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَ��َلَّمَ بِذَنُوبٍ مِنْ مَاءٍ فَأُهْرِيقَ عَلَيْهِ","id":"Telah menceritakan kepada kami ['Abdan] berkata, telah mengabarkan kepada kami ['Abdullah] berkata, telah mengabarkan kepada kami [Yahya bin Sa'id] berkata, aku mendengar [Anas bin Malik] dari Nabi shallallahu 'alaihi wasallam tentang bab menyiramkan air pada bekas kencing. Telah menceritakan kepada kami [Khalid bin Makhlad] berkata, dan telah menceritakan kepada kami [Sulaiman] dari [Yahya bin Sa'id] berkata, \"Aku mendengar [Anas bin Malik] berkata, \"Seorang 'Arab badui datang lalu kencing di sudut Masjid, maka orang-orang pun ingin mengusirnya, tetapi Nabi shallallahu 'alaihi wasallam melarang mereka. Setelah orang itu selesai dari kencingnya Nabi shallallahu 'alaihi wasallam minta setimba air lalu menyiram pada bekasnya.\""},"215":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ يُوسُفَ قَالَ أَخْبَرَنَا مَالِكٌ عَنْ هِشَامِ بْنِ عُرْوَةَ عَنْ أَبِيهِ عَنْ عَائِشَةَ أُمِّ الْمُؤْمِنِينَ أَنَّهَا قَالَتْأُتِيَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِصَبِيٍّ فَبَالَ عَلَى ثَوْبِهِ فَدَعَا بِمَاءٍ فَأَتْبَعَهُ إِيَّاهُ","id":"Telah menceritakan kepada kami ['Abdullah bin Yusuf] berkata, telah mengabarkan kepada kami [Malik] dari [Hisyam bin 'Urwah] dari [Bapaknya] dari ['Aisyah] Ummul Mukminin, ia berkata, \"Pernah seorang bayi dibawa ke hadapan Nabi shallallahu 'alaihi wasallam, lalu bayi tersebut kencing hingga mengenai pakaiannya. Beliau lalu minta air dan mengusapinya dengan auir tersebut.\""},"216":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ يُوسُفَ قَالَ أَخْبَرَنَا مَالِكٌ عَنْ ابْنِ شِهَابٍ عَنْ عُبَيْدِ اللَّهِ بْنِ عَبْدِ اللَّهِ بْنِ عُتْبَةَ عَنْ أُمِّ قَيْسٍ بِنْتِ مِحْصَنٍأَنَّهَا أَتَتْ بِابْنٍ لَهَا صَغِيرٍ لَمْ يَأْكُلْ الطَّعَامَ إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَجْلَسَهُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي حَجْرِهِ فَبَالَ عَلَى ثَوْبِهِ فَدَعَا بِمَاءٍ فَنَضَحَهُ وَلَمْ يَغْسِلْهُ","id":"Telah menceritakan kepada kami ['Abdullah bin Yusuf] berkata, telah mengabarkan kepada kami [Malik] dari [Ibnu Syihab] dari ['Ubaidullah bin 'Abdullah bin 'Utbah] dari [Ummu Qais binti Mihshan], bahwa dia datang menemui Rasulullah shallallahu 'alaihi wasallam dengan membawa anaknya yang masih kecil dan belum makan makanan. Rasulullah lalu mendudukkan anak kecil itu dalam pangkuannya sehingga ia kencing dan mengenai pakaian beliau. Beliau kemudian minta diambilkan air lalu memercikkannya dan tidak mencucinya.\""},"217":{"ar":"حَدَّثَنَا آدَمُ قَالَ حَدَّثَنَا شُعْبَةُ عَنْ الْأَعْمَشِ عَنْ أَبِي وَائِلٍ عَنْ حُذَيْفَةَ قَالَأَتَى النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ سُبَاطَةَ قَوْمٍ فَبَالَ قَائِمًا ثُمَّ دَعَا بِمَاءٍ فَجِئْتُهُ بِمَاءٍ فَتَوَضَّأَ","id":"Telah menceritakan kepada kami [Adam] telah menceritakan kepada kami [Syu'bah] dari [Al A'masy] dari [Abu Wa'il] dari [Hudzaifah] berkata, \"Nabi shallallahu 'alaihi wasallam mendatangi tempat pembuangan sampah suatu kaum, beliau lalu kencing sambil berdiri. Kemudian beliau meminta air, maka aku pun datang dengan membawa air, kemudian beliau berwudlu.\""},"218":{"ar":"حَدَّثَنَا عُثْمَانُ بْنُ أَبِي شَيْبَةَ قَالَ حَدَّثَنَا جَرِيرٌ عَنْ مَنْصُورٍ عَنْ أَبِي وَائِلٍ عَنْ حُذَيْفَةَ قَالَرَأَيْتُنِي أَنَا وَالنَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَتَمَاشَى فَأَتَى سُبَاطَةَ قَوْمٍ خَلْفَ حَائِطٍ فَقَامَ كَمَا يَقُومُ أَحَدُكُمْ فَبَالَ فَانْتَبَذْتُ مِنْهُ فَأَشَارَ إِلَيَّ فَجِئْتُهُ فَقُمْتُ عِنْدَ عَقِبِهِ حَتَّى فَرَغَ","id":"Telah menceritakan kepada kami ['Utsman bin Abu Syaibah] berkata, telah menceritakan kepada kami [Jarir] dari [Manshur] dari [Abu Wa'il] dari [Hudzaifah] berkata, \"Aku berjalan-jalan bersama Nabi shallallahu 'alaihi wasallam, beliau lalu mendatangi tempat pembuangan sampah suatu kaum di balik tembok dan kencing sambil berdiri sebagaimana kalian berdiri. Aku lalu menjauh dari beliau, namun beliau memberi isyarat kepadaku agar mendekat, maka aku pun mendekat dan berdiri di belakangnya hingga beliau selesai.\" "},"219":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ عَرْعَرَةَ قَالَ حَدَّثَنَا شُعْبَةُ عَنْ مَنْصُورٍ عَنْ أَبِي وَائِلٍقَالَ كَانَ أَبُو مُوسَى الْأَشْعَرِيُّ يُشَدِّدُ فِي الْبَوْلِ وَيَقُولُ إِنَّ بَنِي إِسْرَائِيلَ كَانَ إِذَا أَصَابَ ثَوْبَ أَحَدِهِمْ قَرَضَهُ فَقَالَ حُذَيْفَةُ لَيْتَهُ أَمْسَكَ أَتَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ سُبَاطَةَ قَوْمٍ فَبَالَ قَائِمًا","id":"Telah menceritakan kepada kami [Muhammad bin 'Ar'arah] berkata, telah menceritakan kepada kami [Syu'bah] dari [Manshur] dari [Abu Wa'il] ia berkata, \"Abu Musa Al Asy'ari sangat berlebihan dalam urusan kencing, ia berkata, \"Jika Bani Israil kencing lalu mengenai pakaiannya, maka mereka memotong pakaiannya.\" Maka [Hudzaifah] pun berkata, \"Aku tidak setuju! Sebab Nabi shallallahu 'alaihi wasallam pernah kencing sambil berdiri di tempat pembuangan sampah.\""},"220":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ الْمُثَنَّى قَالَ حَدَّثَنَا يَحْيَى عَنْ هِشَامٍ قَالَ حَدَّثَتْنِي فَاطِمَةُ عَنْ أَسْمَاءَ قَالَتْجَاءَتْ امْرَأَةٌ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَتْ أَرَأَيْتَ إِحْدَانَا تَحِيضُ فِي الثَّوْبِ كَيْفَ تَصْنَعُ قَالَ تَحُتُّهُ ثُمَّ تَقْرُصُهُ بِالْمَاءِ وَتَنْضَحُهُ وَتُصَلِّي فِيهِ","id":"Telah menceritakan kepada kami [Muhammad bin Al Mutsanna] berkata, telah menceritakan kepada kami [Yahya] dari [Hisyam] berkata, telah menceritakan kepadaku [Fatimah] dari [Asma'] berkata, \"Seorang wanita datang kepada Nabi shallallahu 'alaihi wasallam dan bertanya \"Bagaimana pendapat Tuan jika salah seorang dari kami darah haidnya mengenai pakaiannya. Apa yang harus dilakukannya?\" Beliau menjawab: \"Membersihkan darah yang menggenai pakaiannya dengan menggosoknya dengan jari, lalu memercikinya dengan air. Kemudian shalat dengan pakaian tersebut.\""},"221":{"ar":"حَدَّثَنَا مُحَمَّدٌ هُوَ ابْنُ سَلَامٍ قَالَ حَدَّثَنَا أَبُو مُعَاوِيَةَ حَدَّثَنَا هِشَامُ بْنُ عُرْوَةَ عَنْ أَبِيهِ عَنْ عَائِشَةَ قَالَتْجَاءَتْ فَاطِمَةُ بِنْتُ أَبِي حُبَيْشٍ إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَتْ يَا رَسُولَ اللَّهِ إِنِّي امْرَأَةٌ أُسْتَحَاضُ فَلَا أَطْهُرُ أَفَأَدَعُ الصَّلَاةَ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا إِنَّمَا ذَلِكِ عِرْقٌ وَلَيْسَ بِحَيْضٍ فَإِذَا أَقْبَلَتْ حَيْضَتُكِ فَدَعِي الصَّلَاةَ وَإِذَا أَدْبَرَتْ فَاغْسِلِي عَنْكِ الدَّمَ ثُمَّ صَلِّي قَالَ وَقَالَ أَبِي ثُمَّ تَوَضَّئِي لِكُلِّ صَلَاةٍ حَتَّى يَجِيءَ ذَلِكَ الْوَقْتُ","id":"Telah menceritakan kepada kami [Muhammad] -yakni Ibnu Salam- berkata, telah menceritakan kepada kami [Abu Mu'awiyah] telah menceritakan kepada kami [Hisyam bin 'Urwah] dari [Bapaknya] dari ['Aisyah] berkata, \"Fatimah binti Abu Hubaiys datang menemui Nabi shallallahu 'alaihi wasallam dan berkata, \"Wahai Rasulullah, aku adalah seorang wanita yang keluar darah istihadlah (darah penyakit) hingga aku tidak suci. Apakah aku boleh meninggalkan shalat?\" Rasulullah shallallahu 'alaihi wasallam lalu menjawab: \"Jangan, sebab itu hanyalah semisal keringat dan bukan darah haid. Jika datang haidmu maka tinggalkan shalat, dan jika telah terhenti maka bersihkanlah sisa darahnya lalu shalat.\" Hisyam berkata, \"Bapakku (Urwah) menyebutkan, \"Berwudlulah kamu setiap akan shalat hingga waktu itu tiba.\""},"222":{"ar":"حَدَّثَنَا عَبْدَانُ قَالَ أَخْبَرَنَا عَبْدُ اللَّهِ بْنُ الْمُبَارَكِ قَالَ أَخْبَرَنَا عَمْرُو بْنُ مَيْمُونٍ الْجَزَرِيُّ عَنْ سُلَيْمَانَ بْنِ يَسَارٍ عَنْ عَائِشَةَ قَالَتْكُنْتُ أَغْسِلُ الْجَنَابَةَ مِنْ ثَوْبِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَيَخْرُجُ إِلَى الصَّلَاةِ وَإِنَّ بُقَعَ الْمَاءِ فِي ثَوْبِهِ","id":"Telah menceritakan kepada kami ['Abdan] berkata, telah mengabarkan kepada kami ['Abdullah bin Al Mubarak] berkata, telah mengabarkan kepada kami ['Amru bin Maimun Al Jazari] dari [Sulaiman bin Yasar] dari ['Aisyah] ia berkata, \"Aku mencuci kain Nabi shallallahu 'alaihi wasallam sisa dari janabat, kemudian beliau keluar untuk shalat, sementara kainnya masih nampak basahnya.\""},"223":{"ar":"حَدَّثَنَا قُتَيْبَةُ قَالَ حَدَّثَنَا يَزِيدُ قَالَ حَدَّثَنَا عَمْرٌو يَعْنِي ابْنَ مَيْمُونٍ عَنْ سُلَيْمَانَ بْنِ يَسَارٍ قَالَ سَمِعْتُ عَائِشَةَ ح و حَدَّثَنَا مُسَدَّدٌ قَالَ حَدَّثَنَا عَبْدُ الْوَاحِدِ قَالَ حَدَّثَنَا عَمْرُو بْنُ مَيْمُونٍ عَنْ سُلَيْمَانَ بْنِ يَسَارٍ قَالَ سَأَلْتُ عَائِشَةَعَنْ الْمَنِيِّ يُصِيبُ الثَّوْبَ فَقَالَتْ كُنْتُ أَغْسِلُهُ مِنْ ثَوْبِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَيَخْرُجُ إِلَى الصَّلَاةِ وَأَثَرُ الْغَسْلِ فِي ثَوْبِهِ بُقَعُ الْمَاءِ","id":"Telah menceritakan kepada kami [Qutaibah] berkata, telah menceritakan kepada kami [Yazid] berkata, telah menceritakan kepada kami ['Amru] -yaitu Ibnu Maimun- dari [Sulaiman bin Yasar] berkata, aku mendengar ['Aisyah] berkata. (dalam jalur lain disebutkan) Telah menceritakan kepada kami [Musaddad] berkata, telah menceritakan kepada kami ['Abdul Wahid] berkata, telah menceritakan kepada kami ['Amru bin Maimun] dari [Sulaiman bin Yasar] berkata, \"Aku bertanya kepada ['Aisyah] tentang mani yang mengenai pakaian. Ia lalu menjawab, \"Aku pernah mencuci air mani dari pakaian Nabi shallallahu 'alaihi wasallam, beliau lalu keluar untuk shalat sementara sisa cucian masih nampak pada pakaian beliau.\""},"224":{"ar":"حَدَّثَنَا مُوسَى بْنُ إِسْمَاعِيلَ الْمِنْقَرِيُّ قَالَ حَدَّثَنَا عَبْدُ الْوَاحِدِ قَالَ حَدَّثَنَا عَمْرُو بْنُ مَيْمُونٍ قَالَ سَأَلْتُ سُلَيْمَانَ بْنَ يَسَارٍفِي الثَّوْبِ تُصِيبُهُ الْجَنَابَةُ قَالَ قَالَتْ عَائِشَةُ كُنْتُ أَغْسِلُهُ مِنْ ثَوْبِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ثُمَّ يَخْرُجُ إِلَى الصَّلَاةِ وَأَثَرُ الْغَسْلِ فِيهِ بُقَعُ الْمَاءِ","id":"Telah menceritakan kepada kami [Musa bin Isma'il Al Minqari] berkata, telah menceritakan kepada kami ['Abdul Wahid] berkata, telah menceritakan kepada kami ['Amru bin Maimun] berkata, \"Aku bertanya kepada [Sulaiman bin Yasar] tentang pakaian yang terkena janabat (mani), ia menjawab, \" ['Aisyah] pernah berkata, \"Aku pernah mencuci air mani dari pakaian Rasulullah shallallahu 'alaihi wasallam, kemudian beliau keluar untuk shalat dan sisa cucian masih nampak pada pakaian beliau.\""},"225":{"ar":"حَدَّثَنَا عَمْرُو بْنُ خَالِدٍ قَالَ حَدَّثَنَا زُهَيْرٌ قَالَ حَدَّثَنَا عَمْرُو بْنُ مَيْمُونِ بْنِ مِهْرَانَ عَنْ سُلَيْمَانَ بْنِ يَسَارٍ عَنْ عَائِشَةَأَنَّهَا كَانَتْ تَغْسِلُ الْمَنِيَّ مِنْ ثَوْبِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ثُمَّ أَرَاهُ فِيهِ بُقْعَةً أَوْ بُقَعًا","id":"Telah menceritakan kepada kami ['Amru bin Khalid] berkata, telah menceritakan kepada kami [Zuhair] berkata, telah menceritakan kepada kami ['Amru bin Maimun bin Mihran] dari [Sulaiman bin Yasar] dari ['Aisyah], bahwa ia pernah mencuci air mani dari pakaian Nabi shallallahu 'alaihi wasallam, kemudian aku masih melihat bekas sisa cucian itu.\""},"226":{"ar":"حَدَّثَنَا سُلَيْمَانُ بْنُ حَرْبٍ قَالَ حَدَّثَنَا حَمَّادُ بْنُ زَيْدٍ عَنْ أَيُّوبَ عَنْ أَبِي قِلَابَةَ عَنْ أَنَسِ بْنِ مَالِكٍ قَالَقَدِمَ أُنَاسٌ مِنْ عُكْلٍ أَوْ عُرَيْنَةَ فَاجْتَوَوْا الْمَدِينَةَ فَأَمَرَهُمْ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِلِقَاحٍ وَأَنْ يَشْرَبُوا مِنْ أَبْوَالِهَا وَأَلْبَانِهَا فَانْطَلَقُوا فَلَمَّا صَحُّوا قَتَلُوا رَاعِيَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَاسْتَاقُوا النَّعَمَ فَجَاءَ الْخَبَرُ فِي أَوَّلِ النَّهَارِ فَبَعَثَ فِي آثَارِهِمْ فَلَمَّا ارْتَفَعَ النَّهَارُ جِيءَ بِهِمْ فَأَمَرَ فَقَطَعَ أَيْدِيَهُمْ وَأَرْجُلَهُمْ وَسُمِرَتْ أَعْيُنُهُمْ وَأُلْقُوا فِي الْحَرَّةِ يَسْتَسْقُونَ فَلَا يُسْقَوْنَقَالَ أَبُو قِلَابَةَ فَهَؤُلَاءِ سَرَقُوا وَقَتَلُوا وَكَفَرُوا بَعْدَ إِيمَانِهِمْ وَحَارَبُوا اللَّهَ وَرَسُولَهُ","id":"Telah menceritakan kepada kami [Sulaiman bin Harb] berkata, telah menceritakan kepada kami [Hammad bin Zaid] dari [Ayyub] dari [Abu Qilabah] dari [Anas bin Malik] berkata, \"Beberapa orang dari 'Ukl atau 'Urainah datang ke Madinah, namun mereka tidak tahan dengan iklim Madinah hingga mereka pun sakit. Beliau lalu memerintahkan mereka untuk mendatangi unta dan meminum air seni dan susunya. Maka mereka pun berangkat menuju kandang unta (zakat), ketika telah sembuh, mereka membunuh pengembala unta Nabi shallallahu 'alaihi wasallam dan membawa unta-untanya. Kemudian berita itu pun sampai kepada Nabi shallallahu 'alaihi wasallam menjelang siang. Maka beliau mengutus rombongan untuk mengikuti jejak mereka, ketika matahari telah tinggi, utusan beliau datang dengan membawa mereka. Beliau lalu memerintahkan agar mereka dihukum, maka tangan dan kaki mereka dipotong, mata mereka dicongkel, lalu mereka dibuang ke pada pasir yang panas. Mereka minta minum namun tidak diberi.\" Abu Qilabah mengatakan, \"Mereka semua telah mencuri, membunuh, murtad setelah keimanan dan memerangi Allah dan rasul-Nya.\""},"227":{"ar":"حَدَّثَنَا آدَمُ قَالَ حَدَّثَنَا شُعْبَةُ قَالَ أَخْبَرَنَا أَبُو التَّيَّاحِ يَزِيدُ بْنُ حُمَيْدٍ عَنْ أَنَسٍ قَالَكَانَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُصَلِّي قَبْلَ أَنْ يُبْنَى الْمَسْجِدُ فِي مَرَابِضِ الْغَنَمِ","id":"Telah menceritakan kepada kami [Adam] berkata, telah menceritakan kepada kami [Syu'bah] berkata, telah mengabarkan kepada kami [Abu At Tayyah Yazid bin Humaid] dari [Anas] berkata, \"Sebelum masjid dibangun, Nabi shallallahu 'alaihi wasallam shalat di kandang kambing.\""},"228":{"ar":"حَدَّثَنَا إِسْمَاعِيلُ قَالَ حَدَّثَنِي مَالِكٌ عَنْ ابْنِ شِهَابٍ الزُّهْرِيِّ عَنْ عُبَيْدِ اللَّهِ بْنِ عَبْدِ اللَّهِ عَنْ ابْنِ عَبَّاسٍ عَنْ مَيْمُونَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ سُئِلَ عَنْ فَأْرَةٍ سَقَطَتْ فِي سَمْنٍ فَقَالَ أَلْقُوهَا وَمَا حَوْلَهَا فَاطْرَحُوهُ وَكُلُوا سَمْنَكُمْ","id":"Telah menceritakan kepada kami [Isma'il] telah menceritakan kepadaku [Malik] dari [Ibnu Syihab Az Zuhri] dari [Ubaidullah bin 'Abdullah] dari [Ibnu 'Abbas] dari [Maimunah], bahwa Rasulullah shallallahu 'alaihi wasallam pernah ditanya tentang bangkai tikus yang jatuh ke dalam lemak (minyak samin). Maka Beliau menjawab: \"Buanglah bangkai tikus itu ada apa yang ada di sekitarnya, lalu makanlah lemak kalian.\""},"229":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ عَبْدِ اللَّهِ قَالَ حَدَّثَنَا مَعْنٌ قَالَ حَدَّثَنَا مَالِكٌ عَنْ ابْنِ شِهَابٍ عَنْ عُبَيْدِ اللَّهِ بْنِ عَبْدِ اللَّهِ بْنِ عُتْبَةَ بْنِ مَسْعُودٍ عَنْ ابْنِ عَبَّاسٍ عَنْ مَيْمُونَةَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ سُئِلَ عَنْ فَأْرَةٍ سَقَطَتْ فِي سَمْنٍ فَقَالَ خُذُوهَا وَمَا حَوْلَهَا فَاطْرَحُوهُقَالَ مَعْنٌ حَدَّثَنَا مَالِكٌ مَا لَا أُحْصِيهِ يَقُولُ عَنْ ابْنِ عَبَّاسٍ عَنْ مَيْمُونَةَ","id":"Telah menceritakan kepada kami ['Ali bin 'Abdullah] berkata, telah menceritakan kepada kami [Ma'n] berkata, telah menceritakan kepada kami [Malik] dari [Ibnu Syihab] dari [Ubaidullah bin 'Abdullah bin 'Utbah bin Mas'ud] dari [Ibnu 'Abbas] dari [Maimunah], bahwa Rasulullah shallallahu 'alaihi wasallam pernah ditanya tentang bangkai tikus yang jatuh ke dalam lemak (minyak samin). Beliau lalu menjawab: \"Buanglah bangkai tikus itu dan lemak yang ada di sekitarnya.\" [Ma'n] berkata, telah menceritakan kepada kami [Malik] -apa yang aku tidak bisa menghitungnya- ia berkata dari [Ibnu 'Abbas] dari [Maimunah].\""},"230":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ مُحَمَّدٍ قَالَ أَخْبَرَنَا عَبْدُ اللَّهِ قَالَ أَخْبَرَنَا مَعْمَرٌ عَنْ هَمَّامِ بْنِ مُنَبِّهٍ عَنْ أَبِي هُرَيْرَةَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ كُلُّ كَلْمٍ يُكْلَمُهُ الْمُسْلِمُ فِي سَبِيلِ اللَّهِ يَكُونُ يَوْمَ الْقِيَامَةِ كَهَيْئَتِهَا إِذْ طُعِنَتْ تَفَجَّرُ دَمًا اللَّوْنُ لَوْنُ الدَّمِ وَالْعَرْفُ عَرْفُ الْمِسْكِ","id":"Telah menceritakan kepada kami [Ahmad bin Muhammad] berkata, telah mengabarkan kepada kami ['Abdullah] berkata, telah mengabarkan kepada kami [Ma'mar] dari [Hammam bin Munabbih] dari [Abu Hurairah] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Setiap luka yang didapatkan seorang Muslim di jalan Allah, maka pada hari kiamat keadaannya seperti saat luka tersebut terjadi. Warnanya warna darah dan harumnya sewangi misik.\""},"231":{"ar":"حَدَّثَنَا أَبُو الْيَمَانِ قَالَ أَخْبَرَنَا شُعَيْبٌ قَالَ أَخْبَرَنَا أَبُو الزِّنَادِ أَنَّ عَبْدَ الرَّحْمَنِ بْنَ هُرْمُزَ الْأَعْرَجَ حَدَّثَهُ أَنَّهُ سَمِعَ أَبَا هُرَيْرَةَأَنَّهُ سَمِعَ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ نَحْنُ الْآخِرُونَ السَّابِقُونَ","id":"Telah menceritakan kepada kami [Abu Al Yaman] berkata, telah mengabarkan kepada kami [Syu'aib] berkata, telah mengabarkan kepada kami [Abu Az Zinad] bahwa ['Abdurrahman bin Hurmuz Al A'raj] menceritakan kepadanya, bahwa ia mendengar [Abu Hurairah] mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Kita adalah orang yang datang terakhir dan akan menjadi yang pertama pada hari kiamat.\""},"232":{"ar":"وَبِإِسْنَادِهِ قَالَ لَا يَبُولَنَّ أَحَدُكُمْ فِي الْمَاءِ الدَّائِمِ الَّذِي لَا يَجْرِي ثُمَّ يَغْتَسِلُ فِيهِ","id":"(Masih dari jalur periwayatan yang sama dengan hadits sebelumnya dari [Abu Hurairah]). Rasulullah shallallahu 'alaihi wasallam bersabda: \"Jangan sekali-kali salah seorang dari kalian kencing pada air yang tidak mengalir, lalu mandi darinya.\""},"233":{"ar":"حَدَّثَنَا عَبْدَانُ قَالَ أَخْبَرَنِي أَبِي عَنْ شُعْبَةَ عَنْ أَبِي إِسْحَاقَ عَنْ عَمْرِو بْنِ مَيْمُونٍ عَنْ عَبْدِ اللَّهِ قَالَ بَيْنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ سَاجِدٌ قَالَ ح و حَدَّثَنِي أَحْمَدُ بْنُ عُثْمَانَ قَالَ حَدَّثَنَا شُرَيْحُ بْنُ مَسْلَمَةَ قَالَ حَدَّثَنَا إِبْرَاهِيمُ بْنُ يُوسُفَ عَنْ أَبِيهِ عَنْ أَبِي إِسْحَاقَ قَالَ حَدَّثَنِي عَمْرُو بْنُ مَيْمُونٍ أَنَّ عَبْدَ اللَّهِ بْنَ مَسْعُودٍ حَدَّثَهُأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يُصَلِّي عِنْدَ الْبَيْتِ وَأَبُو جَهْلٍ وَأَصْحَابٌ لَهُ جُلُوسٌ إِذْ قَالَ بَعْضُهُمْ لِبَعْض أَيُّكُمْ يَجِيءُ بِسَلَى جَزُورِ بَنِي فُلَانٍ فَيَضَعُهُ عَلَى ظَهْرِ مُحَمَّدٍ إِذَا سَجَدَ فَانْبَعَثَ أَشْقَى الْقَوْمِ فَجَاءَ بِهِ فَنَظَرَ حَتَّى سَجَدَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَضَعَهُ عَلَى ظَهْرِهِ بَيْنَ كَتِفَيْهِ وَأَنَا أَنْظُرُ لَا أُغْنِي شَيْئًا لَوْ كَانَ لِي مَنَعَةٌ قَالَ فَجَعَلُوا يَضْحَكُونَ وَيُحِيلُ بَعْضُهُمْ عَلَى بَعْضٍ وَرَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ سَاجِدٌ لَا يَرْفَعُ رَأْسَهُ حَتَّى جَاءَتْهُ فَاطِمَةُ فَطَرَحَتْ عَنْ ظَهْرِهِ فَرَفَعَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ رَأْسَهُ ثُمَّ قَالَ اللَّهُمَّ عَلَيْكَ بِقُرَيْشٍ ثَلَاثَ مَرَّاتٍ فَشَقَّ عَلَيْهِمْ إِذْ دَعَا عَلَيْهِمْ قَالَ وَكَانُوا يَرَوْنَ أَنَّ الدَّعْوَةَ فِي ذَلِكَ الْبَلَدِ مُسْتَجَابَةٌ ثُمَّ سَمَّى اللَّهُمَّ عَلَيْكَ بِأَبِي جَهْلٍ وَعَلَيْكَ بِعُتْبَةَ بْنِ رَبِيعَةَ وَشَيْبَةَ بْنِ رَبِيعَةَ وَالْوَلِيدِ بْنِ عُتْبَةَ وَأُمَيَّةَ بْنِ خَلَفٍ وَعُقْبَةَ بْنِ أَبِي مُعَيْطٍ وَعَدَّ السَّابِعَ فَلَمْ يَحْفَظْ قَالَ فَوَالَّذِي نَفْسِي بِيَدِهِ لَقَدْ رَأَيْتُ الَّذِينَ عَدَّ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ صَرْعَى فِي الْقَلِيبِ قَلِيبِ بَدْرٍ","id":"Telah menceritakan kepada kami ['Abdan] berkata, telah mengabarkan kepadaku [Bapakku] dari [Syu'bah] dari [Abu Ishaq] dari ['Amru bin Maimun] dari ['Abdullah] berkata, \"Ketika Rasulullah shallallahu 'alaihi wasallam sedang sujud, beliau mengucapkan. (dalam jalur lain disebutkan) Dan telah menceritakan kepadaku [Ahmad bin 'Utsman] berkata, telah menceritakan kepada kami [Syuraih bin Maslamah] berkata, telah menceritakan kepada kami [Ibrahim bin Yusuf] dari [Bapaknya] dari [Abu Ishaq] berkata, telah menceritakan kepadaku ['Amru bin Maimun] bahwa ['Abdullah bin Mas'ud] menceritakan kepadanya, bahwa Nabi shallallahu 'alaihi wasallam shalat di dekat Ka'bah sementara Abu Jahal dan teman-temannya duduk di dekat beliau. Lalu sebagian mereka berkata kepada sebagian yang lain, 'Siapa dari kalian yang dapat mendatangkan isi perut (jerohan) unta milik bani fulan, lalu ia letakkan di punggung Muhammad saat dia sujud? ' Maka berangkatlah orang yang paling celaka dari mereka, ia lalu datang kembali dengan membawa kotoran unta tersebut. Orang itu lantas menunggu dan memperhatikan, maka ketika Nabi shallallahu 'alaihi wasallam sujud kotoran itu ia letakkan di punggung beliau di antara kedua pundaknya. Sementara aku hanya bisa melihatnya tidak bisa berbuat apa-apa. Duh, sekiranya aku bisa mencegah! ' Abdullah bin Mas'ud melanjutkan kisahnya, \"Lalu mereka pun tertawa-tawa dan saling menyindir satu sama lain sedang Rasulullah shallallahu 'alaihi wasallam dalam keadaan sujud, beliau tidak mengangkat kepalanya hingga datang Fatimah. Fatimah lalu membersihkan kotoran itu dari punggung beliau, setelah itu baru Rasulullah shallallahu 'alaihi wasallam mengangkat kepalanya seraya berdo'a: \"Ya Allah, aku serahkan (urusan) Quraisy kepada-Mu.\" Sebanyak tiga kali. Maka do'a tersebut membuat mereka ketakutan.\" 'Abdullah bin Mas'ud meneruskan, \"Sebab mereka yakin bahwa do'a yang dipanjatkan tempat itu akan diterima. Kemudian Nabi shallallahu 'alaihi wasallam menyebut satu persatu nama-nama mereka: \"Ya Allah, aku serahkan (urusan) Abu Jahal kepada-Mu, 'Utbah bin Rabi'ah, Syaibah bin Rabi'ah, Al Walid bin 'Utbah, Umayyah bin Khalaf dan 'Uqbah bin Abu Mu'aith.\" Dan Nabi shallallahu 'alaihi wasallam menyebut yang ke tujuh tapi aku lupa.\" 'Abdullah bin Mas'ud berkata, \"Sungguh aku melihat orang-orang yang disebut Nabi shallallahu 'alaihi wasallam tersebut, terbantai di pinggiran lembah Badar (dalam perang Badar).\""},"234":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ يُوسُفَ قَالَ حَدَّثَنَا سُفْيَانُ عَنْ حُمَيْدٍ عَنْ أَنَسِ بْنِ مَالِكٍ قَالَبَزَقَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي ثَوْبِهِقَالَ أَبُو عَبْد اللَّهِ طَوَّلَهُ ابْنُ أَبِي مَرْيَمَ قَالَ أَخْبَرَنَا يَحْيَى بْنُ أَيُّوبَ حَدَّثَنِي حُمَيْدٌ قَالَ سَمِعْتُ أَنَسًا عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah menceritakan kepada kami [Muhammad bin Yusuf] berkata, telah menceritakan kepada kami [Sufyan] dari [Humaid] dari [Anas bin Malik] berkata, \"Nabi shallallahu 'alaihi wasallam meludah di dalam kainnya.\" Abu 'Abdullah berkata, \"Hadits ini disebutkan secara panjang lebar oleh [Ibnu Abu Maryam]. Ia berkata, telah mengabarkan kepada kami [Yahya bin Ayyub] telah menceritakan kepadaku [Humaid] berkata, aku mendengar [Anas] dari Nabi shallallahu 'alaihi wasallam.\""},"235":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ عَبْدِ اللَّهِ قَالَ حَدَّثَنَا سُفْيَانُ قَالَ حَدَّثَنَا الزُّهْرِيُّ عَنْ أَبِي سَلَمَةَ عَنْ عَائِشَةَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ كُلُّ شَرَابٍ أَسْكَرَ فَهُوَ حَرَامٌ","id":"Telah menceritakan kepada kami ['Ali bin 'Abdullah] berkata, telah menceritakan kepada kami [Sufyan] berkata, telah menceritakan kepada kami [Az Zuhri] dari [Abu Salamah] dari ['Aisyah] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Setiap minuman yang memabukkan adalah haram.\""},"236":{"ar":"حَدَّثَنَا مُحَمَّدٌ يَعْنِي ابْنَ سَلَامٍ قَالَ أَخْبَرَنَا سُفْيَانُ بْنُ عُيَيْنَةَ عَنْ أَبِي حَازِمٍ سَمِ��َ سَهْلَ بْنَ سَعْدٍ السَّاعِدِيَّوَسَأَلَهُ النَّاسُ وَمَا بَيْنِي وَبَيْنَهُ أَحَدٌ بِأَيِّ شَيْءٍ دُووِيَ جُرْحُ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ مَا بَقِيَ أَحَدٌ أَعْلَمُ بِهِ مِنِّي كَانَ عَلِيٌّ يَجِيءُ بِتُرْسِهِ فِيهِ مَاءٌ وَفَاطِمَةُ تَغْسِلُ عَنْ وَجْهِهِ الدَّمَ فَأُخِذَ حَصِيرٌ فَأُحْرِقَ فَحُشِيَ بِهِ جُرْحُهُ","id":"Telah menceritakan kepada kami [Muhammad] -yaitu Ibnu Salam- berkata, telah mengabarkan kepada kami [Sufyan bin 'Uyainah] dari [Abu Hazm] ia mendengar [Sahl bin Sa'd As Sa'idi] ditanya oleh manusia -sedang saat itu antara aku dan dia tidak ada seorangpun yang lebih mendengar tentang pengobatan luka yang diderita Nabi shallallahu 'alaihi wasallam-, ia menjawab, \"Tidak ada seorang sahabat yang masih hidup yang lebih tahu tentang itu daripada aku. Pernah 'Ali datang membawa perisai berisi air, lalu Fatimah membersihkan darah yang ada di wajah beliau, lalu diambilnya tikar kemudian dibakar dan ditempelkan pada lukanya.\""},"237":{"ar":"حَدَّثَنَا أَبُو النُّعْمَانِ قَالَ حَدَّثَنَا حَمَّادُ بْنُ زَيْدٍ عَنْ غَيْلَانَ بْنِ جَرِيرٍ عَنْ أَبِي بُرْدَةَ عَنْ أَبِيهِ قَالَأَتَيْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَوَجَدْتُهُ يَسْتَنُّ بِسِوَاكٍ بِيَدِهِ يَقُولُ أُعْ أُعْ وَالسِّوَاكُ فِي فِيهِ كَأَنَّه يَتَهَوَّعُ","id":"Telah menceritakan kepada kami [Abu An Nu'man] berkata, telah menceritakan kepada kami [Hammad bin Zaid] dari [Ghailan bin Jarir] dari [Abu Burdah] dari [Bapaknya] ia berkata, \"Aku datang menemui Nabi shallallahu 'alaihi wasallam dan aku dapati beliau sedang menggosok gigi dengan siwak di tangannya. Beliau mengeluarkan suara, \"U' U'.\" sementara kayu siwak berada di mulutnya seolah ingin muntah.\""},"238":{"ar":"حَدَّثَنَا عُثْمَانُ بْنُ أَبِي شَيْبَةَ قَالَ حَدَّثَنَا جَرِيرٌ عَنْ مَنْصُورٍ عَنْ أَبِي وَائِلٍ عَنْ حُذَيْفَةَ قَالَكَانَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا قَامَ مِنْ اللَّيْلِ يَشُوصُ فَاهُ بِالسِّوَاكِ","id":"Telah menceritakan kepada kami ['Utsman bin Abu Syaibah] berkata, telah menceritakan kepada kami [Jarir] dari [Manshur] dari [Abu Wa'il] dari [Hudzaifah] berkata, \"Jika Nabi shallallahu 'alaihi wasallam bangun di malam hari, beliau membersihkan mulutnya dengan siwak.\""},"239":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ مُقَاتِلٍ قَالَ أَخْبَرَنَا عَبْدُ اللَّهِ قَالَ أَخْبَرَنَا سُفْيَانُ عَنْ مَنْصُورٍ عَنْ سَعْدِ بْنِ عُبَيْدَةَ عَنْ الْبَرَاءِ بْنِ عَازِبٍ قَالَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا أَتَيْتَ مَضْجَعَكَ فَتَوَضَّأْ وُضُوءَكَ لِلصَّلَاةِ ثُمَّ اضْطَجِعْ عَلَى شِقِّكَ الْأَيْمَنِ ثُمَّ قُلْ اللَّهُمَّ أَسْلَمْتُ وَجْهِي إِلَيْكَ وَفَوَّضْتُ أَمْرِي إِلَيْكَ وَأَلْجَأْتُ ظَهْرِي إِلَيْكَ رَغْبَةً وَرَهْبَةً إِلَيْكَ لَا مَلْجَأَ وَلَا مَنْجَا مِنْكَ إِلَّا إِلَيْكَ اللَّهُمَّ آمَنْتُ بِكِتَابِكَ الَّذِي أَنْزَلْتَ وَبِنَبِيِّكَ الَّذِي أَرْسَلْتَ فَإِنْ مُتَّ مِنْ لَيْلَتِكَ فَأَنْتَ عَلَى الْفِطْرَةِ وَاجْعَلْهُنَّ آخِرَ مَا تَتَكَلَّمُ بِهِ قَالَ فَرَدَّدْتُهَا عَلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَلَمَّا بَلَغْتُ اللَّهُمَّ آمَنْتُ بِكِتَابِكَ الَّذِي أَنْزَلْتَ قُلْتُ وَرَسُولِكَ قَالَ لَا وَنَبِيِّكَ الَّذِي أَرْسَلْتَ","id":"Telah menceritakan kepada kami [Muhammad bin Muqatil] berkata, telah mengabarkan kepada kami ['Abdullah] berkata, telah mengabarkan kepada kami [Sufyan] dari [Manshur] dari [Sa'ad bin 'Ubaidah] dari [Al Bara' bin 'Azib] berkata, \"Nabi shallallahu 'alaihi wasallam bersabda: \"Jika kamu mendatangi tempat tidurmu maka wudlulah seperti wudlu untuk shalat, lalu berbaringlah pada sisi kanan badanmu dan ucapkanlah: ALLAHUMMA ASLAMTU WAJHII ILAIKA WA FAWWADLTU AMRII ILAIKA WA ALJA`TU ZHAHRII ILAIKA RAGHBATAN WA RAHBATAN ILAIKA LAA MALJA`A WA LAA MANJAA ILLAA ILAIKA ALLAHUMMA AAMANTU BIKITAABIKALLADZII ANZALTA WANNABIYYIKALLADZII ARSALTA (Ya Allah, aku pasrahkan wajahku kepada-Mu, aku serahkan urusanku kepada-Mu, aku sandarkan punggungku kepada-Mu dengan perasaan senang dan takut kepada-Mu. Tidak ada tempat berlindung dan menyelamatkan diri dari siksa-Mu melainkan kepada-Mu. Ya Allah, aku beriman kepada kitab-Mu yang Engkau turunkan dan kepada Nabi-Mu yang Engkau utus) '. Jika kamu meninggal pada malammu itu, maka kamu dalam keadaan fitrah dan jadikanlah do'a ini sebagai akhir kalimat yang kamu ucapkan.\" Al Bara' bin 'Azib berkata, \"Maka aku ulang-ulang do'a tersebut di hadapan Nabi shallallahu 'alaihi wasallam hingga sampai pada kalimat: ALLAHUMMA AAMANTU BIKITAABIKALLADZII ANZALTA (Ya Allah, aku beriman kepada kitab-Mu yang Engkau turunkan), aku ucapkan: WA RASUULIKA (dan rasul-Mu), beliau bersabda: \"Jangan, tetapi WANNABIYYIKALLADZII ARSALTA (dan kepada Nabi-Mu yang Engkau utus).\""},"240":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ يُوسُفَ قَالَ أَخْبَرَنَا مَالِكٌ عَنْ هِشَامِ بْنِ عُرْوَةَ عَنْ أَبِيهِ عَنْ عَائِشَةَ زَوْجِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ إِذَا اغْتَسَلَ مِنْ الْجَنَابَةِ بَدَأَ فَغَسَلَ يَدَيْهِ ثُمَّ يَتَوَضَّأُ كَمَا يَتَوَضَّأُ لِلصَّلَاةِ ثُمَّ يُدْخِلُ أَصَابِعَهُ فِي الْمَاءِ فَيُخَلِّلُ بِهَا أُصُولَ شَعَرِهِ ثُمَّ يَصُبُّ عَلَى رَأْسِهِ ثَلَاثَ غُرَفٍ بِيَدَيْهِ ثُمَّ يُفِيضُ الْمَاءَ عَلَى جِلْدِهِ كُلِّهِ","id":"Telah menceritakan kepada kami ['Abdullah bin Yusuf] berkata, telah mengabarkan kepada kami [Malik] dari [Hisyam bin 'Urwah] dari [Bapaknya] dari ['Aisyah] isteri Nabi shallallahu 'alaihi wasallam, bahwa jika Nabi shallallahu 'alaihi wasallam mandi karena janabat, beliau memulainya dengan mencuci kedua telapak tangannya, kemudian berwudlu sebagaimana wudlu untuk shalat, kemudian memasukkan jari-jarinya ke dalam air lalu menggosokkannya ke kulit kepalanya, kemudian menyiramkan air ke atas kepalanya dengan cidukan kedua telapak tangannya sebanyak tiga kali, kemudian beliau mengalirkan air ke seluruh kulitnya.\""},"241":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ يُوسُفَ قَالَ حَدَّثَنَا سُفْيَانُ عَنْ الْأَعْمَشِ عَنْ سَالِمِ بْنِ أَبِي الْجَعْدِ عَنْ كُرَيْبٍ عَنْ ابْنِ عَبَّاسٍ عَنْ مَيْمُونَةَ زَوْجِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَتْتَوَضَّأَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وُضُوءَهُ لِلصَّلَاةِ غَيْرَ رِجْلَيْهِ وَغَسَلَ فَرْجَهُ وَمَا أَصَابَهُ مِنْ الْأَذَى ثُمَّ أَفَاضَ عَلَيْهِ الْمَاءَ ثُمَّ نَحَّى رِجْلَيْهِ فَغَسَلَهُمَا هَذِهِ غُسْلُهُ مِنْ الْجَنَابَةِ","id":"Telah menceritakan kepada kami [Muhammad bin Yusuf] berkata, telah menceritakan kepada kami [Sufyan] dari [Al A'masy] dari [Salim bin Abu Al Ja'd] dari [Kuraib] dari [Ibnu 'Abbas] dari [Maimunah] isteri Nabi shallallahu 'alaihi wasallam, ia berkata, \"Nabi shallallahu 'alaihi wasallam berwudlu sebagaimana wudlunya untuk shalat, kecuali kedua kakinya. Beliau lalu mencuci kemaluan dan apa yang terkena kotoran (mani), kemudian menyiramkan air ke atasnya, kemudian mengakhirinya dengan menyela dan mencuci kedua kakinya. Itulah cara beliau mandi dari janabat.\""},"242":{"ar":"حَدَّثَنَا آدَمُ بْنُ أَبِي إِيَاسٍ قَالَ حَدَّثَنَا ابْنُ أَبِي ذِئْبٍ عَنْ الزُّهْرِيِّ عَنْ عُرْوَةَ عَنْ عَائِشَةَ قَالَتْكُنْتُ أَغْتَسِلُ أَنَا وَالنَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِنْ إِنَاءٍ وَاحِدٍ مِنْ قَدَحٍ يُقَالُ لَهُ الْفَرَقُ","id":"Telah menceritakan kepada kami [Adam bin Abu Iyas] berkata, telah menceritakan kepada kami [Ibnu Abu Dzi'b] dari [Az Zuhri] dari ['Urwah] dari ['Aisyah] berkata, \"Aku pernah mandi bersama Nabi shallallahu 'alaihi wasallam dari satu ember terbuat dari tembikar yang disebut Al Faraq.\""},"243":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مُحَمَّدٍ قَالَ حَدَّثَنِي عَبْدُ الصَّمَدِ قَالَ حَدَّثَنِي شُعْبَةُ قَالَ حَدَّثَنِي أَبُو بَكْرِ بْنُ حَفْصٍ قَالَ سَمِعْتُ أَبَا سَلَمَةَ يَقُولُ دَخَلْتُ أَنَا وَأَخُو عَائِشَةَ عَلَى عَائِشَةَفَسَأَلَهَا أَخُوهَا عَنْ غُسْلِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَدَعَتْ بِإِنَاءٍ نَحْوًا مِنْ صَاعٍ فَاغْتَسَلَتْ وَأَفَاضَتْ عَلَى رَأْسِهَا وَبَيْنَنَا وَبَيْنَهَا حِجَابٌقَالَ أَبُو عَبْد اللَّهِ قَالَ يَزِيدُ بْنُ هَارُونَ وَبَهْزٌ وَالْجُدِّيُّ عَنْ شُعْبَةَ قَدْرِ صَاعٍ","id":"Telah menceritakan kepada kami ['Abdullah bin Muhammad] berkata, telah menceritakan kepadaku ['Abdush Shamad] berkata, telah menceritakan kepadaku [Syu'bah] berkata, telah menceritakan kepadaku [Abu Bakar bin Hafsh] berkata, aku mendengar [Abu Salamah] berkata, \"Aku dan saudara 'Aisyah menemui ['Aisyah], lalu saudaranya bertanya kepadanya tentang cara Nabi shallallahu 'alaihi wasallam mandi (dari janabat). 'Aisyah lalu minta diambilkan satu bejana air setara dengan ukuran satu sha'. Kemudian mandi dan menuangkan air ke atas kepalanya, sementara antara kami dengannya terhalang oleh hijab.\" Abu 'Abdullah berkata, [Yazid bin Harun] dan [Bahz] dan [Al Juddi] menyebutkan dari [Syu'bah], \"Sekadar satu sha'.\""},"244":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مُحَمَّدٍ قَالَ حَدَّثَنَا يَحْيَى بْنُ آدَمَ قَالَ حَدَّثَنَا زُهَيْرٌ عَنْ أَبِي إِسْحَاقَ قَالَ حَدَّثَنَا أَبُو جَعْفَرٍ أَنَّهُ كَانَ عِنْدَ جَابِرِ بْنِ عَبْدِ اللَّهِهُوَ وَأَبُوهُ وَعِنْدَهُ قَوْمٌ فَسَأَلُوهُ عَنْ الْغُسْلِ فَقَالَ يَكْفِيكَ صَاعٌ فَقَالَ رَجُلٌ مَا يَكْفِينِي فَقَالَ جَابِرٌ كَانَ يَكْفِي مَنْ هُوَ أَوْفَى مِنْكَ شَعَرًا وَخَيْرٌ مِنْكَ ثُمَّ أَمَّنَا فِي ثَوْبٍ","id":"Telah menceritakan kepada kami ['Abdullah bin Muhammad] berkata, telah menceritakan kepada kami [Yahya bin Adam] berkata, telah menceritakan kepada kami [Zuhair] dari [Abu Ishaq] berkata, telah menceritakan kepada kami [Abu Ja'far] bahwasanya ia berada di sisi [Jabir bin 'Abdullah] -dia dan ayahnya (Ali bin Al Hasan) -, dan di dekat Jabir juga ada sekelompok orang yang bertanya kepadanya tentang cara mandi. Jabir bin Abdullah lalu menjawab, \"Cukup bagimu dengan satu sha' air.\" Tiba-tiba ada seorang yang berkata, \"Bagiku tidak cukup!\" Maka Jabir pun berkata, \"Seukuran itu cukup buat orang yang lebih lebat rambutnya darimu, dan yang lebih baik darimu.\""},"245":{"ar":"حَدَّثَنَا أَبُو نُعَيْمٍ قَالَ حَدَّثَنَا ابْنُ عُيَيْنَةَ عَنْ عَمْرٍو عَنْ جَابِرِ بْنِ زَيْدٍ عَنْ ابْنِ عَبَّاسٍأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَمَيْمُونَةَ كَانَا يَغْتَسِلَانِ مِنْ إِنَاءٍ وَاحِدٍقَالَ أَبُو عَبْد اللَّهِ كَانَ ابْنُ عُيَيْنَةَ يَقُولُ أَخِيرًا عَنْ ابْنِ عَبَّاسٍ عَنْ مَيْمُونَةَ وَالصَّحِيحُ مَا رَوَى أَبُو نُعَيْمٍ","id":"Telah menceritakan kepada kami [Abu Nu'aim] berkata, telah menceritakan kepada kami [Ibnu 'Uyainah] dari ['Amru] dari [Jabir bin Zaid] dari [Ibnu 'Abbas], bahwa Nabi shallallahu 'alaihi wasallam dan Maimunah mandi bersama dari satu ember.\" Abu 'Abdullah berkata, \"Terakhir Ibnu 'Uyainah meriwayatkan dari Ibnu Abbas dari Maimunah, padahal yang benar adalah apa yang diriwayatkan oleh Abu Nu'aim.\""},"246":{"ar":"حَدَّثَنَا أَبُو نُعَيْمٍ قَالَ حَدَّثَنَا زُهَيْرٌ عَنْ أَبِي إِسْحَاقَ قَالَ حَدَّثَنِي سُلَيْمَانُ بْنُ صُرَدٍ قَالَ حَدَّثَنِي جُبَيْرُ بْنُ مُطْعِمٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَمَّا أَنَا فَأُفِيضُ عَلَى رَأْسِي ثَلَاثًا وَأَشَارَ بِيَدَيْهِ كِلْتَيْهِمَا","id":"Telah menceritakan kepada kami [Abu Nu'aim] berkata, telah menceritakan kepada kami [Zuhair] dari [Abu Ishaq] berkata, telah menceritakan kepadaku [Sulaiman bin Shurad] berkata, telah menceritakan kepadaku [Jubair bin Muth'im] berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Aku menyiram kepalaku sebanyak tiga kali.\" Beliau memberi isyarat dengan kedua telapak tangannya."},"247":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ قَالَ حَدَّثَنَا غُنْدَرٌ قَالَ حَدَّثَنَا شُعْبَةُ عَنْ مِخْوَلِ بْنِ رَاشِدٍ عَنْ مُحَمَّدِ بْنِ عَلِيٍّ عَنْ جَابِرِ بْنِ عَبْدِ اللَّهِ قَالَكَانَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُفْرِغُ عَلَى رَأْسِهِ ثَلَاثًا","id":"Telah menceritakan kepada kami [Muhammad bin Basyar] berkata, telah menceritakan kepada kami [Ghundar] berkata, telah menceritakan kepada kami [Syu'bah] dari [Mikhwal bin Rasyid] dari [Muhammad bin 'Ali] dari [Jabir bin 'Abdullah] berkata, \"Nabi shallallahu 'alaihi wasallam menguyurkan air ke atas kepala sebanyak tiga kali.\""},"248":{"ar":"حَدَّثَنَا أَبُو نُعَيْمٍ قَالَ حَدَّثَنَا مَعْمَ��ُ بْنُ يَحْيَى بْنِ سَامٍ حَدَّثَنِي أَبُو جَعْفَرٍ قَالَ قَالَ لِي جَابِرُ بْنُ عَبْدِ اللَّهِوَأَتَانِي ابْنُ عَمِّكَ يُعَرِّضُ بِالْحَسَنِ بْنِ مُحَمَّدِ بْنِ الْحَنَفِيَّةِ قَالَ كَيْفَ الْغُسْلُ مِنْ الْجَنَابَةِ فَقُلْتُ كَانَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَأْخُذُ ثَلَاثَةَ أَكُفٍّ وَيُفِيضُهَا عَلَى رَأْسِهِ ثُمَّ يُفِيضُ عَلَى سَائِرِ جَسَدِهِ فَقَالَ لِي الْحَسَنُ إِنِّي رَجُلٌ كَثِيرُ الشَّعَرِ فَقُلْتُ كَانَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَكْثَرَ مِنْكَ شَعَرًا","id":"Telah menceritakan kepada kami [Abu Nu'aim] berkata, telah menceritakan kepada kami [Ma'mar bin Yahya bin Sam] telah menceritakan kepadaku [Abu Ja'far] berkata, [Jabir bin 'Abdullah] berkata kepadaku, \"Anak pamanmu telah datang kepadaku -mengisahkan Hasan bin Muhammad bin Al Hanafiah-, ia bertanya, \"Bagaimana cara mandi janabat? Aku menjawab, \"Nabi shallallahu 'alaihi wasallam mengambil air dengan tiga ciduk telapak tangannya lalu menyiramkannya ke atas kepalanya, kemudian menyiramkan ke seluruh tubuh.\" Al Hasan lalu berkata kepadaku, \"Aku adalah seorang laki-laki yang rambutnya lebat!\" Aku lalu menjawab, \"Nabi shallallahu 'alaihi wasallam rambutnya lebih lebah dari rambutmu.\""},"249":{"ar":"حَدَّثَنَا مُوسَى بْنُ إِسْمَاعِيلَ قَالَ حَدَّثَنَا عَبْدُ الْوَاحِدِ عَنْ الْأَعْمَشِ عَنْ سَالِمِ بْنِ أَبِي الْجَعْدِ عَنْ كُرَيْبٍ عَنْ ابْنِ عَبَّاسٍ قَالَ قَالَتْ مَيْمُونَةُوَضَعْتُ لِلنَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَاءً لِلْغُسْلِ فَغَسَلَ يَدَيْهِ مَرَّتَيْنِ أَوْ ثَلَاثًا ثُمَّ أَفْرَغَ عَلَى شِمَالِهِ فَغَسَلَ مَذَاكِيرَهُ ثُمَّ مَسَحَ يَدَهُ بِالْأَرْضِ ثُمَّ مَضْمَضَ وَاسْتَنْشَقَ وَغَسَلَ وَجْهَهُ وَيَدَيْهِ ثُمَّ أَفَاضَ عَلَى جَسَدِهِ ثُمَّ تَحَوَّلَ مِنْ مَكَانِهِ فَغَسَلَ قَدَمَيْهِ","id":"Telah menceritakan kepada kami [Musa bin Isma'il] berkata, telah menceritakan kepada kami ['Abdul Wahid] dari [Al A'masy] dari [Salim bin Abu Al Ja'd] dari [Kuraib] dari [Ibnu 'Abbas] berkata, [Maimunah] berkata, \"Aku menyiapkan air mandi untuk Nabi shallallahu 'alaihi wasallam, beliau mencuci kedua telapak tangannya dua atau tiga kali. Kemudian beliau menuangkan air ke telapak tangan kirinya dan membasuh kemaluannya, kemudian beliau usapkan tangannya ke tanah, kemudian berkumur dan memasukkan air ke dalam hidung, lalu membasuh wajah dan kedua tangannya. kemudian beliau mengguyur seluruh tubuhnya. Setelah itu beliau bergeser dari tempatnya semula, lalu mencuci kedua kakinya.\""},"250":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ الْمُثَنَّى قَالَ حَدَّثَنَا أَبُو عَاصِمٍ عَنْ حَنْظَلَةَ عَنْ الْقَاسِمِ عَنْ عَائِشَةَ قَالَتْكَانَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا اغْتَسَلَ مِنْ الْجَنَابَةِ دَعَا بِشَيْءٍ نَحْوَ الْحِلَابِ فَأَخَذَ بِكَفِّهِ فَبَدَأَ بِشِقِّ رَأْسِهِ الْأَيْمَنِ ثُمَّ الْأَيْسَرِ فَقَالَ بِهِمَا عَلَى وَسَطِ رَأْسِهِ","id":"Telah menceritakan kepada kami [Muhammad bin Al Mutsanna] berkata, telah menceritakan kepada kami [Abu 'Ashim] dari [Hanzhalah] dari [Al Qasim] dari ['Aisyah] berkata, \"Jika Nabi shallallahu 'alaihi wasallam mandi janabat, beliau minta diambilkan bejana sebesar bejana yang digunakan untuk memerah susu. Beliau lalu mengambil air dengan telapak tangannya dan mengguyurkannya dimulai dari sisi sebelah kanan lalu sebelah kiri. Kemudian menuangkan dengan keduanya pada bagian tengah kepala.\""},"251":{"ar":"حَدَّثَنَا عُمَرُ بْنُ حَفْصِ بْنِ غِيَاثٍ قَالَ حَدَّثَنَا أَبِي حَدَّثَنَا الْأَعْمَشُ قَالَ حَدَّثَنِي سَالِمٌ عَنْ كُرَيْبٍ عَنْ ابْنِ عَبَّاسٍ قَالَ حَدَّثَتْنَا مَيْمُونَةُ قَالَتْصَبَبْتُ لِلنَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ غُسْلًا فَأَفْرَغَ بِيَمِينِهِ عَلَى يَسَارِهِ فَغَسَلَهُمَا ثُمَّ غَسَلَ فَرْجَهُ ثُمَّ قَالَ بِيَدِهِ الْأَرْضَ فَمَسَحَهَا بِالتُّرَابِ ثُمَّ غَسَلَهَا ثُمَّ تَمَضْمَضَ وَاسْتَنْشَقَ ثُمَّ غَسَلَ وَجْهَهُ وَأَفَاضَ عَلَى رَأْسِهِ ثُمَّ تَنَحَّى فَغَسَلَ قَدَمَيْهِ ثُمَّ أُتِيَ بِمِنْدِيلٍ فَلَمْ يَنْفُضْ بِهَا","id":"Telah menceritakan kepada kami ['Umar bin Hafsh bin Ghiyats] berkata, telah menceritakan kepada kami [Bapakku] telah menceritakan kepada kami [Al A'masy] berkata, telah menceritakan kepadaku [Salim] dari [Kuraib] dari [Ibnu 'Abbas] berkata, telah menceritakan kepada kami [Maimunah] berkata, \"Aku menuangkan air untuk mandi Nabi shallallahu 'alaihi wasallam, lalu dengan tangan kanannya beliau menuangkan air pada tangan kirinya lalu membasuh keduanya. Kemudian mencuci kemaluannya, lalu menyentuhkan tangannya ke bumi dan mengusapnya dengan tanah, lalu mencucinya dengan air. Kemudian berkumur-kumur dan memasukkan air ke hidung, kemudian membasuh muka dan menyiramkan air ke atas kepalanya. Kemudian beliau bergeser untuk mencuci kedua telapak kakinya. Setelahitu beliau diberi handuk, tapi beliau tidak mengeringkan badannya dengan handuk tersebut.\""},"252":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ الزُّبَيْرِ الْحُمَيْدِيُّ قَالَ حَدَّثَنَا سُفْيَانُ قَالَ حَدَّثَنَا الْأَعْمَشُ عَنْ سَالِمِ بْنِ أَبِي الْجَعْدِ عَنْ كُرَيْبٍ عَنْ ابْنِ عَبَّاسٍ عَنْ مَيْمُونَةَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ اغْتَسَلَ مِنْ الْجَنَابَةِ فَغَسَلَ فَرْجَهُ بِيَدِهِ ثُمَّ دَلَكَ بِهَا الْحَائِطَ ثُمَّ غَسَلَهَا ثُمَّ تَوَضَّأَ وُضُوءَهُ لِلصَّلَاةِ فَلَمَّا فَرَغَ مِنْ غُسْلِهِ غَسَلَ رِجْلَيْهِ","id":"Telah menceritakan kepada kami ['Abdullah bin Az Zubair Al Humaidi] berkata, telah menceritakan kepada kami [Sufyan] berkata, telah menceritakan kepada kami [Al A'masy] dari [Salim bin Abu Al Ja'd] dari [Kuraib] dari [Ibnu 'Abbas] dari [Maimunah], bahwa Nabi shallallahu 'alaihi wasallam mandi janabat, beliau lalu mencuci kemaluannya dengan tangan, lalu beliau menyentuhkan tangannya ke dinding, lalu mencucinya dengan air. Kemudian berwudlu sebagaimana wudlu untuk shalat, selesai mandi beliau mencuci kedua kakinya.\""},"253":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مَسْلَمَةَ أَخْبَرَنَا أَفْلَحُ بْنُ حُمَيْدٍ عَنْ الْقَاسِمِ عَنْ عَائِشَةَ قَالَتْكُنْتُ أَغْتَسِلُ أَنَا وَالنَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِنْ إِنَاءٍ وَاحِدٍ تَخْتَلِفُ أَيْدِينَا فِيهِ","id":"Telah menceritakan kepada kami ['Abdullah bin Maslamah] telah mengabarkan kepada kami [Aflah bin Humaid] dari [Al Qasim] dari ['Aisyah] berkata, \"Aku pernah mandi bersama Nabi shallallahu 'alaihi wasallam dari satu bejana, dan tangan kami saling bersentuhan.\""},"254":{"ar":"حَدَّثَنَا مُسَدَّدٌ قَالَ حَدَّثَنَا حَمَّادٌ عَنْ هِشَامٍ عَنْ أَبِيهِ عَنْ عَائِشَةَ قَالَتْكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا اغْتَسَلَ مِنْ الْجَنَابَةِ غَسَلَ يَدَهُ","id":"Telah menceritakan kepada kami [Musaddad] berkata, telah menceritakan kepada kami [Hammad] dari [Hisyam] dari [Bapaknya] dari ['Aisyah] berkata, \"Jika Nabi shallallahu 'alaihi wasallam mandi janabat beliau membasuh tangannya.\""},"255":{"ar":"حَدَّثَنَا أَبُو الْوَلِيدِ قَالَ حَدَّثَنَا شُعْبَةُ عَنْ أَبِي بَكْرِ بْنِ حَفْصٍ عَنْ عُرْوَةَ عَنْ عَائِشَةَ قَالَتْكُنْتُ أَغْتَسِلُ أَنَا وَالنَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِنْ إِنَاءٍ وَاحِدٍ مِنْ جَنَابَةٍوَعَنْ عَبْدِ الرَّحْمَنِ بْنِ الْقَاسِمِ عَنْ أَبِيهِ عَنْ عَائِشَةَ مِثْلَهُ","id":"Telah menceritakan kepada kami [Abu Al Walid] berkata, telah menceritakan kepada kami [Syu'bah] dari [Abu Bakar bin Hafsh] dari ['Urwah] dari ['Aisyah] berkata, \"Aku pernah mandi junub bersama Nabi shallallahu 'alaihi wasallam dalam satu bejana.\" Dan dari ['Abdurrahman bin Al Qasim] dari [Bapaknya] dari ['Aisyah] seperti itu.\""},"256":{"ar":"حَدَّثَنَا أَبُو الْوَلِيدِ قَالَ حَدَّثَنَا شُعْبَةُ عَنْ عَبْدِ اللَّهِ بْنِ عَبْدِ اللَّهِ بْنِ جَبْرٍ قَالَ سَمِعْتُ أَنَسَ بْنَ مَالِكٍ يَقُولُكَانَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَالْمَرْأَةُ مِنْ نِسَائِهِ يَغْتَسِلَانِ مِنْ إِنَاءٍ وَاحِدٍزَادَ مُسْلِمٌ وَوَهْبُ بْنُ جَرِيرٍ عَنْ شُعْبَةَ مِنْ الْجَنَابَةِ","id":"Telah menceritakan kepada kami [Abu Al Walid] berkata, telah menceritakan kepada kami [Syu'bah] dari ['Abdullah bin 'Abdullah bin Jabr] berkata, aku mendengar [Anas bin Malik] berkata, \"Nabi shallallahu 'alaihi wasallam dan salah seorang dari isterinya mandi dalam satu bejana.\" [Muslim] dan [Wahb bin Jarir] dari [Syu'bah] menambahkan, \"Karena junub.\""},"257":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ مَحْبُوبٍ قَالَ حَدَّثَنَا عَبْدُ الْوَاحِدِ قَالَ حَدَّثَنَا الْأَعْمَشُ عَنْ سَالِمِ بْنِ أَبِي الْجَعْدِ عَنْ كُرَيْبٍ مَوْلَى ابْنِ عَبَّاسٍ عَنْ ابْنِ عَبَّاسٍ قَالَ قَالَتْ مَيْمُونَةُوَضَعْتُ لِرَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَاءً يَغْتَسِلُ بِهِ فَأَفْرَغَ عَلَى يَدَيْهِ فَغَسَلَهُمَا مَرَّتَيْنِ مَرَّتَيْنِ أَوْ ثَلَاثًا ثُمَّ أَفْرَغَ بِيَمِينِهِ عَلَى شِمَالِهِ فَغَسَلَ مَذَاكِيرَهُ ثُمَّ دَلَكَ يَدَهُ بِالْأَرْضِ ثُمَّ مَضْمَضَ وَاسْتَنْشَقَ ثُمَّ غَسَلَ وَجْهَهُ وَيَدَيْهِ وَغَسَلَ رَأْسَهُ ثَلَاثًا ثُمَّ أَفْرَغَ عَلَى جَسَدِهِ ثُمَّ تَنَحَّى مِنْ مَقَامِهِ فَغَسَلَ قَدَمَيْهِ","id":"Telah menceritakan kepada kami [Muhammad bin Mahbub] berkata, telah menceritakan kepada kami ['Abdul Wahid] berkata, telah menceritakan kepada kami [Al A'masy] dari [Salim bin Abu Al Ja'd] dari [Kuraib] mantan budak Ibnu 'Abbas, dari [Ibnu 'Abbas] berkata, [Maimunah] berkata, \"Aku menyediakan air mandi untuk Rasulullah shallallahu 'alaihi wasallam, beliau lalu menuangkan air pada kedua tangannya dan mencuci keduanya dua kali dua kali atau tiga kali. Lalu dengan tangan kanannya beliau menuangkan air pada telapak tangan kirinya lalu mencuci kemaluannya, setelah itu menyentuhkan tangannya ke tanah. Kemudian berkumur-kumur dan memasukkan air ke hidung. Kemudian membasuh muka dan kedua tangannya, lalu membasuh kepalanya tiga kali dan mengguyur seluruh badannya. Setelah itu beliau bergeser dari posisi semula lalu mencuci kedua telapak kakinya.\""},"258":{"ar":"حَدَّثَنَا مُوسَى بْنُ إِسْمَاعِيلَ قَالَ حَدَّثَنَا أَبُو عَوَانَةَ حَدَّثَنَا الْأَعْمَشُ عَنْ سَالِمِ بْنِ أَبِي الْجَعْدِ عَنْ كُرَيْبٍ مَوْلَى ابْنِ عَبَّاسٍ عَنْ ابْنِ عَبَّاسٍ عَنْ مَيْمُونَةَ بِنْتِ الْحَارِثِ قَالَتْوَضَعْتُ لِرَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ غُسْلًا وَسَتَرْتُهُ فَصَبَّ عَلَى يَدِهِ فَغَسَلَهَا مَرَّةً أَوْ مَرَّتَيْنِ قَالَ سُلَيْمَانُ لَا أَدْرِي أَذَكَرَ الثَّالِثَةَ أَمْ لَا ثُمَّ أَفْرَغَ بِيَمِينِهِ عَلَى شِمَالِهِ فَغَسَلَ فَرْجَهُ ثُمَّ دَلَكَ يَدَهُ بِالْأَرْضِ أَوْ بِالْحَائِطِ ثُمَّ تَمَضْمَضَ وَاسْتَنْشَقَ وَغَسَلَ وَجْهَهُ وَيَدَيْهِ وَغَسَلَ رَأْسَهُ ثُمَّ صَبَّ عَلَى جَسَدِهِ ثُمَّ تَنَحَّى فَغَسَلَ قَدَمَيْهِ فَنَاوَلْتُهُ خِرْقَةً فَقَالَ بِيَدِهِ هَكَذَا وَلَمْ يُرِدْهَا","id":"Telah menceritakan kepada kami [Musa bin Isma'il] berkata, telah menceritakan kepada kami [Abu 'Awanah] telah menceritakan kepada kami [Al A'masy] dari [Salim bin Abu Al Ja'di] dari [Kuraib] sahaya Ibnu 'Abbas dari [Ibnu 'Abbas] radliallahu 'anhu dari [Maimunah binti Al Harits radliallahu 'anhu] berkata,: \"Aku menyediakan air untuk Rasulullah shallallahu 'alaihi wasallam untuk mandi, dan aku menutupinya. Maka Beliau menuangkan air dengan telapak tangan kanannya lalu mencuci keduanya satu atau dua kali. Lalu menuangkan air dengan telapak tangan kanannya ke atas telapak tangan kirinya kemudian mencuci kemaluannya lalu menyentuhkan tangannya ke tanah. Kemudian berkumur-kumur dan memasukkan air ke hidung. Kemudian membasuh mukanya dan kedua tangannya dan membasuh kepalanya tiga kali kemudian mengguyur seluruh badannya. Kemudian di akhirnya Beliau bergeser dari posisi semula lalu mencuci kedua telapak kakinya\"."},"259":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ قَالَ حَدَّثَنَا ابْنُ أَبِي عَدِيٍّ وَيَحْيَى بْنُ سَعِيدٍ عَنْ شُعْبَةَ عَنْ إِبْرَاهِيمَ بْنِ مُحَمَّدِ بْنِ الْمُنْتَشِرِ عَنْ أَبِيهِ قَالَ ذَكَرْتُهُ لِعَائِشَةَ فَقَالَتْيَرْحَمُ اللَّهُ أَبَا عَبْدِ الرَّحْمَنِ كُنْتُ أُطَيِّبُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَيَطُوفُ عَلَى نِسَائِهِ ثُمَّ يُصْبِحُ مُحْرِمًا يَنْضَخُ طِيبًا","id":"Telah menceritakan kepada kami [Muhammad bin Basysyar] berkata, telah menceritakan kepada kami [Ibnu Abu 'Ady] dan [Yahya bin Sa'id] dari [Syu'bah] dari [Ibrahim bin Muhammad bin Al Muntasyir] dari [bapaknya] berkata,: \"Aku menceritakan tentang (perkataan Ibnu 'Abbas) kepada ['Aisyah], maka jawabnya: \"Semoga Allah merahmati Abu 'Abdurrahman. Sungguh aku pernah memakaikan wewangian kepada Rasulullah shallallahu 'alaihi wasallam kemudian Beliau mendatangi isteri-isterinya. Dan pada pagi harinya Beliau mengenakan pakain ihram dalam keadaan wangi semerbak\""},"260":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ قَالَ حَدَّثَنَا مُعَاذُ بْنُ هِشَامٍ قَالَ حَدَّثَنِي أَبِي عَنْ قَتَادَةَ قَالَ حَدَّثَنَا أَنَسُ بْنُ مَالِكٍ قَالَكَانَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَدُورُ عَلَى نِسَائِهِ فِي السَّاعَةِ الْوَاحِدَةِ مِنْ اللَّيْلِ وَالنَّهَارِ وَهُنَّ إِحْدَى عَشْرَةَ قَالَ قُلْتُ لِأَنَسٍ أَوَكَانَ يُطِيقُهُ قَالَ كُنَّا نَتَحَدَّثُ أَنَّهُ أُعْطِيَ قُوَّةَ ثَلَاثِينَوَقَالَ سَعِيدٌ عَنْ قَتَادَةَ إِنَّ أَنَسًا حَدَّثَهُمْ تِسْعُ نِسْوَةٍ","id":"Telah menceritakan kepada kami [Muhammad bin Basysyar] berkata, telah menceritakan kepada kami [Mu'adz bin Hisyam] berkata, telah menceritakan kepada saya [bapakku] dari [Qatadah] berkata, telah menceritakan kepada kami [Anas bin Malik radliallahu 'anhu] berkata,: \"Adalah Nabi shallallahu 'alaihi wasallam. mendatangi isterinya pada waktu yang sama di malam hari atau siang hari, saat itu jumlah isteri-isteri Beliau sebelas orang\". Aku bertanya kepada Anas bin Malik radliallahu 'anhu: \"Apakah Beliau mampu?\". Jawabnya: \"Beliau diberikan kekuatan setara tiga puluh lelaki\". Berkata, [Sa'id] dari [Qatadah] bahwa [Anas radliallahu 'anhu] menerangkan kepada mereka bahwa jumlah isteri-isteri Beliau shallallahu 'alaihi wasallam. saat itu sembilan orang\"."},"261":{"ar":"حَدَّثَنَا أَبُو الْوَلِيدِ قَالَ حَدَّثَنَا زَائِدَةُ عَنْ أَبِي حَصِينٍ عَنْ أَبِي عَبْدِ الرَّحْمَنِ عَنْ عَلِيٍّ قَالَكُنْتُ رَجُلًا مَذَّاءً فَأَمَرْتُ رَجُلًا أَنْ يَسْأَلَ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لِمَكَانِ ابْنَتِهِ فَسَأَلَ فَقَالَ تَوَضَّأْ وَاغْسِلْ ذَكَرَكَ","id":"Telah menceritakan kepada kami [Abu Al Walid] berkata, telah menceritakan kepada kami [Za'idah] dari [Abi Hushain] dari [Abu 'Abdurrahman] dari ['Ali] berkata,: \"Dulu aku adalah seorang yang sering mengeluarkan madzi. Maka aku minta seseorang untuk bertanya kepada Nabi shallallahu 'alaihi wasallam. karena kedudukan putri Beliau shallallahu 'alaihi wasallam. Maka orang itu bertanya, lalu Jawab Nabi shallallahu 'alaihi wasallam.: \"Baginya wudlu' dan mencuci kemaluannya\"."},"262":{"ar":"حَدَّثَنَا أَبُو النُّعْمَانِ قَالَ حَدَّثَنَا أَبُو عَوَانَةَ عَنْ إِبْرَاهِيمَ بْنِ مُحَمَّدِ بْنِ الْمُنْتَشِرِ عَنْ أَبِيهِ قَالَ سَأَلْتُ عَائِشَةَفَذَكَرْتُ لَهَا قَوْلَ ابْنِ عُمَرَ مَا أُحِبُّ أَنْ أُصْبِحَ مُحْرِمًا أَنْضَخُ طِيبًا فَقَالَتْ عَائِشَةُ أَنَا طَيَّبْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ثُمَّ طَافَ فِي نِسَائِهِ ثُمَّ أَصْبَحَ مُحْرِمًا","id":"Telah menceritakan kepada kami [Abu AN-Nu'man] berkata, telah menceritakan kepada kami [Abu 'Awanah] dari [Ibrahim bin Muhammad bin Al Muntasyir] dari [bapaknya]: \"Aku bertanya kepada ['Aisyah radliallahu 'anhu] lalu aku ceritakan tentang ucapan Ibnu 'Umar radliallahu 'anhu yang mengatakan: \"aku tidak suka bila berpakaian ihram juga memakai wewangian\". Maka 'Aisyah radliallahu 'anhu berkata,: \"Sungguh aku pernah memberikan wewangian kepada Rasulullah shallallahu 'alaihi wasallam. lalu Beliau mendatangi isteri-isterinya. Kemudian Beliau mengenakan pakain ihram\""},"263":{"ar":"حَدَّثَنَا آدَمُ بْنُ أَبِي إِيَاسٍ قَالَ حَدَّثَنَا شُعْبَةُ قَالَ حَدَّثَنَا الْحَكَمُ عَنْ إِبْرَاهِيمَ عَنْ الْأَسْوَدِ عَنْ عَائِشَةَ قَالَتْكَأَنِّي أَنْظُرُ إِلَى وَبِيصِ الطِّيبِ فِي مَفْرِقِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَهُوَ مُحْرِمٌ","id":"Telah menceritakan kepada kami [Adam bin Abu Iyas] berkata, telah menceritakan kepada kami [Syu'bah] berkata, telah menceritakan kepada kami [Al Hakam] dari [Ibrahim] dari [Al Aswad] dari ['Aisyah radliallahu 'anhu] berkata,: \"Seakan aku melihat kilauan wewangian dari rambut Nabi shallallahu 'alaihi wasallam saat Beliau sedang berihram\"."},"264":{"ar":"حَدَّثَنَا عَبْدَانُ قَالَ أَخْبَرَنَا عَبْدُ اللَّهِ قَالَ أَخْبَرَنَا هِشَامُ بْنُ عُرْوَةَ عَنْ أَبِيهِ عَنْ عَائِشَةَ قَالَتْكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا اغْتَسَلَ مِنْ الْجَنَابَةِ غَسَلَ يَدَيْهِ وَتَوَضَّأَ وُضُوءَهُ لِلصَّلَاةِ ثُمَّ اغْتَسَلَ ثُمَّ يُخَلِّلُ بِيَدِهِ شَعَرَهُ حَتَّى إِذَا ظَنَّ أَنَّهُ قَدْ أَرْوَى بَشَرَتَهُ أَفَاضَ عَلَيْهِ الْمَاءَ ثَلَاثَ مَرَّاتٍ ثُمَّ غَسَلَ سَائِرَ جَسَدِهِ وَقَالَتْ كُنْتُ أَغْتَسِلُ أَنَا وَرَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِنْ إِنَاءٍ وَاحِدٍ نَغْرِفُ مِنْهُ جَمِيعًا","id":"Telah menceritakan kepada kami ['Abdan] berkata, telah mengabarkan kepada kami ['Abdullah] berkata, telah mengabarkan kepada kami [Hisyam bin 'Urwah] dari [bapaknya] dari ['Aisyah] berkata,: \"Adalah Nabi Rasulullah shallallahu 'alaihi wasallam. jika mandi janabat, mencuci tangannya dan berwudlu' sebagaimana wudlu' unmtuk shalat. Kemudian mandi dengan menggosok-gosokkan tangannya ke rambut kepalanya hingga bila telah yakin merata mengenai dasar kulit kepalanya Beliau mengguyurkan air ke atasnya tiga kali. Lalu membasuh seluruh badannya\". 'Aisyah berkata,: \"Aku pernah mandi bersama Rasulullah shallallahu 'alaihi wasallam. dari satu bejana dimana kami saling mengambil (menciduk) air bersamaan\"."},"265":{"ar":"حَدَّثَنَا يُوسُفُ بْنُ عِيسَى قَالَ أَخْبَرَنَا الْفَضْلُ بْنُ مُوسَى قَالَ أَخْبَرَنَا الْأَعْمَشُ عَنْ سَالِمٍ عَنْ كُرَيْبٍ مَوْلَى ابْنِ عَبَّاسٍ عَنْ ابْنِ عَبَّاسٍ عَنْ مَيْمُونَةَ قَالَتْوَضَعَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَضُوءًا لِجَنَابَةٍ فَأَكْفَأَ بِيَمِينِهِ عَلَى شِمَالِهِ مَرَّتَيْنِ أَوْ ثَلَاثًا ثُمَّ غَسَلَ فَرْجَهُ ثُمَّ ضَرَبَ يَدَهُ بِالْأَرْضِ أَوْ الْحَائِطِ مَرَّتَيْنِ أَوْ ثَلَاثًا ثُمَّ مَضْمَضَ وَاسْتَنْشَقَ وَغَسَلَ وَجْهَهُ وَذِرَاعَيْهِ ثُمَّ أَفَاضَ عَلَى رَأْسِهِ الْمَاءَ ثُمَّ غَسَلَ جَسَدَهُ ثُمَّ تَنَحَّى فَغَسَلَ رِجْلَيْهِ قَالَتْ فَأَتَيْتُهُ بِخِرْقَةٍ فَلَمْ يُرِدْهَا فَجَعَلَ يَنْفُضُ بِيَدِهِ","id":"Telah menceritakan kepada kami [Yusuf bin 'Isa] berkata, telah mengabarkan kepada kami [Al Fadlol bin Musa] berkata, telah mengabarkan kepada kami [Al A'masy] dari [Salim] dari [Kuraib] sahaya Ibnu 'Abbas dari [Ibnu 'Abbas] radliallahu 'anhu dari [Maimunah] berkata,: \"Rasulullah shallallahu 'alaihi wasallam. mengambil seember air untuk mandi janabat. Beliau menuangkan dengan telapak tangan kanannya ke atas telapak tangan kirinya lalu mencucinya dua kali atau tiga kali. Lalu mencuci kemaluannya lalu memukulkan tangannya ke tanah atau dinding dua kali atau tiga kali. Kemudian berkumur-kumur dan memasukkan air ke hidung lalu mencuci wajahnyaKemudian berkumur-kumur dan memasukkan air ke hidung lalu mencuci wajahnya dan kedua lengannya. Kemudian mengguyurkan air ke atas kepalanya lalu membasuh badannya dan mengakhirinya dengan membasuh kedua telapak kakinya\". 'Aisyah berkata,: \"Maka aku berikan potongan kain tapi Beliau tidak memerlukannya, dan Beliau mengeringkan (membersihkan air dari) badannya dengan tangannya\"."},"266":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مُحَمَّدٍ قَالَ حَدَّثَنَا عُثْمَانُ بْنُ عُمَرَ قَالَ أَخْبَرَنَا يُونُسُ عَنْ الزُّهْرِيِّ عَنْ أَبِي سَلَمَةَ عَنْ أَبِي هُرَيْرَةَ قَالَأُقِيمَتْ الصَّلَاةُ وَعُدِّلَتْ الصُّفُوفُ قِيَامًا فَخَرَجَ إِلَيْنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَلَمَّا قَامَ فِي مُصَلَّاهُ ذَكَرَ أَنَّهُ جُنُبٌ فَقَالَ لَنَا مَكَانَكُمْ ثُمَّ رَجَعَ فَاغْتَسَلَ ثُمَّ خَرَجَ إِلَيْنَا وَرَأْسُهُ يَقْطُرُ فَكَبَّرَ فَصَلَّيْنَا مَعَهُتَابَعَهُ عَبْدُ الْأَعْلَى عَنْ مَعْمَرٍ عَنْ الزُّهْرِيِّ وَرَوَاهُ الْأَوْزَاعِيُّ عَنْ الزُّهْرِيِّ","id":"Telah menceritakan kepada kami [Abdullah bin Muhammad] berkata, telah menceritakan kepada kami ['Utsman bin 'Umar] berkata, telah mengabarkan kepada kami [Yunus] dari [Az Zuhry] dari [Abu Salamah] dari [Abu Hurairah radliallahu 'anhu] berkata,: \"Qamat untuk shalat telah dikumandangkan dan shaf telah diluruskan, lalu keluarlah Rasulullah shallallahu 'alaihi wasallam. Setelah sampai di tempat shalat Beliau baru teringat bahwa Beliau sedang junub, lalu berkata, kepada kami; \"tetaplah di tempat kalian\". Maka Beliau kembali lalu mandi. Kemudian datang dalam keadaan kapalanya basah. Lalu Beliau bertakbir, maka kamipun shalat bersamanya\". Hadits ini juga diriwayatkan oleh [Abdul A'laa] dari [Ma'mar] dari [Az Zuhry] dan diriwayatkan juga oleh [Al Auza'i] dari [Az Zuhry]."},"267":{"ar":"حَدَّثَنَا عَبْدَانُ قَالَ أَخْبَرَنَا أَبُو حَمْزَةَ قَالَ سَمِعْتُ الْأَعْمَشَ عَنْ سَالِمِ بْنِ أَبِي الْجَعْدِ عَنْ كُرَيْبٍ عَنْ ابْنِ عَبَّاسٍ قَالَ قَالَتْ مَيْمُونَةُوَضَعْتُ لِلنَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ غُسْلًا فَسَتَرْتُهُ بِثَوْبٍ وَصَبَّ عَلَى يَدَيْهِ فَغَسَلَهُمَا ثُمَّ صَبَّ بِيَمِينِهِ عَلَى شِمَالِهِ فَغَسَلَ فَرْجَهُ فَضَرَبَ بِيَدِهِ الْأَرْضَ فَمَسَحَهَا ثُمَّ غَسَلَهَا فَمَضْمَضَ وَاسْتَنْشَقَ وَغَسَلَ وَجْهَهُ وَذِرَاعَيْهِ ثُمَّ صَبَّ عَلَى رَأْسِهِ وَأَفَاضَ عَلَى جَسَدِهِ ثُمَّ تَنَحَّى فَغَسَلَ قَدَمَيْهِ فَنَاوَلْتُهُ ثَوْبًا فَلَمْ يَأْخُذْهُ فَانْطَلَقَ وَهُوَ يَنْفُضُ يَدَيْهِ","id":"Telah menceritakan kepada kami ['Abdan] berkata, telah mengabarkan kepada kami [Abu Hamzah] berkata, aku mendengar [Al A'masy] dari [Salim bin Abu AL Ja'di] dari [Kuraib] dari [Ibnu 'Abbas] berkata, telah berkata, [Maimunah radliallahu 'anhu.]: \"Aku memberi air untuk mandi kepada Nabi shallallahu 'alaihi wasallam. lalu aku tutupi Beliau dengan kain. Maka Beliau menuangkan air ke tangannya lalu mencuci keduanya. Kemudian menuangkan air dengan tangan kanannya ke tangan kirinya lalu mencuci kemaluannya, lalu tangannya dipukulkannya ke tanah kemudian mengusapnya lalu mencucinya. Kemudian berkumur-kumur dan memasukkan air ke hidung. Kemudian membasuh mukanya dan kedua lengannya lalu mengguyur kepalanya lalu menyiram seluruh badannya dan diakhiri dengan mencuci kedu telapak kaikinya. Lalu aku sodorkan kain (sebagai pengering) tapi Beliau tidak mengambilnya, lalu Beliau pergi dengan mengeringkan air dari badannya dengan tangannya\"."},"268":{"ar":"حَدَّثَنَا خَلَّادُ بْنُ يَحْيَى قَالَ حَدَّثَنَا إِبْرَاهِيمُ بْنُ نَافِعٍ عَنْ الْحَسَنِ بْنِ مُسْلِمٍ عَنْ صَفِيَّةَ بِنْتِ شَيْبَةَ عَنْ عَائِشَةَ قَالَتْكُنَّا إِذَا أَصَابَتْ إِحْدَانَا جَنَابَةٌ أَخَذَتْ بِيَدَيْهَا ثَلَاثًا فَوْقَ رَأْسِهَا ثُمَّ تَأْخُذُ بِيَدِهَا عَلَى شِقِّهَا الْأَيْمَنِ وَبِيَدِهَا الْأُخْرَى عَلَى شِقِّهَا الْأَيْسَرِ","id":"Telah menceritakan kepada kami [Khallad bin Yahya] berkata, telah menceritakan kepada kami [Ibrahim bin Nafi'] dari [Al Hasan bin Muslim] dari [Shafiyah binti Syaibah] dari ['Aisyah] berkata, \"Jika salah seorang dari kami mengalami haid, maka ia mengambil air dengan kedua tangannya dan disiramkan ke atas kepala, lalu mengambil air dengan tangannya dan disiramkan ke bagian badan sebelah kanan, lalu kembali mengambil air dengan tangannya yang lain dan menyiramkannya ke bagian badan sebelah kiri.\""},"269":{"ar":"حَدَّثَنَا إِسْحَاقُ بْنُ نَصْرٍ قَالَ حَدَّثَنَا عَبْدُ الرَّزَّاقِ عَنْ مَعْمَرٍ عَنْ هَمَّامِ بْنِ مُنَبِّهٍ عَنْ أَبِي هُرَيْرَةَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ كَانَتْ بَنُو إِسْرَائِيلَ يَغْتَسِلُونَ عُرَاةً يَنْظُرُ بَعْضُهُمْ إِلَى بَعْضٍ وَكَانَ مُوسَى صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَغْتَسِلُ وَحْدَهُ فَقَالُوا وَاللَّهِ مَا يَمْنَعُ مُوسَى أَنْ يَغْتَسِلَ مَعَنَا إِلَّا أَنَّهُ آدَرُ فَذَهَبَ مَرَّةً يَغْتَسِلُ فَوَضَعَ ثَوْبَهُ عَلَى حَجَرٍ فَفَرَّ الْحَجَرُ بِثَوْبِهِ فَخَرَجَ مُوسَى فِي إِثْرِهِ يَقُولُ ثَوْبِي يَا حَجَرُ حَتَّى نَظَرَتْ بَنُو إِسْرَائِيلَ إِلَى مُوسَى فَقَالُوا وَاللَّهِ مَا بِمُوسَى مِنْ بَأْسٍ وَأَخَذَ ثَوْبَهُ فَطَفِقَ بِالْحَجَرِ ضَرْبًا فَقَالَ أَبُو هُرَيْرَةَ وَاللَّهِ إِنَّهُ لَنَدَبٌ بِالْحَجَرِ سِتَّةٌ أَوْ سَبْعَةٌ ضَرْبًا بِالْحَجَرِ","id":"Telah menceritakan kepada kami [Ishaq bin Nashir] berkata, telah menceritakan kepada kami [Abdurrazaq] dari [Ma'mar] dari [Hammam bin Munabbih] dari [Abu Hurairah] dari Nabi shallallahu 'alaihi wasallam bersabda: \"Orang-orang bani Israil jika mandi maka mereka mandi dengan telanjang, hingga sebagian melihat sebagian yang lainnya. Sedangkan Nabi Musa 'Alaihis Salam lebih suka mandi sendirian. Maka mereka pun berkata, \"Demi Allah, tidak ada menghalangi Musa untuk mandi bersama kita kecuali karena ia adalah seorang laki-laki yang kemaluannya kena hernia. Lalu pada suatu saat Musa pergi mandi dan meletakkan pakaiannya pada sebuah batu, lalu batu tersebut lari dengan membawa pakaiannya. Maka Musa lari mengejar batu tersebut sambil berkata 'Wahai batu, kembalikan pakaianku! ' sehingga orang-orang bani Israil melihat Musa. Mereka lalu berkata, 'Demi Allah, pada diri Musa tidak ada yang ganjil.' Musa kemudian mengambil pakaiannya dan memukul batu tersebut dengan satu pukulan.\" Abu Hurairah berkata, \"Demi Allah, sungguh pada batu tersebut terdapat bekas pukulan enam atau tujuh akibat pukulannya.\""},"270":{"ar":"وَعَنْ أَبِي هُرَيْرَةَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ بَيْنَا أَيُّوبُ يَغْتَسِلُ عُرْيَانًا فَخَرَّ عَلَيْهِ جَرَادٌ مِنْ ذَهَبٍ فَجَعَلَ أَيُّوبُ يَحْتَثِي فِي ثَوْبِهِ فَنَادَاهُ رَبُّهُ يَا أَيُّوبُ أَلَمْ أَكُنْ أَغْنَيْتُكَ عَمَّا تَرَى قَالَ بَلَى وَعِزَّتِكَ وَلَكِنْ لَا غِنَى بِي عَنْ بَرَكَتِكَوَرَوَاهُ إِبْرَاهِيمُ عَنْ مُوسَى بْنِ عُقْبَةَ عَنْ صَفْوَانَ بْنِ سُلَيْمٍ عَنْ عَطَاءِ بْنِ يَسَارٍ عَنْ أَبِي هُرَيْرَةَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ بَيْنَا أَيُّوبُ يَغْتَسِلُ عُرْيَانًا","id":"Dan (masih dari jalur periwayatan yang sama dengan hadits sebelumnya) dari [Abu Hurairah] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Tatkala Ayyub mandi dalam keadaan telanjang, tiba-tiba muncul belalang dari emas. Lalu Ayyub mengumpulkan dan memasukkannya ke dalam baju. Maka Raabnya memanggilnya: 'Wahai Ayyub, bukankah aku sudah memberimu kecukupan sebagaimana kau lihat? ' Ayyub menjawab, 'Benar, dan demi segala kemuliaan-Mu. Tetapi aku tidak pernah merasa puas dari limpahan barakah-Mu'.\" [Ibrahim] juga meriwayatkan dari [Musa bin 'Uqbah] dari [Shafwan bin Sulaim] dari ['Atha' bin Yasar] dari [Abu Hurairah] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Ketika Ayyub mandi dalam keadaan telanjang.\""},"271":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مَسْلَمَةَ بْنِ قَعْنَبٍ عَنْ مَالِكٍ عَنْ أَبِي النَّضْرِ مَوْلَى عُمَرَ بْنِ عُبَيْدِ اللَّهِ أَنَّ أَبَا مُرَّةَ مَوْلَى أُمِّ هَانِئٍ بِنْتِ أَبِي طَالِبٍ أَخْبَرَهُ أَنَّهُ سَمِعَ أُمَّ هَانِئٍ بِنْتَ أَبِي طَالِبٍ تَقُولُذَهَبْتُ إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَامَ الْفَتْحِ فَوَجَدْتُهُ يَغْتَسِلُ وَفَاطِمَةُ تَسْتُرُهُ فَقَالَ مَنْ هَذِهِ فَقُلْتُ أَنَا أُمُّ هَانِئٍ","id":"Telah menceritakan kepada kami ['Abdullah bin Maslamah bin Qa'nab] dari [Malik] dari [Abu An Nadlr] mantan budak 'Umar bin 'Ubaidullah, bahwa [Abu Murrah] mantan budak Ummu Hani' binti Abu Thalib, telah mengabarkan kepadanya, bahwa ia mendengar [Ummu Hani' binti Abu Thalib] berkata, \"Aku pergi menemui Rasulullah shallallahu 'alaihi wasallam saat pembukaan Kota Makkah, lalu aku dapati beliau sedang mandi dan Fatimah menutupinya. Beliau lalu bertanya: \"Siapa ini?\" Aku menjawab, \"Ummu Hani'.\""},"272":{"ar":"حَدَّثَنَا عَبْدَانُ قَالَ أَخْبَرَنَا عَبْدُ اللَّهِ قَالَ أَخْبَرَنَا سُفْيَانُ عَنْ الْأَعْمَشِ عَنْ سَالِمِ بْنِ أَبِي الْجَعْدِ عَنْ كُرَيْبٍ عَنْ ابْنِ عَبَّاسٍ عَنْ مَيْمُونَةَ قَالَتْسَتَرْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَهُوَ يَغْتَسِلُ مِنْ الْجَنَابَةِ فَغَسَلَ يَدَيْهِ ثُمَّ صَبَّ بِيَمِينِهِ عَلَى شِمَالِهِ فَغَسَلَ فَرْجَهُ وَمَا أَصَابَهُ ثُمَّ مَسَحَ بِيَدِهِ عَلَى الْحَائِطِ أَوْ الْأَرْضِ ثُمَّ تَوَضَّأَ وُضُوءَهُ لِلصَّلَاةِ غَيْرَ رِجْلَيْهِ ثُمَّ أَفَاضَ عَلَى جَسَدِهِ الْمَاءَ ثُمَّ تَنَحَّى فَغَسَلَ قَدَمَيْهِتَابَعَهُ أَبُو عَوَانَةَ وَابْنُ فُضَيْلٍ فِي السَّتْرِ","id":"Telah menceritakan kepada kami ['Abdan] berkata, telah mengabarkan kepada kami ['Abdullah] berkata, telah mengabarkan kepada kami [Sufyan] dari [Al A'masy] dari [Salim bin Abu Al Ja'd] dari [Kuraib] dari [Ibnu 'Abbas] dari [Maimunah] ia berkata, \"Aku menutupi Nabi shallallahu 'alaihi wasallam saat beliau sedang mandi junub. Beliau mencuci kedua tangannya, lalu dengan tangan kanannya beliau menuangkan air pada tangan kirinya, lalu mencuci kemaluannya dan apa yang terkena (mani). Beliau kemudian menggosokkan tangannya ke dinding atau tanah. Kemudian berwudlu sebagaimana wudlu untuk shalat kecuali kedua kakinya. Kemudian beliau mengguyurkan air ke seluruh badannya. Kemudian menyudahi dengan mencuci kedua kakinya.\" Hadits ini dikuatkan oleh [Abu 'Awanah] dan [Ibnu Fudlail] dalam masalah tabir (penutup).\""},"273":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ يُوسُفَ قَالَ أَخْبَرَنَا مَالِكٌ عَنْ هِشَامِ بْنِ عُرْوَةَ عَنْ أَبِيهِ عَنْ زَيْنَبَ بِنْتِ أَبِي سَلَمَةَ عَنْ أُمِّ سَلَمَةَ أُمِّ الْمُؤْمِنِينَ أَنَّهَا قَالَتْجَاءَتْ أُمُّ سُلَيْمٍ امْرَأَةُ أَبِي طَلْحَةَ إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَتْ يَا رَسُولَ اللَّهِ إِنَّ اللَّهَ لَا يَسْتَحْيِي مِنْ الْحَقِّ هَلْ عَلَى الْمَرْأَةِ مِنْ غُسْلٍ إِذَا هِيَ احْتَلَمَتْ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَعَمْ إِذَا رَأَتْ الْمَاءَ","id":"Telah menceritakan kepada kami ['Abdullah bin Yusuf] berkata, telah mengabarkan kepada kami [Malik] dari [Hisyam bin 'Urwah] dari [Bapaknya] dari [Zainab binti Abu Salamah] dari [Ummu Salamah] Ummul Mukminin, bahwa ia berkata, \"Ummu Sulaim, isteri Abu Thalhah, datang kepada Rasulullah shallallahu 'alaihi wasallam dan berkata, \"Wahai Rasulullah, sesungguhnya Allah tidak malu dengan kebenaran. Apakah seorang wanita wajib mandi bila bermimpi?\" Maka Rasulullah shallallahu 'alaihi wasallam menjawab: \"Ya. Jika dia melihat air.\""},"274":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ عَبْدِ اللَّهِ قَالَ حَدَّثَنَا يَحْيَى قَالَ حَدَّثَنَا حُمَيْدٌ قَالَ حَدَّثَنَا بَكْرٌ عَنْ أَبِي رَافِعٍ عَنْ أَبِي هُرَيْرَةَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَقِيَهُ فِي بَعْضِ طَرِيقِ الْمَدِينَةِ وَهُوَ جُنُبٌ فَانْخَنَسْتُ مِنْهُ فَذَهَبَ فَاغْتَسَلَ ثُمَّ جَاءَ فَقَالَ أَيْنَ كُنْتَ يَا أَبَا هُرَيْرَةَ قَالَ كُنْتُ جُنُبًا فَكَرِهْتُ أَنْ أُجَالِسَكَ وَأَنَا عَلَى غَيْرِ طَهَارَةٍ فَقَالَ سُبْحَانَ اللَّهِ إِنَّ الْمُسْلِمَ لَا يَنْجُسُ","id":"Telah menceritakan kepada kami ['Ali bin 'Abdullah] berkata, telah menceritakan kepada kami [Yahya] berkata, telah menceritakan kepada kami [Humaid] berkata, telah menceritakan kepada kami [Bakar] dari [Abu Rafi'] dari [Abu Hurairah], bahwa Nabi shallallahu 'alaihi wasallam pernah berjumpa dengannya di salah satu jalan Madinah, sementara ia dalam keadaan junub.\" Abu Hurairah berkata, 'Aku malu dan pergi diam-diam'. Abu Hurairah lalu pergi mandi dan kembali lagi setelah itu, beliau lalu bertanya: \"Kemana saja kamu tadi wahai Abu Hurairah?\" Abu Hurairah menjawab: \"Aku tadi junub. Dan aku tidak suka bersama Tuan sedang aku dalam keadaan tidak suci.\" Beliau pun bersabda: \"Subhaanallah! Sesungguhnya seorang Muslim itu tidak itu najis.\""},"275":{"ar":"حَدَّثَنَا عَبْدُ الْأَعْلَى بْنُ حَمَّادٍ قَالَ حَدَّثَنَا يَزِيدُ بْنُ زُرَيْعٍ قَالَ حَدَّثَنَا سَعِيدٌ عَنْ قَتَادَةَ أَنَّ أَنَسَ بْنَ مَالِكٍ حَدَّثَهُمْأَنَّ نَبِيَّ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يَطُوفُ عَلَى نِسَائِهِ فِي اللَّيْلَةِ الْوَاحِدَةِ وَلَهُ يَوْمَئِذٍ تِسْعُ نِسْوَةٍ","id":"Telah menceritakan kepada kami ['Abdul A'la bin Hammad] telah menceritakan kepada kami [Abdul A'la bin Abdul A'la] berkata, telah menceritakan kepada kami [Yazid bin Zurai'] berkata, telah menceritakan kepada kami [Sa'id] dari [Qatadah] bahwa [Anas bin Malik] menceritakan kepada mereka, bahwa Nabi shallallahu 'alaihi wasallam menggilir semua isterinya dalam satu malam, padahal saat itu isteri beliau ada sembilan orang.\""},"276":{"ar":"حَدَّثَنَا عَيَّاشٌ قَالَ حَدَّثَنَا عَبْدُ الْأَعْلَى حَدَّثَنَا حُمَيْدٌ عَنْ بَكْرٍ عَنْ أَبِي رَافِعٍ عَنْ أَبِي هُرَيْرَةَ قَالَلَقِيَنِي رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَأَنَا جُنُبٌ فَأَخَذَ بِيَدِي فَمَشَيْتُ مَعَهُ حَتَّى قَعَدَ فَانْسَلَلْتُ فَأَتَيْتُ الرَّحْلَ فَاغْتَسَلْتُ ثُمَّ جِئْتُ وَهُوَ قَاعِدٌ فَقَالَ أَيْنَ كُنْتَ يَا أَبَا هِرٍّ فَقُلْتُ لَهُ فَقَالَ سُبْحَانَ اللَّهِ يَا أَبَا هِرٍّ إِنَّ الْمُؤْمِنَ لَا يَنْجُسُ","id":"Telah menceritakan kepada kami ['Ayyasy] berkata, telah menceritakan kepada kami ['Abdul A'la] telah menceritakan kepada kami [Humaid] dari [Bakar] dari [Abu Rafi'] dari [Abu Hurairah] berkata, \"Rasulullah shallallahu 'alaihi wasallam berjumpa dengan aku padahal aku dalam keadaan junub. Beliau menggandeng tanganku hingga aku pun berjalan bersama beliau hingga beliau duduk. Aku lantas pergi diam-diam kembali ke rumah untuk mandi. Kemudian kembali lagi dan beliau masih duduk. Beliau lalu bertanya: \"Kemana saja kamu tadi wahai Abu Hurairah?\" Maka aku ceritakan pada beliau. Beliau lalu bersabda: \"Subhaanallah! Wahai Abu Hurairah, seorang Muslim itu tidaklah najis.\""},"277":{"ar":"حَدَّثَنَا أَبُو نُعَيْمٍ قَالَ حَدَّثَنَا هِشَامٌ وَشَيْبَانُ عَنْ يَحْيَى بْنِ أَبِي كَثِيرٍ عَنْ أَبِي سَلَمَةَ قَالَ سَأَلْتُ عَائِشَةَأَكَانَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَرْقُدُ وَهُوَ جُنُبٌ قَالَتْ نَعَمْ وَيَتَوَضَّأُ","id":"Telah menceritakan kepada kami [Abu An Nu'aim] berkata, telah menceritakan kepada kami [Hisyam] dan [Syaiban] dari [Yahya bin Abu Katsir] dari [Abu Salamah] berkata, Aku bertanya kepada ['Aisyah], \"Apakah Nabi shallallahu 'alaihi wasallam tidur dalam keadaan junub?\" 'Aisyah menjawab, \"Ya, setelah berwudlu.\""},"278":{"ar":"حَدَّثَنَا قُتَيْبَةُ قَالَ حَدَّثَنَا اللَّيْثُ عَنْ نَافِعٍ عَنْ ��بْنِ عُمَرَأَنَّ عُمَرَ بْنَ الْخَطَّابِ سَأَلَ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَيَرْقُدُ أَحَدُنَا وَهُوَ جُنُبٌ قَالَ نَعَمْ إِذَا تَوَضَّأَ أَحَدُكُمْ فَلْيَرْقُدْ وَهُوَ جُنُبٌ","id":"Telah menceritakan kepada kami [Qutaibah] berkata, telah menceritakan kepada kami [Al Laits] dari [Nafi'] dari [Ibnu 'Umar] bahwa 'Umar bin Al Khaththab bertanya kepada Rasulullah shallallahu 'alaihi wasallam, \"Apakah boleh seorang dari kami tidur dalam keadaan dia junub?\" Rasulullah shallallahu 'alaihi wasallam menjawab: \"Ya. Jika salah seorang dari kalian berwudlu, maka hendaklah ia tidur meskipun dalam keadaan junub.\""},"279":{"ar":"حَدَّثَنَا يَحْيَى بْنُ بُكَيْرٍ قَالَ حَدَّثَنَا اللَّيْثُ عَنْ عُبَيْدِ اللَّهِ بْنِ أَبِي جَعْفَرٍ عَنْ مُحَمَّدِ بْنِ عَبْدِ الرَّحْمَنِ عَنْ عُرْوَةَ عَنْ عَائِشَةَ قَالَتْكَانَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا أَرَادَ أَنْ يَنَامَ وَهُوَ جُنُبٌ غَسَلَ فَرْجَهُ وَتَوَضَّأَ لِلصَّلَاةِ","id":"Telah menceritakan kepada kami [Yahya bin Bukair] berkata, telah menceritakan kepada kami [Al Laits] dari ['Ubaidullah bin Abu Ja'far] dari [Muhammad bin 'Abdurrahman] dari ['Urwah] dari ['Aisyah] berkata, \"Jika Nabi shallallahu 'alaihi wasallam hendak tidur saat dirinya dalam kondisi junub, maka beliau membasuh kemaluannya dan berwudlu sebagaimana wudlu untuk shalat.\""},"280":{"ar":"حَدَّثَنَا مُوسَى بْنُ إِسْمَاعِيلَ قَالَ حَدَّثَنَا جُوَيْرِيَةُ عَنْ نَافِعٍ عَنْ عَبْدِ اللَّهِ قَالَاسْتَفْتَى عُمَرُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَيَنَامُ أَحَدُنَا وَهُوَ جُنُبٌ قَالَ نَعَمْ إِذَا تَوَضَّأَ","id":"Telah menceritakan kepada kami [Musa bin Isma'il] berkata, telah menceritakan kepada kami [Juwairiyah] dari [Nafi'] dari ['Abdullah] berkata, \"'Umar minta fatwa kepada Nabi shallallahu 'alaihi wasallam, \"Apakah salah seorang dari kami boleh tidur saat junub?\" Beliau menjawab: \"Ya. Jika ia berwudlu.\""},"281":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ يُوسُفَ قَالَ أَخْبَرَنَا مَالِكٌ عَنْ عَبْدِ اللَّهِ بْنِ دِينَارٍ عَنْ عَبْدِ اللَّهِ بْنِ عُمَرَ أَنَّهُ قَالَذَكَرَ عُمَرُ بْنُ الْخَطَّابِ لِرَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُ تُصِيبُهُ الْجَنَابَةُ مِنْ اللَّيْلِ فَقَالَ لَهُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ تَوَضَّأْ وَاغْسِلْ ذَكَرَكَ ثُمَّ نَمْ","id":"Telah menceritakan kepada kami ['Abdullah bin Yusuf] berkata, telah mengabarkan kepada kami [Malik] dari ['Abdullah bin Dinar] dari ['Abdullah bin 'Umar] bahwa ia berkata, \"'Umar bin Al Khaththab menceritakan kepada Rasulullah shallallahu 'alaihi wasallam bahwa ia junub di malam hari. Rasulullah shallallahu 'alaihi wasallam lalu berkata kepadanya: \"Wudlu dan cucilah kemaluanmu, kemudian tidurlah.\""},"282":{"ar":"حَدَّثَنَا مُعَاذُ بْنُ فَضَالَةَ قَالَ حَدَّثَنَا هِشَامٌ ح و حَدَّثَنَا أَبُو نُعَيْمٍ عَنْ هِشَامٍ عَنْ قَتَادَةَ عَنْ الْحَسَنِ عَنْ أَبِي رَافِعٍ عَنْ أَبِي هُرَيْرَةَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِذَا جَلَسَ بَيْنَ شُعَبِهَا الْأَرْبَعِ ثُمَّ جَهَدَهَا فَقَدْ وَجَبَ الْغَسْلُتَابَعَهُ عَمْرُو بْنُ مَرْزُوقٍ عَنْ شُعْبَةَ مِثْلَهُ وَقَالَ مُوسَى حَدَّثَنَا أَبَانُ قَالَ حَدَّثَنَا قَتَادَةُ أَخْبَرَنَا الْحَسَنُ مِثْلَهُ","id":"Telah menceritakan kepada kami [Mu'adz bin Fadlalah] berkata, telah menceritakan kepada kami [Hisyam]. (dalam jalur lain disebutkan) Telah menceritakan kepada kami [Abu Nu'aim] dari [Hisyam] dari [Qatadah] dari [Al Hasan] dari [Abu Rafi'] dari [Abu Hurairah] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Jika seseorang duduk di antara empat anggota badannya, lalu bersungguh-sungguh kepadanya, maka wajib banginya mandi.\" Hadits ini dikuatkan oleh ['Amru bin Marzuq] dari [Syu'bah] seperti hadits tersebut. Dan [Musa] berkata, telah menceritakan kepada kami [Aban] berkata, telah menceritakan kepada kami [Qatadah] telah mengabarkan kepada kami [Al Hasan] seperti hadits tersebut.\""},"283":{"ar":"حَدَّثَنَا أَبُو مَعْمَرٍ حَدَّثَنَا عَبْدُ الْوَارِثِ عَنْ الْحُسَيْنِ قَالَ يَحْيَى وَأَخْبَرَنِي أَبُو سَلَمَةَ أَنَّ عَطَاءَ بْنَ يَسَارٍ أَخْبَرَهُ أَنَّ زَيْدَ بْنَ خَالِدٍ الْجُهَنِيَّ أَخْبَرَهُ أَنَّهُ سَأَلَ عُثْمَانَ بْنَ عَفَّانَ فَقَالَأَرَأَيْتَ إِذَا جَامَعَ الرَّجُلُ امْرَأَتَهُ فَلَمْ يُمْنِ قَالَ عُثْمَانُ يَتَوَضَّأُ كَمَا يَتَوَضَّأُ لِلصَّلَاةِ وَيَغْسِلُ ذَكَرَهُ قَالَ عُثْمَانُ سَمِعْتُهُ مِنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَسَأَلْتُ عَنْ ذَلِكَ عَلِيَّ بْنَ أَبِي طَالِبٍ وَالزُّبَيْرَ بْنَ الْعَوَّامِ وَطَلْحَةَ بْنَ عُبَيْدِ اللَّهِ وَأُبَيَّ بْنَ كَعْبٍ رَضِيَ اللَّهُ عَنْهُمْ فَأَمَرُوهُ بِذَلِكَقَالَ يَحْيَى وَأَخْبَرَنِي أَبُو سَلَمَةَ أَنَّ عُرْوَةَ بْنَ الزُّبَيْرِ أَخْبَرَهُ أَنَّ أَبَا أَيُّوبَ أَخْبَرَهُ أَنَّهُ سَمِعَ ذَلِكَ مِنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah menceritakan kepada kami [Abu Ma'mar] telah menceritakan kepada kami ['Abdul Warits] dari [Al Husain], [Yahya] berkata, dan telah mengabarkan kepadaku [Abu Salamah] bahwa ['Atha' bin Yasar] mengabarkan kepadanya, bahwa [Zaid bin Khalid Al Juhaini] mengabarkan kepadanya, bahwa dia bertanya kepada ['Utsman bin 'Affan], \"Bagaimana pendapatmu bila seseorang berhubungan dengan isterinya tapi tidak keluar air mani?\" 'Utsman bin 'Affan menjawab, \"Hendaknya ia berwudlu sebagaimana wudlu untuk shalat, lalu mencuci kemaluannya.\" 'Utsman lalu melanjutkan ucapannya, \"Aku mendengarnya dari Rasulullah shallallahu 'alaihi wasallam, dan aku juga pernah bertanya kepada 'Ali bin Abu Thalib, Az Zubair bin Al 'Awam, Thalhah bin 'Ubaidullah dan Ubay bin Ka'b? radliallahu 'anhum. Mereka semua memerintahkan seperti itu.\" [Yahya] berkata, telah mengabarkan kepadaku [Abu Salamah] bahwa ['Urwah bin Az Zubair] mengabarkan kepadanya, bahwa [Abu Ayyub] mengabarkan kepadanya, bahwa ia mendengar seperti itu dari Rasulullah shallallahu 'alaihi wasallam.\""},"284":{"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا يَحْيَى عَنْ هِشَامِ بْنِ عُرْوَةَ قَالَ أَخْبَرَنِي أَبِي قَالَ أَخْبَرَنِي أَبُو أَيُّوبَ قَالَ أَخْبَرَنِي أُبَيُّ بْنُ كَعْبٍ أَنَّهُ قَالَيَا رَسُولَ اللَّهِ إِذَا جَامَعَ الرَّجُلُ الْمَرْأَةَ فَلَمْ يُنْزِلْ قَالَ يَغْسِلُ مَا مَسَّ الْمَرْأَةَ مِنْهُ ثُمَّ يَتَوَضَّأُ وَيُصَلِّيقَالَ أَبُو عَبْد اللَّهِ الْغَسْلُ أَحْوَطُ وَذَاكَ الْآخِرُ وَإِنَّمَا بَيَّنَّا لِاخْتِلَافِهِمْ","id":"Telah menceritakan kepada kami [Musaddad] telah menceritakan kepada kami [Yahya] dari [Hisyam bin 'Urwah] berkata, telah mengabarkan kepadaku [Bapakku] ia berkata, telah mengabarkan kepadaku [Abu Ayyub] berkata, telah mengabarkan kepadaku [Ubay bin Ka'b] bahwa ia berkata, \"Wahai Rasulullah, bagaimana jika seseorang berhubungan dengan isterinya namun tidak keluar (mani)?\" beliau menjawab: \"Hendaklah ia cuci apa yang mengenai isterinya (kemaluan), lalu wudlu dan shalat.\" Abu 'Abdullah Al Bukhari berkata, \"Mandi adalah sikap yang lebih berhati-hati.\" Inilah akhir dari penjelasan bab ini, dan kami telah menerangkan perbedaan pendapat mereka (para imam).\""},"285":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ عَبْدِ اللَّهِ قَالَ حَدَّثَنَا سُفْيَانُ قَالَ سَمِعْتُ عَبْدَ الرَّحْمَنِ بْنَ الْقَاسِمِ قَالَ سَمِعْتُ الْقَاسِمَ بْنَ مُحَمَّدٍ يَقُولُ سَمِعْتُ عَائِشَةَ تَقُولُخَرَجْنَا لَا نَرَى إِلَّا الْحَجَّ فَلَمَّا كُنَّا بِسَرِفَ حِضْتُ فَدَخَلَ عَلَيَّ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَأَنَا أَبْكِي قَالَ مَا لَكِ أَنُفِسْتِ قُلْتُ نَعَمْ قَالَ إِنَّ هَذَا أَمْرٌ كَتَبَهُ اللَّهُ عَلَى بَنَاتِ آدَمَ فَاقْضِي مَا يَقْضِي الْحَاجُّ غَيْرَ أَنْ لَا تَطُوفِي بِالْبَيْتِ قَالَتْ وَضَحَّى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ نِسَائِهِ بِالْبَقَرِ","id":"Telah menceritakan kepada kami ['Ali bin 'Abdullah] berkata, telah menceritakan kepada kami [Sufyan] berkata, Aku mendengar ['Abdurrahman bin Al Qasim] berkata, Aku mendengar [Al Qasim bin Muhammad] berkata, Aku mendengar ['Aisyah] berkata, \"Kami keluar dan tidak ada tujuan selain untuk ibadah haji. Ketika tiba di Sarif aku mengalami haid, kemudian Rasulullah shallallahu 'alaihi wasallam masuk menemuiku sementara aku sedang menangis. Beliau bertanya: \"Apa yang terjadi denganmu? Apakah kamu datang haid?\" Aku jawab, \"Ya.\" Beliau lalu bersabda: \"Sesungguhnya ini adalah perkara yang telah Allah tetapkan bagi kaum wanita dari anak cucu Adam. Lakukanlah apa yang dilakukan oleh orang-orang yang haji, kecuali thawaf di Ka'bah.\" 'Aisyah berkata, \"Kemudian Rasulullah shallallahu 'alaihi wasallam berkurban dengan menyembelih seekor sapi yang diniatkan untuk semua isterinya.\""},"286":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ يُوسُفَ قَالَ حَدَّثَنَا مَالِكٌ عَنْ هِشَامِ بْنِ عُرْوَةَ عَنْ أَبِيهِ عَنْ عَائِشَةَ قَالَتْكُنْتُ أُرَجِّلُ رَأْسَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَأَنَا حَائِضٌ","id":"Telah menceritakan kepada kami ['Abdullah bin Yusuf] berkata, telah menceritakan kepada kami [Malik] dari [Hisyam bin 'Urwah] dari [Bapaknya] dari ['Aisyah] berkata, \"Aku pernah menyisir rambut Rasulullah shallallahu 'alaihi wasallam, sementara saat itu aku sedang haid.\""},"287":{"ar":"حَدَّثَنَا إِبْرَاهِيمُ بْنُ مُوسَى قَالَ أَخْبَرَنَا هِشَامُ بْنُ يُوسُفَ أَنَّ ابْنَ جُرَيْجٍ أَخْبَرَهُمْ قَالَ أَخْبَرَنِي هِشَامُ بْنُ عُرْوَةَ عَنْ عُرْوَةَأَنَّهُ سُئِلَ أَتَخْدُمُنِي الْحَائِضُ أَوْ تَدْنُو مِنِّي الْمَرْأَةُ وَهِيَ جُنُبٌ فَقَالَ عُرْوَةُ كُلُّ ذَلِكَ عَلَيَّ هَيِّنٌ وَكُلُّ ذَلِكَ تَخْدُمُنِي وَلَيْسَ عَلَى أَحَدٍ فِي ذَلِكَ بَأْسٌ أَخْبَرَتْنِي عَائِشَةُ أَنَّهَا كَانَتْ تُرَجِّلُ تَعْنِي رَأْسَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَهِيَ حَائِضٌ وَرَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حِينَئِذٍ مُجَاوِرٌ فِي الْمَسْجِدِ يُدْنِي لَهَا رَأْسَهُ وَهِيَ فِي حُجْرَتِهَا فَتُرَجِّلُهُ وَهِيَ حَائِضٌ","id":"Telah menceritakan kepada kami [Ibrahim bin Musa] berkata, telah mengabarkan kepada kami [Hisyam bin Yusuf] bahwa [Ibnu Juraij] telah mengabarkan kepada mereka, ia berkata; telah mengabarkan kepadaku [Hisyam bin 'Urwah] dari ['Urwah], bahwa dia ditanya, \"Apakah wanita yang sedang haid boleh melayani aku, atau berdekatan denganku sedangkan dia junub?\" 'Urwah lalu menjawab, \"Bagiku semua itu mudah, dan setiap dari mereka boleh untuk membantuku, dan seseorang tidak berdosa karena hal itu. ['Aisyah] pernah mengabarkan kepadaku bahwa ia pernah menyisir rambut kepala Nabi shallallahu 'alaihi wasallam dalam keadaan haid. Saat itu Rasulullah shallallahu 'alaihi wasallam berada di sisi masjid, beliau mendekatkan kepalanya kepada Aisyah yang berada di dalam kamar dan dalam keadaan haid untuk menyisir rambut kepalanya.\""},"288":{"ar":"حَدَّثَنَا أَبُو نُعَيْمٍ الْفَضْلُ بْنُ دُكَيْنٍ سَمِعَ زُهَيْرًا عَنْ مَنْصُورِ بْنِ صَفِيَّةَ أَنَّ أُمَّهُ حَدَّثَتْهُ أَنَّ عَائِشَةَ حَدَّثَتْهَاأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يَتَّكِئُ فِي حَجْرِي وَأَنَا حَائِضٌ ثُمَّ يَقْرَأُ الْقُرْآنَ","id":"Telah menceritakan kepada kami [Abu Nu'aim Al Fadll bin Dukain] bahwa dia mendengar [Zuhair] dari [Manshur bin Shafiyah] bahwa [Ibunya] menceritakan kepadanya, bahwa ['Aisyah] menceritakan kepadanya, \"Nabi shallallahu 'alaihi wasallam menyandarkan badannya di pangkuanku membaca Al Qur'an, padahal saat itu aku sedang haid.\""},"289":{"ar":"حَدَّثَنَا الْمَكِّيُّ بْنُ إِبْرَاهِيمَ قَالَ حَدَّثَنَا هِشَامٌ عَنْ يَحْيَى بْنِ أَبِي كَثِيرٍ عَنْ أَبِي سَلَمَةَ أَنَّ زَيْنَبَ بِنْتَ أُمِّ سَلَمَةَ حَدَّثَتْهُ أَنَّ أُمَّ سَلَمَةَ حَدَّثَتْهَا قَالَتْبَيْنَا أَنَا مَعَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مُضْطَجِعَةٌ فِي خَمِيصَةٍ إِذْ حِضْتُ فَانْسَلَلْتُ فَأَخَذْتُ ثِيَابَ حِيضَتِي قَالَ أَنُفِسْتِ قُلْتُ نَعَمْ فَدَعَانِي فَاضْطَجَعْتُ مَعَهُ فِي الْخَمِيلَةِ","id":"Telah menceritakan kepada kami [Al Makki bin Ibrahim] berkata, telah menceritakan kepadaku [Hisyam] dari [Yahya bin Abu Katsir] dari [Abu Salamah] bahwa [Zainab binti Ummu Salamah] menceritakan kepadanya, bahwa [Ummu Salamah] berkata, \"Aku dan Nabi shallallahu 'alaihi wasallam berbaring dalam selimut, kemudian aku mengeluarkan darah haid hingga aku pun berlalu dengan diam-diam seraya membawa kain yang terkena darah haidku. Beliau bertanya: \"Apakah kamu sedang haid?\" Aku jawab, \"Ya.\" Beliau lalu memanggilku, maka aku pun berbaring bersama beliau dalam kain tebal.\""},"290":{"ar":"حَدَّثَنَا قَبِيصَةُ قَالَ حَدَّثَنَا سُفْيَانُ عَنْ مَنْصُورٍ عَنْ إِبْرَاهِيمَ عَنْ الْأَسْوَدِ عَنْ عَائِشَةَ قَالَتْكُنْتُ أَغْتَسِلُ أَنَا وَالنَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِنْ إِنَاءٍ وَاحِدٍ كِلَانَا جُنُبٌ وَكَانَ يَأْمُرُنِي فَأَتَّزِرُ فَيُبَاشِرُنِي وَأَنَا حَائِضٌ وَكَانَ يُخْرِجُ رَأْسَهُ إِلَيَّ وَهُوَ مُعْتَكِفٌ فَأَغْسِلُهُ وَأَنَا حَائِضٌ","id":"Telah menceritakan kepada kami [Qabishah] berkata, telah menceritakan kepada kami [Sufyan] dari [Manshur] dari [Ibrahim] dari [Al Aswad] dari ['Aisyah] berkata, \"Aku dan Nabi shallallahu 'alaihi wasallam pernah mandi bersama dari satu bejana. Saat itu kami berdua sedang junub. Beliau juga pernah memerintahkan aku mengenakan kain, lalu beliau mencumbuiku sementara aku sedang haid. Beliau juga pernah mendekatkan kepalanya kepadaku saat beliau i'tikaf, aku lalu basuh kepalanya padahal saat itu aku sedang haid.\""},"291":{"ar":"حَدَّثَنَا إِسْمَاعِيلُ بْنُ خَلِيلٍ قَالَ أَخْبَرَنَا عَلِيُّ بْنُ مُسْهِرٍ قَالَ أَخْبَرَنَا أَبُو إِسْحَاقَ هُوَ الشَّيْبَانِيُّ عَنْ عَبْدِ الرَّحْمَنِ بْنِ الْأَسْوَدِ عَنْ أَبِيهِ عَنْ عَائِشَةَ قَالَتْكَانَتْ إِحْدَانَا إِذَا كَانَتْ حَائِضًا فَأَرَادَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنْ يُبَاشِرَهَا أَمَرَهَا أَنْ تَتَّزِرَ فِي فَوْرِ حَيْضَتِهَا ثُمَّ يُبَاشِرُهَا قَالَتْ وَأَيُّكُمْ يَمْلِكُ إِرْبَهُ كَمَا كَانَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَمْلِكُ إِرْبَهُتَابَعَهُ خَالِدٌ وَجَرِيرٌ عَنْ الشَّيْبَانِيِّ","id":"Telah menceritakan kepada kami [Isma'il bin Khalil] berkata, telah mengabarkan kepada kami ['Ali bin Mushir] berkata, telah mengabarkan kepada kami [Abu Ishaq] -yaitu Asy Syaibani- dari ['Abdurrahman bin Al Aswad] dari [Bapaknya] dari ['Aisyah] ia berkata, \"Jika salah seorang dari kami sedang mengalami haid dan Rasulullah shallallahu 'alaihi wasallam berkeinginan untuk bermesraan, beliau memerintahkan untuk mengenakan kain, lalu beliau pun mencumbuinya.\" 'Aisyah berkata, \"Padahal, siapakah di antara kalian yang mampu menahan hasratnya sebagaimana Rasulullah shallallahu 'alaihi wasallam menahan.\" Hadits ini dikuatkan oleh [Khalid] dan [Jarir] dari [Asy Syaibani].\""},"292":{"ar":"حَدَّثَنَا أَبُو النُّعْمَانِ قَالَ حَدَّثَنَا عَبْدُ الْوَاحِدِ قَالَ حَدَّثَنَا الشَّيْبَانِيُّ قَالَ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ شَدَّادٍ قَالَ سَمِعْتُ مَيْمُونَةَ تَقُولُكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا أَرَادَ أَنْ يُبَاشِرَ امْرَأَةً مِنْ نِسَائِهِ أَمَرَهَا فَاتَّزَرَتْ وَهِيَ حَائِضٌوَرَوَاهُ سُفْيَانُ عَنْ الشَّيْبَانِيِّ","id":"Telah menceritakan kepada kami [Abu An Nu'man] berkata, telah menceritakan kepada kami ['Abdul Wahid] berkata, telah menceritakan kepada kami [Asy Syaibani] berkata, telah menceritakan kepada kami ['Abdullah bin Syadad] berkata, Aku mendengar [Maimunah] berkata, \"Jika Rasulullah shallallahu 'alaihi wasallam ingin mencumbu salah seorang dari isterinya, beliau memerintahkannya untuk mengenakan sarung. Maka ia pun mengenakan sarung, sementara ia sedang haid.\" [Sufan] juga meriwayatkannya dari [Asy Syaibani]."},"293":{"ar":"حَدَّثَنَا سَعِيدُ بْنُ أَبِي مَرْيَمَ قَالَ أَخْبَرَنَا مُحَمَّدُ بْنُ جَعْفَرٍ قَالَ أَخْبَرَنِي زَيْدٌ هُوَ ابْنُ أَسْلَمَ عَنْ عِيَاضِ بْنِ عَبْدِ اللَّهِ عَنْ أَبِي سَعِيدٍ الْخُدْرِيِّ قَالَخَرَجَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي أَضْحَى أَوْ فِطْرٍ إِلَى الْمُصَلَّى فَمَرَّ عَلَى النِّسَاءِ فَقَالَ يَا مَعْشَرَ النِّسَاءِ تَصَدَّقْنَ فَإِنِّي أُرِيتُكُنَّ أَكْثَرَ أَهْلِ النَّارِ فَقُلْنَ وَبِمَ يَا رَسُولَ اللَّهِ قَالَ تُكْثِرْنَ اللَّعْنَ وَتَكْفُرْنَ الْعَشِيرَ مَا رَأَيْتُ مِنْ نَاقِصَاتِ عَقْلٍ وَدِينٍ أَذْهَبَ لِلُبِّ الرَّجُلِ الْحَازِمِ مِنْ إِحْدَاكُنَّ قُلْنَ وَمَا نُقْصَانُ دِينِنَا وَعَقْلِنَا يَا رَسُولَ اللَّهِ قَالَ أَلَيْسَ شَهَادَةُ الْمَرْأَةِ مِثْلَ نِصْفِ شَهَادَةِ الرَّجُلِ قُلْنَ بَلَى قَالَ فَذَلِكِ مِنْ نُقْصَانِ عَقْلِهَا أَلَيْسَ إِذَا حَاضَتْ لَمْ تُصَلِّ وَلَمْ تَصُمْ قُلْنَ بَلَى قَالَ فَذَلِكِ مِنْ نُقْصَانِ دِينِهَا","id":"Telah menceritakan kepada kami [Sa'id bin Abu Maryam] berkata, telah mengabarkan kepada kami [Muhammad bin Ja'far] berkata, telah mengabarkan kepadaku [Zaid] -yaitu Ibnu Aslam- dari ['Iyadl bin 'Abdullah] dari [Abu Sa'id Al Khudri] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam pada hari raya 'Iedul Adlha atau Fitri keluar menuju tempat shalat, beliau melewati para wanita seraya bersabda: \"Wahai para wanita! Hendaklah kalian bersedekahlah, sebab diperlihatkan kepadaku bahwa kalian adalah yang paling banyak menghuni neraka.\" Kami bertanya, \"Apa sebabnya wahai Rasulullah?\" beliau menjawab: \"Kalian banyak melaknat dan banyak mengingkari pemberian suami. Dan aku tidak pernah melihat dari tulang laki-laki yang akalnya lebih cepat hilang dan lemah agamanya selain kalian.\" Kami bertanya lagi, \"Wahai Rasulullah, apa tanda dari kurangnya akal dan lemahnya agama?\" Beliau menjawab: \"Bukankah persaksian seorang wanita setengah dari persaksian laki-laki?\" Kami jawab, \"Benar.\" Beliau berkata lagi: \"Itulah kekurangan akalnya. Dan bukankah seorang wanita bila dia sedang haid dia tidak shalat dan puasa?\" Kami jawab, \"Benar.\" Beliau berkata: \"Itulah kekurangan agamanya.\""},"294":{"ar":"حَدَّثَنَا أَبُو نُعَيْمٍ قَالَ حَدَّثَنَا عَبْدُ الْعَزِيزِ بْنُ أَبِي سَلَمَةَ عَنْ عَبْدِ الرَّحْمَنِ بْنِ الْقَاسِمِ عَنْ الْقَاسِمِ بْنِ مُحَمَّدٍ عَنْ عَائِشَةَ قَالَتْخَرَجْنَا مَعَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا نَذْكُرُ إِلَّا الْحَجَّ فَلَمَّا جِئْنَا سَرِفَ طَمِثْتُ فَدَخَلَ عَلَيَّ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَأَنَا أَبْكِي فَقَالَ مَا يُبْكِيكِ قُلْتُ لَوَدِدْتُ وَاللَّهِ أَنِّي لَمْ أَحُجَّ الْعَامَ قَالَ لَعَلَّكِ نُفِسْتِ قُلْتُ نَعَمْ قَالَ فَإِنَّ ذَلِكِ شَيْءٌ كَتَبَهُ اللَّهُ عَلَى بَنَاتِ آدَمَ فَافْعَلِي مَا يَفْعَلُ الْحَاجُّ غَيْرَ أَنْ لَا تَطُوفِي بِالْبَيْتِ حَتَّى تَطْهُرِي","id":"Telah menceritakan kepada kami [Abu Nu'aim] berkata, telah menceritakan kepadaku ['Abdul 'Aziz bin Abu Salamah] dari ['Abdurrahman bin 'Abdullah Al Qasim] dari [Al Qasim bin Muhammad] dari ['Aisyah] ia berkata, \"Kami keluar bersama Nabi shallallahu 'alaihi wasallam dan tidak ada yang kami ingat kecuali untuk menunaikan hajji. Ketika kami sampai di suatu tempat bernama Sarif aku mengalami haid. Lalu Nabi shallallahu 'alaihi wasallam masuk menemuiku saat aku sedang menangis. Maka beliau bertanya: \"Apa yang membuatmu menangis?\" Aku jawab, \"Demi Allah, pada tahun ini aku tidak bisa melaksanakan haji!\" Beliau berkata: \"Barangkali kamu mengalami haid?\" Aku jawab, \"Benar.\" Beliau pun bersabda: \"Yang demikian itu adalah perkara yang sudah Allah tetapkan buat puteri-puteri keturunan Adam. Maka lakukanlah apa yang dilakukan orang yang berhaji kecuali thawaf di Ka'bah hingga kamu suci.\""},"295":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ يُوسُفَ قَالَ أَخْبَرَنَا مَالِكٌ عَنْ هِشَامِ بْنِ عُرْوَةَ عَنْ أَبِيهِ عَنْ عَائِشَةَ أَنَّهَا قَالَتْقَالَتْ فَاطِمَةُ بِنْتُ أَبِي حُبَيْشٍ لِرَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَا رَسُولَ اللَّهِ إِنِّي لَا أَطْهُرُ أَفَأَدَعُ الصَّلَاةَ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّمَا ذَلِكِ عِرْقٌ وَلَيْسَ بِالْحَيْضَةِ فَإِذَا أَقْبَلَتْ الْحَيْضَةُ فَاتْرُكِي الصَّلَاةَ فَإِذَا ذَهَبَ قَدْرُهَا فَاغْسِلِي عَنْكِ الدَّمَ وَصَلِّي","id":"Telah menceritakan kepada kami ['Abdullah bin Yusuf] berkata, telah mengabarkan kepada kami [Malik] dari [Hisyam bin 'Urwah] dari [Bapaknya] dari ['Aisyah], bahwa ia berkata, \"Fatimah binti Abu Hubaisy berkata kepada Rasulullah shallallahu 'alaihi wasallam, \"Wahai Rasulullah, aku dalam keadaan tidak suci. Apakah aku boleh meninggalkan shalat?\" Rasulullah shallallahu 'alaihi wasallam lalu menjawab: \"Sesungguhnya itu adalah darah penyakit dan bukan darah haid. Jika haid kamu datang maka tingalkanlah shalat, dan jika telah berlalu masa-masa haid, maka bersihkanlah darah darimu lalu shalatlah.\""},"296":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ يُوسُفَ قَالَ أَخْبَرَنَا مَالِكٌ عَنْ هِشَامِ بْنِ عُرْوَةَ عَنْ فَاطِمَةَ بِنْتِ الْمُنْذِرِ عَنْ أَسْمَاءَ بِنْتِ أَبِي بَكْرٍ الصِّدِّيقِ أَنَّهَا قَالَتْسَأَلَتْ امْرَأَةٌ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَتْ يَا رَسُولَ اللَّهِ أَرَأَيْتَ إِحْدَانَا إِذَا أَصَابَ ثَوْبَهَا الدَّمُ مِنْ الْحَيْضَةِ كَيْفَ تَصْنَعُ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا أَصَابَ ثَوْبَ إِحْدَاكُنَّ الدَّمُ مِنْ الْحَيْضَةِ فَلْتَقْرُصْهُ ثُمَّ لِتَنْضَحْهُ بِمَاءٍ ثُمَّ لِتُصَلِّي فِيهِ","id":"Telah menceritakan kepada kami ['Abdullah bin Yusuf] berkata, telah mengabarkan kepada kami [Malik] dari [Hisam bin 'Urwah] dari [Fatimah binti Al Mundzir] dari [Asma' binti Abu Bakar Ash Shiddiq] berkata, \"Seorang wanita bertanya kepada Rasulullah shallallahu 'alaihi wasallam, katanya, \"Wahai Rasulullah, bagaimana pendapatmu bila seorang dari kami bajunya terkena darah haid. Apa yang harus dilakukannya?\" Rasulullah shallallahu 'alaihi wasallam lalu menjawab: \"Jika darah haid mengenai pakaian seorang dari kalian, maka hendaklah ia bersihkan darah yang mengenainya, lalu hendaklah ia percikkan air padanya, kemudian hendaklah ia shalat dengannya.\""},"297":{"ar":"حَدَّثَنَا أَصْبَغُ قَالَ أَخْبَرَنِي ابْنُ وَهْبٍ قَالَ أَخْبَرَنِي عَمْرُو بْنُ الْحَارِثِ عَنْ عَبْدِ الرَّحْمَنِ بْنِ الْقَاسِمِ حَدَّثَهُ عَنْ أَبِيهِ عَنْ عَائِشَةَ قَالَتْكَانَتْ إِحْدَانَا تَحِيضُ ثُمَّ تَقْتَرِصُ الدَّمَ مِنْ ثَوْبِهَا عِنْدَ طُهْرِهَا فَتَغْسِلُهُ وَتَنْضَحُ عَلَى سَائِرِهِ ثُمَّ تُصَلِّي فِيهِ","id":"Telah menceritakan kepada kami [Ashbagh] berkata, telah mengabarkan kepadaku [Ibnu Wahb] berkata, telah mengabarkan kepadaku ['Amru bin Al Harits] dari ['Abdurrahman bin Al Qasim] bahwa ia menceritakan kepadanya dari [Bapaknya] dari ['Aisyah] berkata, \"Salah seorang dari kami mengalami haid, kemudian saat telah suci darah tersebut ia bersihkan, kemudian kain tersebut ia cuci dan bersihkan, kemudian ia shalat dengan menggunakan kain tersebut.\""},"298":{"ar":"حَدَّثَنَا إِسْحَاقُ قَالَ حَدَّثَنَا خَالِدُ بْنُ عَبْدِ اللَّهِ عَنْ خَالِدٍ عَنْ عِكْرِمَةَ عَنْ عَائِشَةَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ اعْتَكَفَ مَعَهُ بَعْضُ نِسَائِهِ وَهِيَ مُسْتَحَاضَةٌ تَرَى الدَّمَ فَرُبَّمَا وَضَعَتْ الطَّسْتَ تَحْتَهَا مِنْ الدَّمِ وَزَعَمَ أَنَّ عَائِشَةَ رَأَتْ مَاءَ الْعُصْفُرِ فَقَالَتْ كَأَنَّ هَذَا شَيْءٌ كَانَتْ فُلَانَةُ تَجِدُهُ","id":"Telah menceritakan kepada kami [Ishaq] berkata, telah menceritakan kepada kami [Khalid bin 'Abdullah] dari [Khalid] dari ['Ikrimah] dari ['Aisyah] berkata, \"Nabi shallallahu 'alaihi wasallam pernah beri'tikaf bersama dengan sebagian isteri-isterinya, sementara saat itu ia sedang mengalami istihadlah dan bisa melihat adanya darah (yang keluar). Dan kadang diletakkan sebuah baskom di bawahnya lantaran darah tersebut. Dan Ikrimah mengklaim bahwa 'Aisyah melihat cairan berwarna kekuningan, lalu ia berkata, \"Seakan ini adalah sesuatu yang pernah dialami oleh fulanah.\""},"299":{"ar":"حَدَّثَنَا قُتَيْبَةُ قَالَ حَدَّثَنَا يَزِيدُ بْنُ زُرَيْعٍ عَنْ خَالِدٍ عَنْ عِكْرِمَةَ عَنْ عَائِشَةَ قَالَتْاعْتَكَفَتْ مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ امْرَأَةٌ مِنْ أَزْوَاجِهِ فَكَانَتْ تَرَى الدَّمَ وَالصُّفْرَةَ وَالطَّسْتُ تَحْتَهَا وَهِيَ تُصَلِّي","id":"Telah menceritakan kepada kami [Qutaibah] berkata, telah menceritakan kepada kami [Yazid bin Zurai'] dari [Khalid] dari ['Ikrimah] dari ['Aisyah] berkata, \"Nabi shallallahu 'alaihi wasallam pernah beri'tikaf bersama salah seorang dari isterinya. Ia melihat ada darah dan cairan berwarna kekuningan, lalu di bawahnya diletakkan baskom sementara ia tetap mengerjakan shalat.\""},"300":{"ar":"حَدَّثَنَا مُسَدَّدٌ قَالَ حَدَّثَنَا مُعْتَمِرٌ عَنْ خَالِدٍ عَنْ عِكْرِمَةَ عَنْ عَائِشَةَأَنَّ بَعْضَ أُمَّهَاتِ الْمُؤْمِنِينَ اعْتَكَفَتْ وَهِيَ مُسْتَحَاضَةٌ","id":"Telah menceritakan kepada kami [Musaddad] berkata, telah menceritakan kepada kami [Mu'tamir] dari [Khalid] dari ['Ikrimah] dari ['Aisyah] berkata, \"Sebagian Ummul Mukminin melakukan iktikaf sementara mereka mengeluarkan darah istihadlah.\""},"301":{"ar":"حَدَّثَنَا أَبُو نُعَيْمٍ قَالَ حَدَّثَنَا إِبْرَاهِيمُ بْنُ نَافِعٍ عَنْ ابْنِ أَبِي نَجِيحٍ عَنْ مُجَاهِدٍ قَالَ قَالَتْ عَائِشَةُمَا كَانَ لِإِحْدَانَا إِلَّا ثَوْبٌ وَاحِدٌ تَحِيضُ فِيهِ فَإِذَا أَصَابَهُ شَيْءٌ مِنْ دَمٍ قَالَتْ بِرِيقِهَا فَقَصَعَتْهُ بِظُفْرِهَا","id":"Telah menceritakan kepada kami [Abu Nu'aim] berkata, telah menceritakan kepada kami [Ibrahim bin Nafi'] dari [Ibnu Abu Najih] dari [Mujahid] berkata, ['Aisyah] berkata, \"Tidaklah ada seorang dari kami kecuali memiliki satu baju yang saat mengalami haid. Jika baju tersebut terkena darah haid, ia dia basahi dengan air ludahnya lalu membersihkanya dengan kukunya.\""},"302":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ عَبْدِ الْوَهَّابِ قَالَ حَدَّثَنَا حَمَّادُ بْنُ زَيْدٍ عَنْ أَيُّوبَ عَنْ حَفْصَةَ قَالَ أَبُو عَبْد اللَّهِ أَوْ هِشَامِ بْنِ حَسَّانَ عَنْ حَفْصَةَ عَنْ أُمِّ عَطِيَّةَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَتْ كُنَّا نُنْهَى أَنْ نُحِدَّ عَلَى مَيِّتٍ فَوْقَ ثَلَاثٍ إِلَّا عَلَى زَوْجٍ أَرْبَعَةَ أَشْهُرٍ وَعَشْرًا وَلَا نَكْتَحِلَ وَلَا نَتَطَيَّبَ وَلَا نَلْبَسَ ثَوْبًا مَصْبُوغًا إِلَّا ثَوْبَ عَصْبٍ وَقَدْ رُخِّصَ لَنَا عِنْدَ الطُّهْرِ إِذَا اغْتَسَلَتْ إِحْدَانَا مِنْ مَحِيضِهَا فِي نُبْذَةٍ مِنْ كُسْتِ أَظْفَارٍ وَكُنَّا نُنْهَى عَنْ اتِّبَاعِ الْجَنَائِزِقَالَ أَبُو عَبْد اللَّهِ رَوَاهُ هِشَامُ بْنُ حَسَّانَ عَنْ حَفْصَةَ عَنْ أُمِّ عَطِيَّةَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah menceritakan kepada kami ['Abdullah bin 'Abdul Wahhab] berkata, telah menceritakan kepada kami [Hammad bin Zaid] dari [Ayyub] dari [Hafshah] berkata, [Abu 'Abdullah atau Hisyam bin Hassan] berkata dari [Hafshah] dari [Ummu 'Athiyah] dari Nabi shallallahu 'alaihi wasallam, ia berkata, \"Kami dilarang berkabung atas kematian di atas tiga hari kecuali atas kematian suami, yaitu selama empat bulan sepuluh hari. Selama masa itu dia tidak boleh bersolek, memakai wewangian, memakai pakaian yang berwarna kecuali pakaian lurik (dari negeri Yaman). Dan kami diberi keringanan bila hendak mandi seusai haid untuk menggunakan sebatang kayu wangi. Dan kami juga dilarang mengantar jenazah.\" Abu 'Abdullah berkata, [Hisyam bin Hassan] meriwayatkan dari [Hafshah] dari [Ummu 'Athiyah] dari Nabi shallallahu 'alaihi wasallam.\""},"303":{"ar":"حَدَّثَنَا يَحْيَى قَالَ حَدَّثَنَا ابْنُ عُيَيْنَةَ عَنْ مَنْصُورِ بْنِ صَفِيَّةَ عَنْ أُمِّهِ عَنْ عَائِشَةَأَنَّ امْرَأَةً سَأَلَتْ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ غُسْلِهَا مِنْ الْمَحِيضِ فَأَمَرَهَا كَيْفَ تَغْتَسِلُ قَالَ خُذِي فِرْصَةً مِنْ مَسْكٍ فَتَطَهَّرِي بِهَا قَالَتْ كَيْفَ أَتَطَهَّرُ قَالَ تَطَهَّرِي بِهَا قَالَتْ كَيْفَ قَالَ سُبْحَانَ اللَّهِ تَطَهَّرِي فَاجْتَبَذْتُهَا إِلَيَّ فَقُلْتُ تَتَبَّعِي بِهَا أَثَرَ الدَّمِ","id":"Telah menceritakan kepada kami [Yahya] berkata, telah menceritakan kepada kami [Ibnu 'Uyainah] dari [Manshur bin Shafiyyah] dari [Ibunya] dari ['Aisyah], \"Seorang wanita bertanya kepada Nabi shallallahu 'alaihi wasallam tentang cara mandi dari haid. Beliau lalu memerintahkan wanita itu bagaimana cara mandi. Beliau bersabda: \"Ambillah sepotong kapas yang diberi wewangian lalu bersucilah.\" Wanita itu bertanya, \"Bagaimana aku bersucinya? Beliau menjawab: \"Bersucilah dengan kapas itu!\" Wanita itu berkata lagi, \"Bagaimana caranya aku bersuci?\" Beliau bersabda: \"Bersucilah dengan menggunakan kapas itu!\" Wanita itu bertanya lagi, \"Bagaimana caranya?\" Maka Beliau berkata, \"Subhaanallah. Bersucilah kamu!\" Lalu aku manarik wanita itu kearahku, lalu aku katakan, \"Kamu bersihkan sisa darahnya dengan kapas itu.\""},"304":{"ar":"حَدَّثَنَا مُسْلِمُ بْنُ إِبْرَاهِيمَ قَالَ حَدَّثَنَا وُهَيْبٌ حَدَّثَنَا مَنْصُورٌ عَنْ أُمِّهِ عَنْ عَائِشَةَأَنَّ امْرَأَةً مِنْ الْأَنْصَارِ قَالَتْ لِلنَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَيْفَ أَغْتَسِلُ مِنْ الْمَحِيضِ قَالَ خُذِي فِرْصَةً مُمَسَّكَةً فَتَوَضَّئِي ثَلَاثًا ثُمَّ إِنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ اسْتَحْيَا فَأَعْرَضَ بِوَجْهِهِ أَوْ قَالَ تَوَضَّئِي بِهَا فَأَخَذْتُهَا فَجَذَبْتُهَا فَأَخْبَرْتُهَا بِمَا يُرِيدُ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah menceritakan kepada kami [Muslim bin Ibrahim] berkata, telah menceritakan kepada kami [Wuhaib] telah menceritakan kepada kami [Manshur] dari [Ibunya] dari ['Aisyah], \"Seorang wanita Anshar bertanya kepada Nabi shallallahu 'alaihi wasallam, \"Bagaimana caranya aku bersuci dari haid?\" Beliau lalu menjawab: \"Ambillah sepotong kapas yang diberi wewangian lalu bersihkanlah tiga kali.\" Kemudian Nabi shallallahu 'alaihi wasallam merasa malu lalu memalingkan mukanya, atau beliau mengatakan: \"Berwudlulah dengan kapas itu.\" Aku lalu tarik wanita itu dan aku terangkan apa yang dimaksud oleh Nabi shallallahu 'alaihi wasallam.\""},"305":{"ar":"حَدَّثَنَا مُوسَى بْنُ إِسْمَاعِيلَ حَدَّثَنَا إِبْرَاهِيمُ حَدَّثَنَا ابْنُ شِهَابٍ عَنْ عُرْوَةَ أَنَّ عَائِشَةَ قَالَتْأَهْلَلْتُ مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي حَجَّةِ الْوَدَاعِ فَكُنْتُ مِمَّنْ تَمَتَّعَ وَلَمْ يَسُقْ الْهَدْيَ فَزَعَمَتْ أَنَّهَا حَاضَتْ وَلَمْ تَطْهُرْ حَتَّى دَخَلَتْ لَيْلَةُ عَرَفَةَ فَقَالَتْ يَا رَسُولَ اللَّهِ هَذِهِ لَيْلَةُ عَرَفَةَ وَإِنَّمَا كُنْتُ تَمَتَّعْتُ بِعُمْرَةٍ فَقَالَ لَهَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ انْقُضِي رَأْسَكِ وَامْتَشِطِي وَأَمْسِكِي عَنْ عُمْرَتِكِ فَفَعَلْتُ فَلَمَّا قَضَيْتُ الْحَجَّ أَمَرَ عَبْدَ الرَّحْمَنِ لَيْلَةَ الْحَصْبَةِ فَأَعْمَرَنِي مِنْ التَّنْعِيمِ مَكَانَ عُمْرَتِي الَّتِي نَسَكْتُ","id":"Telah menceritakan kepada kami [Musa bin Isma'il] telah menceritakan kepada kami [Ibrahim] telah menceritakan kepada kami [Ibnu Syihab] dari ['Urwah] bahwa ['Aisyah] berkata, \"Aku bertalbiyah (memulai haji) bersama Rasulullah shallallahu 'alaihi wasallam pada haji Wada'. Dan aku adalah di antara orang yang melaksanakannya dengan cara tamattu' namun tidak membawa hewan sembelihan.\" Aisyah menyadari bahwa dirinya mengalami haid dan belum bersuci hingga tiba malam 'Arafah. Maka 'Aisyah berkata, \"Wahai Rasulullah, malam ini adalah malam 'Arafah sedangkan aku melaksanakan tamattu' dengan Umrah lebih dahulu?\" Maka bersabdalah Rasulullah shallallahu 'alaihi wasallam kepadanya: \"Urai dam sisirlah rambut kepalamu, lalu tahanlah Umrahmu.\" Aku lalu laksanakan hal itu. Setelah aku menyelesaikan haji, beliau memerintahkan 'Abdurrahman pada malam hashbah (Malam di Muzdalifah) untuk melakukan Umrah buatku dari Tan'im, tempat dimana aku mulai melakukan manasikku.\""},"306":{"ar":"حَدَّثَنَا عُبَيْدُ بْنُ إِسْمَاعِيلَ قَالَ حَدَّثَنَا أَبُو أُسَامَةَ عَنْ هِشَامٍ عَنْ أَبِيهِ عَنْ عَائِشَةَ قَالَتْخَرَجْنَا مُوَافِينَ لِهِلَالِ ذِي الْحِجَّةِ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ أَحَبَّ أَنْ يُهِلَّ بِعُمْرَةٍ فَلْيُهْلِلْ فَإِنِّي لَوْلَا أَنِّي أَهْدَيْتُ لَأَهْلَلْتُ بِعُمْرَةٍ فَأَهَلَّ بَعْضُهُمْ بِعُمْرَةٍ وَأَهَلَّ بَعْضُهُمْ بِحَجٍّ وَكُنْتُ أَنَا مِمَّنْ أَهَلَّ بِعُمْرَةٍ فَأَدْرَكَنِي يَوْمُ عَرَفَةَ وَأَنَا حَائِضٌ فَشَكَوْتُ إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ دَعِي عُمْرَتَكِ وَانْقُضِي رَأْسَكِ وَامْتَشِطِي وَأَهِلِّي بِحَجٍّ فَفَعَلْتُ حَتَّى إِذَا كَانَ لَيْلَةُ الْحَصْبَةِ أَرْسَلَ مَعِي أَخِي عَبْدَ الرَّحْمَنِ بْنَ أَبِي بَكْرٍ فَخَرَجْتُ إِلَى التَّنْعِيمِ فَأَهْلَلْتُ بِعُمْرَةٍ مَكَانَ عُمْرَتِيقَالَ هِشَامٌ وَلَمْ يَكُنْ فِي شَيْءٍ مِنْ ذَلِكَ هَدْيٌ وَلَا صَوْمٌ وَلَا صَدَقَةٌ","id":"Telah menceritakan kepada kami ['Ubaid bin Isma'il] berkata, telah menceritakan kepada kami [Abu Usamah] dari [Hisyam] dari [Bapaknya] dari ['Aisyah] berkata, \"Kami keluar bertepatan saat nampak hilal bulan Dzul Hijjah. Rasulullah shallallahu 'alaihi wasallam lalu bersabda: \"Siapa yang ingin memulai haji dengan Umrah hendaklah ia lakukan. Sekiranya aku tidak membawa hewan sembelihan, aku lebih suka melakukan Umrah lebih dahulu.\" Maka sebagian para sahabat ada yang memulai dengan Umrah dan ada yang memulai dengan haji. Sedang aku termasuk di antara yang mulai dengan Umrah. Maka ketika hari Arafah aku mengalami haid, aku lalu mengadukan hal itu kepada Nabi shallallahu 'alaihi wasallam, beliau lalu bersabda: \"Tinggalkanlah Umrahmu. Uraikan rambut kepalamu lalu sisirlah, kemudian mulailah talbiah dengan haji.\" Maka aku pun laksanakan perintah beliau, hingga ketika tiba malam Hashbah (Malam di Muzdalifah), beliau memerintahkan 'Abdurrahman bin Abu Bakar untuk menemaniku. Maka aku keluar menuju Tan'im, lalu bertalbiah dengan Umrah sebagai ganti Umrahku sebelumnya.\" Hisyam berkata, \"Dan dalam hal itu tidak ada denda baik berupa hadyu (menyembelih), puasa atau pun sedekah.\""},"307":{"ar":"حَدَّثَنَا مُسَدَّدٌ قَالَ حَدَّثَنَا حَمَّادٌ عَنْ عُبَيْدِ اللَّهِ بْنِ أَبِي بَكْرٍ عَنْ أَنَسِ بْنِ مَالِكٍعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِنَّ اللَّهَ عَزَّ وَجَلَّ وَكَّلَ بِالرَّحِمِ مَلَكًا يَقُولُ يَا رَبِّ نُطْفَةٌ يَا رَبِّ عَلَقَةٌ يَا رَبِّ مُضْغَةٌ فَإِذَا أَرَادَ أَنْ يَقْضِيَ خَلْقَهُ قَالَ أَذَكَرٌ أَمْ أُنْثَى شَقِيٌّ أَمْ سَعِيدٌ فَمَا الرِّزْقُ وَالْأَجَلُ فَيُكْتَبُ فِي بَطْنِ أُمِّهِ","id":"Telah menceritakan kepada kami [Musaddad] berkata, telah menceritakan kepada kami [Hammad] dari ['Ubaidullah bin Abu Bakar] dari [Anas bin Malik] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Sesungguhnya Allah Ta'ala menugaskan satu Malaikat dalam rahim seseorang. Malaikat itu berkata, 'Ya Rabb, (sekarang baru) sperma. Ya Rabb, segumpal darah!, Ya Rabb, segumpal daging! ' Maka apabila Allah berkehendak menetapkan ciptaan-Nya, Malaikat itu bertanya, 'Apakah laki-laki atau wanita, celaka atau bahagia, bagaimana dengan rizki dan ajalnya? ' Maka ditetapkanlah ketentuan takdirnya selagi berada dalam perut ibunya.\""},"308":{"ar":"حَدَّثَنَا يَحْيَى بْنُ بُكَيْرٍ قَالَ حَدَّثَنَا اللَّيْثُ عَنْ عُقَيْلٍ عَنْ ابْنِ شِهَابٍ عَنْ عُرْوَةَ عَنْ عَائِشَةَ قَالَتْخَرَجْنَا مَعَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي حَجَّةِ الْوَدَاعِ فَمِنَّا مَنْ أَهَلَّ بِعُمْرَةٍ وَمِنَّا مَنْ أَهَلَّ بِحَجٍّ فَقَدِمْنَا مَكَّةَ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ أَحْرَمَ بِعُمْرَةٍ وَلَمْ يُهْدِ فَلْيُحْلِلْ وَمَنْ أَحْرَمَ بِعُمْرَةٍ وَأَهْدَى فَلَا يُحِلُّ حَتَّى يُحِلَّ بِنَحْرِ هَدْيِهِ وَمَنْ أَهَلَّ بِحَجٍّ فَلْيُتِمَّ حَجَّهُ قَالَتْ فَحِضْتُ فَلَمْ أَزَلْ حَائِضًا حَتَّى كَانَ يَوْمُ عَرَفَةَ وَلَمْ أُهْلِلْ إِلَّا بِعُمْرَةٍ فَأَمَرَنِي النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنْ أَنْقُضَ رَأْسِي وَأَمْتَشِطَ وَأُهِلَّ بِحَجٍّ وَأَتْرُكَ الْعُمْرَةَ فَفَعَلْتُ ذَلِكَ حَتَّى قَضَيْتُ حَجِّي فَبَعَثَ مَعِي عَبْدَ الرَّحْمَنِ بْنَ أَبِي بَكْرٍ الصِّدِّيقِ وَأَمَرَنِي أَنْ أَعْتَمِرَ مَكَانَ عُمْرَتِي مِنْ التَّنْعِيمِ","id":"Telah menceritakan kepada kami [Yahya bin Bukair] berkata, telah menceritakan kepada kami [Al Laits] dari ['Uqail] dari [Ibnu Syihab] dari ['Urwah] dari ['Aisyah] berkata, \"Kami keluar bersama Rasulullah shallallahu 'alaihi wasallam pada saat haji Wada'. Di antara kami ada yang bertalbiah dengan Umrah dan ada pula yang bertalbiah dengan haji. Ketika kami sudah sampai di Makkah, Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa berihram dengan Umrah dan tidak membawa sembelihan, maka hendaklah dia bertahallul. Dan barangsiapa berihram dengan Umrah dan membawa sembelihan, maka janganlah bertahallul kecuali setelah menyembelih hewan pada hari Nahr (hari penyembelihan). Dan barangsiapa bertalbiah (memulai) dengan haji, hendaklah menyempurnakan hajinya.\" 'Aisyah berkata, \"Kemudian aku mengalami haid dan terus terjadi hingga hari 'Arafah, dan aku tidak bertalbiah kecuali dengan Umrah. Maka Nabi shallallahu 'alaihi wasallam memerintahkan aku untuk menguraikan (rambut) kepalaku dan menyisirnya, lalu bertalbiah dengan haji dan meninggalkan Umrah. Maka aku laksanakan hingga aku merampungkan hajiku. Kemudian beliau mengutus saudaraku, 'Abdurrahman bin Abu Bakar untuk menemaniku dan memerintahkan aku agar aku berumrah dari Tan'im sebagai ganti Umrahku sebelumnya.\""},"309":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مُحَمَّدٍ قَالَ حَدَّثَنَا سُفْيَانُ عَنْ هِشَامٍ عَنْ أَبِيهِ عَنْ عَائِشَةَأَنَّ فَاطِمَةَ بِنْتَ أَبِي حُبَيْشٍ كَانَتْ تُسْتَحَاضُ فَسَأَلَتْ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ ذَلِكِ عِرْقٌ وَلَيْسَتْ بِالْحَيْضَةِ فَإِذَا أَقْبَلَتْ الْحَيْضَةُ فَدَعِي الصَّلَاةَ وَإِذَا أَدْبَرَتْ فَاغْتَسِلِي وَصَلِّي","id":"Telah menceritakan kepada kami ['Abdullah bin Muhammad] berkata, telah menceritakan kepada kami [Sufyan] dari [Hisyam] dari [Bapaknya] dari ['Aisyah] bahwa Fatimah binti Abu Hubaisy mengalami istihadlah (mengeluarkan datah penyakit). Maka aku bertanya kepada Nabi shallallahu 'alaihi wasallam, dan beliau menjawab: \"Itu seperti keringat dan bukan darah haid. Jika haid datang maka tinggalkanlah shalat dan jika telah selesai mandilah dan shalatlah.\""},"310":{"ar":"حَدَّثَنَا مُوسَى بْنُ إِسْمَاعِيلَ قَالَ حَدَّثَنَا هَمَّامٌ قَالَ حَدَّثَنَا قَتَادَةُ قَالَ حَدَّثَتْنِي مُعَاذَةُأَنَّ امْرَأَةً قَالَتْ لِعَائِشَةَ أَتَجْزِي إِحْدَانَا صَلَاتَهَا إِذَا طَهُرَتْ فَقَالَتْ أَحَرُورِيَّةٌ أَنْتِ كُنَّا نَحِيضُ مَعَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَلَا يَأْمُرُنَا بِهِ أَوْ قَالَتْ فَلَا نَفْعَلُهُ","id":"Telah menceritakan kepada kami [Musa bin Isma'il] berkata, telah menceritakan kepada kami [Hammam] berkata, telah menceritakan kepada kami [Qatadah] berkata, telah menceritakan kepadaku [Mu'adzah], bahwa ada seorang wanita bertanya kepada ['Aisyah], \"Apakah seorang dari kita harus melaksanakan shalat yang ditinggalkannya bila sudah suci?\" 'Aisyah menjawab, \"Apakah kamu dari kelompok Khawarij! Sungguh kami pernah mengalami haid di sisi Nabi shallallahu 'alaihi wasallam, dan beliau tidak memerintahkan kami untuk itu.\" Atau Aisyah mengatakan, \"Kami tidak melakukannya (mengqadla`).\""},"311":{"ar":"حَدَّثَنَا سَعْدُ بْنُ حَفْصٍ قَالَ حَدَّثَنَا شَيْبَانُ عَنْ يَحْيَى عَنْ أَبِي سَلَمَةَ عَنْ زَيْنَبَ بِنْتِ أَبِي سَلَمَةَ حَدَّثَتْهُ أَنَّ أُمَّ سَلَمَةَ قَالَتْحِضْتُ وَأَنَا مَعَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي الْخَمِيلَةِ فَانْسَلَلْتُ فَخَرَجْتُ مِنْهَا فَأَخَذْتُ ثِيَابَ حِيضَتِي فَلَبِسْتُهَا فَقَالَ لِي رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنُفِسْتِ قُلْتُ نَعَمْ فَدَعَانِي فَأَدْخَلَنِي مَعَهُ فِي الْخَمِيلَةِ قَالَتْ وَحَدَّثَتْنِي أَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يُقَبِّلُهَا وَهُوَ صَائِمٌ وَكُنْتُ أَغْتَسِلُ أَنَا وَالنَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِنْ إِنَاءٍ وَاحِدٍ مِنْ الْجَنَابَةِ","id":"Telah menceritakan kepada kami [Sa'd bin Hafsh] berkata, telah menceritakan kepada kami [Syaiban] dari [Yahya] dari [Abu Salamah] dari [Zainab binti Abu Salamah] bahwa ia menceritakan kepadanya, bahwa [Ummu Salamah] berkata, \"Saat aku berada dalam satu selimut bersama Nabi shallallahu 'alaihi wasallam, aku mengeluarkan darah haid, kemudian pelan-pelan aku keluar dari selimut mengambil pakaian (khusus untuk haid) dan mengenakannya. Rasulullah shallallahu 'alaihi wasallam bertanya kepadaku: \"Apakah kamu sedang haid?\" Aku jawab, \"Ya.\" Beliau lalu memanggil dan mengajakku masuk ke dalam selimut.\" Zainab berkata, \"Ummu Salamah menceritakan kepadaku bahwa Nabi shallallahu 'alaihi wasallam juga menciumnya saat beliau sedang berpuasa. Ummu Salam berkata, \"Aku pernah mandi junub dalam satu bejana bersama Nabi shallallahu 'alaihi wasallam.\""},"312":{"ar":"حَدَّثَنَا مُعَاذُ بْنُ فَضَالَةَ قَالَ حَدَّثَنَا هِشَامٌ عَنْ يَحْيَى عَنْ أَبِي سَلَمَةَ عَنْ زَيْنَبَ بِنْتِ أَبِي سَلَمَةَ عَنْ أُمِّ سَلَمَةَ قَالَتْبَيْنَا أَنَا مَعَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مُضْطَجِعَةٌ فِي خَمِيلَةٍ حِضْتُ فَانْسَلَلْتُ فَأَخَذْتُ ثِيَابَ حِيضَتِي فَقَالَ أَنُفِسْتِ فَقُلْتُ نَعَمْ فَدَعَانِي فَاضْطَجَعْتُ مَعَهُ فِي الْخَمِيلَةِ","id":"Telah menceritakan kepada kami [Mu'adz bin Fadlalah] berkata, telah menceritakan kepada kami [Hisyam] dari [Yahya] dari [Abu Salamah] dari [Zainab binti Abu Salamah] dari [Ummu Salamah] berkata, \"Ketika aku berbaring bersama Nabi shallallahu 'alaihi wasallam dalam satu selimut aku mengalami haid. Maka aku pergi diam-diam dan mengambil baju khusus haidku, beliau bertanya: \"Apakah kamu sedang haid?\" Aku jawab, \"Ya.\" Beliau lalu memanggilku, maka aku pun berbaring bersamanya dalam satu selimut.\""},"313":{"ar":"حَدَّثَنَا مُحَمَّدٌ هُوَ ابْنُ سَلَامٍ قَالَ أَخْبَرَنَا عَبْدُ الْوَهَّابِ عَنْ أَيُّوبَ عَنْ حَفْصَةَ قَالَتْكُنَّا نَمْنَعُ عَوَاتِقَنَا أَنْ يَخْرُجْنَ فِي الْعِيدَيْنِ فَقَدِمَتْ امْرَأَةٌ فَنَزَلَتْ قَصْرَ بَنِي خَلَفٍ فَحَدَّثَتْ عَنْ أُخْتِهَا وَكَانَ زَوْجُ أُخْتِهَا غَزَا مَعَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ثِنْتَيْ عَشَرَةَ غَزْوَةً وَكَانَتْ أُخْتِي مَعَهُ فِي سِتٍّ قَالَتْ كُنَّا نُدَاوِي الْكَلْمَى وَنَقُومُ عَلَى الْمَرْضَى فَسَأَلَتْ أُخْتِي النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَعَلَى إِحْدَانَا بَأْسٌ إِذَا لَمْ يَكُنْ لَهَا جِلْبَابٌ أَنْ لَا تَخْرُجَ قَالَ لِتُلْبِسْهَا صَاحِبَتُهَا مِنْ جِلْبَابِهَا وَلْتَشْهَد الْخَيْرَ وَدَعْوَةَ الْمُسْلِمِينَ فَلَمَّا قَدِمَتْ أُمُّ عَطِيَّةَ سَأَلْتُهَا أَسَمِعْتِ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَتْ بِأَبِي نَعَمْ وَكَانَتْ لَا تَذْكُرُهُ إِلَّا قَالَتْ بِأَبِي سَمِعْتُهُ يَقُولُ يَخْرُجُ الْعَوَاتِقُ وَذَوَاتُ الْخُدُورِ أَوْ الْعَوَاتِقُ ذَوَاتُ الْخُدُورِ وَالْحُيَّضُ وَلْيَشْهَدْنَ الْخَيْرَ وَدَعْوَةَ الْمُؤْمِنِينَ وَيَعْتَزِلُ الْحُيَّضُ الْمُصَلَّى قَالَتْ حَفْصَةُ فَقُلْتُ الْحُيَّضُ فَقَالَتْ أَلَيْسَ تَشْهَدُ عَرَفَةَ وَكَذَا وَكَذَا","id":"Telah menceritakan kepada kami [Muhammad] -yaitu Ibnu Salam- berkata, telah mengabarkan kepada kami ['Abdul Wahhab] dari [Ayyub] dari [Hafshah] berkata, \"Dahulu kami melarang anak-anak gadis remaja kami ikut keluar untuk shalat pada dua hari raya. Hingga suatu hari ada seorang wanita mendatangi desa Qashra Banu Khalaf, wanita itu menceritakan bahwa suami dari saudara perempuannya pernah ikut berperang bersama Nabi shallallahu 'alaihi wasallam sebanyak dua belas peperangan, ia katakan, 'Saudaraku itu hidup bersama suaminya selama enam tahun.' Ia menceritakan, \"Dulu kami sering mengobati orang-orang yang terluka dan mengurus orang yang sakit.' Saudara perempuanku bertanya kepada Nabi shallallahu 'alaihi wasallam, \"Apakah berdosa bila seorang dari kami tidak keluar (mengikuti shalat 'Ied) karena tidak memiliki jilbab?\" Beliau menjawab: \"Hendaklah kawannya memakaikan jilbab miliknya untuknya (meminjamkan) agar mereka dapat menyaksikan kebaikan dan mendo'akan Kaum Muslimin.\" Ketika [Ummu 'Athiyah] tiba aku bertanya kepadanya, \"Apakah kamu mendengar langsung dari Nabi shallallahu 'alaihi wasallam?\" Ummu 'Athiyah menjawab, \"Ya. Demi bapakku!\" Ummu 'Athiyah tidak mengatakan tentang Nabi shallallahu 'alaihi wasallam kecuali hanya mengatakan 'Demi bapakku, aku mendengar beliau bersabda: \"Hendaklah para gadis remaja dan wanita-wanita yang dipingit di rumah, dan wanita yang sedang haid ikut menyaksikan kebaikan dan mendo'akan Kaum Muslimin, dan wanita-wanita haid menjauh dari tempat shalat.\" Hafshah, \"Aku katakan, \"Wanita haid?\" Wanita itu menjawab, \"Bukankah mereka juga hadir di 'Arafah, begini dan begini?\""},"314":{"ar":"حَدَّثَنَا أَحْمَدُ ابْنُ أَبِي رَجَاءٍ قَالَ حَدَّثَنَا أَبُو أُسَامَةَ قَالَ سَمِعْتُ هِشَامَ بْنَ عُرْوَةَ قَالَ أَخْبَرَنِي أَبِي عَنْ عَائِشَةَأَنَّ فَاطِمَةَ بِنْتَ أَبِي حُبَيْشٍ سَأَلَتْ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَتْ إِنِّي أُسْتَحَاضُ فَلَا أَطْهُرُ أَفَأَدَعُ الصَّلَاةَ فَقَالَ لَا إِنَّ ذَلِكِ عِرْقٌ وَلَكِنْ دَعِي الصَّلَاةَ قَدْرَ الْأَيَّامِ الَّتِي كُنْتِ تَحِيضِينَ فِيهَا ثُمَّ اغْتَسِلِي وَصَلِّي","id":"Telah menceritakan kepada kami [Ahmad bin Abu Raja'] berkata, telah menceritakan kepada kami [Abu Usamah] berkata, Aku mendengar [Hisyam bin 'Urwah] berkata, telah mengabarkan kepadaku [Bapakku] dari ['Aisyah] bahwa Fatimah binti Abu Hubaisy bertanya kepada Nabi shallallahu 'alaihi wasallam, katanya, \"Aku mengeluarkan darah istihadlah (penyakit). Apakah aku tinggalkan shalat?\" Beliau menjawab: \"Jangan, karena itu hanyalah darah penyakit seperti keringat. Tinggalkanlah shalat selama masa haidmu, setelah itu mandi dan kerjakanlah shalat.\""},"315":{"ar":"حَدَّثَنَا قُتَيْبَةُ بْنُ سَعِيدٍ قَالَ حَدَّثَنَا إِسْمَاعِيلُ عَنْ أَيُّوبَ عَنْ مُحَمَّدٍ عَنْ أُمِّ عَطِيَّةَ قَالَتْكُنَّا لَا نَعُدُّ الْكُدْرَةَ وَالصُّفْرَةَ شَيْئًا","id":"Telah menceritakan kepada kami [Qutaibah bin Sa'id] berkata, telah menceritakan kepada kami [Isma'il] dari [Ayyub] dari [Muhammad] dari [Ummu 'Athiyyah] berkata, \"Kami tidak menganggap warna keruh dan kekuningan sebagai sesuatu dari haid.\""},"316":{"ar":"حَدَّثَنَا إِبْرَاهِيمُ بْنُ الْمُنْذِرِ قَالَ حَدَّثَنَا مَعْنٌ قَالَ حَدَّثَنِي ابْنُ أَبِي ذِئْبٍ عَنْ ابْنِ شِهَابٍ عَنْ عُرْوَةَ وَعَنْ عَمْرَةَ عَنْ عَائِشَةَ زَوْجِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَأَنَّ أُمَّ حَبِيبَةَ اسْتُحِيضَتْ سَبْعَ سِنِينَ فَسَأَلَتْ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ ذَلِكَ فَأَمَرَهَا أَنْ تَغْتَسِلَ فَقَالَ هَذَا عِرْقٌ فَكَانَتْ تَغْتَسِلُ لِكُلِّ صَلَاةٍ","id":"Telah menceritakan kepada kami [Ibrahim bin Al Mundzir] berkata, telah menceritakan kepada kami [M'an] berkata, telah menceritakan kepadaku [Ibnu Abu Dzi'b] dari [Ibnu Syihab] dari ['Urwah] dan dari ['Amrah] dari ['Aisyah] isteri Nabi shallallahu 'alaihi wasallam, \"Ummu Habibah mengeluarkan darah istihadlah (darah penyakit) selama tujuh tahun. Lalu ia bertanya kepada Rasulullah shallallahu 'alaihi wasallam tentang masalah itu. Beliau lalu memerintahkan kepadanya untuk mandi, beliau bersabda: \"Ini seperti keringat (darah penyakit).\" Maka Ummu Habibah selalu mandi untuk setiap kali shalat.\""},"317":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ يُوسُفَ أَخْبَرَنَا مَالِكٌ عَنْ عَبْدِ اللَّهِ بْنِ أَبِي بَكْرِ بْنِ مُحَمَّدِ بْنِ عَمْرِو بْنِ حَزْمٍ عَنْ أَبِيهِ عَنْ عَمْرَةَ بِنْتِ عَبْدِ الرَّحْمَنِ عَنْ عَائِشَةَ زَوْجِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَأَنَّهَا قَالَتْ لِرَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَا رَسُولَ اللَّهِ إِنَّ صَفِيَّةَ بِنْتَ حُيَيٍّ قَدْ حَاضَتْ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَعَلَّهَا تَحْبِسُنَا أَلَمْ تَكُنْ طَافَتْ مَعَكُنَّ فَقَالُوا بَلَى قَالَ فَاخْرُجِي","id":"Telah menceritakan kepada kami ['Abdullah bin Yusuf] telah mengabarkan kepada kami [Malik] dari ['Abdullah bin Abu Bakar bin Muhammad bin 'Amru bin Hazm] dari [Bapaknya] dari ['Amrah binti 'Abdurrahman] dari ['Aisyah] isteri Nabi shallallahu 'alaihi wasallam, ia berkata kepada Rasulullah shallallahu 'alaihi wasallam: \"Wahai Rasulullah, Shafiyyah binti Huyai sedang haid?\" Rasulullah shallallahu 'alaihi wasallam menjawab: \"Jangan-jangan dia menyusahkan kita! Apakah dia thawaf bersama kalian?\" Mereka menjawab, \"Ya.\" Beliau lalu bersabda (kepada Shafiyyah): \"Ikutlah keluar.\""},"318":{"ar":"حَدَّثَنَا مُعَلَّى بْنُ أَسَدٍ قَالَ حَدَّثَنَا وُهَيْبٌ عَنْ عَبْدِ اللَّهِ بْنِ طَاوُسٍ عَنْ أَبِيهِ عَنْ ابْنِ عَبَّاسٍ قَالَرُخِّصَ لِلْحَائِضِ أَنْ تَنْفِرَ إِذَا حَاضَتْوَكَانَ ابْنُ عُمَرَ يَقُولُ فِي أَوَّلِ أَمْرِهِ إِنَّهَا لَا تَنْفِرُ ثُمَّ سَمِعْتُهُ يَقُولُ تَنْفِرُ إِنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ رَخَّصَ لَهُنَّ","id":"Telah menceritakan kepada kami [Mu'alla bin Asad] berkata, telah menceritakan kepada kami [Wuhaib] dari ['Abdullah bin Thawus] dari [Bapaknya] dari [Ibnu 'Abbas] berkata, \"Wanita yang haid diberi keringanan untuk nafar (meninggalkan Mina), dan pada mulanya [Ibnu Umar] melarang hal itu, namun kemudian aku mendengar ia mengatakan, 'Wanita haid boleh nafar karena Rasulullah shallallahu 'alaihi wasallam telah memberi keringanan buat mereka.\""},"319":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ يُونُسَ عَنْ زُهَيْرٍ قَالَ حَدَّثَنَا هِشَامُ بْنُ عُرْوَةَ عَنْ عُرْوَةَ عَنْ عَائِشَةَ قَالَتْقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا أَقْبَلَتْ الْحَيْضَةُ فَدَعِي الصَّلَاةَ وَإِذَا أَدْبَرَتْ فَاغْسِلِي عَنْكِ الدَّمَ وَصَلِّي","id":"Telah menceritakan kepada kami [Ahmad bin Yunus] dari [Zuhair] berkata, telah menceritakan kepada kami [Hisyam bin 'Urwah] dari ['Urwah] dari ['Aisyah] berkata, \"Nabi shallallahu 'alaihi wasallam bersabda: \"Jika datang haid maka tinggalkanlah shalat, dan bila telah berakhir maka bersihkanlah darah darimu lalu shalatlah.\""},"320":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ أَبِي سُرَيْجٍ قَالَ أَخْبَرَنَا شَبَابَةُ قَالَ أَخْبَرَنَا شُعْبَةُ عَنْ حُسَيْنٍ الْمُعَلِّمِ عَنْ عَبْدِ اللَّهِ بْنِ بُرَيْدَةَ عَنْ سَمُرَةَ بْنِ جُنْدُبٍأَنَّ امْرَأَةً مَاتَتْ فِي بَطْنٍ فَصَلَّى عَلَيْهَا النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَامَ وَسَطَهَا","id":"Telah menceritakan kepada kami [Ahmad bin Abu Suraij] berkata, telah mengabarkan kepada kami [Syababah] berkata, telah mengabarkan kepada kami [Syu'bah] dari [Husain Al Mu'alim] dari ['Abdullah bin Buraidah] dari [Samrah bin Jundub], bahwa ada seorang wanita yang meninggal dunia karena hamil. Maka Nabi shallallahu 'alaihi wasallam menshalatinya dan beliau berdiri di bagian tengah (jenazah) nya.\""},"321":{"ar":"حَدَّثَنَا الْحَسَنُ بْنُ مُدْرِكٍ قَالَ حَدَّثَنَا يَحْيَى بْنُ حَمَّادٍ قَالَ أَخْبَرَنَا أَبُو عَوَانَةَ اسْمُهُ الْوَضَّاحُ مِنْ كِتَابِهِ قَالَ أَخْبَرَنَا سُلَيْمَانُ الشَّيْبَانِيُّ عَنْ عَبْدِ اللَّهِ بْنِ شَدَّادٍ قَالَ سَمِعْتُخَالَتِي مَيْمُونَةَ زَوْجَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهَا كَانَتْ تَكُونُ حَائِضًا لَا تُصَلِّي وَهِيَ مُفْتَرِشَةٌ بِحِذَاءِ مَسْجِدِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَهُوَ يُصَلِّي عَلَى خُمْرَتِهِ إِذَا سَجَدَ أَصَابَنِي بَعْضُ ثَوْبِهِ","id":"Telah menceritakan kepada kami [Al Hasan bin Mudrik] berkata, telah menceritakan kepada kami [Yahya bin Hammad] berkata, telah mengabarkan kepada kami [Abu 'Awanah] nama aslinya adalah Al Wadldlah sebagaimana dalam kitabnya, ia berkata; telah mengabarkan kepada kami [Sulaiman Asy Syaibani] dari ['Abdullah bin Syaddad] berkata, Aku mendengar bibiku [Maimunah] isteri Nabi shallallahu 'alaihi wasallam, bahwa ia mengalami haid dan tidak melaksanakan shalat. Dan ia tidur di depan tempat sujud Rasulullah shallallahu 'alaihi wasallam yang saat itu sedang shalat di atas tikar (kecil) nya, jika sujud beliau maka sebagian kainnya mengenaiku.\""},"322":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ يُوسُفَ قَالَ أَخْبَرَنَا مَالِكٌ عَنْ عَبْدِ الرَّحْمَنِ بْنِ الْقَاسِمِ عَنْ أَبِيهِ عَنْ عَائِشَةَ زَوْجِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَتْخَرَجْنَا مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي بَعْضِ أَسْفَارِهِ حَتَّى إِذَا كُنَّا بِالْبَيْدَاءِ أَوْ بِذَاتِ الْجَيْشِ انْقَطَعَ عِقْدٌ لِي فَأَقَامَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَلَى الْتِمَاسِهِ وَأَقَامَ النَّاسُ مَعَهُ وَلَيْسُوا عَلَى مَاءٍ فَأَتَى النَّاسُ إِلَى أَبِي بَكْرٍ الصِّدِّيقِ فَقَالُوا أَلَا تَرَى مَا صَنَعَتْ عَائِشَةُ أَقَامَتْ بِرَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَالنَّاسِ وَلَيْسُوا عَلَى مَاءٍ وَلَيْسَ مَعَهُمْ مَاءٌ فَجَاءَ أَبُو بَكْرٍ وَرَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَاضِعٌ رَأْسَهُ عَلَى فَخِذِي قَدْ نَامَ فَقَالَ حَبَسْتِ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَالنَّاسَ وَلَيْسُوا عَلَى مَاءٍ وَلَيْسَ مَعَهُمْ مَاءٌ فَقَالَتْ عَائِشَةُ فَعَاتَبَنِي أَبُو بَكْرٍ وَقَالَ مَا شَاءَ اللَّهُ أَنْ يَقُولَ وَجَعَلَ يَطْعُنُنِي بِيَدِهِ فِي خَاصِرَتِي فَلَا يَمْنَعُنِي مِنْ التَّحَرُّكِ إِلَّا مَكَانُ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَلَى فَخِذِي فَقَامَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حِينَ أَصْبَحَ عَلَى غَيْرِ مَاءٍ فَأَنْزَلَ اللَّهُ آيَةَ التَّيَمُّمِ فَتَيَمَّمُوا فَقَالَ أُسَيْدُ بْنُ الْحُضَيْرِ مَا هِيَ بِأَوَّلِ بَرَكَتِكُمْ يَا آلَ أَبِي بَكْرٍ قَالَتْ فَبَعَثْنَا الْبَعِيرَ الَّذِي كُنْتُ عَلَيْهِ فَأَصَبْنَا الْعِقْدَ تَحْتَهُ","id":"Telah menceritakan kepada kami ['Abdullah bin Yusuf] berkata, telah mengabarkan kepada kami [Malik] dari ['Abdurrahman bin Al Qasim] dari [bapaknya] dari ['Aisyah] isteri Nabi shallallahu 'alaihi wasallam, ia berkata, \"Kami keluar bersama Rasulullah shallallahu 'alaihi wasallam dalam salah satu perjalanan yang dilakukannya. Hingga ketika kami sampai di Baida', atau tempat peristirahatan pasukan, aku kehilangan kalungku. Maka Nabi shallallahu 'alaihi wasallam dan para sahabatnya mencarinya sementara mereka tidak berada dekat air. Orang-orang lalu datang kepada Abu Bakar Ash Shidiq seraya berkata, 'Tidakkah kamu perhatikan apa yang telah diperbuat oleh 'Aisyah? Dia telah membuat Rasulullah shallallahu 'alaihi wasallam dan orang-orang tertahan (dari melanjutkan perjalanan) padahal mereka tidak sedang berada dekat air dan mereka juga tidak memiliki air! ' Lalu Abu Bakar datang sedangkan saat itu Rasulullah shallallahu 'alaihi wasallam meletakkan kepalanya di pahaku. Abu Bakar lalu memarahiku dan mengatakan sebagaimana yang dikehendaki Allah untuk (Abu Bakar) mengatakannya. Ia menusuk lambungku, dan tidak ada yang menghalangiku untuk bergerak (karena rasa sakit) kecuali karena keberadaan Rasulullah yang di pahaku.\" Kemudian Rasulullah shallallahu 'alaihi wasallam bangun di waktu subuh dalam keadaan tidak memiliki air. Allah Ta'ala kemudian menurunkan ayat tayamum, maka orang-orang pun bertayamum.\" Usaid bin Al Hudlair lalu berkata, \"Tidaklah Aisyah kecuali awal dari keberkahan keluarga kamu wahai wahai Abu Bakar!\" 'Aisyah berkata, \"Kemudian unta yang aku tunggangi berdiri yang ternyata kami temukan kalungku berada dibawahnya.\""},"323":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ سِنَانٍ هُوَ الْعَوَقِيُّ قَالَ حَدَّثَنَا هُشَيْمٌ قَالَ ح و حَدَّثَنِي سَعِيدُ بْنُ النَّضْرِ قَالَ أَخْبَرَنَا هُشَيْمٌ قَالَ أَخْبَرَنَا سَيَّارٌ قَالَ حَدَّثَنَا يَزِيدُ هُوَ ابْنُ صُهَيْبٍ الْفَقِيرُ قَالَ أَخْبَرَنَا جَابِرُ بْنُ عَبْدِ اللَّهِأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ أُعْطِيتُ خَمْسًا لَمْ يُعْطَهُنَّ أَحَدٌ قَبْلِي نُصِرْتُ بِالرُّعْبِ مَسِيرَةَ شَهْرٍ وَجُعِلَتْ لِي الْأَرْضُ مَسْجِدًا وَطَهُورًا فَأَيُّمَا رَجُلٍ مِنْ أُمَّتِي أَدْرَكَتْهُ الصَّلَاةُ فَلْيُصَلِّ وَأُحِلَّتْ لِي الْمَغَانِمُ وَلَمْ تَحِلَّ لِأَحَدٍ قَبْلِي وَأُعْطِيتُ الشَّفَاعَةَ وَكَانَ النَّبِيُّ يُبْعَثُ إِلَى قَوْمِهِ خَاصَّةً وَبُعِثْتُ إِلَى النَّاسِ عَامَّةً","id":"Telah menceritakan kepada kami [Muhammad bin Sinan] -yaitu Al 'Awaqi- telah menceritakan kepada kami [Husyaim] berkata. (dalam jalur lain disebutkan) Telah menceritakan kepadaku [Sa'id bin An Nadlr] berkata, telah mengabarkan kepada kami [Husyaim] berkata, telah mengabarkan kepada kami [Sayyar] berkata, telah menceritakan kepada kami [Yazid] -yaitu Ibnu Shuhaib Al Faqir- berkata, telah mengabarkan kepada kami [Jabir bin 'Abdullah] bahwa Nabi shallallahu 'alaihi wasallam bersabda: \"Aku diberikan lima perkara yang tidak diberikan kepada orang sebelumku; aku ditolong melawan musuhku dengan ketakutan mereka sejauh satu bulan perjalanan, dijadikan bumi untukku sebagai tempat sujud dan suci. Maka dimana saja salah seorang dari umatku mendapati waktu shalat hendaklah ia shalat, dihalalkan untukku harta rampasan perang yang tidak pernah dihalalkan untuk orang sebelumku, aku diberikan (hak) syafa'at, dan para Nabi sebelumku diutus khusus untuk kaumnya sedangkan aku diutus untuk seluruh manusia.\""},"324":{"ar":"حَدَّثَنَا زَكَرِيَّاءُ بْنُ يَحْيَى قَالَ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ نُمَيْرٍ قَالَ حَدَّثَنَا هِشَامُ بْنُ عُرْوَةَ عَنْ أَبِيهِ عَنْ عَائِشَةَأَنَّهَا اسْتَعَارَتْ مِنْ أَسْمَاءَ قِلَادَةً فَهَلَكَتْ فَبَعَثَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ رَجُلًا فَوَجَدَهَا فَأَدْرَكَتْهُمْ الصَّلَاةُ وَلَيْسَ مَعَهُمْ مَاءٌ فَصَلَّوْا فَشَكَوْا ذَلِكَ إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَنْزَلَ اللَّهُ آيَةَ التَّيَمُّمِ فَقَالَ أُسَيْدُ بْنُ حُضَيْرٍ لِعَائِشَةَ جَزَاكِ اللَّهُ خَيْرًا فَوَاللَّهِ مَا نَزَلَ بِكِ أَمْرٌ تَكْرَهِينَهُ إِلَّا جَعَلَ اللَّهُ ذَلِكِ لَكِ وَلِلْمُسْلِمِينَ فِيهِ خَيْرًا","id":"Telah menceritakan kepada kami [Zakaria bin Yahya] berkata, telah menceritakan kepada kami ['Abdullah bin Numair] berkata, telah menceritakan kepada kami [Hisyam bin 'Urwah] dari [Bapaknya] dari ['Aisyah] bahwa ia meminjam kalung kepada Asma' lalu hilang. Maka Rasulullah shallallahu 'alaihi wasallam mengutus seseorang untuk mencarinya hingga kalung itu pun ditemukan. Lalu datanglah waktu shalat sementara mereka tidak memiliki air, namun mereka tetap melaksanakannya. Setelah itu mereka mengadukan peristiwa itu kepada Rasulullah shallallahu 'alaihi wasallam, hingga turunlah ayat tayamum. Usaid bin Al Hudlair lalu berkata kepada 'Aisyah, \"Semoga Allah membalasmu dengan segala kebaikan. Sungguh demi Allah, tidaklah terjadi suatu peristiwa menimpa anda yang anda tidak sukai kecuali Allah menjadikannya untuk anda dan Kaum Muslimin sebagai kebaikan.\""},"325":{"ar":"حَدَّثَنَا يَحْيَى بْنُ بُكَيْرٍ قَالَ حَدَّثَنَا اللَّيْثُ عَنْ جَعْفَرِ بْنِ رَبِيعَةَ عَنْ الْأَعْرَجِ قَالَ سَمِعْتُ عُمَيْرًا مَوْلَى ابْنِ عَبَّاسٍ قَالَأَقْبَلْتُ أَنَا وَعَبْدُ اللَّهِ بْنُ يَسَارٍ مَوْلَى مَيْمُونَةَ زَوْجِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حَتَّى دَخَلْنَا عَلَى أَبِي جُهَيْمِ بْنِ الْحَارِثِ بْنِ الصِّمَّةِ الْأَنْصَارِيِّ فَقَالَ أَبُو الْجُهَيْمِ الْأَنْصَارِيُّ أَقْبَلَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِنْ نَحْوِ بِئْرِ جَمَلٍ فَلَقِيَهُ رَجُلٌ فَسَلَّمَ عَلَيْهِ فَلَمْ يَرُدَّ عَلَيْهِ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حَتَّى أَقْبَلَ عَلَى الْجِدَارِ فَمَسَحَ بِوَجْهِهِ وَيَدَيْهِ ثُمَّ رَدَّ عَلَيْهِ السَّلَامَ","id":"Telah menceritakan kepada kami [Yahya bin Bukair] berkata, telah menceritakan kepada kami [Al Laits] dari [Ja'far bin Rabi'ah] dari [Al A'raj] ia berkata, \"Aku mendengar [Umair] mantan budak Ibnu Abbas, ia berkata, \"Aku dan Abdullah bin Yasar, mantan budak Maimunah, isteri Nabi shallallahu 'alaihi wasallam berangkat pergi, hingga ketika kami sampai kepada [Abu Juhaim Ibnul Harits bin Ash Shimmah Al Anshari], ia berkata, \"Nabi shallallahu 'alaihi wasallam kembali dari Bi`ar Jamal (nama tempat), lalu ada seorang laki-laki menemui beliau seraya memberi salam, namun beliau tidak membalasnya. Beliau kemudian menghadap ke arah dinding, lalu mengusap muka dan kedua telapak tangannya. baru kemudian membalas salam kepada orang itu.\""},"326":{"ar":"حَدَّثَنَا آدَمُ قَالَ حَدَّثَنَا شُعْبَةُ حَدَّثَنَا الْحَكَمُ عَنْ ذَرٍّ عَنْ سَعِيدِ بْنِ عَبْدِ الرَّحْمَنِ بْنِ أَبْزَى عَنْ أَبِيهِقَالَ جَاءَ رَجُلٌ إِلَى عُمَرَ بْنِ الْخَطَّابِ فَقَالَ إِنِّي أَجْنَبْتُ فَلَمْ أُصِبْ الْمَاءَ فَقَالَ عَمَّارُ بْنُ يَاسِرٍ لِعُمَرَ بْنِ الْخَطَّابِ أَمَا تَذْكُرُ أَنَّا كُنَّا فِي سَفَرٍ أَنَا وَأَنْتَ فَأَمَّا أَنْتَ فَلَمْ تُصَلِّ وَأَمَّا أَنَا فَتَمَعَّكْتُ فَصَلَّيْتُ فَذَكَرْتُ لِلنَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّمَا كَانَ يَكْفِيكَ هَكَذَا فَضَرَبَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِكَفَّيْهِ الْأَرْضَ وَنَفَخَ فِيهِمَا ثُمَّ مَسَحَ بِهِمَا وَجْهَهُ وَكَفَّيْهِ","id":"Telah menceritakan kepada kami [Adam] ia berkata; telah menceritakan kepada kami [Syu'bah] berkata, telah menceritakan kepada kami [Al Hakam] dari [Dzar] dari [Sa'id bin 'Abdurrahman bin Abza] dari [Bapaknya] berkata, \"Seorang laki-laki datang kepada Umar Ibnul Khaththab dan berkata, \"Aku mengalami junub tapi tidak mendapatkan air?\" Maka berkata lah ['Ammar bin Yasir] kepada 'Umar bin Al Khaththab, \"Tidak ingatkah ketika kita dalam suatu perjalanan? Saat itu engkau tidak mengerjakan shalat sedangkan aku bergulingan di atas tanah lalu shalat? Kemudian hal itu aku sampaikan kepada Nabi shallallahu 'alaihi wasallam, dan Nabi shallallahu 'alaihi wasallam bersabda: \"Sebenarnya cukup kamu melakukan begini.\" Beliau lalu memukulkan telapak tangannya ke tanah dan meniupnya, lalu mengusapkannya ke muka dan kedua telapak tangannya.\""},"327":{"ar":"حَدَّثَنَا حَجَّاجٌ قَالَ أَخْبَرَنَا شُعْبَةُ أَخْبَرَنِي الْحَكَمُ عَنْ ذَرٍّ عَنْ سَعِيدِ بْنِ عَبْدِ الرَّحْمَنِ بْنِ أَبْزَى عَنْ أَبِيهِ قَالَ عَمَّارٌبِهَذَا وَضَرَبَ شُعْبَةُ بِيَدَيْهِ الْأَرْضَ ثُمَّ أَدْنَاهُمَا مِنْ فِيهِ ثُمَّ مَسَحَ بِهِمَا وَجْهَهُ وَكَفَّيْهِوَقَالَ النَّضْرُ أَخْبَرَنَا شُعْبَةُ عَنْ الْحَكَمِ قَالَ سَمِعْتُ ذَرًّا يَقُولُ عَنْ ابْنِ عَبْدِ الرَّحْمَنِ بْنِ أَبْزَى قَالَ الْحَكَمُ وَقَدْ سَمِعْتُهُ مِنْ ابْنِ عَبْدِ الرَّحْمَنِ عَنْ أَبِيهِ قَالَ قَالَ عَمَّارٌ","id":"Telah menceritakan kepada kami [Hajjaj] dia berkata; telah mengabarkan kepada kami [Syu'bah] telah mengabarkan kepada kami [Al Hakam] dari [Dzarri] dari [Sa'id bin 'Abdurrahman bin Abza] dari [bapaknya], telah berkata, pula ['Ammar] tentang maslah ini; Maka Syu'bah memukulkan telapak tangannya ke tanah lalu mendekatkannya kepada mulutnya kemudian mengusapkannya ke mukanya dan kedua telapak tangannya. Dan telah berkata [An Nadlar] telah mengabarkan kepada kami [Syu'bah] dari [Al Hakam] dia berkata; saya mendengar [Dzarr] berkata; dari [Ibnu Abdurrahman bin Abzaa], berkata [Al Hakam]; dan aku telah mendengarnya dari [Ibnu Abdurrahman] dari [ayahnya] berkata; [Ammar] berkata;."},"328":{"ar":"حَدَّثَنَا سُلَيْمَانُ بْنُ حَرْبٍ قَالَ حَدَّثَ��َا شُعْبَةُ عَنْ الْحَكَمِ عَنْ ذَرٍّ عَنْ ابْنِ عَبْدِ الرَّحْمَنِ بْنِ أَبْزَى عَنْ أَبِيهِ أَنَّهُ شَهِدَ عُمَرَ وَقَالَ لَهُ عَمَّارٌكُنَّا فِي سَرِيَّةٍ فَأَجْنَبْنَا وَقَالَ تَفَلَ فِيهِمَا","id":"Telah menceritakan kepada kami [Sulaiman bin Harb] berkata, telah menceritakan kepada kami [Syu'bah] dari [Al Hakam] dari [Dzar] dari [Ibnu 'Abdurrahman bin Abza] dari [Bapaknya] bahwa ia pernah melihat 'Umar saat ['Ammar] bertanya kepadanya, \"Kami sedang dalam perjalanan, kemudian kami junub?\" dia menjawab, \"Hendaknya bertayamum.\""},"329":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ كَثِيرٍ أَخْبَرَنَا شُعْبَةُ عَنْ الْحَكَمِ عَنْ ذَرٍّ عَنْ ابْنِ عَبْدِ الرَّحْمَنِ بْنِ أَبْزَى عَنْ عَبْدِ الرَّحْمَنِ بْنِ أَبْزَى قَالَ قَالَ عَمَّارٌلِعُمَرَ تَمَعَّكْتُ فَأَتَيْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ يَكْفِيكَ الْوَجْهَ وَالْكَفَّيْنِحَدَّثَنَا مُسْلِمٌ حَدَّثَنَا شُعْبَةُ عَنْ الْحَكَمِ عَنْ ذَرٍّ عَنْ ابْنِ عَبْدِ الرَّحْمَنِ عَنْ عَبْدِ الرَّحْمَنِ بْنِ أَبْزَى قَالَ شَهِدْتُ عُمَرَ فَقَالَ لَهُ عَمَّارٌ وَسَاقَ الْحَدِيثَ","id":"Telah menceritakan kepada kami [Muhammad bin Katsir] telah mengabarkan kepada kami [Syu'bah] dari [Al Hakam] dari [Dzar] dari [Ibnu 'Abdurrahman bin Abza] dari ['Abdurrahman bin Abza] ia berkata; [Ammar] berkata kepada Umar, \"Aku bergulingan (di atas pasir) lalu menemui Nabi shallallahu 'alaihi wasallam. Maka beliau pun bersabda: \"Cukup bagimu (mengusap debu) pada muka dan kedua telapak tangan.\" Telah menceritakan kepada kami [Muslim] telah menceritakan kepada kami [Syu'bah] dari [Al Hakam] dari [Dzar] dari [Ibnu 'Abdurrahman] dari ['Abdurrahman bin Abza] ia berkata, \"Aku melihat Umar ketika [Ammar] bertanya kepadanya….lalu ia menyebutkan hadits.\""},"330":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ قَالَ حَدَّثَنَا غُنْدَرٌ حَدَّثَنَا شُعْبَةُ عَنْ الْحَكَمِ عَنْ ذَرٍّ عَنْ ابْنِ عَبْدِ الرَّحْمَنِ بْنِ أَبْزَى عَنْ أَبِيهِ قَالَ قَالَ عَمَّارٌفَضَرَبَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِيَدِهِ الْأَرْضَ فَمَسَحَ وَجْهَهُ وَكَفَّيْهِ","id":"Telah menceritakan kepada kami [Muhammad bin Basysyar] ia berkata; telah menceritakan kepada kami [Ghundar] telah menceritakan kepada kami [Syu'bah] dari [Al Hakam] dari [Dzarr] dari [Ibnu 'Abdurrahman bin Abza] dari [Bapaknya] ia berkata, \" [Ammar] berkata, \"Nabi shallallahu 'alaihi wasallam memukulkan telapak tangannya ke tanah lalu mengusapkan pada muka dan kedua telapak tangannya.\""},"331":{"ar":"حَدَّثَنَا مُسَدَّدٌ قَالَ حَدَّثَنِي يَحْيَى بْنُ سَعِيدٍ قَالَ حَدَّثَنَا عَوْفٌ قَالَ حَدَّثَنَا أَبُو رَجَاءٍ عَنْ عِمْرَانَ قَالَكُنَّا فِي سَفَرٍ مَعَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَإِنَّا أَسْرَيْنَا حَتَّى كُنَّا فِي آخِرِ اللَّيْلِ وَقَعْنَا وَقْعَةً وَلَا وَقْعَةَ أَحْلَى عِنْدَ الْمُسَافِرِ مِنْهَا فَمَا أَيْقَظَنَا إِلَّا حَرُّ الشَّمْسِ وَكَانَ أَوَّلَ مَنْ اسْتَيْقَظَ فُلَانٌ ثُمَّ فُلَانٌ ثُمَّ فُلَانٌ يُسَمِّيهِمْ أَبُو رَجَاءٍ فَنَسِيَ عَوْفٌ ثُمَّ عُمَرُ بْنُ الْخَطَّابِ الرَّابِعُ وَكَانَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا نَامَ لَمْ يُوقَظْ حَتَّى يَكُونَ هُوَ يَسْتَيْقِظُ لِأَنَّا لَا نَدْرِي مَا يَحْدُثُ لَهُ فِي نَوْمِهِ فَلَمَّا اسْتَيْقَظَ عُمَرُ وَرَأَى مَا أَصَابَ النَّاسَ وَكَانَ رَجُلًا جَلِيدًا فَكَبَّرَ وَرَفَعَ صَوْتَهُ بِالتَّكْبِيرِ فَمَا زَالَ يُكَبِّرُ وَيَرْفَعُ صَوْتَهُ بِالتَّكْبِيرِ حَتَّى اسْتَيْقَظَ بِصَوْتِهِ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَلَمَّا اسْتَيْقَظَ شَكَوْا إِلَيْهِ الَّذِي أَصَابَهُمْ قَالَ لَا ضَيْرَ أَوْ لَا يَضِيرُ ارْتَحِلُوا فَارْتَحَلَ فَسَارَ غَيْرَ بَعِيدٍ ثُمَّ نَزَلَ فَدَعَا بِالْوَضُوءِ فَتَوَضَّأَ وَنُودِيَ بِالصَّلَاةِ فَصَلَّى بِالنَّاس فَلَمَّا انْفَتَلَ مِنْ صَلَاتِهِ إِذَا هُوَ بِرَجُلٍ مُعْتَزِلٍ لَمْ يُصَلِّ مَعَ الْقَوْمِ قَالَ مَا مَنَعَكَ يَا فُلَانُ أَنْ تُصَلِّيَ مَعَ الْقَوْمِ قَالَ أَصَابَتْنِي جَنَابَةٌ وَلَا مَاءَ قَالَ عَلَيْكَ بِال��َّعِيدِ فَإِنَّهُ يَكْفِيكَ ثُمَّ سَارَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَاشْتَكَى إِلَيْهِ النَّاسُ مِنْ الْعَطَشِ فَنَزَلَ فَدَعَا فُلَانًا كَانَ يُسَمِّيهِ أَبُو رَجَاءٍ نَسِيَهُ عَوْفٌ وَدَعَا عَلِيًّا فَقَالَ اذْهَبَا فَابْتَغِيَا الْمَاءَ فَانْطَلَقَا فَتَلَقَّيَا امْرَأَةً بَيْنَ مَزَادَتَيْنِ أَوْ سَطِيحَتَيْنِ مِنْ مَاءٍ عَلَى بَعِيرٍ لَهَا فَقَالَا لَهَا أَيْنَ الْمَاءُ قَالَتْ عَهْدِي بِالْمَاءِ أَمْسِ هَذِهِ السَّاعَةَ وَنَفَرُنَا خُلُوفًا قَالَا لَهَا انْطَلِقِي إِذًا قَالَتْ إِلَى أَيْنَ قَالَا إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَتْ الَّذِي يُقَالُ لَهُ الصَّابِئُ قَالَا هُوَ الَّذِي تَعْنِينَ فَانْطَلِقِي فَجَاءَا بِهَا إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَحَدَّثَاهُ الْحَدِيثَ قَالَ فَاسْتَنْزَلُوهَا عَنْ بَعِيرِهَا وَدَعَا النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِإِنَاءٍ فَفَرَّغَ فِيهِ مِنْ أَفْوَاهِ الْمَزَادَتَيْنِ أَوْ سَطِيحَتَيْنِ وَأَوْكَأَ أَفْوَاهَهُمَا وَأَطْلَقَ الْعَزَالِيَ وَنُودِيَ فِي النَّاسِ اسْقُوا وَاسْتَقُوا فَسَقَى مَنْ شَاءَ وَاسْتَقَى مَنْ شَاءَ وَكَانَ آخِرُ ذَاكَ أَنْ أَعْطَى الَّذِي أَصَابَتْهُ الْجَنَابَةُ إِنَاءً مِنْ مَاءٍ قَالَ اذْهَبْ فَأَفْرِغْهُ عَلَيْكَ وَهِيَ قَائِمَةٌ تَنْظُرُ إِلَى مَا يُفْعَلُ بِمَائِهَا وَايْمُ اللَّهِ لَقَدْ أُقْلِعَ عَنْهَا وَإِنَّهُ لَيُخَيَّلُ إِلَيْنَا أَنَّهَا أَشَدُّ مِلْأَةً مِنْهَا حِينَ ابْتَدَأَ فِيهَا فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ اجْمَعُوا لَهَا فَجَمَعُوا لَهَا مِنْ بَيْنِ عَجْوَةٍ وَدَقِيقَةٍ وَسَوِيقَةٍ حَتَّى جَمَعُوا لَهَا طَعَامًا فَجَعَلُوهَا فِي ثَوْبٍ وَحَمَلُوهَا عَلَى بَعِيرِهَا وَوَضَعُوا الثَّوْبَ بَيْنَ يَدَيْهَا قَالَ لَهَا تَعْلَمِينَ مَا رَزِئْنَا مِنْ مَائِكِ شَيْئًا وَلَكِنَّ اللَّهَ هُوَ الَّذِي أَسْقَانَا فَأَتَتْ أَهْلَهَا وَقَدْ احْتَبَسَتْ عَنْهُمْ قَالُوا مَا حَبَسَكِ يَا فُلَانَةُ قَالَتْ الْعَجَبُ لَقِيَنِي رَجُلَانِ فَذَهَبَا بِي إِلَى هَذَا الَّذِي يُقَالُ لَهُ الصَّابِئُ فَفَعَلَ كَذَا وَكَذَا فَوَاللَّهِ إِنَّهُ لَأَسْحَرُ النَّاسِ مِنْ بَيْنِ هَذِهِ وَهَذِهِ وَقَالَتْ بِإِصْبَعَيْهَا الْوُسْطَى وَالسَّبَّابَةِ فَرَفَعَتْهُمَا إِلَى السَّمَاءِ تَعْنِي السَّمَاءَ وَالْأَرْضَ أَوْ إِنَّهُ لَرَسُولُ اللَّهِ حَقًّا فَكَانَ الْمُسْلِمُونَ بَعْدَ ذَلِكَ يُغِيرُونَ عَلَى مَنْ حَوْلَهَا مِنْ الْمُشْرِكِينَ وَلَا يُصِيبُونَ الصِّرْمَ الَّذِي هِيَ مِنْهُ فَقَالَتْ يَوْمًا لِقَوْمِهَا مَا أُرَى أَنَّ هَؤُلَاءِ الْقَوْمَ يَدْعُونَكُمْ عَمْدًا فَهَلْ لَكُمْ فِي الْإِسْلَامِ فَأَطَاعُوهَا فَدَخَلُوا فِي الْإِسْلَامِقَالَ أَبُو عَبْد اللَّهِ صَبَأَ خَرَجَ مِنْ دِينٍ إِلَى غَيْرِهِ وَقَالَ أَبُو الْعَالِيَةِ{ الصَّابِئِينَ }فِرْقَةٌ مِنْ أَهْلِ الكِتَابِ يَقْرَءُونَ الزَّبُورَ","id":"Telah menceritakan kepada kami [Musaddad] berkata, telah menceritakan kepadaku [Yahya bin Sa'id] berkata, telah menceritakan kepada kami ['Auf] berkata, telah menceritakan kepada kami [Abu Raja'] dari ['Imran] berkata, \"Kami pernah dalam suatu perjalanan bersama Nabi shallallahu 'alaihi wasallam, kami berjalan di waktu malam hingga ketika sampai di akhir malam kami tidur, dan tidak ada tidur yang paling enak (nyenyak) bagi musafir melebihi yang kami alami. Hingga tidak ada yang membangunkan kami kecuali panas sinar matahari. Dan orang yang pertama kali bangun adalah si fulan, lalu si fulan, lalu seseorang yang Abu 'Auf mengenalnya namun akhirnya lupa. Dan 'Umar bin Al Khaththab adalah orang keempat saat bangun, Sedangkan Nabi shallallahu 'alaihi wasallam bila tidur tidak ada yang membangunkannya hingga beliau bangun sendiri, karena kami tidak tahu apa yang terjadi pada beliau dalam tidurnya. Ketika 'Umar bangun dan melihat apa yang terjadi di tengah banyak orang (yang kesiangan) -dan 'Umar adalah seorang yang tegar penuh keshabaran-, maka ia bertakbir dengan mengeraskan suaranya dan terus saja bertakbir dengan keras hingga Nabi shallallahu 'alaihi wasallam terbangun akibat kerasnya suara takbir 'Umar. Tatkala beliau bangun, orang-orang mengadukan peristiwa yang mereka alami. Maka beliau bersabda: \"Tidak masalah, atau tidak apa dan lanjutkanlah perjalanan.\" Maka beliau meneruskan perjalanan dan setelah beberapa jarak yang tidak jauh beliau berhenti lalu meminta segayung air untuk wudlu, beliau lalu berwudlu kemudian menyeru untuk shalat. Maka beliau shalat bersama orang banyak. Setelah beliau selesai melaksanakan shalatnya, didapatinya ada seorang yang memisahkan diri tidak ikut shalat bersama orang banyak. Maka Nabi shallallahu 'alaihi wasallam bertanya: \"Wahai Fulan, apa yang menghalangimu untuk shalat bersama orang banyak?\" Orang itu menjawab, \"Aku lagi junub, sementara air tidak ada.\" Beliau lantas menjelaskan: \"Kamu cukup menggunakan debu.\" Kemudian Nabi shallallahu 'alaihi wasallam melanjutkan perjalanan hingga akhirnya orang-orang mengadu kepada beliau bahwa mereka kehausan. Maka Nabi shallallahu 'alaihi wasallam meminta seseorang yang bernama Abu Raja' -namun 'Auf lupa- dan 'Ali seraya memerintahkan keduanya: \"Pergilah kalian berdua dan carilah air.\" Maka keduanya berangkat hingga berjumpa dengan seorang wanita yang membawa kantung-kantung berisi air dengan untanya. Maka keduanya bertanya kepadanya, \"Dimana ada air?\" Wanita itu menjawab, \"Terakhir aku lihat air di (daerah) ini adalah waktu sekarang ini. dan perjalanan kami ini juga dalam rangka mencari air.\" Lalu keduanya berkata, \"Kalau begitu pergilah\". Wanita itu bertanya, \"Kalian mau kemana?\" Keduanya menjawab, \"Menemui Rasulullah shallallahu 'alaihi wasallam.\" Wanita itu bertanya, \"Kepada orang yang dianggap telah keluar dari agama (Shabi'i)?\" Keduanya menjawab, \"Ya dialah yang kamu maksud.\" Kemudian kedua sahabat Nabi itu pergi bersama wanita tersebut menemui Nabi shallallahu 'alaihi wasallam. Keduanya kemudian menceritakan peritiwa yang baru saja dialami. Nabi shallallahu 'alaihi wasallam lalu bersabda: \"Turunkanlah dia dari untanya.\" Kemudian Nabi shallallahu 'alaihi wasallam meminta bejana air, beliau lalu menuangkan di mulut kantung-kantung air (milik wanita itu), beliau lepas ikatan kantung-kantung air tersebut seraya berseru kepada orang banyak: \"Ambillah air dan minumlah sesuka kalian!\" Maka orang-orang memberi minum (tunggangan mereka) dan meminum sesuka mereka. Dan akhir, beliau memberi seember air kepada orang yang tadi terkena janabah. Beliau lalu berkata kepadanya: \"Pergi dan mandilah.\" Dans ambil berdiri wanita tersebut mengamati apa yang diperbuat terhadap air kepunyaannya. Demi Allah, kejadian tadi telah membuatnya terperanjat dan juga kami, kami saksikan airnya bertambah banyak dibanding saat yang pertama. Nabi shallallahu 'alaihi wasallam lalu bersabda: \"Berkumpulkan (makanan) untuknya.\" Maka orang-orang pun mengumpulkan makanan berupa kurma, tepung, sawiq (campuran antara susu dengan tepung) untuk wanita tersebut. makanan tersebut kemudian dimasukkan ke dalam kain, mereka menaikkan wanita tersebut di atas kendaraan dan meletakkan makanan tersebut di depannya. Kemudian Nabi shallallahu 'alaihi wasallam berkata kepada wanita tersebut: \"Kamu mengetahui bahwa kami tidak mengurangi sedikitpun air milikmu, tetapi Allah yang telah memberi minum kepada kami.\" Wanita tersebut kemudian pulang menemui keluarganya, mereka lalu bertanya, \"Wahai fulanah, apa yang membuat kamu terlambat?\" Wanita tersebut menjawab, \"Suatu keajaiban! Aku bertemu dengan dua orang laki-laki yang kemudian membawaku bertemu dengan seorang yang disebut Shabi'I, lalu laki-laki itu berbuat begini begini. Demi Allah, dialah orang yang paling menakjubkan (membuat kejadian luar biasa) di antara yang ada ini dan ini.\" Wanita tersebut berkata sambil memberi isyarat dengan mengangkat jari tengah dan telunjuknya ke arah langit, atau antara langit dan bumi. Maksudnya bersaksi bahwa dia adalah Utusan Allah yang haq. Sejak saat itu Kaum Muslimin selalu melindungi wanita tersebut dari Kaum Musyrikin dan tidaklah Kaum Muslimin merusak rumah atau kediaman wanita tersebut. Pada suatu hari wanita itu berkata kepada kaumnya, \"Aku tidak memandang bahwa kaum tersebut membiarkan kalian dengan sengaja. Apakah kalian mau masuk Islam?\" Maka kaumnya mentaatinya dan masuk ke dalam Islam.\" Abu 'Abdullah berkata, \"Yang dimaksud dengan Shabi'i adalah keluar dari suatu agama kepada agama lain.\" Sedangkan Abu' 'Aliyah berkata, \"Ash-Shabi'un adalah kelompok dari Ahlul Kitab yang membaca Kitab Zabur.\""},"332":{"ar":"حَدَّثَنَا بِشْرُ بْنُ خَالِدٍ قَالَ حَدَّثَنَا مُحَمَّدٌ هُوَ غُنْدَرٌ أَخْبَرَنَا شُعْبَةُ عَنْ سُلَيْمَانَ عَنْ أَبِي وَائِلٍ قَالَ قَالَ أَبُو مُوسَى لِعَبْدِ اللَّهِ بْنِ مَسْعُودٍإِذَا لَمْ يَجِدْ الْمَاءَ لَا يُصَلِّي قَالَ عَبْدُ اللَّهِ لَوْ رَخَّصْتُ لَهُمْ فِي هَذَا كَانَ إِذَا وَجَدَ أَحَدُهُمْ الْبَرْدَ قَالَ هَكَذَا يَعْنِي تَيَمَّمَ وَصَلَّى قَالَ قُلْتُ فَأَيْنَ قَوْلُ عَمَّارٍ لِعُمَرَ قَالَ إِنِّي لَمْ أَرَ عُمَرَ قَنِعَ بِقَوْلِ عَمَّارٍ","id":"Telah menceritakan kepada kami [Bisyr bin Khalid] berkata; telah menceritakan kepada kami [Muhammad] -Yaitu Ghundar- telah mengabarkan kepada kami [Syu'bah] dari [Sulaiman] dari [Abu Wa'il] berkata, [Abu Musa] berkata kepada 'Abdullah bin Mas'ud, \"Jika seseorang tidak menemukan air maka ia boleh tidak shalat.\" 'Abdullah menjawab, \"Jika aku beri keringanan kepada mereka dalam masalah ini, maka ketika salah seorang mendapati musim dingin pasti ia akan berkata seperti ini 'yakni Tayamum dan shalat'. Abu Musa berkata, \"Maka aku katakan, \"Kalau begitu dimana kedudukan ucapan 'Ammar kepada 'Umar? ' 'Abdullah bin Mas'ud menjawab: \"Aku menganggap bahwa 'Umar tidak sepakat dengan pendapat ' [Ammar].\""},"333":{"ar":"حَدَّثَنَا عُمَرُ بْنُ حَفْصٍ قَالَ حَدَّثَنَا أَبِي قَالَ حَدَّثَنَا الْأَعْمَشُ قَالَ سَمِعْتُ شَقِيقَ بْنَ سَلَمَةَ قَالَكُنْتُ عِنْدَ عَبْدِ اللَّهِ وَأَبِي مُوسَى فَقَالَ لَهُ أَبُو مُوسَى أَرَأَيْتَ يَا أَبَا عَبْدِ الرَّحْمَنِ إِذَا أَجْنَبَ فَلَمْ يَجِدْ مَاءً كَيْفَ يَصْنَعُ فَقَالَ عَبْدُ اللَّهِ لَا يُصَلِّي حَتَّى يَجِدَ الْمَاءَ فَقَالَ أَبُو مُوسَى فَكَيْفَ تَصْنَعُ بِقَوْلِ عَمَّارٍ حِينَ قَالَ لَهُ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يَكْفِيكَ قَالَ أَلَمْ تَرَ عُمَرَ لَمْ يَقْنَعْ بِذَلِكَ فَقَالَ أَبُو مُوسَى فَدَعْنَا مِنْ قَوْلِ عَمَّارٍ كَيْفَ تَصْنَعُ بِهَذِهِ الْآيَةِ فَمَا دَرَى عَبْدُ اللَّهِ مَا يَقُولُ فَقَالَ إِنَّا لَوْ رَخَّصْنَا لَهُمْ فِي هَذَا لَأَوْشَكَ إِذَا بَرَدَ عَلَى أَحَدِهِمْ الْمَاءُ أَنْ يَدَعَهُ وَيَتَيَمَّمَ فَقُلْتُ لِشَقِيقٍ فَإِنَّمَا كَرِهَ عَبْدُ اللَّهِ لِهَذَا قَالَ نَعَمْ","id":"Telah menceritakan kepada kami [Umar bin Hafsh] berkata; telah menceritakan kepada kami [Bapakku] berkata; telah menceritakan kepada kami [Al A'masy] berkata, aku mendengar [Syaqiq bin Salamah] berkata; aku pernah berada di dekat 'Abdullah bin Mas'ud dan [Abu Musa], Abu Musa lalu berkata kepadanya, \"Bagaimana pendapatmu wahai Abu 'Abdurrahman bila seseorang mengalami junub dan tidak mendapatkan air. Apa yang harus ia lakukan?\" 'Abdullah menjawab, \"Ia tidak boleh shalat hingga mendapatkan air.\" Abu Musa berkata, \"Bagaimana engkau menyikapi perkataan ['Ammar] ketika Nabi shallallahu 'alaihi wasallam berkata kepadanya 'Cukup bagimu begini'? 'Abdullah, \"Apakah kamu tidak tahu kalau 'Umar tidak menerima pendapat tersebut?\" Abu Musa kembali berkata, \"Baik kita tinggalkan pendapat 'Umar! ' Tapi bagaimana sikapmu dengan ayat ini? ' 'Abdullah tidak mengerti apa yang harus ia katakan, lalu ia berkata, \"Jika kami beri keringanan mereka dalam masalah ini, dikhawatirkan jika mereka merasa dingin dengan air, maka mereka tidak mau menggunakan air dan akan melakukan tayamum.\" Aku berkata kepada Syaqiq, 'Hanyasanya 'Abdullah tidak suka adalah karena hal ini.' Ia menjawab, \"Benar.\""},"334":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ سَلَامٍ قَالَ أَخْبَرَنَا أَبُو مُعَاوِيَةَ عَنْ الْأَعْمَشِ عَنْ شَقِيقٍ قَالَكُنْتُ جَالِسًا مَعَ عَبْدِ اللَّهِ وَأَبِي مُوسَى الْأَشْعَرِيِّ فَقَالَ لَهُ أَبُو مُوسَى لَوْ أَنَّ رَجُلًا أَجْنَبَ فَلَمْ يَجِدْ الْمَاءَ شَهْرًا أَمَا كَانَ يَتَيَمَّمُ وَيُصَلِّي فَكَيْفَ تَصْنَعُونَ بِهَذِهِ الْآيَةِ فِي سُورَةِ الْمَائِدَةِ{ فَلَمْ تَجِدُوا مَاءً فَتَيَمَّمُوا صَعِيدًا طَيِّبًا }فَقَالَ عَبْدُ اللَّهِ لَوْ رُخِّصَ لَهُمْ فِي هَذَا لَأَوْشَكُوا إِذَا بَرَدَ عَلَيْهِمْ الْمَاءُ أَنْ يَتَيَمَّمُوا الصَّعِيدَ قُلْتُ وَإِنَّمَا كَرِهْتُمْ هَذَا لِذَا قَالَ نَعَمْ فَقَالَ أَبُو مُوسَى أَلَمْ تَسْمَعْ قَوْلَ عَمَّارٍ لِعُمَرَ بَعَثَنِي رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي حَاجَةٍ ف��أَجْنَبْتُ فَلَمْ أَجِد الْمَاءَ فَتَمَرَّغْتُ فِي الصَّعِيدِ كَمَا تَمَرَّغُ الدَّابَّةُ فَذَكَرْتُ ذَلِكَ لِلنَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ إِنَّمَا كَانَ يَكْفِيكَ أَنْ تَصْنَعَ هَكَذَا فَضَرَبَ بِكَفِّهِ ضَرْبَةً عَلَى الْأَرْضِ ثُمَّ نَفَضَهَا ثُمَّ مَسَحَ بِهِمَا ظَهْرَ كَفِّهِ بِشِمَالِهِ أَوْ ظَهْرَ شِمَالِهِ بِكَفِّهِ ثُمَّ مَسَحَ بِهِمَا وَجْهَهُ فَقَالَ عَبْدُ اللَّهِ أَفَلَمْ تَرَ عُمَرَ لَمْ يَقْنَعْ بِقَوْلِ عَمَّارٍوَزَادَ يَعْلَى عَنْ الْأَعْمَشِ عَنْ شَقِيقٍ كُنْتُ مَعَ عَبْدِ اللَّهِ وَأَبِي مُوسَى فَقَالَ أَبُو مُوسَى أَلَمْ تَسْمَعْ قَوْلَ عَمَّارٍ لِعُمَرَ إِنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بَعَثَنِي أَنَا وَأَنْتَ فَأَجْنَبْتُ فَتَمَعَّكْتُ بِالصَّعِيدِ فَأَتَيْنَا رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَخْبَرْنَاهُ فَقَالَ إِنَّمَا كَانَ يَكْفِيكَ هَكَذَا وَمَسَحَ وَجْهَهُ وَكَفَّيْهِ وَاحِدَةً","id":"Telah menceritakan kepada kami [Muhammad bin Salam] berkata; telah mengabarkan kepada kami [Abu Mu'awiyah] dari [Al A'masy] dari [Syaqiq] ia berkata; Aku pernah duduk bersama 'Abdullah bin Mas'ud dan [Abu Musa Al Asy'ari]. Lalu Abu Musa berkata kepadanya, \"Seandainya ada seseorang mengalami junub dan tidak mendapatkan air selama satu bulan, apakah dia bertayamum dan shalat? Dan bagaimana pendapatmu dengan ayat ini di dalam Surah Al Maidah ayat 6: '(Lalu kamu tidak memperaleh air, maka bertayammumlah dengan tanah yang baik (bersih) '? 'Abdullah, \"Seandainya mereka diberi keringanan dalam masalah ini, bisa jadi nantinya bila ada seseorang dari mereka yang kedinginan dengan air dia akan bertayamum dengan tanah.\" Syaqiq bertanya, \"Apakah kalian tidak suka masalah ini karena faktor itu?\" Dia menjawab, \"Ya.\" Kemudian Abu Musa berkata, \"Tidakkah kamu pernah mendengar ucapan ['Ammar] kepada Umar, 'Rasulullah shallallahu 'alaihi wasallam mengutusku dalam suatu urusan, aku lalu junub dan tidak mendapatkan air. Maka aku pun berguling-guling di atas tanah seperti berguling-gulingnya hewan. Kemudian aku ceritakan hal tersebut kepada Nabi shallallahu 'alaihi wasallam, lalu beliau bersabda: \"Sebenarnya cukup buatmu bila kamu melakukan begini.\" Nabi shallallahu 'alaihi wasallam kemudian memukulkan telapak tangannya ke permukaan tanah dan mengibaskannya, lalu mengusap punggung tangan kanannya dengan telapak tangan kirinya, atau punggung telapak kirinya dengan telapak tangan kanannya, kemudian beliau mengusap wajahnya.\" Abdullah berkata, \"Apakah kamu tidak tahu kalau 'Umar tidak menerima pendapat 'Ammar?\" [Ya'la] menambahkan dari [Al A'masy] dari [Syaqiq], \"Aku pernah bersama 'Abdullah dan Abu Musa. [Abu Musa] lalu berkata, \"Tidakkah kamu mendengar perkataan ['Ammar] kepada 'Umar 'Sesungguhnya Rasulullah shallallahu 'alaihi wasallam mengutus aku dan kamu, lalu aku mengalami junub dan aku bergulingan di atas tanah. Kemudian kita temui Rasulullah shallallahu 'alaihi wasallam menceritakan hal itu kepada beliau. Beliau lalu bersabda: \"Sebenarnya kamu cukup melakukan begini.\" Beliau lalu memukulkan telapak tangannya ke tanah, lalu mengusap muka dan kedua telapak tangannya sekali.\""},"335":{"ar":"بَاب حَدَّثَنَا عَبْدَانُ قَالَ أَخْبَرَنَا عَبْدُ اللَّهِ قَالَ أَخْبَرَنَا عَوْفٌ عَنْ أَبِي رَجَاءٍ قَالَ حَدَّثَنَا عِمْرَانُ بْنُ حُصَيْنٍ الْخُزَاعِيُّأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ رَأَى رَجُلًا مُعْتَزِلًا لَمْ يُصَلِّ فِي الْقَوْمِ فَقَالَ يَا فُلَانُ مَا مَنَعَكَ أَنْ تُصَلِّيَ فِي الْقَوْمِ فَقَالَ يَا رَسُولَ اللَّهِ أَصَابَتْنِي جَنَابَةٌ وَلَا مَاءَ قَالَ عَلَيْكَ بِالصَّعِيدِ فَإِنَّهُ يَكْفِيكَ","id":"Bab. Telah menceritakan kepada kami ['Abdan] berkata, telah mengabarkan kepada kami ['Abdullah] berkata, telah mengabarkan kepada kami ['Auf] dari [Abu Raja'] berkata, telah menceritakan kepada kami ['Imran bin Hushain Al Khaza'i], bahwa Rasulullah shallallahu 'alaihi wasallam melihat seorang menyendiri dan tidak ikut shalat bersama orang banyak, beliau lalu bertanya: \"Wahai fulan, apa yang menghalangi kamu untuk shalat bersama orang-orang?\" Maka orang itu menjawab: \"Wahai Rasulullah, aku mengalami junub dan tidak ada air.\" Maka Nabi shallallahu 'alaihi wasallam bersabda: \"Wajib bagi kamu menggunakan tanah dan itu sudah cukup buatmu.\""},"336":{"ar":"حَدَّثَنَا يَحْيَى بْنُ بُكَيْرٍ قَالَ حَدَّثَنَا اللَّيْثُ عَنْ يُونُسَ عَنْ ابْنِ شِهَابٍ عَنْ أَنَسِ بْنِ مَالِكٍ قَالَ كَانَ أَبُو ذَرٍّ يُحَدِّثُأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ فُرِجَ عَنْ سَقْفِ بَيْتِي وَأَنَا بِمَكَّةَ فَنَزَلَ جِبْرِيلُ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَفَرَجَ صَدْرِي ثُمَّ غَسَلَهُ بِمَاءِ زَمْزَمَ ثُمَّ جَاءَ بِطَسْتٍ مِنْ ذَهَبٍ مُمْتَلِئٍ حِكْمَةً وَإِيمَانًا فَأَفْرَغَهُ فِي صَدْرِي ثُمَّ أَطْبَقَهُ ثُمَّ أَخَذَ بِيَدِي فَعَرَجَ بِي إِلَى السَّمَاءِ الدُّنْيَا فَلَمَّا جِئْتُ إِلَى السَّمَاءِ الدُّنْيَا قَالَ جِبْرِيلُ لِخَازِنِ السَّمَاءِ افْتَحْ قَالَ مَنْ هَذَا قَالَ هَذَا جِبْرِيلُ قَالَ هَلْ مَعَكَ أَحَدٌ قَالَ نَعَمْ مَعِي مُحَمَّدٌ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ أُرْسِلَ إِلَيْهِ قَالَ نَعَمْ فَلَمَّا فَتَحَ عَلَوْنَا السَّمَاءَ الدُّنْيَا فَإِذَا رَجُلٌ قَاعِدٌ عَلَى يَمِينِهِ أَسْوِدَةٌ وَعَلَى يَسَارِهِ أَسْوِدَةٌ إِذَا نَظَرَ قِبَلَ يَمِينِهِ ضَحِكَ وَإِذَا نَظَرَ قِبَلَ يَسَارِهِ بَكَى فَقَالَ مَرْحَبًا بِالنَّبِيِّ الصَّالِحِ وَالِابْنِ الصَّالِحِ قُلْتُ لِجِبْرِيلَ مَنْ هَذَا قَال هَذَا آدَمُ وَهَذِهِ الْأَسْوِدَةُ عَنْ يَمِينِهِ وَشِمَالِهِ نَسَمُ بَنِيهِ فَأَهْلُ الْيَمِينِ مِنْهُمْ أَهْلُ الْجَنَّةِ وَالْأَسْوِدَةُ الَّتِي عَنْ شِمَالِهِ أَهْلُ النَّارِ فَإِذَا نَظَرَ عَنْ يَمِينِهِ ضَحِكَ وَإِذَا نَظَرَ قِبَلَ شِمَالِهِ بَكَى حَتَّى عَرَجَ بِي إِلَى السَّمَاءِ الثَّانِيَةِ فَقَالَ لِخَازِنِهَا افْتَحْ فَقَالَ لَهُ خَازِنِهَا مِثْلَ مَا قَالَ الْأَوَّلُ فَفَتَحَ قَالَ أَنَسٌ فَذَكَرَ أَنَّهُ وَجَدَ فِي السَّمَوَاتِ آدَمَ وَإِدْرِيسَ وَمُوسَى وَعِيسَى وَإِبْرَاهِيمَ صَلَوَاتُ اللَّهِ عَلَيْهِمْ وَلَمْ يُثْبِتْ كَيْفَ مَنَازِلُهُمْ غَيْرَ أَنَّهُ ذَكَرَ أَنَّهُ وَجَدَ آدَمَ فِي السَّمَاءِ الدُّنْيَا وَإِبْرَاهِيمَ فِي السَّمَاءِ السَّادِسَةِ قَالَ أَنَسٌ فَلَمَّا مَرَّ جِبْرِيلُ بِالنَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِإِدْرِيسَ قَالَ مَرْحَبًا بِالنَّبِيِّ الصَّالِحِ وَالْأَخِ الصَّالِحِ فَقُلْتُ مَنْ هَذَا قَالَ هَذَا إِدْرِيسُ ثُمَّ مَرَرْتُ بِمُوسَى فَقَالَ مَرْحَبًا بِالنَّبِيِّ الصَّالِحِ وَالْأَخِ الصَّالِحِ قُلْتُ مَنْ هَذَا قَالَ هَذَا مُوسَى ثُمَّ مَرَرْتُ بِعِيسَى فَقَالَ مَرْحَبًا بِالْأَخِ الصَّالِحِ وَالنَّبِيِّ الصَّالِحِ قُلْتُ مَنْ هَذَا قَالَ هَذَا عِيسَى ثُمَّ مَرَرْتُ بِإِبْرَاهِيمَ فَقَالَ مَرْحَبًا بِالنَّبِيِّ الصَّالِحِ وَالِابْنِ الصَّالِحِ قُلْتُ مَنْ هَذَا قَالَ هَذَا إِبْرَاهِيمُ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ ابْنُ شِهَابٍ فَأَخْبَرَنِي ابْنُ حَزْمٍ أَنَّ ابْنَ عَبَّاسٍ وَأَبَا حَبَّةَ الْأَنْصَارِيَّ كَانَا يَقُولَانِ قَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ثُمَّ عُرِجَ بِي حَتَّى ظَهَرْتُ لِمُسْتَوَى أَسْمَعُ فِيهِ صَرِيفَ الْأَقْلَامِ قَالَ ابْنُ حَزْمٍ وَأَنَسُ بْنُ مَالِكٍ قَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَفَرَضَ اللَّهُ عَزَّ وَجَلَّ عَلَى أُمَّتِي خَمْسِينَ صَلَاةً فَرَجَعْتُ بِذَلِكَ حَتَّى مَرَرْتُ عَلَى مُوسَى فَقَالَ مَا فَرَضَ اللَّهُ لَكَ عَلَى أُمَّتِكَ قُلْتُ فَرَضَ خَمْسِينَ صَلَاةً قَالَ فَارْجِعْ إِلَى رَبِّكَ فَإِنَّ أُمَّتَكَ لَا تُطِيقُ ذَلِكَ فَرَاجَعْتُ فَوَضَعَ شَطْرَهَا فَرَجَعْتُ إِلَى مُوسَى قُلْتُ وَضَعَ شَطْرَهَا فَقَالَ رَاجِعْ رَبَّكَ فَإِنَّ أُمَّتَكَ لَا تُطِيقُ فَرَاجَعْتُ فَوَضَعَ شَطْرَهَا فَرَجَعْتُ إِلَيْهِ فَقَالَ ارْجِعْ إِلَى رَبِّكَ فَإِنَّ أُمَّتَكَ لَا تُطِيقُ ذَلِكَ فَرَاجَعْتُهُ فَقَالَ هِيَ خَمْسٌ وَهِيَ خَمْسُونَ لَا يُبَدَّلُ الْقَوْلُ لَدَيَّ فَرَجَعْتُ إِلَى مُوسَى فَقَالَ رَاجِعْ رَبَّكَ فَقُلْتُ اسْتَحْيَيْتُ مِنْ رَبِّي ثُمَّ انْطَلَقَ بِي حَتَّى انْتَهَى بِي إِلَى سِدْرَةِ الْمُنْتَهَى وَغَشِيَهَا أَلْوَانٌ لَا أَدْرِي مَا هِيَ ثُمَّ أُدْخِلْتُ الْجَنَّةَ فَإِذَا فِيهَا حَبَايِلُ اللُّؤْلُؤِ وَإِذَا تُرَابُهَا الْمِسْكُ","id":"Telah menceritakan kepada kami [Yahya bin Bukair] berkata, telah menceritakan kepada kami [Al Laits] dari [Yunus] dari [Ibnu Syihab] dari [Anas bin Malik] berkata, [Abu Dzar] menceritakan bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Saat aku di Makkah atap rumahku terbuka, tiba-tiba datang Malaikat Jibril Alaihis Salam. Lalu dia membelah dadaku kemudian mencucinya dengan menggunakan air zamzam. Dibawanya pula bejana terbuat dari emas berisi hikmah dan iman, lalu dituangnya ke dalam dadaku dan menutupnya kembali. Lalu dia memegang tanganku dan membawaku menuju langit dunia. Tatkala aku sudah sampai di langit dunia, Jibril Alaihis Salam berkata kepada Malaikat penjaga langit, 'Bukalah'. Malaikat penjaga langit berkata, 'Siapa Ini? ' Jibril menjawab, 'Ini Jibril'. Malaikat penjaga langit bertanya lagi, 'Apakah kamu bersama orang lain? ' Jibril menjawab, \"Ya, bersamaku Muhammad shallallahu 'alaihi wasallam.' Penjaga itu bertanya lagi, 'Apakah dia diutus sebagai Rasul? ' Jibril menjawab, 'Benar.' Ketika dibuka dan kami sampai di langit dunia, ketika itu ada seseorang yang sedang duduk, di sebelah kanan orang itu ada sekelompok manusia begitu juga di sebelah kirinya. Apabila dia melihat kepada sekelompok orang yang di sebelah kanannya ia tertawa, dan bila melihat ke kirinya ia menangis. Lalu orang itu berkata, 'Selamat datang Nabi yang shalih dan anak yang shalih.' Aku bertanya kepada Jibril, 'Siapakah dia? ' Jibril menjawab, \"Dialah Adam Alaihis Salam, dan orang-orang yang ada di sebelah kanan dan kirinya adalah ruh-ruh anak keturunannya. Mereka yang ada di sebelah kanannya adalah para ahli surga sedangkan yang di sebelah kirinya adalah ahli neraka. Jika dia memandang ke sebelah kanannya dia tertawa dan bila memandang ke sebelah kirinya dia menangis.' Kemudian aku dibawa menuju ke langit kedua, Jibril lalu berkata kepada penjaganya seperti terhadap penjaga langit pertama. Maka langit pun dibuka'.\" Anas berkata, \"Kemudian Nabi shallallahu 'alaihi wasallam menyebutkan bahwa pada tingkatan langit-langit itu beliau bertemu dengan Adam, Idris, Musa, 'Isa dan Ibrahim semoga Allah memberi shalawat-Nya kepada mereka. Beliau tidak menceritakan kepadaku keberadaan mereka di langit tersebut, kecuali bahwa beliau bertemu Adam di langit dunia dan Ibrahim di langit keenam.\" Anas melanjutkan, \"Ketika Jibril berjalan bersama Nabi shallallahu 'alaihi wasallam, ia melewati Idris. Maka Idris pun berkata, 'Selamat datang Nabi yang shalih dan saudara yang shalih.' Aku bertanya kepada Jibril, 'Siapakah dia? ' Jibril menjawab, 'Dialah Idris.' Lalu aku berjalan melewati Musa, ia pun berkata, 'Selamat datang Nabi yang shalih dan saudara yang shalih.' Aku bertanya kepada Jibril, 'Siapakah dia? ' Jibril menjawab, 'Dialah Musa.' Kemudian aku berjalan melewati 'Isa, dan ia pun berkata, 'Selamat datang saudara yang shalih dan Nabi yang shalih.' Aku bertanya kepada Jibril, 'Siapakah dia? ' Jibril menjawab, 'Dialah 'Isa.' Kemudian aku melewati Ibrahim dan ia pun berkata, 'Selamat datang Nabi yang shalih dan anak yang shalih.' Aku bertanya kepada Jibril, 'Siapakah dia? ' Jibril menjawab, 'Dialah Ibrahim shallallahu 'alaihi wasallam.' Ibnu Syihab berkata, Ibnu Hazm mengabarkan kepadaku bahwa Ibnu 'Abbas dan Abu Habbah Al Anshari keduanya berkata, \"Nabi shallallahu 'alaihi wasallam bersabda: \"Kemudian aku dimi'rajkan hingga sampai ke suatu tempat yang aku dapat mendengar suara pena yang menulis.\" Ibnu Hazm berkata, \"Anas bin Malik menyebutkan, \"Nabi shallallahu 'alaihi wasallam bersabda: \"Kemudian Allah 'azza wajalla mewajibkan kepada ummatku shalat sebanyak lima puluh kali. Maka aku pergi membawa perintah itu hingga aku berjumpa dengan Musa, lalu ia bertanya, 'Apa yang Allah perintahkan buat umatmu? ' Aku jawab: 'Shalat lima puluh kali.' Lalu dia berkata, 'Kembalilah kepada Rabbmu, karena umatmu tidak akan sanggup! ' Maka aku kembali dan Allah mengurangi setengahnya. Aku kemudian kembali menemui Musa dan aku katakan bahwa Allah telah mengurangi setengahnya. Tapi ia berkata, 'Kembalilah kepada Rabbmu karena umatmu tidak akan sanggup.' Aku lalu kembali menemui Allah dan Allah kemudian mengurangi setengahnya lagi.' Kemudian aku kembali menemui Musa, ia lalu berkata, 'Kembalilah kepada Rabbmu, karena umatmu tetap tidak akan sanggup.' Maka aku kembali menemui Allah Ta'ala, Allah lalu berfirman: 'Lima ini adalah sebagai pengganti dari lima puluh. Tidak ada lagi perubahan keputusan di sisi-Ku! ' Maka aku kembali menemui Musa dan ia kembali berkata, 'Kembailah kepada Rabb-Mu! ' Aku katakan, 'Aku malu kepada Rabb-ku.' Jibril lantas membawaku hingga sampai di Sidratul Muntaha yang diselimuti dengan warna-warni yang aku tidak tahu benda apakah itu. Kemudian aku dimasukkan ke dalam surga, ternyata di dalamnya banyak kubah-kubah terbuat dari mutiara dan tanahnya dari minyak kesturi.\""},"337":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ يُوسُفَ قَالَ أَخْبَرَنَا مَالِكٌ عَنْ صَالِحِ بْنِ كَيْسَانَ عَنْ عُرْوَةَ بْنِ الزُّبَيْرِ عَنْ عَائِشَةَ أُمِّ الْمُؤْمِنِينَ قَالَتْفَرَضَ اللَّهُ الصَّلَاةَ حِينَ فَرَضَهَا رَكْعَتَيْنِ رَكْعَتَيْنِ فِي الْحَضَرِ وَالسَّفَرِ فَأُقِرَّتْ صَلَاةُ السَّفَرِ وَزِيدَ فِي صَلَاةِ الْحَضَرِ","id":"Telah menceritakan kepada kami ['Abdullah bin Yusuf] berkata, telah mengabarkan kepada kami [Malik] dari [Shalih bin Kaisan] dari ['Urwah bin Az Zubair] dari ['Aisyah] Ibu kaum Mu'minin, ia berkata, \"Allah telah mewajibkan shalat, dan awal diwajibkannya adalah dua rakaat dua rakaat, baik saat mukim atau saat dalam perjalanan. Kemudian ditetapkanlah ketentuan tersebut untuk shalat safar (dalam perjalanan), dan ditambahkan lagi untuk shalat di saat mukim.\""},"338":{"ar":"حَدَّثَنَا مُوسَى بْنُ إِسْمَاعِيلَ قَالَ حَدَّثَنَا يَزِيدُ بْنُ إِبْرَاهِيمَ عَنْ مُحَمَّدٍ عَنْ أُمِّ عَطِيَّةَ قَالَتْأُمِرْنَا أَنْ نُخْرِجَ الْحُيَّضَ يَوْمَ الْعِيدَيْنِ وَذَوَاتِ الْخُدُورِ فَيَشْهَدْنَ جَمَاعَةَ الْمُسْلِمِينَ وَدَعْوَتَهُمْ وَيَعْتَزِلُ الْحُيَّضُ عَنْ مُصَلَّاهُنَّ قَالَتْ امْرَأَةٌ يَا رَسُولَ اللَّهِ إِحْدَانَا لَيْسَ لَهَا جِلْبَابٌ قَالَ لِتُلْبِسْهَا صَاحِبَتُهَا مِنْ جِلْبَابِهَاوَقَالَ عَبْدُ اللَّهِ بْنُ رَجَاءٍ حَدَّثَنَا عِمْرَانُ حَدَّثَنَا مُحَمَّدُ بْنُ سِيرِينَ حَدَّثَتْنَا أُمُّ عَطِيَّةَ سَمِعْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِهَذَا","id":"Telah menceritakan kepada kami [Musa bin Isma'il] berkata, telah menceritakan kepada kami [Yazid bin Ibrahim] dari [Muhammad] dari [Ummu 'Athiyah] berkata, \"Kami diperintahkan untuk mengajak keluar (wanita) haid dan wanita yang sedang dipingit pada dua hari raya, sehingga mereka bisa menyaksikan jama'ah kaum Muslimin dan mendo'akan mereka, lalu menjauhkan wanita-wanita haid dari tempat shalat mereka.\" Seorang wanita lalu, \"Wahai Rasulullah, di antara kami ada yang tidak memiliki jilbab?\" Beliau menjawab: \"Hendaklah temannya meminjamkan jilbab miliknya kepadanya.\" ['Abdullah bin Raja'] berkata, telah menceritakan kepada kami ['Imran] telah menceritakan kepada kami [Muhammad bin Sirin] telah menceritakan kepada kami [Ummu 'Athiyah] aku mendengar Nabi shallallahu 'alaihi wasallam bersabda seperti ini.\""},"339":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ يُونُسَ قَالَ حَدَّثَنَا عَاصِمُ بْنُ مُحَمَّدٍ قَالَ حَدَّثَنِي وَاقِدُ بْنُ مُحَمَّدٍ عَنْ مُحَمَّدِ بْنِ الْمُنْكَدِرِ قَالَ صَلَّى جَابِرٌفِي إِزَارٍ قَدْ عَقَدَهُ مِنْ قِبَلِ قَفَاهُ وَثِيَابُهُ مَوْضُوعَةٌ عَلَى الْمِشْجَبِ قَالَ لَهُ قَائِلٌ تُصَلِّي فِي إِزَارٍ وَاحِدٍ فَقَالَ إِنَّمَا صَنَعْتُ ذَلِكَ لِيَرَانِي أَحْمَقُ مِثْلُكَ وَأَيُّنَا كَانَ لَهُ ثَوْبَانِ عَلَى عَهْدِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah menceritakan kepada kami [Ahmad bin Yunus] berkata, telah menceritakan kepada kami ['Ashim bin Muhammad] berkata, telah menceritakan kepadaku [Waqid bin Muhammad] dari [Muhammad bin Al Munkadir] berkata, \"Jabir mengerjakan shalat dengan mengenakan sarung yang ia ikatkan pada leher (tengkuk), sementara pakaiannya ia gantungnya di gantungan baju. Seseorang lalu berkata kepadanya, \"Kenapa kamu shalat dengan menggunakan satu kain!\" [Jabir bin Samurah] menjawab, \"Aku lakukan itu agar bisa dilihat oleh orang bodoh seperti kamu. Sebab mana ada pada masa Nabi shallallahu 'alaihi wasallam, di antara kami yang memiliki dua kain!\""},"340":{"ar":"حَدَّثَنَا مُطَرِّفٌ أَبُو مُصْعَبٍ قَالَ حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ أَبِي الْمَوَالِي عَنْ مُحَمَّدِ بْنِ الْمُنْكَدِرِ قَالَ رَأَيْتُ جَابِرَ بْنَ عَبْدِ اللَّهِيُصَلِّي فِي ثَوْبٍ وَاحِدٍ وَقَالَ رَأَيْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُصَلِّي فِي ثَوْبٍ","id":"Telah menceritakan kepada kami [Mutharrif Abu Mush'ab] berkata, telah menceritakan kepada kami ['Abdurrahman bin Abu Al Mawali] dari [Muhammad bin Al Munkadir] berkata, \"Aku melihat [Jabir bin 'Abdullah] melaksanakan shalat dengan mengenakan satu pakaian. Lalu dia berkata, \"Aku pernah melihat Nabi shallallahu 'alaihi wasallam shalat dengan mengenakan (satu) kain.\""},"341":{"ar":"حَدَّثَنَا عُبَيْدُ اللَّهِ بْنُ مُوسَى قَالَ حَدَّثَنَا هِشَامُ بْنُ عُرْوَةَ عَنْ أَبِيهِ عَنْ عُمَرَ بْنِ أَبِي سَلَمَةَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ صَلَّى فِي ثَوْبٍ وَاحِدٍ قَدْ خَالَفَ بَيْنَ طَرَفَيْهِ","id":"Telah menceritakan kepada kami ['Ubaidullah bin Musa] berkata, telah menceritakan kepada kami [Hisyam bin 'Urwah] dari [Bapaknya] dari ['Umar bin Abu Salamah], bahwa Nabi shallallahu 'alaihi wasallam shalat dengan mengenakan satu kain yang diikatkan pada kedua sisinya.\""},"342":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ الْمُثَنَّى قَالَ حَدَّثَنَا يَحْيَى قَالَ حَدَّثَنَا هِشَامٌ قَالَ حَدَّثَنِي أَبِي عَنْ عُمَرَ بْنِ أَبِي سَلَمَةَأَنَّهُ رَأَى النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُصَلِّي فِي ثَوْبٍ وَاحِدٍ فِي بَيْتِ أُمِّ سَلَمَةَ قَدْ أَلْقَى طَرَفَيْهِ عَلَى عَاتِقَيْهِ","id":"Telah menceritakan kepada kami [Muhammad bin Al Mutsanna] berkata, telah menceritakan kepada kami [Yahya] berkata, telah menceritakan kepada kami [Hisyam] berkata, telah menceritakan kepadaku [Bapakku] dari ['Umar bin Abu Salamah] bahwa dia melihat Nabi shallallahu 'alaihi wasallam shalat di rumah Ummu Salamah dengan mengenakan satu kain yang kedua sisinya digantungkan pada kedua pundaknya.\""},"343":{"ar":"حَدَّثَنَا عُبَيْدُ بْنُ إِسْمَاعِيلَ قَالَ حَدَّثَنَا أَبُو أُسَامَةَ عَنْ هِشَامٍ عَنْ أَبِيهِ أَنَّ عُمَرَ بْنَ أَبِي سَلَمَةَ أَخْبَرَه�� قَالَرَأَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُصَلِّي فِي ثَوْبٍ وَاحِدٍ مُشْتَمِلًا بِهِ فِي بَيْتِ أُمِّ سَلَمَةَ وَاضِعًا طَرَفَيْهِ عَلَى عَاتِقَيْهِ","id":"Telah menceritakan kepada kami ['Ubaid bin Isma'il] berkata, telah menceritakan kepada kami [Abu Usamah] dari [Hisyam] dari [Bapaknya] bahwa ['Umar bin Abu Salamah] mengabarkan kepadanya, ia berkata, \"Aku melihat Rasulullah shallallahu 'alaihi wasallam shalat di rumah Ummu Salamah dengan mengenakan satu kain yang menutupi seluruh badannya yang diletakkan pada kedua pundaknya.\""},"344":{"ar":"حَدَّثَنَا إِسْمَاعِيلُ بْنُ أَبِي أُوَيْسٍ قَالَ حَدَّثَنِي مَالِكُ بْنُ أَنَسٍ عَنْ أَبِي النَّضْرِ مَوْلَى عُمَرَ بْنِ عُبَيْدِ اللَّهِ أَنَّ أَبَا مُرَّةَ مَوْلَى أُمِّ هَانِئٍ بِنْتِ أَبِي طَالِبٍ أَخْبَرَهُ أَنَّهُ سَمِعَ أُمَّ هَانِئٍ بِنْتَ أَبِي طَالِبٍ تَقُولُذَهَبْتُ إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَامَ الْفَتْحِ فَوَجَدْتُهُ يَغْتَسِلُ وَفَاطِمَةُ ابْنَتُهُ تَسْتُرُهُ قَالَتْ فَسَلَّمْتُ عَلَيْهِ فَقَالَ مَنْ هَذِهِ فَقُلْتُ أَنَا أُمُّ هَانِئٍ بِنْتُ أَبِي طَالِبٍ فَقَالَ مَرْحَبًا بِأُمِّ هَانِئٍ فَلَمَّا فَرَغَ مِنْ غُسْلِهِ قَامَ فَصَلَّى ثَمَانِيَ رَكَعَاتٍ مُلْتَحِفًا فِي ثَوْبٍ وَاحِدٍ فَلَمَّا انْصَرَفَ قُلْتُ يَا رَسُولَ اللَّهِ زَعَمَ ابْنُ أُمِّي أَنَّهُ قَاتِلٌ رَجُلًا قَدْ أَجَرْتُهُ فُلَانَ ابْنَ هُبَيْرَةَ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَدْ أَجَرْنَا مَنْ أَجَرْتِ يَا أُمَّ هَانِئٍ قَالَتْ أُمُّ هَانِئٍ وَذَاكَ ضُحًى","id":"Telah menceritakan kepada kami [Isma'il bin Abu Uwais] berkata, telah menceritakan kepadaku [Malik bin Anas] dari [Abu An Nadlar] mantan budak 'Umar bin 'Abdullah bahwa [Abu Murrah] mantan budak Ummu Hani' binti Abu Thalib mengabarkan kepadanya, bahwa ia mendengar [Ummu Hani' binti Abu Thalib] berkata, \"Aku berkunjung kepada Rasulullah shallallahu 'alaihi wasallam pada hari pembebasan Makkah, aku dapati beliau mandi sementara Fatimah, puteri beliau menutupinya dengan tabir.\" Ummu Hani' binti Abu Thalib berkata, \"Aku lantas memberi salam kepada beliau, lalu beliau bertanya: \"Siapakah ini?\" Aku menjawab, \"Aku Ummu Hani' binti Abu Thalib.\" Lalu beliau bertanya, \"Selamat datang wahai Ummu Hani'.\" Setelah selesai mandi beliau shalat delapan rakaat dengan berselimut pada satu baju. Setelah selesai shalat aku berkata, \"Wahai Rasulullah, anak ibuku mengatakan dia telah membunuh seseorang dan aku telah memberi ganti rugi kepada seseorang yakni Abu Hubairah.\" Maka Rasulullah shallallahu 'alaihi wasallam: \"Kami telah setuju apa yang engkau berikan wahai Ummu Hani'!\" Ummu Hani' berkata, \"Saat itu adalah waktu dluha.\""},"345":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ يُوسُفَ قَالَ أَخْبَرَنَا مَالِكٌ عَنْ ابْنِ شِهَابٍ عَنْ سَعِيدِ بْنِ الْمُسَيَّبِ عَنْ أَبِي هُرَيْرَةَأَنَّ سَائِلًا سَأَلَ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ الصَّلَاةِ فِي ثَوْبٍ وَاحِدٍ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَوَلِكُلِّكُمْ ثَوْبَانِ","id":"Telah menceritakan kepada kami ['Abdullah bin Yusuf] berkata, telah mengabarkan kepada kami [Malik] dari [Ibnu Syihab] dari [Sa'id bin Al Musayyab] dari [Abu Hurairah] bahwa ada seseorang bertanya kepada Rasulullah shallallahu 'alaihi wasallam tentang shalat menggunakan satu baju. Maka Rasulullah shallallahu 'alaihi wasallam bersabda: \"Apakah setiap orang dari kalian memiliki dua baju?\""},"346":{"ar":"حَدَّثَنَا أَبُو عَاصِمٍ عَنْ مَالِكٍ عَنْ أَبِي الزِّنَادِ عَنْ عَبْدِ الرَّحْمَنِ الْأَعْرَجِ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا يُصَلِّي أَحَدُكُمْ فِي الثَّوْبِ الْوَاحِدِ لَيْسَ عَلَى عَاتِقَيْهِ شَيْءٌ","id":"Telah menceritakan kepada kami [Abu 'Ashim] dari [Malik] dari [Abu Az Zanad] dari ['Abdurrahman Al 'raj] dari [Abu Hurairah] berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Janganlah salah seorang dari kalian shalat dengan menggunakan satu kain, hingga tidak selembar pun kain yang menutupi kedua pundaknya.\""},"347":{"ar":"حَدَّثَنَا أَبُو نُعَيْمٍ قَالَ حَدَّثَنَا شَيْبَانُ عَنْ يَحْيَى بْنِ أَبِي كَثِيرٍ عَنْ عِكْرِمَةَ قَالَ سَمِعْتُهُ أَوْ كُنْتُ سَأَلْتُهُ قَالَ سَمِعْتُ أَبَا هُرَيْرَةَ يَقُولُأَشْهَدُ أَنِّي سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ مَنْ صَلَّى فِي ثَوْبٍ وَاحِدٍ فَلْيُخَالِفْ بَيْنَ طَرَفَيْهِ","id":"Telah menceritakan kepada kami [Abu Nu'aim] berkata, telah menceritakan kepada kami [Syaiban] dari [Yahya bin Abu Katsir] dari ['Ikrimah] berkata, \"Aku pernah mendengar, atau aku pernah bertanya kepadanya, ia berkata, \"Aku mendengar [Abu Hurairah] berkata, \"Aku bersumpah bahwa aku mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa shalat dengan menggunakan satu kain, maka hendaklah ia serempangkan pada kedua pundaknya.\""},"348":{"ar":"حَدَّثَنَا يَحْيَى بْنُ صَالِحٍ قَالَ حَدَّثَنَا فُلَيْحُ بْنُ سُلَيْمَانَ عَنْ سَعِيدِ بْنِ الْحَارِثِ قَالَ سَأَلْنَا جَابِرَ بْنَ عَبْدِ اللَّهِعَنْ الصَّلَاةِ فِي الثَّوْبِ الْوَاحِدِ فَقَالَ خَرَجْتُ مَعَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي بَعْضِ أَسْفَارِهِ فَجِئْتُ لَيْلَةً لِبَعْضِ أَمْرِي فَوَجَدْتُهُ يُصَلِّي وَعَلَيَّ ثَوْبٌ وَاحِدٌ فَاشْتَمَلْتُ بِهِ وَصَلَّيْتُ إِلَى جَانِبِهِ فَلَمَّا انْصَرَفَ قَالَ مَا السُّرَى يَا جَابِرُ فَأَخْبَرْتُهُ بِحَاجَتِي فَلَمَّا فَرَغْتُ قَالَ مَا هَذَا الِاشْتِمَالُ الَّذِي رَأَيْتُ قُلْتُ كَانَ ثَوْبٌ يَعْنِي ضَاقَ قَالَ فَإِنْ كَانَ وَاسِعًا فَالْتَحِفْ بِهِ وَإِنْ كَانَ ضَيِّقًا فَاتَّزِرْ بِهِ","id":"Telah menceritakan kepada kami [Yahya bin Shalih] berkata, telah menceritakan kepada kami [Fulaih bin Sulaiman] dari [Sa'id bin Al Harits] berkata, \"Kami bertanya kepada [Jabir bin 'Abdullah] tentang shalat dengan mengenakan satu lembar kain. Maka ia menjawab, \"Aku pernah shalat bersama Nabi shallallahu 'alaihi wasallam dalam salah satu perjalanannya. Pada suau malamnya aku datang untuk keperluanku. Saat itu aku dapati beliau sedang shalat dengan mengenakan satu kain. Maka aku bergabung dengan beliau dan shalat disampingnya. Setelah selesai beliau bertanya: \"Ada urusan apa (malam-malam begini) kamu datang wahai Jabir?\" Maka aku sampaikan keperluanku kepada beliau. Setelah aku selesai, beliau berkata: \"Kenapa aku lihat kamu menyelimutkan (kain) seperti ini? ' Aku jawab, \"Kainku sempit!\" Beliau bersabda: \"Jika kain itu lebar maka diikatkanlah dari pundak, namun bila sempit maka cukup dikenakan (sebatas untuk menutup aurat).\""},"349":{"ar":"حَدَّثَنَا مُسَدَّدٌ قَالَ حَدَّثَنَا يَحْيَى عَنْ سُفْيَانَ قَالَ حَدَّثَنِي أَبُو حَازِمٍ عَنْ سَهْلِ بْنِ سَعْدٍ قَالَكَانَ رِجَالٌ يُصَلُّونَ مَعَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَاقِدِي أُزْرِهِمْ عَلَى أَعْنَاقِهِمْ كَهَيْئَةِ الصِّبْيَانِ وَيُقَالُ لِلنِّسَاءِ لَا تَرْفَعْنَ رُءُوسَكُنَّ حَتَّى يَسْتَوِيَ الرِّجَالُ جُلُوسًا","id":"Telah menceritakan kepada kami [Musaddad] berkata, telah menceritakan kepada kami [Yahya] dari [Sufyan] berkata, telah menceritakan kepadaku [Abu Hazim] dari [Sahal bin Sa'd] berkata, \"Kaum laki-laki shalat bersama Nabi shallallahu 'alaihi wasallam dengan mengikatkan kain pada leher-leher mereka seperti bayi. Lalu dikatakan kepada kaum wanita: \"Janganlah kalian mengangkat kepala kalian hingga para laki-laki telah duduk.\""},"350":{"ar":"حَدَّثَنَا يَحْيَى قَالَ حَدَّثَنَا أَبُو مُعَاوِيَةَ عَنْ الْأَعْمَشِ عَنْ مُسْلِمٍ عَنْ مَسْرُوقٍ عَنْ مُغِيرَةَ بْنِ شُعْبَةَ قَالَكُنْتُ مَعَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي سَفَرٍ فَقَالَ يَا مُغِيرَةُ خُذْ الْإِدَاوَةَ فَأَخَذْتُهَا فَانْطَلَقَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حَتَّى تَوَارَى عَنِّي فَقَضَى حَاجَتَهُ وَعَلَيْهِ جُبَّةٌ شَأْمِيَّةٌ فَذَهَبَ لِيُخْرِجَ يَدَهُ مِنْ كُمِّهَا فَضَاقَتْ فَأَخْرَجَ يَدَهُ مِنْ أَسْفَلِهَا فَصَبَبْتُ عَلَيْهِ فَتَوَضَّأَ وُضُوءَهُ لِلصَّلَاةِ وَمَسَحَ عَلَى خُفَّيْهِ ثُمَّ صَلَّى","id":"Telah menceritakan kepada kami [Yahya] berkata, telah menceritakan kepada kami [Abu Mu'awiyah] dari [Al A'masy] dari [Muslim] dari [Masruq] dari [Mughirah bin Syu'bah] berkata, \"Aku pernah bersama Nabi shallallahu 'alaihi wasallam dalam suatu perjalanan, beliau bersabda: \"Wahai Mughirah, ambilkan segayung air.\" Aku lalu mencarikan air untuk beliau, dan Rasulullah shallallahu 'alaihi wasallam pergi manjuah hingga tidak terlihat olehku untuk buang hajat. Saat itu beliau mengenakan jubah lebar, beliau berusaha mengeluarkan tangannya lewat lubang lengan namun terlalu sempit. Lalu beliau mengeluarkan tangannya lewat bawah jubahnya, lantas aku sodorkan segayung air kemudian beliau berwudlu sebagaimana wudlu untuk shalat dengan mengusap kedua sepatunya lalu shalat.\""},"351":{"ar":"حَدَّثَنَا مَطَرُ بْنُ الْفَضْلِ قَالَ حَدَّثَنَا رَوْحٌ قَالَ حَدَّثَنَا زَكَرِيَّاءُ بْنُ إِسْحَاقَ حَدَّثَنَا عَمْرُو بْنُ دِينَارٍ قَالَ سَمِعْتُ جَابِرَ بْنَ عَبْدِ اللَّهِ يُحَدِّثُأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يَنْقُلُ مَعَهُمْ الْحِجَارَةَ لِلْكَعْبَةِ وَعَلَيْهِ إِزَارُهُ فَقَالَ لَهُ الْعَبَّاسُ عَمُّهُ يَا ابْنَ أَخِي لَوْ حَلَلْتَ إِزَارَكَ فَجَعَلْتَ عَلَى مَنْكِبَيْكَ دُونَ الْحِجَارَةِ قَالَ فَحَلَّهُ فَجَعَلَهُ عَلَى مَنْكِبَيْهِ فَسَقَطَ مَغْشِيًّا عَلَيْهِ فَمَا رُئِيَ بَعْدَ ذَلِكَ عُرْيَانًا صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah menceritakan kepada kami [Mathar bin Al Fadlal] berkata, telah menceritakan kepada kami [Rauh] berkata, telah menceritakan kepada kami [Zakaria bin Ishaq] telah menceritakan kepada kami ['Amru bin Dinar] berkata, aku mendengar [Jabir bin 'Abdullah] menceritakan bahwa Rasulullah shallallahu 'alaihi wasallam bersama orang-orang Quraisy memindahkan batu Ka'bah sementara saat itu beliau mengenakan kain lebar.\" Pamannya, Al 'Abbas, lalu berkata kepadanya, \"Wahai anak saudaraku, seandainya kainmu engkau letakkan pada pundakmu tentu batu akan lebih ringan. Maka beliau lepas dan dipakaikannya di pundaknya, tiba-tiba beliau terjatuh dan pingsan. Setelah peristiwa itu tidak pernah Nabi shallallahu 'alaihi wasallam terlihat telanjang.\""},"352":{"ar":"حَدَّثَنَا سُلَيْمَانُ بْنُ حَرْبٍ قَالَ حَدَّثَنَا حَمَّادُ بْنُ زَيْدٍ عَنْ أَيُّوبَ عَنْ مُحَمَّدٍ عَنْ أَبِي هُرَيْرَةَ قَالَقَامَ رَجُلٌ إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَسَأَلَهُ عَنْ الصَّلَاةِ فِي الثَّوْبِ الْوَاحِدِ فَقَالَ أَوَكُلُّكُمْ يَجِدُ ثَوْبَيْنِ ثُمَّ سَأَلَ رَجُلٌ عُمَرَ فَقَالَ إِذَا وَسَّعَ اللَّهُ فَأَوْسِعُوا جَمَعَ رَجُلٌ عَلَيْهِ ثِيَابَهُ صَلَّى رَجُلٌ فِي إِزَارٍ وَرِدَاءٍ فِي إِزَارٍ وَقَمِيصٍ فِي إِزَارٍ وَقَبَاءٍ فِي سَرَاوِيلَ وَرِدَاءٍ فِي سَرَاوِيلَ وَقَمِيصٍ فِي سَرَاوِيلَ وَقَبَاءٍ فِي تُبَّانٍ وَقَبَاءٍ فِي تُبَّانٍ وَقَمِيصٍ قَالَ وَأَحْسِبُهُ قَالَ فِي تُبَّانٍ وَرِدَاءٍ","id":"Telah menceritakan kepada kami [Sulaiman bin Harb] berkata, telah menceritakan kepada kami [Hammad bin Zaid] dari [Ayyub] dari [Muhammad] dari [Abu Hurairah] berkata, \"Seorang laki-laki datang dan bertanya kepada Rasulullah shallallahu 'alaihi wasallam tentang shalat dengan menggunakan satu lembar baju. Maka Rasulullah shallallahu 'alaihi wasallam pun bersabda: \"Apakah setiap kalian memiliki dua helai baju?\" Kemudian ada seseorang bertanya kepada 'Umar, lalu ia menjawab, \"Jika Allah memberi kelapangan (kemudahan), maka pergunakanlah.\" Bila seseorang memiliki banyak pakaian, maka dia shalat dengan pakaiannya itu. Ada yang shalat dengan memakai kain dan rida (selendang besar), ada yang memakai kain dan gamis (baju panjang sampai kaki), ada yang memakai kain dan baju, ada yang memakai celana panjang dan rida', ada yang memakai celana panjang dan gamis, ada yang memakai celana panjang dan baju, ada yang memakai celana pendek dan rida', ada yang memakai celana pendek dan gamis.\" Abu Hurairah berkata, \"Menurutku 'Umar mengatakan, \"Dan ada yang memakai celana pendek dan rida'.\""},"353":{"ar":"حَدَّثَنَا عَاصِمُ بْنُ عَلِيٍّ قَالَ حَدَّثَنَا ابْنُ أَبِي ذِئْبٍ عَنْ الزُّهْرِيِّ عَنْ سَالِمٍ عَنْ ابْنِ عُمَرَ قَالَسَأَلَ رَجُلٌ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ مَا يَلْبَسُ الْمُحْرِمُ فَقَالَ لَا يَلْبَسُ الْقَمِيصَ وَلَا السَّرَاوِيلَ وَلَا الْبُرْنُسَ وَلَا ثَوْبًا مَسَّهُ الزَّعْفَرَانُ وَلَا وَرْسٌ فَمَنْ لَمْ يَجِدْ النَّعْلَيْنِ فَلْيَلْبَسْ الْخُفَّيْنِ وَلْيَقْطَعْهُمَا حَتَّى يَكُونَا أَسْفَلَ مِنْ الْكَعْبَيْنِوَعَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِثْلَهُ","id":"Telah menceritakan kepada kami ['Ashim bin 'Ali] berkata, telah menceritakan kepada kami [Ibnu Abu Dzi'b] dari [Az Zuhri] dari [Salim] dari [Ibnu 'Umar] berkata, \"Ada seseorang bertanya kepada Rasulullah shallallahu 'alaihi wasallam, \"Apa yang harus dikenakan oleh seseorang saat ihram?\" Rasulullah shallallahu 'alaihi wasallam menjawab: \"Dia tidak boleh mengenakan baju, celana, mantel dan tidak boleh pula pakaian yang diberi minyak wangi atau wewangian dari daun tumbuhan. Dan siapa yang tidak memiliki sandal, ia boleh mengenakan sepatu tapi hendaklah dipotong hingga berada dibawah mata kaki.\" Dan dari [Nafi'] dari [Ibnu 'Umar] dari Nabi shallallahu 'alaihi wasallam seperti ini juga.\""},"354":{"ar":"حَدَّثَنَا قُتَيْبَةُ بْنُ سَعِيدٍ قَالَ حَدَّثَنَا لَيْثٌ عَنْ ابْنِ شِهَابٍ عَنْ عُبَيْدِ اللَّهِ بْنِ عَبْدِ اللَّهِ بْنِ عُتْبَةَ عَنْ أَبِي سَعِيدٍ الْخُدْرِيِّ أَنَّهُ قَالَنَهَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ اشْتِمَالِ الصَّمَّاءِ وَأَنْ يَحْتَبِيَ الرَّجُلُ فِي ثَوْبٍ وَاحِدٍ لَيْسَ عَلَى فَرْجِهِ مِنْهُ شَيْءٌ","id":"Telah menceritakan kepada kami [Qutaibah bin Sa'id] berkata, telah menceritakan kepada kami [Laits] dari [Ibnu Syihab] dari ['Ubaidullah bin 'Abdullah bin 'Utbah] dari [Abu Sa'id Al Khudri] bahwa ia berkata, \"Rasulullah shallallahu 'alaihi wasallam melarang seseorang mengenakan pakaian shama` (berselimut sehingga seluruh bagian badannya tertutup) dan melarang seseorang duduk ihtiba` dengan selembar kain hingga tidak ada yang menutupi bagian kemaluannya.\" "},"355":{"ar":"حَدَّثَنَا قَبِيصَةُ بْنُ عُقْبَةَ قَالَ حَدَّثَنَا سُفْيَانُ عَنْ أَبِي الزِّنَادِ عَنْ الْأَعْرَجِ عَنْ أَبِي هُرَيْرَةَ قَالَنَهَى النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ بَيْعَتَيْنِ عَنْ اللِّمَاسِ وَالنِّبَاذِ وَأَنْ يَشْتَمِلَ الصَّمَّاءَ وَأَنْ يَحْتَبِيَ الرَّجُلُ فِي ثَوْبٍ وَاحِدٍ","id":"Telah menceritakan kepada kami [Qabishah bin 'Uqbah] berkata, telah menceritakan kepada kami [Sufyan] dari [Abu Az Zinad] dari [Al A'raj] dari [Abu Hurairah] berkata, \"Nabi shallallahu 'alaihi wasallam melarang dua macam jual beli; jual beli Al Limas dan An Nibadz. Dan melarang dari dua cara berpakaian; berpakaian shama` dan seorang laki-laki duduk ihtiba dengan mengenakan satu kain.\" "},"356":{"ar":"حَدَّثَنَا إِسْحَاقُ قَالَ حَدَّثَنَا يَعْقُوبُ بْنُ إِبْرَاهِيمَ قَالَ حَدَّثَنَا ابْنُ أَخِي ابْنِ شِهَابٍ عَنْ عَمِّهِ قَالَ أَخْبَرَنِي حُمَيْدُ بْنُ عَبْدِ الرَّحْمَنِ بْنِ عَوْفٍ أَنَّ أَبَا هُرَيْرَةَ قَالَبَعَثَنِي أَبُو بَكْرٍ فِي تِلْكَ الْحَجَّةِ فِي مُؤَذِّنِينَ يَوْمَ النَّحْرِ نُؤَذِّنُ بِمِنًى أَنْ لَا يَحُجَّ بَعْدَ الْعَامِ مُشْرِكٌ وَلَا يَطُوفَ بِالْبَيْتِ عُرْيَانٌ قَالَ حُمَيْدُ بْنُ عَبْدِ الرَّحْمَنِ ثُمَّ أَرْدَفَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَلِيًّا فَأَمَرَهُ أَنْ يُؤَذِّنَ بِبَرَاءَةٌ قَالَ أَبُو هُرَيْرَةَ فَأَذَّنَ مَعَنَا عَلِيٌّ فِي أَهْل مِنًى يَوْمَ النَّحْرِ لَا يَحُجُّ بَعْدَ الْعَامِ مُشْرِكٌ وَلَا يَطُوفُ بِالْبَيْتِ عُرْيَانٌ","id":"Telah menceritakan kepada kami [Ishaq] berkata, telah menceritakan kepada kami [Ya'qub bin Ibrahim] berkata, telah menceritakan kepada kami [anak saudara Ibnu Syihab] dari [Pamannya] berkata, telah mengabarkan kepadaku [Humaid bin 'Abdurrahman bin 'Auf] bahwa [Abu Hurairah] berkata, \"Pada hari Nahr (Idul Adlha) Abu Bakar mengutusku kepada para pemberi pengumuman saat pelaksanaan haji, di Mina kami umumkan bahwa orang Musyrik tidak boleh berhaji setelah tahun ini dan tidak boleh thawaf dengan keadaan telanjang.\" Humaid bin 'Abdurrahman berkata, \"Kemudian Rasulullah shallallahu 'alaihi wasallam membonceng Ali pada tunggangannya dan memerintahkannya untuk mengumumkan surat Al Bara'ah (At-Taubah).\" Abu Hurairah berkata, \"'Ali lalu mengumumkan bersama kami pada penduduk Mina di hari Nahar, bahwa orang Musyrik tidak boleh berhaji setelah tahun ini dan tidak boleh thawaf dengan keadaan telanjang.\""},"357":{"ar":"حَدَّثَنَا عَبْدُ الْعَزِيزِ بْنُ عَبْدِ اللَّهِ قَالَ حَدَّثَنِي ابْنُ أَبِي الْمَوَالِي عَنْ مُحَمَّدِ بْنِ الْمُنْكَدِرِ قَالَ دَخَلْتُ عَلَى جَابِرِ بْنِ عَبْدِ اللَّهِوَهُوَ يُصَلِّي فِي ثَوْبٍ مُلْتَحِفًا بِهِ وَرِدَاؤُهُ مَوْضُوعٌ فَلَمَّا انْصَرَفَ قُلْنَا يَا أَبَا عَبْدِ اللَّهِ تُصَلِّي وَرِدَاؤُكَ مَوْضُوعٌ قَالَ نَعَمْ أَحْبَبْتُ أَنْ يَرَانِي الْجُهَّالُ مِثْلُكُمْ رَأَيْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُصَلِّي هَكَذَا","id":"Telah menceritakan kepada kami ['Abdul Aziz bin 'Abdullah] berkata, telah menceritakan kepadaku [Ibnu Abu Al Mawali] dari [Muhammad bin Al Munkadir] berkata, \"Aku masuk menemui [Jabir bin 'Abdullah] yang saat itu sedang shalat dengan menggunakan kain sarung yang diikatkannya pada tengkuk, sedangkan pakaiannnya diletakkan pada gantungan baju. Setelah selesai kami bertanya, \"Wahai Abu 'Abdullah, bagaimana kamu shalat sedangkan kain rida' (selendang) mu kau gantung pada gantungan baju? ' Maka Jabir menjawab, \"Benar. Sesungguhnya aku senang bila berbuat seperti itu agar bisa dilihat oleh orang bodoh seperti kamu. Aku pernah melihat Nabi shallallahu 'alaihi wasallam shalat dengan cara seperti itu.\""},"358":{"ar":"حَدَّثَنَا يَعْقُوبُ بْنُ إِبْرَاهِيمَ قَالَ حَدَّثَنَا إِسْمَاعِيلُ بْنُ عُلَيَّةَ قَالَ حَدَّثَنَا عَبْدُ الْعَزِيزِ بْنُ صُهَيْبٍ عَنْ أَنَسِ بْنِ مَالِكٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ غَزَا خَيْبَرَ فَصَلَّيْنَا عِنْدَهَا صَلَاةَ الْغَدَاةِ بِغَلَسٍ فَرَكِبَ نَبِيُّ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَرَكِبَ أَبُو طَلْحَةَ وَأَنَا رَدِيفُ أَبِي طَلْحَةَ فَأَجْرَى نَبِيُّ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي زُقَاقِ خَيْبَرَ وَإِنَّ رُكْبَتِي لَتَمَسُّ فَخِذَ نَبِيِّ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ثُمَّ حَسَرَ الْإِزَارَ عَنْ فَخِذِهِ حَتَّى إِنِّي أَنْظُرُ إِلَى بَيَاضِ فَخِذِ نَبِيِّ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَلَمَّا دَخَلَ الْقَرْيَةَ قَالَ اللَّهُ أَكْبَرُ خَرِبَتْ خَيْبَرُ إِنَّا إِذَا نَزَلْنَا بِسَاحَةِ قَوْمٍ{ فَسَاءَ صَبَاحُ الْمُنْذَرِينَ }قَالَهَا ثَلَاثًا قَالَ وَخَرَجَ الْقَوْمُ إِلَى أَعْمَالِهِمْ فَقَالُوا مُحَمَّدٌ قَالَ عَبْدُ الْعَزِيزِ وَقَالَ بَعْضُ أَصْحَابِنَا وَالْخَمِيسُ يَعْنِي الْجَيْشَ قَالَ فَأَصَبْنَاهَا عَنْوَةً فَجُمِعَ السَّبْيُ فَجَاءَ دِحْيَةُ الْكَلْبِيُّ رَضِيَ اللَّهُ عَنْهُ فَقَالَ يَا نَبِيَّ اللَّهِ أَعْطِنِي جَارِيَةً مِنْ السَّبْيِ قَالَ اذْهَبْ فَخُذْ جَارِيَةً فَأَخَذَ صَفِيَّةَ بِنْتَ حُيَيٍّ فَجَاءَ رَجُلٌ إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ يَا نَبِيَّ اللَّهِ أَعْطَيْتَ دِحْيَةَ صَفِيَّةَ بِنْتَ حُيَيٍّ سَيِّدَةَ قُرَيْظَةَ وَالنَّضِيرِ لَا تَصْلُحُ إِلَّا لَكَ قَالَ ادْعُوهُ بِهَا فَجَاءَ بِهَا فَلَمَّا نَظَرَ إِلَيْهَا النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ خُذْ جَارِيَةً مِنْ السَّبْيِ غَيْرَهَا قَالَ فَأَعْتَقَهَا النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَتَزَوَّجَهَا فَقَالَ لَهُ ثَابِتٌ يَا أَبَا حَمْزَةَ مَا أَصْدَقَهَا قَالَ نَفْسَهَا أَعْتَقَهَا وَتَزَوَّجَهَا حَتَّى إِذَا كَانَ بِالطَّرِيقِ جَهَّزَتْهَا لَهُ أُمُّ سُلَيْمٍ فَأَهْدَتْهَا لَهُ مِنْ اللَّيْلِ فَأَصْبَحَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَرُوسًا فَقَالَ مَنْ كَانَ عِنْدَهُ شَيْءٌ فَلْيَجِئْ بِهِ وَبَسَطَ نِطَعًا فَجَعَلَ الرَّجُلُ يَجِيءُ بِالتَّمْرِ وَجَعَلَ الرَّجُلُ يَجِيءُ بِالسَّمْنِ قَالَ وَأَحْسِبُهُ قَدْ ذَكَرَ السَّوِيقَ قَالَ فَحَاسُوا حَيْسًا فَكَانَتْ وَلِيمَةَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah menceritakan kepada kami [Ya'qub bin Ibrahim] berkata, telah menceritakan kepada kami [Ima'il bin 'Ulayyah] berkata, telah menceritakan kepada kami ['Abdul 'Aziz bin Shuhaib] dari [Anas bin Malik] bahwa Rasulullah shallallahu 'alaihi wasallam berperang di Khaibar. Maka kami melaksanakan shalat shubuh di sana di hari yang masih sangat gelap, lalu Nabi shallallahu 'alaihi wasallam dan Abu Thalhah mengendarai tunggangannya, sementara aku memboncenmg Abu Thalhah. Nabi shallallahu 'alaihi wasallam lalu melewati jalan sempit di Khaibar dan saat itu sungguh lututku menyentuh paha Nabi shallallahu 'alaihi wasallam. Lalu beliau menyingkap sarung dari pahanya hingga aku dapat melihat paha Nabi shallallahu 'alaihi wasallam yang putih. Ketika memasuki desa beliau bersabda: \"Allahu Akbar, binasalah Khaibar dan penduduknya! Sungguh, jika kami mendatangi halaman suatu Kaum, maka (amat buruklah pagi hari yang dialami oleh orang-orang yang diperingatkan itu) ' (Qs. Asf Shaffaat: 177). Beliau mengucapkan kalimat ayat ini tiga kali.\" Anas bin Malik melanjutkan, \"(Saat itu) orang-orang keluar untuk bekerja, mereka lantas berkata, 'Muhammad datang! ' 'Abdul 'Aziz berkata, \"Sebagian sahabat kami menyebutkan, \"Pasukan (datang)! ' Maka kami pun menaklukan mereka, para tawanan lantas dikumpukan. Kemudian datanglah Dihyah Al Kalbi seraya berkata, \"Wahai Nabi Allah, berikan aku seorang wanita dari tawanan itu!\" Maka Nabi shallallahu 'alaihi wasallam berkata, \"Pergi dan bawalah seorang tawanan wanita.\" Dihyah lantas mengambil Shafiyah binti Huyai. Tiba-tiba datang seseorang kepada Nabi shallallahu 'alaihi wasallam dan berkata, \"Wahai Nabi Allah, Tuan telah memberikan Shafiyah binti Huyai kepada Dihyah! Padahal dia adalah wanita yang terhormat dari suku Quraizhoh dan suku Nadlit. Dia tidak layak kecuali untuk Tuan.\" Beliau lalu bersabda: \"Panggillah Dihyah dan wanita itu.\" Maka Dihyah datang dengan membawa Shafiah. Tatkala Nabi shallallahu 'alaihi wasallam melihat Shafiah, beliau berkata, \"Ambillah wanita tawanan yang lain selain dia.\" Lalu Nabi shallallahu 'alaihi wasallam memerdekakan wanita tersebut dan menikahinya.\" Tsabit berkata kepada Anas bin Malik, \"Apa yang menjadi maharnya?\" Anas menjawab, \"Maharnya adalah kemerdekaan wanita itu, beliau memerdekakan dan menikahinya.\" Saat berada diperjalanan, Ummu Sulaim merias Shafiah lalu menyerahkannya kepada Nabi shallallahu 'alaihi wasallam saat malam tiba, sehingga jadilah beliau pengantin. Beliau lalu bersabda: \"Siapa saja dari kalian yang memeliki sesuatu hendaklah ia bawa kemari.\" Beliau lantas menggelar hamparan terbuat dari kulit, lalu berdatanganlah orang-orang dengan membawa apa yang mereka miliki. Ada yang membawa kurma dan ada yang membawa keju/lemak.\" Anas mengatakan, \"Aku kira ia juga menyebutkan sawiq (makanan yang dibuat dari biji gandung dan adonan tepung gandum). Lalu Nabi shallallahu 'alaihi wasallam mencampur makanan-makanan tersebut. Maka itulah walimahan Rasulullah shallallahu 'alaihi wasallam.\""},"359":{"ar":"حَدَّثَنَا أَبُو الْيَمَانِ قَالَ أَخْبَرَنَا شُعَيْبٌ عَنْ الزُّهْرِيِّ قَالَ أَخْبَرَنِي عُرْوَةُ أَنَّ عَائِشَةَ قَالَتْلَقَدْ كَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُصَلِّي الْفَجْرَ فَيَشْهَدُ مَعَهُ نِسَاءٌ مِنْ الْمُؤْمِنَاتِ مُتَلَفِّعَاتٍ فِي مُرُوطِهِنَّ ثُمَّ يَرْجِعْنَ إِلَى بُيُوتِهِنَّ مَا يَعْرِفُهُنَّ أَحَدٌ","id":"Telah menceritakan kepada kami [Abu Al Yaman] berkata, telah mengabarkan kepada kami [Syu'aib] dari [Az Zuhri] berkata, telah mengabarkan kepadaku ['Urwah] bahwa ['Aisyah] berkata, \"Rasulullah shallallahu 'alaihi wasallam shalat fajar dan ikut juga wanita-wanita Mu'minat yang wajahnya tertutup dengan kerudung, kemudian kembali ke rumah mereka masing-masing tanpa diketahui oleh seorangpun.\""},"360":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ يُونُسَ قَالَ حَدَّثَنَا إِبْرَاهِيمُ بْنُ سَعْدٍ قَالَ حَدَّثَنَا ابْنُ شِهَابٍ عَنْ عُرْوَةَ عَنْ عَائِشَةَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ صَلَّى فِي خَمِيصَةٍ لَهَا أَعْلَامٌ فَنَظَرَ إِلَى أَعْلَامِهَا نَظْرَةً فَلَمَّا انْصَرَفَ قَالَ اذْهَبُوا بِخَمِيصَتِي هَذِهِ إِلَى أَبِي جَهْمٍ وَأْتُونِي بِأَنْبِجَانِيَّةِ أَبِي جَهْمٍ فَإِنَّهَا أَلْهَتْنِي آنِفًا عَنْ صَلَاتِيوَقَالَ هِشَامُ بْنُ عُرْوَةَ عَنْ أَبِيهِ عَنْ عَائِشَةَ قَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كُنْتُ أَنْظُرُ إِلَى عَلَمِهَا وَأَنَا فِي الصَّلَاةِ فَأَخَافُ أَنْ تَفْتِنَنِي","id":"Telah menceritakan kepada kami [Ahmad bin Yunus] berkata, telah menceritakan kepada kami [Ibrahim bin Sa'd] berkata, telah menceritakan kepada kami [Ibnu Syihab] dari ['Urwah] dari ['Aisyah] bahwa Nabi shallallahu 'alaihi wasallam shalat di atas kain yang bergambar. Lalu beliau melihat kepada gambar tersebut. Selesai shalat beliau berkata: \"Pergilah dengan membawa kain ini kepada Abu Jahm dan gantilah dengan pakaian polos dari Abu Jahm. Sungguh kain ini tadi telah mengganggu shalatku.\" [Hisyam bin 'Urwah] berkata dari [Bapaknya] dari ['Aisyah] berkata, \"Nabi shallallahu 'alaihi wasallam bersabda: \"Aku melihat pada gambarnya dan aku khawatir gambar itu menggangguku.\""},"361":{"ar":"حَدَّثَنَا أَبُو مَعْمَرٍ عَبْدُ اللَّهِ بْنُ عَمْرٍو قَالَ حَدَّثَنَا عَبْدُ الْوَارِثِ قَالَ حَدَّثَنَا عَبْدُ الْعَزِيزِ بْنُ صُهَيْبٍ عَنْ أَنَسِ بْنِ مَالِكٍكَانَ قِرَامٌ لِعَائِشَةَ سَتَرَتْ بِهِ جَانِبَ بَيْتِهَا فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَمِيطِي عَنَّا قِرَامَكِ هَذَا فَإِنَّهُ لَا تَزَالُ تَصَاوِيرُهُ تَعْرِضُ فِي صَلَاتِي","id":"Telah menceritakan kepada kami [Abu Ma'mar 'Abdullah bin 'Amru] berkata, telah menceritakan kepada kami ['Abdul Warits] berkata, telah menceritakan kepada kami ['Abdul 'Aziz bin Shuhaib] dari [Anas bin Malik], bahwa kain tipis milik 'Aisyah digunakan untuk gorden, Nabi shallallahu 'alaihi wasallam lalu bersabda: \"Singkirkanlah kain ini dari kita, karena gambar-bambarnya selalu menggangguku dalam shalatku.\""},"362":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ يُوسُفَ قَالَ حَدَّثَنَا اللَّيْثُ عَنْ يَزِيدَ بْنِ أَبِي حَبِيبٍ عَنْ أَبِي الْخَيْرِ عَنْ عُقْبَةَ بْنِ عَامِرٍ قَالَأُهْدِيَ إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَرُّوجُ حَرِيرٍ فَلَبِسَهُ فَصَلَّى فِيهِ ثُمَّ انْصَرَفَ فَنَزَعَهُ نَزْعًا شَدِيدًا كَالْكَارِهِ لَهُ وَقَالَ لَا يَنْبَغِي هَذَا لِلْمُتَّقِينَ","id":"Telah menceritakan kepada kami ['Abdullah bin Yusuf] telah menceritakan kepada kami [Al Laits] dari [Yazid bin Abu Habib] dari [Abu Al Khair] dari ['Uqbah bin 'Amir] berkata, \"Nabi shallallahu 'alaihi wasallam diberi hadiah berupa kain yang terbuat dari sutra, lalu beliau memakainya dan shalat. Setelah selesai, beliau menyingkirkannya dengan keras seakan tidak suka, beliau bersabda: \"Ini tidak patut bagi orang yang bertakwa.\""},"363":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ عَرْعَرَةَ قَالَ حَدَّثَنِي عُمَرُ بْنُ أَبِي زَائِدَةَ عَنْ عَوْنِ بْنِ أَبِي جُحَيْفَةَ عَنْ أَبِيهِ قَالَرَأَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي قُبَّةٍ حَمْرَاءَ مِنْ أَدَمٍ وَرَأَيْتُ بِلَالًا أَخَذَ وَضُوءَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَرَأَيْتُ النَّاسَ يَبْتَدِرُونَ ذَاكَ الْوَضُوءَ فَمَنْ أَصَابَ مِنْهُ شَيْئًا تَمَسَّحَ بِهِ وَمَنْ لَمْ يُصِبْ مِنْهُ شَيْئًا أَخَذَ مِنْ بَلَلِ يَدِ صَاحِبِهِ ثُمَّ رَأَيْتُ بِلَالًا أَخَذَ عَنَزَةً فَرَكَزَهَا وَخَرَجَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي حُلَّةٍ حَمْرَاءَ مُشَمِّرًا صَلَّى إِلَى الْعَنَزَةِ بِالنَّاسِ رَكْعَتَيْنِ وَرَأَيْتُ النَّاسَ وَالدَّوَابَّ يَمُرُّونَ مِنْ بَيْنِ يَدَيْ الْعَنَزَةِ","id":"Telah menceritakan kepada kami [Muhammad bin 'Ar'arah] berkata, telah menceritakan kepadaku ['Umar bin Abu Za'idah] dari ['Aun bin Abu Juhaifah] dari [Bapaknya] berkata, \"Aku melihat Rasulullah shallallahu 'alaihi wasallam berada dalam kemah merah yang terbuat dari kulit yang disamak. Dan aku lihat Bilal mengambilkan air wudlu untuk Rasulullah shallallahu 'alaihi wasallam, dan aku lihat orang-orang saling berebut air tersebut. Orang yang mendapatkanya maka ia langsung mengusapkannya, dan bagi yang tidak maka ia mengambilnya dari dari tangan temannya yang basah. Kemudian aku lihat Bilal mengambil tombak kecil dan menancapkannya di tanah, lalu Nabi shallallahu 'alaihi wasallam keluar dengan mengenakan pakaian merah menghadap ke arah tombak kecil dan memimpin orang-orang shalat sebanyak dua raka'at. Dan aku lihat orang-orang dan hewan berlalu melewati depan tombak tersebut.\""},"364":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ عَبْدِ اللَّهِ قَالَ حَدَّثَنَا سُفْيَانُ قَالَ حَدَّثَنَا أَبُو حَازِمٍ قَالَ سَأَلُوا سَهْلَ بْنَ سَعْدٍمِنْ أَيِّ شَيْءٍ الْمِنْبَرُ فَقَالَ مَا بَقِيَ بِالنَّاسِ أَعْلَمُ مِنِّي هُوَ مِنْ أَثْلِ الْغَابَةِ عَمِلَهُ فُلَانٌ مَوْلَى فُلَانَةَ لِرَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَقَامَ عَلَيْهِ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حِينَ عُمِلَ وَوُضِعَ فَاسْتَقْبَلَ الْقِبْلَةَ كَبَّرَ وَقَامَ النَّاسُ خَلْفَهُ فَقَرَأَ وَرَكَعَ وَرَكَعَ النَّاسُ خَلْفَهُ ثُمَّ رَفَعَ رَأْسَهُ ثُمَّ رَجَعَ الْقَهْقَرَى فَسَجَدَ عَلَى الْأَرْضِ ثُمَّ عَادَ إِلَى الْمِنْبَرِ ثُمَّ رَكَعَ ثُمَّ رَفَعَ رَأْسَهُ ثُمَّ رَجَعَ الْقَهْقَرَى حَتَّى سَجَدَ بِالْأَرْضِ فَهَذَا شَأْنُهُقَالَ أَبُو عَبْد اللَّهِ قَالَ عَلِيُّ بْنُ الْمَدِينِيِّ سَأَلَنِي أَحْمَدُ بْنُ حَنْبَلٍ رَحِمَهُ اللَّهُ عَنْ هَذَا الْحَدِيثِ قَالَ فَإِنَّمَا أَرَدْتُ أَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ أَعْلَى مِنْ النَّاسِ فَلَا بَأْسَ أَنْ يَكُونَ الْإِمَامُ أَعْلَى مِنْ النَّاسِ بِهَذَا الْحَدِيثِ قَالَ فَقُلْتُ إِنَّ سُفْيَانَ بْنَ عُيَيْنَةَ كَانَ يُسْأَلُ عَنْ هَذَا كَثِيرًا فَلَمْ تَسْمَعْهُ مِنْهُ قَالَ لَا","id":"Telah menceritakan kepada kami ['Ali bin 'Abdullah] berkata, telah menceritakan kepada kami [Sufyan] berkata, telah menceritakan kepada kami [Abu Hazim] berkata, \"Orang-orang bertanya kepada [Sahal bin Sa'd] tentang terbuat dari apa mimbar Rasulullah? Maka dia berkata, \"Tidak ada seorangpun yang masih hidup dari para sahabat yang lebih mengetahui masalah ini selain aku. Mimbar itu terbuat dari batang pohon hutan yang tak berduri, mimbar itu dibuat oleh seorang budak wanita untuk Rasulullah shallallahu 'alaihi wasallam. Ketika selesai dibuat dan diletakkan, Rasulullah shallallahu 'alaihi wasallam berdiri pada mimbar tersebut menghadap kiblat. Beliau bertakbir dan orang-orang pun ikut shalat dibelakangnya, beliau lalu membaca surat lalu rukuk, dan orang-orang pun ikut rukuk di belakangnya. Kemudian beliau mengangkat kepalanya, lalu mundur ke belakang turun dan sujud di atas tanah. Kemudian beliau kembali ke atas mimbar dan rukuk, kemudian mengangkat kepalnya lalu turun kembali ke tanah pada posisi sebelumnya dan sujud di tanah. Itulah keberadaan mimbar.\" Abu 'Abdullah berkata, 'Ali Al Madini berkata, Ahmad bin Hambal rahimahullah bertanya kepadaku tentang hadits ini. Ia katakan, \"Yang aku maksudkan bahwa Nabi shallallahu 'alaihi wasallam posisinya lebih tinggi daripada orang-orang. Maka tidak mengapa seorang imam posisinya lebih tinggi daripada Makmum berdasarkan hadits ini.\" Sahl bin Sa'd berkata, \"Aku katakan, \"Sesungguhnya Sufyan bin 'Uyainah sering ditanya tentang masalah ini, 'Apakah kamu tidak pernah mendengarnya? ' Ahmad bin Hambal rahimahullah menjawab, \"Tidak.\""},"365":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ عَبْدِ الرَّحِيمِ قَالَ حَدَّثَنَا يَزِيدُ بْنُ هَارُونَ قَالَ أَخْبَرَنَا حُمَيْدٌ الطَّوِيلُ عَنْ أَنَسِ بْنِ مَالِكٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ سَقَطَ عَنْ فَرَسِهِ فَجُحِشَتْ سَاقُهُ أَوْ كَتِفُهُ وَآلَى مِنْ نِسَائِهِ شَهْرًا فَجَلَسَ فِي مَشْرُبَةٍ لَهُ دَرَجَتُهَا مِنْ جُذُوعٍ فَأَتَاهُ أَصْحَابُهُ يَعُودُونَهُ فَصَلَّى بِهِمْ جَالِسًا وَهُمْ قِيَامٌ فَلَمَّا سَلَّمَ قَالَ إِنَّمَا جُعِلَ الْإِمَامُ لِيُؤْتَمَّ بِهِ فَإِذَا كَبَّرَ فَكَبِّرُوا وَإِذَا رَكَعَ فَارْكَعُوا ��َإِذَا سَجَدَ فَاسْجُدُوا وَإِنْ صَلَّى قَائِمًا فَصَلُّوا قِيَامًا وَنَزَلَ لِتِسْعٍ وَعِشْرِينَ فَقَالُوا يَا رَسُولَ اللَّهِ إِنَّكَ آلَيْتَ شَهْرًا فَقَالَ إِنَّ الشَّهْرَ تِسْعٌ وَعِشْرُونَ","id":"Telah menceritakan kepada kami [Muhammad bin 'Abdurrahim] berkata, telah menceritakan kepada kami [Yazid bin Harun] berkata, telah mengabarkan kepada kami [Humaid Ath Thawil] dari [Anas bin Malik], bahwa Rasulullah shallallahu 'alaihi wasallam pernah terjatuh dari kudanya hingga mengakibatkan betisnya atau bahunya terluka. Maka Nabi shallallahu 'alaihi wasallam menjauhi isteri-isterinya selama sebulan. Beliau lalu duduk di ruangan yang agak tinggi yang tangganya terbuat dari kayu. Para sahabatnya lalu mengunjunginya, Beliau lalu shalat mengimami mereka dengan duduk sedangkan para sahabatnya shalat dengan berdiri. Setelah salam, beliau bersabda: \"Sesungguhnya dijadikannya imam itu untuk diikuti. Jika imam bertakbir maka takbirlah kalian, jika rukuk maka rukuklah kalian, jika sujud maka sujudlah kalian, dan jika ia shalat dengan berdiri maka shalatlah kalian dengan berdiri.\" Kemudian Beliau shallallahu 'alaihi wasallam turun kembali setelah dua puluh sembilan hari. Mereka pun berkata, \"Wahai Rasulullah, bukankan engkau mengasingkan diri selama satu bulan? Beliau menjawab: \"Satu bulan itu dua puluh sembailan hari.\""},"366":{"ar":"حَدَّثَنَا مُسَدَّدٌ عَنْ خَالِدٍ قَالَ حَدَّثَنَا سُلَيْمَانُ الشَّيْبَانِيُّ عَنْ عَبْدِ اللَّهِ بْنِ شَدَّادٍ عَنْ مَيْمُونَةَ قَالَتْكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُصَلِّي وَأَنَا حِذَاءَهُ وَأَنَا حَائِضٌ وَرُبَّمَا أَصَابَنِي ثَوْبُهُ إِذَا سَجَدَ قَالَتْ وَكَانَ يُصَلِّي عَلَى الْخُمْرَةِ","id":"Telah menceritakan kepada kami [Musaddad] dari [Khalid] berkata, telah menceritakan kepada kami [Sulaiman Asy Syaibani] dari ['Abdullah bin Syidad] dari [Maimunah] ia berkata, \"Pernah Rasulullah shallallahu 'alaihi wasallam shalat sementara aku berada di sampingnya, dan saat itu aku sedang haid. Dan setiapkali beliau sujud, pakaian beliau mengenai aku. Dan beliau shalat di atas tikar kecil.\""},"367":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ يُوسُفَ قَالَ أَخْبَرَنَا مَالِكٌ عَنْ إِسْحَاقَ بْنِ عَبْدِ اللَّهِ بْنِ أَبِي طَلْحَةَ عَنْ أَنَسِ بْنِ مَالِكٍأَنَّ جَدَّتَهُ مُلَيْكَةَ دَعَتْ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لِطَعَامٍ صَنَعَتْهُ لَهُ فَأَكَلَ مِنْهُ ثُمَّ قَالَ قُومُوا فَلِأُصَلِّ لَكُمْ قَالَ أَنَسٌ فَقُمْتُ إِلَى حَصِيرٍ لَنَا قَدْ اسْوَدَّ مِنْ طُولِ مَا لُبِسَ فَنَضَحْتُهُ بِمَاءٍ فَقَامَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَصَفَفْتُ وَالْيَتِيمَ وَرَاءَهُ وَالْعَجُوزُ مِنْ وَرَائِنَا فَصَلَّى لَنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ رَكْعَتَيْنِ ثُمَّ انْصَرَفَ","id":"Telah menceritakan kepada kami ['Abdullah bin Yusuf] berkata, telah mengabarkan kepada kami [Malik] dari [Ishaq bin 'Abdullah bin Abu Thalhah] dari [Anas bin Malik] bahwa neneknya, Mulaikah, mengundang Rasulullah shallallahu 'alaihi wasallam untuk menghadiri hidangan yang ia masak untuk beliau. Beliau kemudian menyantap makanan tersebut kemudian bersabda: \"Berdirilah, aku akan pimpin kalian shalat.\" Anas berkata, \"Maka aku berdiri di tikar milik kami yang sudah lusuh dan hitam akibat sering digunakan. Aku lalu memercikinya dengan air, kemudian Rasulullah shallallahu 'alaihi wasallam berdiri diatasnya. Aku dan seorang anak yatim lalu membuat barisan di belakang beliau, sementara orang tua (nenek) berdiri di belakang kami. Rasulullah shallallahu 'alaihi wasallam lalu shalat memimpim kami sebanyak dua rakaat lalu pergi.\""},"368":{"ar":"حَدَّثَنَا أَبُو الْوَلِيدِ قَالَ حَدَّثَنَا شُعْبَةُ قَالَ حَدَّثَنَا سُلَيْمَانُ الشَّيْبَانِيُّ عَنْ عَبْدِ اللَّهِ بْنِ شَدَّادٍ عَنْ مَيْمُونَةَ قَالَتْكَانَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُصَلِّي عَلَى الْخُمْرَةِ","id":"Telah menceritakan kepada kami [Abu Al Walid] berkata, telah menceritakan kepada kami [Syu'bah] berkata, telah menceritakan kepada kami [Sulaiman Asy Syaibani] dari ['Abdullah bin Syaddad] dari [Maimunah] ia berkata, \"Nabi shallallahu 'alaihi wasallam shalat di atas tikar kecil.\""},"369":{"ar":"حَدَّثَنَا إِسْمَاعِيلُ قَالَ حَدَّثَنِي مَالِكٌ عَنْ أَبِي النَّضْرِ مَوْلَى عُمَرَ بْنِ عُبَيْدِ اللَّهِ عَنْ أَبِي سَلَمَةَ بْنِ عَبْدِ الرَّحْمَنِ عَنْ عَائِشَةَ زَوْجِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهَا قَالَتْكُنْتُ أَنَامُ بَيْنَ يَدَيْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَرِجْلَايَ فِي قِبْلَتِهِ فَإِذَا سَجَدَ غَمَزَنِي فَقَبَضْتُ رِجْلَيَّ فَإِذَا قَامَ بَسَطْتُهُمَا قَالَتْ وَالْبُيُوتُ يَوْمَئِذٍ لَيْسَ فِيهَا مَصَابِيحُ","id":"Telah menceritakan kepada kami [Isma'il] berkata, telah menceritakan kepadaku [Malik] dari [Abu An Nadlr] mantan budak 'Umar bin 'Ubaidullah, dari [Abu Salamah bin 'Abdurrahman] dari ['Aisyah] isteri Nabi shallallahu 'alaihi wasallam, ia berkata, \"Aku pernah tidur di depan Rasulullah shallallahu 'alaihi wasallam sementara kedua kakiku di arah Qiblat (shalatnya). Jika sujud beliau menyentuh kakiku, maka aku tarik kedua kakiku. Dan jika berdiri aku kembali meluruskan kakiku.\" 'Aisyah berkata, \"Pada saat itu di rumah-rumah belum ada lampu penerang.\""},"370":{"ar":"حَدَّثَنَا يَحْيَى بْنُ بُكَيْرٍ قَالَ حَدَّثَنَا اللَّيْثُ حَدَّثَنِي عُقَيْلٌ عَنْ ابْنِ شِهَابٍ قَالَ أَخْبَرَنِي عُرْوَةُ أَنَّ عَائِشَةَ أَخْبَرَتْهُأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يُصَلِّي وَهِيَ بَيْنَهُ وَبَيْنَ الْقِبْلَةِ عَلَى فِرَاشِ أَهْلِهِ اعْتِرَاضَ الْجَنَازَةِ","id":"Telah menceritakan kepada kami [Yahya bin Bukair] berkata, telah menceritakan kepada kami [Al Laits] telah menceritakan kepadaku ['Uqail] dari [Ibnu Syihab] berkata, telah mengabarkan kepadaku ['Urwah] bahwa ['Aisyah] mengabarkan kepadanya, bahwa ketika Rasulullah shallallahu 'alaihi wasallam sedang shalat Aisyah pernah tidur di arah kiblat beliau, ia tidur di atas kasur dengan posisi seperti jenazah.\""},"371":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ يُوسُفَ قَالَ حَدَّثَنَا اللَّيْثُ عَنْ يَزِيدَ عَنْ عِرَاكٍ عَنْ عُرْوَةَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يُصَلِّي وَعَائِشَةُ مُعْتَرِضَةٌ بَيْنَهُ وَبَيْنَ الْقِبْلَةِ عَلَى الْفِرَاشِ الَّذِي يَنَامَانِ عَلَيْهِ","id":"Telah menceritakan kepada kami ['Abdullah bin Yusuf] berkata, telah menceritakan kepada kami [Al Laits] dari [Yazid] dari ['Irak] dari ['Urwah], bahwa ketika Nabi shallallahu 'alaihi wasallam sedang shalat, 'Aisyah berbaring antara beliau dengan arah kiblatnya, di atas tempat tidur yang digunakan untuk tidur keduanya.\""},"372":{"ar":"حَدَّثَنَا أَبُو الْوَلِيدِ هِشَامُ بْنُ عَبْدِ الْمَلِكِ قَالَ حَدَّثَنَا بِشْرُ بْنُ الْمُفَضَّلِ قَالَ حَدَّثَنِي غَالِبٌ الْقَطَّانُ عَنْ بَكْرِ بْنِ عَبْدِ اللَّهِ عَنْ أَنَسِ بْنِ مَالِكٍ قَالَكُنَّا نُصَلِّي مَعَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَيَضَعُ أَحَدُنَا طَرَفَ الثَّوْبِ مِنْ شِدَّةِ الْحَرِّ فِي مَكَانِ السُّجُودِ","id":"Telah menceritakan kepada kami [Abu Al Walid Hisyam bin 'Abdul Malik] berkata, telah menceritakan kepada kami [Bisyir bin Al Mufadlal] berkata, telah menceritakan kepadaku [Ghalib Al Qaththan] dari [Bakar bin 'Abdullah] dari [Anas bin Malik] berkata, \"Kami shalat bersama Nabi shallallahu 'alaihi wasallam, lalu salah seorang dari kami meletakkan salah satu dari ujung bajunya di tempat sujudnya karena panasnya tempat sujud.\""},"373":{"ar":"حَدَّثَنَا آدَمُ بْنُ أَبِي إِيَاسٍ قَالَ حَدَّثَنَا شُعْبَةُ قَالَ أَخْبَرَنَا أَبُو مَسْلَمَةَ سَعِيدُ بْنُ يَزِيدَ الْأَزْدِيُّ قَالَ سَأَلْتُ أَنَسَ بْنَ مَالِكٍأَكَانَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُصَلِّي فِي نَعْلَيْهِ قَالَ نَعَمْ","id":"Telah menceritakan kepada kami [Adam bin Abu Iyas] berkata, telah menceritakan kepada kami [Syu'bah] berkata, telah mengabarkan kepada kami [Abu Maslamah Sa'id bin Yazid Al Azdi] berkata, \"Aku bertanya kepada [Anas bin Malik], \"Apakah Nabi shallallahu 'alaihi wasallam pernah shalat dengan memakai sandal?\" Dia menjawab, \"Ya.\""},"374":{"ar":"حَدَّثَنَا آدَمُ قَالَ حَدَّثَنَا شُعْبَةُ عَنْ الْأَعْمَشِ قَالَ سَمِعْتُ إِبْرَاهِيمَ يُحَدِّثُ عَنْ هَمَّامِ بْنِ الْحَارِثِ قَالَ رَأَيْتُ جَرِيرَ بْنَ عَبْدِ اللَّهِبَالَ ثُمَّ تَوَضَّأَ وَمَسَحَ عَلَى خُفَّيْهِ ثُمَّ قَامَ فَصَلَّى فَسُئِلَ فَقَالَ رَأَيْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ صَنَعَ مِثْلَ هَذَاقَالَ إِبْرَاهِيمُ فَكَانَ يُعْجِبُهُمْ لِأَنَّ جَرِيرًا كَانَ مِنْ آخِرِ مَنْ أَسْلَمَ","id":"Telah menceritakan kepada kami [Adam] berkata, telah menceritakan kepada kami [Syu'bah] dari [Al A'masy] berkata, aku mendengar [Ibrahim] menceritakan dari [Hammam bin Al Harits] berkata, \"Aku pernah melihat [Jarir bin 'Abdullah] kencing, lalu ia berwudlu dan mengusap dua sepatunya lalu berdiri shalat. Maka hal itu ditanyakan kepadanya, ia lantas menjawab, \"Aku pernah melihat Rasulullah shallallahu 'alaihi wasallam berbuat seperti ini.\" Ibrahim berkata, \"Yang jadi mengherankan mereka adalah karena Jarir adalah termasuk di antara orang yang masuk Islam belakangan\"."},"375":{"ar":"حَدَّثَنَا إِسْحَاقُ بْنُ نَصْرٍ قَالَ حَدَّثَنَا أَبُو أُسَامَةَ عَنْ الْأَعْمَشِ عَنْ مُسْلِمٍ عَنْ مَسْرُوقٍ عَنْ الْمُغِيرَةِ بْنِ شُعْبَةَ قَالَوَضَّأْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَمَسَحَ عَلَى خُفَّيْهِ وَصَلَّى","id":"Telah menceritakan kepada kami [Ishaq bin Nashr] berkata, telah menceritakan kepada kami [Abu Usamah] dari [Al A'masy] dari [Muslim] dari [Masruq] dari [Al Mughirah bin Syu'bah] berkata, \"Aku memberi air wudlu kepada Nabi shallallahu 'alaihi wasallam, beliau lalu mengusap kedua sepatunya dan shalat.\""},"376":{"ar":"أَخْبَرَنَا الصَّلْتُ بْنُ مُحَمَّدٍ أَخْبَرَنَا مَهْدِيٌّ عَنْ وَاصِلٍ عَنْ أَبِي وَائِلٍ عَنْ حُذَيْفَةَرَأَى رَجُلًا لَا يُتِمُّ رُكُوعَهُ وَلَا سُجُودَهُ فَلَمَّا قَضَى صَلَاتَهُ قَالَ لَهُ حُذَيْفَةُ مَا صَلَّيْتَ قَالَ وَأَحْسِبُهُ قَالَ لَوْ مُتَّ مُتَّ عَلَى غَيْرِ سُنَّةِ مُحَمَّدٍ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah mengabarkan kepada kami [Ash Shaltu bin Muhammad] telah mengabarkan kepada kami [Mahdi] dari [Washil] dari [Abu Wa'il] dari [Hudzaifah], bahwa ia melihat seorang laki-laki tidak sempurna dalam rukuk dan sujudnya. Setelah orang itu selesai shalat, Hudzaifah berkata kepadanya, \"Kamu belum shalat!\" Orang itu berkata, \"Aku rasa sudah cukup.\" Hudzaifah berkata lagi, \"Seandainya kamu meninggal, maka kamu meninggal dunia bukan di atas sunah Muhammad shallallahu 'alaihi wasallam.\""},"377":{"ar":"أَخْبَرَنَا يَحْيَى بْنُ بُكَيْرٍ حَدَّثَنَا بَكْرُ بْنُ مُضَرَ عَنْ جَعْفَرِ بْنِ رَبِيعَةَ عَنْ ابْنِ هُرْمُزَ عَنْ عَبْدِ اللَّهِ بْنِ مَالِكٍ ابْنِ بُحَيْنَةَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ إِذَا صَلَّى فَرَّجَ بَيْنَ يَدَيْهِ حَتَّى يَبْدُوَ بَيَاضُ إِبْطَيْهِوَقَالَ اللَّيْثُ حَدَّثَنِي جَعْفَرُ بْنُ رَبِيعَةَ نَحْوَهُ","id":"Telah mengabarkan kepada kami [Yahya bin Bukair] telah menceritakan kepada kami [Bakar bin Mudlar] dari [Ja'far bin Rabi'ah] dari [Ibnu Hurmuz] dari ['Abdullah bin Malik bin Buhainah], bahwa jika Nabi shallallahu 'alaihi wasallam shalat, beliau membentangkan kedua lengannya hingga tampak putih ketiaknya.\" [Al Laits] berkata, telah menceritakan kepadaku [Ja'far bin Rabi'ah] seperti itu.\""},"378":{"ar":"حَدَّثَنَا عَمْرُو بْنُ عَبَّاسٍ قَالَ حَدَّثَنَا ابْنُ الْمَهْدِيِّ قَالَ حَدَّثَنَا مَنْصُورُ بْنُ سَعْدٍ عَنْ مَيْمُونِ بْنِ سِيَاهٍ عَنْ أَنَسِ بْنِ مَالِكٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ صَلَّى صَلَاتَنَا وَاسْتَقْبَلَ قِبْلَتَنَا وَأَكَلَ ذَبِيحَتَنَا فَذَلِكَ الْمُسْلِمُ الَّذِي لَهُ ذِمَّةُ اللَّهِ وَذِمَّةُ رَسُولِهِ فَلَا تُخْفِرُوا اللَّهَ فِي ذِمَّتِهِ","id":"Telah menceritakan kepada kami ['Amru bin 'Abbas] berkata, telah menceritakan kepada kami [Ibnu Al Mahdi] berkata, telah menceritakan kepada kami [Manshur bin Sa'd] dari [Maimun bin Siyah] dari [Anas bin Malik] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa shalat seperti shalat kita, menghadap ke arah kiblat kita dan memakan sembilan kita, maka dia adalah seorang Muslim, ia memiliki perlindungan dari Allah dan Rasul-Nya. Maka janganlah kalian mendurhakai Allah dengan mencederai perlindungan-Nya.\""},"379":{"ar":"حَدَّثَنَا نُعَيْمٌ قَالَ حَدَّثَنَا ابْنُ الْمُبَارَكِ عَنْ حُمَيْدٍ الطَّوِيلِ عَنْ أَنَسِ بْنِ مَالِكٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أُمِرْتُ أَنْ أُقَاتِلَ النَّاسَ حَتَّى يَقُولُوا لَا إِلَهَ إِلَّا اللَّهُ فَإِذَا قَالُوهَا وَصَلَّوْا صَلَاتَنَا وَاسْتَقْبَلُوا قِبْلَتَنَا وَذَبَحُوا ذَبِيحَتَنَا فَقَدْ حَرُمَتْ عَلَيْنَا دِمَاؤُهُمْ وَأَمْوَالُهُمْ إِلَّا بِحَقِّهَا وَحِسَابُهُمْ عَلَى اللَّهِقَالَ ابْنُ أَبِي مَرْيَمَ أَخْبَرَنَا يَحْيَى بْنُ أَيُّوبَ حَدَّثَنَا حُمَيْدٌ حَدَّثَنَا أَنَسٌ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَقَالَ عَلِيُّ بْنُ عَبْدِ اللَّهِ حَدَّثَنَا خَالِدُ بْنُ الْحَارِثِ قَالَ حَدَّثَنَا حُمَيْدٌ قَالَ سَأَلَ مَيْمُونُ بْنُ سِيَاهٍ أَنَسَ بْنَ مَالِكٍ قَالَ يَا أَبَا حَمْزَةَ مَا يُحَرِّمُ دَمَ الْعَبْدِ وَمَالَهُ فَقَالَ مَنْ شَهِدَ أَنْ لَا إِلَهَ إِلَّا اللَّهُ وَاسْتَقْبَلَ قِبْلَتَنَا وَصَلَّى صَلَاتَنَا وَأَكَلَ ذَبِيحَتَنَا فَهُوَ الْمُسْلِمُ لَهُ مَا لِلْمُسْلِمِ وَعَلَيْهِ مَا عَلَى الْمُسْلِمِ","id":"Telah menceritakan kepada kami [Nu'aim] berkata, telah menceritakan kepada kami [Ibnu Al Mubarak] dari [Humaid Ath Thawil] dari [Anas bin Malik] berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Aku diperintah untuk memerangi manusia hingga mereka mengucapkan Laa ilaaha illallah (Tidak ada Tuhan yang berhak disembah selain Allah) '. Jika mereka mengucapkannya kemudian mendirikan shalat seperti shalat kita, menghadap ke kiblat kita dan menyembelih seperti cara kita menyembelih, maka darah dan harta mereka haram (suci) bagi kita kecuali dengan hak Islam dan perhitungannya ada pada Allah.\" [Ibnu Abu Maryam] berkata, telah mengabarkan kepada kami [Yahya bin Ayyub] telah menceritakan kepada kami [Humaid] telah menceritakan kepada kami [Anas] dari Nabi shallallahu 'alaihi wasallam. Dan ['Ali bin 'Abdullah] berkata, telah menceritakan kepada kami [Khalid bin Al Harits] berkata, telah menceritakan kepada kami [Humaid] berkata, \"Maimun bin Siyah bertanya kepada [Anas bin Malik], \"Wahai Abu Hamzah, apa yang menjadikan haramnya darah dan harta seorang hamba?\" Ali menjawab, \"Siapa yang bersaksi Laa ilaaha illallah (Tidak ada Tuhan yang berhak disembah selain Allah), menghadap ke kiblat kita, shalat sepeti shalat kita dan memakan sembelihan kita, maka dia adalah Muslim, baginya hak dan kewajiban seorang Muslim.\""},"380":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ عَبْدِ اللَّهِ قَالَ حَدَّثَنَا سُفْيَانُ قَالَ حَدَّثَنَا الزُّهْرِيُّ عَنْ عَطَاءِ بْنِ يَزِيدَ اللَّيْثِيِّ عَنْ أَبِي أَيُّوبَ الْأَنْصَارِيِّأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِذَا أَتَيْتُمْ الْغَائِطَ فَلَا تَسْتَقْبِلُوا الْقِبْلَةَ وَلَا تَسْتَدْبِرُوهَا وَلَكِنْ شَرِّقُوا أَوْ غَرِّبُوا قَالَ أَبُو أَيُّوبَ فَقَدِمْنَا الشَّأْمَ فَوَجَدْنَا مَرَاحِيضَ بُنِيَتْ قِبَلَ الْقِبْلَةِ فَنَنْحَرِفُ وَنَسْتَغْفِرُ اللَّهَ تَعَالَىوَعَنْ الزُّهْرِيِّ عَنْ عَطَاءٍ قَالَ سَمِعْتُ أَبَا أَيُّوبَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِثْلَهُ","id":"Telah menceritakan kepada kami ['Ali bin 'Abdullah] berkata, telah menceritakan kepada kami [Sufyan] berkata, telah menceritakan kepada kami [Az Zuhri] dari ['Atha' bin Yazid Al Laitsi] dari [Abu Ayyub Al Anshari], bahwa Nabi shallallahu 'alaihi wasallam bersabda: \"Jika kalian mendatangi masuk ke dalam WC, maka janganlah kalian menghadap ke arah kiblat dan jangan pula membelakanginya. Tetapi menghadaplah ke timurnya atau ke baratnya.\" Abu Ayyub berkata, \"Ketika kami datang ke Syam, kami dapati WC rumah-rumah di sana dibangun menghadap kiblat. Maka kami alihkan dan kami memohon ampun kepada Allah Ta'ala.\" Dan dari [Az Zuhri] dari ['Atha] berkata, aku mendengar [Abu Ayyub] dari Nabi shallallahu 'alaihi wasallam seperti ini.\""},"381":{"ar":"حَدَّثَنَا الْحُمَيْدِيُّ قَالَ حَدَّثَنَا سُفْيَانُ قَالَ حَدَّثَنَا عَمْرُو بْنُ دِينَارٍ قَالَ سَأَلْنَا ابْنَ عُمَرَعَنْ رَجُلٍ طَافَ بِالْبَيْتِ الْعُمْرَةَ وَلَمْ يَطُفْ بَيْنَ الصَّفَا وَالْمَرْوَةِ أَيَأْتِي امْرَأَتَهُ فَقَالَ قَدِمَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَطَافَ بِالْبَيْتِ سَبْعًا وَصَلَّى خَلْفَ الْمَقَامِ رَكْعَتَيْنِ وَطَافَ بَيْنَ الصَّفَا وَالْمَرْوَةِ وَقَدْ كَانَ لَكُمْ فِي رَسُولِ اللَّهِ أُسْوَةٌ حَسَنَةٌوَسَأَلْنَا جَابِرَ بْنَ عَبْدِ اللَّهِ فَقَالَ لَا يَقْرَبَنَّهَا حَتَّى يَطُوفَ بَيْنَ الصَّفَا وَالْمَرْوَةِ","id":"Telah menceritakan kepada kami [Al Humaid] berkata, telah menceritakan kepada kami [Sufyan] berkata, telah menceritakan kepada kami ['Amru bin Dinar] berkata, \"Kami pernah bertanya kepada [Ibnu 'Umar] tentang seseorang yang thawaf di Ka'bah untuk 'Umrah tetapi tidak melakukan sa'i antara Shafa dan Marwah. Apakah dia boleh berhubungan (jima') dengan isterinya?\" Maka Ibnu 'Umar berkata, \"Nabi shallallahu 'alaihi wasallam datang Makkah, lalu thawaf mengelilingi Ka'bah tujuh kali, shalat di sisi Maqam dua rakaat, lalu sa'i antara antara Shafa dan Marwah. Dan sungguh bagi kalian ada suri tauladan yang baik pada diri Rasulullah.\" Dan kami pernah bertanya kepada [Jabir bin 'Abdullah] tentang masalah ini. Maka ia menjawab, \"Jangan sekali-kali ia mendekati isterinya hingga ia melaksanakan sa'i antara bukit Shafa dan Marwah.\""},"382":{"ar":"حَدَّثَنَا مُسَدَّدٌ قَالَ حَدَّثَنَا يَحْيَى عَنْ سَيْفٍ يَعْنِي ابْنَ سُلَيْمَانَ قَالَ سَمِعْتُ مُجَاهِدًا قَالَ أُتِيَ ابْنُ عُمَرَفَقِيلَ لَهُ هَذَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ دَخَلَ الْكَعْبَةَ فَقَالَ ابْنُ عُمَرَ فَأَقْبَلْتُ وَالنَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَدْ خَرَجَ وَأَجِدُ بِلَالًا قَائِمًا بَيْنَ الْبَابَيْنِ فَسَأَلْتُ بِلَالًا فَقُلْتُ أَصَلَّى النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي الْكَعْبَةِ قَالَ نَعَمْ رَكْعَتَيْنِ بَيْنَ السَّارِيَتَيْنِ اللَّتَيْنِ عَلَى يَسَارِهِ إِذَا دَخَلْتَ ثُمَّ خَرَجَ فَصَلَّى فِي وَجْهِ الْكَعْبَةِ رَكْعَتَيْنِ","id":"Telah menceritakan kepada kami [Musaddad] berkata, telah menceritakan kepada kami [Yahya] dari [Saif] -Ibnu Sulaiman- berkata, aku mendengar [Mujahid] berkata, \" [Ibnu 'Umar] pernah di datangi dan ditanya, \"Rasulullah shallallahu 'alaihi wasallam masuk ke dalam Ka'bah. Maka Ibnu 'Umar berkata, \"Aku lalu mendatangi Nabi shallallahu 'alaihi wasallam, namun beliau telah keluar, dan aku mendapati Bilal sedang berdiri di antara dua pintu. Aku lalu bertanya kepada Bilal, \"Apakah Nabi shallallahu 'alaihi wasallam shalat di dalam Ka'bah? [Bilal] menjawab, \"Ya, dua rakaat antara dua sisi dua tiang sebelah kiri dari arah kamu masuk, lalu beliau keluar dan shalat menghadap Ka'bah dua rakaat.\""},"383":{"ar":"حَدَّثَنَا إِسْحَاقُ بْنُ نَصْرٍ قَالَ حَدَّثَنَا عَبْدُ الرَّزَّاقِ أَخْبَرَنَا ابْنُ جُرَيْجٍ عَنْ عَطَاءٍ قَالَ سَمِعْتُ ابْنَ عَبَّاسٍ قَالَلَمَّا دَخَلَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْبَيْتَ دَعَا فِي نَوَاحِيهِ كُلِّهَا وَلَمْ يُصَلِّ حَتَّى خَرَجَ مِنْهُ فَلَمَّا خَرَجَ رَكَعَ رَكْعَتَيْنِ فِي قُبُلِ الْكَعْبَةِ وَقَالَ هَذِهِ الْقِبْلَةُ","id":"Telah menceritakan kepada kami [Ishaq bin Nashr] berkata, telah menceritakan kepada kami [Abdurrazaq] telah mengabarkan kepada kami [Ibnu Juraij] dari ['Atha'] berkata, aku mendengar [Ibnu 'Abbas] berkata, \"Ketika Nabi shallallahu 'alaihi wasallam masuk ke dalam Ka'bah, beliau berdo'a di seluruh sisinya dan tidak melakukan shalat hingga beliau keluar darinya. Beliau kemudian shalat dua rakaat dengan memandang Ka'bah lalu bersabda: \"Inilah kiblat.\""},"384":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ رَجَاءٍ قَالَ حَدَّثَنَا إِسْرَائِيلُ عَنْ أَبِي إِسْحَاقَ عَنْ الْبَرَاءِ بْنِ عَازِبٍ رَضِيَ اللَّهُ عَنْهُمَا قَالَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ صَلَّى نَحْوَ بَيْتِ الْمَقْدِسِ سِتَّةَ عَشَرَ أَوْ سَبْعَةَ عَشَرَ شَهْرًا وَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُحِبُّ أَنْ يُوَجَّهَ إِلَى الْكَعْبَةِ فَأَنْزَلَ اللَّهُ{ قَدْ نَرَى تَقَلُّبَ وَجْهِكَ فِي السَّمَاءِ }فَتَوَجَّهَ نَحْوَ الْكَعْبَةِ وَقَالَ السُّفَهَاءُ مِنْ النَّاسِ وَهُمْ الْيَهُودُ{ مَا وَلَّاهُمْ عَنْ قِبْلَتِهِمْ الَّتِي كَانُوا عَلَيْهَا قُلْ لِلَّهِ الْمَشْرِقُ وَالْمَغْرِبُ يَهْدِي مَنْ يَشَاءُ إِلَى صِرَاطٍ مُسْتَقِيمٍ }فَصَلَّى مَعَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ رَجُلٌ ثُمَّ خَرَجَ بَعْدَ مَا صَلَّى فَمَرَّ عَلَى قَوْمٍ مِنْ الْأَنْصَارِ فِي صَلَاةِ الْعَصْرِ نَحْوَ بَيْتِ الْمَقْدِسِ فَقَالَ هُوَ يَشْهَدُ أَنَّهُ صَلَّى مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَأَنَّهُ تَوَجَّهَ نَحْوَ الْكَعْبَةِ فَتَحَرَّفَ الْقَوْمُ حَتَّى تَوَجَّهُوا نَحْوَ الْكَعْبَةِ","id":"Telah menceritakan kepada kami ['Abdullah bin Raja'] berkata, telah menceritakan kepada kami [Israil] dari [Abu Ishaq] dari [Al Bara' bin 'Azib? radliallahu 'anhuma] berkata, \"Rasulullah shallallahu 'alaihi wasallam shalat mengahdap Baitul Maqdis selama enam belas atau tujuh belas bulan, dan Rasulullah shallallahu 'alaihi wasallam menginginkan kiblat tersebut dialihkan ke arah Ka'bah. Maka Allah menurunkan ayat: (\"Sungguh Kami (sering) melihat mukamu menengadah ke langit) ' (Qs. Al Baqarah: 144). Maka kemudian Nabi shallallahu 'alaihi wasallam menghadap ke Ka'bah. Lalu berkatalah orang-orang yang kurang akal, yaitu orang-orang Yahudi: '(Apakah yang memalingkan mereka (umat Islam) dari kiblatnya (Baitul Maqdis) yang dahulu mereka telah berkiblat kepadanya?\" Katakanlah: \"Kepunyaan Allah-lah timur dan barat. Dia memberi petunjuk kepada siapa yang dikehendaki-Nya ke jalan yang lurus) ' (As. Al Baqarah: 144). Kemudian ada seseorang yang ikut shalat bersama Nabi shallallahu 'alaihi wasallam, orang itu kemudian keluar setelah menyelesikan shalatnya. Kemudian orang itu melewati Kaum Anshar yang sedang melaksanakan shalat 'Ashar dengan menghadap Baitul Maqdis. Lalu orang itu bersaksi bahwa dia telah shalat bersama Rasulullah shallallahu 'alaihi wasallam dengan menghadap Ka'bah. Maka orang-orang itu pun berputar dan menghadap Ka'bah.\""},"385":{"ar":"حَدَّثَنَا مُسْلِمُ بْنُ إِبْرَاهِيمَ قَالَ حَدَّثَنَا هِشَامُ بْنُ أَبِي عَبْدِ اللَّهِ قَالَ حَدَّثَنَا يَحْيَى بْنُ أَبِي كَثِيرٍ عَنْ مُحَمَّدِ بْنِ عَبْدِ الرَّحْمَنِ عَنْ جَابِرِ بْنِ عَبْدِ اللَّهِ قَالَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُصَلِّي عَلَى رَاحِلَتِهِ حَيْثُ تَوَجَّهَتْ فَإِذَا أَرَادَ الْفَرِيضَةَ نَزَلَ فَاسْتَقْبَلَ الْقِبْلَةَ","id":"Telah menceritakan kepada kami [Muslim bin Ibrahim] berkata, telah menceritakan kepada kami [Hisyam bin Abu 'abdullah] berkata, telah menceritakan kepada kami [Yahya bin Abu Katsir] dari [Muhammad bin 'Abdurrahman] dari [Jabir bin 'Abdullah] berkata, \"Rasulullah shallallahu 'alaihi wasallam shalat diatas tunggangannya menghadap kemana arah tunggangannya menghadap. Jika Beliau hendak melaksanakan shalat yang fardlu, maka beliau turun lalu shalat menghadap kiblat.\""},"386":{"ar":"حَدَّثَنَا عُثْمَانُ قَالَ حَدَّثَنَا جَرِيرٌ عَنْ مَنْصُورٍ عَنْ إِبْرَاهِيمَ عَنْ عَلْقَمَةَ قَالَ قَالَ عَبْدُ اللَّهِصَلَّى النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِبْرَاهِيمُ لَا أَدْرِي زَادَ أَوْ نَقَصَ فَلَمَّا سَلَّمَ قِيلَ لَهُ يَا رَسُولَ اللَّهِ أَحَدَثَ فِي الصَّلَاةِ شَيْءٌ قَالَ وَمَا ذَاكَ قَالُوا صَلَّيْتَ كَذَا وَكَذَا فَثَنَى رِجْلَيْهِ وَاسْتَقْبَلَ الْقِبْلَةَ وَسَجَدَ سَجْدَتَيْنِ ثُمَّ سَلَّمَ فَلَمَّا أَقْبَلَ عَلَيْنَا بِوَجْهِهِ قَالَ إِنَّهُ لَوْ حَدَثَ فِي الصَّلَاةِ شَيْءٌ لَنَبَّأْتُكُمْ بِهِ وَلَكِنْ إِنَّمَا أَنَا بَشَرٌ مِثْلُكُمْ أَنْسَى كَمَا تَنْسَوْنَ فَإِذَا نَسِيتُ فَذَكِّرُونِي وَإِذَا شَكَّ أَحَدُكُمْ فِي صَلَاتِهِ فَلْيَتَحَرَّ الصَّوَابَ فَلْيُتِمَّ عَلَيْهِ ثُمَّ لِيُسَلِّمْ ثُمَّ يَسْجُدُ سَجْدَتَيْنِ","id":"Telah menceritakan kepada kami ['Utsman] berkata, telah menceritakan kepada kami [Jarir] dari [Manshur] dari [Ibrahim] dari ['Alqamah] berkata, [Abdullah] berkata, \"Nabi shallallahu 'alaihi wasallam melaksanakan shalat.\" Ibrahim melanjutkan, \"Tapi aku tidak tahu apakah beliau kelebihan rakaat atau kurang. Setelah salam, beliau pun ditanya: \"Wahai Rasulullah, telah terjadi sesuatu dalam shalat!. Beliau bertanya: \"Apakah itu?\" Maka mereka menjawab, \"Tuan shalat begini dan begini.\" Beliau kemudian duduk pada kedua kakinya menghadap kiblat, kemudian beliau sujud dua kali, kemudian salam. Ketika menghadap ke arah kami, beliau bersabda: \"Seungguhnya bila ada sesuatu yang baru dari shalat pasti aku beritahukan kepada kalian. Akan tetapi aku ini hanyalah manusia seperti kalian yang bisa lupa sebagaimana kalian juga bisa lupa, maka jika aku terlupa ingatkanlah. Dan jika seseorang dari kalian ragu dalam shalatnya maka dia harus meyakini mana yang benar, kemudian hendaklah ia sempurnakan, lalu salam kemudian sujud dua kali.\""},"387":{"ar":"حَدَّثَنَا عَمْرُو بْنُ عَوْنٍ قَالَ حَدَّثَنَا هُشَيْمٌ عَنْ حُمَيْدٍ عَنْ أَنَسِ بْنِ مَالِكٍ قَالَ قَالَ عُمَرُ بْنُ الْخَطَّابِ رَضِيَ اللَّهُ عَنْهُوَافَقْتُ رَبِّي فِي ثَلَاثٍ فَقُلْتُ يَا رَسُولَ اللَّهِ لَوْ اتَّخَذْنَا مِنْ مَقَامِ إِبْرَاهِيمَ مُصَلًّى فَنَزَلَتْ{ وَاتَّخِذُوا مِنْ مَقَامِ إِبْرَاهِيمَ مُصَلًّى }وَآيَةُ الْحِجَابِ قُلْتُ يَا رَسُولَ الل��َهِ لَوْ أَمَرْتَ نِسَاءَكَ أَنْ يَحْتَجِبْنَ فَإِنَّهُ يُكَلِّمُهُنَّ الْبَرُّ وَالْفَاجِرُ فَنَزَلَتْ آيَةُ الْحِجَابِ وَاجْتَمَعَ نِسَاءُ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي الْغَيْرَةِ عَلَيْهِ فَقُلْتُ لَهُنَّ{ عَسَى رَبُّهُ إِنْ طَلَّقَكُنَّ أَنْ يُبَدِّلَهُ أَزْوَاجًا خَيْرًا مِنْكُنَّ }فَنَزَلَتْ هَذِهِ الْآيَةُقَالَ أَبُو عَبْد اللَّهِ و حَدَّثَنَا ابْنُ أَبِي مَرْيَمَ قَالَ أَخْبَرَنَا يَحْيَى بْنُ أَيُّوبَ قَالَ حَدَّثَنِي حُمَيْدٌ قَالَ سَمِعْتُ أَنَسًا بِهَذَا","id":"Telah menceritakan kepada kami ['Amru bin 'Aun] berkata, telah menceritakan kepada kami [Husyaim] dari [Humaid] dari [Anas bin Malik] berkata, ['Umar bin Al Khaththab], \"Aku memiliki pemikiran yang aku ingin jika itu dikabulkan oleh Rabbku dalam tiga persoalan. Maka aku sampaikan kepada Rasulullah shallallahu 'alaihi wasallam, 'Wahai Rasulullah, seandainya Maqam Ibrahim kita jadikan sebagai tempat shalat? Lalu turunlah ayat: '(Dan jadikanlah sebahagian maqam Ibrahim sebagai tempat shalat) ' (Qs. Al Baqarah: 125). Yang kedua tentang hijab. Aku lalu berkata, 'Wahai Rasulullah, seandainya Tuan perintahkan isteri-isteri Tuan untuk berhijab karena yang berkomunikasi dengan mereka ada orang yang shalih dan juga ada yang fajir (suka bermaksiat).' Maka turunlah ayat hijab. Dan yang ketiga, saat isteri-isteri beliau cemburu kepada beliau (sehingga banyak yang membangkang), aku katakan kepada mereka, 'Semoga bila Beliau menceraikan kalian Rabbnya akan menggantinya dengan isteri-isteri yang lebih baik dari kalian.' Maka turunlah ayat tentang masalah ini.\" Abu Abdullah berkata; telah menceritakan kepada kami [Ibnu Abu Maryam] berkata, telah mengabarkan kepada kami [Yahya bin Ayyub] berkata, telah menceritakan kepadaku [Humaid] ia berkata, Aku mendengar [Anas] seperti hadits ini.\""},"388":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ يُوسُفَ قَالَ أَخْبَرَنَا مَالِكُ بْنُ أَنَسٍ عَنْ عَبْدِ اللَّهِ بْنِ دِينَارٍ عَنْ عَبْدِ اللَّهِ بْنِ عُمَرَ قَالَبَيْنَا النَّاسُ بِقُبَاءٍ فِي صَلَاةِ الصُّبْحِ إِذْ جَاءَهُمْ آتٍ فَقَالَ إِنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَدْ أُنْزِلَ عَلَيْهِ اللَّيْلَةَ قُرْآنٌ وَقَدْ أُمِرَ أَنْ يَسْتَقْبِلَ الْكَعْبَةَ فَاسْتَقْبِلُوهَا وَكَانَتْ وُجُوهُهُمْ إِلَى الشَّأْمِ فَاسْتَدَارُوا إِلَى الْكَعْبَةِ","id":"Telah menceritakan kepada kami ['Abdullah bin Yusuf] berkata, telah mengabarkan kepada kami [Malik bin Anas] dari ['Abdullah bin Dinar] dari ['Abdullah bin 'Umar] berkata, \"Ketika orang-orang shalat subuh di Quba', tiba-tiba datang seorang laki-laki dan berkata, \"Sungguh, tadi malam telah turun ayat kepada Rasulullah shallallahu 'alaihi wasallam, beliau diperintahkan untuk menghadap ke arah Ka'bah. Maka orang-orang yang sedang shalat berputar menghadap Ka'bah, padahal pada saat itu wajah-wajah mereka sedang menghadap negeri Syam. Mereka kemudian berputar ke arah Ka'bah.\""},"389":{"ar":"حَدَّثَنَا مُسَدَّدٌ قَالَ حَدَّثَنَا يَحْيَى عَنْ شُعْبَةَ عَنْ الْحَكَمِ عَنْ إِبْرَاهِيمَ عَنْ عَلْقَمَةَ عَنْ عَبْدِ اللَّهِ قَالَصَلَّى النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الظُّهْرَ خَمْسًا فَقَالُوا أَزِيدَ فِي الصَّلَاةِ قَالَ وَمَا ذَاكَ قَالُوا صَلَّيْتَ خَمْسًا فَثَنَى رِجْلَيْهِ وَسَجَدَ سَجْدَتَيْنِ","id":"Telah menceritakan kepada kami [Musaddad] berkata, telah menceritakan kepada kami [Yahya] dari [Syu'bah] dari [Al Hakam] dari [Ibrahim] dari ['Alqamah] dari ['Abdullah] berkata, \"Nabi shallallahu 'alaihi wasallam pernah melaksanakan shalat Zhuhur lima rakaat. Maka orang-orang berkata, \"Apakah ada tambahan dalam shalat?\" Beliau balik bertanya: \"Apakah yang terjadi?\" Mereka menjawab, \"Tuan telah shalat sebanyak lima rakaat.\" Maka beliau pun duduk di atas kedua kakinya lalu sujud dua kali.\""},"390":{"ar":"حَدَّثَنَا قُتَيْبَةُ قَالَ حَدَّثَنَا إِسْمَاعِيلُ بْنُ جَعْفَرٍ عَنْ حُمَيْدٍ عَنْ أَنَسِ بْنِ مَالِكٍأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ رَأَى نُخَامَةً فِي الْقِبْلَةِ فَشَقَّ ذَلِكَ عَلَيْهِ حَتَّى رُئِيَ فِي وَجْهِهِ فَقَامَ فَحَكَّهُ بِيَدِهِ فَقَالَ إِنَّ أَحَدَكُمْ إِذَا قَامَ فِي صَلَاتِهِ فَإِنَّهُ يُنَاجِي رَبَّهُ أَوْ إِنَّ رَبَّهُ بَيْنَهُ وَبَيْنَ الْقِبْلَةِ فَلَا يَبْزُقَنَّ أَحَدُكُمْ قِبَلَ قِبْلَتِهِ وَلَكِنْ عَنْ يَسَارِهِ أَوْ تَحْتَ قَدَمَيْهِ ثُمَّ أَخَذَ طَرَفَ رِدَائِهِ فَبَصَقَ فِيهِ ثُمَّ رَدَّ بَعْضَهُ عَلَى بَعْضٍ فَقَالَ أَوْ يَفْعَلُ هَكَذَا","id":"Telah menceritakan kepada kami [Qutaibah] berkata, telah menceritakan kepada kami [Isma'il bin Ja'far] dari [Humaid] dari [Anas bin Malik] bahwa Nabi shallallahu 'alaihi wasallam melihat ada dahak di dinding kiblat, beliau lalu merasa jengkel hingga nampak tersirat pada wajahnya. Kemudian beliau menggosoknya dengan tangannya seraya bersabda: \"Jika seseorang dari kalian berdiri shalat sesungguhnya dia sedang berhadapan dengan Rabbnya, atau sesungguhnya Rabbnya berada antara dia dan kiblat, maka janganlah dia meludah ke arah kiblat, tetapi lakukanlah ke arah kirinya atau di bawah kaki (kirinya).\" Kemudian Nabi shallallahu 'alaihi wasallam memegang tepi kainnya dan meludah di dalamnya, setelah itu beliau membalik posisi kainnya lalu berkata, atau beliau melakukan seperti ini.\""},"391":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ يُوسُفَ قَالَ أَخْبَرَنَا مَالِكٌ عَنْ نَافِعٍ عَنْ عَبْدِ اللَّهِ بْنِ عُمَرَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ رَأَى بُصَاقًا فِي جِدَارِ الْقِبْلَةِ فَحَكَّهُ ثُمَّ أَقْبَلَ عَلَى النَّاسِ فَقَالَ إِذَا كَانَ أَحَدُكُمْ يُصَلِّي فَلَا يَبْصُقُ قِبَلَ وَجْهِهِ فَإِنَّ اللَّهَ قِبَلَ وَجْهِهِ إِذَا صَلَّى","id":"Telah menceritakan kepada kami ['Abdullah bin Yusuf] berkata, telah mengabarkan kepada kami [Malik] dari [Nafi'] dari ['Abdullah bin 'Umar], bahwa Rasulullah shallallahu 'alaihi wasallam melihat ludah di dinding kiblat, lalu beliau menggosoknya kemudian menghadap ke arah orang banyak seraya bersabda: \"Jika seseorang dari kalian berdiri shalat janganlah dia meludah ke arah depannya, karena Allah berada di hadapannya ketika dia shalat.\""},"392":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ يُوسُفَ قَالَ أَخْبَرَنَا مَالِكٌ عَنْ هِشَامِ بْنِ عُرْوَةَ عَنْ أَبِيهِ عَنْ عَائِشَةَ أُمِّ الْمُؤْمِنِينَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ رَأَى فِي جِدَارِ الْقِبْلَةِ مُخَاطًا أَوْ بُصَاقًا أَوْ نُخَامَةً فَحَكَّهُ","id":"Telah menceritakan kepada kami ['Abdullah bin Yusuf] berkata, telah mengabarkan kepada kami [Malik] dari [Hisyam bin 'Urwah] dari [Bapaknya] dari ['Aisyah] Ummul Mukminin, bahwa Rasulullah shallallahu 'alaihi wasallam melihat ludah atau ingus pada dinding kiblat, beliau lalu menggosoknya.\""},"393":{"ar":"حَدَّثَنَا مُوسَى بْنُ إِسْمَاعِيلَ قَالَ أَخْبَرَنَا إِبْرَاهِيمُ بْنُ سَعْدٍ أَخْبَرَنَا ابْنُ شِهَابٍ عَنْ حُمَيْدِ بْنِ عَبْدِ الرَّحْمَنِ أَنَّ أَبَا هُرَيْرَةَ وَأَبَا سَعِيدٍ حَدَّثَاهُأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ رَأَى نُخَامَةً فِي جِدَارِ الْمَسْجِدِ فَتَنَاوَلَ حَصَاةً فَحَكَّهَا فَقَالَ إِذَا تَنَخَّمَ أَحَدُكُمْ فَلَا يَتَنَخَّمَنَّ قِبَلَ وَجْهِهِ وَلَا عَنْ يَمِينِهِ وَلْيَبْصُقْ عَنْ يَسَارِهِ أَوْ تَحْتَ قَدَمِهِ الْيُسْرَى","id":"Telah menceritakan kepada kami [Musa bin Isma'il] berkata, telah mengabarkan kepada kami [Ibrahim bin Sa'd] telah mengabarkan kepada kami [Ibnu Syihab] dari [Humaid bin 'Abdurrahman] bahwa [Abu Hurairah] dan [Abu Sa'id] keduanya menceritakan, bahwa Rasulullah shallallahu 'alaihi wasallam melihat ludah pada dinding masjid, beliau lalu mengambil batu kerikil kemudian menggosoknya. Setelah itu beliau bersabda: \"Jika salah seorang dari kalian meludah maka janganlah ia membuangnya ke arah depan atau sebelah kanannya, tetapi hendaklah ia lakukan ke arah kirinya atau di bawah kaki (kirinya).\""},"394":{"ar":"حَدَّثَنَا يَحْيَى بْنُ بُكَيْرٍ قَالَ حَدَّثَنَا اللَّيْثُ عَنْ عُقَيْلٍ عَنْ ابْنِ شِهَابٍ عَنْ حُمَيْدِ بْنِ عَبْدِ الرَّحْمَنِ أَنَّ أَبَا هُرَيْرَةَ وَأَبَا سَعِيدٍ أَخْبَرَاهُأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ رَأَى نُخَامَةً فِي حَائِطِ الْمَسْجِدِ فَتَنَاوَلَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حَصَاةً فَحَتَّهَا ثُمَّ قَالَ إِذَا تَنَخَّمَ أَحَدُكُمْ فَلَا يَتَنَخَّمْ قِبَلَ وَجْهِهِ وَلَا عَنْ يَمِينِهِ وَلْيَبْصُقْ عَنْ يَسَارِهِ أَوْ تَحْتَ قَدَمِهِ الْيُسْرَى","id":"Telah menceritakan kepada kami [Yahya bin Bukair] berkata, telah telah menceritakan kepada kami [Al Laits] dari ['Uqail] dari [Ibnu Syihab] dari [Humaid bin 'Abdurrahman] bahwa [Abu Hurairah] dan [Abu Sa'id] keduanya mengabarkan kepadanya bahwa Rasulullah shallallahu 'alaihi wasallam pernah melihat ludah pada dinding masjid, maka Rasulullah shallallahu 'alaihi wasallam mengambil batu kerikil dan menggosoknya. Kemudian beliau bersabda: \"Jika salah seorang dari kalian meludah janganlah ia meludah ke arah kiblat atau ke sebelah kanannya, tapi hendaklah ia lakukan ke arah kiri atau di bawah kaki kirinya.\""},"395":{"ar":"حَدَّثَنَا حَفْصُ بْنُ عُمَرَ قَالَ حَدَّثَنَا شُعْبَةُ قَالَ أَخْبَرَنِي قَتَادَةُ قَالَ سَمِعْتُ أَنَسَ بْنَ مَالِكٍ قَالَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا يَتْفِلَنَّ أَحَدُكُمْ بَيْنَ يَدَيْهِ وَلَا عَنْ يَمِينِهِ وَلَكِنْ عَنْ يَسَارِهِ أَوْ تَحْتَ رِجْلِهِ","id":"Telah menceritakan kepada kami [Hafsh bin 'Umar] telah menceritakan kepada kami [Syu'bah] berkata, telah mengabarkan kepadaku [Qatadah] berkata, aku mendengar [Anas bin Malik] berkata, \"Nabi shallallahu 'alaihi wasallam bersabda: \"Jangan sekali-kali salah seorang dari kalian meludah ke arah depan atau samping kanannya, tapi hendaklah ke arah kiri atau di bawah kakinya.\""},"396":{"ar":"حَدَّثَنَا آدَمُ قَالَ حَدَّثَنَا شُعْبَةُ قَالَ حَدَّثَنَا قَتَادَةُ قَالَ سَمِعْتُ أَنَسَ بْنَ مَالِكٍ قَالَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ الْمُؤْمِنَ إِذَا كَانَ فِي الصَّلَاةِ فَإِنَّمَا يُنَاجِي رَبَّهُ فَلَا يَبْزُقَنَّ بَيْنَ يَدَيْهِ وَلَا عَنْ يَمِينِهِ وَلَكِنْ عَنْ يَسَارِهِ أَوْ تَحْتَ قَدَمِهِ","id":"Telah menceritakan kepada kami [Adam] berkata, telah menceritakan kepada kami [Syu'bah] berkata, telah menceritakan kepada kami [Qatadah] berkata, aku mendengar [Anas bin Malik] berkata, \"Nabi shallallahu 'alaihi wasallam bersabda: \"Jika seorang Mukmin sedang shalat, sesungguhnya ia sedang berhadapan dengan Rabbnya. Maka janganlah ia meludah ke arah depan atau sebelah kanannya, namun hendaklah ia melakukannya ke arah kiri atau di bawah kakinya.\""},"397":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ عَبْدِ اللَّهِ قَالَ حَدَّثَنَا سُفْيَانُ حَدَّثَنَا الزُّهْرِيُّ عَنْ حُمَيْدِ بْنِ عَبْدِ الرَّحْمَنِ عَنْ أَبِي سَعِيدٍأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَبْصَرَ نُخَامَةً فِي قِبْلَةِ الْمَسْجِدِ فَحَكَّهَا بِحَصَاةٍ ثُمَّ نَهَى أَنْ يَبْزُقَ الرَّجُلُ بَيْنَ يَدَيْهِ أَوْ عَنْ يَمِينِهِ وَلَكِنْ عَنْ يَسَارِهِ أَوْ تَحْتَ قَدَمِهِ الْيُسْرَىوَعَنْ الزُّهْرِيِّ سَمِعَ حُمَيْدًا عَنْ أَبِي سَعِيدٍ نَحْوَهُ","id":"Telah menceritakan kepada kami ['Ali bin 'Abdullah] berkata, telah menceritakan kepada kami [Sufyan] telah menceritakan kepada kami [Az Zuhri] dari [Humaid bin 'Abdurrahman] dari [Abu Sa'id] bahwa Nabi shallallahu 'alaihi wasallam melihat ludah pada arah kiblat masjid, beliau lalu menggosoknya dengan batu kerikil. Kemudian beliau melarang seorang laki-laki meludah ke arah depan atau sebelah kanannya. Tetapi hendaklah ia melakukannya ke arah kiri atau ke bawah kaki kirinya.\" Dan dari [Az Zuhri] ia mendengar [Humaid] dari [Abu Sa'id] seperti ini.\""},"398":{"ar":"حَدَّثَنَا آدَمُ قَالَ حَدَّثَنَا شُعْبَةُ قَالَ حَدَّثَنَا قَتَادَةُ قَالَ سَمِعْتُ أَنَسَ بْنَ مَالِكٍ قَالَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْبُزَاقُ فِي الْمَسْجِدِ خَطِيئَةٌ وَكَفَّارَتُهَا دَفْنُهَا","id":"Telah menceritakan kepada kami [Adam] berkata, telah menceritakan kepada kami [Syu'bah] berkata, telah menceritakan kepada kami [Qatadah] berkata, aku mendengar [Anas bin Malik] berkata, \"Nabi shallallahu 'alaihi wasallam bersabda: \"Meludah di dalam Masjid adalah suatu dosa. Maka kafarahnya (tebusannya) adalah menguburnya.\""},"399":{"ar":"حَدَّثَنَا إِسْحَاقُ بْنُ نَصْرٍ قَالَ حَدَّثَنَا عَبْدُ الرَّزَّاقِ عَنْ مَعْمَرٍ عَنْ هَمَّامٍ سَمِعَ أَبَا هُرَيْرَةَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِذَا قَامَ أَحَدُكُمْ إِلَى الصَّلَاةِ فَلَا يَبْصُقْ أَمَامَهُ فَإِنَّمَا يُنَاجِي اللَّهَ مَا دَامَ فِي مُصَلَّاهُ وَلَا عَنْ يَمِينِهِ فَإِنَّ عَنْ يَمِينِهِ مَلَكًا وَلْيَبْصُقْ عَنْ يَسَارِهِ أَوْ تَحْتَ قَدَمِهِ فَيَدْفِنُهَا","id":"Telah menceritakan kepada kami [Ishaq bin Nashr] berkata, telah menceritakan kepada kami berkata [Abdurrazaq] dari [Ma'mar] dari [Hammam] ia mendengar [Abu Hurairah] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Jika salah seorang dari kalian berdiri shalat, maka janganlah meludah ke arah depannya sebab ia sedang berhadapan dengan Allah selagi ia berada di tempat shalatnya, dan jangan ke sebelah kanannya karena di sana ada Malaikat. Tetapi hendaklah ia meludah ke arah kiri atau di bawah kakinya, kemudian dikuburnya.\""},"400":{"ar":"حَدَّثَنَا مَالِكُ بْنُ إِسْمَاعِيلَ قَالَ حَدَّثَنَا زُهَيْرٌ قَالَ حَدَّثَنَا حُمَيْدٌ عَنْ أَنَسِ بْنِ مَالِكٍأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ رَأَى نُخَامَةً فِي الْقِبْلَةِ فَحَكَّهَا بِيَدِهِ وَرُئِيَ مِنْهُ كَرَاهِيَةٌ أَوْ رُئِيَ كَرَاهِيَتُهُ لِذَلِكَ وَشِدَّتُهُ عَلَيْهِ وَقَالَ إِنَّ أَحَدَكُمْ إِذَا قَامَ فِي صَلَاتِهِ فَإِنَّمَا يُنَاجِي رَبَّهُ أَوْ رَبُّهُ بَيْنَهُ وَبَيْنَ قِبْلَتِهِ فَلَا يَبْزُقَنَّ فِي قِبْلَتِهِ وَلَكِنْ عَنْ يَسَارِهِ أَوْ تَحْتَ قَدَمِهِ ثُمَّ أَخَذَ طَرَفَ رِدَائِهِ فَبَزَقَ فِيهِ وَرَدَّ بَعْضَهُ عَلَى بَعْضٍ قَالَ أَوْ يَفْعَلُ هَكَذَا","id":"Telah menceritakan kepada kami [Malik bin Isma'il] berkata, telah menceritakan kepada kami [Zuhair] berkata, telah menceritakan kepada kami [Humaid] dari [Anas bin Malik], bahwa Nabi shallallahu 'alaihi wasallam melihat dahak di dinding kiblat lalu menggosoknya dengan tangannya. Dan nampak kebencian dari beliau, atau kebenciannya terlihat karena hal itu. Beliau pun bersabda: \"Jika salah seorang dari kalian berdiri shalat, sesungguhnya ia sedang berhadapan dengan Rabbnya, atau sesungguhnya Rabbnya berada antara dia dan arah kiblatnya, maka janganlah ia meludah ke arah kiblat. Tetapi hendaklah ia lakukan ke arah kiri atau di bawah kaki (kirinya).\" Kemudian Nabi shallallahu 'alaihi wasallam memegang tepi kainnya dan meludah di dalamnya, setelah itu beliau membalik posisi kainnya lalu berkata, atau beliau melakukan seperti ini.\""},"401":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ يُوسُفَ قَالَ أَخْبَرَنَا مَالِكٌ عَنْ أَبِي الزِّنَادِ عَنْ الْأَعْرَجِ عَنْ أَبِي هُرَيْرَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ هَلْ تَرَوْنَ قِبْلَتِي هَا هُنَا فَوَاللَّهِ مَا يَخْفَى عَلَيَّ خُشُوعُكُمْ وَلَا رُكُوعُكُمْ إِنِّي لَأَرَاكُمْ مِنْ وَرَاءِ ظَهْرِي","id":"Telah menceritakan kepada kami ['Abdullah bin Yusuf] berkata, telah mengabarkan kepada kami [Malik] dari [Abu Az Zinad] dari [Al A'raj] dari [Abu Hurairah], bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Apakah kalian lihat kiblatku disini? Demi Allah, tidaklah tersembunyi bagiku khusyuk dan rukuk kalian. Sungguh, aku dapat melihatnya dari belakang punggungku.\""},"402":{"ar":"حَدَّثَنَا يَحْيَى بْنُ صَالِحٍ قَالَ حَدَّثَنَا فُلَيْحُ بْنُ سُلَيْمَانَ عَنْ هِلَالِ بْنِ عَلِيٍّ عَنْ أَنَسِ بْنِ مَالِكٍ قَالَصَلَّى بِنَا النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ صَلَاةً ثُمَّ رَقِيَ الْمِنْبَرَ فَقَالَ فِي الصَّلَاةِ وَفِي الرُّكُوعِ إِنِّي لَأَرَاكُمْ مِنْ وَرَائِي كَمَا أَرَاكُمْ","id":"Telah menceritakan kepada kami [Yahya bin Shalih] berkata, telah menceritakan kepada kami [Fulaih bin Sulaiman] dari [Hilal bin 'Ali] dari [Anas bin Malik] berkata, \"Nabi shallallahu 'alaihi wasallam pernah shalat bersama kami, kemudian beliau naik mimbar dan bersabda: \"Sesungguhnya saat shalat dan rukuk, aku dapat melihat kalian dari belakangku sebagaimana sekarang aku melihat kalian.\""},"403":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ يُوسُفَ قَالَ أَخْبَرَنَا مَالِكٌ عَنْ نَافِعٍ عَنْ عَبْدِ اللَّهِ بْنِ عُمَرَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ سَابَقَ بَيْنَ الْخَيْلِ الَّتِي أُضْمِرَتْ مِنْ الْحَفْيَاءِ وَأَمَدُهَا ثَنِيَّةُ الْوَدَاعِ وَسَابَقَ بَيْنَ الْخَيْلِ الَّتِي لَمْ تُضْمَرْ مِنْ الثَّنِيَّةِ إِلَى مَسْجِدِ بَنِي زُرَيْقٍ وَأَنَّ عَبْدَ اللَّهِ بْنَ عُمَرَ كَانَ فِيمَنْ سَابَقَ بِهَا","id":"Telah menceritakan kepada kami ['Abdullah bin Yusuf] berkata, telah mengabarkan kepada kami [Malik] dari [Nafi'] dari ['Abdullah bin 'Umar], bahwa Rasulullah shallallahu 'alaihi wasallam pernah mempertandingkan antara kudan yang dipersiapkan untuk pacuan yang jaraknya dimulai dari Al Hafya' sampai Tsaniyatul Wada', dan kuda yang tidak disiapkanuntuk pacuan yang dimulai dari Al Hafya' hingga Masjid Bani Zuraiq.\" 'Abdullah bin 'Umar adalah termasuk orang yang mengikuti pacuan tersebut.\""},"404":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ يُوسُفَ أَخْبَرَنَا مَالِكٌ عَنْ إِسْحَاقَ بْنِ عَبْدِ اللَّهِ بْنِ أَبِي طَلْحَةَ سَمِعَ أَنَسًا قَالَوَجَدْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي الْمَسْجِدِ مَعَهُ نَاسٌ فَقُمْتُ فَقَالَ لِي آرْسَلَكَ أَبُو طَلْحَةَ قُلْتُ نَعَمْ فَقَالَ لِطَعَامٍ قُلْتُ نَعَمْ فَقَالَ لِمَنْ مَعَهُ قُومُوا فَانْطَلَقَ وَانْطَلَقْتُ بَيْنَ أَيْدِيهِمْ","id":"Telah menceritakan kepada kami ['Abdullah bin Yusuf] berkata, telah mengabarkan kepada kami [Malik] dari [Ishaq bin 'Abdullah bin Abu Thalhah] bahwa dia mendengar [Anas] berkata, \"Aku menemui Nabi shallallahu 'alaihi wasallam saat beliau sedang berada di Masjid bersama orang banyak. Maka aku menghadap kepada beliau, lalu beliau bertanya kepadaku: \"Apakah kamu diutus oleh Abu Thalhah?\" Aku menjawab, \"Ya.\" Beliau bertanya lagi: \"Untuk undangan makan?\" Aku menjawab: \"Benar.\" Kemudian beliau bersabda kepada orang-orang yang bersama beliau: \"Mari berangkat!\" Maka beliau pun berangkat dan aku juga berangkat bersama mereka\"."},"405":{"ar":"حَدَّثَنَا يَحْيَى بْنُ مُوسَى قَالَ أَخْبَرَنَا عَبْدُ الرَّزَّاقِ قَالَ أَخْبَرَنَا ابْنُ جُرَيْجٍ قَالَ أَخْبَرَنِي ابْنُ شِهَابٍ عَنْ سَهْلِ بْنِ سَعْدٍأَنَّ رَجُلًا قَالَ يَا رَسُولَ اللَّهِ أَرَأَيْتَ رَجُلًا وَجَدَ مَعَ امْرَأَتِهِ رَجُلًا أَيَقْتُلُهُ فَتَلَاعَنَا فِي الْمَسْجِدِ وَأَنَا شَاهِدٌ","id":"Telah menceritakan kepada kami [Yahya bin Musa] berkata, telah mengabarkan kepada kami [Abdurrazaq] berkata, telah mengabarkan kepada kami [Ibnu Juraij] berkata, telah mengabarkan kepada kami [Ibnu Syihab] dari [Sahal bin Sa'd], bahwa ada seorang laki-laki datang dan berkata, \"Wahai Rasulullah, bagaimana pendapatmu jika seorang suami mendapati laki-laki lain bersama isterinya? Lalu keduanya saling melaknat di dalam masjid, sementara aku menyaksiakannya.\""},"406":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مَسْلَمَةَ قَالَ حَدَّثَنَا إِبْرَاهِيمُ بْنُ سَعْدٍ عَنْ ابْنِ شِهَابٍ عَنْ مَحْمُودِ بْنِ الرَّبِيعِ عَنْ عِتْبَانَ بْنِ مَالِكٍأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَتَاهُ فِي مَنْزِلِهِ فَقَالَ أَيْنَ تُحِبُّ أَنْ أُصَلِّيَ لَكَ مِنْ بَيْتِكَ قَالَ فَأَشَرْتُ لَهُ إِلَى مَكَانٍ فَكَبَّرَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَصَفَفْنَا خَلْفَهُ فَصَلَّى رَكْعَتَيْنِ","id":"Telah menceritakan kepada kami ['Abdullah bin Maslamah] berkata, telah menceritakan kepada kami [Ibrahim bin Sa'd] dari [Ibnu Syihab] dari [Mahmud bin Ar Rabi'] dari ['Itban bin Malik], bahwa Nabi shallallahu 'alaihi wasallam mendatanginya di rumahnya seraya bersabda: \"Mana tempat di rumahmu yang kau sukai untuk aku pimpin shalat?\" Maka aku menunjukkan suatu tempat, lalu Nabi shallallahu 'alaihi wasallam takbir dan kami membuat shaf di belakangnya, kemudian beliaupun shalat dua rakaat.\""},"407":{"ar":"حَدَّثَنَا سَعِيدُ بْنُ عُفَيْرٍ قَالَ حَدَّثَنِي اللَّيْثُ قَالَ حَدَّثَنِي عُقَيْلٌ عَنْ ابْنِ شِهَابٍ قَالَ أَخْبَرَنِي مَحْمُودُ بْنُ الرَّبِيعِ الْأَنْصَارِيُّ أَنَّ عِتْبَانَ بْنَ مَالِكٍوَهُوَ مِنْ أَصْحَابِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِمَّنْ شَهِدَ بَدْرًا مِنْ الْأَنْصَارِ أَنَّهُ أَتَى رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ يَا رَسُولَ اللَّهِ قَدْ أَنْكَرْتُ بَصَرِي وَأَنَا أُصَلِّي لِقَوْمِي فَإِذَا كَانَتْ الْأَمْطَارُ سَالَ الْوَادِي الَّذِي بَيْنِي وَبَيْنَهُمْ لَمْ أَسْتَطِعْ أَنْ آتِيَ مَسْجِدَهُمْ فَأُصَلِّيَ بِهِمْ وَوَدِدْتُ يَا رَسُولَ اللَّهِ أَنَّكَ تَأْتِينِي فَتُصَلِّيَ فِي بَيْتِي فَأَتَّخِذَهُ مُصَلًّى قَالَ فَقَالَ لَهُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ سَأَفْعَلُ إِنْ شَاءَ اللَّهُ قَالَ عِتْبَانُ فَغَدَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَأَبُو بَكْرٍ حِينَ ارْتَفَعَ النَّهَارُ فَاسْتَأْذَنَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَذِنْتُ لَهُ فَلَمْ يَجْلِسْ حَتَّى دَخَلَ الْبَيْتَ ثُمَّ قَالَ أَيْنَ تُحِبُّ أَنْ أُصَلِّيَ مِنْ بَيْتِكَ قَالَ فَأَشَرْتُ لَهُ إِلَى نَاحِيَةٍ مِنْ الْبَيْتِ فَقَامَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَكَبَّرَ فَقُمْنَا فَصَفَّنَا فَصَلَّى رَكْعَتَيْنِ ثُمَّ سَلَّمَ قَالَ وَحَبَسْنَاهُ عَلَى خَزِيرَةٍ صَنَعْنَاهَا لَهُ قَالَ فَآبَ فِي الْبَيْتِ رِجَالٌ مِنْ أَهْلِ الدَّارِ ذَوُو عَدَدٍ فَاجْتَمَعُوا فَقَالَ قَائِلٌ مِنْهُمْ أَيْنَ مَالِكُ بْنُ الدُّخَيْشِنِ أَوِ ابْنُ الدُّخْشُنِ فَقَالَ بَعْضُهُمْ ذَلِكَ مُنَافِقٌ لَا يُحِبُّ اللَّهَ وَرَسُولَهُ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا تَقُلْ ذَلِكَ أَلَا تَرَاهُ قَدْ قَالَ لَا إِلَهَ إِلَّا اللَّهُ يُرِيدُ بِذَلِكَ وَجْهَ اللَّهِ قَالَ اللَّهُ وَرَسُولُهُ أَعْلَمُ قَالَ فَإِنَّا نَرَى وَجْهَهُ وَنَصِيحَتَهُ إِلَى الْمُنَافِقِينَ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَإِنَّ اللَّهَ قَدْ حَرَّمَ عَلَى النَّارِ مَنْ قَالَ لَا إِلَهَ إِلَّا اللَّهُ يَبْتَغِي بِذَلِكَ وَجْهَ اللَّهِقَالَ ابْنُ شِهَابٍ ثُمَّ سَأَلْتُ الْحُصَيْنَ بْنَ مُحَمَّدٍ الْأَنْصَارِيَّ وَهُوَ أَحَدُ بَنِي سَالِمٍ وَهُوَ مِنْ سَرَاتِهِمْ عَنْ حَدِيثِ مَحْمُودِ بْنِ الرَّبِيعِ الْأَنْصَارِيِّ فَصَدَّقَهُ بِذَلِكَ","id":"Telah menceritakan kepada kami [Sa'id bin 'Ufair] berkata, telah menceritakan kepadaku [Al Laits] berkata, telah menceritakan kepadaku ['Uqail] dari [Ibnu Syihab] berkata, telah menceritakan kapadaku [Mahmud bin Ar Rabi' Al Anshari] bahwa ['Itban bin Malik] seorang sahabat Rasulullah shallallahu 'alaihi wasallam yang pernah ikut perang Badar dari kalangan Anshar, dia pernah menemui Rasulullah shallallahu 'alaihi wasallam dan bersabda: \"Wahai Rasulullah, pandanganku sudah buruk sedang aku sering memimpin shalat kaumku. Apabila turun hujun, maka air menggenangi lembah yang ada antara aku dan mereka sehingga aku tidak bisa pergi ke masjid untuk memimpin shalat. Aku menginginkan Tuan dapat mengunjungi aku lalu shalat di rumahku yang akan aku jadikan sebagai tempat shalat.\" Mahmud berkata, \"Kemudian Rasulullah shallallahu 'alaihi wasallam bersabda kepadanya: \"Aku akan lakukan insyaallah.\" 'Itban berkata, \"Maka berangkatlah Rasulullah shallallahu 'alaihi wasallam dan Abu Bakar ketika siang hari, beliau lalu meminta izin lalu aku mengizinkannya, dan beliau tidak duduk hingga beliau masuk ke dalam rumah. Kemudian beliau bersabda: \"Mana tempat di rumahmu yang kau sukai untuk aku pimpin shalat.\" Maka aku tunjukkan tempat di sisi rumah. Nabi shallallahu 'alaihi wasallam lalu berdiri dan takbir. Sementara kami berdiri membuat shaf di belakang beliau, beliau shalat dua rakaat kemudian salam.\" 'Itban melanjutkan, \"Lalu kami suguhkan makanan dari daging yang kami masak untuk beliau. Maka berkumpullah warga desa di rumahku dalam jumlah yang banyak. Salah seorang dari mereka lalu berkata, \"Mana Malik bin Ad-Dukhaisyin atau Ibnu Ad Dukhsyun?\" Ada seorang yang menjawab, \"Dia munafik, dia tidak mencintai Allah dan Rasul-Nya.\" Maka Rasulullah shallallahu 'alaihi wasallam pun bersabda: \"Janganlah kamu ucapkan seperti itu. Bukankan kamu tahu dia telah mengucapkan LAA ILAAHA ILLALLAH dengan mengharap ridla Allah?\" Orang itu menjawab, \"Allah dan Rasul-Nya yang lebih tahu.\" 'Itban berkata, \"Kami lihat pandangan dan nasehat beliau itu untuk kaum Munafikin. Bersabda Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya Allah telah mengharamkan neraka bagi orang yang mengucapkan LAA ILAAHA ILLALLAH dengan mengharap ridla Allah?\" [Ibnu Syihab] berkata, \"Kemudian aku tanyakan kepada [Al Hushain bin Muhammad Al Anshari] salah seorang dari Bani Salim yang termasuk orang terpandang tentang hadits Mahmud bin Ar Rabi' ini. Maka dia membenarkannya.\""},"408":{"ar":"حَدَّثَنَا سُلَيْمَانُ بْنُ حَرْبٍ قَالَ حَدَّثَنَا شُعْبَةُ عَنْ الْأَشْعَثِ بْنِ سُلَيْمٍ عَنْ أَبِيهِ عَنْ مَسْرُوقٍ عَنْ عَائِشَةَ قَالَتْكَانَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُحِبُّ التَّيَمُّنَ مَا اسْتَطَاعَ فِي شَأْنِهِ كُلِّهِ فِي طُهُورِهِ وَتَرَجُّلِهِ وَتَنَعُّلِهِ","id":"Telah menceritakan kepada kami [Sulaiman bin Harb] berkata, telah menceritakan kepada kami [Syu'bah] dari [Al Asy'ats bin Sulaim] dari [ayahnya] dari [Masruq] dari ['Aisyah] berkata, \"Nabi shallallahu 'alaihi wasallam suka mendahulukan yang kanan dalam setiap perbuatannya. Seperti dalam bersuci, menaiki kendaraan dan memakai sandal.\""},"409":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ الْمُثَنَّى قَالَ حَدَّثَنَا يَحْيَى عَنْ هِشَامٍ قَالَ أَخْبَرَنِي أَبِي عَنْ عَائِشَةَ أُمِّ الْمُؤْمِنِينَأَنَّ أُمَّ حَبِيبَةَ وَأُمَّ سَلَمَةَ ذَكَرَتَا كَنِيسَةً رَأَيْنَهَا بِالْحَبَشَةِ فِيهَا تَصَاوِيرُ فَذَكَرَتَا لِلنَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ إِنَّ أُولَئِكَ إِذَا كَانَ فِيهِمْ الرَّجُلُ الصَّالِحُ فَمَاتَ بَنَوْا عَلَى قَبْرِهِ مَسْجِدًا وَصَوَّرُوا فِيهِ تِلْكَ الصُّوَرَ فَأُولَئِكَ شِرَارُ الْخَلْقِ عِنْدَ اللَّهِ يَوْمَ الْقِيَامَةِ","id":"Telah menceritakan kepada kami [Muhammad bin Al Mutsanna] berkata, telah menceritakan kepada kami [Yahya] dari [Hisyam] berkata, [Bapakku] mengabarkan kepadaku dari ['Aisyah] Ummul Mukminin, bahwa Ummu Habibah dan Ummu Salamah menceritakan kepada Nabi shallallahu 'alaihi wasallam bahwa mereka melihat gereja di Habasyah yang didalamnya terdapat gambar. Maka beliau pun bersabda: \"Sesungguhnya jika orang shalih dari mereka meninggal, maka mereka mendirikan masjid di atas kuburannya dan membuat patungnya di sana. Maka mereka itulah seburuk-buruk makhluk di sisi Allah pada hari kiyamat.\""},"410":{"ar":"حَدَّثَنَا مُسَدَّدٌ قَالَ حَدَّثَنَا عَبْدُ الْوَارِثِ عَنْ أَبِي التَّيَّاحِ عَنْ أَنَسِ بْنِ مَالِكٍ قَالَقَدِمَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْمَدِينَةَ فَنَزَلَ أَعْلَى الْمَدِينَةِ فِي حَيٍّ يُقَالُ لَهُمْ بَنُو عَمْرِو بْنِ عَوْفٍ فَأَقَامَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِيهِمْ أَرْبَعَ عَشْرَةَ لَيْلَةً ثُمَّ أَرْسَلَ إِلَى بَنِي النَّجَّارِ فَجَاءُوا مُتَقَلِّدِي السُّيُوفِ كَأَنِّي أَنْظُرُ إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَلَى رَاحِلَتِهِ وَأَبُو بَكْرٍ رِدْفُهُ وَمَلَأُ بَنِي النَّجَّارِ حَوْلَهُ حَتَّى أَلْقَى بِفِنَاءِ أَبِي أَيُّوبَ وَكَانَ يُحِبُّ أَنْ يُصَلِّيَ حَيْثُ ��َدْرَكَتْهُ الصَّلَاةُ وَيُصَلِّي فِي مَرَابِضِ الْغَنَمِ وَأَنَّهُ أَمَرَ بِبِنَاءِ الْمَسْجِدِ فَأَرْسَلَ إِلَى مَلَإٍ مِنْ بَنِي النَّجَّارِ فَقَالَ يَا بَنِي النَّجَّارِ ثَامِنُونِي بِحَائِطِكُمْ هَذَا قَالُوا لَا وَاللَّهِ لَا نَطْلُبُ ثَمَنَهُ إِلَّا إِلَى اللَّهِ فَقَالَ أَنَسٌ فَكَانَ فِيهِ مَا أَقُولُ لَكُمْ قُبُورُ الْمُشْرِكِينَ وَفِيهِ خَرِبٌ وَفِيهِ نَخْلٌ فَأَمَرَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِقُبُورِ الْمُشْرِكِينَ فَنُبِشَتْ ثُمَّ بِالْخَرِبِ فَسُوِّيَتْ وَبِالنَّخْلِ فَقُطِعَ فَصَفُّوا النَّخْلَ قِبْلَةَ الْمَسْجِدِ وَجَعَلُوا عِضَادَتَيْهِ الْحِجَارَةَ وَجَعَلُوا يَنْقُلُونَ الصَّخْرَ وَهُمْ يَرْتَجِزُونَ وَالنَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَعَهُمْ وَهُوَ يَقُولُ اللَّهُمَّ لَا خَيْرَ إِلَّا خَيْرُ الْآخِرَهْفَاغْفِرْ لِلْأَنْصَارِ وَالْمُهَاجِرَهْ","id":"Telah menceritakan kepada kami [Musaddad] berkata, telah menceritakan kepada kami ['Abdul Warits] dari [Abu At Tayyah] dari [Anas bin Malik] berkata, \"Nabi shallallahu 'alaihi wasallam tiba di Madinah lalu singgah di perkampungan bani 'Amru bin 'Auf, Nabi shallallahu 'alaihi wasallam tinggal di sana selama empat belas malam. Kemudian beliau mengutus seseorang menemui bani Najjar, maka mereka pun datang dengan pedang di badan mereka. Aku melihat Nabi shallallahu 'alaihi wasallam di atas tunggangannya sedangkan Abu Bakar membonceng di belakangnya dan para pembesar bani Najjar berada di sekelilingnya hingga sampai di sumur milik Abu Ayyub. Beliau suka segera shalat saat waktu shalat sudah masuk, maka beliau pun shalat di kandang kambing. Kemudian beliau memerintahkan untuk membangun masjid, beliau mengutus seseorang menemui pembesar bani Najjar. utusan itu menyampaikan: \"Wahai bani Najjar, sebutkan berapa harga kebun kalian ini?\" Mereka menjawab, \"Tidak, demi Allah. Kami tidak akan menjualnya kecuali kepada Allah!\" Anas berkata, \"Aku beritahu kepada kalian bahwa pada kebun itu banyak terdapat kuburan orang-orang musyrik, juga ada sisa-sisa reruntuhan rumah dan pohon-pohon kurma. Maka Nabi shallallahu 'alaihi wasallam memerintahkan untuk membongkar kuburan-kuburan tersebut, reruntuhan rumah diratakan dan pohon-pohon kurma ditumbangkan lalu dipindahkan di depan arah kiblat masjid. Maka lalu membuat pintu masjid dari pohon dan mengangkut batu bata sambil menyanyikan nasyid. Dan Nabi shallallahu 'alaihi wasallam ikut bekerja pula bersama mereka sambil mengucapkan: \"Ya Allah. Tidak ada kebaikan kecuali kebaikan akhirat, maka ampunilah kaum Anshar dan Muhajirin.\""},"411":{"ar":"حَدَّثَنَا سُلَيْمَانُ بْنُ حَرْبٍ قَالَ حَدَّثَنَا شُعْبَةُ عَنْ أَبِي التَّيَّاحِ عَنْ أَنَسِ بْنِ مَالِكٍ قَالَكَانَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُصَلِّي فِي مَرَابِضِ الْغَنَمِ ثُمَّ سَمِعْتُهُ بَعْدُ يَقُولُ كَانَ يُصَلِّي فِي مَرَابِضِ الْغَنَمِ قَبْلَ أَنْ يُبْنَى الْمَسْجِدُ","id":"Telah menceritakan kepada kami [Sulaiman bin Harb] berkata, telah menceritakan kepada kami [Syu'bah] dari [Abu At Tayyah] dari [Anas bin Malik] berkata, \"Nabi shallallahu 'alaihi wasallam pernah shalat di kandang kambing.\" Setelah itu aku mendengar Anas mengatakan, \"Beliau shalat di kandang kambing sebelum masjid di bangun.\""},"412":{"ar":"حَدَّثَنَا صَدَقَةُ بْنُ الْفَضْلِ قَالَ أَخْبَرَنَا سُلَيْمَانُ بْنُ حَيَّانَ قَالَ حَدَّثَنَا عُبَيْدُ اللَّهِ عَنْ نَافِعٍ قَالَ رَأَيْتُ ابْنَ عُمَرَيُصَلِّي إِلَى بَعِيرِهِ وَقَالَ رَأَيْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَفْعَلُهُ","id":"Telah menceritakan kepada kami [Shadaqah bin Al Fadll] berkata, telah mengabarkan kepada kami [Sulaiman bin Hayyan] berkata, telah menceritakan kepada kami ['Ubaidullah] dari [Nafi'] berkata, \"Aku melihat [Ibnu 'Umar] shalat menghadap untanya, dan ia mengatakan, \"Aku pernah melihat Rasulullah shallallahu 'alaihi wasallam melakukannya.\""},"413":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مَسْلَمَةَ عَنْ مَالِكٍ عَنْ زَيْدِ بْنِ أَسْلَمَ عَنْ عَطَاءِ بْنِ يَسَارٍ عَنْ عَبْدِ اللَّهِ بْنِ عَبَّاسٍ قَالَانْخَسَفَتْ الشَّمْسُ فَصَلَّى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ثُمَّ قَالَ أُرِيتُ النَّارَ فَلَمْ أَرَ مَنْظَرًا كَالْيَوْمِ قَطُّ أَفْظَعَ","id":"Telah menceritakan kepada kami ['Abdullah bin Maslamah] dari [Malik] dari [Zaid bin Aslam] dari ['Atha' bin Yasar] dari ['Abdullah bin 'Abbas] berkata, \"Ketika terjadi gerhana matahari Rasulullah shallallahu 'alaihi wasallam melaksanakan shalat (gerhana), kemudin beliau bersabda: \"Neraka telah diperlihatkan kepadaku, dan belum pernah sekalipun aku melihat suatu pemandangan yang lebih mengerikan dari pada hari ini.\""},"414":{"ar":"حَدَّثَنَا مُسَدَّدٌ قَالَ حَدَّثَنَا يَحْيَى عَنْ عُبَيْدِ اللَّهِ بْنِ عُمَرَ قَالَ أَخْبَرَنِي نَافِعٌ عَنْ ابْنِ عُمَرَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ اجْعَلُوا فِي بُيُوتِكُمْ مِنْ صَلَاتِكُمْ وَلَا تَتَّخِذُوهَا قُبُورًا","id":"Telah menceritakan kepada kami [Musadad] berkata, telah menceritakan kepada kami [Yahya] dari ['Ubaidullah bin 'Umar] berkata, telah mengabarkan kepadaku [Nafi'] dari [Ibnu 'Umar] dari Nabi shallallahu 'alaihi wasallam bersabda: \"Jadikanlah (sebagian dari) shalat kalian ada di rumah kalian, dan jangan kalian jadikan ia sebagai kuburan.\""},"415":{"ar":"حَدَّثَنَا إِسْمَاعِيلُ بْنُ عَبْدِ اللَّهِ قَالَ حَدَّثَنِي مَالِكٌ عَنْ عَبْدِ اللَّهِ بْنِ دِينَارٍ عَنْ عَبْدِ اللَّهِ بْنِ عُمَرَ رَضِيَ اللَّهُ عَنْهُمَاأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا تَدْخُلُوا عَلَى هَؤُلَاءِ الْمُعَذَّبِينَ إِلَّا أَنْ تَكُونُوا بَاكِينَ فَإِنْ لَمْ تَكُونُوا بَاكِينَ فَلَا تَدْخُلُوا عَلَيْهِمْ لَا يُصِيبُكُمْ مَا أَصَابَهُمْ","id":"Telah menceritakan kepada kami [Isma'il bin 'Abdullah] berkata, telah menceritakan kepadaku [Malik] dari ['Abdullah bin Dinar] dari ['Abdullah bin 'Umar] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Janganlah kalian memasuki tempat yang penghuninya disiksa kecuali kalian menangis, jika tidak bisa menangis maka janganlah kalian memasukinya agar kalian tidak mendapat mushibah sebagaimana mereka mendapatkannya.\""},"416":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ سَلَامٍ قَالَ أَخْبَرَنَا عَبْدَةُ عَنْ هِشَامِ بْنِ عُرْوَةَ عَنْ أَبِيهِ عَنْ عَائِشَةَأَنَّ أُمَّ سَلَمَةَ ذَكَرَتْ لِرَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَنِيسَةً رَأَتْهَا بِأَرْضِ الْحَبَشَةِ يُقَالُ لَهَا مَارِيَةُ فَذَكَرَتْ لَهُ مَا رَأَتْ فِيهَا مِنْ الصُّوَرِ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أُولَئِكَ قَوْمٌ إِذَا مَاتَ فِيهِمْ الْعَبْدُ الصَّالِحُ أَوْ الرَّجُلُ الصَّالِحُ بَنَوْا عَلَى قَبْرِهِ مَسْجِدًا وَصَوَّرُوا فِيهِ تِلْكَ الصُّوَرَ أُولَئِكَ شِرَارُ الْخَلْقِ عِنْدَ اللَّهِ","id":"Telah menceritakan kepada kami [Muhammad bin Salam] berkata, telah mengabarkan kepada kami ['Abdah] dari [Hisyam bin 'Urwah] dari [Bapaknya] dari ['Aisyah], bahwa Ummu Salamah menceritakan kepada Rasulullah shallallahu 'alaihi wasallam sebuah gereja yang dia lihat di suatu tempat di negeri Habasyah (Eithofia) yang disebut Mariyah. Kemudian dia ceritakan apa yang dilihatnya bahwa didalamnya ada gambar (patung). Rasulullah shallallahu 'alaihi wasallam pun bersabda: \"Mereka adalah suatu kaum yang jika ada hamba shalih atau laki-laki shalih dari mereka meninggal, mereka membangun masjid di atas kuburannya dan membuatkan patung untuknya. Maka mereka itulah seburuk-buruk makhluk di sisi Allah.\""},"417":{"ar":"حَدَّثَنَا أَبُو الْيَمَانِ قَالَ أَخْبَرَنَا شُعَيْبٌ عَنْ الزُّهْرِيِّ أَخْبَرَنِي عُبَيْدُ اللَّهِ بْنُ عَبْدِ اللَّهِ بْنِ عُتْبَةَ أَنَّ عَائِشَةَ وَعَبْدَ اللَّهِ بْنَ عَبَّاسٍ قَالَالَمَّا نَزَلَ بِرَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ طَفِقَ يَطْرَحُ خَمِيصَةً لَهُ عَلَى وَجْهِهِ فَإِذَا اغْتَمَّ بِهَا كَشَفَهَا عَنْ وَجْهِهِ فَقَالَ وَهُوَ كَذَلِكَ لَعْنَةُ اللَّهِ عَلَى الْيَهُودِ وَالنَّصَارَى اتَّخَذُوا قُبُورَ أَنْبِيَائِهِمْ مَسَاجِدَيُحَذِّرُ مَا صَنَعُوا","id":"Telah menceritakan kepada kami [Abu Al Yaman] berkata, telah mengabarkan kepada kami [Syu'aib] dari [Az Zuhri] telah mengabarkan kepadaku [Ubaidullah bin 'Abdullah bin 'Utbah] bahwa ['Aisyah] dan ['Abdullah bin 'Abbas] keduanya berkata, \"Ketika sakit Rasulullah shallallahu 'alaihi wasallam semakin parah, beliau memegang bajunya dan ditutupkan pada mukanya. Bila telah terasa sesak, beliau lepaskan dari mukanya. Ketika keadaannya seperti itu beliau bersabda: 'Semoga laknat Allah tertipa kepada orang-orang Yahudi dan Nashara, mereka menjadikan kuburan para Nabi mereka sebagai masjid.' Beliau memberi peringatan (kaum Muslimin) atas apa yang mereka lakukan.\""},"418":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مَسْلَمَةَ عَنْ مَالِكٍ عَنْ ابْنِ شِهَابٍ عَنْ سَعِيدِ بْنِ الْمُسَيَّبِ عَنْ أَبِي هُرَيْرَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ قَاتَلَ اللَّهُ الْيَهُودَ اتَّخَذُوا قُبُورَ أَنْبِيَائِهِمْ مَسَاجِدَ","id":"Telah menceritakan kepada kami ['Abdullah bin Maslamah] dari [Malik] dari [Ibnu Syihab] dari [Sa'in bin Al Musattab] dari [Abu Hurairah] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Allah melaknat Yahudi dan Nashara karena mereka menjadikan kuburan para Nabi mereka sebagai masjid.\""},"419":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ سِنَانٍ قَالَ حَدَّثَنَا هُشَيْمٌ قَالَ حَدَّثَنَا سَيَّارٌ هُوَ أَبُو الْحَكَمِ قَالَ حَدَّثَنَا يَزِيدُ الْفَقِيرُ قَالَ حَدَّثَنَا جَابِرُ بْنُ عَبْدِ اللَّهِ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أُعْطِيتُ خَمْسًا لَمْ يُعْطَهُنَّ أَحَدٌ مِنْ الْأَنْبِيَاءِ قَبْلِي نُصِرْتُ بِالرُّعْبِ مَسِيرَةَ شَهْرٍ وَجُعِلَتْ لِي الْأَرْضُ مَسْجِدًا وَطَهُورًا وَأَيُّمَا رَجُلٍ مِنْ أُمَّتِي أَدْرَكَتْهُ الصَّلَاةُ فَلْيُصَلِّ وَأُحِلَّتْ لِي الْغَنَائِمُ وَكَانَ النَّبِيُّ يُبْعَثُ إِلَى قَوْمِهِ خَاصَّةً وَبُعِثْتُ إِلَى النَّاسِ كَافَّةً وَأُعْطِيتُ الشَّفَاعَةَ","id":"Telah menceritakan kepada kami [Muhammad bin Sinan] berkata, telah menceritakan kepada kami [Husyaim] berkata, telah menceritakan kepada kami [Sayyarah] -yaitu Abu Al Hakam- berkata, telah menceritakan kepada kami [Yazid Al Faqir] berkata, telah menceritakan kepada kami [Jabir bin 'Abdullah] berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Aku diberikan lima perkara yang tidak diberikan kepada seorangpun dari Nabi-Nabi sebelumku; aku ditolong melawan musuhku dengan ketakutan mereka sepanjang sebulan perjalanan, bumi dijadikan untukku sebagai tempat sujud dan suci; maka dimana saja seorang laki-laki dari ummatku mendapati waktu shalat hendaklah ia shalat. Dihalalkan harta rampasan untukku, para Nabi sebelumku diutus khusus untuk kaumnya sedangkan aku diutus untuk seluruh manusia, dan aku diberikah (hak) syafa'at\"."},"420":{"ar":"حَدَّثَنَا عُبَيْدُ بْنُ إِسْمَاعِيلَ قَالَ حَدَّثَنَا أَبُو أُسَامَةَ عَنْ هِشَامِ بْنِ عُرْوَةَ عَنْ أَبِيهِ عَنْ عَائِشَةَأَنَّ وَلِيدَةً كَانَتْ سَوْدَاءَ لِحَيٍّ مِنْ الْعَرَبِ فَأَعْتَقُوهَا فَكَانَتْ مَعَهُمْ قَالَتْ فَخَرَجَتْ صَبِيَّةٌ لَهُمْ عَلَيْهَا وِشَاحٌ أَحْمَرُ مِنْ سُيُورٍ قَالَتْ فَوَضَعَتْهُ أَوْ وَقَعَ مِنْهَا فَمَرَّتْ بِهِ حُدَيَّاةٌ وَهُوَ مُلْقًى فَحَسِبَتْهُ لَحْمًا فَخَطِفَتْهُ قَالَتْ فَالْتَمَسُوهُ فَلَمْ يَجِدُوهُ قَالَتْ فَاتَّهَمُونِي بِهِ قَالَتْ فَطَفِقُوا يُفَتِّشُونَ حَتَّى فَتَّشُوا قُبُلَهَا قَالَتْ وَاللَّهِ إِنِّي لَقَائِمَةٌ مَعَهُمْ إِذْ مَرَّتْ الْحُدَيَّاةُ فَأَلْقَتْهُ قَالَتْ فَوَقَعَ بَيْنَهُمْ قَالَتْ فَقُلْتُ هَذَا الَّذِي اتَّهَمْتُمُونِي بِهِ زَعَمْتُمْ وَأَنَا مِنْهُ بَرِيئَةٌ وَهُوَ ذَا هُوَ قَالَتْ فَجَاءَتْ إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَسْلَمَتْ قَالَتْ عَائِشَةُ فَكَانَ لَهَا خِبَاءٌ فِي الْمَسْجِدِ أَوْ حِفْشٌ قَالَتْ فَكَانَتْ تَأْتِينِي فَتَحَدَّثُ عِنْدِي قَالَتْ فَلَا تَجْلِسُ عِنْدِي مَجْلِسًا إِلَّا قَالَتْ وَيَوْمَ الْوِشَاحِ مِنْ أَعَاجِيبِ رَبِّنَاأَلَا إِنَّهُ مِنْ بَلْدَةِ الْكُ��ْرِ أَنْجَانِيقَالَتْ عَائِشَةُ فَقُلْتُ لَهَا مَا شَأْنُكِ لَا تَقْعُدِينَ مَعِي مَقْعَدًا إِلَّا قُلْتِ هَذَا قَالَتْ فَحَدَّثَتْنِي بِهَذَا الْحَدِيثِ","id":"Telah menceritakan kepada kami [Ubaid bin Isma'il] berkata, telah menceritakan kepada kami [Abu Usamah] dari [Hisyam bin 'Urwah] dari [Bapaknya] dari ['Aisyah], bahwa ada seorang budak perempuan hitam milik suatu kaum orang 'Arab telah mereka merdekakan.\" 'Aisyah mengatakan, \"Pada suatu hari sahaya ini keluar bersama seorang bayi perempuan dengan membawa kain tikar tenunan berwarna merah terbuat dari kulit yang dihiasi dengan permata. Berkata, 'Aisyah radliallahu 'anhu: Maka sahaya itu meletakkan tikar tersebut atau duduk diatasnya. Lalu tiba-tiba ada burung terluka yang jatuh. Sahaya itu menganggapnya sebagai daging maka diambilnya. Lalu orang-orang itu mencari burung tersebut tapi tidak menemukannya. Berkata, 'Aisyah radliallahu 'anhu: \"Lalu orang-orang itu menanyakannya kepadaku. Be 'Aisyah radliallahu 'anhu: \"lalu orang-orng iru menggeledah sampai pada bagian depan sahaya tersebut. 'Aisyah radliallahu 'anhu berkata,: \"Demi Allah, aku ada bersama mereka saat butung itu jatuh lalu dia mengambilnya. Maka terjadilah apa yang terjadi diantara mereka. 'Aisyah radliallahu 'anhu berkata,: \"Aku katakan: Inilah yang kalian duga aku berada di balik ini semua padahal orang ini lah yang berbuat dan aku berlepas diri darinya\". 'Aisyah radliallahu 'anhu berkata,: \"Lalu sahaya ini menemui Rasulullah shallallahu 'alaihi wasallam. dan masuk Islam. Berkata, 'Aisyah radliallahu 'anhu: Sahaya ini memiliki rumah kecil di dekat masjid. 'Aisyah radliallahu 'anhu berkata,: \"Dan setiap dia menemui aku dia menceritakan disampingku. 'Aisyah radliallahu 'anhu berkata,: \" Tidaklah dia duduk disisiku melainkan selalu bersya'ir: Berkata, 'Aisyah radliallahu 'anhu: aku katakana kepadanya: \"Apa alasanmmu setiap kali bermajelis denganku kamu bersya'ir seperti itu?\" 'Aisyah radliallahu 'anhu berkata,: Maka dia ceritakan seperti kejadian dalam hadits ini\"."},"421":{"ar":"حَدَّثَنَا مُسَدَّدٌ قَالَ حَدَّثَنَا يَحْيَى عَنْ عُبَيْدِ اللَّهِ قَالَ حَدَّثَنِي نَافِعٌ قَالَ أَخْبَرَنِي عَبْدُ اللَّهِ بْنُ عُمَرَأَنَّهُ كَانَ يَنَامُ وَهُوَ شَابٌّ أَعْزَبُ لَا أَهْلَ لَهُ فِي مَسْجِدِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah menceritakan kepada kami [Musaddad] berkata, telah menceritakan kepada kami [Yahya] dari ['Ubaidullah] berkata, telah menceritakan kepadaku [Nafi'] berkata, telah mengabarkan kepadaku ['Abdullah bin 'Umar], bahwa ia pernah tidur di masjid Nabi shallallahu 'alaihi wasallam saat dia masih pemuda lajang dan belum punya keluarga.\""},"422":{"ar":"حَدَّثَنَا قُتَيْبَةُ بْنُ سَعِيدٍ قَالَ حَدَّثَنَا عَبْدُ الْعَزِيزِ بْنُ أَبِي حَازِمٍ عَنْ أَبِي حَازِمٍ عَنْ سَهْلِ بْنِ سَعْدٍ قَالَجَاءَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بَيْتَ فَاطِمَةَ فَلَمْ يَجِدْ عَلِيًّا فِي الْبَيْتِ فَقَالَ أَيْنَ ابْنُ عَمِّكِ قَالَتْ كَانَ بَيْنِي وَبَيْنَهُ شَيْءٌ فَغَاضَبَنِي فَخَرَجَ فَلَمْ يَقِلْ عِنْدِي فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لِإِنْسَانٍ انْظُرْ أَيْنَ هُوَ فَجَاءَ فَقَالَ يَا رَسُولَ اللَّهِ هُوَ فِي الْمَسْجِدِ رَاقِدٌ فَجَاءَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَهُوَ مُضْطَجِعٌ قَدْ سَقَطَ رِدَاؤُهُ عَنْ شِقِّهِ وَأَصَابَهُ تُرَابٌ فَجَعَلَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَمْسَحُهُ عَنْهُ وَيَقُولُ قُمْ أَبَا تُرَابٍ قُمْ أَبَا تُرَابٍ","id":"Telah menceritakan kepada kami [Qutaibah bin Sa'id] berkata, telah menceritakan kepada kami ['Abdul 'Aziz bin Abu Hazim] dari [Abu Hazim] dari [Sahl bin Sa'd] berkata, \"Rasulullah shallallahu 'alaihi wasallam datang ke rumah Fatimah namun 'Ali tidak ada di rumah. Beliau lalu bertanya: \"Kemana putera pamanmu?\" Fatimah menjawab, \"Antara aku dan dia terjadi sesuatu hingga dia marah kepadaku, lalu dia pergi dan tidak tidur siang di rumah.\" Maka Rasulullah shallallahu 'alaihi wasallam berkata kepada seseorang: \"Carilah, dimana dia!\" Kemudian orang itu kembali dan berkata, \"Wahai Rasulullah, dia ada di masjid sedang tidur.\" Maka Rasulullah shallallahu 'alaihi wasallam mendatanginya, ketika itu Ali sedang berbaring sementara kain selendangnya jatuh di sisinya hingga ia tertutupi debu. Maka Rasulullah shallallahu 'alaihi wasallam membersihkannya seraya berkata: \"Wahai Abu Thurab, bangunlah. Wahai Abu Thurab, bangunlah.\" "},"423":{"ar":"حَدَّثَنَا يُوسُفُ بْنُ عِيسَى قَالَ حَدَّثَنَا ابْنُ فُضَيْلٍ عَنْ أَبِيهِ عَنْ أَبِي حَازِمٍ عَنْ أَبِي هُرَيْرَةَ قَالَلَقَدْ رَأَيْتُ سَبْعِينَ مِنْ أَصْحَابِ الصُّفَّةِ مَا مِنْهُمْ رَجُلٌ عَلَيْهِ رِدَاءٌ إِمَّا إِزَارٌ وَإِمَّا كِسَاءٌ قَدْ رَبَطُوا فِي أَعْنَاقِهِمْ فَمِنْهَا مَا يَبْلُغُ نِصْفَ السَّاقَيْنِ وَمِنْهَا مَا يَبْلُغُ الْكَعْبَيْنِ فَيَجْمَعُهُ بِيَدِهِ كَرَاهِيَةَ أَنْ تُرَى عَوْرَتُهُ","id":"Telah menceritakan kepada kami [Yusuf bin 'Isa] berkata, telah menceritakan kepada kami [Ibnu Fudlail] dari [Bapaknya] dari [Abu Hazm] dari [Abu Hurairah] berkata, \"Sungguh, aku pernah melihat sekitar tujuh puluh orang dari Ashhabush Shuffah. Tidak ada seorangpun dari mereka yang memiliki rida' (selendang), atau kain, atau baju panjang kecuali mereka ikatkan dari leher mereka. Di antara mereka ada yang kainnya sampai ke tengah betisnya dan ada yang sampai ke mata kaki. Kemudian dia lipatkan dengan tangannya karena khawatir auratnya terlihat.\" "},"424":{"ar":"حَدَّثَنَا خَلَّادُ بْنُ يَحْيَى قَالَ حَدَّثَنَا مِسْعَرٌ قَالَ حَدَّثَنَا مُحَارِبُ بْنُ دِثَارٍ عَنْ جَابِرِ بْنِ عَبْدِ اللَّهِ قَالَأَتَيْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَهُوَ فِي الْمَسْجِدِ قَالَ مِسْعَرٌ أُرَاهُ قَالَ ضُحًى فَقَالَ صَلِّ رَكْعَتَيْنِ وَكَانَ لِي عَلَيْهِ دَيْنٌ فَقَضَانِي وَزَادَنِي","id":"Telah menceritakan kepada kami [Khallad bin Yahya] berkata, telah menceritakan kepada kami [Mis'ar] berkata, telah menceritakan kepada kami [Muharib bin Ditsar] dari [Jabir bin 'Abdullah] berkata, \"Aku datang menemui Nabi shallallahu 'alaihi wasallam saat beliau berada di masjid -Mis'ar berkata, \"Menurutku Jabir berkata, 'Saat waktu dluha.'- Jabir bin 'Abdullah berkata, \"Beliau bersabda: \"Shalatlah dua rakaat.\" Ketika itu beliau mempunyai hutang kepadaku. Maka beliau membayarnya dan memberi tambahan kepadaku.\""},"425":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ يُوسُفَ قَالَ أَخْبَرَنَا مَالِكٌ عَنْ عَامِرِ بْنِ عَبْدِ اللَّهِ بْنِ الزُّبَيْرِ عَنْ عَمْرِو بْنِ سُلَيْمٍ الزُّرَقِيِّ عَنْ أَبِي قَتَادَةَ السَّلَمِيِّأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِذَا دَخَلَ أَحَدُكُمْ الْمَسْجِدَ فَلْيَرْكَعْ رَكْعَتَيْنِ قَبْلَ أَنْ يَجْلِسَ","id":"Telah menceritakan kepada kami ['Abdullah bin Yusuf] berkata, telah mengabarkan kepada kami [Malik] dari ['Amir bin 'Abdullah bin Az Zubair] dari ['Amru bin Sulaim Az Zaraqi] dari [Abu Qatadah As Salami], bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Jika salah seorang dari kalian masuk masjid, maka hendaklah ia shalat dua rakaat sebelum ia duduk.\""},"426":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ يُوسُفَ قَالَ أَخْبَرَنَا مَالِكٌ عَنْ أَبِي الزِّنَادِ عَنْ الْأَعْرَجِ عَنْ أَبِي هُرَيْرَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ الْمَلَائِكَةُ تُصَلِّي عَلَى أَحَدِكُمْ مَا دَامَ فِي مُصَلَّاهُ الَّذِي صَلَّى فِيهِ مَا لَمْ يُحْدِثْ تَقُولُ اللَّهُمَّ اغْفِرْ لَهُ اللَّهُمَّ ارْحَمْهُ","id":". Telah menceritakan kepada kami ['Abdullah bin Yusuf] berkata, telah mengabarkan kepada kami [Malik] dari [Abu Az Zanad] dari [Al A'raj] dari [Abu Hurairah], bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Para Malaikat selalu memberi shalawat (mendo'akan) kepada salah seorang dari kalian selama ia masih di tempat ia shalat dan belum berhadats. Malaikat berkata, 'Ya Allah ampunilah dia. Ya Allah rahmatilah dia'.\""},"427":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ عَبْدِ اللَّهِ قَالَ حَدَّثَنَا يَعْقُوبُ بْنُ إِبْرَاهِيمَ بْنِ سَعْدٍ قَالَ حَدَّثَنِي أَبِي عَنْ صَالِحِ بْنِ كَيْسَانَ قَالَ حَدَّثَنَا نَافِعٌ أَنَّ عَبْدَ اللَّهِ بْنَ عُمَرَ أَخْبَرَهُأَنَّ الْمَسْجِدَ كَانَ عَلَى عَهْدِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَبْنِيًّا بِاللَّبِنِ وَسَقْفُهُ الْجَرِيدُ وَعُمُدُهُ خَشَبُ النَّخْلِ فَلَمْ يَزِدْ فِيهِ أَبُو بَكْرٍ شَيْئًا وَزَادَ فِيهِ عُمَرُ وَبَنَاهُ عَلَى بُنْيَانِهِ فِي عَهْدِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِاللَّبِنِ وَالْجَرِيدِ وَأَعَادَ عُمُدَهُ خَشَبًا ثُمَّ غَيَّرَهُ عُثْمَانُ فَزَادَ فِيهِ زِيَادَةً كَثِيرَةً وَبَنَى جِدَارَهُ بِالْحِجَارَةِ الْمَنْقُوشَةِ وَالْقَصَّةِ وَجَعَلَ عُمُدَهُ مِنْ حِجَارَةٍ مَنْقُوشَةٍ وَسَقَفَهُ بِالسَّاجِ","id":"Telah menceritakan kepada kami ['Ali bin 'Abdullah] berkata, telah menceritakan kepada kami [Ya'qub bin Ibrahim bin Sa'd] berkata, telah menceritakan kepadaku [Bapakku] dari [Shalih bin Kaisan] berkata, telah menceritakan kepada kami [Nafi'] bahwa ['Abdullah bin 'Umar] mengabarkan kepadanya, bahwa pada masa Rasulullah shallallahu 'alaihi wasallam Masjid dibangun dengan menggunakan tanah liat yang dikeraskan (bata). Atapnya dari dedaunan sedangkan tiangnya dari batang pohon kurma. Pada masanya Abu Bakar tidak memberi tambahan renovasi apapun, kemudian pada masanya Umar bin Al Khaththab ia memberi tambahan renovasi, Umar merenovasi dengan batu bata dan dahan barang kurma sesuai dengan bentuk yang ada di masa Rasulullah shallallahu 'alaihi wasallam. Tiang utama ia ganti dengan kayu. Kemudian pada masa Utsman ia banyak melakukan perubahan dan renovasi, dinding masjid ia bangun dari batu yang diukir dan batu kapur. Kemudian tiang dari batu berukir dan atapnya dari batang kayu pilihan.\""},"428":{"ar":"حَدَّثَنَا مُسَدَّدٌ قَالَ حَدَّثَنَا عَبْدُ الْعَزِيزِ بْنُ مُخْتَارٍ قَالَ حَدَّثَنَا خَالِدٌ الْحَذَّاءُ عَنْ عِكْرِمَةَ قَالَ لِي ابْنُ عَبَّاسٍ وَلِابْنِهِ عَلِيٍّ انْطَلِقَا إِلَى أَبِي سَعِيدٍفَاسْمَعَا مِنْ حَدِيثِهِ فَانْطَلَقْنَا فَإِذَا هُوَ فِي حَائِطٍ يُصْلِحُهُ فَأَخَذَ رِدَاءَهُ فَاحْتَبَى ثُمَّ أَنْشَأَ يُحَدِّثُنَا حَتَّى أَتَى ذِكْرُ بِنَاءِ الْمَسْجِدِ فَقَالَ كُنَّا نَحْمِلُ لَبِنَةً لَبِنَةً وَعَمَّارٌ لَبِنَتَيْنِ لَبِنَتَيْنِ فَرَآهُ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَيَنْفُضُ التُّرَابَ عَنْهُ وَيَقُولُ وَيْحَ عَمَّارٍ تَقْتُلُهُ الْفِئَةُ الْبَاغِيَةُ يَدْعُوهُمْ إِلَى الْجَنَّةِ وَيَدْعُونَهُ إِلَى النَّارِ قَالَ يَقُولُ عَمَّارٌ أَعُوذُ بِاللَّهِ مِنْ الْفِتَنِ","id":"Telah menceritakan kepada kami [Musaddad] berkata, telah menceritakan kepada kami ['Abdul 'Aziz bin Mukhtar] berkata, telah menceritakan kepada kami [Khalid Al Hadza'] dari ['Ikrimah], Ibnu 'Abbas kepadaku dan kepada Ali, anaknya, \"Pergilah kalian bedua menemui [Abu Sa'id] dan dengarlah hadits darinya!\" Maka kami pun berangkat. Dan kami dapati dia sedang membetulkan dinding miliknya, ia mengambil kain selendangnya dan duduk ihtiba`. Kemudian ia mulai berbicara hingga menyebutkan tentang pembangunan masjid. Ia mengkisahkan, \"Masing-masing kami membawa bata satu persatu, sedangkan 'Ammar membawa dua bata dua bata sekaligus. Saat Nabi shallallahu 'alaihi wasallam melihatnya, beliau berkata sambil meniup debu yang ada padanya: \"Kasihan 'Ammar, dia akan dibunuh oleh golongan durjana. Dia mengajak mereka ke surga sedangkan mereka mengajaknya ke neraka.\" Ibnu 'Abbas berkata, \"'Ammar lantas berkata, \"Aku berlindung kepada Allah dari fitnah tersebut.\""},"429":{"ar":"حَدَّثَنَا قُتَيْبَةُ بْنُ سَعِيدٍ قَالَ حَدَّثَنَا عَبْدُ الْعَزِيزِ حَدَّثَنِي أَبُو حَازِمٍ عَنْ سَهْلٍ قَالَبَعَثَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِلَى امْرَأَةٍ مُرِي غُلَامَكِ النَّجَّارَ يَعْمَلْ لِي أَعْوَادًا أَجْلِسُ عَلَيْهِنَّ","id":"Telah menceritakan kepada kami [Qutaibah bin Sa'id] berkata, telah menceritakan kepada kami ['Abdul 'Aziz] telah menceritakan kepadaku [Abu Hazim] dari [Sahl] berkata, \"Rasulullah shallallahu 'alaihi wasallam mengutus seorang wanita dan berkata, \"Perintahkan budakmu yang tukang kayu itu membuat tangga mimbar untukku, hingga aku bisa duduk di atasnya.\""},"430":{"ar":"حَدَّثَنَا خَلَّادٌ قَالَ حَدَّثَنَا عَبْدُ الْوَاحِدِ بْنُ أَيْمَنَ عَنْ أَبِيهِ عَنْ جَابِرِ بْنِ عَبْدِ اللَّهِأَنَّ امْرَأَةً قَالَتْ يَا رَسُولَ اللَّهِ أَلَا أَجْعَلُ لَكَ شَيْئًا تَقْعُدُ عَلَيْهِ فَإِنَّ لِي غُلَامًا نَجَّارًا قَالَ إِنْ شِئْتِ فَعَمِلَتْ الْمِنْبَرَ","id":"Telah menceritakan kepada kami [Khallad] berkata, telah menceritakan kepada kami ['Abdul Wahid bin Aiman] dari [Bapaknya] dari [Jabir bin 'Abdullah], bahwa ada seorang wanita berkata, \"Wahai Rasulullah, bolehkah aku buatkan sesuatu untuk Tuan, sehingga Tuan bisa duduk di atasnya? Karena aku punya seorang budak yang ahli dalam masalah pertukangan kayu.\" Beliau menjawab: \"Silakan, kalau kamu mau.\" Maka wanita itu membuat sebuah mimbar.\""},"431":{"ar":"حَدَّثَنَا يَحْيَى بْنُ سُلَيْمَانَ حَدَّثَنِي ابْنُ وَهْبٍ أَخْبَرَنِي عَمْرٌو أَنَّ بُكَيْرًا حَدَّثَهُ أَنَّ عَاصِمَ بْنَ عُمَرَ بْنِ قَتَادَةَ حَدَّثَهُ أَنَّهُ سَمِعَ عُبَيْدَ اللَّهِ الْخَوْلَانِيَّ أَنَّهُ سَمِعَ عُثْمَانَ بْنَ عَفَّانَيَقُولُ عِنْدَ قَوْلِ النَّاسِ فِيهِ حِينَ بَنَى مَسْجِدَ الرَّسُولِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّكُمْ أَكْثَرْتُمْ وَإِنِّي سَمِعْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ مَنْ بَنَى مَسْجِدًا قَالَ بُكَيْرٌ حَسِبْتُ أَنَّهُ قَالَ يَبْتَغِي بِهِ وَجْهَ اللَّهِ بَنَى اللَّهُ لَهُ مِثْلَهُ فِي الْجَنَّةِ","id":"Telah menceritakan kepada kami [Yahya bin Sulaiman] telah menceritakan kepadaku [Ibnu Wahb] telah mengabarkan kepadaku ['Amru] bahwa [Bukair] menceritakan kepadanya, bahwa ['Ashim bin 'Umar bin Qatadah] menceritakan kepadanya, bahwa dia mendengar ['Ubaidullah Al Khaulani] mendengar ['Utsman bin 'Affan] berkata di tengah pembicaraan orang-orang sekitar masalah pembangunan masjid Rasulullah shallallahu 'alaihi wasallam, ia katakan, \"Sungguh, kalian telah banyak berbicara, padahal aku mendengar Nabi shallallahu 'alaihi wasallam bersabda: \"Siapa yang membangun masjid -Bukair berkata, \"Menurutku beliau mengatakan- karena mengharapkah ridla Allah, maka Allah akan membangun untuknya yang seperti itu di surga.\""},"432":{"ar":"حَدَّثَنَا قُتَيْبَةُ بْنُ سَعِيدٍ قَالَ حَدَّثَنَا سُفْيَانُ قَالَ قُلْتُ لِعَمْرٍو أَسَمِعْتَ جَابِرَ بْنَ عَبْدِ اللَّهِ يَقُولُمَرَّ رَجُلٌ فِي الْمَسْجِدِ وَمَعَهُ سِهَامٌ فَقَالَ لَهُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَمْسِكْ بِنِصَالِهَا","id":"Telah menceritakan kepada kami [Qutaibah bin Sa'id] berkata, telah menceritakan kepada kami [Sufyan] berkata, aku katakan kepada ['Amru], \"Apakah kamu mendengar [Jabir bin 'Abdullah] berkata, \"Ada seorang laki-laki berjalan di dalam masjid dengan membawa panah. Maka Rasulullah shallallahu 'alaihi wasallam bersabda kepadanya: \"Jagalah ujung panahmu!\""},"433":{"ar":"حَدَّثَنَا مُوسَى بْنُ إِسْمَاعِيلَ قَالَ حَدَّثَنَا عَبْدُ الْوَاحِدِ قَالَ حَدَّثَنَا أَبُو بُرْدَةَ بْنُ عَبْدِ اللَّهِ قَالَ سَمِعْتُ أَبَا بُرْدَةَ عَنْ أَبِيهِعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ مَرَّ فِي شَيْءٍ مِنْ مَسَاجِدِنَا أَوْ أَسْوَاقِنَا بِنَبْلٍ فَلْيَأْخُذْ عَلَى نِصَالِهَا لَا يَعْقِرْ بِكَفِّهِ مُسْلِمًا","id":"Telah menceritakan kepada kami [Musa bin Isma'il] berkata, telah menceritakan kepada kami ['Abdul Wahid] berkata, telah menceritakan kepada kami [Abu Burdah bin 'Abdullah] berkata, aku mendengar [Abu Burdah] dari [Bapaknya] dari Nabi shallallahu 'alaihi wasallam bersabda: \"Barangsiapa lewat dengan membawa panah di masjid atau pasar kita, maka hendaklah dipegang ujung panahnya dengan tangannya agar tidak melukai seorang muslim.\""},"434":{"ar":"حَدَّثَنَا أَبُو الْيَمَانِ الْحَكَمُ بْنُ نَافِعٍ قَالَ أَخْبَرَنَا شُعَيْبٌ عَنْ الزُّهْرِيِّ قَالَ أَخْبَرَنِي أَبُو سَلَمَةَ بْنُ عَبْدِ الرَّحْمَنِ بْنِ عَوْفٍ أَنَّهُسَمِعَ حَسَّانَ بْنَ ثَابِتٍ الْأَنْصَارِيَّ يَسْتَشْهِدُ أَبَا هُرَيْرَةَ أَنْشُدُكَ اللَّهَ هَلْ سَمِعْتَ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ يَا حَسَّانُ أَجِبْ عَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ اللَّهُمَّ أَيِّدْهُ بِرُوحِ الْقُدُسِ قَالَ أَبُو هُرَيْرَةَ نَعَمْ","id":"Telah menceritakan kepada kami [Abu Al Yaman Al Hakam bin Nafi'] berkata, telah mengabarkan kepada kami [Syu'aib] dari [Az Zuhri] berkata, telah mengabarkan kepadaku [Abu Salamah bin 'Abdurrahman bin 'Auf] bahwa dia mendengar [Hassan bin Tsabit Al Anshari] meminta kesaksian [Abu Hurairah], \"Semoga Allah memberimu kebaikan, apakah anda mendengar Nabi shallallahu 'alaihi wasallam bersabda: \"Wahai Hassan, penuhilah panggilan Rasulullah shallallahu 'alaihi wasallam (permintaan untuk melawan kaum kafir). Ya Allah, kuatkanlah dia dengan Ruhul Qudus (Malaikat Jibril) '. Abu Hurairah menjawab, \"Ya.\""},"435":{"ar":"حَدَّثَنَا عَبْدُ الْعَزِيزِ بْنُ عَبْدِ اللَّهِ قَالَ حَدَّثَنَا إِبْرَاهِيمُ بْنُ سَعْدٍ عَنْ صَالِحِ بْنِ كَيْسَانَ عَنْ ابْنِ شِهَابٍ قَالَ أَخْبَرَنِي عُرْوَةُ بْنُ الزُّبَيْرِ أَنَّ عَائِشَةَ قَالَتْلَقَدْ رَأَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَوْمًا عَلَى بَابِ حُجْرَتِي وَالْحَبَشَةُ يَلْعَبُونَ فِي الْمَسْجِدِ وَرَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَسْتُرُنِي بِرِدَائِهِ أَنْظُرُ إِلَى لَعِبِهِمْزَادَ إِبْرَاهِيمُ بْنُ الْمُنْذِرِ حَدَّثَنَا ابْنُ وَهْبٍ أَخْبَرَنِي يُونُسُ عَنْ ابْنِ شِهَابٍ عَنْ عُرْوَةَ عَنْ عَائِشَةَ قَالَتْ رَأَيْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَالْحَبَشَةُ يَلْعَبُونَ بِحِرَابِهِمْ","id":"Telah menceritakan kepada kami ['Abdul 'Aziz bin 'Abdullah] berkata, telah menceritakan kepada kami [Ibrahim bin Sa'd] dari [Shalih bin Kaisan] dari [Ibnu Syihab] berkata, telah mengabarkan kepadaku ['Urwah bin Az Zubair] bahwa ['Aisyah] berkata, \"Pada suatu hari aku penah melihat Rasulullah shallallahu 'alaihi wasallam berdiri di pintu rumahku sedangkan budak-budak Habasyah sedang bermain di dalam Masjid. Rasulullah shallallahu 'alaihi wasallam menutupiku dengan kain selendangnya saat aku menyaksikan permainan mereka.\" [Ibraim bin Al Mundzir] menambahkan, telah menceritakan kepada kami [Ibnu Wahb] telah mengabarkan kepadaku [Yunus] dari [Ibnu Syihab] dari ['Urwah] dari ['Aisyah] berkata, \"Aku melihat Rasulullah shallallahu 'alaihi wasallam menyaksikan budak-budak Habasyah mempertunjukkan permainan tombak mereka.\""},"436":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ عَبْدِ اللَّهِ قَالَ حَدَّثَنَا سُفْيَانُ عَنْ يَحْيَى عَنْ عَمْرَةَ عَنْ عَائِشَةَ قَالَتْأَتَتْهَا بَرِيرَةُ تَسْأَلُهَا فِي كِتَابَتِهَا فَقَالَتْ إِنْ شِئْتِ أَعْطَيْتُ أَهْلَكِ وَيَكُونُ الْوَلَاءُ لِي وَقَالَ أَهْلُهَا إِنْ شِئْتِ أَعْطَيْتِهَا مَا بَقِيَ وَقَالَ سُفْيَانُ مَرَّةً إِنْ شِئْتِ أَعْتَقْتِهَا وَيَكُونُ الْوَلَاءُ لَنَا فَلَمَّا جَاءَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ذَكَّرَتْهُ ذَلِكَ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ابْتَاعِيهَا فَأَعْتِقِيهَا فَإِنَّ الْوَلَاءَ لِمَنْ أَعْتَقَ ثُمَّ قَامَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَلَى الْمِنْبَرِ وَقَالَ سُفْيَانُ مَرَّةً فَصَعِدَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَلَى الْمِنْبَرِ فَقَالَ مَا بَالُ أَقْوَامٍ يَشْتَرِطُونَ شُرُوطًا لَيْسَ فِي كِتَابِ اللَّهِ مَنْ اشْتَرَطَ شَرْطًا لَيْسَ فِي كِتَابِ اللَّهِ فَلَيْسَ لَهُ وَإِنْ اشْتَرَطَ مِائَةَ مَرَّةٍقَالَ عَلِيٌّ قَالَ يَحْيَى وَعَبْدُ الْوَهَّابِ عَنْ يَحْيَى عَنْ عَمْرَةَ نَحْوَهُ وَقَالَ جَعْفَرُ بْنُ عَوْنٍ عَنْ يَحْيَى قَالَ سَمِعْتُ عَمْرَةَ قَالَتْ سَمِعْتُ عَائِشَةَ وَرَوَاهُ مَالِكٌ عَنْ يَحْيَى عَنْ عَمْرَةَ أَنَّ بَرِيرَةَ وَلَمْ يَذْكُرْ صَعِدَ الْمِنْبَرَ","id":"Telah menceritakan kepada kami ['Ali bin 'Abdullah] berkata, telah menceritakan kepada kami [Sufyan] dari [Yahya] dari ['Amrah] dari ['Aisyah] berkata, \"Barirah datang kepadanya dan meminta tolong dalam masalah pembebasannya dirinya (sebagai budak).\" 'Aisyah lalu berkata, \"Kalau kamu mau, aku berikan tebusan kepada tuanmu dan perwalianmu milikku.\" Tuannya berkata, \"Kalau mau, engkau bisa berikan sisanya (harga budak tersebut).\" Sekali waktu Sufyan menyebutkan, \"Kalau kamu mau, bebaskanlah dia dan perwalian milik kami.\" Ketika Rasulullah shallallahu 'alaihi wasallam datang, Aisyah menceritakan hal itu kepada beliau. Maka Nabi shallallahu 'alaihi wasallam pun bersabda: \"Belil dan merdekakanlah. Sesungguhnya perwalian itu bagi orang yang memerdekakannya.\" Kemudian Rasulullah shallallahu 'alaihi wasallam berdiri dekat mimbar, sekali waktu Sufyan menyebutkanm \"Rasulullah shallallahu 'alaihi wasallam naik mimbar lalu bersabda: \"Kenapa suatu kaum membuat persyaratan dengan syarat-syarat yang tidak ada pada Kitabullah. Barangsiapa membuat syarat yang tidak ada pada Kitabullah, maka tidak berlaku sekalipun dia membuat persyaratan seratus kali.\" ['Ali] berkata, [Yahya] berkata dan ['Abdul Wahhab] dari [Yahya] dari ['Amrah] seperti hadits ini.\" Dan [Ja'far bin 'Aun] berkata, dari [Yahya] ia berkata, aku mendengar ['Amrah] berkata, aku mendengar ['Aisyah]. Dan [Malik] meriwayatkan dari [Yahya] dari ['Amrah] bahwa Bararah….namun ia tidak menyebut bahwa (Rasulullah) naik mimbar.\""},"437":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مُحَمَّدٍ قَالَ حَدَّثَنَا عُثْمَانُ بْنُ عُمَرَ قَالَ أَخْبَرَنَا يُونُسُ عَنْ الزُّهْرِيِّ عَنْ عَبْدِ اللَّهِ بْنِ كَعْبِ بْنِ مَالِكٍ عَنْ كَعْبٍأَنَّهُ تَقَاضَى ابْنَ أَبِي حَدْرَدٍ دَيْنًا كَانَ لَهُ عَلَيْهِ فِي الْمَسْجِدِ فَارْتَفَعَتْ أَصْوَاتُهُمَا حَتَّى سَمِعَهَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَهُوَ فِي بَيْتِهِ فَخَرَجَ إِلَيْهِمَا حَتَّى كَشَفَ سِجْفَ حُجْرَتِهِ فَنَادَى يَا كَعْبُ قَالَ لَبَّيْكَ يَا رَسُولَ اللَّهِ قَالَ ضَعْ مِنْ دَيْنِكَ هَذَا وَأَوْمَأَ إِلَيْهِ أَيْ الشَّطْرَ قَالَ لَقَدْ فَعَلْتُ يَا رَسُولَ اللَّهِ قَالَ قُمْ فَاقْضِهِ","id":"Telah menceritakan kepada kami ['Abdullah bin Muhammad] berkata, telah menceritakan kepada kami ['Utsman bin 'Umar] berkata, telah mengabarkan kepada kami [Yunus] dari [Az Zuhri] dari ['Abdullah bin Ka'b bin Malik] dari [Ka'b], bahwa ia pernah menagih hutang kepada Ibnu Abu Hadrad di dalam Masjid hingga suara keduanya meninggi yang akhirnya didengar oleh Rasulullah shallallahu 'alaihi wasallam yang berada di rumah. Beliau kemudian keluar menemui keduanya sambil menyingkap kain gorden kamarnya, beliau bersabda: \"Wahai Ka'b!\" Ka'b bin Malik menjawab: \"Wahai Rasulullah, aku penuhi panggilanmu.\" Beliau bersabda: \"Bebaskanlah hutangmu ini.\" Beliau lalu memberi isyarat untuk membebaskan setengahnya. Ka'b bin Malik menjawab, \"Sudah aku lakukan wahai Rasulullah.\" Beliau lalu bersabda (kepada Ibnu Abu Hadrad): \"Sekarang bayarlah.\""},"438":{"ar":"حَدَّثَنَا سُلَيْمَانُ بْنُ حَرْبٍ قَالَ حَدَّثَنَا حَمَّادُ بْنُ زَيْدٍ عَنْ ثَابِتٍ عَنْ أَبِي رَافِعٍ عَنْ أَبِي هُرَيْرَةَأَنَّ رَجُلًا أَسْوَدَ أَوْ امْرَأَةً سَوْدَاءَ كَانَ يَقُمُّ الْمَسْجِدَ فَمَاتَ فَسَأَلَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْهُ فَقَالُوا مَاتَ قَالَ أَفَلَا كُنْتُمْ آذَنْتُمُونِي بِهِ دُلُّونِي عَلَى قَبْرِهِ أَوْ قَالَ قَبْرِهَا فَأَتَى قَبْرَهَا فَصَلَّى عَلَيْهَا","id":"Telah menceritakan kepada kami [Sulaiman bin Harb] berkata, telah menceritakan kepada kami [Hammad bin Zaid] dari [Tsabit] dari [Rafi'] dari [Abu Hurairah], \"Ada seorang laki-laki kulit hitam atau wanita kulit hitam yang menjadi tukang sapu Masjid meninggal dunia. Nabi shallallahu 'alaihi wasallam lalu bertanya tentang keberadaan orang tersebut. Orang-orang pun menjawab, \"Dia telah meninggal!\" Beliaupun bersabda: \"Kenapa kalian tidak memberi kabar kepadaku? Tunjukkanlah kuburannya padaku!\" beliau kemudian mendatangi kuburan orang itu kemudian menshalatinya.\""},"439":{"ar":"حَدَّثَنَا عَبْدَانُ عَنْ أَبِي حَمْزَةَ عَنْ الْأَعْمَشِ عَنْ مُسْلِمٍ عَنْ مَسْرُوقٍ عَنْ عَائِشَةَ قَالَتْلَمَّا أُنْزِلَتْ الْآيَاتُ مِنْ سُورَةِ الْبَقَرَةِ فِي الرِّبَا خَرَجَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِلَى الْمَسْجِدِ فَقَرَأَهُنَّ عَلَى النَّاسِ ثُمَّ حَرَّمَ تِجَارَةَ الْخَمْرِ","id":"Telah menceritakan kepada kami ['Abdan] dari [Abu Hamzah] dari [Al A'masy] dari [Muslim] dari [Masruq] dari ['Aisyah] berkata, \"Ketika turun ayat-ayat dalam Surah Al Baqarah tentang masalah riba, Nabi shallallahu 'alaihi wasallam keluar ke masjid lalu membacakan ayat-ayat tersebut kepada manusia. Kemudian beliau mengharamkan perdagangan khamer.\""},"440":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ وَاقِدٍ قَالَ حَدَّثَنَا حَمَّادُ بْنُ زَيْدٍ عَنْ ثَابِتٍ عَنْ أَبِي رَافِعٍ عَنْ أَبِي هُرَيْرَةَأَنَّ امْرَأَةً أَوْ رَجُلًا كَانَتْ تَقُمُّ الْمَسْجِدَ وَلَا أُرَاهُ إِلَّا امْرَأَةً فَذَكَرَ حَدِيثَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُ صَلَّى عَلَى قَبْرِهَا","id":"Telah menceritakan kepada kami [Ahmad bin Waqid] berkata, telah menceritakan kepada kami [Hammad bin Zaid] dari [Tsabit] dari [Abu Rafi'] dari [Abu Hurairah], \"Seorang laki-laki atau perempuan mengurusi (kebersihan) Masjid, dan aku tidak melihat kecuali bahwa ia adalah seorang wanita. Lalu dia menyebutkan hadits Nabi shallallahu 'alaihi wasallam bahwa beliau shalat di atas kuburnya.\""},"441":{"ar":"حَدَّثَنَا إِسْحَاقُ بْنُ إِبْرَاهِيمَ قَالَ أَخْبَرَنَا رَوْحٌ وَمُحَمَّدُ بْنُ جَعْفَرٍ عَنْ شُعْبَةَ عَنْ مُحَمَّدِ بْنِ زِيَادٍ عَنْ أَبِي هُرَيْرَةَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِنَّ عِفْرِيتًا مِنْ الْجِنِّ تَفَلَّتَ عَلَيَّ الْبَارِحَةَ أَوْ كَلِمَةً نَحْوَهَا لِيَقْطَعَ عَلَيَّ الصَّلَاةَ فَأَمْكَنَنِي اللَّهُ مِنْهُ فَأَرَدْتُ أَنْ أَرْبِطَهُ إِلَى سَارِيَةٍ مِنْ سَوَارِي الْمَسْجِدِ حَتَّى تُصْبِحُوا وَتَنْظُرُوا إِلَيْهِ كُلُّكُمْ فَذَكَرْتُ قَوْلَ أَخِي سُلَيْمَانَ رَبِّ{ هَبْ لِي مُلْكًا لَا يَنْبَغِي لِأَحَدٍ مِنْ بَعْدِي }قَالَ رَوْحٌ فَرَدَّهُ خَاسِئًا","id":"Telah menceritakan kepada kami [Ishaq bin Ibrahim] berkata, telah mengabarkan kepada kami [Rauh] dan [Muhammad bin Ja'far] dari [Syu'bah] dari [Muhammad bin Ziyad] dari [Abu Hurairah] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Sesungguhnya 'Ifrit dari bangsa Jin baru saja menggaguku untuk memutus shalatku tapi Allah memenangkan aku atasnya, dan aku berkehendak untuk mengikatnya di salah satu tiang masjid sampai waktu shubuh sehingga tiap orang dari dapat kalian dapat melihatnya. Namun aku teringat ucapan saudaraku Sulaiman Alaihis Salam ketika berdo'a: '(Ya Rabb, anugerahkanlah kepadaku kerajaan yang tidak akan dimiliki oleh seorangpun setelah aku) ' (QS. Shaad: 35). Rauh berkata, \"Kemudian beliau mengusirnya dalan keadaan hina.\""},"442":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ يُوسُفَ قَالَ حَدَّثَنَا اللَّيْثُ قَالَ حَدَّثَنَا سَعِيدُ بْنُ أَبِي سَعِيدٍ سَمِعَ أَبَا هُرَيْرَةَ قَالَبَعَثَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ خَيْلًا قِبَلَ نَجْدٍ فَجَاءَتْ بِرَجُلٍ مِنْ بَنِي حَنِيفَةَ يُقَالُ لَهُ ثُمَامَةُ بْنُ أُثَالٍ فَرَبَطُوهُ بِسَارِيَةٍ مِنْ سَوَارِي الْمَسْجِدِ فَخَرَجَ إِلَيْهِ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ أَطْلِقُوا ثُمَامَةَ فَانْطَلَقَ إِلَى نَخْلٍ قَرِيبٍ مِنْ الْمَسْجِدِ فَاغْتَسَلَ ثُمَّ دَخَلَ الْمَسْجِدَ فَقَالَ أَشْهَدُ أَنْ لَا إِلَهَ إِلَّا اللَّهُ وَأَنَّ مُحَمَّدًا رَسُولُ اللَّهِ","id":"Telah menceritakan kepada kami ['Abdullah bin Yusuf] berkata, telah menceritakan kepada kami [Al Laits] berkata, telah menceritakan kepada kami [Sa'id bin Abu Sa'id] bahwa ia mendengar [Abu Hurairah] berkata, \"Nabi shallallahu 'alaihi wasallam pernah mengirim pasukan berkuda mendatangi Najed, pasukan itu lalu kembali dengan membawa seorang laki-laki dari bani Hanifah yang bernama Tsumamah bin Utsal. Mereka kemudian mengikat laki-laki itu di salah satu tiang masjid. Rasulullah shallallahu 'alaihi wasallam lalu keluar menemuinya dan bersabda: \"Lepaskanlah Tsumamah.\" Tsumamah kemudian masuk ke kebun kurma dekat Masjid untuk mandi. Setelah itu ia kembali masuk ke Masjid dan mengucapkan, \"Aku bersaksi bahwa tidak ada Tuhan yang berhak disembah selian Allah dan Muhammad adalah utusan Allah.\""},"443":{"ar":"حَدَّثَنَا زَكَرِيَّاءُ بْنُ يَحْيَى قَالَ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ نُمَيْرٍ قَالَ حَدَّثَنَا هِشَامٌ عَنْ أَبِيهِ عَنْ عَائِشَةَ قَالَتْأُصِيبَ سَعْدٌ يَوْمَ الْخَنْدَقِ فِي الْأَكْحَلِ فَضَرَبَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ خَيْمَةً فِي الْمَسْجِدِ لِيَعُودَهُ مِنْ قَرِيبٍ فَلَمْ يَرُعْهُمْ وَفِي الْمَسْجِدِ خَيْمَةٌ مِنْ بَنِي غِفَارٍ إِلَّا الدَّمُ يَسِيلُ إِلَيْهِمْ فَقَالُوا يَا أَهْلَ الْخَيْمَةِ مَا هَذَا الَّذِي يَأْتِينَا مِنْ قِبَلِكُمْ فَإِذَا سَعْدٌ يَغْذُو جُرْحُهُ دَمًا فَمَاتَ فِيهَا","id":"Telah menceritakan kepada kami [Zakaria bin Yahya] berkata, telah menceritakan kepada kami ['Abdullah bin Numair] berkata, telah menceritakan kepada kami [Hisyam] dari [Bapaknya] dari ['Aisyah] berkata, \"Pada hari peperangan Khandaq, Sa'd terluka pada bagian lengannya. Nabi shallallahu 'alaihi wasallam kemudian mendirikan tenda untuk menjenguk Sa'd dari dekat, sementara di Masjid banyak juga tenda milik bani ghifar. Kemudian banyak darah yang mengalir ke arah mereka (orang-orang bani Ghifar), maka mereka pun berkata, 'Wahai penghuni tenda! Cairan apa yang mengenai kami ini? Ia muncul dari arah kalian? ' Dan ternyata cairan itu ada darah Sa'd yang keluar sehingga ia pun meninggal.\""},"444":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ يُوسُفَ قَالَ أَخْبَرَنَا مَالِكٌ عَنْ مُحَمَّدِ بْنِ عَبْدِ الرَّحْمَنِ بْنِ نَوْفَلٍ عَنْ عُرْوَةَ بْنِ الزُّبَيْرِ عَنْ زَيْنَبَ بِنْتِ أَبِي سَلَمَةَ عَنْ أُمِّ سَلَمَةَ قَالَتْشَكَوْتُ إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنِّي أَشْتَكِي قَالَ طُوفِي مِنْ وَرَاءِ النَّاسِ وَأَنْتِ رَاكِبَةٌ فَطُفْتُ وَرَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُصَلِّي إِلَى جَنْبِ الْبَيْتِ يَقْرَأُ بْ الطُّورِ وَكِتَابٍ مَسْطُورٍ","id":"Telah menceritakan kepada kami ['Abdullah bin Yusuf] berkata, telah mengabarkan kepada kami [Malik] dari [Muhammad bin 'Abdurrahman bin Naufal] dari ['Urwah bin Az Zubair] dari [Zainab binti Abu Salamah] dari [Ummu Salamah] berkata, \"Aku mengadu kepada Rasulullah shallallahu 'alaihi wasallam bahwa aku mengalami rasa sakit. Beliau kemudian bersabda: \"Thawaflah di belakang orang dengan berkendaraan.\" Maka aku pun melakukan thawaf, sedangkan Rasulullah shallallahu 'alaihi wasallam shalat di sisi Ka'bah dengan membaca: \"WATHTHUUR WA KITAABIM MASTHUUR (Demi bukit, dan Kitab yang ditulis) ' (Qs. Ath Thuur: 1-2)."},"445":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ الْمُثَنَّى قَالَ حَدَّثَنَا مُعَاذُ بْنُ هِشَامٍ قَالَ حَدَّثَنِي أَبِي عَنْ قَتَادَةَ قَالَ حَدَّثَنَا أَنَسُ بْنُ مَالِكٍأَنَّ رَجُلَيْنِ مِنْ أَصْحَابِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ خَرَجَا مِنْ عِنْدِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي لَيْلَةٍ مُظْلِمَةٍ وَمَعَهُمَا مِثْلُ الْمِصْبَاحَيْنِ يُضِيئَانِ بَيْنَ أَيْدِيهِمَا فَلَمَّا افْتَرَقَا صَارَ مَعَ كُلِّ وَاحِدٍ مِنْهُمَا وَاحِدٌ حَتَّى أَتَى أَهْلَهُ","id":"Telah menceritakan kepada kami [Muhammad bin Al Mutsanna] berkata, telah menceritakan kepada kami [Mu'adz bin Hisyam] berkata, telah menceritakan kepadaku [Bapakku] dari [Qatadah] berkata, telah menceritakan kepada kami [Anas bin Malik], bahwa dua orang sahabat Nabi shallallahu 'alaihi wasallam keluar dari kediaman beliau pada malam yang gelap gulita. Dan seakan pada keduanya ada lampu kecil yang menerangi keduanya, ketika keduanya berpisah, masing-masing dari shahabat tersebut diiringi cahaya hingga tiba menemui keluarganya.\""},"446":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ سِنَانٍ قَالَ حَدَّثَنَا فُلَيْحٌ قَالَ حَدَّثَنَا أَبُو النَّضْرِ عَنْ عُبَيْدِ بْنِ حُنَيْنٍ عَنْ بُسْرِ بْنِ سَعِيدٍ عَنْ أَبِي سَعِيدٍ الْخُدْرِيِّ قَالَخَطَبَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ إِنَّ اللَّهَ خَيَّرَ عَبْدًا بَيْنَ الدُّنْيَا وَبَيْنَ مَا عِنْدَهُ فَاخْتَارَ مَا عِنْدَ اللَّهِ فَبَكَى أَبُو بَكْرٍ الصِّدِّيقُ رَضِيَ اللَّهُ عَنْهُ فَقُلْتُ فِي نَفْسِي مَا يُبْكِي هَذَا الشَّيْخَ إِنْ يَكُنْ اللَّهُ خَيَّرَ عَبْدًا بَيْنَ الدُّنْيَا وَبَيْنَ مَا عِنْدَهُ فَاخْتَارَ مَا عِنْدَ اللَّهِ فَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ هُوَ الْعَبْدَ وَكَانَ أَبُو بَكْرٍ أَعْلَمَنَا قَالَ يَا أَبَا بَكْرٍ لَا تَبْكِ إِنَّ أَمَنَّ النَّاسِ عَلَيَّ فِي صُحْبَتِهِ وَمَالِهِ أَبُو بَكْرٍ وَلَوْ كُنْتُ مُتَّخِذًا خَلِيلًا مِنْ أُمَّتِي لَاتَّخَذْتُ أَبَا بَكْرٍ وَلَكِنْ أُخُوَّةُ الْإِسْلَامِ وَمَوَدَّتُهُ لَا يَبْقَيَنَّ فِي الْمَسْجِدِ بَابٌ إِلَّا سُدَّ إِلَّا بَابُ أَبِي بَكْرٍ","id":"Telah menceritakan kepada kami [Muhammad bin Sinan] berkata, telah menceritakan kepada kami [Fulaih] berkata, telah menceritakan kepada kami [Abu Nadlr] dari ['Ubaid bin Hunain] dari [Busr bin Sa'd] dari [Abu Sa'id Al Khudru] berkata, \"Nabi shallallahu 'alaihi wasallam menyampaikan khuthbahnya, \"Sesungguhnya Allah telah menawarkan kepada seorang hamba untuk memilih antara dunia dan apa yang ada di sisi-Nya. Kemudian hamba tersebut memilih apa yang ada di sisi Allah.\" Maka tiba-tiba Abu Bakar Ash Shidiq menangis. Aku berpikir dalam hati, apa yang membuat orang tua ini menangis, hanya karena Allah menawarkan kepada seorang hamba untuk memilih antara dunia dan apa yang ada di sisi-Nya lalu hamba tersebut memilih apa yang ada di sisi Allah?\" Dan ternyata Rasulullah shallallahu 'alaihi wasallam adalah yang dimaksud hamba tersebut. Dan Abu Bakr adalah orang yang paling memahami isyarat itu. Kemudian beliau berkata: \"Wahai Abu Bakar, jangalah kamu menangis. Sesungguhnya manusia yang paling terpercaya di hadapanku dalam persahabatannya dan hartanya adalah Abu Bakar. Seandainya aku boleh mengambil kekasih dari ummatku, tentulah Abu Bakar orangnya. Akan tetapi yang ada adalah persaudaraan Islam dan berkasih sayang dalam Islam. Sungguh, tidak ada satupun pintu di dalam Masjid yang tersisa melainkan akan tertutup kecuali pintunya Abu Bakar.\""},"447":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مُحَمَّدٍ الْجُعْفِيُّ قَالَ حَدَّثَنَا وَهْبُ بْنُ جَرِيرٍ قَالَ حَدَّثَنَا أَبِي قَالَ سَمِعْتُ يَعْلَى بْنَ حَكِيمٍ عَنْ عِكْرِمَةَ عَنْ ابْنِ عَبَّاسٍ قَالَخَرَجَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي مَرَضِهِ الَّذِي مَاتَ فِيهِ عَاصِبٌ رَأْسَهُ بِخِرْقَةٍ فَقَعَدَ عَلَى الْمِنْبَرِ فَحَمِدَ اللَّهَ وَأَثْنَى عَلَيْهِ ثُمَّ قَالَ إِنَّهُ لَيْسَ مِنْ النَّاسِ أَحَدٌ أَمَنَّ عَلَيَّ فِي نَفْسِهِ وَمَالِهِ مِنْ أَبِي بكْرِ بْنِ أَبِي قُحَافَةَ وَلَوْ كُنْتُ مُتَّخِذًا مِنْ النَّاسِ خَلِيلًا لَاتَّخَذْتُ أَبَا بَكْرٍ خَلِيلًا وَلَكِنْ خُلَّةُ الْإِسْلَامِ أَفْضَلُ سُدُّوا عَنِّي كُلَّ خَوْخَةٍ فِي هَذَا الْمَسْجِدِ غَيْرَ خَوْخَةِ أَبِي بَكْرٍ","id":"Telah menceritakan kepada kami ['Abdullah bin Muhammad Al Ju'fi] berkata, telah menceritakan kepada kami [Wahb bin Jarir] berkata, telah menceritakan kepadaku [Bapakku] ia berkata, Aku mendengar [Ya'la bin Hakim] dari ['Ikrimah] dari [Ibnu 'Abbas] berkata, \"Pada suatu hari Rasulullah shallallahu 'alaihi wasallam keluar dalam keadaan sakit yang membawa pada ajalnya. Saat itu kepalanya dibalut dengan kain, beliau lalu naik mimbar dan menucapkan puja dan puji kepada Allah. Kemudian beliau bersabda: \"Sesungguhnya tidak ada seorangpun yang paling amanah dihadapanku, baik pada dirinya maupun hartanya melebihi Abu Bakar bin Abu Qahafah. Seandainya aku boleh mengambil kekasih dari ummatku tentulah aku ambil Abu Bakar sebagai kekasihku. Akan tetapi persaudaraan Islam lebih utama. Tutuplah semua pintu dariku kecuali pintu Abu Bakar.\""},"448":{"ar":"حَدَّثَنَا أَبُو النُّعْمَانِ وَقُتَيْبَةُ بْنُ سَعِيدٍ قَالَا حَدَّثَنَا حَمَّادُ بْنُ زَيْدٍ عَنْ أَيُّوبَ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَدِمَ مَكَّةَ فَدَعَا عُثْمَانَ بْنَ طَلْحَةَ فَفَتَحَ الْبَابَ فَدَخَلَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَبِلَالٌ وَأُسَامَةُ بْنُ زَيْدٍ وَعُثْمَانُ بْنُ طَلْحَةَ ثُمَّ أَغْلَقَ الْبَابَ فَلَبِثَ فِيهِ سَاعَةً ثُمَّ خَرَجُوا قَالَ ابْنُ عُمَرَ فَبَدَرْتُ فَسَأَلْتُ بِلَالًا فَقَالَ صَلَّى فِيهِ فَقُلْتُ فِي أَيٍّ قَالَ بَيْنَ الْأُسْطُوَانَتَيْنِ قَالَ ابْنُ عُمَرَ فَذَهَبَ عَلَيَّ أَنْ أَسْأَلَهُ كَمْ صَلَّى","id":"Telah menceritakan kepada kami [Abu An Nu'man] dan [Qutaibah bin Sa'id] berkata, telah menceritakan kepada kami [Hammad bin Zaid] dari [Ayyub] dari [Nafi'] dari [Ibnu 'Umar] bahwa Nabi shallallahu 'alaihi wasallam mengunjungi Makkah (Ka'bah) seraya memanggil 'Utsman bin Thalhah, 'Utsman bin Thalhah kemudian membuka pintu (Ka'bah) dan Nabi shallallahu 'alaihi wasallam pun masuk diikuti oleh Bilal, Usamah bin Zaid, dan 'Utsman bin Thalhah, lalu pintu ditutup. Beliau berada di dalam sesaat kemudian mereka keluar.\" Ibnu Umar berkata, \"Aku segera menemui Bilal untuk menanyakan sesuatu, [Bilal] pun menjawab, \"Beliau melaksanakan shalat di dalam (Ka'bah).\" Aku bertanya lagi, \"Di sebelah mana?\" Bilal menjawab, \"Di antara dua tiang.\" Ibnu Umar berkata, \"Lalu aku lupa untuk bertanya berapa beliau shalat.\""},"449":{"ar":"حَدَّثَنَا قُتَيْبَةُ قَالَ حَدَّثَنَا اللَّيْثُ عَنْ سَعِيدِ بْنِ أَبِي سَعِيدٍ أَنَّهُ سَمِعَ أَبَا هُرَيْرَةَ يَقُولُبَعَثَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ خَيْلًا قِبَلَ نَجْدٍ فَجَاءَتْ بِرَجُلٍ مِنْ بَنِي حَنِيفَةَ يُقَالُ لَهُ ثُمَامَةُ بْنُ أُثَالٍ فَرَبَطُوهُ بِسَارِيَةٍ مِنْ سَوَارِي الْمَسْجِدِ","id":"Telah menceritakan kepada kami [Qutaibah] berkata, telah menceritakan kepada kami [Al Laits] dari [Sa'id bin Abu Sa'id] bahwa dia mendengar [Abu Hurairah] berkata, \"Nabi shallallahu 'alaihi wasallam pernah mengirim pasukan berkuda mendatangi Najed, kemudian pasukan tersebut kembali dengan membawa tawanan seorang laki-laki dari Bani Hanifah yang bernama Tsumamah bin Utsal. Kemudian laki-laki itu diikat di salah satu tiang masjid.\""},"450":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ عَبْدِ اللَّهِ قَالَ حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ قَالَ حَدَّثَنَا الْجُعَيْدُ بْنُ عَبْدِ الرَّحْمَنِ قَالَ حَدَّثَنِي يَزِيدُ بْنُ خُصَيْفَةَ عَنْ السَّائِبِ بْنِ يَزِيدَ قَالَ كُنْتُ قَائِمًا فِي الْمَسْجِدِ فَحَصَبَنِي رَجُلٌ فَنَظَرْتُ فَإِذَا عُمَرُ بْنُ الْخَطَّابِفَقَالَ اذْهَبْ فَأْتِنِي بِهَذَيْنِ فَجِئْتُهُ بِهِمَا قَالَ مَنْ أَنْتُمَا أَوْ مِنْ أَيْنَ أَنْتُمَا قَالَا مِنْ أَهْلِ الطَّائِفِ قَالَ لَوْ كُنْتُمَا مِنْ أَهْلِ الْبَلَدِ لَأَوْجَعْتُكُمَا تَرْفَعَانِ أَصْوَاتَكُمَا فِي مَسْجِدِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah menceritakan kepada kami ['Ali bin 'Abdullah] berkata, telah menceritakan kepada kami [Yahya bin Sa'id] berkata, telah menceritakan kepada kami [Al Ju'aid bin 'Abdurrahman] berkata, telah menceritakan kepadaku [Yazid bin Khushaifah] dari [As Sa'ib bin Yazid] berkata, \"Ketika aku berdiri di dalam masjid tiba-tiba ada seseorang melempar aku dengan kerikil, dan ternyata setelah aku perhatikan orang itu adalah ' [Umar bin Al Khaththab]. Dia berkata, \"Pergi dan bawalah dua orang ini kepadaku.\" Maka aku datang dengan membawa dua orang yang dimaksud, Umar lalu bertanya, \"Siapa kalian berdua?\" Atau \"Dari mana asalnya kalian berdua?\" Keduanya menjawab, \"Kami berasal dari Tha'if\" 'Umar bin Al Khaththab pun berkata, \"Sekiranya kalian dari penduduk sini maka aku akan hukum kalian berdua! Sebab kalian telah meninggikan suara di Masjid Rasulullah shallallahu 'alaihi wasallam.\""},"451":{"ar":"حَدَّثَنَا أَحْمَدُ قَالَ حَدَّثَنَا ابْنُ وَهْبٍ قَالَ أَخْبَرَنِي يُونُسُ بْنُ يَزِيدَ عَنْ ابْنِ شِهَابٍ حَدَّثَنِي عَبْدُ اللَّهِ بْنُ كَعْبِ بْنِ مَالِكٍ أَنَّ كَعْبَ بْنَ مَالِكٍ أَخْبَرَهُأَنَّهُ تَقَاضَى ابْنَ أَبِي حَدْرَدٍ دَيْنًا لَهُ عَلَيْهِ فِي عَهْدِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي الْمَسْجِدِ فَارْتَفَعَتْ أَصْوَاتُهُمَا حَتَّى سَمِعَهَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَهُوَ فِي بَيْتِهِ فَخَرَجَ إِلَيْهِمَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حَتَّى كَشَفَ سِجْفَ حُجْرَتِهِ وَنَادَى كَعْبَ بْنَ مَالِكٍ قَالَ يَا كَعْبُ قَالَ لَبَّيْكَ يَا رَسُولَ اللَّهِ فَأَشَارَ بِيَدِهِ أَنْ ضَعْ الشَّطْرَ مِنْ دَيْنِكَ قَالَ كَعْبٌ قَدْ فَعَلْتُ يَا رَسُولَ اللَّهِ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قُمْ فَاقْضِهِ","id":"Telah menceritakan kepada kami [Ahmad] berkata, telah menceritakan kepada kami [Ibnu Wahb] berkata, telah mengabarkan kepadaku [Yunus bin Yazid] dari [Ibnu Syihab] telah menceritakan kepadaku ['Abdullah bin Ka'b bin Malik] bahwa [Ka'b bin Malik] mengabarkan kepadanya, bahwa ia menagih hutang kepada Ibnu Abu Hadrad pada masa Rasulullah shallallahu 'alaihi wasallam dalam masjid hingga suara keduanya meninggi dan didengar oleh Rasulullah shallallahu 'alaihi wasallam yang sedang berada di rumah. Maka Rasulullah shallallahu 'alaihi wasallam kemudian keluar menemui keduanya sambil menyingkap kain gorden kamar. Beliau memanggil Ka'b bin Malik: \"Wahai Ka'b!\" Ka'b bin Malik menjawab, \"Wahai Rasulullah, aku penuhi panggilanmu.\" Beliau memberi isyarat dengan tangannya agar ia membebaskan setengah dari hutangnya. Ka'b bin Malik berkata, \"Wahai Rasulullah, aku sudah lakukan.\" Rasulullah shallallahu 'alaihi wasallam kemudian bersabda: \"Sekarang bayarlah.\""},"452":{"ar":"حَدَّثَنَا مُسَدَّدٌ قَالَ حَدَّثَنَا بِشْرُ بْنُ الْمُفَضَّلِ حَدَّثَنَا عُبَيْدُ اللَّهِ عَنْ نَافِعٍ عَنْ عَبْدِ اللَّهِ بْنِ عُمَرَ قَالَسَأَلَ رَجُلٌ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَهُوَ عَلَى الْمِنْبَرِ مَا تَرَى فِي صَلَاةِ اللَّيْلِ قَالَ مَثْنَى مَثْنَى فَإِذَا خَشِيَ الصُّبْحَ صَلَّى وَاحِدَةً فَأَوْتَرَتْ لَهُ مَا صَلَّى وَإِنَّهُ كَانَ يَقُولُ اجْعَلُوا آخِرَ صَلَاتِكُمْ وِتْرًا فَإِنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَمَرَ بِهِ","id":"Telah menceritakan kepada kami [Musaddad] berkata, telah menceritakan kepada kami [Bisyr bin Al Mufadldlal] telah menceritakan kepada kami ['Ubaidullah] dari [Nafi'] dari ['Abdullah bin 'Umar] berkata, \"Seorang laki-laki bertanya kepada Nabi shallallahu 'alaihi wasallam yang pada saat itu sedang di atas mimbar, \"Bagaimana cara shalat malam?\" Beliau menjawab: \"Dua rakaat dua rakaat. Apabila dikhawatirkan masuk shubuh, maka shalatlah satu rakaat sebagai witir (penutup) bagi shalatnya sebelumnya.\" Ibnu 'Umar berkata, \"Jadikanlah witir sebagai shalat terakhir kalian, karena Nabi shallallahu 'alaihi wasallam memerintahkan hal yang demikian.\""},"453":{"ar":"حَدَّثَنَا أَبُو النُّعْمَانِ قَالَ حَدَّثَنَا حَمَّادُ بْنُ زَيْدٍ عَنْ أَيُّوبَ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَأَنَّ رَجُلًا جَاءَ إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَهُوَ يَخْطُبُ فَقَالَ كَيْفَ صَلَاةُ اللَّيْلِ فَقَالَ مَثْنَى مَثْنَى فَإِذَا خَشِيتَ الصُّبْحَ فَأَوْتِرْ بِوَاحِدَةٍ تُوتِرُ لَكَ مَا قَدْ صَلَّيْتَقَالَ الْوَلِيدُ بْنُ كَثِيرٍ حَدَّثَنِي عُبَيْدُ اللَّهِ بْنُ عَبْدِ اللَّهِ أَنَّ ابْنَ عُمَرَ حَدَّثَهُمْ أَنَّ رَجُلًا نَادَى النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَهُوَ فِي الْمَسْجِدِ","id":"Telah menceritakan kepada kami [Abu An Nu'man] berkata, telah menceritakan kepada kami [Hammad bin Zaid] dari [Ayyub] dari [Nafi'] dari [Ibnu 'Umar] berkata, \"Seorang laki-laki datang kepada Nabi shallallahu 'alaihi wasallam saat beliau sedang berkhuthbah. Katanya, \"Bagaimana cara shalat malam?\" Beliau menjawab: \"Dua rakaat dua rakaat. Apabila dikhawatirkan masuk subuh, maka shalatlah satu rakaat sebagai witir (penutup) bagi shalat yang telah kamu laksanakan sebelumnya.\" [Al Walid bin Katsir] berkata, telah menceritakan kepadaku ['Ubaidullah bin 'Abdullah] bahwa [Ibnu 'Umar] menceritakan kepada mereka, bahwa ada seseorang yang memanggil Nabi shallallahu 'alaihi wasallam saat beliau berada di masjid.\""},"454":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ يُوسُفَ قَالَ أَخْبَرَنَا مَالِكٌ عَنْ إِسْحَاقَ بْنِ عَبْدِ اللَّهِ بْنِ أَبِي طَلْحَةَ أَنَّ أَبَا مُرَّةَ مَوْلَى عَقِيلِ بْنِ أَبِي طَالِبٍ أَخْبَرَهُ عَنْ أَبِي وَاقِدٍ اللَّيْثِيِّ قَالَبَيْنَمَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي الْمَسْجِدِ فَأَقْبَلَ ثَلَاثَةُ نَفَرٍ فَأَقْبَلَ اثْنَانِ إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَذَهَبَ وَاحِدٌ فَأَمَّا أَحَدُهُمَا فَرَأَى فُرْجَةً فِي الْحَلْقَةِ فَجَلَسَ وَأَمَّا الْآخَرُ فَجَلَسَ خَلْفَهُمْ فَلَمَّا فَرَغَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ أَلَا أُخْبِرُكُمْ عَنْ النَّفَرِ الثَّلَاثَةِ أَمَّا أَحَدُهُمْ فَأَوَى إِلَى اللَّهِ فَآوَاهُ اللَّهُ وَأَمَّا الْآخَرُ فَاسْتَحْيَا فَاسْتَحْيَا اللَّهُ مِنْهُ وَأَمَّا الْآخَرُ فَأَعْرَضَ فَأَعْرَضَ اللَّهُ عَنْهُ","id":"Telah menceritakan kepada kami ['Abdullah bin Yusuf] berkata, telah mengabarkan kepada kami [Malik] dari [Ishaq bin 'Abdullah bin Abu Thalhah] bahwa [Abu Murrah] mantan budak 'Uqail bin Abu Thalib mengabarkan kepadanya dari [Abu Waqid Al Laitsi] berkata, \"Ketika Rasulullah shallallahu 'alaihi wasallam berada di masjid, maka datanglah tiga orang laki-laki. Dua orang menghadap Nabi shallallahu 'alaihi wasallam dan seorang lagi pergi. Satu di antara dua orang ini nampak berbahagia bermajelis bersama Nabi shallallahu 'alaihi wasallam sedang yang satu lagi duduk di belakang mereka. Setelah Rasulullah shallallahu 'alaihi wasallam selesai (menyampaikan pengajaran) beliau bersabda: \"Maukah kalian aku beritahu tentang ketiga orang tadi? Adapun seorang di antara mereka, dia meminta perlindungan kepada Allah maka Allah lindungi dia. Yang kedua, dia malu kepada Allah maka Allah pun malu kepadanya. Sedangkan yang ketiga berpaling dari Allah maka Allah pun berpaling darinya.\""},"455":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مَسْلَمَةَ عَنْ مَالِكٍ عَنْ ابْنِ شِهَابٍ عَنْ عَبَّادِ بْنِ تَمِيمٍ عَنْ عَمِّهِأَنَّهُ رَأَى رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مُسْتَلْقِيًا فِي الْمَسْجِدِ وَاضِعًا إِحْدَى رِجْلَيْهِ عَلَى الْأُخْرَىوَعَنْ ابْنِ شِهَابٍ عَنْ سَعِيدِ بْنِ الْمُسَيَّبِ قَالَ كَانَ عُمَرُ وَعُثْمَانُ يَفْعَلَانِ ذَلِكَ","id":"Telah menceritakan kepada kami ['Abdullah bin Maslamah] dari [Malik] dari [Ibnu Syihab] dari ['Abbad bin Tamim] dari [Pamannya] bahwa dia melihat Rasulullah shallallahu 'alaihi wasallam berbaring di dalam masjid dengan meletakkan satu kakinya di atas kaki yang lain.\" Dan dari Ibnu Syihab dari Sa'id bin Al Musayyab berkata, \"'Umar dan 'Utsman juga melakukan hal serupa.\""},"456":{"ar":"حَدَّثَنَا يَحْيَى بْنُ بُكَيْرٍ قَالَ حَدَّثَنَا اللَّيْثُ عَنْ عُقَيْلٍ عَنْ ابْنِ شِهَابٍ قَالَ أَخْبَرَنِي عُرْوَةُ بْنُ الزُّبَيْرِ أَنَّ عَائِشَةَ زَوْجَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَتْلَمْ أَعْقِلْ أَبَوَيَّ إِلَّا وَهُمَا يَدِينَانِ الدِّينَ وَلَمْ يَمُرَّ عَلَيْنَا يَوْمٌ إِلَّا يَأْتِينَا فِيهِ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ طَرَفَيْ النَّهَارِ بُكْرَةً وَعَشِيَّةً ثُمَّ بَدَا لِأَبِي بَكْرٍ فَابْتَنَى مَسْجِدًا بِفِنَاءِ دَارِهِ فَكَانَ يُصَلِّي فِيهِ وَيَقْرَأُ الْقُرْآنَ فَيَقِفُ عَلَيْهِ نِسَاءُ الْمُشْرِكِينَ وَأَبْنَاؤُهُمْ يَعْجَبُونَ مِنْهُ وَيَنْظُرُونَ إِلَيْهِ وَكَانَ أَبُو بَكْرٍ رَجُلًا بَكَّاءً لَا يَمْلِكُ عَيْنَيْهِ إِذَا قَرَأَ الْقُرْآنَ فَأَفْزَعَ ذَلِكَ أَشْرَافَ قُرَيْشٍ مِنْ الْمُشْرِكِينَ","id":"Telah menceritakan kepada kami [Yahya bin Bukair] berkata, telah menceritakan kepada kami [Al Laits] dari ['Uqail] dari [Ibnu Syihab] berkata, telah mengabarkan kepadaku ['Urwah bin Az Zubair] bahwa ['Aisyah] isteri Nabi shallallahu 'alaihi wasallam berkata, \"Aku belum mengerti kedua orang tuaku kecuali saat keduanya telah memeluk agama ini. Dan tidak berlalu suatu haripun dalam kehidupan kami kecuali Rasulullah shallallahu 'alaihi wasallam datang menemui kami di penghujung hari, baik pada saat paginya maupun sore. Aku ingat saat nampak keIslaman Abu Bakar, ketika dia di masjid dan shalat di sana dengan membaca Al Qur'an. Maka wanita-wanita dan anak-anak Musyrik memperhatikan dia dengan penuh keheranan. Sementara Abu Bakar adalah seseorang yang sangat mudah menangis, yang tidak bisa menguasai air matanya apabila dia membaca Al Qur'an. Dan kejadian itu telah menggemparkankan para pembesar Musyrikin Quraisy.\""},"457":{"ar":"حَدَّثَنَا مُسَدَّدٌ قَالَ حَدَّثَنَا أَبُو مُعَاوِيَةَ عَنْ الْأَعْمَشِ عَنْ أَبِي صَالِحٍ عَنْ أَبِي هُرَيْرَةَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ صَلَاةُ الْجَمِيعِ تَزِيدُ عَلَى صَلَاتِهِ فِي بَيْتِهِ وَصَلَاتِهِ فِي سُوقِهِ خَمْسًا وَعِشْرِينَ دَرَجَةً فَإِنَّ أَحَدَكُمْ إِذَا تَوَضَّأَ فَأَحْسَنَ وَأَتَى الْمَسْجِدَ لَا يُرِيدُ إِل��َا الصَّلَاةَ لَمْ يَخْطُ خَطْوَةً إِلَّا رَفَعَهُ اللَّهُ بِهَا دَرَجَةً وَحَطَّ عَنْهُ خَطِيئَةً حَتَّى يَدْخُلَ الْمَسْجِدَ وَإِذَا دَخَلَ الْمَسْجِدَ كَانَ فِي صَلَاةٍ مَا كَانَتْ تَحْبِسُهُ وَتُصَلِّي يَعْنِي عَلَيْهِ الْمَلَائِكَةُ مَا دَامَ فِي مَجْلِسِهِ الَّذِي يُصَلِّي فِيهِ اللَّهُمَّ اغْفِرْ لَهُ اللَّهُمَّ ارْحَمْهُ مَا لَمْ يُحْدِثْ فِيهِ","id":"Telah menceritakan kepada kami [Musaddad] berkata, telah menceritakan kepada kami [Abu Mu'awanah] dari [Al A'masy] dari [Abu Shalih] dari [Abu Hurairah] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Shalat berjama'ah lebih utama dari shalatnya sendirian di rumah atau di pasarnya sebanyak dua puluh lima derajat. Jika salah seorang dari kalian berwudlu lalu membaguskan wudlunya kemudian mendatangi masjid dengan tidak ada tujuan lain kecuali shalat, maka tidak ada langkah yang dilakukannya kecuali Allah akan mengangkatnya dengan langkah itu setinggi satu derajat, dan mengahapus darinya satu kesalahan hingga dia memasuki masjid. Dan jika dia telah memasuki masjid, maka dia akan dihitung dalam keadaan shalat selagi dia meniatkannya, dan para malaikat akan mendoakannya selama dia masih berada di tempat yang ia gunakan untuk shalat, 'Ya Allah ampunkanlah dia. Ya Allah rahmatilah dia'. Selama dia belum berhadats.\""},"458":{"ar":"حَدَّثَنَا حَامِدُ بْنُ عُمَرَ عَنْ بِشْرٍ حَدَّثَنَا عَاصِمٌ حَدَّثَنَا وَاقِدٌ عَنْ أَبِيهِ عَنْ ابْنِ عُمَرَ أَوْ ابْنِ عَمْرٍوشَبَكَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَصَابِعَهُوَقَالَ عَاصِمُ بْنُ عَلِيٍّ حَدَّثَنَا عَاصِمُ بْنُ مُحَمَّدٍ سَمِعْتُ هَذَا الْحَدِيثَ مِنْ أَبِي فَلَمْ أَحْفَظْهُ فَقَوَّمَهُ لِي وَاقِدٌ عَنْ أَبِيهِ قَالَ سَمِعْتُ أَبِي وَهُوَ يَقُولُ قَالَ عَبْدُ اللَّهِ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَا عَبْدَ اللَّهِ بْنَ عَمْرٍو كَيْفَ بِكَ إِذَا بَقِيتَ فِي حُثَالَةٍ مِنْ النَّاسِ بِهَذَا","id":"Telah menceritakan kepada kami [Hamid bin 'Umar] dari [Bisyr] telah menceritakan kepada kami ['Ashim] telah menceritakan kepada kami [Waqid] dari [Bapaknya] dari [Ibnu 'Umar] atau [Ibnu 'Amru], bahwa Nabi shallallahu 'alaihi wasallam menganyam jemarinya.\" [Ashim bin 'Ali] berkata, telah menceritakan kepada kami ['Ashim bin Muhammad] berkata, aku mendengar hadits ini dari bapakku, tapi aku tidak hafal. Lalu [Waqid] mengingatkan aku dari [Bapaknya] ia berkata; aku mendengar [Bapakku] ia berkata; ['Abdullah] berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Wahai 'Abdullah bin 'Amru, mengapa jika kamu bersama orang-orang lemah itu kamu berbuat begini?\""},"459":{"ar":"حَدَّثَنَا خَلَّادُ بْنُ يَحْيَى قَالَ حَدَّثَنَا سُفْيَانُ عَنْ أَبِي بُرْدَةَ بْنِ عَبْدِ اللَّهِ بْنِ أَبِي بُرْدَةَ عَنْ جَدِّهِ عَنْ أَبِي مُوسَىعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِنَّ الْمُؤْمِنَ لِلْمُؤْمِنِ كَالْبُنْيَانِ يَشُدُّ بَعْضُهُ بَعْضًا وَشَبَّكَ أَصَابِعَهُ","id":"Telah menceritakan kepada kami [Khallad bin Yahya] berkata, telah menceritakan kepada kami [Sufyan] dari [Abu Burdah bin 'Abdullah bin Abu Burdah] dari [Kakeknya] dari [Abu Musa] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Sesungguhnya seorang mukmin dengan mukmin lainnya seperti satu bangunan yang saling menguatkan satu sama lain.\" kemudian beliau menganyam jari jemarinya.\""},"460":{"ar":"حَدَّثَنَا إِسْحَاقُ قَالَ حَدَّثَنَا النَّضْرُ بْنُ شُمَيْلٍ أَخْبَرَنَا ابْنُ عَوْنٍ عَنْ ابْنِ سِيرِينَ عَنْ أَبِي هُرَيْرَةَ قَالَصَلَّى بِنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِحْدَى صَلَاتَيْ الْعَشِيِّ قَالَ ابْنُ سِيرِينَ سَمَّاهَا أَبُو هُرَيْرَةَ وَلَكِنْ نَسِيتُ أَنَا قَالَ فَصَلَّى بِنَا رَكْعَتَيْنِ ثُمَّ سَلَّمَ فَقَامَ إِلَى خَشَبَةٍ مَعْرُوضَةٍ فِي الْمَسْجِدِ فَاتَّكَأَ عَلَيْهَا كَأَنَّه غَضْبَانُ وَوَضَعَ يَدَهُ الْيُمْنَى عَلَى الْيُسْرَى وَشَبَّكَ بَيْنَ أَصَابِعِهِ وَوَضَعَ خَدَّهُ الْأَيْمَنَ عَلَى ظَهْرِ كَفِّهِ الْيُسْرَى وَخَرَجَتْ السَّرَعَانُ مِنْ أَبْوَابِ الْمَسْجِدِ فَقَالُوا قَصُرَتْ الصَّلَاةُ وَفِي الْقَوْمِ أَبُو بَكْرٍ وَعُمَرُ فَهَابَا أَنْ يُكَلِّمَاهُ وَفِي الْقَوْمِ رَجُلٌ فِي يَدَيْهِ طُولٌ يُقَالُ لَهُ ذُو الْيَدَيْنِ قَالَ يَا رَسُولَ اللَّهِ أَنَسِيتَ أَمْ قَصُرَتْ الصَّلَاةُ قَالَ لَمْ أَنْسَ وَلَمْ تُقْصَرْ فَقَالَ أَكَمَا يَقُولُ ذُو الْيَدَيْنِ فَقَالُوا نَعَمْ فَتَقَدَّمَ فَصَلَّى مَا تَرَكَ ثُمَّ سَلَّمَ ثُمَّ كَبَّرَ وَسَجَدَ مِثْلَ سُجُودِهِ أَوْ أَطْوَلَ ثُمَّ رَفَعَ رَأْسَهُ وَكَبَّرَ ثُمَّ كَبَّرَ وَسَجَدَ مِثْلَ سُجُودِهِ أَوْ أَطْوَلَ ثُمَّ رَفَعَ رَأْسَهُ وَكَبَّرَ فَرُبَّمَا سَأَلُوهُ ثُمَّ سَلَّمَ فَيَقُولُ نُبِّئْتُ أَنَّ عِمْرَانَ بْنَ حُصَيْنٍ قَالَ ثُمَّ سَلَّمَ","id":"Telah menceritakan kepada kami [Ishaq] berkata, telah menceritakan kepada kami [An Nadlr bin Syumail] telah mengabarkan kepada kami [Ibnu 'Aun] dari [Ibnu Sirin] dari [Abu Hurairah] berkata, \"Rasulullah bersama kami melaksanakan salah satu dari shalat yang berada di waktu malam.\" Ibnu Sirin berkata, \"Abu Hurairah menyebutkan menyebutkan (nama) shalat tersebut, tetapi aku lupa.\" Abu Hurairah mengatakan, \"Beliau shalat bersama kami dua rakaat kemudian salam, kemudian beliau mendatangi kayu yang tergeletak di masjid. Beliau lalu berbaring pada kayu tersebut seolah sedang marah dengan meletakkan lengan kanannya di atas lengan kirinya serta menganyam jari jemarinya, sedangkan pipi kanannya diletakkan pada punggung telapak tangan kiri. Kemudian beliau keluar dari pintu masjid dengan cepat. Orang-orang pun berkata, \"Apakah shalat telah diqashar (diringkas)?\" Padahal ditengah-tengah orang banyak tersebut ada Abu Bakar dan 'Umar, dan keduanya enggan membicarakannya. Sementara di tengah kerumunan tersebut ada seseorang yang tangannya panjang dan dipanggil dengan nama Dzul Yadain, dia berkata, \"Wahai Rasulullah, apakah Tuan lupa atau shalat diqashar?\" Beliau menjawab: \"Aku tidak lupa dan shalat juga tidak diqashar.\" Beliau bertanya: \"Apakah benar yang dikatakan Dzul Yadain?\" Orang-orang menjawab, \"Benar.\" Beliau kemudian maju ke depan dan mengerjakan shalat yang tertinggal kemudian salam. Setelah itu beliau takbir dan sujud seperti sujudnya yang dilakukannya atau lebih lama lagi. Kemudian beliau mengangkat kepalanya dan takbir, kemudian takbir dan sujud seperti sujudnya atau lebih lama lagi, kemudian mengangkat kepalanya dan takbir.\" Bisa jadi orang-orang bertanya kepadanya (Ibnu Sirin), apakah dalam hadits ada lafadz 'Kemudian beliau salam' lalu ia berkata; aku mendapat berita bahwa Imran bin Hushain berkata; kemudian beliau salam'.\""},"461":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ أَبِي بَكْرٍ الْمُقَدَّمِيُّ قَالَ حَدَّثَنَا فُضَيْلُ بْنُ سُلَيْمَانَ قَالَ حَدَّثَنَا مُوسَى بْنُ عُقْبَةَ قَالَ رَأَيْتُ سَالِمَ بْنَ عَبْدِ اللَّهِ يَتَحَرَّى أَمَاكِنَ مِنْ الطَّرِيقِ فَيُصَلِّي فِيهَا وَيُحَدِّثُ أَنَّ أَبَاهُكَانَ يُصَلِّي فِيهَا وَأَنَّهُ رَأَى النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُصَلِّي فِي تِلْكَ الْأَمْكِنَةِوَحَدَّثَنِي نَافِعٌ عَنْ ابْنِ عُمَرَ أَنَّهُ كَانَ يُصَلِّي فِي تِلْكَ الْأَمْكِنَةِ وَسَأَلْتُ سَالِمًا فَلَا أَعْلَمُهُ إِلَّا وَافَقَ نَافِعًا فِي الْأَمْكِنَةِ كُلِّهَا إِلَّا أَنَّهُمَا اخْتَلَفَا فِي مَسْجِدٍ بِشَرَفِ الرَّوْحَاءِ","id":"Telah menceritakan kepada kami [Muhammad bin Abu Bakar Al Muqaddam] berkata, telah menceritakan kepada kami [Fudlail bin Sulaiman] berkata, telah menceritakan kepada kami [Musa bin 'Uqbah] berkata, \"Aku melihat [Salim bin 'Abdullah] memilih tempat di suatu jalan lalu melaksanakan shalat di tempat tersebut. Dan dia menceritakan bahwa [Bapaknya] pernah shalat di tempat itu, dan bapaknya pernah melihat Nabi shallallahu 'alaihi wasallam juga shalat di tempat itu.\" Telah menceritakan kepadaku [Nafi'] dari [Ibnu 'Umar] bahwa dia pernah shalat di tempat itu, dan aku bertanya kepada Salim, dan aku juga tidak mengetahuinya kecuali dia sepakat dengan Nafi' tentang tempat yang dimaksud. Namun keduanya berbeda pendapat tentang masjid yang berada di Syarfil Rawha'.\""},"462":{"ar":"حَدَّثَنَا إِبْرَاهِيمُ بْنُ الْمُنْذِرِ الْحِزَامِيُّ قَالَ حَدَّثَنَا أَنَسُ بْنُ عِيَاضٍ قَالَ حَدَّثَنَا مُوسَى بْنُ عُقْبَةَ عَنْ نَافِعٍ أَنَّ عَبْدَ اللَّهِ بْنَ عُمَرَ أَخْبَرَهُأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يَنْزِلُ بِذِي الْحُلَيْفَةِ حِينَ يَعْتَمِرُ وَفِي حَجَّتِهِ حِينَ حَجَّ تَحْتَ سَمُرَةٍ فِي مَوْضِعِ الْمَسْجِدِ الَّذِي بِذِي الْحُلَيْفَةِ وَكَانَ إِذَا رَجَعَ مِنْ غَزْوٍ كَانَ فِي تِلْكَ الطَّرِيقِ أَوْ حَجٍّ أَوْ عُمْرَةٍ هَبَطَ مِنْ بَطْنِ وَادٍ فَإِذَا ظَهَرَ مِنْ بَطْنِ وَادٍ أَنَاخَ بِالْبَطْحَاءِ الَّتِي عَلَى شَفِيرِ الْوَادِي الشَّرْقِيَّةِ فَعَرَّسَ ثَمَّ حَتَّى يُصْبِحَ لَيْسَ عِنْدَ الْمَسْجِدِ الَّذِي بِحِجَارَةٍ وَلَا عَلَى الْأَكَمَةِ الَّتِي عَلَيْهَا الْمَسْجِدُ كَانَ ثَمَّ خَلِيجٌ يُصَلِّي عَبْدُ اللَّهِ عِنْدَهُ فِي بَطْنِهِ كُثُبٌ كَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ثَمَّ يُصَلِّي فَدَحَا السَّيْلُ فِيهِ بِالْبَطْحَاءِ حَتَّى دَفَنَ ذَلِكَ الْمَكَانَ الَّذِي كَانَ عَبْدُ اللَّهِ يُصَلِّي فِيهِ وَأَنَّ عَبْدَ اللَّهِ بْنَ عُمَرَ حَدَّثَهُ أَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ صَلَّى حَيْثُ الْمَسْجِدُ الصَّغِيرُ الَّذِي دُونَ الْمَسْجِدِ الَّذِي بِشَرَفِ الرَّوْحَاءِ وَقَدْ كَانَ عَبْدُ اللَّهِ يَعْلَمُ الْمَكَانَ الَّذِي كَانَ صَلَّى فِيهِ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ ثَمَّ عَنْ يَمِينِكَ حِينَ تَقُومُ فِي الْمَسْجِدِ تُصَلِّي وَذَلِكَ الْمَسْجِدُ عَلَى حَافَةِ الطَّرِيقِ الْيُمْنَى وَأَنْتَ ذَاهِبٌ إِلَى مَكَّةَ بَيْنَهُ وَبَيْنَ الْمَسْجِدِ الْأَكْبَرِ رَمْيَةٌ بِحَجَرٍ أَوْ نَحْوُ ذَلِكَ وَأَنَّ ابْنَ عُمَرَ كَانَ يُصَلِّي إِلَى الْعِرْقِ الَّذِي عِنْدَ مُنْصَرَفِ الرَّوْحَاءِ وَذَلِكَ الْعِرْقُ انْتِهَاءُ طَرَفِهِ عَلَى حَافَةِ الطَّرِيقِ دُونَ الْمَسْجِدِ الَّذِي بَيْنَهُ وَبَيْنَ الْمُنْصَرَفِ وَأَنْتَ ذَاهِبٌ إِلَى مَكَّةَ وَقَدْ ابْتُنِيَ ثَمَّ مَسْجِدٌ فَلَمْ يَكُنْ عَبْدُ اللَّهِ بْنُ عُمَرَ يُصَلِّي فِي ذَلِكَ الْمَسْجِدِ كَانَ يَتْرُكُهُ عَنْ يَسَارِهِ وَوَرَاءَهُ وَيُصَلِّي أَمَامَهُ إِلَى الْعِرْقِ نَفْسِهِ وَكَانَ عَبْدُ اللَّهِ يَرُوحُ مِنْ الرَّوْحَاءِ فَلَا يُصَلِّي الظُّهْرَ حَتَّى يَأْتِيَ ذَلِكَ الْمَكَانَ فَيُصَلِّي فِيهِ الظُّهْرَ وَإِذَا أَقْبَلَ مِنْ مَكَّةَ فَإِنْ مَرَّ بِهِ قَبْلَ الصُّبْحِ بِسَاعَةٍ أَوْ مِنْ آخِرِ السَّحَرِ عَرَّسَ حَتَّى يُصَلِّيَ بِهَا الصُّبْحَ وَأَنَّ عَبْدَ اللَّهِ حَدَّثَهُ أَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يَنْزِلُ تَحْتَ سَرْحَةٍ ضَخْمَةٍ دُونَ الرُّوَيْثَةِ عَنْ يَمِينِ الطَّرِيقِ وَوِجَاهَ الطَّرِيقِ فِي مَكَانٍ بَطْحٍ سَهْلٍ حَتَّى يُفْضِيَ مِنْ أَكَمَةٍ دُوَيْنَ بَرِيدِ الرُّوَيْثَةِ بِمِيلَيْنِ وَقَدْ انْكَسَرَ أَعْلَاهَا فَانْثَنَى فِي جَوْفِهَا وَهِيَ قَائِمَةٌ عَلَى سَاقٍ وَفِي سَاقِهَا كُثُبٌ كَثِيرَةٌ وَأَنَّ عَبْدَ اللَّهِ بْنَ عُمَرَ حَدَّثَهُ أَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ صَلَّى فِي طَرَفِ تَلْعَةٍ مِنْ وَرَاءِ الْعَرْجِ وَأَنْتَ ذَاهِبٌ إِلَى هَضْبَةٍ عِنْدَ ذَلِكَ الْمَسْجِدِ قَبْرَانِ أَوْ ثَلَاثَةٌ عَلَى الْقُبُورِ رَضَمٌ مِنْ حِجَارَةٍ عَنْ يَمِينِ الطَّرِيقِ عِنْدَ سَلَمَاتِ الطَّرِيقِ بَيْنَ أُولَئِكَ السَّلَمَاتِ كَانَ عَبْدُ اللَّهِ يَرُوحُ مِنْ الْعَرْجِ بَعْدَ أَنْ تَمِيلَ الشَّمْسُ بِال��هَاجِرَةِ فَيُصَلِّي الظُّهْرَ فِي ذَلِكَ الْمَسْجِدِ وَأَنَّ عَبْدَ اللَّهِ بْنَ عُمَرَ حَدَّثَهُ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَزَلَ عِنْدَ سَرَحَاتٍ عَنْ يَسَارِ الطَّرِيقِ فِي مَسِيلٍ دُونَ هَرْشَى ذَلِكَ الْمَسِيلُ لَاصِقٌ بِكُرَاعِ هَرْشَى بَيْنَهُ وَبَيْنَ الطَّرِيقِ قَرِيبٌ مِنْ غَلْوَةٍ وَكَانَ عَبْدُ اللَّهِ يُصَلِّي إِلَى سَرْحَةٍ هِيَ أَقْرَبُ السَّرَحَاتِ إِلَى الطَّرِيقِ وَهِيَ أَطْوَلُهُنَّ وَأَنَّ عَبْدَ اللَّهِ بْنَ عُمَرَ حَدَّثَهُ أَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يَنْزِلُ فِي الْمَسِيلِ الَّذِي فِي أَدْنَى مَرِّ الظَّهْرَانِ قِبَلَ الْمَدِينَةِ حِينَ يَهْبِطُ مِنْ الصَّفْرَاوَاتِ يَنْزِلُ فِي بَطْنِ ذَلِكَ الْمَسِيلِ عَنْ يَسَارِ الطَّرِيقِ وَأَنْتَ ذَاهِبٌ إِلَى مَكَّةَ لَيْسَ بَيْنَ مَنْزِلِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَبَيْنَ الطَّرِيقِ إِلَّا رَمْيَةٌ بِحَجَرٍ وَأَنَّ عَبْدَ اللَّهِ بْنَ عُمَرَ حَدَّثَهُ أَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يَنْزِلُ بِذِي طُوًى وَيَبِيتُ حَتَّى يُصْبِحَ يُصَلِّي الصُّبْحَ حِينَ يَقْدَمُ مَكَّةَ وَمُصَلَّى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ذَلِكَ عَلَى أَكَمَةٍ غَلِيظَةٍ لَيْسَ فِي الْمَسْجِدِ الَّذِي بُنِيَ ثَمَّ وَلَكِنْ أَسْفَلَ مِنْ ذَلِكَ عَلَى أَكَمَةٍ غَلِيظَةٍ وَأَنَّ عَبْدَ اللَّهِ بْنَ عُمَرَ حَدَّثَهُ أَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ اسْتَقْبَلَ فُرْضَتَيْ الْجَبَلِ الَّذِي بَيْنَهُ وَبَيْنَ الْجَبَلِ الطَّوِيلِ نَحْوَ الْكَعْبَةِ فَجَعَلَ الْمَسْجِدَ الَّذِي بُنِيَ ثَمَّ يَسَارَ الْمَسْجِدِ بِطَرَفِ الْأَكَمَةِ وَمُصَلَّى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَسْفَلَ مِنْهُ عَلَى الْأَكَمَةِ السَّوْدَاءِ تَدَعُ مِنْ الْأَكَمَةِ عَشَرَةَ أَذْرُعٍ أَوْ نَحْوَهَا ثُمَّ تُصَلِّي مُسْتَقْبِلَ الْفُرْضَتَيْنِ مِنْ الْجَبَلِ الَّذِي بَيْنَكَ وَبَيْنَ الْكَعْبَةِ","id":"Telah menceritakan kepada kami [Ibrahim bin Al Mundzir Al Hizami] berkata, telah menceritakan kepada kami [Anas bin 'Iyadl] berkata, telah menceritakan kepada kami [Musa bin 'Uqbah] dari [Nafi'] bahwa ['Abdullah bin 'Umar] mengabarkan kepadanya, bahwa Rasulullah shallallahu 'alaihi wasallam berhenti di Dzul Hulaifah di bawah pohon samurah ketika melaksanakan 'Umrah dan hajinya, yaitu tempat yang sekarang digunakan sebagai masjid di daerah Dzul Hulaifah. Ketika beliau kembali dari suatu peperangan, atau haji, atau umrah, dan melewati jalan tersebut beliau turun melalu dasar lembah, dan ketika telah sampai di dasar lembah beliau singgah di Bathha' (saluran tempat mengalirnya air) yang terletak di tebing sebelah timur dari lembah tersebut. Di situ beliau bermalam dan beristirahat sampai pagi. Beliau tidak singgah di masjid yang berbatu dan tidak juga di bukit yang ada masjidnya. Di lembah itu terdapat celah yang pernah digunakan oleh 'Abdullah untuk melekasanakan shalat. Di dasar lembah tersebut ada gundukan pasir dimana Rasulullah shallallahu 'alaihi wasallam pernah shalat di situ. Suatu hari aliran air di Bathha' menyeret gundukan pasir tersebut sehingga menutup celah yang pernah digunakan oleh 'Abdullah untuk shalat. 'Abdullah bin 'Umar menceritakan kepadanya (Nafi') bahwa Nabi shallallahu 'alaihi wasallam pernah melaksanakan shalat di masjid kecil, bukan masjid yang terdapat di Syarful Rauha'. 'Abdullah mengetahui tempat yang pernah digunakan oleh Nabi shallallahu 'alaihi wasallam untuk shalat. Ia berkata, \"Disana, di sebelah kanan jika kamu berdiri shalat di masjid itu. Masjid itu terletak di sebelah kanan jalan jika kamu berjalan menuju ke arah Makkah. Jarak masjid tersebut dengan masjid besar sejauh lemparan batu atau kurang lebihnya sekitar itu.\" A'abdullah bin 'Umar juga pernah shalat di lembah 'Irqi yang terletak diperbatasan Rauha'. Lembah ini ujungnya di sisi jalan di bawah masjid yang posisinya di sebelah kanan jika kamu berjalan menuju Makkah. Disana sudah dibangun masjid namun 'Abdullah bin 'Umar belum pernah shalat di masjid tersebut. Dia melewati masjid tersebut dari sebelah kiri dan belakangnya, kemudian ia shalat di depannya di lembah 'Irq itu sendiri. Pernah ketika dia kembali dari Rauha', dia tidak shalat Zhuhur (di tempat lain) hingga sampai di tempat tersebut, kemudian dia shalat Zhuhur di tempat tersebut. Jika dia kembali dari Makkah dan melewati tempat itu satu jam sebelum Shubuh atau di akhir waktu sahar (menjelang shubuh), dia beristirahat hingga shalat Shubuh di tempat itu. 'Abdullah juga menceritakan kepadanya bahwa Nabi shallallahu 'alaihi wasallam pernah berhenti singgah di bawah pohon besar di desa Ar-Ruwaitsah di sebelah kanan jalan menghadap ke jalan, yakni pada tempat yang rendah dan datar. Sehingga beliau bisa melalui tebing datar yang jaraknya dua mil dari ujung jalan yang datar desa Ar-Ruwaitsah. Tebing itu bagian atasnya sudah banyak yang rontok dan berjatuhan di sisi bawahnya, namun tebing itu masih berdiri tegak pada landasannya sekalipun pada sisinya itu banyak terdapat celah. 'Abdullah bin 'Umar juga menceritakan kepadanya bahwa Nabi shallallahu 'alaihi wasallam pernah shalat di dekat air terjun yang posisinya di belakang desa Al 'Arj jika kamu menuju desa Hadlbah. Pada masjid itu ada dua atau tiga kuburan yang ditandai dengan batu yang berada di sebelah kanan jalan, pada jalan yang datar. Di sisi kanan jalan yang datar itulah 'Abdullah pernah melintas ketika kembali dari desa Al 'Irj setelah matahari condong pada tengah hari, lalu dia shalat Zhuhur di masjid itu. 'Abdullah bin 'Umar juga menceritakan bahwa Rasulullah shallallahu 'alaihi wasallam pernah singgah di pohon-pohon besar di sebelah kiri jalan di tempat saluran air dekat desa Harsya. Saluran air itu letaknya berhubungan dengan ujung jalan desa Harsya yang jaraknya sejauh lemparan anak panah (kira-kira dua pertiga mil). 'Abdullah pernah shalat di dekat pohon yang paling besar dan paling tinggi di antara pohon-pohon besar tersebut. 'Abdullah juga menceritakan bahwa Nabi shallallahu 'alaihi wasallam pernah singgah pada saluran air yang terletak dekat lembah yang disebut dengan Marrul Zhahran, yakni sebelum Madinah jika menuruni lembah Shafrawat. Beliau singgah dan turun hingga ke bawah yang posisinya ada di sebelah kiri jalan jika kamu menuju arah Makkah. Jarak antara saluran air yang beliau singgahi dengan jalan hanya berjarak tidak lebih dari sejauh lemparan batu. 'Abdullah bin 'Umar juga menceritakan kepadanya bahwa Nabi shallallahu 'alaihi wasallam pernah singgah di Dzu Thuwa dan bermalam di sana sampai subuh, ia lalu melaksanakan shalat subuh di sana ketika Beliau pergi mengunjungi Makkah. Tempat shalat Rasulullah shallallahu 'alaihi wasallam tersebut posisinya pada sebuah bukit besar, bukan pada posisi di mana sekarang dibangun masjid, yaitu pada dasar bukit tersebut. 'Abdullah bin 'Umar juga menceritakan kepadanya bahwa Nabi shallallahu 'alaihi wasallam pernah menghadap dua jalan masuk menuju gunung yang jaraknya dengan puncak gunung sekitar sebesar Ka'bah, posisinya sekarang di sebelah kiri dari masjid yang didirikan. Dan tempar shalat Nabi shallallahu 'alaihi wasallam letaknya lebih rendah dari tebing yang berwarna hitam. Jarak tempat itu dari tebing tersebut sepuluh hasta atau kurang lebih sekitar itu. Dan jika kamu shalat menghadap dua jalan ke gunung tersebut maka tempat tersebut berada di tengah antara kamu berdiri dengan Ka'bah.\""},"463":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ يُوسُفَ قَالَ أَخْبَرَنَا مَالِكٌ عَنْ ابْنِ شِهَابٍ عَنْ عُبَيْدِ اللَّهِ بْنِ عَبْدِ اللَّهِ بْنِ عُتْبَةَ عَنْ عَبْدِ اللَّهِ بْنِ عَبَّاسٍ أَنَّهُ قَالَأَقْبَلْتُ رَاكِبًا عَلَى حِمَارٍ أَتَانٍ وَأَنَا يَوْمَئِذٍ قَدْ نَاهَزْتُ الِاحْتِلَامَ وَرَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُصَلِّي بِالنَّاسِ بِمِنًى إِلَى غَيْرِ جِدَارٍ فَمَرَرْتُ بَيْنَ يَدَيْ بَعْضِ الصَّفِّ فَنَزَلْتُ وَأَرْسَلْتُ الْأَتَانَ تَرْتَعُ وَدَخَلْتُ فِي الصَّفِّ فَلَمْ يُنْكِرْ ذَلِكَ عَلَيَّ أَحَدٌ","id":"Telah menceritakan kepada kami ['Abdullah bin Yusuf] berkata, telah mengabarkan kepada kami [Malik] dari [Ibnu Syihab] dari ['Ubaidullah bin 'Abdullah bin 'Utbah] dari ['Abdullah bin 'Abbas] bahwa dia berkata, \"Pada suatu hari aku datang sambil menunggang keledai betina dan pada saat itu usiaku hampir baligh. Saat itu Rasulullah shallallahu 'alaihi wasallam sedang shalat bersama orang banyak di Mina tanpa ada dinding (tabir) di hadapannya. Maka aku lewat didepan sebagian shaf, aku lantas turun dan aku biarkan keledaiku mencari makan. Kemudian aku masuk ke barisan shaf dan tidak ada seorang pun yang menegurku.\""},"464":{"ar":"حَدَّثَنَا إِسْحَاقُ يَعْنِي ابْنَ مَنْصُورٍ قَالَ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ نُمَيْرٍ قَالَ حَدَّثَنَا عُبَيْدُ اللَّهِ بْنُ عُمَرَ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ إِذَا خَرَجَ يَوْمَ الْعِيدِ أَمَرَ بِالْحَرْبَةِ فَتُوضَعُ بَيْنَ يَدَيْهِ فَيُصَلِّي إِلَيْهَا وَالنَّاسُ وَرَاءَهُ وَكَانَ يَفْعَلُ ذَلِكَ فِي السَّفَرِ فَمِنْ ثَمَّ اتَّخَذَهَا الْأُمَرَاءُ","id":"Telah menceritakan kepada kami [Ishaq] -yakni Ibnu Manshur- berkata, telah menceritakan kepada kami ['Abdullah bin Numair] berkata, telah menceritakan kepada kami ['Ubaidullah bin 'Umar] dari [Nafi'] dari [Ibnu 'Umar], bahwa Rasulullah shallallahu 'alaihi wasallam jika keluar untuk shalat 'ied, beliau meminta sebuah tombak lalu ditancapkannya di hadapannya. Kemudian beliau shalat dengan menghadap ke arahnya, sedangkan orang-orang shalat di belakangnya. Beliau juga berbuat seperti itu ketika dalam bepergian, yang kemudian diteruskan oleh para pemimpin (Khulafa Rasyidun).\""},"465":{"ar":"حَدَّثَنَا أَبُو الْوَلِيدِ قَالَ حَدَّثَنَا شُعْبَةُ عَنْ عَوْنِ بْنِ أَبِي جُحَيْفَةَ قَالَ سَمِعْتُ أَبِيأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ صَلَّى بِهِمْ بِالْبَطْحَاءِ وَبَيْنَ يَدَيْهِ عَنَزَةٌ الظُّهْرَ رَكْعَتَيْنِ وَالْعَصْرَ رَكْعَتَيْنِ تَمُرُّ بَيْنَ يَدَيْهِ الْمَرْأَةُ وَالْحِمَارُ","id":"Telah menceritakan kepada kami [Abu Al Walid] berkata, telah menceritakan kepada kami [Syu'bah] dari ['Aun bin Abu Juhaifah] berkata, aku mendengar [Bapakku], bahwa Nabi shallallahu 'alaihi wasallam pernah melaksanakan shalat bersama para sahabat di daerah Bathha`, dan di hadapan beliau ditancapkan sebuah tombak kecil. Beliau mengerjakan shalat Zhuhur dua rakaat dan shalat Ashar dua rakaat, sementara wanita dan keledai berlalu lalang di hadapannya.\""},"466":{"ar":"حَدَّثَنَا عَمْرُو بْنُ زُرَارَةَ قَالَ أَخْبَرَنَا عَبْدُ الْعَزِيزِ بْنُ أَبِي حَازِمٍ عَنْ أَبِيهِ عَنْ سَهْلِ بْنِ سَعْدٍ قَالَكَانَ بَيْنَ مُصَلَّى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَبَيْنَ الْجِدَارِ مَمَرُّ الشَّاةِ","id":"Telah menceritakan kepada kami ['Amru bin Zurarah] berkata, telah mengabarkan kepada kami ['Abdul 'Aziz bin Abu Hazim] dari [Bapaknya] dari [Sahl bin Sa'd] berkata, \"Jarak antara tempat shalat Rasulullah shallallahu 'alaihi wasallam dengan dinding (pembatas) adalah selebar untuk jalan kambing.\""},"467":{"ar":"حَدَّثَنَا الْمَكِّيُّ بْنُ إِبْرَاهِيمَ قَالَ حَدَّثَنَا يَزِيدُ بْنُ أَبِي عُبَيْدٍ عَنْ سَلَمَةَ قَالَكَانَ جِدَارُ الْمَسْجِدِ عِنْدَ الْمِنْبَرِ مَا كَادَتْ الشَّاةُ تَجُوزُهَا","id":"Telah menceritakan kepada kami [Al Makki bin Ibrahim] berkata, telah menceritakan kepada kami [Yazid bin Abu 'Ubaid] dari [Salamah] berkata, \"Jarak antara dinding masjid di mimbar kira-kira seukuran kambing bisa lewat.\""},"468":{"ar":"حَدَّثَنَا مُسَدَّدٌ قَالَ حَدَّثَنَا يَحْيَى عَنْ عُبَيْدِ اللَّهِ أَخْبَرَنِي نَافِعٌ عَنْ عَبْدِ اللَّهِ بْنِ عُمَرَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يُرْكَزُ لَهُ الْحَرْبَةُ فَيُصَلِّي إِلَيْهَا","id":"Telah menceritakan kepada kami [Musaddad] berkata, telah menceritakan kepada kami [Yahya] dari ['Ubaidullah] telah mengabarkan kepadaku [Nafi'] dari ['Abdullah bin 'Umar], bahwa Nabi shallallahu 'alaihi wasallam menancapkan sebuah tombak lalu shalat menghadapnya.\""},"469":{"ar":"حَدَّثَنَا آدَمُ قَالَ حَدَّثَنَا شُعْبَةُ قَالَ حَدَّثَنَا عَوْنُ بْنُ أَبِي جُحَيْفَةَ قَالَ سَمِعْتُ أَبِي قَالَخَرَجَ عَلَيْنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِالْهَاجِرَةِ فَأُتِيَ بِوَضُوءٍ فَتَوَضَّأَ فَصَلَّى بِنَا الظُّهْرَ وَالْعَصْرَ وَبَيْنَ يَدَيْهِ عَنَزَةٌ وَالْمَرْأَةُ وَالْحِمَارُ يَمُرُّونَ مِنْ وَرَائِهَا","id":"Telah menceritakan kepada kami [Adam] berkata, telah menceritakan kepada kami [Syu'bah] berkata, telah menceritakan kepada kami ['Aun bin Abu Juhaifah] berkata, \"Aku mendengar [Bapakku] berkata, \"Nabi shallallahu 'alaihi wasallam keluar menemui kami saat terik matahari. Kemudian beliau diberi bejana berisi air, lalu beliau berwudlu dan mengerjakan shalat Zhuhur dan 'Ashar bersama kami. Sementara itu dihadapannya ditancapkan sebuah tonggak, sementara para wanita dan keledai berlalu lalang di belakang tonggak kayu tersebut.\""},"470":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ حَاتِمِ بْنِ بَزِيعٍ قَالَ حَدَّثَنَا شَاذَانُ عَنْ شُعْبَةَ عَنْ عَطَاءِ بْنِ أَبِي مَيْمُونَةَ قَالَ سَمِعْتُ أَنَسَ بْنَ مَالِكٍ قَالَكَانَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا خَرَجَ لِحَاجَتِهِ تَبِعْتُهُ أَنَا وَغُلَامٌ وَمَعَنَا عُكَّازَةٌ أَوْ عَصًا أَوْ عَنَزَةٌ وَمَعَنَا إِدَاوَةٌ فَإِذَا فَرَغَ مِنْ حَاجَتِهِ نَاوَلْنَاهُ الْإِدَاوَةَ","id":"Telah menceritakan kepada kami [Muhammad bin Hatim bin Bazi'] berkata, telah menceritakan kepada kami [Syadzan] dari [Syu'bah] dari ['Atha' bin Abu Maimunah] berkata, \"Aku mendengar [Anas bin Malik] berkata, \"Jika Nabi shallallahu 'alaihi wasallam keluar untuk buang hajat, maka aku dan seorang anak kecil mengikuti beliau dengan membawa tongkat, atau sebatang kayu, atau bekas tombak dan bejana berisi air. Jika beliau selesai dari buang hajat, maka kami memberikan bejana tersebut kepada beliau.\""},"471":{"ar":"حَدَّثَنَا سُلَيْمَانُ بْنُ حَرْبٍ قَالَ حَدَّثَنَا شُعْبَةُ عَنْ الْحَكَمِ عَنْ أَبِي جُحَيْفَةَ قَالَخَرَجَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِالْهَاجِرَةِ فَصَلَّى بِالْبَطْحَاءِ الظُّهْرَ وَالْعَصْرَ رَكْعَتَيْنِ وَنَصَبَ بَيْنَ يَدَيْهِ عَنَزَةً وَتَوَضَّأَ فَجَعَلَ النَّاسُ يَتَمَسَّحُونَ بِوَضُوئِهِ","id":"Telah menceritakan kepada kami [Sulaiman bin Harb] berkata, telah menceritakan kepada kami [Syu'bah] dari [Al Hakam] dari [Abu Juhaifah] berkata, \"Rasulullah shallallahu 'alaihi wasallam keluar saat terik matahari. Kemudian beliau melaksanakan shalat Zhuhur dan 'Ashar dua rakaat dua rakaat di Bathha`. Sementara dihadapannya ditancapkan sebuah tongkat. Ketika beliau berwudlu, maka orang-orang mengusapkan bekas air wudlunya (ke badan).\""},"472":{"ar":"حَدَّثَنَا الْمَكِّيُّ بْنُ إِبْرَاهِيمَ قَالَ حَدَّثَنَا يَزِيدُ بْنُ أَبِي عُبَيْدٍ قَالَكُنْتُ آتِي مَعَ سَلَمَةَ بْنِ الْأَكْوَعِ فَيُصَلِّي عِنْدَ الْأُسْطُوَانَةِ الَّتِي عِنْدَ الْمُصْحَفِ فَقُلْتُ يَا أَبَا مُسْلِمٍ أَرَاكَ تَتَحَرَّى الصَّلَاةَ عِنْدَ هَذِهِ الْأُسْطُوَانَةِ قَالَ فَإِنِّي رَأَيْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَتَحَرَّى الصَّلَاةَ عِنْدَهَا","id":"Telah menceritakan kepada kami [Al Makki bin Ibrahim] berkata, telah menceritakan kepada kami [Yazid bin Abu 'Ubaid] berkata, \"Aku dan [Salamah bin Al Akwa'] datang (ke Masjid), lalu dia shalat menghadap tiang yang dekat dengan tempat muhshaf. Lalu aku tanyakan, 'Wahai Abu Muslim, kenapa aku lihat kamu memilih tempat shalat dekat tiang ini? ' Dia menjawab, 'Sungguh aku melihat Nabi shallallahu 'alaihi wasallam memilih untuk shalat di situ'.\""},"473":{"ar":"حَدَّثَنَا قَبِيصَةُ قَالَ حَدَّثَنَا سُفْيَانُ عَنْ عَمْرِو بْنِ عَامِرٍ عَنْ أَنَسِ بْنِ مَالِكٍ قَالَلَقَدْ رَأَيْتُ كِبَارَ أَصْحَابِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَبْتَدِرُونَ السَّوَارِيَ عِنْدَ الْمَغْرِبِوَزَادَ شُعْبَةُ عَنْ عَمْرٍو عَنْ أَنَسٍ حَتَّى يَخْرُجَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah menceritakan kepada kami [Qabishah] berkata, telah menceritakan kepada kami [Sufyan] dari ['Amru bin 'Amir] dari [Anas bin Malik] berkata, \"Aku pernah melihat para sahabat senior berlomba mendekati tiang saat adzan Maghrib.\" [Syu'bah] menambahkan dari ['Amru] dari [Anas], \"Sehingga Nabi shallallahu 'alaihi wasallam keluar.\""},"474":{"ar":"حَدَّثَنَا مُوسَى بْنُ إِسْمَاعِيلَ قَالَ حَدَّثَنَا جُوَيْرِيَةُ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ قَالَدَخَلَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْبَيْتَ وَأُسَامَةُ بْنُ زَيْدٍ وَعُثْمَانُ بْنُ طَلْحَةَ وَبِلَالٌ فَأَطَالَ ثُمَّ خَرَجَ وَكُنْتُ أَوَّلَ النَّاسِ دَخَلَ عَلَى أَثَرِهِ فَسَأَلْتُ بِلَالًا أَيْنَ صَلَّى قَالَ بَيْنَ الْعَمُودَيْنِ الْمُقَدَّمَيْنِ","id":"Telah menceritakan kepada kami [Musa bin Isma'il] berkata, telah menceritakan kepada kami [Juwairiah] dari [Nafi'] dari [Ibnu 'Umar] berkata, \"Nabi shallallahu 'alaihi wasallam masuk ke dalam Ka'bah bersama Usamah bin Zaid, 'Utsman bin Thalhah dan Bilal dalam waktu yang cukup lama. Kemudian beliau keluar dan akulah orang yang pertama kali masuk setelah beliau keluar. Aku lantas bertanya kepada Bilal, \"Dimana beliau tadi melaksanakan shalat? ' [Bilal] menjawab, \"Di antara dua tiang depan.\""},"475":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ يُوسُفَ قَالَ أَخْبَرَنَا مَالِكٌ عَنْ نَافِعٍ عَنْ عَبْدِ اللَّهِ بْنِ عُمَرَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ دَخَلَ الْكَعْبَةَ وَأُسَامَةُ بْنُ زَيْدٍ وَبِلَالٌ وَعُثْمَانُ بْنُ طَلْحَةَ الْحَجَبِيُّ فَأَغْلَقَهَا عَلَيْهِ وَمَكَثَ فِيهَا فَسَأَلْتُ بِلَالًا حِينَ خَرَجَ مَا صَنَعَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ جَعَلَ عَمُودًا عَنْ يَسَارِهِ وَعَمُودًا عَنْ يَمِينِهِ وَثَلَاثَةَ أَعْمِدَةٍ وَرَاءَهُ وَكَانَ الْبَيْتُ يَوْمَئِذٍ عَلَى سِتَّةِ أَعْمِدَةٍ ثُمَّ صَلَّىوَقَالَ لَنَا إِسْمَاعِيلُ حَدَّثَنِي مَالِكٌ وَقَالَ عَمُودَيْنِ عَنْ يَمِينِهِ","id":"Telah menceritakan kepada kami ['Abdullah bin Yusuf] berkata, telah mengabarkan kepada kami [Malik] dari [Nafi'] dari ['Abdullah bin 'Umar], bahwa Rasulullah shallallahu 'alaihi wasallam masuk ke dalam Ka'bah bersama Usamah bin Zaid, Bilal dan 'Utsman bin Thalhah Al Hajabi kemudian pintu ditutup, dan beliau berada di dalamnya. Kemudian setelah beliau keluar aku bertanya kepada [Bilal] apa yang dilakukan oleh beliau di dalamnya. Bilal menjawab, 'Beliau menjadikan tiang berada di sebelah kiri, lalu satu di sebelah kanan dan tiga tiang berada di belakangnya -saat itu tiang Ka'bah berjumlah enam buah- kemudian beliau shalat'.\" [Isma'il] menyebutkan kepada kami; [Malik] menceritakan kepadaku, ia sebutkan, \"Dua tiang di sebelah kanannya.\""},"476":{"ar":"حَدَّثَنَا إِبْرَاهِيمُ بْنُ الْمُنْذِرِ قَالَ حَدَّثَنَا أَبُو ضَمْرَةَ قَالَ حَدَّثَنَا مُوسَى بْنُ عُقْبَةَ عَنْ نَافِعٍ أَنَّ عَبْدَ اللَّهِ بْنَ عُمَرَكَانَ إِذَا دَخَلَ الْكَعْبَةَ مَشَى قِبَلَ وَجْهِهِ حِينَ يَدْخُلُ وَجَعَلَ الْبَابَ قِبَلَ ظَهْرِهِ فَمَشَى حَتَّى يَكُونَ بَيْنَهُ وَبَيْنَ الْجِدَارِ الَّذِي قِبَلَ وَجْهِهِ قَرِيبًا مِنْ ثَلَاثَةِ أَذْرُعٍ صَلَّى يَتَوَخَّى الْمَكَانَ الَّذِي أَخْبَرَهُ بِهِ بِلَالٌ أَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ صَلَّى فِيهِ قَالَ وَلَيْسَ عَلَى أَحَدِنَا بَأْسٌ إِنْ صَلَّى فِي أَيِّ نَوَاحِي الْبَيْتِ شَاءَ","id":"Telah menceritakan kepada kami [Ibrahim bin Al Mundzir] berkata, telah menceritakan kepada kami [Abu Dlamrah] berkata, telah menceritakan kepada kami [Musa bin 'Uqbah] dari [Nafi'] bahwa ['Abdullah bin 'Umar], bahwa jika ia masuk ke dalam Ka'bah, ia berjalan ke arah depan sementara pintu Ka'bah di belakangnya. Ia terus berjalah hingga antara dia dan dinding dihadapannya kira-kira tiga hasta, lalu dia shalat di tempat dimana [Bilal] mengabarkan bahwa Nabi shallallahu 'alaihi wasallam pernah shalat di posisi itu.\" 'Abdullah bin 'Umar berkata, \"Dan tidak mengapa jika di antara kami shalat di dalam Ka'bah menghadap kemana saja yang dia mau.\""},"477":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ أَبِي بَكْرٍ الْمُقَدَّمِيُّ حَدَّثَنَا مُعْتَمِرٌ عَنْ عُبَيْدِ اللَّهِ بْنِ عُمَرَ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُ كَانَ يُعَرِّضُ رَاحِلَتَهُ فَيُصَلِّي إِلَيْهَا قُلْتُ أَفَرَأَيْتَ إِذَا هَبَّتْ الرِّكَابُ قَالَ كَانَ يَأْخُذُ هَذَا الرَّحْلَ فَيُعَدِّلُهُ فَيُصَلِّي إِلَى آخِرَتِهِ أَوْ قَالَ مُؤَخَّرِهِ وَكَانَ ابْنُ عُمَرَ رَضِيَ اللَّهُ عَنْهُ يَفْعَلُهُ","id":"Telah menceritakan kepada kami [Muhammad bin Abu Bakar Al Muqaddami] telah menceritakan kepada kami [Mu'tamir] dari ['Ubaidullah bin 'Umar] dari [Nafi'] dari [Ibnu 'Umar] dari Nabi shallallahu 'alaihi wasallam, bahwa beliau pernah menambatkan tunggangannya lalu shalat menghadap ke arahnya.\" Aku (Nafi') berkata, 'Apakah kamu pernah melihat bahwa tunggangannya itu berjalan pergi? ' Ibnu 'Umar menjawab, 'Beliau ambil tali pelananya lalu meletakkannya di depannya, kemudian shalat menghadap ke arahnyanya.' Dan Ibnu 'Umar juga pernah melakukannya.\""},"478":{"ar":"حَدَّثَنَا عُثْمَانُ بْنُ أَبِي شَيْبَةَ قَالَ حَدَّثَنَا جَرِيرٌ عَنْ مَنْصُورٍ عَنْ إِبْرَاهِيمَ عَنْ الْأَسْوَدِ عَنْ عَائِشَةَ قَالَتْأَعَدَلْتُمُونَا بِالْكَلْبِ وَالْحِمَارِ لَقَدْ رَأَيْتُنِي مُضْطَجِعَةً عَلَى السَّرِيرِ فَيَجِيءُ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَيَتَوَسَّطُ السَّرِيرَ فَيُصَلِّي فَأَكْرَهُ أَنْ أُسَنِّحَهُ فَأَنْسَلُّ مِنْ قِبَلِ رِجْلَيْ السَّرِيرِ حَتَّى أَنْسَلَّ مِنْ لِحَافِي","id":"Telah menceritakan kepada kami ['Utsman bin Abu Syaibah] berkata, telah menceritakan kepada kami [Jarir] dari [Manshur] dari [Ibrahim] dari [Al Aswad] dari ['Aisyah] berkata, \"Apakah kalian menyamakan kami dengan anjing dan keledai? Sungguh, aku pernah berbaring di atas tikar, lalu Nabi shallallahu 'alaihi wasallam datang dan berdiri melaksanakan shalat di tengah tikar. Aku tidak ingin mengganggu beliau, maka aku geser kakiku pelan-pekan dari tikar hingga aku keluar dari selimutku.\""},"479":{"ar":"حَدَّثَنَا أَبُو مَعْمَرٍ قَالَ حَدَّثَنَا عَبْدُ الْوَارِثِ قَالَ حَدَّثَنَا يُونُسُ عَنْ حُمَيْدِ بْنِ هِلَالٍ عَنْ أَبِي صَالِحٍ أَنَّ أَبَا سَعِيدٍ قَالَ قَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ح و حَدَّثَنَا آدَمُ بْنُ أَبِي إِيَاسٍ قَالَ حَدَّثَنَا سُلَيْمَانُ بْنُ المُغِيرَةِ قَالَ حَدَّثَنَا حُمَيْدُ بْنُ هِلَالٍ الْعَدَوِيُّ قَالَ حَدَّثَنَا أَبُو صَالِحٍ السَّمَّانُ قَالَ رَأَيْتُ أَبَا سَعِيدٍ الْخُدْرِيَّفِي يَوْمِ جُمُعَةٍ يُصَلِّي إِلَى شَيْءٍ يَسْتُرُهُ مِنْ النَّاسِ فَأَرَادَ شَابٌّ مِنْ بَنِي أَبِي مُعَيْطٍ أَنْ يَجْتَازَ بَيْنَ يَدَيْهِ فَدَفَعَ أَبُو سَعِيدٍ فِي صَدْرِهِ فَنَظَرَ الشَّابُّ فَلَمْ يَجِدْ مَسَاغًا إِلَّا بَيْنَ يَدَيْهِ فَعَادَ لِيَجْتَازَ فَدَفَعَهُ أَبُو سَعِيدٍ أَشَدَّ مِنْ الْأُولَى فَنَالَ مِنْ أَبِي سَعِيدٍ ثُمَّ دَخَلَ عَلَى مَرْوَانَ فَشَكَا إِلَيْهِ مَا لَقِيَ مِنْ أَبِي سَعِيدٍ وَدَخَلَ أَبُو سَعِيدٍ خَلْفَهُ عَلَى مَرْوَانَ فَقَالَ مَا لَكَ وَلِابْنِ أَخِيكَ يَا أَبَا سَعِيدٍ قَالَ سَمِعْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ إِذَا صَلَّى أَحَدُكُمْ إِلَى شَيْءٍ يَسْتُرُهُ مِنْ النَّاسِ فَأَرَادَ أَحَدٌ أَنْ يَجْتَازَ بَيْنَ يَدَيْهِ فَلْيَدْفَعْهُ فَإِنْ أَبَى فَلْيُقَاتِلْهُ فَإِنَّمَا هُوَ شَيْطَانٌ","id":"Telah menceritakan kepada kami [Abu Ma'mar] berkata, telah menceritakan kepada kami ['Abdul Warits] berkata, telah menceritakan kepada kami [Yunus] dari [Humaid bin Hilal] dari [Abu Shalih] bahwa [Abu Sa'id] berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda. (dalam jalur lain disebutkan) Telah menceritakan kepada kami [Adam bin Abu Iyas] berkata, telah menceritakan kepada kami [Sulaiman bin Al Mughirah] berkata, telah menceritakan kepada kami [Humaid bin Hilal Al 'Adawi] berkata, telah menceritakan kepada kami [Abu Shalih as Samman] berkata, \"Pada hari jum'at aku melihat [Abu Sa'id Al Khudri] shalat menghadap sesuatu yang membatasinya dari orang-orang (yang lewat). Kemudian ada seorang pemuda dari Bani Abu Mu'aith hendak lewat di depannya. Maka Abu Sa'id menghalangi orang itu dengan menahan dadanya. Pemuda itu mencari jalan tapi tidak ada kecuali di depan Abu Sa'id. Maka pemuda itu mengulangi lagi untuk lewat. Abu Sa'id kembali menghadangnya dengan lebih keras dari yang pertama. Kemudian pemuda itu pergi meninggalkan Abu Sa'id dan menemui Marwan, ia lalu mengadukan peristiwa yang terjadai antara dirinya dengan Abu Sa'id. Setelah itu Abu Sa'id ikut menemui Marwan, Marwan pun berkata, \"Apa yang kau lakukan terhadap anak saudaramu ini, wahai Abu Sa'id?\" Abu Sa'id menjawab, \"Aku pernah mendengar Nabi shallallahu 'alaihi wasallam bersabda: \"Jika seorang dari kalian shalat menghadap sesuatu yang membatasinya dari orang, kemudian ada seseorang yang hendak lewat dihadapannya maka hendaklah dicegah. Jika dia tidak mau maka perangilah dia, karena dia adalah setan.\""},"480":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ يُوسُفَ قَالَ أَخْبَرَنَا مَالِكٌ عَنْ أَبِي النَّضْرِ مَوْلَى عُمَرَ بْنِ عُبَيْدِ اللَّهِ عَنْ بُسْرِ بْنِ سَعِيدٍأَنَّ زَيْدَ بْنَ خَالِدٍ أَرْسَلَهُ إِلَى أَبِي جُهَيْمٍ يَسْأَلُهُ مَاذَا سَمِعَ مِنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي الْمَارِّ بَيْنَ يَدَيْ الْمُصَلِّي فَقَالَ أَبُو جُهَيْمٍ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَوْ يَعْلَمُ الْمَارُّ بَيْنَ يَدَيْ الْمُصَلِّي مَاذَا عَلَيْهِ لَكَانَ أَنْ يَقِفَ أَرْبَعِينَ ��َيْرًا لَهُ مِنْ أَنْ يَمُرَّ بَيْنَ يَدَيْهِ قَالَ أَبُو النَّضْرِ لَا أَدْرِي أَقَالَ أَرْبَعِينَ يَوْمًا أَوْ شَهْرًا أَوْ سَنَةً","id":"Telah menceritakan kepada kami ['Abdullah bin Yusuf] berkata, telah mengabarkan kepada kami [Malik] dari [Abu An Nadlr] mantan budak 'Umar bin 'Abaidullah dari [Busr bin Sa'id] bahwa Zaid bin Khalid mengutusnya kepada Abu Juhaim untuk menanyakan apa yang didengarnya dari Rasulullah shallallahu 'alaihi wasallam tentang orang yang lewat di depan orang yang sedang shalat. [Abu Juhaim] lalu berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sekiranya orang yang lewat di depan orang yang mengerjakan shalat mengetahui apa akibat yang akan ia tanggung, niscaya ia berdiri selama empat puluh lebih baik baginya dari pada dia lewat di depan orang yang sedang shalat.\" Abu An Nadlr berkata, \"Aku tidak tahu yang dimaksud dengan jumlah 'empat puluh itu', apakah empat puluh hari, atau bulan, atau tahun.\""},"481":{"ar":"حَدَّثَنَا إِسْمَاعِيلُ بْنُ خَلِيلٍ حَدَّثَنَا عَلِيُّ بْنُ مُسْهِرٍ عَنْ الْأَعْمَشِ عَنْ مُسْلِمٍ يَعْنِي ابْنَ صُبَيْحٍ عَنْ مَسْرُوقٍ عَنْ عَائِشَةَأَنَّهُ ذُكِرَ عِنْدَهَا مَا يَقْطَعُ الصَّلَاةَ فَقَالُوا يَقْطَعُهَا الْكَلْبُ وَالْحِمَارُ وَالْمَرْأَةُ قَالَتْ لَقَدْ جَعَلْتُمُونَا كِلَابًا لَقَدْ رَأَيْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُصَلِّي وَإِنِّي لَبَيْنَهُ وَبَيْنَ الْقِبْلَةِ وَأَنَا مُضْطَجِعَةٌ عَلَى السَّرِيرِ فَتَكُونُ لِي الْحَاجَةُ فَأَكْرَهُ أَنْ أَسْتَقْبِلَهُ فَأَنْسَلُّ انْسِلَالًاوَعَنْ الْأَعْمَشِ عَنْ إِبْرَاهِيمَ عَنْ الْأَسْوَدِ عَنْ عَائِشَةَ نَحْوَهُ","id":"Telah menceritakan kepada kami [Isma'il bin Khalil] telah menceritakan kepada kami ['Ali bin Mushir] dari [Al A'masy] dari [Muslim] -yakni Abu Shubaih- dari [Masruq] dari ['Aisyah], bahwa telah disebutkan di sisinya tentang sesuatu yang dapat memutuskan shalat, orang-orang mengatakan, 'Yang dapat memutus shalat diantaranya adalah anjing, keledai dan wanita.' Maka 'Aisyah pun berkata, \"Sungguh kalian telah menganggap kami (kaum wanita) sebagaimana anjing. Sungguh aku pernah melihat Nabi shallallahu 'alaihi wasallam melaksanakan shalat, sementara aku berbaring di atas tikar antara beliau dan dengan arah biblatnya. Saat aku ada keperluan dan aku tidak ingin menghadapnya, maka aku pergi dengan pelan-pelan.\" Dan dari [Al A'masy] dari [Ibrahim] dari [Al Aswad] dari ['Aisyah] seperti ini.\""},"482":{"ar":"حَدَّثَنَا مُسَدَّدٌ قَالَ حَدَّثَنَا يَحْيَى قَالَ حَدَّثَنَا هِشَامٌ قَالَ حَدَّثَنِي أَبِي عَنْ عَائِشَةَ قَالَتْكَانَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُصَلِّي وَأَنَا رَاقِدَةٌ مُعْتَرِضَةٌ عَلَى فِرَاشِهِ فَإِذَا أَرَادَ أَنْ يُوتِرَ أَيْقَظَنِي فَأَوْتَرْتُ","id":"Telah menceritakan kepada kami [Musaddad] berkata, telah menceritakan kepada kami [Yahya] berkata, telah menceritakan kepada kami [Hisyam] berkata, telah menceritakan kepadaku [Bapakku] dari ['Aisyah] ia berkata, \"Nabi shallallahu 'alaihi wasallam shalat sedangkan aku tidur di atas ranjangnya dengan membentang dihapannya. Ketika akan witir, beliau membangunkan aku hingga aku pun shalat witir.\""},"483":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ يُوسُفَ قَالَ أَخْبَرَنَا مَالِكٌ عَنْ أَبِي النَّضْرِ مَوْلَى عُمَرَ بْنِ عُبَيْدِ اللَّهِ عَنْ أَبِي سَلَمَةَ بْنِ عَبْدِ الرَّحْمَنِ عَنْ عَائِشَةَ زَوْجِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهَا قَالَتْكُنْتُ أَنَامُ بَيْنَ يَدَيْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَرِجْلَايَ فِي قِبْلَتِهِ فَإِذَا سَجَدَ غَمَزَنِي فَقَبَضْتُ رِجْلَيَّ فَإِذَا قَامَ بَسَطْتُهُمَا قَالَتْ وَالْبُيُوتُ يَوْمَئِذٍ لَيْسَ فِيهَا مَصَابِيحُ","id":"Telah menceritakan kepada kami ['Abdullah bin Yusuf] berkata, telah mengabarkan kepada kami [Malik] dari [Abu An Nadlr] mantan budak 'Umar bin 'Ubaidullah, dari [Abu Salamah bin 'Abdurrahman] dari ['Aisyah] isteri Nabi shallallahu 'alaihi wasallam, ia berkata, \"Aku pernah tidur di depan Rasulullah shallallahu 'alaihi wasallam dan kakiku berada di arah kiblatnya. Jika akan sujud beliau menyentuhku dengan tangannya, maka aku pun menarik kakiku. Dan jika beliau berdiri aku luruskan kembali kakiku.\" 'Aisyah berkata, \"Pada zaman iku rumah-rumah tidak memiliki lampu.\""},"484":{"ar":"حَدَّثَنَا عُمَرُ بْنُ حَفْصِ بْنِ غِيَاثٍ قَالَ حَدَّثَنَا أَبِي قَالَ حَدَّثَنَا الْأَعْمَشُ قَالَ حَدَّثَنَا إِبْرَاهِيمُ عَنْ الْأَسْوَدِ عَنْ عَائِشَةَ ح قَالَ الْأَعْمَشُ وَحَدَّثَنِي مُسْلِمٌ عَنْ مَسْرُوقٍ عَنْ عَائِشَةَذُكِرَ عِنْدَهَا مَا يَقْطَعُ الصَّلَاةَ الْكَلْبُ وَالْحِمَارُ وَالْمَرْأَةُ فَقَالَتْ شَبَّهْتُمُونَا بِالْحُمُرِ وَالْكِلَابِ وَاللَّهِ لَقَدْ رَأَيْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُصَلِّي وَإِنِّي عَلَى السَّرِيرِ بَيْنَهُ وَبَيْنَ الْقِبْلَةِ مُضْطَجِعَةً فَتَبْدُو لِي الْحَاجَةُ فَأَكْرَهُ أَنْ أَجْلِسَ فَأُوذِيَ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَنْسَلُّ مِنْ عِنْدِ رِجْلَيْهِ","id":"Telah menceritakan kepada kami ['Umar bin Hafsh bin 'Iyats] berkata, telah menceritakan kepada kami [Bapakku] ia berkata, telah menceritakan kepada kami [Al A'masy] berkata, telah menceritakan kepada kami [Ibrahim] dari [Al Aswad] dari ['Aisyah]. (dalam jalur lain disebutkan) [Al A'masy] berkata, telah menceritakan kepadaku [Muslim] dari [Masruq] dari ['Aisyah], bahwa telah disebutkan kepadanya tentang sesuatu yang dapat memutuskan shalat; anjing, keledai dan wanita. Maka ia pun berkata, \"Kalian telah menyamakan kami dengan keledai dan anjing! Demi Allah, aku pernah melihat Nabi shallallahu 'alaihi wasallam shalat sedangkan aku berbaring di atas tikar antara beliau dan arah kiblatnya. Sehingga ketika aku ada suatu keperluan dan aku tidak ingin duduk hingga menyebabkan Nabi shallallahu 'alaihi wasallam terganggu, maka aku pun pergi diam-diam dari dekat kedua kaki beliau.\""},"485":{"ar":"حَدَّثَنَا إِسْحَاقُ بْنُ إِبْرَاهِيمَ قَالَ أَخْبَرَنَا يَعْقُوبُ بْنُ إِبْرَاهِيمَ بْنِ سَعْدٍ قَالَ حَدَّثَنِي ابْنُ أَخِي ابْنِ شِهَابٍ أَنَّهُ سَأَلَ عَمَّهُ عَنْ الصَّلَاةِ يَقْطَعُهَا شَيْءٌ فَقَالَ لَا يَقْطَعُهَا شَيْءٌ أَخْبَرَنِي عُرْوَةُ بْنُ الزُّبَيْرِ أَنَّ عَائِشَةَ زَوْجَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَتْلَقَدْ كَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُومُ فَيُصَلِّي مِنْ اللَّيْلِ وَإِنِّي لَمُعْتَرِضَةٌ بَيْنَهُ وَبَيْنَ الْقِبْلَةِ عَلَى فِرَاشِ أَهْلِهِ","id":"Telah menceritakan kepada kami [Ishaq bin Ibrahim] berkata, telah mengabarkan kepada kami [Ya'qub bin Ibrahim bin Sa'id] berkata, telah menceritakan kepadaku [Anak saudara Ibnu Syihab], bahwa dia pernah bertanya kepada [Pamannya] tentang sesuatu yang dapat memutuskan shalat. Maka pamannya menjawab, \"Tidak ada yang dapat memutuskan shalat. Aku telah mendapat kabar dari ['Urwah bin Az Zubair] bahwa ['Aisyah] isteri Nabi shallallahu 'alaihi wasallam berkata, \"Sungguh Rasulullah shallallahu 'alaihi wasallam pernah berdiri melaksanakan shalat malam sedangkan aku berbaring membentang antara beliau dan arah kiblatnya di tempat tidur keluarga.\""},"486":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ يُوسُفَ قَالَ أَخْبَرَنَا مَالِكٌ عَنْ عَامِرِ بْنِ عَبْدِ اللَّهِ بْنِ الزُّبَيْرِ عَنْ عَمْرِو بْنِ سُلَيْمٍ الزُّرَقِيِّ عَنْ أَبِي قَتَادَةَ الْأَنْصَارِيِّأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يُصَلِّي وَهُوَ حَامِلٌ أُمَامَةَ بِنْتَ زَيْنَبَ بِنْتِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَلِأَبِي الْعَاصِ بْنِ رَبِيعَةَ بْنِ عَبْدِ شَمْسٍ فَإِذَا سَجَدَ وَضَعَهَا وَإِذَا قَامَ حَمَلَهَا","id":"Telah menceritakan kepada kami ['Abdullah bin Yusuf] berkata, telah mengabarkan kepada kami [Malik] dari ['Amir bin 'Abdullah bin Az Zubair] dari ['Amru bin Sulaim Az Zuraqi] dari [Abu Qatadah Al Anshari], bahwa Rasulullah shallallahu 'alaihi wasallam pernah shalat dengan menggendong Umamah binti Zainab binti Rasulullah shallallahu 'alaihi wasallam.\" Dan menurut riwayat Abu Al 'Ash bin Rabi'ah bin 'Abdu Syamsi, ia menyebutkan, \"Jika sujud beliau letakkan anak itu dan bila berdiri beliau gendong lagi.\""},"487":{"ar":"حَدَّثَنَا عَمْرُو بْنُ زُرَارَةَ قَالَ أَخْبَرَنَا هُشَيْمٌ عَنْ الشَّيْبَانِيِّ عَنْ عَبْدِ اللَّهِ بْنِ شَدَّادِ بْنِ الْهَادِ قَالَ أَخْبَرَتْنِي خَالَتِي مَيْمُونَةُ بِنْتُ الْحَارِثِ قَالَتْكَانَ فِرَاشِي حِيَالَ مُصَلَّى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَرُبَّمَا وَقَعَ ثَوْبُهُ عَلَيَّ وَأَنَا عَلَى فِرَاشِي","id":"Telah menceritakan kepada kami ['Amru bin Zurarah] berkata, telah mengabarkan kepada kami [Husyaim] dari [Asy Syaibani] dari ['Abdullah bin Syaddad bin Al Had] berkata, bibiku [Maimunah binti Al Harits] mengabarkan kepadaku, ia berkata, \"Tempat tidurku berhadapan dengan tempat shalat Nabi shallallahu 'alaihi wasallam, dan terkadang pakaian beliau mengenaiku saat aku sedang tidur.\""},"488":{"ar":"حَدَّثَنَا أَبُو النُّعْمَانِ قَالَ حَدَّثَنَا عَبْدُ الْوَاحِدِ بْنُ زِيَادٍ قَالَ حَدَّثَنَا الشَّيْبَانِيُّ سُلَيْمَانُ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ شَدَّادٍ قَالَ سَمِعْتُ مَيْمُونَةَ تَقُولُكَانَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُصَلِّي وَأَنَا إِلَى جَنْبِهِ نَائِمَةٌ فَإِذَا سَجَدَ أَصَابَنِي ثَوْبُهُ وَأَنَا حَائِضٌوَزَادَ مُسَدَّدٌ عَنْ خَالِدٍ قَالَ حَدَّثَنَا سُلَيْمَانُ الشَّيْبَانِيُّ وَأَنَا حَائِضٌ","id":"Telah menceritakan kepada kami [Abu An Nu'man] berkata, telah menceritakan kepada kami ['Abdul Wahid bin Ziyad] berkata, telah menceritakan kepada kami [Asy Syaibani Sulaiman] berkata, telah menceritakan kepada kami ['Abdullah bin Syaddad] berkata, \"Aku mendengar [Maimunah] berkata, \"Pernah Nabi shallallahu 'alaihi wasallam shalat sedangkan aku tidur disampingnya. Jika sujud baju beliau mengenaiku, padahal saat itu aku sedang haid.\" [Musaddad] menambahkan dari [Khalid] ia berkata, [Sulaiman Asy Syaibani] menceritakan kepadaku dengan lafadz, \"Dan aku sedang haid.\""},"489":{"ar":"حَدَّثَنَا عَمْرُو بْنُ عَلِيٍّ قَالَ حَدَّثَنَا يَحْيَى قَالَ حَدَّثَنَا عُبَيْدُ اللَّهِ قَالَ حَدَّثَنَا الْقَاسِمُ عَنْ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَا قَالَتْبِئْسَمَا عَدَلْتُمُونَا بِالْكَلْبِ وَالْحِمَارِ لَقَدْ رَأَيْتُنِي وَرَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُصَلِّي وَأَنَا مُضْطَجِعَةٌ بَيْنَهُ وَبَيْنَ الْقِبْلَةِ فَإِذَا أَرَادَ أَنْ يَسْجُدَ غَمَزَ رِجْلَيَّ فَقَبَضْتُهُمَا","id":"Telah menceritakan kepada kami ['Amru bin 'Ali] berkata, telah menceritakan kepada kami [Yahya] berkata, telah menceritakan kepada kami ['Ubaidullah] berkata, telah menceritakan kepada kami [Al Qasim] dari ['Aisyah] berkata, \"Sangat buruk apa yang kalian lakukan dengan menyamakan kami dengan anjing dan keledai! Sungguh, aku pernah lihat Rasulullah shallallahu 'alaihi wasallam shalat sedangkan aku berbaring antara beliau dan arah kiblatnya. Jika akan sujud beliau mendorong kakiku dengan tangannya, maka aku pun segera menarik kedua kakiku.\""},"490":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ إِسْحَاقَ السُّورَمَارِيُّ قَالَ حَدَّثَنَا عُبَيْدُ اللَّهِ بْنُ مُوسَى قَالَ حَدَّثَنَا إِسْرَائِيلُ عَنْ أَبِي إِسْحَاقَ عَنْ عَمْرِو بْنِ مَيْمُونٍ عَنْ عَبْدِ اللَّهِ قَالَبَيْنَمَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَائِمٌ يُصَلِّي عِنْدَ الْكَعْبَةِ وَجَمْعُ قُرَيْشٍ فِي مَجَالِسِهِمْ إِذْ قَالَ قَائِلٌ مِنْهُمْ أَلَا تَنْظُرُونَ إِلَى هَذَا الْمُرَائِي أَيُّكُمْ يَقُومُ إِلَى جَزُورِ آلِ فُلَانٍ فَيَعْمِدُ إِلَى فَرْثِهَا وَدَمِهَا وَسَلَاهَا فَيَجِيءُ بِهِ ثُمَّ يُمْهِلُهُ حَتَّى إِذَا سَجَدَ وَضَعَهُ بَيْنَ كَتِفَيْهِ فَانْبَعَثَ أَشْقَاهُمْ فَلَمَّا سَجَدَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَضَعَهُ بَيْنَ كَتِفَيْهِ وَثَبَتَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ سَاجِدًا فَضَحِكُوا حَتَّى مَالَ بَعْضُهُمْ إِلَى بَعْضٍ مِنْ الضَّحِكِ فَانْطَلَقَ مُنْطَلِقٌ إِلَى فَاطِمَةَ عَلَيْهَا السَّلَام وَهِيَ جُوَيْرِيَةٌ فَأَقْبَلَتْ تَسْعَى وَثَبَتَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ سَاجِدًا حَتَّى أَلْقَتْهُ عَنْهُ وَأَقْبَلَتْ عَلَيْهِمْ تَسُبُّهُمْ فَلَمَّا قَضَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الصَّلَاةَ قَالَ اللَّهُمَّ عَلَيْكَ بِقُرَيْشٍ اللَّهُمَّ عَلَيْكَ بِقُرَيْشٍ اللَّهُمَّ عَلَيْكَ بِقُرَيْشٍ ثُمَّ سَمَّى اللَّهُمَّ عَلَيْكَ بِعَمْرِو بْنِ هِشَامٍ وَعُتْبَةَ بْنِ رَبِيعَةَ وَشَيْبَةَ بْنِ رَبِيعَةَ وَالْوَلِيدِ بْنِ عُتْبَةَ وَأُمَيَّةَ بْنِ خَلَفٍ وَعُقْبَةَ بْنِ أَبِي مُعَيْطٍ وَعُمَارَةَ بْنِ الْوَلِيدِ قَالَ عَبْدُ اللَّهِ فَوَاللَّهِ لَقَدْ رَأَيْتُهُمْ صَرْعَى يَوْمَ بَدْرٍ ثُمَّ سُحِبُوا إِلَى الْقَلِيبِ قَلِيبِ بَدْرٍ ثُمَّ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَأُتْبِعَ أَصْحَابُ الْقَلِيبِ لَعْنَةً","id":"Telah menceritakan kepada kami [Ahmad bin Ishaq As Suramari] berkata, telah menceritakan kepada kami [Ubaidullah bin Musa] berkata, telah menceritakan kepada kami [Isra'il] dari [Abu Ishaq] dari ['Amru bin Maimun] dari ['Abdullah] berkata, \"Ketika Rasulullah shallallahu 'alaihi wasallam shalat di dekat Ka'bah, ada orang-orang Quraisy yang sedang duduk-duduk di majelis mereka. Ketika itu ada seorang laki-laki dari mereka yang berkata, 'Tidakkah kalian melihat kepada orang yang riya' ini? Siapa dari kalian yang dapat mengambilkan buatku sisa unta yang baru disembelih milik fulan, lalu dia kumpulkan kotorannya, darah dan plasenta (ari-ari) nya! ' Maka ada seorang laki-laki datang dengan membawa kotoran tersebut, ia menunggu sampai beliau sujud. Sehingga ketika beliau sujud, ia ia bisa meletakkan kotoran tersebut di antara bahu beliau. Maka ketika Rasulullah shallallahu 'alaihi wasallam sujud, orang itu meletakkan kotoran-kotoran unta itu di antara dua bahu beliau. Dan Nabi shallallahu 'alaihi wasallam tetap dalam keadaan sujud, mereka pun tertawa hingga sebagian condong kepada sebagian yang lain. Lalu ada seseorang menemui Fatimah? radliallahu 'anha, dan orang itu adalah Juwairiyah. Maka Fatimah bergegas mendatangi Nabi shallallahu 'alaihi wasallam yang saat itu masih dalam keadaan sujud. Kemudian Fatimah membersihkan kotoran-kotoran unta tersebut dari beliau. Kemudian Fatimah menghadap ke arah mereka dan mengumpat orang-orang Quraisy tersebut. Setelah Rasulullah shallallahu 'alaihi wasallam menyelesaikan shalat dan berdo'a: \"Ya Allah kuserahkan (urusan) Quraisy kepada-Mu, Ya Allah kuserahkan Quraisy kepada-Mu, Ya Allah kuserahkan Quraisy kepada-Mu.\" Kemudian Nabi shallallahu 'alaihi wasallam menyebut satu persatu nama-nama mereka: \"Ya Allah kuserahkan (urusan) 'Amru bin Hisyam kepada-Mu, 'Utbah bin Rabi'ah, Syaibah bin Rabi'ah, Al Walid bin 'Utbah, Umayyah bin Khalaf, 'Uqbah bin Abu Mu'aith dan 'Umarah bin Al Walid.\" 'Abdullah bin Mas'ud berkata, \"Demi Allah, aku melihat orang-orang yang disebut Nabi shallallahu 'alaihi wasallam tersebut terbantai pada perang Badar, kemudian mereka dibunag ke lembah Badar.\" Lalu Nabi shallallahu 'alaihi wasallam bersabda: \"Jadilah para penghuni lembah ini diiringi dengan kutukan.\""},"491":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مَسْلَمَةَ قَالَ قَرَأْتُ عَلَى مَالِكٍ عَنْ ابْنِ شِهَابٍ أَنَّ عُمَرَ بْنَ عَبْدِ الْعَزِيزِ أَخَّرَ الصَّلَاةَ يَوْمًا فَدَخَلَ عَلَيْهِ عُرْوَةُ بْنُ الزُّبَيْرِ فَأَخْبَرَهُ أَنَّ الْمُغِيرَةَ بْنَ شُعْبَةَ أَخَّرَ الصَّلَاةَ يَوْمًا وَهُوَ بِالْعِرَاقِ فَدَخَلَ عَلَيْهِ أَبُو مَسْعُودٍ الْأَنْصَارِيُّفَقَالَ مَا هَذَا يَا مُغِيرَةُ أَلَيْسَ قَدْ عَلِمْتَ أَنَّ جِبْرِيلَ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَزَلَ فَصَلَّى فَصَلَّى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ثُمَّ صَلَّى فَصَلَّى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ثُمَّ صَلَّى فَصَلَّى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ثُمَّ صَلَّى فَصَلَّى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ثُمَّ صَلَّى فَصَلَّى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ثُمَّ قَالَ بِهَذَا أُمِرْتُفَقَالَ عُمَرُ لِعُرْوَةَ اعْلَمْ مَا تُحَدِّثُ أَوَأَنَّ جِبْرِيلَ هُوَ أَقَامَ لِرَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَقْتَ الصَّلَاةِ قَالَ عُرْوَةُ كَذَلِكَ كَانَ بَشِيرُ بْنُ أَبِي مَسْعُودٍ يُحَدِّثُ عَنْ أَبِيهِ قَالَ عُرْوَةُ وَلَقَدْ حَدَّثَتْنِي عَائِشَةُ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يُصَلِّي الْعَصْرَ وَالشَّمْسُ فِي حُجْرَتِهَا قَبْلَ أَنْ تَظْهَرَ","id":"Telah menceritakan kepada kami ['Abdullah bin Maslamah] berkata; Aku membacakannya di hadapan [Malik] dari [Ibnu Syihab] bahwa 'Umar bin 'Abdul 'Aziz pada suatu hari mengakhirkan pelaksanaan shalat. Kemudian ['Urwah bin Az Zubair] datang menemuinya dan mengabarkan kepadanya bahwa Al Mughirah bin Syu'bah pada suatu hari juga pernah mengakhirkan shalat, dan saat itu dia tinggal di 'Irak. Kemudian [Abu Mas'ud Al Anshari] datang menemuinya seraya berkata, \"Apa yang kamu lakukan ini wahai Al Mughirah? Bukankah kamu telah mengetahui bahwa Malaikat Jibril shallallahu 'alaihi wasallam pernah turun kemudian melaksanakan shalat, kemudian Rasulullah shallallahu 'alaihi wasallam juga ikut melaksanakan shalat? Kemudian Jibril shalat lagi dan Rasulullah shallallahu 'alaihi wasallam juga ikut shalat kembali? Kemudian Jibril shalat lagi dan Rasulullah shallallahu 'alaihi wasallam juga ikut shalat kembali? Kemudian Jibril shalat lagi dan Rasulullah shallallahu 'alaihi wasallam juga ikut shalat kembali? Kemudian Jibril shalat lagi dan Rasulullah shallallahu 'alaihi wasallam juga ikut shalat kembali? Kemudian Jibril berkata, \"Inilah waktu-waktu yang diperintahkan kepadaku (agar engkau melaksanakannya).\" 'Umar lalu berkata kepada 'Urwah, \"Ketahuilah apa yang kamu ceritakan! Sesungguhnya Jibril datang untuk menjelaskan kepada Rasulullah shallallahu 'alaihi wasallam tentang waktu-waktu shalat.\" 'Urwah berkata, \"Begitulah adanya. bahwasanya [Basyir bin Abu Mas'ud] menceritakan dari [Bapaknya]. Urwah berkata, \" [Aisyah] menceritakan kepadaku bahwa Rasulullah shallallahu 'alaihi wasallam pernah melaksanakan shalat 'Ashar, sementara cahaya matahari yang ada dalam kamarnya belum nampak.\""},"492":{"ar":"حَدَّثَنَا قُتَيْبَةُ بْنُ سَعِيدٍ قَالَ حَدَّثَنَا عَبَّادٌ هُوَ ابْنُ عَبَّادٍ عَنْ أَبِي جَمْرَةَ عَنْ ابْنِ عَبَّاسٍ قَالَقَدِمَ وَفْدُ عَبْدِ الْقَيْسِ عَلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالُوا إِنَّا مِنْ هَذَا الْحَيِّ مِنْ رَبِيعَةَ وَلَسْنَا نَصِلُ إِلَيْكَ إِلَّا فِي الشَّهْرِ الْحَرَامِ فَمُرْنَا بِشَيْءٍ نَأْخُذْهُ عَنْكَ وَنَدْعُو إِلَيْهِ مَنْ وَرَاءَنَا فَقَالَ آمُرُكُمْ بِأَرْبَعٍ وَأَنْهَاكُمْ عَنْ أَرْبَعٍ الْإِيمَانِ بِاللَّهِ ثُمَّ فَسَّرَهَا لَهُمْ شَهَادَةُ أَنْ لَا إِلَهَ إِلَّا اللَّهُ وَأَنِّي رَسُولُ اللَّهِ وَإِقَامُ الصَّلَاةِ وَإِيتَاءُ الزَّكَاةِ وَأَنْ تُؤَدُّوا إِلَيَّ خُمُسَ مَا غَنِمْتُمْ وَأَنْهَى عَنْ الدُّبَّاءِ وَالْحَنْتَمِ وَالْمُقَيَّرِ وَالنَّقِيرِ","id":"Telah menceritakan kepada kami [Qutaibah bin Sa'id] berkata, telah menceritakan kepada kami ['Abbad] -yaitu Ibnu 'Abbad- dari [Abu Hamzah] dari [Ibnu 'Abbas] berkata, \"Utusan 'Abdul Qais datang kepada Rasulullah shallallahu 'alaihi wasallam dan berkata, \"Sesungguhnya kami dari suku Rabi'ah, dan kami tidak dapat mengunjungi tuan kecuali pada bulan haram. Maka perintahlah kepada kami dengan sesuatu yang kami ambil dari tuan dan dapat kami sampaikan kepada penduduk kami. Maka Nabi shallallahu 'alaihi wasallam bersabda: \"Aku perintahkan kalian dengan empat perkara dan aku larang dari empat perkara; Iman kepada Allah. Lalu Nabi shallallahu 'alaihi wasallam menjelaskan kepada mereka; yaitu persaksian bahwa tidak ada Tuhan yang berhak disembah selain Allah dan Muhammad adalah utusan Allah, menegakkan shalat, menunaikan zakat, pusa Ramadan dan kalian kelurakan seperlima dari harta rampasan perang. Dan aku larang kalian dari Ad Duba`, Al Hantam, Al Muqayyar dan An Naqir.\" "},"493":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ الْمُثَنَّى قَالَ حَدَّثَنَا يَحْيَى قَالَ حَدَّثَنَا إِسْمَاعِيلُ قَالَ حَدَّثَنَا قَيْسٌ عَنْ جَرِيرِ بْنِ عَبْدِ اللَّهِ قَالَبَايَعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَلَى إِقَامِ الصَّلَاةِ وَإِيتَاءِ الزَّكَاةِ وَالنُّصْحِ لِكُلِّ مُسْلِمٍ","id":"Telah menceritakan kepada kami [Muhammad bin Al Mutsanna] berkata, telah menceritakan kepada kami [Yahya] berkata, telah menceritakan kepada kami [Isma'il] berkata, telah menceritakan kepada kami [Qais] dari [Jarir bin 'Abdullah] berkata, \"Aku membai'at Rasulullah shallallahu 'alaihi wasallam untuk menegakkan shalat, menunaikan zakat dan untuk setia kepada setiap Muslim.\""},"494":{"ar":"حَدَّثَنَا مُسَدَّدٌ قَالَ حَدَّثَنَا يَحْيَى عَنْ الْأَعْمَشِ قَالَ حَدَّثَنِي شَقِيقٌ قَالَ سَمِعْتُ حُذَيْفَةَ قَالَكُنَّا جُلُوسًا عِنْدَ عُمَرَ رَضِيَ اللَّهُ عَنْهُ فَقَالَ أَيُّكُمْ يَحْفَظُ قَوْلَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي الْفِتْنَةِ قُلْتُ أَنَا كَمَا قَالَهُ قَالَ إِنَّكَ عَلَيْهِ أَوْ عَلَيْهَا لَجَرِيءٌ قُلْتُ فِتْنَةُ الرَّجُلِ فِي أَهْلِهِ وَمَالِهِ وَوَلَدِهِ وَجَارِهِ تُكَفِّرُهَا الصَّلَاةُ وَالصَّوْمُ وَالصَّدَقَةُ وَالْأَمْرُ وَالنَّهْيُ قَالَ لَيْسَ هَذَا أُرِيدُ وَلَكِنْ الْفِتْنَةُ الَّتِي تَمُوجُ كَمَا يَمُوجُ الْبَحْرُ قَالَ لَيْسَ عَلَيْكَ مِنْهَا بَأْسٌ يَا أَمِيرَ الْمُؤْمِنِينَ إِنَّ بَيْنَكَ وَبَيْنَهَا بَابًا مُغْلَقًا قَالَ أَيُكْسَرُ أَمْ يُفْتَحُ قَالَ يُكْسَرُ قَالَ إِذًا لَا يُغْلَقَ أَبَدًا قُلْنَا أَكَانَ عُمَرُ يَعْلَمُ الْبَابَ قَالَ نَعَمْ كَمَا أَنَّ دُونَ الْغَدِ اللَّيْلَةَ إِنِّي حَدَّثْتُهُ بِحَدِيثٍ لَيْسَ بِالْأَغَالِيطِ فَهِبْنَا أَنْ نَسْأَلَ حُذَيْفَةَ فَأَمَرْنَا مَسْرُوقًا فَسَأَلَهُ فَقَالَ الْبَابُ عُمَرُ","id":"Telah menceritakan kepada kami [Musaddad] berkata, telah menceritakan kepada kami [Yahya] dari [Al A'masy] berkata, telah menceritakan kepadaku [Syaqiq] berkata, Aku pernah mendengar [Hudzaifah] berkata, \"Kami pernah bermajelis bersama 'Umar, lalu ia berkata, \"Siapa di antara kalian yang masih ingat sabda Rasulullah shallallahu 'alaihi wasallam tentang masalah fitnah? ' Aku lalu menjawab, 'Aku masih ingat seperti yang beliau sabdakan! ' 'Umar bertanya, \"Kamu dengar dari beliau atau kamu mendengar perkataan itu dari orang lain?\" Aku menjawab, 'Yaitu fitnah seseorang dalam keluarganya, harta, anak dan tetangganya. Dan fitnah itu akan terhapus oleh amalan shalat, puasa, sedekah, amar ma'ruf dan nahi munkar.\" 'Umar berkata, \"Bukan itu yang aku mau. Tapi fitnah yang dahsyat seperti dahsyatnya air laut.\" Hudzaifah berkata, \"Wahai Amirul Mukminin, sesungguhnya fitnah itu tidak akan membahayakan engkau! antara engkau dengannya terhalang oleh pintu yang tertutup.\" 'Umar bertanya; \"Pintu yang rusak atau terbuka?\" Hudzaifah menjawab, \"Rusak.\" 'Umar pun berkata, \"Kalau begitu tidak akan bisa ditutup selamanya! ' Kami (perawi) bertanya, \"Apakah 'Umar mengerti pintu yang dimaksud?\" Hudzaifah menjawab, \"Ya. Sebagaimana mengertinya dia bahwa setelah pagi adalah malam hari. Aku telah menceritakan kepadanya suatu hadits yang tidak ada kerancuannya.\" Namun kami takut untuk bertanya kepada Hudzaifah, lalu aku suruh Masruq untuk, lalu ia pun menanyakannya kepadanya. Hudzaifah lalu menjawab, \"Pintu itu adalah Umar.\""},"495":{"ar":"حَدَّثَنَا قُتَيْبَةُ قَالَ حَدَّثَنَا يَزِيدُ بْنُ زُرَيْعٍ عَنْ سُلَيْمَانَ التَّيْمِيِّ عَنْ أَبِي عُثْمَانَ النَّهْدِيِّ عَنْ ابْنِ مَسْعُودٍأَنَّ رَجُلًا أَصَابَ مِنْ امْرَأَةٍ قُبْلَةً فَأَتَى النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَخْبَرَهُ فَأَنْزَلَ اللَّهُ عَزَّ وَجَلَّ{ أَقِمْ الصَّلَاةَ طَرَفَيْ النَّهَارِ وَزُلَفًا مِنْ اللَّيْلِ إِنَّ الْحَسَنَاتِ يُذْهِبْنَ السَّيِّئَاتِ }فَقَالَ الرَّجُلُ يَا رَسُولَ اللَّهِ أَلِي هَذَا قَالَ لِجَمِيعِ أُمَّتِي كُلِّهِمْ","id":"Telah menceritakan kepada kami [Qutaibah] berkata, telah menceritakan kepada kami [Yazid bin Zurai'] dari [Sulaiman At Taimi] dari [Abu 'Utsman An Nahdi] dari [Ibnu Mas'ud], bahwa ada seorang laki-laki mencium seorang wanita, ia lalu mendatangi Nabi shallallahu 'alaihi wasallam dan mengabarkan kepada beliau. Maka turunlah firman Allah: '(Dan dirikanlah shalat pada kedua tepi siang (pagi dan petang) dan pada bahagian permulaan daripada malam. Sesungguhnya perbuatan-perbuatan yang baik itu menghapuskan (dosa) perbuatan-perbuatan yang buruk).' (Qs. Huud: 114). Laki-laki itu lalu bertanya, \"Wahai Rasulullah, apakah ini khusus buatku?\" beliau menjawab: \"Untuk semua umatku.\""},"496":{"ar":"حَدَّثَنَا أَبُو الْوَلِيدِ هِشَامُ بْنُ عَبْدِ الْمَلِكِ قَالَ حَدَّثَنَا شُعْبَةُ قَالَ الْوَلِيدُ بْنُ الْعَيْزَارِ أَخْبَرَنِي قَالَ سَمِعْتُ أَبَا عَمْرٍو الشَّي��بَانِيَّ يَقُولُ حَدَّثَنَا صَاحِبُ هَذِهِ الدَّارِ وَأَشَارَ إِلَى دَارِ عَبْدِ اللَّهِ قَالَسَأَلْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَيُّ الْعَمَلِ أَحَبُّ إِلَى اللَّهِ قَالَ الصَّلَاةُ عَلَى وَقْتِهَا قَالَ ثُمَّ أَيٌّ قَالَ ثُمَّ بِرُّ الْوَالِدَيْنِ قَالَ ثُمَّ أَيٌّ قَالَ الْجِهَادُ فِي سَبِيلِ اللَّهِ قَالَ حَدَّثَنِي بِهِنَّ وَلَوْ اسْتَزَدْتُهُ لَزَادَنِي","id":"Telah menceritakan kepada kami [Abu Al Walid Hisyam bin 'Abdul Malik] berkata, telah menceritakan kepada kami [Syu'bah] berkata, telah mengabarkan kepadaku [Al Walid bin Al 'Aizar] berkata, Aku mendengar [Abu 'Amru Asy Syaibani] berkata, \"Pemilik rumah ini menceritakan kepada kami -seraya menunjuk rumah ['Abdullah] - ia berkata, \"Aku pernah bertanya kepada Nabi shallallahu 'alaihi wasallam, \"Amal apakah yang paling dicintai oleh Allah?\" Beliau menjawab: \"Shalat pada waktunya.\" 'Abdullah bertanya lagi, \"Kemudian apa kagi?\" Beliau menjawab: \"Kemudian berbakti kepada kedua orangtua.\" 'Abdullah bertanya lagi, \"Kemudian apa kagi?\" Beliau menjawab: \"Jihad fi sabilillah.\" 'Abdullah berkata, \"Beliau sampaikan semua itu, sekiranya aku minta tambah, niscaya beliau akan menambahkannya untukku.\""},"497":{"ar":"حَدَّثَنَا إِبْرَاهِيمُ بْنُ حَمْزَةَ قَالَ حَدَّثَنِي ابْنُ أَبِي حَازِمٍ وَالدَّرَاوَرْدِيُّ عَنْ يَزِيدَ يَعْنِي ابْنِ عَبْدِ اللَّهِ بْنِ الْهَادِ عَنْ مُحَمَّدِ بْنِ إِبْرَاهِيمَ عَنْ أَبِي سَلَمَةَ بْنِ عَبْدِ الرَّحْمَنِ عَنْ أَبِي هُرَيْرَةَأَنَّهُ سَمِعَ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ أَرَأَيْتُمْ لَوْ أَنَّ نَهَرًا بِبَابِ أَحَدِكُمْ يَغْتَسِلُ فِيهِ كُلَّ يَوْمٍ خَمْسًا مَا تَقُولُ ذَلِكَ يُبْقِي مِنْ دَرَنِهِ قَالُوا لَا يُبْقِي مِنْ دَرَنِهِ شَيْئًا قَالَ فَذَلِكَ مِثْلُ الصَّلَوَاتِ الْخَمْسِ يَمْحُو اللَّهُ بِهِ الْخَطَايَا","id":"Telah menceritakan kepada kami [Ibrahim bin Hamzah] berkata, telah menceritakan kepadaku [Ibnu Abu Hazim] dan [Ad Darawardi] dari [Yazid] -yakni Ibnu 'abdullah bin Al Hadi- dari [Muhammad bin Ibrahim] dari [Abu Salamah bin 'Abdurrahman] dari [Abu Hurairah], bahwa ia mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Bagaimana pendapat kalian seandainya ada sungai di depan pintu rumah salah seorang dari kalian, lalu dia mandi lima kali setiap hari? Apakah kalian menganggap masih akan ada kotoran (daki) yang tersisa padanya?\" Para sahabat menjawab, \"Tidak akan ada yang tersisa sedikitpun kotoran padanya.\" Lalu beliau bersabda: \"Seperti itu pula dengan shalat lima waktu, dengannya Allah akan menghapus semua kesalahan.\""},"498":{"ar":"حَدَّثَنَا مُوسَى بْنُ إِسْمَاعِيلَ قَالَ حَدَّثَنَا مَهْدِيٌّ عَنْ غَيْلَانَ عَنْ أَنَسٍ قَالَمَا أَعْرِفُ شَيْئًا مِمَّا كَانَ عَلَى عَهْدِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قِيلَ الصَّلَاةُ قَالَ أَلَيْسَ ضَيَّعْتُمْ مَا ضَيَّعْتُمْ فِيهَا","id":"Telah menceritakan kepada kami [Musa bin Isma'il] berkata, telah menceritakan kepada kami [Mahdi] dari [Ghailan] dari [Anas] berkata, \"Aku tidak pernah mengenal sasuatupun di zaman Rasulullah shallallahu 'alaihi wasallam seperti apa yang terjadi sekarang.\" Dikatakan kepadanya, \"Apakah yang kau maksud shalat?\" Anas berkata, \"Bukankah memang benar kalian telah melalaikannya?\""},"499":{"ar":"حَدَّثَنَا عَمْرُو بْنُ زُرَارَةَ قَالَ أَخْبَرَنَا عَبْدُ الْوَاحِدِ بْنُ وَاصِلٍ أَبُو عُبَيْدَةَ الْحَدَّادُ عَنْ عُثْمَانَ بْنِ أَبِي رَوَّادٍ أَخِي عَبْدِ الْعَزِيزِ بْنِ أَبِي رَوَّادٍ قَالَ سَمِعْتُ الزُّهْرِيَّ يَقُولُ دَخَلْتُ عَلَى أَنَسِ بْنِ مَالِكٍ بِدِمَشْقَ وَهُوَ يَبْكِي فَقُلْتُ مَا يُبْكِيكَ فَقَالَلَا أَعْرِفُ شَيْئًا مِمَّا أَدْرَكْتُ إِلَّا هَذِهِ الصَّلَاةَ وَهَذِهِ الصَّلَاةُ قَدْ ضُيِّعَتْوَقَالَ بَكْرُ بْنُ خَلَفٍ حَدَّثَنَا مُحَمَّدُ بْنُ بَكْرٍ الْبُرْسَانِيُّ أَخْبَرَنَا عُثْمَانُ بْنُ أَبِي رَوَّادٍ نَحْوَهُ","id":"Telah menceritakan kepada kami ['Amru bin Zurarah] berkata, telah mengabarkan kepada kami ['Abdul Wahid bin Washil Abu 'Ubaidah Al Haddad] dari ['Utsman bin Abu Rawwad] saudara Al 'Aziz bin Abu Rawwad, ia berkata, aku mendengar [Az Zuhri] berkata, \"Aku pernah menemui [Anas bin Malik] di Damaskus, sementara saat itu ia sedang menangis. Aku lalu bertanya, 'Apa yang membuatmu menangis? Anas lalu menjawab, \"Aku tidak pernah mengenal sasuatupun di zaman Rasulullah shallallahu 'alaihi wasallam seperti apa yang aku temui sekarang selain masalah shalat. Shalat sekarang ini sudah dilalaikan.\" [Bakar bin Khalaf] berkata, telah menceritakan kepada kami [Muhammad bin Bakar Al Barsani] telah mengabarkan kepada kami ['Utsman bin Abu Rawwad] dengan hadits seperti ini.\""},"500":{"ar":"حَدَّثَنَا مُسْلِمُ بْنُ إِبْرَاهِيمَ قَالَ حَدَّثَنَا هِشَامٌ عَنْ قَتَادَةَ عَنْ أَنَسِ بْنِ مَالِكٍ قَالَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ أَحَدَكُمْ إِذَا صَلَّى يُنَاجِي رَبَّهُ فَلَا يَتْفِلَنَّ عَنْ يَمِينِهِ وَلَكِنْ تَحْتَ قَدَمِهِ الْيُسْرَىوَقَالَ سَعِيدٌ عَنْ قَتَادَةَ لَا يَتْفِلُ قُدَّامَهُ أَوْ بَيْنَ يَدَيْهِ وَلَكِنْ عَنْ يَسَارِهِ أَوْ تَحْتَ قَدَمَيْهِ وَقَالَ شُعْبَةُ لَا يَبْزُقُ بَيْنَ يَدَيْهِ وَلَا عَنْ يَمِينِهِ وَلَكِنْ عَنْ يَسَارِهِ أَوْ تَحْتَ قَدَمِهِ وَقَالَ حُمَيْدٌ عَنْ أَنَسٍ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا يَبْزُقْ فِي الْقِبْلَةِ وَلَا عَنْ يَمِينِهِ وَلَكِنْ عَنْ يَسَارِهِ أَوْ تَحْتَ قَدَمِهِ","id":"Telah menceritakan kepada kami [Muslim bin Ibrahim] berkata, telah menceritakan kepada kami [Hisyam] dari [Qatadah] dari [Anas bin Malik] berkata, \"Nabi shallallahu 'alaihi wasallam bersabda: \"Jika salah seorang dari kalian shalat bermunajat kepada Rabbnya, maka janganlah dia meludah ke sebelah kanannya, tetapi henklah ke sebelah kiri atau bawah kaki kirinya.\" [Sa'id] menyebutkan dari [Qatadah], \"Janganlah dia meludah ke arah depannya, tetapi ke sebelah kiri atau di bawah kedua kakinya.\" [Syu'bah] menyebutkan: \"Janganlah ia meludah ke arah depan atau sebelah kanannya, tetapi hendaklah ke sebelah kiri atau di bawah kaki kirinya.\" Dan [Humaid] menyebutkan dari [Anas] dari Nabi shallallahu 'alaihi wasallam: \"Janganlah ia meludah ke arah kiblat atau sebelah kanannya, tetapi hendaklah ke sebelah kiri atau di bawah kakinya.\""}};
